// Cache of Slack user IDs → display names so we can build human-readable
// thread context without round-tripping users.info on every message.
const userDisplayNameCache = new Map();

async function getUserDisplayName(userId) {
  if (!userId) return null;
  if (userDisplayNameCache.has(userId)) return userDisplayNameCache.get(userId);
  try {
    const info = await app.client.users.info({ token: SLACK_BOT_TOKEN, user: userId });
    const profile = info.user?.profile || {};
    const name =
      profile.display_name_normalized ||
      profile.real_name_normalized ||
      profile.real_name ||
      info.user?.name ||
      null;
    userDisplayNameCache.set(userId, name);
    return name;
  } catch (err) {
    console.error(`[bill-ling] getUserDisplayName(${userId}): ${err.message}`);
    userDisplayNameCache.set(userId, null);
    return null;
  }
}

/**
 * Check if a Slack user is OOO / on annual leave by reading their status.
 * Returns true if status contains :palm_tree:, :no_entry:, or common OOO phrases.
 */
async function isUserOOO(userId) {
  try {
    const info = await app.client.users.info({ token: SLACK_BOT_TOKEN, user: userId });
    const statusEmoji = info.user?.profile?.status_emoji || "";
    const statusText = (info.user?.profile?.status_text || "").toLowerCase();
    return (
      statusEmoji === ":palm_tree:" ||
      statusEmoji === ":no_entry:" ||
      /\b(out of office|annual leave|on leave|on holiday|vacation|ooo|away)\b/i.test(statusText)
    );
  } catch (err) {
    console.error(`[bill-ling] Failed to check OOO status for ${userId}:`, err.message);
    return false; // default to available if we can't check
  }
}

/**
 * Given a chase chain (array of { name, id }), return the first available person.
 * If everyone is OOO, returns the last person in the chain (Hargo as final fallback).
 */
async function getAvailableChaseTarget(chain) {
  for (const person of chain) {
    const ooo = await isUserOOO(person.id);
    if (!ooo) {
      return person;
    }
    console.log(`[bill-ling] ${person.name} is OOO — trying next in chain`);
  }
  // Everyone OOO — fall back to last person (Hargo)
  console.log(`[bill-ling] Everyone in chain is OOO — falling back to ${chain[chain.length - 1].name}`);
  return chain[chain.length - 1];
}

// Parse the GBP amount being approved for an awaiting_approval chase item.
// Prefers the LLM-extracted `amount`; falls back to the first £ figure in the
// chase message / description / quote. Returns a finite number or null.
function parseApprovalAmountGBP(item) {
  const direct = Number(item && item.amount);
  if (item && item.amount != null && Number.isFinite(direct)) return direct;
  const text = `${(item && item.chase_message) || ""} ${(item && item.description) || ""} ${(item && item.quote) || ""}`;
  const m = text.match(/£\s*([\d,]+(?:\.\d{1,2})?)/);
  if (m) {
    const n = Number(m[1].replace(/,/g, ""));
    if (Number.isFinite(n)) return n;
  }
  return null;
}

// Force a chase message to @-mention `toId`, replacing the first existing
// <@…> mention (whoever the LLM picked) or prepending if none is present.
function setChaseMention(chaseMsg, toId) {
  if (!chaseMsg) return `<@${toId}>`;
  if (chaseMsg.includes(`<@${toId}>`)) return chaseMsg;
  if (/<@[A-Z0-9]+>/i.test(chaseMsg)) return chaseMsg.replace(/<@[A-Z0-9]+>/i, `<@${toId}>`);
  return `<@${toId}> ${chaseMsg}`;
}

