//     amount and whether Stuart (≤ £750) or Richard (> £750) has approved,
//     then append to the existing close sheet under Fraud & VC Write Off
//   - no chasing, no follow-ups, no reminders
const VC_WRITEOFF_CHANNEL_NAME = "collab-vc-complaint-writeoff-approval";
const VC_WRITEOFF_THRESHOLD_GBP = 750;

// Approver identifiers. Env vars accept either a user ID (U…/W…) or a DM
// channel ID (D…) — the latter is what you get if you copied a Slack DM URL.
// Both forms are resolved to a canonical user ID at startup via
// resolveSlackUserOrDmId() below; that resolved ID is what classifier
// prompts use to detect approval messages by ID match.
let   STUART_USER_ID  = process.env.STUART_USER_ID  || null;
let   RICHARD_USER_ID = process.env.RICHARD_USER_ID || null;
let   vcWriteoffChannelId = process.env.VC_WRITEOFF_CHANNEL_ID || null;
const channelNameCache = new Map(); // channelId → name

/**
 * Accept either a Slack user ID (U…/W…) or a DM channel ID (D…) and return
 * the canonical user ID. For a DM channel we read its members and return
 * the participant that isn't the bot.
 */
async function resolveSlackUserOrDmId(id) {
  if (!id) return null;
  if (/^[UW][A-Z0-9]+$/i.test(id)) return id; // already a user ID
  if (/^D[A-Z0-9]+$/i.test(id)) {
    try {
      const r = await app.client.conversations.members({
        token: SLACK_BOT_TOKEN, channel: id,
      });
      const members = r.members || [];
      // Pick the one that isn't us (the bot). For 1:1 DMs there are 2 members.
      const userId = members.find(m => m && m !== BOT_USER_ID);
      return userId || null;
    } catch (err) {
      console.error(`[bill-ling] resolveSlackUserOrDmId(${id}): ${err.message}`);
      return null;
    }
  }
  return null;
}

async function resolveApproverIds() {
  if (STUART_USER_ID) {
    const resolved = await resolveSlackUserOrDmId(STUART_USER_ID);
    if (resolved && resolved !== STUART_USER_ID) {
      console.log(`[bill-ling] STUART_USER_ID resolved from DM ${STUART_USER_ID} → user ${resolved}.`);
      STUART_USER_ID = resolved;
    } else if (!resolved) {
      console.warn(`[bill-ling] STUART_USER_ID="${STUART_USER_ID}" could not be resolved to a user ID.`);
      STUART_USER_ID = null;
    } else {
      console.log(`[bill-ling] STUART_USER_ID confirmed as user ${STUART_USER_ID}.`);
    }
  }
  if (RICHARD_USER_ID) {
    const resolved = await resolveSlackUserOrDmId(RICHARD_USER_ID);
    if (resolved && resolved !== RICHARD_USER_ID) {
      console.log(`[bill-ling] RICHARD_USER_ID resolved from DM ${RICHARD_USER_ID} → user ${resolved}.`);
      RICHARD_USER_ID = resolved;
    } else if (!resolved) {
      console.warn(`[bill-ling] RICHARD_USER_ID="${RICHARD_USER_ID}" could not be resolved to a user ID.`);
      RICHARD_USER_ID = null;
    } else {
      console.log(`[bill-ling] RICHARD_USER_ID confirmed as user ${RICHARD_USER_ID}.`);
    }
  }
}

async function getChannelName(channelId) {
  if (!channelId) return "";
  if (channelNameCache.has(channelId)) return channelNameCache.get(channelId);
  try {
    const info = await app.client.conversations.info({ token: SLACK_BOT_TOKEN, channel: channelId });
    const name = info.channel?.name || "";
    channelNameCache.set(channelId, name);
    return name;
  } catch (err) {
    console.error(`[bill-ling] getChannelName(${channelId}): ${err.message}`);
    return "";
  }
}

async function isVcWriteoffChannel(channelId) {
  if (!channelId) return false;
  if (vcWriteoffChannelId && channelId === vcWriteoffChannelId) return true;
  const name = await getChannelName(channelId);
  if (name === VC_WRITEOFF_CHANNEL_NAME) {
    vcWriteoffChannelId = channelId; // cache for fast path
    return true;
  }
  return false;
}

/**
 * Strict-silence channels: Billington must NEVER speak here unless explicitly
 * @-mentioned. Passive triggers (name mention, direct-reply-to-Billington)
 * are suppressed entirely. Applies to both write-off approval channels
 * (Hargo, 22/05/2026 — after A00190153/A00216640 "Noted. fully closed..."
 * unsolicited reply to a Hargo status statement).
 */
async function isMentionOnlyChannel(channelId) {
  if (!channelId) return false;
  if (channelId === CHANNELS.RISK_OPS_WRITEOFF_CLOSE) return true;
  if (await isVcWriteoffChannel(channelId)) return true;
  return false;
}

