const sheetsAuth = new google.auth.GoogleAuth({
  keyFile: process.env.GOOGLE_APPLICATION_CREDENTIALS,
  scopes: ["https://www.googleapis.com/auth/spreadsheets"],
});
const sheetsClient = google.sheets({ version: "v4", auth: sheetsAuth });
const CLOSE_AGREEMENT_SHEET_ID = "10_81YrlB61uM7chbpoJy362W0S0MCO0XNt57uIPan8w";
const CLOSE_AGREEMENT_TAB = "agreements_to_close";

const CLOSE_REASON_COLUMNS = {
  return_to_sender:                        { col: "B", label: "Return to Sender", anchorTypeIds: [30] },
  asset_lost_in_transit:                   { col: "C", label: "Asset Lost in Transit", anchorTypeIds: [46] },
  warranty_return_cancellation:            { col: "D", label: "Warranty Return Cancellation", anchorTypeIds: [] },
  asset_return_cancelled_device_received:  { col: "E", label: "Asset Return — Device Received", anchorTypeIds: [30] },
  escalation_asset_received:               { col: "F", label: "Escalation — Asset Received", anchorTypeIds: [] },
  fraud_and_vc_write_off:                  { col: "G", label: "Fraud & VC Write Off", anchorTypeIds: [26, 70] },
};

/**
 * Check Anchor API for existing write-off/close transactions for an agreement.
 * Returns { found: boolean, typeId: number|null, description: string|null, date: string|null }
 */
async function checkAnchorForCloseTransaction(agreementId, anchorTypeIds) {
  if (!anchorTypeIds || anchorTypeIds.length === 0) return { found: false };
  try {
    const xml = await getAgreementFromAnchor(agreementId);
    const txnBlocks = xml.match(/<(?:a:)?Transaction>[\s\S]*?<\/(?:a:)?Transaction>/g) || [];
    for (const block of txnBlocks) {
      const typeMatch = block.match(/<(?:a:)?TypeId>(\d+)<\/(?:a:)?TypeId>/);
      if (!typeMatch) continue;
      const typeId = parseInt(typeMatch[1], 10);
      if (anchorTypeIds.includes(typeId)) {
        const dateMatch = block.match(/<(?:a:)?TransactionDate>([^<]+)<\/(?:a:)?TransactionDate>/);
        const date = dateMatch ? dateMatch[1].slice(0, 10) : null;
        const description = TRANSACTION_TYPES[typeId] || `Unknown (${typeId})`;
        return { found: true, typeId, description, date };
      }
    }
    return { found: false };
  } catch (err) {
    console.error(`[bill-ling] checkAnchorForCloseTransaction(${agreementId}):`, err.message);
    return { found: false, error: err.message };
  }
}

/**
 * Check if an agreement already exists in the close sheet.
 * Returns true if found.
 */
async function isAgreementInCloseSheet(agreementId) {
  try {
    const existing = await sheetsClient.spreadsheets.values.get({
      spreadsheetId: CLOSE_AGREEMENT_SHEET_ID,
      range: `${CLOSE_AGREEMENT_TAB}!A:A`,
    });
    const rows = existing.data.values || [];
    return rows.some(r => (r[0] || "").toUpperCase() === agreementId.toUpperCase());
  } catch (err) {
    console.error(`[bill-ling] isAgreementInCloseSheet(${agreementId}):`, err.message);
    return false;
  }
}

function parseCloseReason(text) {
  const lower = text.toLowerCase();
  // Test more specific patterns first to avoid overlap
  if (/\b(asset\s+lost\s+in\s+transit|lost\s+in\s+transit)\b/.test(lower)) return "asset_lost_in_transit";
  if (/\b(fraud|vc[\s-]?write[\s-]?off)\b/.test(lower)) return "fraud_and_vc_write_off";
  // Plain "write off" without "fraud"/"vc"/"lost in transit" is ambiguous
  if (/\b(write[\s-]?off)\b/.test(lower)) return "ambiguous_write_off";
  if (/\b(return\s+to\s+sender|rts)\b/.test(lower)) return "return_to_sender";
  if (/\b(warranty\s+(return|cancellation))\b/.test(lower)) return "warranty_return_cancellation";
  // Escalation must be checked BEFORE generic "asset return" to avoid false match
  if (/\b(escalation.{0,20}(asset|device)\s+(return|received)|(asset|device)\s+(return|received).{0,20}escalation)\b/.test(lower)) return "escalation_asset_received";
  if (/\b(asset\s+return|device\s+received)\b/.test(lower)) return "asset_return_cancelled_device_received";
  return null;
}

async function writeCloseAgreements(agreementIds, reasonKey, auditCtx = null) {
  const { col, label } = CLOSE_REASON_COLUMNS[reasonKey];
  const colIndex = col.charCodeAt(0) - "A".charCodeAt(0); // B=1, C=2, ..., G=6

  // Get all existing values in column A to find next blank row and check for duplicates
  const existing = await sheetsClient.spreadsheets.values.get({
    spreadsheetId: CLOSE_AGREEMENT_SHEET_ID,
    range: `${CLOSE_AGREEMENT_TAB}!A:A`,
  });
  const rows = existing.data.values || [];
  const existingIds = new Set(rows.map(r => (r[0] || "").toUpperCase()));

  const duplicates = agreementIds.filter(id => existingIds.has(id.toUpperCase()));
  const toWrite = agreementIds.filter(id => !existingIds.has(id.toUpperCase()));

  if (toWrite.length === 0) {
    return { written: [], duplicates, startRow: null };
  }

  const startRow = rows.length + 1; // next blank row (1-indexed)

  // Build row data: each row is an array of 7 cells (A-G), sparse
  const rowData = toWrite.map(id => {
    const row = new Array(7).fill("");
    row[0] = id;           // column A
    row[colIndex] = "TRUE"; // target column
    return row;
  });

  await sheetsClient.spreadsheets.values.update({
    spreadsheetId: CLOSE_AGREEMENT_SHEET_ID,
    range: `${CLOSE_AGREEMENT_TAB}!A${startRow}:G${startRow + rowData.length - 1}`,
    valueInputOption: "USER_ENTERED",
    requestBody: { values: rowData },
  });

  // ── Audit log per agreement added ──
  if (auditCtx) {
    const baseType = "close_sheet_added";
    const suffix = auditCtx.actionTypeSuffix ? `_${auditCtx.actionTypeSuffix}` : "";
    for (let i = 0; i < toWrite.length; i++) {
      const id = toWrite[i];
      const rowNum = startRow + i;
      await logBillingtonAction({
        actionCategory: "sheet_write",
        actionType: `${baseType}${suffix}`,
        agreementId: id,
        reference: reasonKey,
        status: "success",
        description: `Added ${id} to agreements_to_close → col ${col} (${label})`,
        requestedBy: auditCtx.requestedBy,
        requestedByUserId: auditCtx.requestedByUserId,
        triggeredBy: auditCtx.triggeredBy,
        triggerSource: auditCtx.triggerSource,
        sourceLink: auditCtx.sourceLink,
        targetSheetRow: `${CLOSE_AGREEMENT_TAB}!${col}${rowNum}`,
        idempotencyKey: `close_sheet:${id}:${reasonKey}`,
      });
    }
  }

  return {
    written: toWrite.map((id, i) => ({ id, row: startRow + i })),
    duplicates,
    startRow,
  };
}

