async function getWaiveLogTabName() {
  if (WAIVE_LOG_TAB_CACHE) return WAIVE_LOG_TAB_CACHE;
  const meta = await sheetsClient.spreadsheets.get({
    spreadsheetId: WAIVE_LOG_SHEET_ID,
    fields: "sheets(properties(sheetId,title))",
  });
  const sheet = (meta.data.sheets || []).find(s => s.properties.sheetId === WAIVE_LOG_TAB_GID);
  WAIVE_LOG_TAB_CACHE = sheet?.properties?.title || "Sheet1";
  return WAIVE_LOG_TAB_CACHE;
}

/**
 * Inspect an agreement in Anchor to determine the damage-fee collection
 * status for the Waive Log workflow (Hargo, 21/05/2026).
 *
 * Returns:
 *   { hasDamageFee: bool,
 *     status: 'no_damage_fee'        — no PaymentProfile entry with SubTypeDescription = "Damage Fee"
 *           | 'paid_card'            — at least one TypeId 23 collection after the damage fee, not reversed
 *           | 'paid_dd_confirmed'    — DD collection > 1 working day old, not reversed
 *           | 'attempted_unconfirmed' — DD collection within last 1 working day, not yet reversible
 *           | 'uncollected_or_bounced' — no successful collection (no attempts OR all reversed)
 *     details: { damageFeeDates: [], damageFeeAmounts: [], collections: [], reversals: [] }
 *   }
 */
async function getDamageFeeStatus(agreementId) {
  const xml = await getAgreementFromAnchor(agreementId);

  // ── 1. PaymentProfile entries with SubTypeDescription = Damage Fee ──
  const profiles = xml.match(/<(?:a:)?PaymentProfile>[\s\S]*?<\/(?:a:)?PaymentProfile>/g) || [];
  const damageFeeEntries = [];
  for (const p of profiles) {
    const sub = p.match(/<(?:a:)?SubTypeDescription>([^<]*)</);
    if (!sub || sub[1].trim().toLowerCase() !== "damage fee") continue;
    const dt = p.match(/<(?:a:)?PaymentDate>([^<]+)</);
    const amt = p.match(/<(?:a:)?PaymentAmount>([^<]+)</);
    damageFeeEntries.push({
      date: dt ? dt[1].slice(0, 10) : null,
      amount: amt ? parseFloat(amt[1]) : 0,
    });
  }
  if (damageFeeEntries.length === 0) {
    return { hasDamageFee: false, status: "no_damage_fee", details: {}, damageFeeAmount: 0 };
  }
  // Sum every damage-fee PaymentProfile entry's amount — this is the
  // canonical waive amount used in the Waive Log column L and the hourly
  // report (Hargo, 21/05/2026: amount must come from PaymentProfile, not
  // from the spreadsheet's column H).
  const damageFeeAmount = Number(damageFeeEntries.reduce((sum, e) => sum + (Number.isFinite(e.amount) ? e.amount : 0), 0).toFixed(2));
  // Earliest damage fee date — collections on/after this date are candidates.
  const earliestDamageFeeDate = damageFeeEntries
    .map(e => e.date).filter(Boolean).sort()[0];

  // ── 2. Transactions: collections + reversals ────────────────────────
  const txContainer = (xml.match(/<(?:a:)?Transactions>([\s\S]*?)<\/(?:a:)?Transactions>/) || [])[1] || "";
  const txBlocks = txContainer.match(/<(?:a:)?Transaction>[\s\S]*?<\/(?:a:)?Transaction>/g) || [];
  const txns = txBlocks.map(b => ({
    typeId: parseInt(((b.match(/<(?:a:)?TypeId>(\d+)</) || [])[1]) || "0", 10),
    date: ((b.match(/<(?:a:)?TransactionDate>([^<]+)</) || [])[1] || "").slice(0, 10),
    amount: parseFloat(((b.match(/<(?:a:)?Gross>(-?[\d.]+)</) || [])[1]) || "0"),
  })).filter(t => t.date && earliestDamageFeeDate && t.date >= earliestDamageFeeDate);

  const COLLECTION_TYPES = new Set([12, 23, 53, 55]);
  const REVERSAL_TYPES   = new Set([24, 54, 56, 150, 151, 152, 153, 154, 155, 156]);

  const collections = txns.filter(t => COLLECTION_TYPES.has(t.typeId) && t.amount > 0);
  const reversals   = txns.filter(t => REVERSAL_TYPES.has(t.typeId));

  // Pair each collection with a same-amount reversal on/after its date.
  // Pragmatic match (no exact 1:1 pairing tracking) — good enough at the
  // per-agreement scale we operate on here.
  function isReversed(coll) {
    return reversals.some(r =>
      Math.abs(Math.abs(r.amount) - coll.amount) <= 0.01 &&
      r.date >= coll.date
    );
  }
  const unreversed = collections.filter(c => !isReversed(c));

  if (unreversed.length === 0) {
    return {
      hasDamageFee: true,
      status: "uncollected_or_bounced",
      damageFeeAmount,
      details: { damageFeeEntries, collections, reversals },
    };
  }

  // Card collections (TypeId 23) → always confirmed.
  if (unreversed.some(c => c.typeId === 23)) {
    return {
      hasDamageFee: true,
      status: "paid_card",
      damageFeeAmount,
      details: { damageFeeEntries, collections, reversals },
    };
  }

  // DD collections: confirmed if today > nextWorkingDay(coll.date).
  const todayStr = new Date().toLocaleDateString("en-CA", { timeZone: "Europe/London" });
  const confirmedDD = unreversed.find(c => c.typeId === 12 && todayStr > nextWorkingDay(c.date));
  if (confirmedDD) {
    return {
      hasDamageFee: true,
      status: "paid_dd_confirmed",
      damageFeeAmount,
      details: { damageFeeEntries, collections, reversals, collection: confirmedDD },
    };
  }
  // DD too recent → still in BACS clearing window.
  const recentDD = unreversed.find(c => c.typeId === 12);
  if (recentDD) {
    return {
      hasDamageFee: true,
      status: "attempted_unconfirmed",
      damageFeeAmount,
      details: { damageFeeEntries, collections, reversals, collection: recentDD },
    };
  }
  // Opos/Perch — treat like DD (assume confirmed if >1 working day, else unconfirmed).
  const otherConfirmed = unreversed.find(c => (c.typeId === 53 || c.typeId === 55) && todayStr > nextWorkingDay(c.date));
  if (otherConfirmed) {
    return { hasDamageFee: true, status: "paid_dd_confirmed", damageFeeAmount, details: { damageFeeEntries, collections, reversals, collection: otherConfirmed } };
  }
  // Fallback
  return { hasDamageFee: true, status: "uncollected_or_bounced", damageFeeAmount, details: { damageFeeEntries, collections, reversals } };
}

/**
 * Process the Waive Log tab. Returns
 *   { eligible, skippedBadRow, skippedAlreadyTicked, skippedDuplicate, written, errors }.
 *
 * - eligible:           rows passing the A/B/C/G non-null filter
 * - skippedBadRow:      filter failed (missing A/B/C/G, or A doesn't look like A00…)
 * - skippedAlreadyTicked: row's column I was already TRUE → already processed
 * - skippedDuplicate:   agreement_id already in agreements_to_close column A
 * - written:            agreement_ids successfully appended to close sheet
 * - errors:             per-row write failures
 */
async function processWaiveLog() {
  const tab = await getWaiveLogTabName();
  const sheetRes = await sheetsClient.spreadsheets.values.get({
    spreadsheetId: WAIVE_LOG_SHEET_ID,
    range: `${tab}!A:J`,
  });
  const rows = sheetRes.data.values || [];
  if (rows.length <= 1) {
    return { eligible: [], skippedBadRow: [], skippedAlreadyTicked: [], skippedDuplicate: [], skippedNoDamageFee: [], skippedPaid: [], skippedUnconfirmed: [], chasesPaid: [], chasesUnconfirmed: [], partialPaid: [], partialUncollected: [], partialUnconfirmed: [], chasesPartial: [], written: [], errors: [] };
  }

  const skippedBadRow = [];
  const skippedAlreadyTicked = [];
  const candidates = []; // { rowNum, agreementId }
  // Row 1 (rows[0]) is the header — skip.
  for (let i = 1; i < rows.length; i++) {
    const r = rows[i];
    const colA = (r[0] || "").trim();
    const colB = (r[1] || "").trim();
    const colC = (r[2] || "").trim();
    const colG = (r[6] || "").trim();
    const colH = (r[7] || "").trim();
    const colIRaw = (r[8] || "").trim();
    const colI = colIRaw.toUpperCase();
    const rowNum = i + 1; // 1-indexed Sheets row

    if (!colA || !colB || !colC || !colG) {
      // Only flag a "bad row" if there's an agreement id present — otherwise
      // it's just a blank trailing row and not worth surfacing.
      if (colA) skippedBadRow.push({ rowNum, agreementId: colA, reason: "missing A/B/C/G" });
      continue;
    }
    if (!/^A\d{4,9}$/i.test(colA)) {
      skippedBadRow.push({ rowNum, agreementId: colA, reason: "agreement id format invalid" });
      continue;
    }
    // Hargo, 21/05/2026: any "warranty" mention in column I → silently
    // exclude. Catches "warranty return", "Warranty Activation Charge",
    // etc. — case-insensitive. These are handled outside the closure flow.
    if (/\bwarranty\b/i.test(colIRaw)) {
      continue;
    }
    if (colI === "TRUE") {
      skippedAlreadyTicked.push({ rowNum, agreementId: colA.toUpperCase() });
      continue;
    }
    // Column I must be explicitly "FALSE" to be eligible. Empty, "Pending",
    // anything else → ignore the row entirely.
    if (colI !== "FALSE") {
      skippedBadRow.push({ rowNum, agreementId: colA, reason: `column I = "${colIRaw || "(blank)"}" — only TRUE/FALSE is recognised; row ignored` });
      continue;
    }
    candidates.push({
      rowNum,
      agreementId: colA.toUpperCase(),
      reason: colG,
      amount: colH,
    });
  }

  if (candidates.length === 0) {
    return { eligible: [], skippedBadRow, skippedAlreadyTicked, skippedDuplicate: [], skippedNoDamageFee: [], skippedPaid: [], skippedUnconfirmed: [], chasesPaid: [], chasesUnconfirmed: [], partialPaid: [], partialUncollected: [], partialUnconfirmed: [], chasesPartial: [], written: [], errors: [] };
  }

  // Read close sheet col A once to dedup.
  const existing = await sheetsClient.spreadsheets.values.get({
    spreadsheetId: CLOSE_AGREEMENT_SHEET_ID,
    range: `${CLOSE_AGREEMENT_TAB}!A:A`,
  });
  const existingIds = new Set((existing.data.values || []).map(r => (r[0] || "").toUpperCase()));

  const skippedDuplicate = [];
  const skippedNoDamageFee = [];
  const skippedPaid = [];
  const skippedUnconfirmed = [];
  // Hargo, 27/05/2026: "chases" are agreements that were previously
  // reported on an earlier working day and are STILL pending. We do NOT
  // re-include them in the top-level Waive Log channel post — instead
  // we post a thread reply on the ORIGINAL first-report message.
  const chasesPaid = [];
  const chasesUnconfirmed = [];
  // Hargo, 29/05/2026: PARTIAL waivers — column H (the "cost of waiving")
  // is a positive value strictly LESS than the Anchor damage-fee amount.
  // These never auto-close. Billington waits for the DD then flags
  // Charlotte to post a partial GOGW for £H (+ a paired refund only if the
  // fee was actually collected). Kept in their own arrays so the hourly
  // report renders them in a clearly-labelled section.
  const partialPaid = [];        // fee collected → flag GOGW £H + refund £H
  const partialUncollected = []; // past due, nothing collected → flag GOGW £H only
  const partialUnconfirmed = []; // DD pending OR fee not yet due → wait/recheck
  const chasesPartial = [];      // partial rows previously reported, still pending
  const toAddToClose = []; // candidates eligible for the close sheet
  const errors = [];

  // Helper to write a Billington note to column K and (optionally) a
  // human-readable flag to column J on the Waive Log row.
  const writeNoteK = async (rowNum, note) => {
    try {
      await sheetsClient.spreadsheets.values.update({
        spreadsheetId: WAIVE_LOG_SHEET_ID,
        range: `${tab}!K${rowNum}`,
        valueInputOption: "USER_ENTERED",
        requestBody: { values: [[note]] },
      });
    } catch (err) {
      console.error(`[bill-ling] writeNoteK row ${rowNum} failed:`, err.message);
    }
  };
  const writeFlagJ = async (rowNum, flag) => {
    try {
      await sheetsClient.spreadsheets.values.update({
        spreadsheetId: WAIVE_LOG_SHEET_ID,
        range: `${tab}!J${rowNum}`,
        valueInputOption: "USER_ENTERED",
        requestBody: { values: [[flag]] },
      });
    } catch (err) {
      console.error(`[bill-ling] writeFlagJ row ${rowNum} failed:`, err.message);
    }
  };
  const writeAmountL = async (rowNum, amount) => {
    // Hargo, 21/05/2026: damage fee amount from Anchor PaymentProfile goes
    // into column L of the Waive Log (first sheet). Independent of column H
    // which is the human-entered "cost of waiving" estimate.
    try {
      await sheetsClient.spreadsheets.values.update({
        spreadsheetId: WAIVE_LOG_SHEET_ID,
        range: `${tab}!L${rowNum}`,
        valueInputOption: "USER_ENTERED",
        requestBody: { values: [[amount ? `£${amount.toFixed(2)}` : ""]] },
      });
    } catch (err) {
      console.error(`[bill-ling] writeAmountL row ${rowNum} failed:`, err.message);
    }
  };

  // Per-candidate Anchor check (Hargo, 21/05/2026):
  //  1. No damage fee on Anchor → note in K, leave I as FALSE.
  //  2. Damage fee + paid via card / confirmed DD → note in K + flag for
  //     Charlotte in J, leave I as FALSE (she should not be auditing this).
  //  3. Damage fee + DD attempted but unconfirmed (<1 working day) → note
  //     in K saying recheck after 1 working day. Leave I as FALSE.
  //  4. Damage fee + uncollected or bounced → write to close sheet,
  //     tick I = TRUE.
  for (const c of candidates) {
    let status;
    try {
      status = await getDamageFeeStatus(c.agreementId);
    } catch (err) {
      errors.push({ rowNum: c.rowNum, agreementId: c.agreementId, error: `Anchor read failed: ${err.message}` });
      await writeNoteK(c.rowNum, `Could not read Anchor (${new Date().toISOString().slice(0, 10)}): ${err.message}`);
      continue;
    }

    // Write the canonical damage-fee amount (from PaymentProfile) to col L
    // for every row regardless of status — even no_damage_fee rows get
    // £0.00 so it's clear we checked.
    await writeAmountL(c.rowNum, status.damageFeeAmount || 0);

    if (status.status === "no_damage_fee") {
      skippedNoDamageFee.push({ rowNum: c.rowNum, agreementId: c.agreementId });
      await writeNoteK(c.rowNum, `Damage fee does not exist on Anchor for this agreement (checked ${new Date().toISOString().slice(0, 10)}). Not added to closure sheet.`);
      continue;
    }

    // ── PARTIAL waiver detection (Hargo, 29/05/2026) ───────────────────
    // Column H = the amount we actually want to waive.
    //   • H blank/null    → FULL waive of the repair charge (existing flow).
    //   • H ≥ fee due      → treat as a full waive (existing flow).
    //   • 0 < H < fee due  → PARTIAL waive: do NOT auto-close. Wait for the
    //     DD to be attempted/confirmed, then flag Charlotte to post a
    //     partial GOGW for £H (+ a paired refund ONLY if the fee was
    //     actually collected). "fee due" = the canonical Anchor
    //     PaymentProfile damage-fee amount (the same value written to col L).
    const feeDue = Number(status.damageFeeAmount || 0);
    const cleanedH = (c.amount || "").toString().replace(/[£,\s]/g, "");
    const hVal = cleanedH ? Number(cleanedH) : NaN;
    const isPartial = Number.isFinite(hVal) && hVal > 0 && feeDue > 0.01 && hVal < (feeDue - 0.01);

    if (isPartial) {
      const waiveAmt = Number(hVal.toFixed(2));
      const todayWdIso = new Date().toLocaleDateString("en-CA", { timeZone: "Europe/London" });
      const feeCollected = (status.status === "paid_card" || status.status === "paid_dd_confirmed");

      // Already actioned? GOGW £H present in Anchor (+ refund £H if the fee
      // was collected) → mark the row done and stop chasing. Mirrors the
      // full-waive actioned-recognition below.
      try {
        const xml = await getAgreementFromAnchor(c.agreementId);
        const txContainerLocal = (xml.match(/<(?:a:)?Transactions>([\s\S]*?)<\/(?:a:)?Transactions>/) || [, ""])[1];
        const txns = (txContainerLocal.match(/<(?:a:)?Transaction>[\s\S]*?<\/(?:a:)?Transaction>/g) || [])
          .map(b => ({
            typeId: parseInt(((b.match(/<(?:a:)?TypeId>(\d+)</) || [])[1]) || "0", 10),
            amount: parseFloat(((b.match(/<(?:a:)?Gross>(-?[\d.]+)</) || [])[1]) || "0"),
            date:   ((b.match(/<(?:a:)?TransactionDate>([^<]+)</) || [])[1] || "").slice(0, 10),
          }));
        const tol = 0.01;
        const gogwH = txns.find(t => t.typeId === 61 && Math.abs(Math.abs(t.amount) - waiveAmt) <= tol);
        const refundH = txns.find(t => t.typeId === 149 && Math.abs(Math.abs(t.amount) - waiveAmt) <= tol);
        const actioned = feeCollected ? (gogwH && refundH) : !!gogwH;
        if (actioned) {
          try {
            await sheetsClient.spreadsheets.values.batchUpdate({
              spreadsheetId: WAIVE_LOG_SHEET_ID,
              requestBody: {
                valueInputOption: "USER_ENTERED",
                data: [
                  { range: `${tab}!I${c.rowNum}`, values: [["TRUE"]] },
                  { range: `${tab}!J${c.rowNum}`, values: [[`✅ PARTIAL waiver ACTIONED — GOGW £${waiveAmt.toFixed(2)}${feeCollected ? ` + refund £${waiveAmt.toFixed(2)}` : " (no refund — fee uncollected)"} posted. No further action needed.`]] },
                  { range: `${tab}!K${c.rowNum}`, values: [[`PARTIAL waiver actioned: GOGW £${waiveAmt.toFixed(2)} (TypeId 61${gogwH?.date ? `, ${gogwH.date}` : ""})${feeCollected ? ` + refund £${waiveAmt.toFixed(2)} (TypeId 149${refundH?.date ? `, ${refundH.date}` : ""})` : " (no refund — fee was uncollected)"} found in Anchor (recognised by Billington on ${todayWdIso}).`]] },
                ],
              },
            });
          } catch (err) {
            console.error(`[bill-ling] Waive Log partial row ${c.rowNum} mark-actioned failed:`, err.message);
          }
          // Confirm both legs in the thread (Hargo, 18/06/2026: "always confirm
          // when the GOGW has been posted and the refund").
          const _thrP = waiveLogReportThreads.get(c.agreementId);
          if (_thrP && _thrP.ts) {
            try {
              await app.client.chat.postMessage({
                token: SLACK_BOT_TOKEN, channel: _thrP.channel, thread_ts: _thrP.ts,
                text: `✅ Confirmed in Anchor for *${c.agreementId}*: PARTIAL waiver actioned — GOGW £${waiveAmt.toFixed(2)}${feeCollected ? ` + refund £${waiveAmt.toFixed(2)}` : " (no refund — fee was uncollected)"} posted. Marking the Waive Log row done, no further action needed.`,
                mrkdwn: true, unfurl_links: false, unfurl_media: false,
              });
            } catch (e) { console.error(`[bill-ling] Waive Log partial confirm-post failed for ${c.agreementId}:`, e.message); }
          }
          if (waiveLogReportThreads.has(c.agreementId)) { waiveLogReportThreads.delete(c.agreementId); await saveWaiveLogThreadsAsync(); }
          if (waiveLogPendingReported.has(c.agreementId)) { waiveLogPendingReported.delete(c.agreementId); await saveWaiveLogPendingAsync(); }
          skippedAlreadyTicked.push(c);
          continue;
        }
      } catch (err) {
        console.error(`[bill-ling] partial actioned-check failed for ${c.agreementId}:`, err.message);
      }

      const lastReportedWd = waiveLogPendingReported.get(c.agreementId);
      const existingThread = waiveLogReportThreads.get(c.agreementId);
      // Damage-fee due date = the latest PaymentProfile damage-fee date.
      const dueDates = (status.details?.damageFeeEntries || []).map(e => e.date).filter(Boolean).sort();
      const dueDate = dueDates.length ? dueDates[dueDates.length - 1] : null;

      // (a) Fee collected (card / confirmed DD): the customer paid the full
      //     fee, so waiving £H means GOGW £H + refund £H. Flag Charlotte.
      if (feeCollected) {
        const method = status.status === "paid_card" ? "card payment" : "confirmed DD";
        const collDate = status.details?.collection?.date || "(date unknown)";
        if (lastReportedWd === todayWdIso) continue; // silent — already reported today
        if (existingThread) {
          chasesPartial.push({ rowNum: c.rowNum, agreementId: c.agreementId, subkind: "paid", method: status.status, feeDue, waiveAmt, collDate, channel: existingThread.channel, ts: existingThread.ts, firstReportedAt: existingThread.firstReportedAt });
          waiveLogPendingReported.set(c.agreementId, todayWdIso);
          await saveWaiveLogPendingAsync();
          continue;
        }
        partialPaid.push({ rowNum: c.rowNum, agreementId: c.agreementId, method: status.status, feeDue, waiveAmt, collDate });
        waiveLogPendingReported.set(c.agreementId, todayWdIso);
        await saveWaiveLogPendingAsync();
        await writeNoteK(c.rowNum, `PARTIAL waiver: damage fee £${feeDue.toFixed(2)} was collected via ${method} on ${collDate}; only £${waiveAmt.toFixed(2)} (column H) is to be waived. Awaiting partial GOGW £${waiveAmt.toFixed(2)} + refund £${waiveAmt.toFixed(2)} — checked ${todayWdIso}.`);
        await writeFlagJ(c.rowNum, `⚠️ <@${CHARLOTTE_PLATT_USER_ID}> PARTIAL waiver — damage fee £${feeDue.toFixed(2)} was collected via ${method}; only £${waiveAmt.toFixed(2)} (column H) is to be waived. Please post GOGW £${waiveAmt.toFixed(2)} + refund £${waiveAmt.toFixed(2)}.`);
        continue;
      }

      // (b) DD attempted but not yet confirmed (<1 working day) → wait,
      //     recheck on the next working day, flag once it confirms.
      if (status.status === "attempted_unconfirmed") {
        const collDate = status.details?.collection?.date || "(date unknown)";
        if (lastReportedWd === todayWdIso) continue;
        if (existingThread) {
          chasesPartial.push({ rowNum: c.rowNum, agreementId: c.agreementId, subkind: "unconfirmed", feeDue, waiveAmt, collDate, channel: existingThread.channel, ts: existingThread.ts, firstReportedAt: existingThread.firstReportedAt });
          waiveLogPendingReported.set(c.agreementId, todayWdIso);
          await saveWaiveLogPendingAsync();
          continue;
        }
        partialUnconfirmed.push({ rowNum: c.rowNum, agreementId: c.agreementId, feeDue, waiveAmt, collDate });
        waiveLogPendingReported.set(c.agreementId, todayWdIso);
        await saveWaiveLogPendingAsync();
        await writeNoteK(c.rowNum, `PARTIAL waiver: DD attempted on ${collDate} for the damage fee but not yet confirmed (<1 working day). Won't close — will recheck next working day and flag for a partial GOGW £${waiveAmt.toFixed(2)} once the DD confirms (checked ${todayWdIso}).`);
        continue;
      }

      // (c) uncollected_or_bounced → no successful collection.
      //     • Before the fee due date → wait for the DD attempt (don't flag).
      //     • On/after the due date with nothing collected → flag Charlotte
      //       to post GOGW £H ONLY (no refund — nothing was collected).
      if (dueDate && todayWdIso < dueDate) {
        if (lastReportedWd === todayWdIso) continue;
        partialUnconfirmed.push({ rowNum: c.rowNum, agreementId: c.agreementId, feeDue, waiveAmt, collDate: null, notDue: true, dueDate });
        waiveLogPendingReported.set(c.agreementId, todayWdIso);
        await saveWaiveLogPendingAsync();
        await writeNoteK(c.rowNum, `PARTIAL waiver: damage fee not yet due (due ${dueDate}). Won't close — waiting for the DD to be attempted before flagging (checked ${todayWdIso}).`);
        continue;
      }
      if (lastReportedWd === todayWdIso) continue;
      if (existingThread) {
        chasesPartial.push({ rowNum: c.rowNum, agreementId: c.agreementId, subkind: "uncollected", feeDue, waiveAmt, dueDate, channel: existingThread.channel, ts: existingThread.ts, firstReportedAt: existingThread.firstReportedAt });
        waiveLogPendingReported.set(c.agreementId, todayWdIso);
        await saveWaiveLogPendingAsync();
        continue;
      }
      partialUncollected.push({ rowNum: c.rowNum, agreementId: c.agreementId, feeDue, waiveAmt, dueDate });
      waiveLogPendingReported.set(c.agreementId, todayWdIso);
      await saveWaiveLogPendingAsync();
      await writeNoteK(c.rowNum, `PARTIAL waiver: no DD collected on/after the due date${dueDate ? ` (${dueDate})` : ""}. Damage fee £${feeDue.toFixed(2)} uncollected; only £${waiveAmt.toFixed(2)} (column H) is to be waived via GOGW (no refund — nothing was collected). Not closed — flagged for Charlotte (checked ${todayWdIso}).`);
      await writeFlagJ(c.rowNum, `⚠️ <@${CHARLOTTE_PLATT_USER_ID}> PARTIAL waiver — no DD collected on/after the due date${dueDate ? ` (${dueDate})` : ""}; damage fee £${feeDue.toFixed(2)} is uncollected. Please post a GOGW of £${waiveAmt.toFixed(2)} (column H — the partially-waived value). No refund (nothing was collected). Do NOT close.`);
      continue;
    }

    if (status.status === "paid_card" || status.status === "paid_dd_confirmed") {
      const method = status.status === "paid_card" ? "card payment" : "confirmed DD";
      const collDate = status.details?.collection?.date || "(date unknown)";
      const amount = status.details?.collection?.amount;

      // Has the waive already been actioned? Hargo, 27/05/2026:
      //   (a) Agreement already on the close sheet (any column) → done.
      //   (b) Anchor has a GOGW (TypeId 61) + refund (TypeId 149) both
      //       matching the damage fee amount → done (covers the waive).
      // Either signal closes the row out: I=TRUE, note in K, no further
      // reports / chases.
      let anchorActioned = false;
      let anchorActionedReason = "";
      let gogwTxn = null, refundTxn = null;  // Anchor status of each waive leg
      try {
        const xml = (status.details && status.details.xml) || await getAgreementFromAnchor(c.agreementId);
        const txContainerLocal = (xml.match(/<(?:a:)?Transactions>([\s\S]*?)<\/(?:a:)?Transactions>/) || [, ""])[1];
        const txns = (txContainerLocal.match(/<(?:a:)?Transaction>[\s\S]*?<\/(?:a:)?Transaction>/g) || [])
          .map(b => ({
            typeId: parseInt(((b.match(/<(?:a:)?TypeId>(\d+)</) || [])[1]) || "0", 10),
            amount: parseFloat(((b.match(/<(?:a:)?Gross>(-?[\d.]+)</) || [])[1]) || "0"),
            date:   ((b.match(/<(?:a:)?TransactionDate>([^<]+)</) || [])[1] || "").slice(0, 10),
          }));
        const tol = 0.01;
        const damageFee = status.damageFeeAmount;
        gogwTxn   = txns.find(t => t.typeId === 61  && Math.abs(Math.abs(t.amount) - damageFee) <= tol) || null;
        refundTxn = txns.find(t => t.typeId === 149 && Math.abs(Math.abs(t.amount) - damageFee) <= tol) || null;
        if (gogwTxn && refundTxn) {
          anchorActioned = true;
          anchorActionedReason = `GOGW £${damageFee.toFixed(2)} (TypeId 61, ${gogwTxn.date}) + refund £${damageFee.toFixed(2)} (TypeId 149, ${refundTxn.date}) posted in Anchor — Raylo covered the damage fee via GOGW and refunded it back`;
        }
      } catch (err) {
        console.error(`[bill-ling] Anchor actioned-check failed for ${c.agreementId}:`, err.message);
      }
      let inCloseSheet = false;
      try { inCloseSheet = await isAgreementInCloseSheet(c.agreementId); } catch (_) {}

      if (anchorActioned || inCloseSheet) {
        // Mark complete: I=TRUE, refresh K and J, do NOT include in
        // skippedPaid (so the hourly channel post stays silent on this row).
        const summary = anchorActioned
          ? `Damage fee waive ACTIONED: ${anchorActionedReason}.${inCloseSheet ? " Already on close sheet." : ""}`
          : `Damage fee waive ACTIONED: agreement already on close sheet.`;
        try {
          await sheetsClient.spreadsheets.values.batchUpdate({
            spreadsheetId: WAIVE_LOG_SHEET_ID,
            requestBody: {
              valueInputOption: "USER_ENTERED",
              data: [
                { range: `${tab}!I${c.rowNum}`, values: [["TRUE"]] },
                { range: `${tab}!J${c.rowNum}`, values: [[`✅ Damage fee waive ACTIONED — no further action needed.`]] },
                { range: `${tab}!K${c.rowNum}`, values: [[`${summary} (recognised by Billington on ${new Date().toISOString().slice(0, 10)}).`]] },
              ],
            },
          });
        } catch (err) {
          console.error(`[bill-ling] Waive Log row ${c.rowNum} mark-actioned failed:`, err.message);
        }
        // Confirm in the thread that BOTH legs are posted (Hargo, 18/06/2026:
        // "always confirm when the GOGW has been posted and the refund"). Only
        // when Anchor-actioned (both present) and only if there's a thread to
        // reply in. Posts once — the row is I=TRUE next run so we won't re-enter.
        if (anchorActioned) {
          const _thr = waiveLogReportThreads.get(c.agreementId);
          if (_thr && _thr.ts) {
            try {
              await app.client.chat.postMessage({
                token: SLACK_BOT_TOKEN,
                channel: _thr.channel,
                thread_ts: _thr.ts,
                text: `✅ Confirmed in Anchor for *${c.agreementId}*: ${anchorActionedReason}. Damage fee waive complete — marking the Waive Log row done, no further action needed.`,
                mrkdwn: true, unfurl_links: false, unfurl_media: false,
              });
            } catch (e) {
              console.error(`[bill-ling] Waive Log confirm-post failed for ${c.agreementId}:`, e.message);
            }
          }
        }
        // Clear from chase-tracking state — no more chases needed.
        if (waiveLogReportThreads.has(c.agreementId)) {
          waiveLogReportThreads.delete(c.agreementId);
          await saveWaiveLogThreadsAsync();
        }
        if (waiveLogPendingReported.has(c.agreementId)) {
          waiveLogPendingReported.delete(c.agreementId);
          await saveWaiveLogPendingAsync();
        }
        skippedAlreadyTicked.push(c); // count it as "done" so the report sees it
        continue;
      }

      // Not yet actioned. Per-working-day dedup (Hargo, 27/05/2026): if
      // we've already reported this row today, fully silent — no channel,
      // no chase. Recheck happens on the NEXT working day.
      const todayWdIso = new Date().toLocaleDateString("en-CA", { timeZone: "Europe/London" });
      const lastReportedWd = waiveLogPendingReported.get(c.agreementId);
      if (lastReportedWd === todayWdIso) {
        continue; // silent — already reported today
      }

      // If we've already reported this agreement on an EARLIER working
      // day, the new working-day report is a CHASE — post as a thread
      // reply to the original message, NOT a new top-level channel post.
      const existingThread = waiveLogReportThreads.get(c.agreementId);
      const isChase = !!existingThread;

      if (isChase) {
        chasesPaid.push({
          rowNum: c.rowNum,
          agreementId: c.agreementId,
          method: status.status,
          damageFeeAmount: status.damageFeeAmount,
          collDate,
          amount,
          channel: existingThread.channel,
          ts: existingThread.ts,
          firstReportedAt: existingThread.firstReportedAt,
          gogwPosted: !!gogwTxn, gogwDate: gogwTxn?.date || null,
          refundPosted: !!refundTxn, refundDate: refundTxn?.date || null,
        });
        waiveLogPendingReported.set(c.agreementId, todayWdIso);
        await saveWaiveLogPendingAsync();
        // Don't re-write J/K — they were set on the first report and
        // remain valid. The Slack thread reply is the audit trail.
        continue;
      }

      // First-time report — surface in the top-level channel post and
      // write J/K. After the post lands, runWaiveLogCron will store the
      // thread mapping so subsequent working days post chases here.
      skippedPaid.push({ rowNum: c.rowNum, agreementId: c.agreementId, method: status.status, damageFeeAmount: status.damageFeeAmount, collDate, amount, gogwPosted: !!gogwTxn, gogwDate: gogwTxn?.date || null, refundPosted: !!refundTxn, refundDate: refundTxn?.date || null });
      waiveLogPendingReported.set(c.agreementId, todayWdIso);
      await saveWaiveLogPendingAsync();
      await writeNoteK(
        c.rowNum,
        `Damage fee already collected via ${method} on ${collDate}${amount ? ` (£${amount.toFixed(2)})` : ""}. Awaiting waive action (GOGW + refund + close-sheet) — checked ${new Date().toISOString().slice(0, 10)}.`
      );
      await writeFlagJ(
        c.rowNum,
        `⚠️ <@${CHARLOTTE_PLATT_USER_ID}> please ACTION — damage fee was collected via ${method} on ${collDate}; needs to be waived (GOGW + refund + add to close sheet).`
      );
      continue;
    }

    if (status.status === "attempted_unconfirmed") {
      // Hargo, 25/05/2026: dedup per working day. If we've already reported
      // this agreement as pending today, don't re-report (no channel line,
      // no sheet-note re-write). The recheck happens on the NEXT WORKING
      // DAY — not the next hourly cron run.
      const todayWdIso = new Date().toLocaleDateString("en-CA", { timeZone: "Europe/London" });
      const lastReportedWd = waiveLogPendingReported.get(c.agreementId);
      if (lastReportedWd === todayWdIso) {
        continue; // silent skip — already reported on this working day
      }

      const collDate = status.details?.collection?.date || "(date unknown)";
      const amount = status.details?.collection?.amount;

      // Hargo, 27/05/2026: if previously reported on an earlier working
      // day, this is a chase — post as thread reply, not top-level.
      const existingThread = waiveLogReportThreads.get(c.agreementId);
      if (existingThread) {
        chasesUnconfirmed.push({
          rowNum: c.rowNum,
          agreementId: c.agreementId,
          damageFeeAmount: status.damageFeeAmount,
          collDate,
          amount,
          channel: existingThread.channel,
          ts: existingThread.ts,
          firstReportedAt: existingThread.firstReportedAt,
        });
        waiveLogPendingReported.set(c.agreementId, todayWdIso);
        await saveWaiveLogPendingAsync();
        continue;
      }

      skippedUnconfirmed.push({ rowNum: c.rowNum, agreementId: c.agreementId, damageFeeAmount: status.damageFeeAmount, collDate, amount });
      waiveLogPendingReported.set(c.agreementId, todayWdIso);
      await saveWaiveLogPendingAsync();
      await writeNoteK(
        c.rowNum,
        `DD attempted on ${collDate}${amount ? ` (£${amount.toFixed(2)})` : ""} for the damage fee but not yet confirmed (<1 working day). Will recheck on the next working day (checked ${todayWdIso}).`
      );
      continue;
    }

    // status === "uncollected_or_bounced" → eligible for close sheet.
    if (existingIds.has(c.agreementId)) {
      skippedDuplicate.push(c);
      // Still tick I = TRUE so we don't keep re-checking it.
      try {
        await sheetsClient.spreadsheets.values.update({
          spreadsheetId: WAIVE_LOG_SHEET_ID,
          range: `${tab}!I${c.rowNum}`,
          valueInputOption: "USER_ENTERED",
          requestBody: { values: [["TRUE"]] },
        });
        await writeNoteK(c.rowNum, `Agreement already in agreements_to_close (checked ${new Date().toISOString().slice(0, 10)}). Marked TRUE.`);
      } catch (err) {
        errors.push({ rowNum: c.rowNum, agreementId: c.agreementId, error: `tick I (dedup) failed: ${err.message}` });
      }
      continue;
    }
    toAddToClose.push({ ...c, damageFeeAmount: status.damageFeeAmount });
  }

  // Bulk write the eligible candidates to the close sheet.
  let writeResult = { written: [], duplicates: [], startRow: null };
  if (toAddToClose.length > 0) {
    // Audit context per row — Waive Log col B is "Waived by" (the requester).
    // Cron triggers this loop, so triggeredBy = cron:waive_log.
    const byId = new Map(toAddToClose.map(c => [c.agreementId.toUpperCase(), c]));
    writeResult = await writeCloseAgreements(
      toAddToClose.map(c => c.agreementId),
      WAIVE_LOG_CLOSE_REASON_KEY,
      {
        requestedBy: toAddToClose[0]?.waivedBy || "",
        triggeredBy: "cron:waive_log",
        triggerSource: "cron",
        actionTypeSuffix: "waive_log_cron",
      }
    );
  }
  const writtenIds = new Set(writeResult.written.map(w => w.id.toUpperCase()));

  // Enrich each written entry with the source row's reason + amount so the
  // hourly cron can format a clean "agreement → amount → reason" report.
  const written = [];
  for (const c of toAddToClose) {
    if (!writtenIds.has(c.agreementId)) continue;
    written.push({
      agreementId: c.agreementId,
      reason: c.reason,
      damageFeeAmount: c.damageFeeAmount,
      rowNum: c.rowNum,
    });
    try {
      await sheetsClient.spreadsheets.values.update({
        spreadsheetId: WAIVE_LOG_SHEET_ID,
        range: `${tab}!I${c.rowNum}`,
        valueInputOption: "USER_ENTERED",
        requestBody: { values: [["TRUE"]] },
      });
      await writeNoteK(c.rowNum, `Damage fee on Anchor, no successful collection found. Added to agreements_to_close on ${new Date().toISOString().slice(0, 10)}.`);
    } catch (err) {
      errors.push({ rowNum: c.rowNum, agreementId: c.agreementId, error: `tick I / note K failed: ${err.message}` });
    }
  }

  return {
    eligible: candidates,
    skippedBadRow,
    skippedAlreadyTicked,
    skippedDuplicate,
    skippedNoDamageFee,
    skippedPaid,
    skippedUnconfirmed,
    chasesPaid,
    chasesUnconfirmed,
    partialPaid,
    partialUncollected,
    partialUnconfirmed,
    chasesPartial,
    written,
    errors,
  };
}

// ── Waive paid damage fee — GOGW + refund + add to close sheet ────────
// Hargo, 27/05/2026: when the Waive Log update flags a row as "damage fee
// already collected — pending action (Charlotte please action)", Hargo can
// request Billington to action the waive by posting a GOGW (TypeId 61) for the
// amount in column H of the Waive Log, then a paired refund (TypeId 149),
// then adding the agreement to the close sheet under
// `escalation_asset_received`. Pre-flight: refuse if the customer is
// already in credit OR an asset-return / lost-in-transit / write-off
// closure has already been posted.

/**
 * Find the Waive Log row for an agreement and return column-H amount
 * (the "amount to waive"). Returns null if not found. Hargo, 27/05/2026.
 */
async function findWaiveLogRowForAgreement(agreementId) {
  const tab = await getWaiveLogTabName();
  const sheetRes = await sheetsClient.spreadsheets.values.get({
    spreadsheetId: WAIVE_LOG_SHEET_ID,
    range: `${tab}!A:L`,
  });
  const rows = sheetRes.data.values || [];
  const wanted = String(agreementId || "").trim().toUpperCase();
  // Walk bottom-up — most recent waive log row wins if there are duplicates.
  for (let i = rows.length - 1; i >= 1; i--) {
    const r = rows[i];
    const colA = (r[0] || "").trim().toUpperCase();
    if (colA !== wanted) continue;
    const rawH = (r[7] || "").toString().trim();
    const cleanedH = rawH.replace(/[£,\s]/g, "");
    const amountH = cleanedH ? Number(cleanedH) : NaN;
    return {
      rowNum: i + 1,
      agreementId: colA,
      waivedBy:    (r[1] || "").trim(),
      dateRaised:  (r[2] || "").trim(),
      reasonG:     (r[6] || "").trim(),
      rawAmountH:  rawH,
      amountH:     Number.isFinite(amountH) ? amountH : null,
      colIRaw:     (r[8] || "").trim(),
    };
  }
  return null;
}

/**
 * Pre-flight checks for a "waive paid damage fee" request:
 *   - Customer must NOT already be in credit (TotalArrears < 0 → refuse).
 *   - Agreement must NOT have a closure transaction already posted
 *     (TypeId 30 Asset Returned / 46 Lost in transit / 26 Write-off /
 *      70 Debt sale write-off → refuse "already settled").
 *   - Damage fee must have actually been collected (matches the
 *     "fee has now been confirmed collected" check Hargo already trusts).
 *
 * Returns { ok, reason, anchor } — anchor surfaced for the success-path
 * logging.
 */
async function evaluateWaivePaidDamageFeeSafety(agreementId) {
  // (1) Damage fee collected check — re-use the existing status evaluator.
  let status;
  try { status = await getDamageFeeStatus(agreementId); }
  catch (err) { return { ok: false, reason: `Couldn't read Anchor: ${err.message}` }; }
  if (!status.hasDamageFee) {
    return { ok: false, reason: "Anchor shows no damage fee on this agreement." };
  }
  if (status.status !== "paid_card" && status.status !== "paid_dd_confirmed") {
    return { ok: false, reason: `Damage fee is *not yet confirmed collected* (status=${status.status}). Waive-paid action is only valid once the fee has been collected.` };
  }
  // (2) TotalArrears credit check.
  let totalArrears;
  try { totalArrears = await getAgreementLiveTotalArrears(agreementId); }
  catch (err) { return { ok: false, reason: `Couldn't read TotalArrears: ${err.message}` }; }
  if (totalArrears !== null && totalArrears < -0.01) {
    return { ok: false, reason: `Refusing — agreement is already in credit (TotalArrears £${totalArrears.toFixed(2)}). Posting another GOGW + refund would over-credit the customer.` };
  }
  // (3) Closure transaction check.
  const CLOSURE_TXN_TYPE_IDS = [26, 30, 46, 70];
  let xml;
  try { xml = await getAgreementFromAnchor(agreementId); }
  catch (err) { return { ok: false, reason: `Couldn't read Anchor: ${err.message}` }; }
  const txContainer = (xml.match(/<(?:a:)?Transactions>([\s\S]*?)<\/(?:a:)?Transactions>/) || [])[1] || "";
  const txBlocks = txContainer.match(/<(?:a:)?Transaction>[\s\S]*?<\/(?:a:)?Transaction>/g) || [];
  for (const block of txBlocks) {
    const typeId = parseInt(((block.match(/<(?:a:)?TypeId>(\d+)</) || [])[1]) || "0", 10);
    if (CLOSURE_TXN_TYPE_IDS.includes(typeId)) {
      const date = ((block.match(/<(?:a:)?TransactionDate>([^<]+)</) || [])[1] || "").slice(0, 10);
      const desc = TRANSACTION_TYPES[typeId] || `TypeId ${typeId}`;
      return { ok: false, reason: `Refusing — agreement is already settled via *${desc}* (posted ${date}). Waive flow shouldn't run on closed agreements.` };
    }
  }
  return { ok: true, totalArrears, damageFeeAmount: status.damageFeeAmount };
}

/**
 * Execute the waive-paid-damage-fee chain for a single agreement:
 *   1. GOGW (TypeId 61) of column H amount
 *   2. Poll until live TotalArrears reflects the GOGW
 *   3. Refund (TypeId 149) of column H amount
 *   4. Append to close sheet under `escalation_asset_received`
 *
 * Caller is responsible for authorisation (REFUND_AUTHORISED_USERS) and
 * any channel gating. Returns a structured result.
 */
async function executeWaivePaidDamageFee(agreementId, auditCtx = {}) {
  // Reuse today's date in London for transaction posting + sheet write.
  const today = new Date().toLocaleDateString("en-CA", { timeZone: "Europe/London" });
  const result = {
    agreementId,
    waiveLogRow: null,
    safety: null,
    gogw:   { status: "pending", amount: null, error: null },
    refund: { status: "pending", amount: null, error: null },
    sheet:  { status: "pending", row: null, alreadyInSheet: false, error: null },
  };

  // 1. Find waive log row.
  result.waiveLogRow = await findWaiveLogRowForAgreement(agreementId);
  if (!result.waiveLogRow) {
    return { ...result, fatal: `No Waive Log row found for ${agreementId}.` };
  }

  // 2. Pre-flight safety checks (also returns the canonical Anchor damage-fee amount).
  result.safety = await evaluateWaivePaidDamageFeeSafety(agreementId);
  if (!result.safety.ok) {
    return { ...result, fatal: result.safety.reason };
  }

  // 2b. Determine the waive amount (Hargo, 29/05/2026):
  //   • Column H populated & valid → waive exactly £H (full OR partial).
  //   • Column H blank/invalid     → FULL waive: fall back to the canonical
  //     Anchor damage-fee amount (PaymentProfile sum == column L), per the
  //     rule "if column H is null, assume the full repair charge is waived".
  const feeDue = Number.isFinite(result.safety.damageFeeAmount) ? Number(result.safety.damageFeeAmount.toFixed(2)) : null;
  const hValid = Number.isFinite(result.waiveLogRow.amountH) && result.waiveLogRow.amountH > 0;
  let amount;
  let waiveBasis;
  if (hValid) {
    amount = Number(result.waiveLogRow.amountH.toFixed(2));
    waiveBasis = (feeDue && amount < feeDue - 0.01) ? "partial (column H)" : "full (column H)";
  } else if (feeDue && feeDue > 0) {
    amount = feeDue;
    waiveBasis = "full (column H blank → Anchor repair charge)";
  } else {
    return { ...result, fatal: `Waive Log row ${result.waiveLogRow.rowNum} for ${agreementId} has no valid amount in column H (got "${result.waiveLogRow.rawAmountH}") and Anchor shows no damage-fee amount to fall back on. Please populate column H first.` };
  }
  result.waiveBasis = waiveBasis;

  // Common audit fields shared across GOGW, refund, close-sheet, Waive Log row.
  // requestedBy = Waive Log col B "Waived by" (whoever flagged the row),
  // triggeredBy = the Slack user who asked Billington to action it.
  const baseAudit = {
    requestedBy: result.waiveLogRow.waivedBy || auditCtx.requestedBy || "",
    triggeredBy: auditCtx.triggeredBy || "",
    triggerSource: auditCtx.triggerSource || "",
    sourceLink: auditCtx.sourceLink || "",
  };

  // 3. Post GOGW (TypeId 61).
  const gogwNotes = `Waive Log: damage fee waiver — paired refund follows. Waive log row ${result.waiveLogRow.rowNum}.`;
  try {
    await addTransactionToAnchor(agreementId, today, amount, gogwNotes, 61, {
      ...baseAudit,
      actionType: "gogw_posted",
      description: `GOGW £${amount.toFixed(2)} posted for damage fee waive on ${agreementId} (Waive Log row ${result.waiveLogRow.rowNum})`,
      idempotencyKey: `gogw:${agreementId}:${gogwNotes}:${today}`,
    });
    result.gogw = { status: "posted", amount, error: null };
  } catch (err) {
    result.gogw = { status: "failed", amount, error: err.message };
    return { ...result, fatal: `GOGW post failed: ${err.message}` };
  }

  // 4. Poll for total_arrears to reflect the GOGW.
  const attempts = [0, 1000, 2000, 3000, 5000];
  let totalArrears = null;
  for (let i = 0; i < attempts.length; i++) {
    if (attempts[i] > 0) await new Promise(r => setTimeout(r, attempts[i]));
    try {
      totalArrears = await getAgreementLiveTotalArrears(agreementId);
      if (totalArrears !== null && totalArrears <= -(amount - 0.01)) break;
    } catch (_) { /* retry */ }
  }
  if (totalArrears === null || totalArrears > -(amount - 0.01)) {
    result.refund = { status: "skipped_polling_exhausted", amount, error: `live TotalArrears £${totalArrears === null ? "null" : totalArrears.toFixed(2)} didn't reach target £-${amount.toFixed(2)} after ~11s` };
    return { ...result, fatal: `GOGW posted but TotalArrears didn't reflect after retrying ~11s. Refund + sheet append NOT actioned — try the standalone refund (\`post refund £${amount.toFixed(2)} on ${agreementId}\`) once Anchor settles.` };
  }

  // 5. Post refund (TypeId 149).
  const refundNotes = `Waive Log: damage fee waiver refund — paired with GOGW. Waive log row ${result.waiveLogRow.rowNum}.`;
  try {
    await addTransactionToAnchor(agreementId, today, amount, refundNotes, 149, {
      ...baseAudit,
      actionType: "refund_posted",
      description: `Refund £${amount.toFixed(2)} posted (paired with GOGW) for damage fee waive on ${agreementId} (Waive Log row ${result.waiveLogRow.rowNum})`,
      idempotencyKey: `refund:${agreementId}:${refundNotes}:${today}`,
    });
    result.refund = { status: "posted", amount, error: null };
  } catch (err) {
    result.refund = { status: "failed", amount, error: err.message };
    return { ...result, fatal: `GOGW posted (£${amount.toFixed(2)}) but refund FAILED: ${err.message}. Retry the standalone refund command.` };
  }

  // 6. Append to close sheet under escalation_asset_received (column F).
  try {
    const write = await writeCloseAgreements([agreementId], WAIVE_LOG_CLOSE_REASON_KEY, {
      ...baseAudit,
      actionTypeSuffix: "waive_paid_damage_fee",
    });
    const wrote = (write.written || []).find(w => w.id === agreementId);
    const dup = (write.duplicates || []).some(d => String(d).toUpperCase() === agreementId.toUpperCase());
    result.sheet = { status: dup ? "already_in_sheet" : "added", row: wrote?.row || null, alreadyInSheet: dup, error: null };
  } catch (err) {
    result.sheet = { status: "failed", row: null, alreadyInSheet: false, error: err.message };
    return { ...result, fatal: `GOGW + refund posted (£${amount.toFixed(2)}) but close-sheet append FAILED: ${err.message}. Add manually.` };
  }

  // 7. Update the Waive Log row to reflect the action — tick column I,
  // write a Billington note in column K, refresh column J so it no longer
  // says "please action". Hargo, 27/05/2026.
  try {
    await markWaiveLogRowActioned({
      rowNum: result.waiveLogRow.rowNum,
      amount,
      gogwDate: today,
      closeSheetRow: result.sheet.row,
      alreadyInSheet: result.sheet.alreadyInSheet,
    });
    result.waiveLogUpdated = true;
    await logBillingtonAction({
      actionCategory: "sheet_write",
      actionType: "waive_log_actioned",
      agreementId,
      amountGbp: amount,
      status: "success",
      description: `Waive Log row ${result.waiveLogRow.rowNum} marked I=TRUE, J=success, K=audit note (GOGW £${amount.toFixed(2)} + refund £${amount.toFixed(2)} on ${today})`,
      requestedBy: baseAudit.requestedBy,
      triggeredBy: baseAudit.triggeredBy,
      triggerSource: baseAudit.triggerSource,
      sourceLink: baseAudit.sourceLink,
      targetSheetRow: `Waive Log!I${result.waiveLogRow.rowNum}`,
      idempotencyKey: `waive_log_actioned:${agreementId}:${result.waiveLogRow.rowNum}`,
    });
  } catch (err) {
    result.waiveLogUpdated = false;
    result.waiveLogUpdateError = err.message;
    console.error(`[bill-ling] waive paid damage fee: Waive Log row update failed for ${agreementId}:`, err.message);
    // Not fatal — Anchor + close sheet succeeded; sheet annotation is informational.
  }

  return { ...result, fatal: null };
}

/**
 * Mark a Waive Log row as actioned by Billington's waive-paid-damage-fee flow.
 * Hargo, 27/05/2026 — updates:
 *   I: TRUE (added to closure sheet — same convention as processWaiveLog)
 *   J: success message superseding the prior "please IGNORE" flag
 *   K: full audit note (GOGW + refund amounts, dates, close sheet row)
 *
 * Called after Anchor posts + close sheet write succeed. Sheet annotation
 * failures are NOT fatal to the overall action — surfaced separately.
 */
async function markWaiveLogRowActioned({ rowNum, amount, gogwDate, closeSheetRow, alreadyInSheet }) {
  const tab = await getWaiveLogTabName();
  const actionDate = new Date().toISOString().slice(0, 10);
  const noteK = `Damage fee waived by Billington on ${actionDate}. GOGW £${amount.toFixed(2)} (TypeId 61, ${gogwDate}) + paired refund £${amount.toFixed(2)} (TypeId 149, ${gogwDate}) posted in Anchor. ${alreadyInSheet ? "Agreement was already on the close sheet" : `Added to close sheet${closeSheetRow ? ` (row ${closeSheetRow})` : ""}`} under Escalation — Asset Received.`;
  const flagJ = `✅ Damage fee waived by Billington on ${actionDate} — GOGW + refund + close-sheet actioned. No further action needed.`;
  // Batch update all three cells in one call.
  await sheetsClient.spreadsheets.values.batchUpdate({
    spreadsheetId: WAIVE_LOG_SHEET_ID,
    requestBody: {
      valueInputOption: "USER_ENTERED",
      data: [
        { range: `${tab}!I${rowNum}`, values: [["TRUE"]] },
        { range: `${tab}!J${rowNum}`, values: [[flagJ]] },
        { range: `${tab}!K${rowNum}`, values: [[noteK]] },
      ],
    },
  });
  console.log(`[bill-ling] Waive Log row ${rowNum}: marked I=TRUE, K=note, J=success.`);
}

// ─────────────────────────────────────────────────────────────────────────
// Billington Audit Log (Hargo, 27/05/2026)
// ─────────────────────────────────────────────────────────────────────────
// One append-only row per ACTUAL completed write action.
//
// Explicitly EXCLUDED:
//   • dry runs (e.g. Late Fee Waive recommendations)
//   • drafts (e.g. iOutlet email drafts)
//   • Slack writes (chat.postMessage, reactions, etc.)
//
// Sheet: https://docs.google.com/spreadsheets/d/18E7XWNue0iVybvYCAdFYt-26ye9gVHAVS_OUQLl868s
// Tab: audit_log (gid=0)
//
// Slack user_id → display name resolution is cached in-memory so we don't
// hammer users.info on every audit write.
// ─────────────────────────────────────────────────────────────────────────
const AUDIT_LOG_SHEET_ID = "18E7XWNue0iVybvYCAdFYt-26ye9gVHAVS_OUQLl868s";
const AUDIT_LOG_TAB = "audit_log";
const AUDIT_LOG_REVISION = process.env.K_REVISION || process.env.CLOUD_RUN_REVISION || "local";

// In-memory cache: Slack user_id → display name. Refreshed lazily.
const auditUserNameCache = new Map();
async function resolveSlackDisplayName(userId) {
  if (!userId || typeof userId !== "string") return "";
  if (!/^U[A-Z0-9]+$/.test(userId)) return userId; // already a name, not an id
  if (auditUserNameCache.has(userId)) return auditUserNameCache.get(userId);
  try {
    const info = await app.client.users.info({ token: SLACK_BOT_TOKEN, user: userId });
    const name = info.user?.profile?.real_name || info.user?.profile?.display_name || info.user?.name || userId;
    auditUserNameCache.set(userId, name);
    return name;
  } catch (_) {
    auditUserNameCache.set(userId, userId);
    return userId;
  }
}

/**
 * Log a single Billington action to the audit sheet.
 *
 * @param {Object} opts
 * @param {string} opts.actionCategory     "anchor_transaction" | "anchor_payment_profile" | "sheet_write" | "email_sent" | "gmail_label"
 * @param {string} opts.actionType          e.g. "gogw_posted" / "refund_posted" / "close_sheet_added"
 * @param {string} [opts.agreementId]
 * @param {number} [opts.anchorTypeId]
 * @param {number} [opts.amountGbp]         Signed: positive = credit to customer, negative = debit
 * @param {string} [opts.reference]         Transaction reference / sheet column / email subject
 * @param {string} [opts.status]            "success" (default) | "partial" | "error" | "skipped"
 * @param {string} opts.description         Human-readable summary
 * @param {string} [opts.requestedBy]       Staff member who originated the request (display name)
 * @param {string} [opts.requestedByUserId] If we only have a Slack user_id, we'll resolve
 * @param {string} [opts.triggeredBy]       Slack user_id, "cron:waive_log", "event:gmail_reply", etc.
 * @param {string} [opts.triggerSource]     "slack_mention" | "dm" | "cron" | "event:..."
 * @param {string} [opts.sourceLink]        Slack message permalink, etc.
 * @param {string} [opts.targetSheetRow]    e.g. "agreements_to_close!A2143"
 * @param {string} [opts.errorMessage]      Only when status ≠ "success"
 * @param {string} [opts.idempotencyKey]    Recommended — prevents duplicate logs on retry
 */
async function logBillingtonAction(opts) {
  try {
    // ── Hard exclusions per Hargo's spec: no dry runs, drafts, or Slack writes ──
    if (!opts || !opts.actionCategory) return;
    if (opts.status === "dry_run") return;
    if (opts.actionCategory === "slack_post") return;
    if (opts.actionCategory === "draft") return;
    if (opts.actionType && /\b(dry_run|draft|preview|simulate)\b/i.test(opts.actionType)) return;

    // Resolve requested_by to a display name if we only have an id
    let requestedBy = opts.requestedBy || "";
    if (!requestedBy && opts.requestedByUserId) {
      requestedBy = await resolveSlackDisplayName(opts.requestedByUserId);
    }
    // Resolve triggered_by to a display name when it looks like a Slack user_id
    let triggeredByDisplay = opts.triggeredBy || "";
    if (triggeredByDisplay && /^U[A-Z0-9]+$/.test(triggeredByDisplay)) {
      const name = await resolveSlackDisplayName(triggeredByDisplay);
      triggeredByDisplay = `${name} (${opts.triggeredBy})`;
    }

    const now = new Date();
    const utcIso = now.toISOString();
    const londonStr = now.toLocaleString("en-GB", {
      timeZone: "Europe/London",
      day: "2-digit", month: "2-digit", year: "numeric",
      hour: "2-digit", minute: "2-digit", second: "2-digit",
    });

    const row = [
      utcIso,
      londonStr,
      opts.actionCategory || "",
      opts.actionType || "",
      opts.agreementId || "",
      opts.anchorTypeId != null ? String(opts.anchorTypeId) : "",
      opts.amountGbp != null && Number.isFinite(opts.amountGbp) ? opts.amountGbp.toFixed(2) : "",
      opts.reference || "",
      opts.status || "success",
      opts.description || "",
      requestedBy || "",
      triggeredByDisplay || "",
      opts.triggerSource || "",
      opts.sourceLink || "",
      opts.targetSheetRow || "",
      opts.errorMessage || "",
      opts.idempotencyKey || "",
      AUDIT_LOG_REVISION,
    ];

    // Append (don't overwrite). Use USER_ENTERED so timestamp formatting works
    // if the user changes col A/B format later.
    await sheetsClient.spreadsheets.values.append({
      spreadsheetId: AUDIT_LOG_SHEET_ID,
      range: `${AUDIT_LOG_TAB}!A:R`,
      valueInputOption: "USER_ENTERED",
      insertDataOption: "INSERT_ROWS",
      requestBody: { values: [row] },
    });
  } catch (err) {
    // NEVER let an audit failure crash the actual operation.
    console.error("[bill-ling] logBillingtonAction failed:", err.message, "opts:", JSON.stringify({
      cat: opts?.actionCategory, type: opts?.actionType, agr: opts?.agreementId, status: opts?.status,
    }));
  }
}

/**
 * Build a Slack message permalink from channel + ts.
 * Returns "" if either is missing.
 */
async function buildSlackPermalink(channel, ts) {
  if (!channel || !ts) return "";
  try {
    const r = await app.client.chat.getPermalink({ token: SLACK_BOT_TOKEN, channel, message_ts: ts });
    return r.permalink || "";
  } catch (_) {
    return "";
  }
}

// ─────────────────────────────────────────────────────────────────────────
// Late Fee Waive — DRY RUN workflow (Hargo, 27/05/2026)
// ─────────────────────────────────────────────────────────────────────────
// Reads the "Late Fee Waiver Request Form" responses sheet, finds rows
// timestamped TODAY (London), and recommends Anchor TypeId 50 reversals
// for non-waived late fees on each agreement.
//
// Sheet columns (responses tab, gid=1900804404):
//   A: Timestamp (DD/MM/YYYY HH:MM:SS)
//   B: Email address (requester)
//   C: agreement_id
//   D: number_of_fees_to_waive
//   F: execution_reference
//   G: ranked
//   H: cancellation_reversal  ← skip if truthy
//   I: billington_notes        ← we write recommendations here
//   J: billington_waived       ← only set TRUE in live mode (NOT in dry run)
//   K: waived_amount
//
// Anchor:
//   TypeId 49 = late fee (negative amount, ref e.g. "LPF-A00X-YYYY-MM-DD")
//   TypeId 50 = late fee reversal (positive amount)
//
// Matching late fees → reversals:
//   1. Direct reference match: reversal.Reference contains late fee's Reference
//   2. Otherwise count-based: top-K most-recent late fees are attributed to
//      the K reversals on the agreement (covers human "1st/2nd fee waived" posts)
//
// Recommendation: take the top N still-active late fees (most recent first)
// where N = number_of_fees_to_waive. If already waived ≥ N, no action.
//
// Output: DM Hargo + write to billington_notes column (I). NO Anchor posts yet.
// ─────────────────────────────────────────────────────────────────────────
const LATE_FEE_WAIVE_SHEET_ID = "1FD14JB-mXMoNKOBDMjZf3tW9gUSKtUj9tMFOFsoJ3Qw";
const LATE_FEE_WAIVE_TAB_GID = 1900804404;
let LATE_FEE_WAIVE_TAB_CACHE = null;

// Hargo, 29/05/2026: disabled. Cron + on-demand triggers both gated by this
// flag. Flip back to `true` to re-enable.
const LATE_FEE_WAIVE_DRY_RUN_ENABLED = false;

// Per-row dedup so we don't spam Hargo's DM every hour.
const LATE_FEE_WAIVE_REPORTED_FILE = require("path").join(__dirname, "late-fee-waive-reported.json");
const LATE_FEE_WAIVE_REPORTED_GCS_KEY = "late-fee-waive-reported.json";
let lateFeeWaiveReported = new Map(); // rowNum (string) → "YYYY-MM-DD"

function loadLateFeeWaiveReportedLocal() {
  try {
    if (fs.existsSync(LATE_FEE_WAIVE_REPORTED_FILE)) {
      const data = JSON.parse(fs.readFileSync(LATE_FEE_WAIVE_REPORTED_FILE, "utf8"));
      lateFeeWaiveReported = new Map(Object.entries(data.entries || {}));
      console.log(`[bill-ling] Loaded ${lateFeeWaiveReported.size} late-fee-waive-reported entries from local.`);
    }
  } catch (err) {
    console.error("[bill-ling] late-fee-waive-reported local load failed:", err.message);
  }
}
async function loadLateFeeWaiveReportedGcs() {
  try {
    const data = await loadJsonFromGcs(LATE_FEE_WAIVE_REPORTED_GCS_KEY);
    if (data?.entries) {
      for (const [k, v] of Object.entries(data.entries)) lateFeeWaiveReported.set(k, v);
      console.log(`[bill-ling] Loaded late-fee-waive-reported from GCS; total now ${lateFeeWaiveReported.size}.`);
    }
  } catch (err) {
    console.warn("[bill-ling] late-fee-waive-reported GCS load failed:", err.message);
  }
}
async function saveLateFeeWaiveReportedAsync() {
  const payload = { entries: Object.fromEntries(lateFeeWaiveReported) };
  try { fs.writeFileSync(LATE_FEE_WAIVE_REPORTED_FILE, JSON.stringify(payload, null, 2)); } catch (_) {}
  try { await saveJsonToGcs(LATE_FEE_WAIVE_REPORTED_GCS_KEY, payload); }
  catch (err) { console.error("[bill-ling] saveLateFeeWaiveReportedAsync GCS failed:", err.message); }
}
loadLateFeeWaiveReportedLocal();
loadLateFeeWaiveReportedGcs();

async function getLateFeeWaiveTabName() {
  if (LATE_FEE_WAIVE_TAB_CACHE) return LATE_FEE_WAIVE_TAB_CACHE;
  const meta = await sheetsClient.spreadsheets.get({
    spreadsheetId: LATE_FEE_WAIVE_SHEET_ID,
    fields: "sheets(properties(sheetId,title))",
  });
  const sheet = (meta.data.sheets || []).find(s => s.properties.sheetId === LATE_FEE_WAIVE_TAB_GID);
  LATE_FEE_WAIVE_TAB_CACHE = sheet?.properties?.title || "responses";
  return LATE_FEE_WAIVE_TAB_CACHE;
}

/**
 * Determine which late fees on an agreement are already waived vs still active.
 *
 * Returns: {
 *   lateFees: [{ date, amount, reference }]  // sorted DESC by date
 *   reversals: [{ date, amount, reference }],
 *   active: [...],                              // late fees needing reversal
 *   waived: [...],                              // late fees with a matched reversal
 *   reversalsToday: [...],                       // reversals dated today (London)
 *   settlementTransactions: [...],               // any TypeId in ANCHOR_SETTLEMENT_TYPE_IDS
 * }
 */

// Anchor TypeIds where Settlement Transaction = Yes
// (per https://www.notion.so/Anchor-Transaction-Types-33a5bb4b4a65814684d7d4b69779bc13)
// Presence of any of these on an agreement → late fees must NOT be waived.
//   26 Write-off
//   28 Non-return fee (Card)
//   29 FPC payment (legacy, inactive)
//   30 Asset returned
//   34 Asset purchased
//   45 Raylo payment
//   46 Asset lost in transit
//   70 Debt sale write-off
//   71 Debt sale write-off reversal
//   76 Asset rehired
const ANCHOR_SETTLEMENT_TYPE_IDS = new Set([26, 28, 29, 30, 34, 45, 46, 70, 71, 76]);

/**
 * Pre-flight exclusion list (Hargo, 27/05/2026): any agreement that appears
 * in `agreement_settlement_dates` (already settled) or `pending_cancellations`
 * (in the cancellation workflow) must NOT have late fees reversed via the
 * dry-run / live workflow. Returns a Set of upper-cased agreement IDs.
 *
 * Each query is wrapped in its own try/catch so a permission failure on one
 * view doesn't sink the other. Failures are logged so they can be remediated.
 */
async function getLateFeeWaiveExclusionSet() {
  const excluded = new Set();
  const errors = [];
  // Hargo, 27/05/2026: settlement-status is determined per-agreement via
  // Anchor transactions (TypeIds in ANCHOR_SETTLEMENT_TYPE_IDS) at recommend
  // time. The "pending cancellation" exclusion uses the BQ
  // landing_billington.pending_cancellations view, which joins to Sheets-
  // backed external tables in landing_google_sheets — so we MUST use the
  // Drive-scoped REST helper here, not the default bigquery client.
  try {
    const rows = await runBigQueryDriveBackedQuery(
      "SELECT agreement_id FROM `raylo-production.landing_billington.pending_cancellations`",
      "EU"
    );
    let added = 0;
    for (const r of rows) {
      const id = (r.agreement_id || "").toString().trim().toUpperCase();
      if (id) { excluded.add(id); added++; }
    }
    console.log(`[bill-ling] Late Fee Waive exclusion: pending_cancellations → ${added} agreement_ids`);
  } catch (err) {
    console.error(`[bill-ling] Late Fee Waive exclusion query failed (pending_cancellations): ${err.message}`);
    errors.push({ label: "pending_cancellations", error: err.message });
  }
  return { excluded, errors };
}

async function getLateFeeWaiveStatus(agreementId) {
  const xml = await getAgreementFromAnchor(agreementId);
  const txContainer = (xml.match(/<(?:a:)?Transactions>([\s\S]*?)<\/(?:a:)?Transactions>/) || [, ""])[1];
  const txBlocks = txContainer.match(/<(?:a:)?Transaction>[\s\S]*?<\/(?:a:)?Transaction>/g) || [];

  const tag = (b, n) => {
    const m = b.match(new RegExp(`<(?:a:)?${n}>([^<]*)</(?:a:)?${n}>`));
    return m ? m[1] : null;
  };

  const lateFees = [];
  const reversals = [];
  const settlementTransactions = [];
  for (const b of txBlocks) {
    const typeId = parseInt(tag(b, "TypeId") || "0", 10);
    // Track any settlement-flagged transactions (write-off, asset return,
    // asset purchase, debt sale, etc.) so we can exclude the agreement.
    if (ANCHOR_SETTLEMENT_TYPE_IDS.has(typeId)) {
      settlementTransactions.push({
        typeId,
        date: (tag(b, "TransactionDate") || "").slice(0, 10),
        amount: parseFloat(tag(b, "Gross") || "0"),
        reference: tag(b, "Reference") || "",
      });
    }
    if (typeId !== 49 && typeId !== 50) continue;
    const obj = {
      typeId,
      date: (tag(b, "TransactionDate") || "").slice(0, 10),
      amount: parseFloat(tag(b, "Gross") || "0"),
      reference: tag(b, "Reference") || "",
    };
    if (typeId === 49) lateFees.push(obj);
    else reversals.push(obj);
  }

  lateFees.sort((a, b) => b.date.localeCompare(a.date)); // DESC by date
  reversals.sort((a, b) => b.date.localeCompare(a.date));

  // Mark which late fees are already waived.
  // Pass 1: direct reference match — reversal.Reference contains late fee's Reference
  //         (Billington's own posts will use this convention).
  // Pass 2: date-based attribution — each unmatched reversal claims the MOST
  //         RECENT unmatched late fee dated ON OR BEFORE the reversal's date.
  //         Reversals processed in ASC order so earliest reversal claims
  //         earliest eligible (oldest-first principle for "1st fee waived").
  const reversalUsed = new Set();
  for (let i = 0; i < lateFees.length; i++) {
    const lf = lateFees[i];
    if (!lf.reference) continue;
    for (let j = 0; j < reversals.length; j++) {
      if (reversalUsed.has(j)) continue;
      const rev = reversals[j];
      if (rev.reference && rev.reference.includes(lf.reference)) {
        lf.matchedReversal = rev;
        reversalUsed.add(j);
        break;
      }
    }
  }
  // Pass 2: date-based attribution. Process reversals oldest-first; each
  // claims the most recent unmatched late fee on-or-before its date.
  const reversalsAsc = reversals
    .map((r, idx) => ({ r, idx }))
    .filter(({ idx }) => !reversalUsed.has(idx))
    .sort((a, b) => a.r.date.localeCompare(b.r.date));
  for (const { r: rev, idx: j } of reversalsAsc) {
    for (let i = 0; i < lateFees.length; i++) { // DESC order — first hit = most recent
      if (lateFees[i].matchedReversal) continue;
      if (lateFees[i].date > rev.date) continue; // skip late fees AFTER the reversal
      lateFees[i].matchedReversal = rev;
      reversalUsed.add(j);
      break;
    }
  }
  // Fallback (rare): any reversal that couldn't be attributed by date
  // (e.g. a reversal posted BEFORE any late fee — shouldn't happen, but
  // guard against malformed data) claims the most recent unmatched late
  // fee regardless of date.
  for (let j = 0; j < reversals.length; j++) {
    if (reversalUsed.has(j)) continue;
    for (let i = 0; i < lateFees.length; i++) {
      if (lateFees[i].matchedReversal) continue;
      lateFees[i].matchedReversal = reversals[j];
      reversalUsed.add(j);
      break;
    }
  }

  const todayIso = new Date().toLocaleDateString("en-CA", { timeZone: "Europe/London" });
  const reversalsToday = reversals.filter(r => r.date === todayIso);
  const waived = lateFees.filter(lf => lf.matchedReversal);
  const active = lateFees.filter(lf => !lf.matchedReversal);

  return { lateFees, reversals, waived, active, reversalsToday, settlementTransactions };
}

/**
 * Build a recommendation for one sheet row.
 *
 * Algorithm (Hargo, 27/05/2026):
 *   • TODAY vs TODAY check: if reversals_today_count ≥ number_to_waive AND
 *     reversals_today_amount ≥ requested_amount → already fulfilled today,
 *     no action.
 *   • Otherwise compute need_today = number_to_waive - reversals_today_count.
 *   • Cap by total eligible count = (count of TypeId 49) - (count of TypeId 50,
 *     all-time, attributed to specific late fees) — i.e. active fees.
 *   • Take the top N most-recent active late fees.
 *   • If actual < need_today, status = "capped" (request exceeds eligible).
 *
 * Returns: {
 *   row: { rowNum, agreementId, numberToWaive, requesterEmail, ... },
 *   status: 'recommend' | 'fulfilled_today' | 'capped' | 'no_eligible' |
 *           'no_late_fees' | 'error',
 *   toReverse: [{ date, amount, reference }],  // recommended reversals
 *   reversalsTodayCount: number,
 *   reversalsTodayAmount: number,
 *   amountRequested: number,
 *   activeCount: number,                       // total eligible (max)
 *   noteForSheet: string,                       // → goes in column I
 *   error?: string,
 * }
 */

/**
 * Return the canonical `LPF-{agreement_id}-YYYY-MM-DD` reference for a
 * late fee. If the late fee's own Reference is already in that format we
 * preserve it; otherwise we synthesise one from the agreement ID and
 * (late fee date - 1 day) — matches the convention that LPF refs encode
 * the original missed-payment date (one day before the fee is posted).
 *
 * Hargo, 28/05/2026: legacy fees with refs like "1 Payment Missed (£29 LPF
 * trigger)" or "2 Payments Missed (£29 LPF trigger)" must NOT be used
 * verbatim as reversal references — they don't include the agreement ID
 * or a date. Normalising them keeps the audit trail consistent.
 */
function buildLpfReversalRef(agreementId, lateFee) {
  const id = (agreementId || "").toString().trim().toUpperCase();
  const ref = (lateFee?.reference || "").trim();
  const lfDate = (lateFee?.date || "").trim(); // YYYY-MM-DD
  const standardPattern = new RegExp(`^LPF-${id}-\\d{4}-\\d{2}-\\d{2}$`, "i");
  if (standardPattern.test(ref)) return ref;
  // Synthesise: ref date = late fee TransactionDate - 1 day (LPF convention).
  if (/^\d{4}-\d{2}-\d{2}$/.test(lfDate)) {
    const d = new Date(`${lfDate}T00:00:00Z`);
    if (!Number.isNaN(d.getTime())) {
      d.setUTCDate(d.getUTCDate() - 1);
      const refDate = d.toISOString().slice(0, 10);
      return `LPF-${id}-${refDate}`;
    }
  }
  // Last-resort fallback — should never reach here for a real late fee.
  return `LPF-${id}-${lfDate || "unknown-date"}`;
}

async function buildLateFeeWaiveRecommendation(row) {
  const todayIso = new Date().toISOString().slice(0, 10);
  try {
    const st = await getLateFeeWaiveStatus(row.agreementId);

    // Hargo, 27/05/2026: if Anchor shows any "Settlement Transaction" (per
    // the Notion Anchor Transaction Types table) on this agreement, do NOT
    // recommend any reversal — the agreement is settled / asset returned /
    // written off / etc.
    if (st.settlementTransactions && st.settlementTransactions.length > 0) {
      const summary = st.settlementTransactions
        .slice()
        .sort((a, b) => b.date.localeCompare(a.date))
        .map(t => `TypeId ${t.typeId} on ${t.date}`)
        .join(", ");
      return {
        row,
        status: "excluded_settled",
        toReverse: [],
        todayMatchedPairs: [],
        reversalsTodayCount: 0,
        reversalsTodayAmount: 0,
        amountRequested: 0,
        activeCount: 0,
        settlementTransactions: st.settlementTransactions,
        noteForSheet:
          `DRY RUN (${todayIso}): Excluded — agreement has settlement transaction(s) on Anchor (${summary}). ` +
          `Late fees not waived on settled / written-off / returned / repurchased / etc. agreements.`,
      };
    }

    if (st.lateFees.length === 0) {
      return {
        row,
        status: "no_late_fees",
        toReverse: [],
        reversalsTodayCount: 0,
        reversalsTodayAmount: 0,
        amountRequested: 0,
        activeCount: 0,
        noteForSheet: `DRY RUN (${todayIso}): No late fee transactions (TypeId 49) found on Anchor. Nothing to reverse.`,
      };
    }

    // Today's progress: how many reversals already posted today + their sum.
    const reversalsTodayCount = st.reversalsToday.length;
    const reversalsTodayAmount = st.reversalsToday.reduce((s, r) => s + Math.abs(r.amount), 0);

    // Amount requested today: number_to_waive × the typical late fee amount
    // on this agreement (use the most recent late fee's amount — historically
    // £29 for current pricing, £19/£12 for older proposals).
    const typicalLateFeeAmount = st.lateFees.length > 0 ? Math.abs(st.lateFees[0].amount) : 0;
    const amountRequested = row.numberToWaive * typicalLateFeeAmount;

    // Build "today's matched late fees" — for each reversal posted today,
    // find the late fee it was attributed to. Used in the digest so Hargo
    // can confirm exactly which late fee was waived + the reversal ref used.
    const todayMatchedPairs = []; // { lateFee, reversal }
    for (const lf of st.lateFees) {
      if (lf.matchedReversal && st.reversalsToday.includes(lf.matchedReversal)) {
        todayMatchedPairs.push({ lateFee: lf, reversal: lf.matchedReversal });
      }
    }

    // ── TODAY vs TODAY check ──
    // If we've already posted ≥ N reversals today AND the £ amount matches
    // or exceeds the requested amount, the request is fulfilled.
    if (reversalsTodayCount >= row.numberToWaive && reversalsTodayAmount >= amountRequested - 0.01) {
      const fulfilledLines = todayMatchedPairs.map((p, i) =>
        `${i + 1}. waived £${Math.abs(p.lateFee.amount).toFixed(2)} late fee from ${p.lateFee.date} (ref ${p.lateFee.reference || "(no ref)"}) via reversal posted ${p.reversal.date} ref "${p.reversal.reference || "(no ref)"}"`
      ).join("; ");
      return {
        row,
        status: "fulfilled_today",
        toReverse: [],
        todayMatchedPairs,
        reversalsTodayCount,
        reversalsTodayAmount,
        amountRequested,
        activeCount: st.active.length,
        noteForSheet:
          `DRY RUN (${todayIso}): Request fulfilled TODAY — ${reversalsTodayCount} reversal${reversalsTodayCount === 1 ? "" : "s"} ` +
          `posted today on Anchor totalling £${reversalsTodayAmount.toFixed(2)} ` +
          `(requested: ${row.numberToWaive} × £${typicalLateFeeAmount.toFixed(2)} = £${amountRequested.toFixed(2)}). No action needed.` +
          (fulfilledLines ? ` Matched: ${fulfilledLines}.` : ""),
      };
    }

    // Need to add more reversals today.
    const needToday = row.numberToWaive - reversalsTodayCount;
    // Cap by total active count (can't reverse what's already reversed).
    const actual = Math.min(needToday, st.active.length);

    if (actual === 0) {
      return {
        row,
        status: "no_eligible",
        toReverse: [],
        todayMatchedPairs,
        reversalsTodayCount,
        reversalsTodayAmount,
        amountRequested,
        activeCount: st.active.length,
        noteForSheet:
          `DRY RUN (${todayIso}): No active late fees left to reverse. ` +
          `Requested ${row.numberToWaive}, ${reversalsTodayCount} already reversed today, ` +
          `${st.waived.length} reversed historically (all ${st.lateFees.length} late fees attributed). ` +
          `No further reversal possible — request exceeds eligible amount.`,
      };
    }

    // Take the top N most-recent active late fees (most recent first).
    // Normalise the reversal reference per Hargo, 28/05/2026 — legacy refs
    // like "1 Payment Missed (£29 LPF trigger)" don't carry the agreement
    // ID or date, so we synthesise an LPF-A00X-YYYY-MM-DD ref from the
    // late fee's TransactionDate. `reversalRef` is what we'll send to
    // Anchor on the live post; `lf.reference` is the original raw value.
    const toReverse = st.active.slice(0, actual).map(lf => ({
      ...lf,
      reversalRef: buildLpfReversalRef(row.agreementId, lf),
    }));
    const status = actual < needToday ? "capped" : "recommend";

    // Hargo, 27/05/2026: each line shows "post today, reverses late fee
    // from X" rather than "£29 on X" — the original-fee date is shown for
    // context but the post date is always today.
    // Hargo, 28/05/2026: always show the normalised reversalRef (not the
    // raw late-fee Reference) since that's what Billington will post.
    const recLines = toReverse.map((lf, i) =>
      `${i + 1}. +£${Math.abs(lf.amount).toFixed(2)}, ref ${lf.reversalRef} (reverses late fee originally posted ${lf.date}${lf.reference && lf.reference !== lf.reversalRef ? `, original ref "${lf.reference}"` : ""})`
    ).join("; ");

    const noteForSheet =
      `DRY RUN (${todayIso}): ` +
      `Recommend posting ${toReverse.length} reversal${toReverse.length === 1 ? "" : "s"} TODAY (${todayIso}) ` +
      `(TypeId 50, positive amount, ref = late fee's ref). ` +
      (reversalsTodayCount > 0
        ? `Already today: ${reversalsTodayCount} reversal${reversalsTodayCount === 1 ? "" : "s"} = £${reversalsTodayAmount.toFixed(2)}. `
        : "") +
      (status === "capped"
        ? `Capped: requested ${row.numberToWaive} but only ${st.active.length} active fee${st.active.length === 1 ? "" : "s"} remaining (need_today=${needToday}, eligible_max=${st.active.length}). `
        : "") +
      `Recommendations: ${recLines}.`;

    return {
      row,
      status,
      toReverse,
      todayMatchedPairs,
      reversalsTodayCount,
      reversalsTodayAmount,
      amountRequested,
      activeCount: st.active.length,
      noteForSheet,
    };
  } catch (err) {
    return {
      row,
      status: "error",
      toReverse: [],
      reversalsTodayCount: 0,
      reversalsTodayAmount: 0,
      amountRequested: 0,
      activeCount: 0,
      noteForSheet: `DRY RUN (${new Date().toISOString().slice(0, 10)}): Anchor read failed — ${err.message}`,
      error: err.message,
    };
  }
}

/**
 * End-to-end: read today's eligible rows from the responses sheet, build
 * recommendations for each, write notes to billington_notes column (I),
 * return aggregated result for the DM digest.
 *
 * Dedup: per-row, per-day. A row that has already been DM-reported today
 * is processed (notes refreshed) but excluded from the new-recommendations
 * payload returned for the digest.
 */
async function processLateFeeWaiveDryRun({ force = false } = {}) {
  const tab = await getLateFeeWaiveTabName();
  const sheetRes = await sheetsClient.spreadsheets.values.get({
    spreadsheetId: LATE_FEE_WAIVE_SHEET_ID,
    range: `${tab}!A:K`,
  });
  const rows = sheetRes.data.values || [];

  const today = new Date().toLocaleDateString("en-GB", { timeZone: "Europe/London" }); // DD/MM/YYYY
  const todayIso = new Date().toLocaleDateString("en-CA", { timeZone: "Europe/London" }); // YYYY-MM-DD

  // Build the list of today's eligible candidates.
  // Hargo, 27/05/2026: column G ("ranked") deduplicates same-day requests
  // for the same agreement — only rank=1 is processed, higher ranks are
  // tagged as duplicates and get a clear note in billington_notes (col I).
  const candidates = [];
  const duplicateRows = []; // rank > 1 rows for today
  const skipped = { not_today: 0, bad_format: 0, cancellation: 0, already_waived: 0, not_rank_1: 0, already_processed: 0 };
  // Marker string that means a row already has TODAY's dry-run note in col I.
  // We check the prefix against this so any earlier dry-run run today
  // (recommendation, duplicate, capped, etc.) is treated as "processed".
  const todayProcessedMarker = `DRY RUN (${todayIso})`;
  for (let i = 1; i < rows.length; i++) {
    const r = rows[i];
    const colA = (r[0] || "").trim();
    const colB = (r[1] || "").trim();
    const colC = (r[2] || "").trim().toUpperCase();
    const colD = (r[3] || "").trim();
    const colF = (r[5] || "").trim();
    const colG = (r[6] || "").trim();
    const colH = (r[7] || "").trim();
    const colI = (r[8] || "").trim();
    const colJ = (r[9] || "").trim().toUpperCase();
    const rowNum = i + 1;

    if (!colA.startsWith(today)) { skipped.not_today++; continue; }
    if (!colC || !/^A\d{4,9}$/i.test(colC)) { skipped.bad_format++; continue; }
    const n = parseInt(colD, 10);
    if (!Number.isFinite(n) || n < 1) { skipped.bad_format++; continue; }

    if (colH && colH.toUpperCase() !== "FALSE") { skipped.cancellation++; continue; }
    if (colJ === "TRUE") { skipped.already_waived++; continue; }

    // Hargo, 27/05/2026: skip rows that already have today's dry-run note in
    // billington_notes (col I). Prevents redundant Anchor lookups and
    // sheet rewrites on subsequent hourly runs.
    if (colI.startsWith(todayProcessedMarker)) {
      skipped.already_processed++;
      continue;
    }

    // Skip duplicate requests for the same agreement — only rank=1 wins.
    // Treat blank G as rank=1 (defensive for older rows that pre-date the
    // ranking column, or rows where the formula hasn't filled).
    const rank = colG === "" ? 1 : parseInt(colG, 10);
    if (Number.isFinite(rank) && rank !== 1) {
      skipped.not_rank_1++;
      duplicateRows.push({ rowNum, agreementId: colC, rank, requesterEmail: colB });
      continue;
    }

    candidates.push({
      rowNum,
      timestamp: colA,
      requesterEmail: colB,
      agreementId: colC,
      numberToWaive: n,
      executionReference: colF,
      rank: rank,
    });
  }

  // Pre-flight exclusion: fetch agreements that are settled or pending
  // cancellation — these must NOT have late fees reversed.
  const { excluded: excludedSet, errors: exclusionErrors } = await getLateFeeWaiveExclusionSet();

  const recommendations = [];
  const newForDm = []; // rows not yet reported today
  for (const row of candidates) {
    let rec;
    if (excludedSet.has(row.agreementId)) {
      rec = {
        row,
        status: "excluded",
        toReverse: [],
        todayMatchedPairs: [],
        reversalsTodayCount: 0,
        reversalsTodayAmount: 0,
        amountRequested: 0,
        activeCount: 0,
        noteForSheet:
          `DRY RUN (${todayIso}): Excluded — agreement is on the pending-cancellations list. ` +
          `Late fee reversals are NOT recommended for cancelling agreements.`,
      };
    } else {
      rec = await buildLateFeeWaiveRecommendation(row);
    }
    recommendations.push(rec);

    // Dedup: only include in DM digest if not yet reported today.
    const lastReported = lateFeeWaiveReported.get(String(row.rowNum));
    if (force || lastReported !== todayIso) {
      newForDm.push(rec);
      lateFeeWaiveReported.set(String(row.rowNum), todayIso);
    }
  }

  // ── Add duplicate notes for rank > 1 rows so the sheet is unambiguous ──
  // Hargo, 27/05/2026: each duplicate row gets a clear "DUPLICATE" note in
  // billington_notes so stale recommendations from previous runs don't
  // linger.
  for (const dup of duplicateRows) {
    recommendations.push({
      row: {
        rowNum: dup.rowNum,
        agreementId: dup.agreementId,
        requesterEmail: dup.requesterEmail,
        numberToWaive: 0,
        rank: dup.rank,
      },
      status: "duplicate_today",
      toReverse: [],
      todayMatchedPairs: [],
      reversalsTodayCount: 0,
      reversalsTodayAmount: 0,
      amountRequested: 0,
      activeCount: 0,
      noteForSheet:
        `DRY RUN (${todayIso}): DUPLICATE — ${dup.agreementId} already requested today by another submitter (this is rank ${dup.rank}; only rank 1 is processed). No action.`,
    });
  }

  // ── Batch write all billington_notes (column I) in ONE API call ──
  // Hargo, 27/05/2026: with 100+ rows we hit Sheets API quota (60 writes/
  // min/user) if we write each row individually. batchUpdate collapses N
  // writes into 1 request — but we still chunk to be safe.
  if (recommendations.length > 0) {
    const dataPerCall = 100; // single batchUpdate can contain many ranges
    for (let i = 0; i < recommendations.length; i += dataPerCall) {
      const chunk = recommendations.slice(i, i + dataPerCall);
      const data = chunk.map(rec => ({
        range: `${tab}!I${rec.row.rowNum}`,
        values: [[rec.noteForSheet]],
      }));
      try {
        await sheetsClient.spreadsheets.values.batchUpdate({
          spreadsheetId: LATE_FEE_WAIVE_SHEET_ID,
          requestBody: { valueInputOption: "USER_ENTERED", data },
        });
      } catch (err) {
        console.error(`[bill-ling] Late Fee Waive: batchUpdate of ${chunk.length} notes failed:`, err.message);
      }
    }
  }

  if (newForDm.length > 0) {
    await saveLateFeeWaiveReportedAsync();
  }

  return {
    recommendations,
    newForDm,
    skipped,
    exclusionErrors,
    totalCandidates: candidates.length,
  };
}

/**
 * Build the DM digest text for Hargo from a dry-run result.
 * Returns null if there's nothing new to report.
 */
function formatLateFeeWaiveDigest(result) {
  if (!result || result.newForDm.length === 0) return null;

  const todayDisplay = new Date().toLocaleString("en-GB", {
    timeZone: "Europe/London",
    day: "2-digit", month: "2-digit", year: "numeric",
    hour: "2-digit", minute: "2-digit",
  });
  const lines = [`*Late Fee Waive — DRY RUN — ${todayDisplay} London*`];
  lines.push(`_(No Anchor transactions posted. Recommendations only — sheet column I updated for each row.)_`);

  // Surface any failed exclusion queries so Hargo can fix permissions.
  if (result.exclusionErrors && result.exclusionErrors.length > 0) {
    lines.push("");
    lines.push(`*⚠️ Exclusion-list queries with errors (treated as empty — agreements NOT filtered):*`);
    for (const e of result.exclusionErrors) {
      lines.push(`• \`${e.label}\`: ${e.error}`);
    }
  }

  const byStatus = {
    excluded:           result.newForDm.filter(r => r.status === "excluded"),
    excluded_settled:   result.newForDm.filter(r => r.status === "excluded_settled"),
    recommend:          result.newForDm.filter(r => r.status === "recommend"),
    capped:             result.newForDm.filter(r => r.status === "capped"),
    fulfilled_today:    result.newForDm.filter(r => r.status === "fulfilled_today"),
    no_eligible:        result.newForDm.filter(r => r.status === "no_eligible"),
    no_late_fees:       result.newForDm.filter(r => r.status === "no_late_fees"),
    error:              result.newForDm.filter(r => r.status === "error"),
  };

  if (byStatus.excluded_settled.length > 0) {
    lines.push("");
    lines.push(`*⛔ ${byStatus.excluded_settled.length} EXCLUDED — settlement transaction on Anchor (no reversal):*`);
    for (const r of byStatus.excluded_settled) {
      lines.push(`• \`${r.row.agreementId}\` — requested ${r.row.numberToWaive} — by ${r.row.requesterEmail || "(unknown)"}, row ${r.row.rowNum}`);
      if (r.settlementTransactions && r.settlementTransactions.length > 0) {
        const summary = r.settlementTransactions.map(t => `TypeId ${t.typeId} on ${t.date}`).join(", ");
        lines.push(`    ⛔ settlement transactions: ${summary}`);
      }
    }
  }

  if (byStatus.excluded.length > 0) {
    lines.push("");
    lines.push(`*⛔ ${byStatus.excluded.length} EXCLUDED — pending cancellation (no reversal):*`);
    for (const r of byStatus.excluded) {
      lines.push(`• \`${r.row.agreementId}\` — requested ${r.row.numberToWaive} — by ${r.row.requesterEmail || "(unknown)"}, row ${r.row.rowNum}`);
    }
  }

  if (byStatus.recommend.length > 0) {
    lines.push("");
    lines.push(`*✅ ${byStatus.recommend.length} to action TODAY (matches request count):*`);
    for (const r of byStatus.recommend) {
      const todayTag = r.reversalsTodayCount > 0
        ? ` (${r.reversalsTodayCount} already today = £${r.reversalsTodayAmount.toFixed(2)})`
        : "";
      lines.push(`• \`${r.row.agreementId}\` — requested ${r.row.numberToWaive} = £${r.amountRequested.toFixed(2)}, would post ${r.toReverse.length} more${todayTag}` +
                 ` — by ${r.row.requesterEmail || "(unknown)"}, row ${r.row.rowNum}`);
      // Show today's already-posted reversals first (if any), then the new recommendations
      if (r.todayMatchedPairs && r.todayMatchedPairs.length > 0) {
        for (const p of r.todayMatchedPairs) {
          lines.push(`    ✓ already waived: £${Math.abs(p.lateFee.amount).toFixed(2)} late fee from ${p.lateFee.date} (ref \`${p.lateFee.reference || "(none)"}\`) — reversal posted today, ref \`${p.reversal.reference || "(none)"}\``);
        }
      }
      for (const lf of r.toReverse) {
        lines.push(`    → would post: TypeId 50, +£${Math.abs(lf.amount).toFixed(2)}, ref \`${lf.reversalRef || lf.reference || "(none)"}\` (reverses late fee from ${lf.date}${lf.reference && lf.reversalRef && lf.reference !== lf.reversalRef ? `, original ref "${lf.reference}"` : ""})`);
      }
    }
  }

  if (byStatus.capped.length > 0) {
    lines.push("");
    lines.push(`*⚠️ ${byStatus.capped.length} CAPPED (request exceeds eligible — would post max possible):*`);
    for (const r of byStatus.capped) {
      const todayTag = r.reversalsTodayCount > 0
        ? ` (${r.reversalsTodayCount} already today = £${r.reversalsTodayAmount.toFixed(2)})`
        : "";
      lines.push(`• \`${r.row.agreementId}\` — requested ${r.row.numberToWaive} = £${r.amountRequested.toFixed(2)}, ` +
                 `eligible max ${r.activeCount}, would post ${r.toReverse.length} more${todayTag}` +
                 ` — by ${r.row.requesterEmail || "(unknown)"}, row ${r.row.rowNum}`);
      if (r.todayMatchedPairs && r.todayMatchedPairs.length > 0) {
        for (const p of r.todayMatchedPairs) {
          lines.push(`    ✓ already waived: £${Math.abs(p.lateFee.amount).toFixed(2)} late fee from ${p.lateFee.date} (ref \`${p.lateFee.reference || "(none)"}\`) — reversal posted today, ref \`${p.reversal.reference || "(none)"}\``);
        }
      }
      for (const lf of r.toReverse) {
        lines.push(`    → would post: TypeId 50, +£${Math.abs(lf.amount).toFixed(2)}, ref \`${lf.reversalRef || lf.reference || "(none)"}\` (reverses late fee from ${lf.date}${lf.reference && lf.reversalRef && lf.reference !== lf.reversalRef ? `, original ref "${lf.reference}"` : ""})`);
      }
    }
  }

  if (byStatus.fulfilled_today.length > 0) {
    lines.push("");
    lines.push(`*✔️ ${byStatus.fulfilled_today.length} ALREADY FULFILLED TODAY (no action):*`);
    for (const r of byStatus.fulfilled_today) {
      lines.push(`• \`${r.row.agreementId}\` — requested ${r.row.numberToWaive} = £${r.amountRequested.toFixed(2)}, ` +
                 `reversed today ${r.reversalsTodayCount} = £${r.reversalsTodayAmount.toFixed(2)} (row ${r.row.rowNum})`);
      if (r.todayMatchedPairs && r.todayMatchedPairs.length > 0) {
        for (const p of r.todayMatchedPairs) {
          lines.push(`    ✓ waived £${Math.abs(p.lateFee.amount).toFixed(2)} late fee from ${p.lateFee.date} (ref \`${p.lateFee.reference || "(none)"}\`) — reversal posted today, ref \`${p.reversal.reference || "(none)"}\``);
        }
      }
    }
  }

  if (byStatus.no_eligible.length > 0) {
    lines.push("");
    lines.push(`*🚫 ${byStatus.no_eligible.length} no eligible fees left to reverse:*`);
    for (const r of byStatus.no_eligible) {
      lines.push(`• \`${r.row.agreementId}\` — requested ${r.row.numberToWaive}, ` +
                 `already reversed today ${r.reversalsTodayCount}, no active fees remaining (row ${r.row.rowNum})`);
      if (r.todayMatchedPairs && r.todayMatchedPairs.length > 0) {
        for (const p of r.todayMatchedPairs) {
          lines.push(`    ✓ waived £${Math.abs(p.lateFee.amount).toFixed(2)} late fee from ${p.lateFee.date} (ref \`${p.lateFee.reference || "(none)"}\`) — reversal posted today, ref \`${p.reversal.reference || "(none)"}\``);
        }
      }
    }
  }

  if (byStatus.no_late_fees.length > 0) {
    lines.push("");
    lines.push(`*🚫 ${byStatus.no_late_fees.length} no late fees on Anchor:*`);
    for (const r of byStatus.no_late_fees) {
      lines.push(`• \`${r.row.agreementId}\` (row ${r.row.rowNum})`);
    }
  }

  if (byStatus.error.length > 0) {
    lines.push("");
    lines.push(`*❌ ${byStatus.error.length} error${byStatus.error.length === 1 ? "" : "s"}:*`);
    for (const r of byStatus.error) {
      lines.push(`• \`${r.row.agreementId}\` (row ${r.row.rowNum}): ${r.error}`);
    }
  }

  return lines.join("\n");
}

/**
 * LIVE action for a single agreement — posts TypeId 50 reversal(s) for the
 * top-N most-recent active late fees on the agreement, updates the responses
 * sheet (J=TRUE, K=total amount), and audit-logs every Anchor write.
 *
 * Hargo, 27/05/2026: this is the live counterpart to the hourly dry-run scan.
 * Triggered on-demand via "@Billington process late payment fee reversal on A00X".
 * Same recommendation logic (Anchor settlement + today vs today + active cap).
 *
 * Returns: {
 *   agreementId, row,
 *   rec: <buildLateFeeWaiveRecommendation result>,
 *   posted: [{ lateFee, amount }],
 *   errors: [{ lateFee, error }],
 *   totalAmount: number,
 *   fatal: string | null
 * }
 */
async function executeLateFeeWaiveLive(agreementId, auditCtx = {}) {
  const today    = new Date().toLocaleDateString("en-CA", { timeZone: "Europe/London" });
  const todayDmy = new Date().toLocaleDateString("en-GB", { timeZone: "Europe/London" });

  // 1. Load today's responses sheet, find the rank=1 row for this agreement.
  const tab = await getLateFeeWaiveTabName();
  const sheetRes = await sheetsClient.spreadsheets.values.get({
    spreadsheetId: LATE_FEE_WAIVE_SHEET_ID,
    range: `${tab}!A:K`,
  });
  const rows = sheetRes.data.values || [];

  let row = null;
  for (let i = 1; i < rows.length; i++) {
    const r = rows[i];
    const colA = (r[0] || "").trim();
    const colC = (r[2] || "").trim().toUpperCase();
    const colG = (r[6] || "").trim();
    const colH = (r[7] || "").trim();
    const colJ = (r[9] || "").trim().toUpperCase();

    if (!colA.startsWith(todayDmy)) continue;
    if (colC !== agreementId.toUpperCase()) continue;
    const rank = colG === "" ? 1 : parseInt(colG, 10);
    if (Number.isFinite(rank) && rank !== 1) continue;
    if (colH && colH.toUpperCase() !== "FALSE") {
      return { fatal: `Row ${i + 1} for ${agreementId} has cancellation_reversal flagged — not processing.` };
    }
    if (colJ === "TRUE") {
      return { fatal: `Row ${i + 1} for ${agreementId} is already marked billington_waived = TRUE.` };
    }

    row = {
      rowNum: i + 1,
      timestamp: colA,
      requesterEmail: (r[1] || "").trim(),
      agreementId: colC,
      numberToWaive: parseInt((r[3] || "").trim(), 10),
      executionReference: (r[5] || "").trim(),
    };
    break;
  }

  if (!row) {
    return { fatal: `No today's rank-1 Late Fee Waiver request found for ${agreementId} (or it's already marked billington_waived). Confirm the form submission was made today.` };
  }

  // 2. Pre-flight exclusion: pending_cancellations.
  let exclusionErrors = [];
  try {
    const { excluded, errors } = await getLateFeeWaiveExclusionSet();
    exclusionErrors = errors;
    if (excluded.has(agreementId)) {
      return { fatal: `${agreementId} is on the pending-cancellations list — late fees not waived on cancelling agreements.` };
    }
  } catch (err) {
    console.warn(`[bill-ling] executeLateFeeWaiveLive: exclusion check failed for ${agreementId}: ${err.message}`);
  }

  // 3. Build recommendation (same logic as dry-run).
  const rec = await buildLateFeeWaiveRecommendation(row);

  if (rec.status === "no_late_fees") {
    return { fatal: `No late fees (TypeId 49) on Anchor for ${agreementId} — nothing to reverse.` };
  }
  if (rec.status === "no_eligible") {
    return { fatal: `${agreementId} has no eligible late fees left to reverse. Request exceeds eligible amount.` };
  }
  if (rec.status === "excluded_settled") {
    const types = [...new Set(rec.settlementTransactions.map(t => t.typeId))].sort((a, b) => a - b);
    return { fatal: `${agreementId} has settlement transaction(s) on Anchor (TypeId ${types.join(", ")}) — late fees not waived on settled agreements.` };
  }
  if (rec.status === "fulfilled_today") {
    return { fatal: `Request already fulfilled today on ${agreementId}: ${rec.reversalsTodayCount} reversal(s) totalling £${rec.reversalsTodayAmount.toFixed(2)} posted today. No further action.` };
  }
  if (rec.status === "error") {
    return { fatal: rec.error || "Anchor read failed when building recommendation." };
  }
  if (!["recommend", "capped"].includes(rec.status)) {
    return { fatal: `Unexpected status: ${rec.status}` };
  }

  // 4. Post the reversals (TypeId 50, positive amount, ref = late fee's ref).
  const posted = [];
  const errors = [];
  let totalAmount = 0;
  const requestedBy = row.requesterEmail || auditCtx.requestedBy || "";

  for (const lf of rec.toReverse) {
    const amount = Math.abs(lf.amount);
    // Use the normalised reversal ref (LPF-AGREEMENT-YYYY-MM-DD), not the
    // raw original Reference — see buildLpfReversalRef + Hargo 28/05/2026.
    const reversalRef = lf.reversalRef || buildLpfReversalRef(agreementId, lf);
    try {
      // The "notes" field on Anchor's AddTransaction maps to the transaction's
      // Reference field on the resulting txn.
      await addTransactionToAnchor(agreementId, today, amount, reversalRef, 50, {
        ...auditCtx,
        requestedBy,
        actionType: "late_fee_reversal_posted",
        description: `Late fee reversal £${amount.toFixed(2)} posted on ${agreementId} (TypeId 50, ref ${reversalRef}, reverses late fee from ${lf.date}${lf.reference && lf.reference !== reversalRef ? `, original ref "${lf.reference}"` : ""})`,
        idempotencyKey: `late_fee_reversal:${agreementId}:${reversalRef}:${today}`,
      });
      posted.push({ lateFee: lf, amount, reversalRef });
      totalAmount += amount;
    } catch (err) {
      errors.push({ lateFee: lf, error: err.message, reversalRef });
      console.error(`[bill-ling] executeLateFeeWaiveLive: TypeId 50 post failed for ${agreementId} ref=${reversalRef}: ${err.message}`);
    }
  }

  // 5. Update sheet row only if at least one reversal posted.
  if (posted.length > 0) {
    try {
      const noteLine =
        `✅ ACTIONED (${today}): Posted ${posted.length} TypeId 50 reversal${posted.length === 1 ? "" : "s"} totalling £${totalAmount.toFixed(2)} ` +
        `(refs: ${posted.map(p => p.reversalRef || p.lateFee.reference).join(", ")}).`;
      await sheetsClient.spreadsheets.values.batchUpdate({
        spreadsheetId: LATE_FEE_WAIVE_SHEET_ID,
        requestBody: {
          valueInputOption: "USER_ENTERED",
          data: [
            { range: `${tab}!I${row.rowNum}`, values: [[noteLine]] },
            { range: `${tab}!J${row.rowNum}`, values: [["TRUE"]] },
            { range: `${tab}!K${row.rowNum}`, values: [[totalAmount.toFixed(2)]] },
          ],
        },
      });
      await logBillingtonAction({
        actionCategory: "sheet_write",
        actionType: "late_fee_waive_row_actioned",
        agreementId,
        amountGbp: totalAmount,
        reference: posted.map(p => p.reversalRef || p.lateFee.reference).join(", "),
        status: "success",
        description: `Late Fee Waiver responses row ${row.rowNum} marked actioned: J=TRUE, K=£${totalAmount.toFixed(2)}, I=audit note`,
        requestedBy,
        triggeredBy: auditCtx.triggeredBy,
        triggerSource: auditCtx.triggerSource,
        sourceLink: auditCtx.sourceLink,
        targetSheetRow: `${tab}!J${row.rowNum}`,
        idempotencyKey: `late_fee_actioned:${agreementId}:${row.rowNum}`,
      });
    } catch (err) {
      console.error(`[bill-ling] executeLateFeeWaiveLive: sheet update failed for row ${row.rowNum}: ${err.message}`);
    }
  }

  return {
    agreementId,
    row,
    rec,
    posted,
    errors,
    totalAmount,
    exclusionErrors,
    fatal: null,
  };
}

/**
 * Hargo, 08/06/2026: action a refund that's already been approved in a Slack
 * thread, when Hargo or Charlotte replies "approved @billington" (or similar).
 * Posts GOGW (TypeId 61) + paired refund (TypeId 149).
 *
 * DETERMINISTIC — NO LLM (security rule, Hargo): the figure is NOT inferred at
 * approval time. Billington locks the figure when it first proposes the refund
 * (the approval notification displays `post gogw and refund £X on A00…
 * type:<tag>`). This executor reads that exact displayed command back out of
 * Billington's OWN message in the thread and posts it verbatim. If no locked
 * command from Billington is present, it refuses and asks for the explicit
 * command — it never guesses an amount.
 *
 * Safety:
 *   - Caller must already have verified the user is in BILLINGTON_REFUND_AUTHORISERS.
 *   - Only the locked command in a Billington (bot) message is trusted — a
 *     human quoting a figure in their own reply is ignored, so the figure can
 *     only ever be one Billington itself displayed and an authoriser approved.
 *   - Re-confirm at approval time: before posting it re-derives the amount +
 *     GOGW type from the thread's HUMAN messages and refuses if either has
 *     drifted from the locked figure (the thread changed between proposal and
 *     approval). Option B is a confirmation, not a blind replay.
 *   - Idempotency: refuses if the thread already carries a Billington "posted"
 *     confirmation OR Anchor already shows a refund (TypeId 149) for this
 *     agreement since the request date — Anchor's idempotencyKey only de-dupes
 *     the audit log, not the SOAP POST, so these are the real duplicate guards.
 *   - GOGW and refund are paired (poll arrears between them like
 *     executeWaivePaidDamageFee does).
 *
 * Returns: {
 *   agreementId, amount, category,
 *   gogw:   { status: "posted" | "failed", error?: string },
 *   refund: { status: "posted" | "failed" | "skipped_polling_exhausted", error?: string },
 *   fatal?: string,
 * }
 */
async function executeBillingtonAutoApprovedRefund({ channel, thread_ts, user, auditCtx = {}, overrideAmount = null, overrideCategory = null, overrideAgreementId = null }) {
  const today = new Date().toLocaleDateString("en-CA", { timeZone: "Europe/London" });

  // 1. Fetch thread.
  let messages = [];
  try {
    const tr = await app.client.conversations.replies({
      token: SLACK_BOT_TOKEN, channel, ts: thread_ts, limit: 50,
    });
    messages = tr.messages || [];
  } catch (err) {
    return { fatal: `Couldn't fetch thread: ${err.message}` };
  }
  if (messages.length === 0) {
    return { fatal: "Thread is empty." };
  }

  // 2. Idempotency guard — if Billington already confirmed a posted GOGW +
  //    refund (or Anchor reflected one) in this thread, do NOT post again.
  //    Anchor's idempotencyKey only de-dupes the audit log, not the SOAP POST,
  //    so this thread-level check is the real duplicate guard.
  const alreadyPosted = messages.some(m => {
    if (!(m.bot_id || m.user === BOT_USER_ID)) return false;
    const t = (typeof getMessageText === "function" ? getMessageText(m) : (m.text || "")) || "";
    return /✅\s*Done\.\s*Posted on/i.test(t)
        || /has been posted in Anchor/i.test(t)
        || /Marking as complete/i.test(t);
  });
  if (alreadyPosted) {
    return { fatal: `This thread already has a posted GOGW + refund confirmation — I won't post it again. If you genuinely need another, use the explicit \`post gogw and refund £X on A00XXXXXX\` command.` };
  }

  // 3. Read the LOCKED command back out of Billington's OWN proposal in this
  //    thread — no LLM. Billington wrote `post gogw and refund £X on A00…
  //    type:<tag>` when it first flagged the approval for processing; we parse
  //    that verbatim. Only Billington (bot) messages are trusted as the source
  //    of the figure (a human quoting a number in their reply is ignored). We
  //    scan newest → oldest so the most recent locked proposal wins.
  const lockedRe = /post\s+gogw\s+and\s+refund\s+£\s*([\d,]+(?:\.\d{1,2})?)\s+on\s+(A\d{5,9})\s+type\s*[:=]\s*(escalation|closure|partial|full)\b/i;
  let locked = null;
  for (let i = messages.length - 1; i >= 0; i--) {
    const m = messages[i];
    if (!(m.bot_id || m.user === BOT_USER_ID)) continue;
    const t = (typeof getMessageText === "function" ? getMessageText(m) : (m.text || "")) || "";
    const mm = t.match(lockedRe);
    if (mm) { locked = mm; break; }
  }
  let agreementId, amount, typeTag, category, dentonResolved = false;
  if (Number.isFinite(overrideAmount) && overrideAmount > 0 && overrideCategory && overrideAgreementId) {
    // Vetted figure from a Billington button (already reconciled with Denton at
    // button-production, incl. any fee deduction, and re-confirmed by the presser).
    // Use it verbatim — no re-derivation drift. Hargo, 07/07/2026.
    agreementId = String(overrideAgreementId).toUpperCase();
    amount = overrideAmount;
    category = overrideCategory;
    typeTag = (GOGW_CATEGORY_TO_TYPE_TAG[category] || "type:full").replace(/^type:/, "");
    dentonResolved = true; // reconciliation already done when the button was posted
  } else if (locked) {
    agreementId = locked[2].toUpperCase();
    amount = parseFloat(locked[1].replace(/,/g, ""));
    typeTag = locked[3].toLowerCase();
    category = GOGW_TYPE_TAG_TO_CATEGORY[typeTag] || "Billington auto-action refund";
  } else {
    // No displayed command found (e.g. the chase offered "approved @billington"
    // without showing the figure). Re-derive from the thread exactly as the
    // proposal does — agreement, amount (incl. Denton's confirmed total), and
    // GOGW type. Hargo, 09/06/2026: "if approved is mentioned by Hargo /
    // Charlotte / Ciaran, proceed with the usual posting checks WITHOUT being
    // blocked by re-confirming the figures, because Billington has already
    // worked them out." We still ASK rather than guess when the type is
    // unclear, and the already-processed guards below still run.
    const inferenceText = [
      messages[0] ? getMessageText(messages[0]) : "",
      ...messages.slice(1)
        .filter(m => m.user !== BOT_USER_ID && !/good to go for processing|I read this as:/i.test(getMessageText(m)))
        .map(m => getMessageText(m)),
    ].join("\n");
    const agIds = [...new Set((inferenceText.match(/\bA\d{5}(?:\d{3})?\b/gi) || []).map(s => s.toUpperCase()))];
    if (agIds.length === 0) {
      return { fatal: `I couldn't find an agreement ID in this thread, so I won't guess. Post it explicitly, e.g. \`post gogw and refund £AMOUNT on A00XXXXXX type:full\`.` };
    }
    if (agIds.length > 1) {
      return { fatal: `This thread mentions more than one agreement (${agIds.join(", ")}), so I won't guess which to refund. Post it explicitly, e.g. \`post gogw and refund £AMOUNT on ${agIds[0]} type:full\`.` };
    }
    const lock = computeRefundLock(agIds[0], inferenceText);
    if (lock && lock.cmd) {
      // Amount AND category both readable from the thread.
      agreementId = agIds[0];
      amount = lock.amount;
      typeTag = lock.tag.replace(/^type:/, "");
      category = lock.category;
    } else if (lock && lock.amount && !lock.tag) {
      // Amount known, category (full vs partial trade-in) unclear. Don't bounce
      // it back to the operator — ask Denton and work it out from the figures
      // (Hargo, 07/07/2026): refund ≈ declared → Full; refund ≈ difference →
      // Partial. Only refuse if Denton can't make it unambiguous.
      const resolved = await resolveTradeInCategoryViaDenton({ agreementId: agIds[0], amount: lock.amount, channel, thread_ts });
      if (!resolved.category) {
        return { fatal: `I checked with Denton but still couldn't confirm whether ${agIds[0]} is a full or partial trade-in — ${resolved.reason}. Reply with the type (full / partial / closure / escalation) or post it explicitly, e.g. \`post gogw and refund £${lock.amount.toFixed(2)} on ${agIds[0]} type:full\`.` };
      }
      agreementId = agIds[0];
      amount = lock.amount;
      category = resolved.category;
      typeTag = (GOGW_CATEGORY_TO_TYPE_TAG[category] || "type:full").replace(/^type:/, "");
      dentonResolved = true;
    } else {
      return { fatal: `I couldn't read a clear figure + category for ${agIds[0]} from this thread, so I won't guess. Post it explicitly, e.g. \`post gogw and refund £AMOUNT on ${agIds[0]} type:full\`.` };
    }
  }

  if (!/^A\d{5,9}$/.test(agreementId)) {
    return { fatal: `The agreement ID didn't validate. Post the GOGW + refund manually with \`post gogw and refund £X on A00XXXXXX\`.` };
  }
  if (!Number.isFinite(amount) || amount <= 0) {
    return { fatal: `The amount didn't validate. Post the GOGW + refund manually.` };
  }

  // 3b. Denton confirmation for trade-in refunds (Hargo, 07/07/2026): before
  //     posting a full/partial trade-in, confirm the value + type against Denton.
  //     If Denton hasn't been consulted in this thread, @-ask it and reconcile
  //     from the figures (refund ≈ declared → Full; ≈ difference → Partial) —
  //     Denton is the source of truth, not an echoed phrase/command. Runs even
  //     when the category was already read from the thread (unless we just
  //     resolved it via Denton above). Non-trade-in categories skip this.
  if (!dentonResolved && (category === "Full trade in value" || category === "Partial trade in value")) {
    const resolved = await resolveTradeInCategoryViaDenton({ agreementId, amount, channel, thread_ts });
    if (!resolved.category) {
      return { fatal: `Before posting I checked with Denton to confirm the trade-in on ${agreementId} but couldn't reconcile it — ${resolved.reason}. Confirm the type or post it explicitly, e.g. \`post gogw and refund £${amount.toFixed(2)} on ${agreementId} type:full\`.` };
    }
    category = resolved.category;
    typeTag = (GOGW_CATEGORY_TO_TYPE_TAG[category] || "type:full").replace(/^type:/, "");
  }

  // 4. Already-processed guard at approval time (Hargo, 09/06/2026). When an
  //    authoriser replies "approved @billington" they are confirming the exact
  //    figure + type Billington already displayed and LOCKED — so we PROCEED
  //    with that locked command. We deliberately do NOT re-derive the
  //    amount/type from the thread and refuse on drift: the lock already
  //    represents the agreed figure, and refusing a valid approval over a
  //    re-parse difference was wrong (Hargo: "when billington provides options
  //    and says 'approved billington' it should know to proceed and only refuse
  //    if it has already been processed"). The ONLY stop conditions are
  //    duplicate-processing ones: the thread idempotency guard (step 2 above)
  //    plus this Anchor check — if a refund already shows on the agreement,
  //    don't post it again.
  const requestDate = messages[0]?.ts
    ? new Date(Number(messages[0].ts) * 1000).toISOString().slice(0, 10)
    : today;
  const anchorAlready = await checkAnchorForRefund(agreementId, requestDate);
  if (anchorAlready.posted) {
    return { fatal: `Stopped: a refund already shows on ${agreementId} in Anchor (${anchorAlready.detail}) — looks like this was already processed. Not posting again.` };
  }

  // 4b. Existing-GOGW guard (Hargo, 07/07/2026): if an unreversed GOGW (TypeId 61)
  //     is already on Anchor since the request date, DON'T post another. This is
  //     the retry-after-timeout case — the GOGW landed but the arrears poll timed
  //     out before the refund. Skip the GOGW post and go straight to the refund,
  //     so a re-click (via the retry button) completes it rather than doubling up.
  let gogwAlreadyOnAnchor = false;
  try {
    const gx = await getAgreementFromAnchor(agreementId);
    const gblocks = gx.match(/<(?:a:)?Transaction>[\s\S]*?<\/(?:a:)?Transaction>/g) || [];
    let posted61 = 0, reversed61 = 0;
    for (const blk of gblocks) {
      const tm = blk.match(/<(?:a:)?TypeId>(\d+)<\/(?:a:)?TypeId>/); if (!tm) continue;
      const tid = parseInt(tm[1], 10);
      if (tid !== 61 && tid !== 62) continue;
      const dm = blk.match(/<(?:a:)?TransactionDate>([^<]+)<\/(?:a:)?TransactionDate>/);
      const d = dm ? dm[1].slice(0, 10) : null;
      if (d && requestDate && d < requestDate) continue;
      const am = blk.match(/<(?:a:)?Amount>([^<]+)<\/(?:a:)?Amount>/);
      const a = am ? Math.abs(parseFloat(am[1])) : 0;
      if (tid === 61) posted61 += a; else reversed61 += a;
    }
    if (posted61 - reversed61 > 0.01) gogwAlreadyOnAnchor = true;
  } catch (_) { /* can't read — fall through and let the post run */ }

  // 5. Post GOGW (TypeId 61) — unless one is already on Anchor (retry case).
  const gogwNotes = `${category} — Billington auto-action (Slack thread approval).`.slice(0, 150);
  const result = {
    agreementId,
    amount,
    category,
    gogw:   { status: "pending", error: null },
    refund: { status: "pending", error: null },
  };
  if (gogwAlreadyOnAnchor) {
    result.gogw = { status: "already_posted", error: null };
  } else {
    try {
      await addTransactionToAnchor(agreementId, today, amount, gogwNotes, 61, {
        ...auditCtx,
        actionType: "gogw_posted",
        description: `GOGW £${amount.toFixed(2)} (${category}) posted via Slack auto-approval on ${agreementId}`,
        idempotencyKey: `gogw_auto:${agreementId}:${thread_ts}`,
      });
      result.gogw = { status: "posted", error: null };
    } catch (err) {
      result.gogw = { status: "failed", error: err.message };
      return { ...result, fatal: `GOGW post failed: ${err.message}`, anchorHttpStatus: err.anchorHttpStatus, anchorStatus: err.anchorStatus, anchorReason: err.anchorReason, failedStep: "GOGW" };
    }
  }

  // 6. Poll for TotalArrears to reflect the GOGW (max ~11s).
  const attempts = [0, 1000, 2000, 3000, 5000];
  let totalArrears = null;
  for (let i = 0; i < attempts.length; i++) {
    if (attempts[i] > 0) await new Promise(r => setTimeout(r, attempts[i]));
    try {
      totalArrears = await getAgreementLiveTotalArrears(agreementId);
      if (totalArrears !== null && totalArrears <= -(amount - 0.01)) break;
    } catch (_) { /* retry */ }
  }
  if (totalArrears === null || totalArrears > -(amount - 0.01)) {
    result.refund = { status: "skipped_polling_exhausted", error: `live TotalArrears £${totalArrears === null ? "null" : totalArrears.toFixed(2)} didn't reach target £-${amount.toFixed(2)} after ~11s` };
    return { ...result, fatal: `GOGW posted but TotalArrears didn't reflect it within ~11s. Refund NOT posted — retry with \`post refund £${amount.toFixed(2)} on ${agreementId}\` once Anchor settles.` };
  }

  // 7. Post refund (TypeId 149).
  const refundNotes = `${category} — paired refund (auto-action).`.slice(0, 150);
  try {
    await addTransactionToAnchor(agreementId, today, amount, refundNotes, 149, {
      ...auditCtx,
      actionType: "refund_posted",
      description: `Refund £${amount.toFixed(2)} (${category}) posted via Slack auto-approval on ${agreementId}`,
      idempotencyKey: `refund_auto:${agreementId}:${thread_ts}`,
    });
    result.refund = { status: "posted", error: null };
  } catch (err) {
    result.refund = { status: "failed", error: err.message };
    return { ...result, fatal: `GOGW posted (£${amount.toFixed(2)}) but refund FAILED: ${err.message}`, anchorHttpStatus: err.anchorHttpStatus, anchorStatus: err.anchorStatus, anchorReason: err.anchorReason, failedStep: "refund" };
  }

  return result;
}

/**
 * Cron entry point — run the dry-run scan and DM Hargo a digest of any
 * newly-seen requests. Silent if nothing new.
 */
async function runLateFeeWaiveDryRunCron() {
  try {
    const result = await processLateFeeWaiveDryRun();
    console.log(`[bill-ling] Late Fee Waive dry-run: ${result.totalCandidates} eligible rows today, ${result.newForDm.length} new for DM, skipped: ${JSON.stringify(result.skipped)}`);
    const digest = formatLateFeeWaiveDigest(result);
    if (!digest) {
      console.log("[bill-ling] Late Fee Waive dry-run: nothing new — DM skipped.");
      return;
    }
    try {
      const dm = await app.client.conversations.open({
        token: SLACK_BOT_TOKEN,
        users: HARGO_USER_ID,
      });
      const dmChannel = dm.channel?.id;
      if (!dmChannel) {
        console.error("[bill-ling] Late Fee Waive dry-run: could not open DM channel with Hargo.");
        return;
      }
      await app.client.chat.postMessage({
        token: SLACK_BOT_TOKEN,
        channel: dmChannel,
        text: digest,
        mrkdwn: true,
        unfurl_links: false,
        unfurl_media: false,
      });
    } catch (err) {
      console.error("[bill-ling] Late Fee Waive dry-run DM failed:", err.message);
    }
  } catch (err) {
    console.error("[bill-ling] runLateFeeWaiveDryRunCron error:", err.message);
  }
}

/**
 * Delete every row in `agreements_to_close` whose column A matches one of
 * the supplied agreement IDs. Returns { deleted: [{id,row}], notFound: [...] }.
 * Rows are deleted in reverse order so earlier indices stay valid.
 *
 * Used by the VC write-off retraction-cleanup path. Be careful — this
 * permanently removes the row, so callers MUST confirm both:
 *   1. the request was retracted in the thread, AND
 *   2. Anchor has not posted a fraud-and-vc write-off transaction yet
 * before invoking this helper.
 */
async function deleteCloseSheetRowsForAgreements(agreementIds) {
  if (!Array.isArray(agreementIds) || agreementIds.length === 0) {
    return { deleted: [], notFound: [] };
  }
  // We need the numeric sheetId for the tab to use deleteDimension.
  const ss = await sheetsClient.spreadsheets.get({
    spreadsheetId: CLOSE_AGREEMENT_SHEET_ID,
  });
  const tab = (ss.data.sheets || []).find(s => s.properties?.title === CLOSE_AGREEMENT_TAB);
  if (!tab) throw new Error(`Tab "${CLOSE_AGREEMENT_TAB}" not found in close-agreement spreadsheet.`);
  const tabId = tab.properties.sheetId;

  const colA = await sheetsClient.spreadsheets.values.get({
    spreadsheetId: CLOSE_AGREEMENT_SHEET_ID,
    range: `${CLOSE_AGREEMENT_TAB}!A:A`,
  });
  const rows = colA.data.values || [];
  const wanted = new Set(agreementIds.map(s => String(s).toUpperCase()));

  // Collect every matching row index (0-based) so we can delete bottom-up.
  // Capture the rendered ID/row pair before mutating so the response is
  // consistent even after deletions.
  const matches = [];
  rows.forEach((row, idx) => {
    const cell = (row?.[0] || "").toUpperCase();
    if (cell && wanted.has(cell)) {
      matches.push({ id: cell, row: idx + 1, idx });
    }
  });

  const foundIds = new Set(matches.map(m => m.id));
  const notFound = agreementIds
    .map(s => String(s).toUpperCase())
    .filter(id => !foundIds.has(id));

  // Reverse-sort by idx so the earlier rows aren't shifted during deletion.
  matches.sort((a, b) => b.idx - a.idx);
  const deleted = [];
  for (const { id, row, idx } of matches) {
    try {
      await sheetsClient.spreadsheets.batchUpdate({
        spreadsheetId: CLOSE_AGREEMENT_SHEET_ID,
        requestBody: {
          requests: [{
            deleteDimension: {
              range: { sheetId: tabId, dimension: "ROWS", startIndex: idx, endIndex: idx + 1 },
            },
          }],
        },
      });
      deleted.push({ id, row });
    } catch (err) {
      console.error(`[bill-ling] deleteCloseSheetRowsForAgreements: failed to delete row ${row} (${id}):`, err.message);
    }
  }
  return { deleted, notFound };
}

// ---------------------------------------------------------------------------
// VC Complaint Write-off Approval — sensitive channel handler
//
// Strict privacy rules (see CHANNELS section above for full list). This
// function ONLY reads the specific thread Billington was @-mentioned in,
// never stores anything, and refuses any channel-wide request. Its single
// job is to check whether the right approver has signed off (Stuart for
// amounts ≤ £750, Richard for > £750) and, if so, append the agreement
// to the existing close sheet under Fraud & VC Write Off.
// EXCEPTION (Hargo, 07/07/2026): for DECEASED write-offs there is no amount
// limit — Stuart (or Richard) can approve at any value; the £750 → Richard
// escalation does not apply. See isDeceasedWriteoffThread.
// ---------------------------------------------------------------------------
async function handleVcWriteoffApproval({ channel, thread_ts, ts, say }) {
  // Pull the thread (and ONLY this thread) from Slack
  let threadMessages = [];
  try {
    const thread = await app.client.conversations.replies({
      token: SLACK_BOT_TOKEN, channel, ts: thread_ts, limit: 100,
    });
    threadMessages = thread.messages || [];
  } catch (err) {
    await say({ text: `Couldn't read this thread: ${err.message}`, thread_ts });
    return;
  }

  // Resolve display names for every speaker in the thread so the classifier
  // can match approvers by name as well as by ID. Without this, Stuart's
  // message "@Marianne Carter approved" reads to the LLM as just
  // "<@U_STUART>: <@U_MARIANNE> approved" and the approver attribution can
  // be ambiguous if STUART_USER_ID isn't pre-configured.
  const speakerIds = [...new Set(
    threadMessages.map(m => m.user).filter(Boolean)
  )];
  const speakerNames = {};
  await Promise.all(speakerIds.map(async (uid) => {
    speakerNames[uid] = await getUserDisplayName(uid);
  }));

  // Build a labelled, text-only view of the thread for the LLM. Each line is
  // prefixed with `[Speaker: <@USERID> (Display Name)]` so the model is
  // unambiguous about who is talking, regardless of how the body @-mentions
  // other people. Nothing here is persisted.
  const threadText = threadMessages
    .map((m) => {
      const speakerId = m.user || m.bot_id || "unknown";
      const speakerName = (m.user && speakerNames[m.user]) ? ` (${speakerNames[m.user]})` : "";
      const body = (typeof getMessageText === "function") ? getMessageText(m) : (m.text || "");
      return `[Speaker: <@${speakerId}>${speakerName}] ${body}`;
    })
    .join("\n");

  // ── Stage 1: deterministic agreement-ID extraction from thread text ────
  const allAgreementIds = [...new Set(
    (threadText.match(/\bA\d{5,9}\b/gi) || []).map(s => s.toUpperCase())
  )];
  if (allAgreementIds.length === 0) {
    await say({ text: "No agreement IDs found in this thread — I need at least one (e.g. A00233543) before I can act.", thread_ts });
    return;
  }

  // ── Stage 2: split into 'already on sheet' vs 'new' ────────────────────
  // For anything already on the sheet, also check Anchor to see whether the
  // close transaction (Fraud & VC write-off TypeIds 26 / 70) has been posted
  // yet. This tells the requester whether their previous entry has been
  // actioned operationally, without their having to look it up themselves.
  const writeOffTypeIds = CLOSE_REASON_COLUMNS.fraud_and_vc_write_off.anchorTypeIds;
  const alreadyOnSheetEntries = [];
  const newAgreementIds = [];
  for (const agId of allAgreementIds) {
    let inSheet = false;
    try { inSheet = await isAgreementInCloseSheet(agId); }
    catch (err) { console.error(`[bill-ling] VC: isAgreementInCloseSheet(${agId}):`, err.message); }
    if (inSheet) {
      let anchor = { found: false };
      try { anchor = await checkAnchorForCloseTransaction(agId, writeOffTypeIds); }
      catch (err) { anchor = { found: false, error: err.message }; }
      alreadyOnSheetEntries.push({ agId, anchor });
    } else {
      newAgreementIds.push(agId);
    }
  }

  // ── Stage 3: classifier (always runs) — gets retraction + amount +
  // approver in a single LLM call, used by BOTH the cleanup path
  // (already-on-sheet entries when retracted) AND the new-agreement
  // approval path. We always run it because retraction needs to be
  // detected even when every ID is already on the sheet.
  const stuartHint  = STUART_USER_ID  ? `\n- Stuart's Slack user ID: <@${STUART_USER_ID}>`   : "\n- Stuart's user ID is not configured; identify Stuart by the display name in the [Speaker: ...] tag (anyone whose display name is 'Stuart').";
  const richardHint = RICHARD_USER_ID ? `\n- Richard's Slack user ID: <@${RICHARD_USER_ID}>` : "\n- Richard's user ID is not configured; identify Richard by the display name in the [Speaker: ...] tag (anyone whose display name is 'Richard').";
  const prompt = `You are reviewing a VC complaint write-off approval thread. Output ONLY JSON.

The agreement IDs being discussed in this thread are: ${allAgreementIds.join(", ")}.

CRITICAL READING RULE
Each line begins with \`[Speaker: <@USERID> (Display Name)]\`. The SPEAKER is the person who wrote the message. Anyone @-mentioned WITHIN the message body is being addressed — they are NOT the speaker.

Example: \`[Speaker: <@U_STUART> (Stuart)] <@U_MARIANNE> approved\` means STUART wrote the message, addressed to Marianne, and Stuart is approving. It does NOT mean Marianne approved.

From the thread, identify:
1. amount: the GBP value being written off for those agreements. Pick the FINAL stated total (not historical figures, not arrears amounts). If multiple agreements with separate amounts, pick the SUM of those write-off totals. If no amount is stated, return null.
2. stuartApproved: true if STUART (as the SPEAKER of a message) has given an UNCONDITIONAL approval for the write-off. Approval phrases include 'approved', 'go ahead', 'yes write it off', 'happy to approve', 'confirmed', 'OK to proceed', 'sign off', 'agreed', 'consider it approved'. Bare 'approved' on its own from Stuart counts. A message from someone ELSE saying 'Stuart approved' does NOT count by itself unless Stuart's own message is also present.
   IMPORTANT — CONDITIONAL APPROVALS: If Stuart's message is conditional ('happy to approve **but only if** ...', 'approved **provided that** ...', 'OK **on the basis that** ...', 'fine **as long as** ...'), it does NOT yet count as approval. Set stuartApproved=true ONLY IF the condition has been clearly satisfied LATER in the thread — by Stuart himself confirming ('consider it approved then', 'go ahead now', 'sorted, approved') or by another speaker confirming the condition AND Stuart subsequently re-confirming. If the condition is not clearly satisfied, set stuartApproved=false and put the unmet condition in pendingCondition.
3. richardApproved: same rule, but for Richard as the SPEAKER, with the same conditional-approval handling.${stuartHint}${richardHint}
4. requestRetracted: true if the requester (or anyone in the thread, EXCLUDING Billington's own past replies) has retracted, withdrawn, or cancelled the write-off request AFTER any approval was given. Retraction phrases: 'please ignore', 'ignore the above', 'disregard', 'cancel that', 'cancel this request', 'scratch that', 'no longer needed', 'withdraw', 'never mind', 'they have the device', 'customer has the device', 'we don't need to write this off', 'not needed anymore'. CRITICAL: a retraction message AFTER approval supersedes the approval — the write-off must NOT proceed.
5. retractionEvidence: short quote of the retraction message (<= 200 chars), or null.
6. pendingCondition: if there is a conditional approval that hasn't been resolved, a short summary of what condition is outstanding (e.g. "Stuart wants confirmation the other two devices have been returned"). Otherwise null.

Reply with this exact JSON shape, nothing else:
{"amount": number|null, "stuartApproved": false, "richardApproved": false, "approverDisplayName": "Stuart"|"Richard"|null, "requestRetracted": false, "retractionEvidence": null, "pendingCondition": null, "evidence": "short quote of the approval message, <= 200 chars"}

Thread:
${threadText}`;

  let parsed;
  try {
    const raw = await askClaude(prompt);
    parsed = JSON.parse(raw.replace(/```json|```/g, "").trim());
  } catch (err) {
    await say({ text: `I couldn't parse this thread cleanly: ${err.message}`, thread_ts });
    return;
  }

  const amount = (typeof parsed.amount === "number" && parsed.amount > 0) ? parsed.amount : null;
  const isRetracted = !!parsed.requestRetracted;
  const retractionQuote = (typeof parsed.retractionEvidence === "string" && parsed.retractionEvidence)
    ? parsed.retractionEvidence.slice(0, 200)
    : null;

  // ── Stage 3.5: Already-on-sheet handling — uses retraction info ────────
  // If the request has been retracted, then for any agreement already on
  // the sheet:
  //   - If Anchor has already posted a Fraud & VC write-off (TypeId 26 or
  //     70), it's been actioned — we just confirm. Can't roll back.
  //   - If Anchor has NOT posted yet, the row is still safe to remove —
  //     delete it from the sheet so the operations team isn't actioning a
  //     stale request.
  // If the request hasn't been retracted, render the standard status lines
  // (processed / pending in Anchor).
  const alreadyOnSheetLines = [];
  if (alreadyOnSheetEntries.length > 0) {
    alreadyOnSheetLines.push(`*Already on the close sheet:*`);
    if (isRetracted) {
      // Split into 'safe to delete' (no Anchor txn) vs 'too late' (processed).
      const toDelete = [];
      for (const { agId, anchor } of alreadyOnSheetEntries) {
        if (anchor.found) {
          const dateStr = anchor.date ? ` on ${fmtDate(anchor.date)}` : "";
          alreadyOnSheetLines.push(`✅ *${agId}* — already on the close sheet AND processed in Anchor (${anchor.description}${dateStr}). Cannot roll back; the write-off has been actioned.`);
        } else if (anchor.error) {
          alreadyOnSheetLines.push(`⚠️ *${agId}* — already on the close sheet. Anchor check failed (${anchor.error}); not removing the row, please verify manually.`);
        } else {
          toDelete.push(agId);
        }
      }
      if (toDelete.length > 0) {
        try {
          const delResult = await deleteCloseSheetRowsForAgreements(toDelete);
          for (const d of delResult.deleted) {
            alreadyOnSheetLines.push(`🗑️ *${d.id}* — was on the close sheet but not yet processed in Anchor. Removed (row ${d.row}) because the request was retracted.`);
          }
          for (const nf of delResult.notFound) {
            alreadyOnSheetLines.push(`⚠️ *${nf}* — couldn't find a matching row to delete (someone may have removed it already).`);
          }
        } catch (err) {
          console.error("[bill-ling] VC retraction-cleanup delete error:", err.message);
          alreadyOnSheetLines.push(`❌ Failed to remove rows for ${toDelete.join(", ")}: ${err.message}. Please remove them manually.`);
        }
      }
    } else {
      // Standard status report.
      for (const { agId, anchor } of alreadyOnSheetEntries) {
        if (anchor.found) {
          const dateStr = anchor.date ? ` on ${fmtDate(anchor.date)}` : "";
          alreadyOnSheetLines.push(`✅ *${agId}* — already on the close sheet and processed in Anchor (${anchor.description}${dateStr}).`);
        } else if (anchor.error) {
          alreadyOnSheetLines.push(`⚠️ *${agId}* — already on the close sheet. Anchor check failed: ${anchor.error}`);
        } else {
          alreadyOnSheetLines.push(`⏳ *${agId}* — already on the close sheet but *not yet processed in Anchor* (no Fraud & VC write-off transaction found).`);
        }
      }
    }
  }

  // Helper to prepend the "already on sheet" section to any reply.
  const composeReply = (newSection) => {
    const blocks = [];
    if (alreadyOnSheetLines.length > 0) blocks.push(alreadyOnSheetLines.join("\n"));
    if (newSection) blocks.push(newSection);
    return blocks.join("\n\n");
  };

  // Nothing further to do if every agreement was already on the sheet —
  // we've either reported status (non-retracted) or rolled back / confirmed
  // (retracted). Surface the retraction quote for context if relevant.
  if (newAgreementIds.length === 0) {
    const tail = (isRetracted && retractionQuote)
      ? `_Retraction noted_: "${retractionQuote}"`
      : null;
    await say({ text: composeReply(tail), thread_ts });
    return;
  }

  // For new agreements, retraction wins: don't add anything new either.
  if (isRetracted) {
    const evidence = retractionQuote ? `\n\n_Retraction noted_: "${retractionQuote}"` : "";
    await say({
      text: composeReply(
        `*New agreements (${newAgreementIds.join(", ")}):*\n` +
        `⚠️ The write-off request appears to have been *retracted* in this thread after approval was given. ` +
        `I won't add ${newAgreementIds.length === 1 ? "this agreement" : "these agreements"} to the close sheet.\n` +
        `If the request is still active, please post a fresh confirmation in the thread and tag me again.${evidence}`
      ),
      thread_ts,
    });
    return;
  }

  if (amount === null) {
    await say({
      text: composeReply(
        `*New agreements (${newAgreementIds.join(", ")}):*\n` +
        `I couldn't find a write-off amount in this thread. Please state the GBP total clearly so I can route to the right approver (Stuart ≤ £${VC_WRITEOFF_THRESHOLD_GBP} / Richard > £${VC_WRITEOFF_THRESHOLD_GBP}).`
      ),
      thread_ts,
    });
    return;
  }

  // Deceased write-offs: no £750 limit — Stuart (or Richard) can approve any
  // amount (Hargo, 07/07/2026). Otherwise the £750 threshold routes the approver.
  const isDeceased = isDeceasedWriteoffThread(threadText);
  const requiredApprover = (isDeceased || amount <= VC_WRITEOFF_THRESHOLD_GBP) ? "Stuart" : "Richard";
  const hasRequiredApproval = isDeceased
    ? (!!parsed.stuartApproved || !!parsed.richardApproved)
    : (requiredApprover === "Stuart" ? !!parsed.stuartApproved : !!parsed.richardApproved);

  if (!hasRequiredApproval) {
    const pending = (typeof parsed.pendingCondition === "string" && parsed.pendingCondition.trim())
      ? `\n\n_Outstanding condition_: ${parsed.pendingCondition.trim().slice(0, 300)}\nOnce that's confirmed in the thread, ${requiredApprover} (or you) can ping me again.`
      : "";
    await say({
      text: composeReply(
        `*New agreements (${newAgreementIds.join(", ")}):*\n` +
        `Write-off amount *£${amount.toFixed(2)}* requires *${requiredApprover}'s* approval ` +
        `${isDeceased ? "(deceased write-off — Stuart can approve at any amount)" : `(threshold £${VC_WRITEOFF_THRESHOLD_GBP})`}. I haven't seen that explicit unconditional approval in this thread yet — ` +
        `I'll only add to the close sheet once ${requiredApprover} confirms. ` +
        `_I won't be chasing in this channel._${pending}`
      ),
      thread_ts,
    });
    return;
  }

  // ── Stage 4: approval present → append the new agreements to the sheet ─
  try {
    const result = await writeCloseAgreements(newAgreementIds, "fraud_and_vc_write_off", {
      triggeredBy: "cron",
      triggerSource: "cron:writeoff_approval_scan",
      actionTypeSuffix: "writeoff_approval_scan",
    });
    const wroteCount = result.written.length;
    const dupCount   = result.duplicates.length;
    const newLines = [];
    if (wroteCount > 0) {
      newLines.push(`✅ Added ${wroteCount} agreement(s) to the close sheet under *Fraud & VC Write Off*:`);
      for (const w of result.written) newLines.push(`  › ${w.id} (row ${w.row})`);
      // Enrol each newly-added agreement in the follow-up tracker so the
      // closure transaction lands a thread note when it's posted in Anchor.
      const sourceChannelName = await getChannelName(channel);
      for (const w of result.written) {
        try { enrolWriteoffFollowup(w.id, { sourceChannelId: channel, sourceThread_ts: thread_ts, sourceChannelName }); }
        catch (err) { console.error(`[bill-ling] enrolWriteoffFollowup(${w.id}) from on-demand handler:`, err.message); }
      }
    }
    if (dupCount > 0) {
      // Defensive — alreadyOnSheetEntries should have caught these, but if a
      // race added them between our check and writeCloseAgreements we still
      // want to surface it.
      newLines.push(`${wroteCount > 0 ? "" : "ℹ️ "}${dupCount} agreement(s) were already in the sheet: ${result.duplicates.join(", ")}`);
    }
    newLines.push(`_Approval recognised from ${requiredApprover} for £${amount.toFixed(2)}._`);
    await say({ text: composeReply(newLines.join("\n")), thread_ts });
  } catch (err) {
    console.error("[bill-ling] VC write-off sheet write error:", err.message);
    await say({ text: composeReply(`Couldn't write the new agreement(s) to the close sheet: ${err.message}`), thread_ts });
  }
}

// ---------------------------------------------------------------------------
// Hourly Write-off Approval Scan (Hargo, 22/05/2026)
//
// Proactively scans #collab-vc-complaint-writeoff-approval and
// #collab-risk-ops-writeoff-close for threads where Stuart or Richard has
// approved a write-off. For each approved agreement:
//   - If net cash received (strict formula: sum Gross across TypeId
//     12/23/24/149/150-156) is ≤ £0.01 — i.e. no payments OR all already
//     refunded — append the agreement to the close sheet under
//     "Fraud & VC Write Off" (column G, TypeIds 26/70).
//   - If net cash received > £0.01 — payments still on the customer that
//     haven't been refunded — DM Ciaran Dobbin, Charlotte Platt, and Hargo
//     to flag for review BEFORE the agreement is closed/written off.
//
// Channel-specific rules:
//   VC channel: respect £750 threshold — Stuart for ≤ £750, Richard for
//   > £750. If no amount stated, require either approver.
//   Risk-ops channel: write-off is the default closure type — either
//   Stuart's or Richard's approval is sufficient, no threshold.
//
// State is persisted per (channel, thread_ts, agreement_id) tuple so each
// approval is acted on exactly once. Look-back: 7 days each scan (catches
// approvals from the last week if the bot was down or the cron skipped).
// ---------------------------------------------------------------------------
const WRITEOFF_SCAN_FILE = require("path").join(__dirname, "writeoff-approval-scan.json");
const WRITEOFF_SCAN_GCS_KEY = "writeoff-approval-scan.json";
// 30 days, not 7 (Hargo, 07/07/2026). Deceased/complaint write-offs routinely
// wait 1-2+ weeks for death certs, third-party confirmation and sign-off, so
// the APPROVAL often lands well after the request. A 7-day window meant threads
// aged out before approval and were never actioned (A00240782 posted 29/06,
// Stuart-approved 06/07 → missed; the 4-MacBook request posted 25/06). The
// per-thread writeoffScanState keeps this idempotent, so a wider window just
// catches late approvals without re-processing anything already handled.
const WRITEOFF_SCAN_LOOKBACK_DAYS = 30;
let writeoffScanState = new Map(); // key: `${channelId}:${thread_ts}:${agreementId}` → { outcome, at }

function loadWriteoffScanStateLocal() {
  try {
    if (fs.existsSync(WRITEOFF_SCAN_FILE)) {
      const data = JSON.parse(fs.readFileSync(WRITEOFF_SCAN_FILE, "utf8"));
      writeoffScanState = new Map(Object.entries(data.entries || {}));
      console.log(`[bill-ling] Loaded ${writeoffScanState.size} writeoff-scan entries from local.`);
    }
  } catch (err) {
    console.error("[bill-ling] writeoff-scan local load failed:", err.message);
  }
}
async function loadWriteoffScanStateGcs() {
  try {
    const data = await loadJsonFromGcs(WRITEOFF_SCAN_GCS_KEY);
    if (data?.entries) {
      for (const [k, v] of Object.entries(data.entries)) writeoffScanState.set(k, v);
      console.log(`[bill-ling] Loaded writeoff-scan from GCS; total now ${writeoffScanState.size}.`);
    }
  } catch (err) {
    console.warn("[bill-ling] writeoff-scan GCS load failed:", err.message);
  }
}
function saveWriteoffScanState() {
  const payload = { entries: Object.fromEntries(writeoffScanState) };
  try { fs.writeFileSync(WRITEOFF_SCAN_FILE, JSON.stringify(payload, null, 2)); } catch (_) {}
  saveJsonToGcs(WRITEOFF_SCAN_GCS_KEY, payload).catch(() => {});
}

// Synchronous (awaitable) version — used after closure-note state writes so
// SIGTERM mid-iteration can't lose the just-noted progress. Hargo, 22/05/2026.
async function saveWriteoffScanStateAsync() {
  const payload = { entries: Object.fromEntries(writeoffScanState) };
  try { fs.writeFileSync(WRITEOFF_SCAN_FILE, JSON.stringify(payload, null, 2)); } catch (_) {}
  try { await saveJsonToGcs(WRITEOFF_SCAN_GCS_KEY, payload); }
  catch (err) { console.error("[bill-ling] saveWriteoffScanStateAsync GCS failed:", err.message); }
}
loadWriteoffScanStateLocal();
loadWriteoffScanStateGcs();

// Deceased write-off detection (Hargo, 07/07/2026): when the write-off reason
// is a deceased customer, Stuart can approve at ANY amount — the £750 → Richard
// escalation does NOT apply. Detected deterministically from the thread text
// (these requests always say "deceased" / "death cert" / reference next of kin,
// the executor, probate, etc.).
function isDeceasedWriteoffThread(text) {
  return /\b(deceased|death\s*cert(ificate)?|passed\s+away|\bdied\b|next\s+of\s+kin|executor|probate|bereave)\b/i.test(text || "");
}

/**
 * Classify a write-off thread (LLM-based). Returns:
 *   { amount, stuartApproved, richardApproved, requestRetracted, ... }
 * Mirrors the prompt in handleVcWriteoffApproval but factored out for reuse
 * by the proactive scan.
 */
async function classifyWriteoffThread(threadMessages, agreementIds) {
  const speakerIds = [...new Set(threadMessages.map(m => m.user).filter(Boolean))];
  const speakerNames = {};
  await Promise.all(speakerIds.map(async (uid) => {
    speakerNames[uid] = await getUserDisplayName(uid);
  }));
  const threadText = threadMessages
    .map((m) => {
      const speakerId = m.user || m.bot_id || "unknown";
      const speakerName = (m.user && speakerNames[m.user]) ? ` (${speakerNames[m.user]})` : "";
      const body = (typeof getMessageText === "function") ? getMessageText(m) : (m.text || "");
      return `[Speaker: <@${speakerId}>${speakerName}] ${body}`;
    }).join("\n");

  const stuartHint  = STUART_USER_ID  ? `\n- Stuart's Slack user ID: <@${STUART_USER_ID}>`   : "\n- Stuart's user ID is not configured; identify Stuart by the display name in the [Speaker: ...] tag (anyone whose display name is 'Stuart').";
  const richardHint = RICHARD_USER_ID ? `\n- Richard's Slack user ID: <@${RICHARD_USER_ID}>` : "\n- Richard's user ID is not configured; identify Richard by the display name in the [Speaker: ...] tag (anyone whose display name is 'Richard').";
  const prompt = `You are reviewing a write-off approval thread. Output ONLY JSON.

Agreement IDs in this thread: ${agreementIds.join(", ")}.

CRITICAL READING RULE
Each line begins with \`[Speaker: <@USERID> (Display Name)]\`. The SPEAKER wrote the message. Anyone @-mentioned WITHIN the body is being addressed — they are NOT the speaker.

Identify:
1. amount: GBP write-off total (final stated figure, sum if multiple agreements). null if not stated.
2. stuartApproved: true if STUART (as speaker) has given an UNCONDITIONAL approval. Phrases: 'approved', 'go ahead', 'happy to approve', 'confirmed', 'OK to proceed', 'sign off', 'agreed', 'consider it approved'. Bare 'approved' from Stuart counts. Someone else saying 'Stuart approved' does NOT count unless Stuart's own message is also present.
   CONDITIONAL APPROVALS: 'approved but only if ...', 'OK on the basis that ...' do NOT count. Set true ONLY IF the condition is satisfied later in the thread.
3. richardApproved: same rule for Richard as speaker.${stuartHint}${richardHint}
4. requestRetracted: true if anyone (excluding Billington) retracted the request AFTER any approval was given.
5. retractionEvidence: short quote (<=200 chars) or null.
6. pendingCondition: short summary of an unresolved condition, or null.
7. refundRequested: true ONLY if someone in the thread has issued an UNCONDITIONAL DIRECTIVE that a refund be processed. A DIRECTIVE is a clear instruction or decision — not a question, not a hypothetical, not an open discussion. STRICT EXAMPLES (true): 'refund the customer £X', 'please process a refund of £X', 'we need to refund £X — go ahead', 'yes please refund', 'refund all collected payments', 'agreed, refund this'. STRICT NEGATIVES (false): 'do we need to refund?', 'should we refund?', 'is a refund due?', 'what about the payments?', 'might need to refund', 'we may owe them', 'check whether a refund is needed', 'asking if this needs refunding'. If the thread CONTAINS an OPEN QUESTION about whether to refund and that question has NOT been answered with a directive, set refundRequested=FALSE even though the topic was raised. Just mentioning historical payments does NOT count. Set false by default unless you can quote an actual instruction.
8. refundAmount: the GBP refund amount stated in the DIRECTIVE (if any), or null. If there's only a question (no directive), set to null.
9. openRefundQuestion: true if the thread CONTAINS an EXPLICIT, UNRESOLVED question about whether or not to refund the customer (e.g. 'do we need to refund this customer?', 'should we be refunding them?', 'is a refund due here?', 'are we owing them money?'). Set false if the question has been answered later in the thread (either with a directive to refund — which makes refundRequested=true — or with a clear 'no refund needed' answer). Set false if the thread simply doesn't discuss refunding at all. This is the case where the topic is RAISED but UNDECIDED, so closure must NOT be auto-actioned.
10. openRefundQuestionQuote: short quote of the unresolved question (<=200 chars), or null.
11. targetAgreementIds: array of agreement IDs that are EXPLICITLY being REQUESTED for write-off in this thread. EXCLUDE agreements that are only MENTIONED as context (e.g. 'the customer also has A00X which was returned', 'there were 2 other devices A00Y and A00Z that were returned'). Only include the agreement IDs where the original requester (or someone in the thread before approval) said 'write off A00…' or 'agreement: A00…' as the SUBJECT of the request. If the thread says something like 'Agreement: A00X' followed by request details, then mentions 'A further note on this one, there were also A00Y and A00Z' for context, ONLY include A00X. Be CONSERVATIVE — when in doubt, exclude. Default to listing only the agreement explicitly preceded by 'Agreement:', '@-mention + write off A00…', or 'requesting write off for A00…'.

Reply with this exact JSON shape, nothing else:
{"amount": number|null, "stuartApproved": false, "richardApproved": false, "approverDisplayName": "Stuart"|"Richard"|null, "requestRetracted": false, "retractionEvidence": null, "pendingCondition": null, "refundRequested": false, "refundAmount": null, "openRefundQuestion": false, "openRefundQuestionQuote": null, "targetAgreementIds": [], "evidence": "short quote of the approval, <=200 chars"}

Thread:
${threadText}`;

  const raw = await askClaude(prompt);
  return JSON.parse(raw.replace(/```json|```/g, "").trim());
}

/**
 * Compute net unrefunded cash for an agreement using Hargo's strict formula:
 *   sum(Gross) across TypeId 12 / 23 / 24 / 149 / 150–156
 * Positive = customer paid more than has been refunded.
 * Also returns a per-TypeId breakdown so the flag DM can show the trail.
 */
async function getAgreementNetUnrefundedWithBreakdown(agreementId) {
  const txns = await getAgreementTransactionsFromAnchor(agreementId);
  const breakdown = new Map();
  for (const t of txns) {
    if (!NET_PAYMENT_TYPE_IDS_FOR_REFUND.has(t.typeId)) continue;
    if (!breakdown.has(t.typeId)) breakdown.set(t.typeId, { count: 0, sum: 0 });
    const e = breakdown.get(t.typeId);
    e.count++;
    e.sum += Number.isFinite(t.amount) ? t.amount : 0;
  }
  const net = computeStrictNetPayments(txns);
  return { net, breakdown };
}

/**
 * Format the {channel_id, thread_ts} of a Slack thread as a permalink (best
 * effort — falls back to a simple text reference if the API call fails).
 */
async function getThreadPermalink(channelId, thread_ts) {
  try {
    const res = await app.client.chat.getPermalink({
      token: SLACK_BOT_TOKEN, channel: channelId, message_ts: thread_ts,
    });
    return res?.permalink || null;
  } catch (_) { return null; }
}

/**
 * Hourly proactive scan. For each of the two write-off channels, pull top-level
 * messages from the last WRITEOFF_SCAN_LOOKBACK_DAYS days, classify each
 * thread, and act per the rules above. Idempotent — relies on
 * writeoffScanState keyed by (channel, thread_ts, agreement_id).
 */
async function runWriteoffApprovalScan(opts = {}) {
  // Options for one-off / admin-triggered scans (Hargo, 22/05/2026):
  //   - lookbackDays: how far back to scan (default: WRITEOFF_SCAN_LOOKBACK_DAYS).
  //   - oldestIsoDate: if set, use this exact date as the oldest cut-off
  //     (overrides lookbackDays). Format YYYY-MM-DD.
  //   - channelsFilter: array of channel keys to scan, e.g. ["risk-ops"]
  //     or ["vc"]. Defaults to both.
  //   - runLabel: string included in logs to identify this run.
  const {
    lookbackDays = WRITEOFF_SCAN_LOOKBACK_DAYS,
    oldestIsoDate = null,
    channelsFilter = null,
    runLabel = "hourly",
  } = opts;
  console.log(`[bill-ling] writeoff-scan(${runLabel}): starting — lookback ${oldestIsoDate || `${lookbackDays}d`}, channels=${channelsFilter ? channelsFilter.join(",") : "all"}`);
  // Resolve VC channel ID on demand if not yet cached — `vcWriteoffChannelId`
  // gets populated lazily when a message lands in the VC channel, which
  // doesn't happen on quiet days, so the proactive scan misses the channel
  // entirely. Walk conversations.list once and cache.
  if (!vcWriteoffChannelId) {
    try {
      let cursor;
      do {
        const r = await app.client.conversations.list({
          token: SLACK_BOT_TOKEN,
          limit: 1000,
          types: "public_channel,private_channel",
          ...(cursor ? { cursor } : {}),
        });
        const found = (r.channels || []).find(c => c.name === VC_WRITEOFF_CHANNEL_NAME);
        if (found) { vcWriteoffChannelId = found.id; break; }
        cursor = r.response_metadata?.next_cursor || "";
      } while (cursor);
      if (vcWriteoffChannelId) console.log(`[bill-ling] writeoff-scan: resolved VC channel ${vcWriteoffChannelId}.`);
      else console.warn(`[bill-ling] writeoff-scan: could not resolve #${VC_WRITEOFF_CHANNEL_NAME}.`);
    } catch (err) {
      console.error(`[bill-ling] writeoff-scan: conversations.list failed:`, err.message);
    }
  }

  const channels = [];
  if (vcWriteoffChannelId && (!channelsFilter || channelsFilter.includes("vc"))) {
    channels.push({ id: vcWriteoffChannelId, name: VC_WRITEOFF_CHANNEL_NAME, requireAmountThreshold: true });
  }
  if (!channelsFilter || channelsFilter.includes("risk-ops")) {
    channels.push({ id: CHANNELS.RISK_OPS_WRITEOFF_CLOSE, name: "collab-risk-ops-writeoff-close", requireAmountThreshold: false });
  }

  // Hargo, 28/05/2026: always use the rolling lookback window. The
  // `oldestIsoDate` parameter is kept for backward compatibility but no
  // longer restricts the message fetch — per-thread state in
  // writeoffScanState already prevents double-processing of approvals
  // that landed before the resume date. Using a strict date floor caused
  // approvals on yesterday's threads (e.g. Richard's 18:12 approval on a
  // thread Marianne started at 15:51 the day before) to be missed when
  // the cron passed `oldestIsoDate: todayIso` each tick.
  const oldestTs = Math.floor((Date.now() - lookbackDays * 86400_000) / 1000);
  const writeOffAnchorTypeIds = CLOSE_REASON_COLUMNS.fraud_and_vc_write_off.anchorTypeIds; // [26, 70]
  let stateDirty = false;
  const summary = {
    threadsScanned: 0,
    closureNotesPosted: [], // agreementId
    addedToSheet: [], // agreementId
    blockedOpenQuestion: [], // agreementId
    blockedRefundDue: [], // agreementId
    contextOnlySkipped: 0,
    alreadyHandled: 0,
    classifyErrors: 0,
  };

  for (const ch of channels) {
    if (!ch.id) {
      console.warn(`[bill-ling] writeoff-scan: skipping ${ch.name} — channel id not resolved.`);
      continue;
    }
    let topLevel = [];
    try {
      // conversations.history returns top-level messages (not replies)
      let cursor = undefined;
      do {
        const resp = await app.client.conversations.history({
          token: SLACK_BOT_TOKEN, channel: ch.id, oldest: String(oldestTs), limit: 200, cursor,
        });
        topLevel.push(...(resp.messages || []));
        cursor = resp.response_metadata?.next_cursor || undefined;
      } while (cursor);
    } catch (err) {
      console.error(`[bill-ling] writeoff-scan: conversations.history failed for ${ch.name}:`, err.message);
      continue;
    }
    console.log(`[bill-ling] writeoff-scan: ${ch.name} → ${topLevel.length} top-level messages in last ${WRITEOFF_SCAN_LOOKBACK_DAYS}d.`);

    for (const parent of topLevel) {
      if (parent.subtype === "channel_join" || parent.subtype === "channel_leave") continue;
      if (parent.bot_id) continue; // skip bot-posted parents (our own digests, etc.)
      const thread_ts = parent.thread_ts || parent.ts;
      if (!thread_ts) continue;

      // Pull all thread messages (parent + replies). If a parent has no
      // replies and isn't a thread parent, conversations.replies still
      // returns just the parent.
      let threadMessages = [];
      try {
        const tr = await app.client.conversations.replies({
          token: SLACK_BOT_TOKEN, channel: ch.id, ts: thread_ts, limit: 200,
        });
        threadMessages = tr.messages || [];
      } catch (err) {
        console.error(`[bill-ling] writeoff-scan: conversations.replies failed for ${ch.name} ts=${thread_ts}:`, err.message);
        continue;
      }
      if (threadMessages.length === 0) continue;

      // Combined text for agreement-ID extraction
      const combinedText = threadMessages
        .map(m => (typeof getMessageText === "function") ? getMessageText(m) : (m.text || ""))
        .join("\n");
      const agreementIds = [...new Set((combinedText.match(/\bA\d{5,9}\b/gi) || []).map(s => s.toUpperCase()))];
      if (agreementIds.length === 0) continue;

      // Quick pre-filter — if EVERY agreement has already been handled for
      // this thread, skip without an LLM call.
      summary.threadsScanned++;
      const allHandled = agreementIds.every(agId => writeoffScanState.has(`${ch.id}:${thread_ts}:${agId}`));
      if (allHandled) { summary.alreadyHandled++; continue; }

      // Classify (LLM)
      let parsed;
      try {
        parsed = await classifyWriteoffThread(threadMessages, agreementIds);
      } catch (err) {
        console.error(`[bill-ling] writeoff-scan: classify failed for ${ch.name} ts=${thread_ts}:`, err.message);
        summary.classifyErrors++;
        continue;
      }

      if (parsed.requestRetracted) {
        // Mark every unhandled agreement as "retracted" so we don't re-process.
        for (const agId of agreementIds) {
          const key = `${ch.id}:${thread_ts}:${agId}`;
          if (writeoffScanState.has(key)) continue;
          writeoffScanState.set(key, { outcome: "retracted", at: new Date().toISOString() });
          stateDirty = true;
        }
        continue;
      }

      // Anchor closure pre-check across ALL extracted agreements — BEFORE the
      // approval gate. Hargo, 22/05/2026: closure notes must fire whenever
      // an agreement is closed in Anchor, regardless of whether the LLM
      // judged the thread "approved" by the right person at the right
      // threshold. Operationally, ops sometimes write off without strict
      // threshold compliance (A00194693, A00282576 were closed in Anchor
      // despite Stuart-only approval > £750), and Billington should still
      // post the closure record for visibility.
      const closureOnlyAgreementIds = new Set();
      for (const agId of agreementIds) {
        const key = `${ch.id}:${thread_ts}:${agId}`;
        const existing = writeoffScanState.get(key);
        if (existing && existing.notedOnThreadAt) {
          closureOnlyAgreementIds.add(agId);
          continue; // already noted — don't re-check
        }
        let anchorClose = { found: false };
        try { anchorClose = await checkAnchorForCloseTransaction(agId, writeOffAnchorTypeIds); } catch (_) {}
        if (anchorClose.found) {
          // Mark state BEFORE posting (Hargo, 22/05/2026 — A00282576 duplicate
          // incident): if the Slack post succeeds but the process is killed
          // before state can be saved, the GCS state pickup on next start
          // sees `notedOnThreadAt` and skips. Save synchronously to GCS
          // immediately so SIGTERM mid-iteration can't lose progress.
          writeoffScanState.set(key, {
            outcome: "already_closed_in_anchor",
            anchorTypeId: anchorClose.typeId,
            anchorDate: anchorClose.date || null,
            notedOnThreadAt: new Date().toISOString(),
            at: existing?.at || new Date().toISOString(),
          });
          await saveWriteoffScanStateAsync();
          stateDirty = false; // already saved
          try {
            const posted = await noteClosureOnThread(ch.id, thread_ts, agId, anchorClose.typeId, anchorClose.date, anchorClose.description);
            if (posted) summary.closureNotesPosted.push(agId);
          } catch (err) {
            console.error(`[bill-ling] writeoff-scan: pre-approval-gate noteClosureOnThread failed for ${agId}:`, err.message);
          }
          closureOnlyAgreementIds.add(agId);
        }
      }

      // Approval gate
      const amount = (typeof parsed.amount === "number" && parsed.amount > 0) ? parsed.amount : null;
      // Deceased write-offs: no £750 limit — Stuart (or Richard) can approve any
      // amount (Hargo, 07/07/2026). Detected from the thread text.
      const isDeceased = isDeceasedWriteoffThread(combinedText);
      let approved = false;
      if (ch.requireAmountThreshold) {
        if (isDeceased) {
          approved = !!parsed.stuartApproved || !!parsed.richardApproved;
        } else if (amount !== null) {
          const requiredApprover = amount <= VC_WRITEOFF_THRESHOLD_GBP ? "Stuart" : "Richard";
          approved = requiredApprover === "Stuart" ? !!parsed.stuartApproved : !!parsed.richardApproved;
        } else {
          // No amount stated — accept either approver as long as someone unconditionally signed off.
          approved = !!parsed.stuartApproved || !!parsed.richardApproved;
        }
      } else {
        // risk-ops: either approver is sufficient.
        approved = !!parsed.stuartApproved || !!parsed.richardApproved;
      }
      if (!approved) continue;

      const approverName = parsed.stuartApproved && parsed.richardApproved
        ? "Stuart & Richard"
        : parsed.stuartApproved ? "Stuart" : parsed.richardApproved ? "Richard" : "(unknown)";

      const permalink = await getThreadPermalink(ch.id, thread_ts);
      const threadRef = permalink ? `<${permalink}|thread>` : `thread ts=${thread_ts}`;

      const refundRequested = !!parsed.refundRequested;
      const refundAmount = (typeof parsed.refundAmount === "number" && parsed.refundAmount > 0) ? parsed.refundAmount : null;
      const openRefundQuestion = !!parsed.openRefundQuestion;
      const openRefundQuestionQuote = (typeof parsed.openRefundQuestionQuote === "string" && parsed.openRefundQuestionQuote.trim())
        ? parsed.openRefundQuestionQuote.trim().slice(0, 200) : null;

      // Hargo, 22/05/2026: ONLY act on agreements EXPLICITLY requested for
      // write-off in the thread, NOT every A00 ID mentioned. A thread may
      // reference other agreements as context (e.g. "there were 2 other
      // devices A00X and A00Y which were returned"). The LLM identifies
      // the request targets via `targetAgreementIds`. Intersect with the
      // regex-extracted IDs as a defensive check.
      // SAFEGUARD: when a thread mentions exactly ONE agreement, that
      // agreement IS the target — bypass the LLM filter to avoid
      // inconsistent classifier output dropping single-agreement requests.
      let targetAgreementIds;
      if (agreementIds.length === 1) {
        targetAgreementIds = [...agreementIds];
      } else {
        const targetIdsRaw = Array.isArray(parsed.targetAgreementIds) ? parsed.targetAgreementIds : [];
        const extractedSet = new Set(agreementIds);
        targetAgreementIds = targetIdsRaw
          .map(s => typeof s === "string" ? s.toUpperCase().trim() : "")
          .filter(s => /^A\d{5,9}$/.test(s) && extractedSet.has(s));
      }
      // Agreements mentioned but NOT targeted — handle Anchor-already-closed
      // pre-check (post note if applicable) but never add to sheet / flag.
      const contextOnlyIds = agreementIds.filter(id => !targetAgreementIds.includes(id));

      // Per-thread accumulator for adds — collected here so we can post a
      // single combined thread reply @-mentioning Hargo (rather than one
      // post per agreement). Hargo, 22/05/2026: add-to-sheet confirmations
      // belong in the thread, not in DMs.
      const addedInThisThread = [];

      // First pass: Anchor closure pre-check across ALL mentioned agreements
      // (target + context). Posts the in-thread closure note when applicable.
      // Idempotent via thread inspection.
      for (const agId of contextOnlyIds) {
        const key = `${ch.id}:${thread_ts}:${agId}`;
        if (writeoffScanState.has(key) && writeoffScanState.get(key).notedOnThreadAt) continue;
        let anchorClose = { found: false };
        try { anchorClose = await checkAnchorForCloseTransaction(agId, writeOffAnchorTypeIds); } catch (_) {}
        if (anchorClose.found) {
          // Pre-post state save: see comment above. Synchronous to GCS.
          writeoffScanState.set(key, {
            outcome: "context_only_closed_in_anchor",
            anchorTypeId: anchorClose.typeId,
            anchorDate: anchorClose.date || null,
            notedOnThreadAt: new Date().toISOString(),
            at: new Date().toISOString(),
          });
          await saveWriteoffScanStateAsync();
          try {
            const posted = await noteClosureOnThread(ch.id, thread_ts, agId, anchorClose.typeId, anchorClose.date, anchorClose.description);
            if (posted) summary.closureNotesPosted.push(agId);
          } catch (err) {
            console.error(`[bill-ling] writeoff-scan: context-id noteClosureOnThread failed for ${agId}:`, err.message);
          }
        } else {
          // Not requested for write-off and not closed in Anchor — just
          // record that we considered and skipped it.
          writeoffScanState.set(key, { outcome: "context_only_skipped", at: new Date().toISOString() });
          stateDirty = true;
          summary.contextOnlySkipped++;
        }
      }

      // Per-agreement processing — ONLY targets explicitly requested
      for (const agId of targetAgreementIds) {
        const key = `${ch.id}:${thread_ts}:${agId}`;
        if (writeoffScanState.has(key)) continue;

        // RULE 1 (Hargo, 22/05/2026): Anchor write-off pre-check FIRST.
        // If TypeId 26 or 70 is already on Anchor, post a single factual
        // closure note in the source thread (if not already noted by us
        // there). Idempotent via thread inspection — won't double-post.
        // No DMs.
        let anchorClose = { found: false };
        try { anchorClose = await checkAnchorForCloseTransaction(agId, writeOffAnchorTypeIds); } catch (_) {}
        if (anchorClose.found) {
          const existing = writeoffScanState.get(key);
          // Pre-post state save: see comment above. Synchronous to GCS.
          writeoffScanState.set(key, {
            outcome: "already_closed_in_anchor",
            anchorTypeId: anchorClose.typeId,
            anchorDate: anchorClose.date || null,
            notedOnThreadAt: new Date().toISOString(),
            at: existing?.at || new Date().toISOString(),
          });
          await saveWriteoffScanStateAsync();
          try {
            const posted = await noteClosureOnThread(ch.id, thread_ts, agId, anchorClose.typeId, anchorClose.date, anchorClose.description);
            if (posted) summary.closureNotesPosted.push(agId);
          } catch (err) {
            console.error(`[bill-ling] writeoff-scan: noteClosureOnThread failed for ${agId}:`, err.message);
          }
          continue;
        }

        // Skip if already in close sheet (someone added it manually or via
        // the on-demand handler). Don't re-add.
        let inSheet = false;
        try { inSheet = await isAgreementInCloseSheet(agId); } catch (_) {}
        if (inSheet) {
          // Keep the entry in the follow-up tracker so the next-working-day
          // re-check still fires (it might have been added without enrolment).
          writeoffScanState.set(key, { outcome: "already_in_sheet", at: new Date().toISOString() });
          stateDirty = true;
          enrolWriteoffFollowup(agId, { sourceChannelId: ch.id, sourceThread_ts: thread_ts, sourceChannelName: ch.name });
          continue;
        }

        // RULE 2 (Hargo, 22/05/2026): Branch on the refund state of the thread.
        //   - Refund REQUESTED (unconditional directive): use the strict
        //     net-payments check. If net unrefunded > £0.01 → flag
        //     Ciaran/Charlotte/Hargo, do NOT add. If net ≤ £0.01 → add.
        //   - OPEN REFUND QUESTION (raised in thread, NOT resolved): flag
        //     Hargo only, do NOT add. The question must be answered first.
        //     (Hargo, 22/05/2026 — A00119901: "is a refund due?" raised
        //     but undecided; auto-adding to the sheet would pre-empt that.)
        //   - No refund discussion at all: add straight to the sheet under
        //     Fraud & VC Write Off (no payment check needed).
        if (openRefundQuestion) {
          const permaQuote = openRefundQuestionQuote ? `\n*Question raised:* "${openRefundQuestionQuote}"` : "";
          const flagText =
            `❓ *Blocked* — unresolved refund question on an approved write-off.\n\n` +
            `*Agreement:* ${agId}\n` +
            `*Approver:* ${approverName}${amount ? ` (£${amount.toFixed(2)})` : ""}\n` +
            `*Source:* ${threadRef} in #${ch.name}${permaQuote}\n\n` +
            `Not added to the close sheet.`;
          try {
            await sendDM(HARGO_USER_ID, flagText);
            writeoffScanState.set(key, { outcome: "flagged_open_refund_question", at: new Date().toISOString() });
            stateDirty = true;
            summary.blockedOpenQuestion.push(agId);
          } catch (err) {
            console.error(`[bill-ling] writeoff-scan: open-question DM failed for ${agId}:`, err.message);
          }
          continue;
        }
        if (!refundRequested) {
          // Asset-return pre-check (Hargo, 22/05/2026): if the device has
          // been collected or assessed, this should probably NOT be a
          // Fraud & VC Write Off. Add the note to the thread reply so the
          // operator can correct the closure type before it lands.
          const assetReturn = await checkAssetReturnStatus(agId);
          try {
            const result = await writeCloseAgreements([agId], "fraud_and_vc_write_off", {
              triggeredBy: "cron",
              triggerSource: "cron:writeoff_approval_scan",
              actionTypeSuffix: "writeoff_approval_scan",
              requestedBy: approverName || "",
            });
            const wrote = result.written.find(w => w.id === agId);
            const row = wrote ? wrote.row : null;
            writeoffScanState.set(key, { outcome: "added_to_sheet_no_refund_needed", row, assetReturn: assetReturn.mayHaveReturnedAsset ? assetReturn : null, at: new Date().toISOString() });
            stateDirty = true;
            enrolWriteoffFollowup(agId, { sourceChannelId: ch.id, sourceThread_ts: thread_ts, sourceChannelName: ch.name });
            addedInThisThread.push({ agId, row, approverName, amount, refundProcessed: false, net: null, assetReturn });
            summary.addedToSheet.push(agId);
          } catch (err) {
            console.error(`[bill-ling] writeoff-scan: writeCloseAgreements failed for ${agId}:`, err.message);
            // Don't mark — try again next hour.
          }
        } else {
          // Refund directive issued → net check
          let net = 0, breakdown = new Map();
          try { ({ net, breakdown } = await getAgreementNetUnrefundedWithBreakdown(agId)); }
          catch (err) {
            console.error(`[bill-ling] writeoff-scan: Anchor net read failed for ${agId}:`, err.message);
            continue; // don't mark — retry next hour
          }

          if (net <= 0.01) {
            // Refund was processed (or netted out) — safe to add.
            const assetReturn = await checkAssetReturnStatus(agId);
            try {
              const result = await writeCloseAgreements([agId], "fraud_and_vc_write_off", {
              triggeredBy: "cron",
              triggerSource: "cron:writeoff_approval_scan",
              actionTypeSuffix: "writeoff_approval_scan",
              requestedBy: approverName || "",
            });
              const wrote = result.written.find(w => w.id === agId);
              const row = wrote ? wrote.row : null;
              writeoffScanState.set(key, { outcome: "added_to_sheet_refund_processed", net, row, assetReturn: assetReturn.mayHaveReturnedAsset ? assetReturn : null, at: new Date().toISOString() });
              stateDirty = true;
              enrolWriteoffFollowup(agId, { sourceChannelId: ch.id, sourceThread_ts: thread_ts, sourceChannelName: ch.name });
              addedInThisThread.push({ agId, row, approverName, amount, refundProcessed: true, net, assetReturn });
              summary.addedToSheet.push(agId);
            } catch (err) {
              console.error(`[bill-ling] writeoff-scan: writeCloseAgreements failed for ${agId}:`, err.message);
            }
          } else {
            // Refund due but not processed — DO NOT add to sheet; flag.
            const breakdownLines = [];
            for (const [tid, e] of [...breakdown.entries()].sort((a,b)=>a[0]-b[0])) {
              const desc = (TRANSACTION_TYPES?.[tid]) || `TypeId ${tid}`;
              breakdownLines.push(`  • TypeId ${tid} (${desc}) — ${e.count} txn(s), gross £${e.sum.toFixed(2)}`);
            }
            const flagText =
              `🚨 *Blocked* — write-off approved but refund directive not yet processed.\n\n` +
              `*Agreement:* ${agId}\n` +
              `*Approver:* ${approverName}${amount ? ` (£${amount.toFixed(2)})` : ""}\n` +
              (refundAmount ? `*Refund directive:* £${refundAmount.toFixed(2)}\n` : "") +
              `*Source:* ${threadRef} in #${ch.name}\n` +
              `*Net unrefunded cash:* *£${net.toFixed(2)}*\n` +
              (breakdownLines.length ? `\nBreakdown:\n${breakdownLines.join("\n")}\n` : "") +
              `\nNot added to the close sheet.`;
            try {
              await Promise.all([
                sendDM(CIARAN_DOBBIN_USER_ID, flagText),
                sendDM(CHARLOTTE_PLATT_USER_ID, flagText),
                sendDM(HARGO_USER_ID, flagText),
              ]);
              writeoffScanState.set(key, { outcome: "flagged_refund_due", net, at: new Date().toISOString() });
              stateDirty = true;
              summary.blockedRefundDue.push(agId);
            } catch (err) {
              console.error(`[bill-ling] writeoff-scan: flag DMs failed for ${agId}:`, err.message);
            }
          }
        }
      }

      // After the per-agreement loop for this thread: post a single combined
      // thread reply @-mentioning Hargo for any agreements added to the
      // close sheet. One post per thread, regardless of how many agreements
      // were added.
      if (addedInThisThread.length > 0) {
        const head = addedInThisThread.length === 1
          ? `<@${HARGO_USER_ID}> ✍️ added *${addedInThisThread[0].agId}* to the close sheet under *Fraud & VC Write Off*${addedInThisThread[0].row ? ` (row ${addedInThisThread[0].row})` : ""}.`
          : `<@${HARGO_USER_ID}> ✍️ added *${addedInThisThread.length}* agreement(s) to the close sheet under *Fraud & VC Write Off*:`;
        const lines = addedInThisThread.length === 1
          ? []
          : addedInThisThread.map(a => `• *${a.agId}*${a.row ? ` (row ${a.row})` : ""}${a.refundProcessed ? ` — refund processed (net £${a.net.toFixed(2)})` : ""}`);
        const refundLine = (addedInThisThread.length === 1 && addedInThisThread[0].refundProcessed)
          ? `\nRefund processed (net £${addedInThisThread[0].net.toFixed(2)}).`
          : "";
        const approver = addedInThisThread[0].approverName;
        const approverAmount = addedInThisThread[0].amount;
        const approverLine = approver !== "(unknown)"
          ? `\nApprover: ${approver}${approverAmount ? ` (£${approverAmount.toFixed(2)})` : ""}.`
          : "";
        // Asset-return notes (Hargo, 22/05/2026): if any added agreement
        // has collection_completed_at or assessment_completed_at set in
        // landing_billington, flag it — the device may have been returned
        // already, in which case Asset Return is the correct closure type,
        // not Fraud & VC Write Off.
        const assetReturnLines = addedInThisThread
          .filter(a => a.assetReturn && a.assetReturn.mayHaveReturnedAsset)
          .map(a => {
            const cc = a.assetReturn.collectionCompletedAt;
            const ac = a.assetReturn.assessmentCompletedAt;
            const parts = [];
            if (cc) parts.push(`collection_completed_at = ${cc}`);
            if (ac) parts.push(`assessment_completed_at = ${ac}`);
            return `• *${a.agId}* — ${parts.join(", ")}`;
          });
        const assetReturnSection = assetReturnLines.length > 0
          ? `\n\n⚠️ *Asset may have already been returned* — consider whether Asset Return (TypeId 30) is the correct closure type rather than Fraud & VC Write Off:\n${assetReturnLines.join("\n")}`
          : "";
        const body = [head, ...lines].join("\n") + refundLine + approverLine + assetReturnSection;
        // Pre-post idempotency: check the thread for an existing add-to-sheet
        // reply for the SAME set of agreement IDs from Billington. If found,
        // skip the post entirely. Hargo, 22/05/2026 (post-A00282576 incident).
        const addedAgreementSet = new Set(addedInThisThread.map(a => a.agId));
        let alreadyPosted = false;
        try {
          const tr = await app.client.conversations.replies({
            token: SLACK_BOT_TOKEN, channel: ch.id, ts: thread_ts, limit: 200,
          });
          alreadyPosted = (tr.messages || []).some(m => {
            const isBotMsg = (BOT_USER_ID && m.user === BOT_USER_ID) || !!m.bot_id;
            if (!isBotMsg && m.user) return false;
            const t = m.text || "";
            if (!/added .* to the close sheet under \*?Fraud & VC Write Off/i.test(t)) return false;
            // Must mention every agreement in this batch
            for (const a of addedAgreementSet) {
              if (!t.includes(a)) return false;
            }
            return true;
          });
        } catch (err) {
          console.error(`[bill-ling] writeoff-scan: add-to-sheet idempotency read failed: ${err.message}`);
          alreadyPosted = true; // fail closed
        }
        if (alreadyPosted) {
          console.log(`[bill-ling] writeoff-scan: skipping add-to-sheet post for thread ${thread_ts} — already posted in this thread.`);
        } else {
          try {
            await app.client.chat.postMessage({
              token: SLACK_BOT_TOKEN,
              channel: ch.id,
              thread_ts,
              text: body,
              mrkdwn: true,
              unfurl_links: false,
              unfurl_media: false,
            });
          } catch (err) {
            console.error(`[bill-ling] writeoff-scan: thread-reply add-to-sheet post failed (${ch.name} ts=${thread_ts}):`, err.message);
          }
        }
      }
    }
  }

  if (stateDirty) saveWriteoffScanState();
  console.log(`[bill-ling] writeoff-scan(${runLabel}): done — threads=${summary.threadsScanned}, alreadyHandled=${summary.alreadyHandled}, closureNotes=${summary.closureNotesPosted.length}, added=${summary.addedToSheet.length}, blockedOpenQ=${summary.blockedOpenQuestion.length}, blockedRefund=${summary.blockedRefundDue.length}, classifyErrors=${summary.classifyErrors}`);
  return summary;
}

// ---------------------------------------------------------------------------
// Write-off follow-up tracker (Hargo, 22/05/2026)
// After Billington adds an agreement to the close sheet, the write-off
// transaction (TypeId 26 or 70) still has to be posted in Anchor by the
// operations team. This tracker re-checks Anchor each working day and:
//   - marks the entry resolved when the closure transaction lands;
//   - escalates to Hargo / Charlotte / Ciaran by DM when 5 working days
//     have passed without the closure transaction being posted.
// State is keyed by agreement ID and persisted to JSON + GCS.
// ---------------------------------------------------------------------------
const WRITEOFF_FOLLOWUP_FILE = require("path").join(__dirname, "writeoff-followup.json");
const WRITEOFF_FOLLOWUP_GCS_KEY = "writeoff-followup.json";
const WRITEOFF_FOLLOWUP_ESCALATE_AFTER_DAYS = 5;
let writeoffFollowup = new Map(); // agreementId → { addedAt, sourceChannelId, sourceThread_ts, sourceChannelName, lastCheckedAt, checksRun, escalatedAt, resolvedAt, anchorTypeId }

function loadWriteoffFollowupLocal() {
  try {
    if (fs.existsSync(WRITEOFF_FOLLOWUP_FILE)) {
      const data = JSON.parse(fs.readFileSync(WRITEOFF_FOLLOWUP_FILE, "utf8"));
      writeoffFollowup = new Map(Object.entries(data.entries || {}));
      console.log(`[bill-ling] Loaded ${writeoffFollowup.size} writeoff-followup entries from local.`);
    }
  } catch (err) {
    console.error("[bill-ling] writeoff-followup local load failed:", err.message);
  }
}
async function loadWriteoffFollowupGcs() {
  try {
    const data = await loadJsonFromGcs(WRITEOFF_FOLLOWUP_GCS_KEY);
    if (data?.entries) {
      for (const [k, v] of Object.entries(data.entries)) writeoffFollowup.set(k, v);
      console.log(`[bill-ling] Loaded writeoff-followup from GCS; total now ${writeoffFollowup.size}.`);
    }
  } catch (err) {
    console.warn("[bill-ling] writeoff-followup GCS load failed:", err.message);
  }
}
function saveWriteoffFollowup() {
  const payload = { entries: Object.fromEntries(writeoffFollowup) };
  try { fs.writeFileSync(WRITEOFF_FOLLOWUP_FILE, JSON.stringify(payload, null, 2)); } catch (_) {}
  saveJsonToGcs(WRITEOFF_FOLLOWUP_GCS_KEY, payload).catch(() => {});
}
loadWriteoffFollowupLocal();
loadWriteoffFollowupGcs();

/**
 * Post a single factual closure note in the source Slack thread when a
 * write-off transaction has been posted in Anchor. Idempotent — checks the
 * thread for an existing note (our canonical marker) before posting.
 *
 * Hargo, 22/05/2026: the strict-silence rule still applies to conversational
 * replies, but closure notes are factual record-keeping and MUST appear in
 * the thread so the team has visibility without checking Anchor manually.
 *
 * Returns true if a new note was posted, false if one already existed.
 */
// Marker for closure note dedup. The text "Closure recorded" is the
// canonical anchor — Slack converts the literal 📝 emoji to `:memo:` in
// the stored text, so we MUST NOT rely on the emoji for matching.
const WRITEOFF_NOTE_MARKER_PATTERN = /Closure recorded:?\s*\*?(A\d{5,9})\*?/i;

// Process-level dedup: keys of (channel:thread_ts:agreementId) for closure
// notes posted in the current process lifetime. Prevents same-process repeat
// posts even when state save is mid-flight. Resets on container restart, but
// the Slack-thread check + GCS state pickup any cross-restart duplicates.
const postedClosureKeysThisProcess = new Set();

/**
 * Post a single factual closure note in the source Slack thread when a
 * write-off transaction has been posted in Anchor. Layered idempotency
 * (Hargo, 22/05/2026 — A00282576 duplicate-post incident):
 *   1. Process-level Set: instant skip if posted in this run.
 *   2. GCS state pickup: written synchronously after a successful post, so
 *      a restart mid-run can still pick up progress.
 *   3. Slack-thread inspection: look for "Closure recorded ... A00X" in any
 *      prior message in the thread (any author, any emoji form — the text
 *      "Closure recorded" plus the agreement ID is sufficient).
 *   4. Pre-post intent flag: write GCS state with `postIntent` BEFORE the
 *      Slack POST, so even if the post succeeds but state save fails, the
 *      next process sees the intent and refuses to re-post until the
 *      thread inspection confirms.
 *   5. Post-read confirmation: after posting, wait briefly and re-read the
 *      thread to confirm our message is visible. If not, log warning but
 *      treat as success (Slack's eventual consistency).
 *
 * Returns true if a new note was posted, false if a duplicate was skipped
 * or an error prevented the post.
 */
async function noteClosureOnThread(channelId, thread_ts, agreementId, anchorTypeId, anchorDate, description) {
  if (!channelId || !thread_ts || !agreementId) return false;
  const dedupKey = `${channelId}:${thread_ts}:${agreementId}`;

  // Layer 1: process-level dedup
  if (postedClosureKeysThisProcess.has(dedupKey)) {
    console.log(`[bill-ling] noteClosureOnThread: skipped ${agreementId} — already posted in this process.`);
    return false;
  }

  // Layer 3: Slack-thread inspection. Match "Closure recorded ... A00X"
  // by regex — robust to emoji conversion (📝 ↔ :memo:) and any past
  // formatting variant.
  try {
    const tr = await app.client.conversations.replies({
      token: SLACK_BOT_TOKEN, channel: channelId, ts: thread_ts, limit: 200,
    });
    const msgs = tr.messages || [];
    const alreadyNoted = msgs.some(m => {
      // Only consider bot-authored messages (Billington's own posts).
      const isBotMsg = (BOT_USER_ID && m.user === BOT_USER_ID) || !!m.bot_id;
      if (!isBotMsg && m.user) return false;
      const t = m.text || "";
      if (!t.includes(agreementId)) return false;
      return /Closure recorded/i.test(t);
    });
    if (alreadyNoted) {
      console.log(`[bill-ling] noteClosureOnThread: skipped ${agreementId} — thread already has a closure note.`);
      postedClosureKeysThisProcess.add(dedupKey); // cache so we don't re-inspect next time
      return false;
    }
  } catch (err) {
    console.error(`[bill-ling] noteClosureOnThread: thread read failed for ${agreementId}:`, err.message);
    // Fail closed — don't post if we can't verify idempotency.
    return false;
  }

  const desc = description || TRANSACTION_TYPES[anchorTypeId] || "Closure";
  // Use shortcode :memo: instead of the literal emoji so what Slack stores
  // matches our match regex byte-for-byte (defensive; the regex covers
  // both, but no point relying on emoji conversion behavior).
  const text = `<@${HARGO_USER_ID}> :memo: Closure recorded: *${agreementId}* — TypeId ${anchorTypeId} (${desc}) posted in Anchor${anchorDate ? ` on ${anchorDate}` : ""}.`;

  // Layer 4: pre-post intent. Mark in process Set FIRST so concurrent
  // callers in the same process can't double-post even if the second call
  // raced past the Slack-inspection check.
  postedClosureKeysThisProcess.add(dedupKey);

  try {
    await app.client.chat.postMessage({
      token: SLACK_BOT_TOKEN,
      channel: channelId,
      thread_ts,
      text,
      mrkdwn: true,
      unfurl_links: false,
      unfurl_media: false,
    });
    return true;
  } catch (err) {
    console.error(`[bill-ling] noteClosureOnThread: post failed for ${agreementId}:`, err.message);
    // Roll back the process-level guard so a retry next run can attempt.
    postedClosureKeysThisProcess.delete(dedupKey);
    return false;
  }
}

function enrolWriteoffFollowup(agreementId, source) {
  if (writeoffFollowup.has(agreementId)) return; // don't reset clock on duplicates
  writeoffFollowup.set(agreementId, {
    addedAt: new Date().toISOString(),
    sourceChannelId: source?.sourceChannelId || null,
    sourceThread_ts: source?.sourceThread_ts || null,
    sourceChannelName: source?.sourceChannelName || null,
    lastCheckedAt: null,
    checksRun: 0,
    escalatedAt: null,
    resolvedAt: null,
    anchorTypeId: null,
  });
  saveWriteoffFollowup();
}

async function runWriteoffFollowupCheck() {
  const writeOffAnchorTypeIds = CLOSE_REASON_COLUMNS.fraud_and_vc_write_off.anchorTypeIds; // [26, 70]
  const todayIso = londonTodayIso();
  let dirty = false;
  let resolvedCount = 0;
  let escalatedCount = 0;
  let pendingCount = 0;

  for (const [agId, entry] of writeoffFollowup.entries()) {
    if (entry.resolvedAt) continue; // already done
    // Re-check Anchor for closure transaction
    let anchorClose = { found: false };
    try { anchorClose = await checkAnchorForCloseTransaction(agId, writeOffAnchorTypeIds); }
    catch (err) {
      console.error(`[bill-ling] writeoff-followup: Anchor check failed for ${agId}:`, err.message);
      continue;
    }
    entry.lastCheckedAt = new Date().toISOString();
    entry.checksRun = (entry.checksRun || 0) + 1;
    dirty = true;

    if (anchorClose.found) {
      // Pre-post state save: mark resolved BEFORE posting so SIGTERM mid-call
      // doesn't lose the resolution flag (which would cause re-post on next
      // run). Save synchronously to GCS.
      entry.resolvedAt = new Date().toISOString();
      entry.anchorTypeId = anchorClose.typeId;
      resolvedCount++;
      saveWriteoffFollowup();
      if (entry.sourceChannelId && entry.sourceThread_ts) {
        try {
          await noteClosureOnThread(entry.sourceChannelId, entry.sourceThread_ts, agId, anchorClose.typeId, anchorClose.date, anchorClose.description);
        } catch (err) {
          console.error(`[bill-ling] writeoff-followup: noteClosureOnThread failed for ${agId}:`, err.message);
        }
      }
      continue;
    }

    // Not posted yet. How many working days since added?
    const addedDateIso = (entry.addedAt || "").slice(0, 10);
    const wdSinceAdded = workingDaysBetween(addedDateIso, todayIso);
    if (!entry.escalatedAt && wdSinceAdded >= WRITEOFF_FOLLOWUP_ESCALATE_AFTER_DAYS) {
      const sourceLine = entry.sourceChannelName && entry.sourceThread_ts
        ? `\n*Source:* thread ts=${entry.sourceThread_ts} in #${entry.sourceChannelName}`
        : "";
      const escalation =
        `⏰ *Write-off escalation* — ${wdSinceAdded} working day(s) since *${agId}* was added to the close sheet; closure transaction (TypeId 26/70) still not posted in Anchor.${sourceLine}\n` +
        `Added: ${addedDateIso}`;
      try {
        await Promise.all([
          sendDM(HARGO_USER_ID, escalation),
          sendDM(CHARLOTTE_PLATT_USER_ID, escalation),
          sendDM(CIARAN_DOBBIN_USER_ID, escalation),
        ]);
        entry.escalatedAt = new Date().toISOString();
        escalatedCount++;
      } catch (err) {
        console.error(`[bill-ling] writeoff-followup: escalation DM failed for ${agId}:`, err.message);
      }
    } else {
      pendingCount++;
    }
  }

  if (dirty) saveWriteoffFollowup();
  console.log(`[bill-ling] writeoff-followup: ${resolvedCount} resolved, ${escalatedCount} escalated, ${pendingCount} pending.`);
}

function londonTodayIso() {
  const now = new Date();
  // Convert to London TZ via locale parts
  const parts = new Intl.DateTimeFormat("en-CA", { timeZone: "Europe/London", year: "numeric", month: "2-digit", day: "2-digit" }).formatToParts(now);
  const y = parts.find(p=>p.type==="year").value;
  const m = parts.find(p=>p.type==="month").value;
  const d = parts.find(p=>p.type==="day").value;
  return `${y}-${m}-${d}`;
}

