/**
 * Sanitise Claude output for Slack mrkdwn — fix common markdown leaks.
 * Converts **bold** → *bold*, removes markdown tables, strips ## headers.
 */
function sanitiseForSlack(text) {
  // Convert markdown links [text](url) to Slack links <url|text>
  text = text.replace(/\[([^\]]+)\]\(([^)]+)\)/g, "<$2|$1>");
  // Convert **bold** to *bold* (Slack mrkdwn)
  text = text.replace(/\*\*([^*]+)\*\*/g, "*$1*");
  // Convert markdown headers (## Heading) to *Heading*
  text = text.replace(/^#{1,6}\s+(.+)$/gm, "*$1*");
  // Remove markdown table separators (|---|---|)
  text = text.replace(/^\|[-:\s|]+\|$/gm, "");
  // Convert markdown table rows to bullet points
  text = text.replace(/^\|\s*(.+?)\s*\|$/gm, (_, row) => {
    const cells = row.split("|").map(c => c.trim()).filter(Boolean);
    return cells.length > 1 ? `• ${cells.join(" | ")}` : `• ${cells[0]}`;
  });
  // Strip em dashes and en dashes — the model keeps using them despite instructions
  text = text.replace(/\s*[—–]\s*/g, ", ");
  // Clean up any resulting double commas or comma-at-start
  text = text.replace(/,\s*,/g, ",");
  text = text.replace(/^\s*,\s*/gm, "");
  // Remove consecutive blank lines
  text = text.replace(/\n{3,}/g, "\n\n");
  return text.trim();
}

/**
 * Decide whether an Anthropic API error should be retried.
 * Transient: 429 (rate limited), 5xx including the 529 "Overloaded" code,
 * network/connection errors. Anything else (4xx other than 429) → no retry.
 */
function _isTransientAnthropicError(err) {
  if (!err) return false;
  const status = err.status || err.statusCode || (err.response && err.response.status);
  if (typeof status === "number") {
    if (status === 429) return true;
    if (status >= 500 && status <= 599) return true; // includes 529 Overloaded
  }
  // Anthropic SDK surfaces overloaded as err.error?.error?.type === "overloaded_error"
  const innerType = err?.error?.error?.type || err?.error?.type;
  if (innerType === "overloaded_error" || innerType === "rate_limit_error" || innerType === "api_error") return true;
  // Network-level errors
  const code = err.code || err.cause?.code;
  if (code === "ECONNRESET" || code === "ETIMEDOUT" || code === "ENOTFOUND" || code === "EAI_AGAIN") return true;
  return false;
}

/**
 * Wrap a `anthropic.messages.create` call with exponential backoff retries on
 * transient errors (429, 5xx including 529 overloaded, network blips), plus
 * a final fallback to CLAUDE_FALLBACK_MODEL when the primary model exhausts.
 *
 * Retry schedule: 6 attempts at 0/1/3/7/15/30 seconds — total ~56s ceiling.
 * The longer tail handles sustained Anthropic-side overload windows.
 *
 * Fallback: once retries on the primary model are exhausted (and the last
 * error was transient), one final attempt is made on the fallback model.
 * Anthropic's serving capacity is per-model, so a Sonnet/Haiku attempt often
 * succeeds when Opus is overloaded. The fallback is skipped if the caller
 * already specified a non-default model, or if the env-overridable
 * CLAUDE_FALLBACK_MODEL is blank.
 */
async function _callAnthropicWithRetry(label, params) {
  const delays = [0, 1000, 3000, 7000, 15000, 30000];
  let lastErr = null;
  for (let i = 0; i < delays.length; i++) {
    if (delays[i] > 0) await new Promise(r => setTimeout(r, delays[i]));
    try {
      return await anthropic.messages.create(params);
    } catch (err) {
      lastErr = err;
      const status = err.status || err.statusCode || (err?.response?.status) || "?";
      const inner = err?.error?.error?.type || err?.error?.type || "";
      const isTransient = _isTransientAnthropicError(err);
      const exhausted = i === delays.length - 1;
      if (!isTransient || exhausted) {
        // Fallback model attempt — only when transient and we haven't already
        // been calling the fallback, and the fallback is configured.
        if (isTransient && CLAUDE_FALLBACK_MODEL && params.model !== CLAUDE_FALLBACK_MODEL) {
          console.warn(`[bill-ling] ${label}: primary model ${params.model} exhausted (status=${status}${inner ? `, type=${inner}` : ""}). Falling back to ${CLAUDE_FALLBACK_MODEL}.`);
          try {
            return await anthropic.messages.create({ ...params, model: CLAUDE_FALLBACK_MODEL });
          } catch (fbErr) {
            const fbStatus = fbErr.status || fbErr.statusCode || (fbErr?.response?.status) || "?";
            const fbInner = fbErr?.error?.error?.type || fbErr?.error?.type || "";
            console.error(`[bill-ling] ${label}: fallback model ${CLAUDE_FALLBACK_MODEL} also failed (status=${fbStatus}${fbInner ? `, type=${fbInner}` : ""}): ${fbErr.message}`);
            throw fbErr;
          }
        }
        console.error(`[bill-ling] ${label}: non-retryable or out of retries (status=${status}${inner ? `, type=${inner}` : ""}): ${err.message}`);
        throw err;
      }
      console.warn(`[bill-ling] ${label}: transient error (status=${status}${inner ? `, type=${inner}` : ""}), retry ${i + 1}/${delays.length - 1} in ${delays[i + 1]}ms...`);
    }
  }
  throw lastErr;
}

async function askClaude(userMessage, { model } = {}) {
  try {
    const response = await _callAnthropicWithRetry("askClaude", {
      model: model || CLAUDE_MODEL,
      max_tokens: 4096,
      system: getSystemPromptWithDate(),
      messages: [{ role: "user", content: userMessage }],
    });
    const raw = response.content
      .filter((block) => block.type === "text")
      .map((block) => block.text)
      .join("\n");
    return sanitiseForSlack(raw);
  } catch (err) {
    console.error("[bill-ling] askClaude error:", err.message);
    throw err; // re-throw so callers with specific fallbacks can handle it
  }
}

/**
 * Send a multi-turn conversation to Claude with the Bill Ling system prompt.
 * Maintains the provided history array (mutated in-place with the new pair).
 *
 * @param {Array<{role: string, content: string}>} history  Mutable history array
 * @param {string} userMessage
 * @returns {Promise<string>}
 */
async function askClaudeWithHistory(history, userMessage) {
  // Append user turn
  history.push({ role: "user", content: userMessage });

  // Keep only the last MAX_HISTORY_MESSAGES entries to avoid token bloat
  while (history.length > MAX_HISTORY_MESSAGES) {
    history.shift();
  }

  const response = await _callAnthropicWithRetry("askClaudeWithHistory", {
    model: CLAUDE_MODEL,
    max_tokens: 4096,
    system: getSystemPromptWithDate(),
    messages: history,
  });

  const assistantText = sanitiseForSlack(
    response.content
      .filter((block) => block.type === "text")
      .map((block) => block.text)
      .join("\n")
  );

  // Append assistant turn
  history.push({ role: "assistant", content: assistantText });

  // Trim again after appending assistant reply
  while (history.length > MAX_HISTORY_MESSAGES) {
    history.shift();
  }

  return assistantText;
}

/**
 * Fetch a Slack private file URL and return { data: base64string, media_type }.
 * Returns null if the fetch fails or the file is not an image.
 */
async function fetchSlackImageAsBase64(urlPrivate) {
  try {
    const res = await fetch(urlPrivate, {
      headers: { Authorization: `Bearer ${SLACK_BOT_TOKEN}` },
    });
    if (!res.ok) {
      console.error(`[bill-ling] fetchSlackImageAsBase64: HTTP ${res.status} for ${urlPrivate}`);
      return null;
    }
    const contentType = res.headers.get("content-type") || "image/jpeg";
    const mediaType = contentType.split(";")[0].trim();
    const allowedTypes = ["image/jpeg", "image/png", "image/gif", "image/webp"];
    if (!allowedTypes.includes(mediaType)) return null;
    const buffer = await res.arrayBuffer();
    const data = Buffer.from(buffer).toString("base64");
    return { data, media_type: mediaType };
  } catch (err) {
    console.error("[bill-ling] fetchSlackImageAsBase64 error:", err.message);
    return null;
  }
}

/**
 * Send a message to Claude that includes one or more images.
 * imageBlocks: array of { data: base64, media_type: "image/jpeg"|"image/png"|... }
 */
async function askClaudeWithImages(userMessage, imageBlocks) {
  const contentBlocks = [
    ...imageBlocks.map(img => ({
      type: "image",
      source: { type: "base64", media_type: img.media_type, data: img.data },
    })),
    { type: "text", text: userMessage || "What do you see in this image?" },
  ];
  const response = await _callAnthropicWithRetry("askClaudeWithImages", {
    model: CLAUDE_MODEL,
    max_tokens: 4096,
    system: getSystemPromptWithDate(),
    messages: [{ role: "user", content: contentBlocks }],
  });
  const raw = response.content
    .filter(b => b.type === "text")
    .map(b => b.text)
    .join("\n");
  return sanitiseForSlack(raw);
}

// ---------------------------------------------------------------------------
// Intent classification
// ---------------------------------------------------------------------------

/**
 * Ask Claude to classify the intent of a message.
 * Returns one of: "make" | "bacs" | "email" | "summary" | "channel" | "instruction" | "general"
 */
const MASTER_PRAISE_PATTERN  = /\b(well\s*done|good|great|excellent)\b.{0,20}\b(my\s*apprentice)\b/i;
const HELLO_THERE_PATTERN    = /\bhello\s+there\b/i;
const LEARN_POWER_PATTERN    = /is it possible to learn this power/i;
const SON_PATTERN            = /\bson\b/i;
// Greeting pattern — deterministic so the LLM never misinterprets the time-based rule
const GREETING_PATTERN       = /^\s*(?:@\S+\s+)*good\s+(morning|afternoon|evening)\b[.!,]?\s*$/i;

/**
 * Returns the wrong-time-of-day greeting based on the ACTUAL current time in London.
 * In the morning (before 12:00) → "Good afternoon"
 * In the afternoon/evening (12:00+) → "Good morning"
 */
function wrongGreeting() {
  const hour = new Date().toLocaleString("en-GB", { hour: "numeric", hour12: false, timeZone: "Europe/London" });
  return Number(hour) < 12 ? "Good afternoon" : "Good morning";
}
const NOT_RESOLVED_PATTERN   = /not\s+(resolved|done|complete|finished|closed|actioned)|reopen|re-?open|remove\s+(the\s+)?(tick|check|✅)|still\s+open|still\s+pending|hasn.?t\s+been\s+(done|processed|resolved)/i;

// Resolve a channel from a message using #name or natural language keywords
function resolveChannelFromText(text) {
  const CHANNEL_MAP = {
    "data-billing-alerts":                  CHANNELS.DATA_BILLING_ALERTS,
    "data-billing-updates":                 CHANNELS.DATA_BILLING_UPDATES,
    "team-ops-strategy-only":               CHANNELS.TEAM_OPS_STRATEGY,
    "cross-functional-collections":         CHANNELS.CROSS_FUNCTIONAL_COLLECTIONS,
    "collab-hire-agreement-audit-updates":  CHANNELS.HIRE_AGREEMENT_AUDIT,
    "customer-refunds-and-complaints":      CHANNELS.CUSTOMER_REFUNDS,
    "team-billing-operations-emails":       CHANNELS.TEAM_BILLING_OPERATIONS_EMAILS,
  };
  // Try #channel-name first
  const hashMatch = text.match(/#([\w-]+)/);
  if (hashMatch && CHANNEL_MAP[hashMatch[1]]) return CHANNEL_MAP[hashMatch[1]];
  // Natural language fuzzy keywords → channel
  const lower = text.toLowerCase();
  if (/billing.?update|data.billing.update|data.update.channel|billing.channel/.test(lower))       return CHANNELS.DATA_BILLING_UPDATES;
  if (/billing.?alert|data.billing.alert/.test(lower))                          return CHANNELS.DATA_BILLING_ALERTS;
  if (/ops.?strategy|team.?ops/.test(lower))                                    return CHANNELS.TEAM_OPS_STRATEGY;
  if (/cross.?functional|collections.?channel/.test(lower))                     return CHANNELS.CROSS_FUNCTIONAL_COLLECTIONS;
  if (/hire.?agreement|audit.?update/.test(lower))                              return CHANNELS.HIRE_AGREEMENT_AUDIT;
  if (/refund.{0,20}channel|customer.{0,5}refund|refund.{0,20}complaint|complaint.{0,20}channel/.test(lower)) return CHANNELS.CUSTOMER_REFUNDS;
  return null;
}

// Reacts with 🤝 when someone thanks Billington. Hargo, 26/05/2026 (A00119901
// incident): only fire on messages that are PURELY a thanks. If the message
// contains an action command (write off / refund / check / process / etc.)
// or @-mentions someone other than Billington adjacent to the thanks, treat
// the thanks as directed elsewhere and fall through so the action handler
// runs. Prevents the bug where a multi-part message like
//   "@Mark Dornan great thanks for confirming!
//    @Billington write off A00119901"
// short-circuits on the thanks and never executes the write-off.
async function maybeReactThankYou(text, channel, ts) {
  const thankYouPattern = /\b(thank(s| you)?|cheers|appreciate(d)?|ta)\b/i;
  if (!thankYouPattern.test(text)) return false;

  // If the message contains an actionable command, DO NOT short-circuit.
  const actionablePattern = /\b(write[\s-]?off|refund|close\s+account|check|process|sync|run|scan|update|post|add|send|reverse|retry|try\s+again|fix|cancel|approve|charge|collect|trigger|action)\b/i;
  if (actionablePattern.test(text)) {
    return false;
  }

  // If there's an @-mention of someone OTHER than Billington in the message,
  // it's likely the thanks is directed at them — skip the reaction unless
  // the thanks is clearly attached to Billington.
  if (BOT_USER_ID) {
    const mentioned = [...text.matchAll(/<@([A-Z0-9]+)>/g)].map(m => m[1]);
    const someoneElseMentioned = mentioned.some(uid => uid !== BOT_USER_ID);
    const billingtonMentioned = mentioned.includes(BOT_USER_ID);
    // If someone else is mentioned and Billington isn't, the thanks isn't for us.
    if (someoneElseMentioned && !billingtonMentioned) return false;
    // If BOTH are mentioned, only react if "thanks" appears within ~40 chars
    // of the Billington mention (i.e. directly attached to us).
    if (someoneElseMentioned && billingtonMentioned) {
      const billingtonIdx = text.indexOf(`<@${BOT_USER_ID}>`);
      const window = text.slice(Math.max(0, billingtonIdx - 40), billingtonIdx + 40);
      if (!thankYouPattern.test(window)) return false;
    }
  }

  try {
    await app.client.reactions.add({
      token: SLACK_BOT_TOKEN,
      name: "handshake",
      channel,
      timestamp: ts,
    });
    console.log("[bill-ling] Reacted with 🤝 to thank-you message.");
  } catch (err) {
    if (!err.message?.includes("already_reacted")) {
      console.error("[bill-ling] Failed to add handshake reaction:", err.message);
    }
  }
  return true; // was a thank-you — caller should not send a text reply
}

async function classifyIntent(text) {
  const prompt = `You are classifying a message sent to Billington, an AI assistant for Hargo at Raylo (a UK phone subscription/leasing company).

Billington has access to:
- make: Make.com automation scenarios (Raylo's billing/ops automations — e.g. BACS Updates, ARUDD, GoCardless, Stripe, Direct Debit, collections campaigns). Route here ONLY when asking if a specific Make.com scenario/campaign/automation is running, active, paused, or turned off. Do NOT route here for questions about late fees timing or estimated time to apply fees — those use bacs_monitoring data and should go to bacs_files.
- gocardless_balance: The GoCardless *account* balance / funds held with GoCardless awaiting payout — e.g. "GoCardless balance", "GoCardless account balance", "how much is in the GoCardless account?", "GC funds", "when will the GoCardless funds run out?", "do we need to top up GoCardless?". This is the org-level payment-account balance (like the Stannp balance check), NOT a per-agreement query. Any question that names a specific A00… agreement ID goes to "agreement" (Anchor API), never here.
- arudd: Asking for the ARUDD bounce report/update — e.g. "ARUDD update", "bounce report", "what were yesterday's bounces", "ARUDD figures", "how many bounced today/yesterday". Route here whenever the question is specifically about the ARUDD bounce reconciliation report.
- bacs_files: Use for ANY request for a BACS batch report, BACS file update, batch generation details, or late fees timing — e.g. "today's BACS update", "give me the BACS update", "BACS batch update", "3pm update", "BACS summary", "BACS file summary", "show me all BACS files", "what batches have been generated", "batch report", "collection file update", "how many instalments are due on [date]", "how long will it take to generate the batch", "when does the batch need to be created", "batch generation time", "forecast for [date]", "estimated time to apply late fees", "when will late fees be applied", "late fees today". If the message contains "BACS" and is asking for a report, update, or summary, ALWAYS use bacs_files — never summary. If the message asks about late fees timing/estimated time, ALWAYS use bacs_files — never make.
- bacs: AGGREGATE / cross-agreement analytical questions about BACS payment data, damage fees, or BigQuery data — e.g. "how many DDs bounced?", "show me recollections for March", "what's the posted count for 27 March?", "what % of asset returns have damage fees?", "average damage fee amount", "damage fee rate by grade", "which agreements have damage fees?". ALSO use for BigQuery table/view queries — e.g. "when was this table last modified?", any mention of a GCP project/dataset/table name. Do NOT use for requests that say "BACS update", "BACS summary", or "3pm update" — those are bacs_files. CRITICAL: questions about transactions, payments, collections, refunds, reversals, arrears, balance, or DDs on ONE OR MORE specific A00… agreement IDs go to "agreement" (Anchor API), NEVER to "bacs" — BQ is delayed and lacks the per-transaction ledger detail.
- agreement: Use when checking ANYTHING via the live Anchor API for ONE OR MORE specific A00… agreement IDs. Triggers include: "check A00114761 via the API", "look up A00307833 in Anchor", "check the API for A00237049", "pull A00114761 from Anchor", "has the instalment been posted for A00122571?", "has the refund been posted on A00307833?", "was the DD posted for A00114761 today?", "check if the transaction has been posted for A00237049", AND ALSO any per-agreement payment/collection question: "have any payments been collected on A00190153?", "any successful collections on A00…?", "what DDs have been collected on A00…?", "has the customer paid on A00…?", "any failed DDs / bounces on A00…?", "any chargebacks on A00…?", "what's the payment history for A00…?", "show transactions on A00…", "is A00… up to date?", "what's the balance/outstanding/arrears on A00…?", "any refunds/reversals on A00…?". The keyword "collected", "collection", "payment", "DD", "card", "refund", "reversal", "chargeback", "bounce", "arrears", "balance" combined with a specific A00… ID ALWAYS routes to agreement (Anchor API), NEVER to bacs. The Anchor API has the real-time transaction ledger — BigQuery does NOT.
- email: Hargo's Gmail inbox and sent mail.
- summary: A summary of monitored Slack channels ONLY (billing alerts, billing updates, ops strategy, collections, hire agreement audit). NEVER use for BACS-related requests — if the message mentions BACS, use bacs_files instead.
- channel: a specific named Slack channel the user wants read.
- refunds: Use when the user wants a status check, drill-down, or action on items in the #customer-refunds-and-complaints channel — e.g. "which refunds are pending?", "any unconfirmed refunds?", "check the refunds channel", "show me outstanding refund requests", "post a refunds update", "mark those as paid", "all refund files have been paid", "confirm this batch was paid yesterday", "update the threads as paid". Also use when someone confirms that refund files have been paid/processed by Barclays. Do NOT use for factual data questions about refunds like "what is the highest refund amount", "how many refunds have we processed" — those are "general".
- tasks: Use when the user is asking about Billington's own scheduled tasks, routine, schedule, or automated checks — e.g. "what are your scheduled tasks?", "what do you do?", "your routine", "when do you check the refund channel?", "when is your next update?", "what are you monitoring?", "list your tasks", "your schedule". Do NOT use for user reminders (remind me / cancel reminder) — those are "reminder".
- notices: Use when asking for the daily Notices QA report (LPF/NODS and NOSIA/SNOSIA email QA) — e.g. "NODS report", "NOSIA update", "notices QA", "show me today's notices", "how many NODS were sent?", "SNOSIA failures?", "LPF and NODS QA". If the question is an analytical query about NODS/NOSIA data (trends, comparisons, specific dates), use "bacs" instead to query BigQuery directly.
- close_agreement: Use when the user wants to log an agreement closure, write-off, or close reason to the agreements sheet — e.g. "process write off for A00233543", "A00276240 asset lost in transit", "close A00259211 return to sender", "write off A00233543 and A00259211". Must include at least one agreement ID (A00XXXXXX) and a close reason (write off, lost in transit, return to sender, warranty return, asset return, escalation).
- instruction: the user is telling Billington to remember, learn, or update its behaviour.
- reminder: the user is asking Billington to set a reminder, cancel a reminder, or list their OWN reminders — e.g. "remind me to check BACS at 3pm", "remind Charlotte to pick up the residuals issue on Monday", "cancel reminder #3", "what reminders do I have", "set a reminder for 10am tomorrow". Do NOT use for questions about Billington's own scheduled tasks — those are "tasks".
- general: anything else — general questions, conversation, advice, OR statements/comments where Billington has been copied in but is not being directly asked to do anything (e.g. "think there was a data issue last night", "just so you know X happened").

IMPORTANT RULES:
- If the message is a passing comment, FYI, or observation (not a direct question or task for Billington), ALWAYS classify as "general" — even if it mentions BACS, data, or payments.
- Examples that must be "general": "think there was a data issue last night", "just so you know the batch failed", "heads up on X", "looks like Y happened".
- If the message is in a thread and is a go-ahead, confirmation, or proceed request (e.g. "can we proceed with the refund", "yes go ahead", "please process this", "happy to proceed"), classify as "general" — the thread context will guide the response. Do NOT classify these as "refunds" just because the word "refund" appears.
- Only classify as "bacs" if Billington is being directly asked to look something up or answer a question about payment data.
- If the message is too vague to confidently classify — e.g. just "update", "give me a summary", "what's happening", "any news?" with no clear subject — reply with: CLARIFY: followed by a short, specific question to ask the user. For example: "CLARIFY: Sure — did you want the BACS batch update, ARUDD bounce report, or a channel summary?"

Message: "${text.replace(/"/g, "'")}"

Reply with ONLY one word from this list (make, arudd, bacs_files, bacs, email, summary, channel, refunds, agreement, tasks, notices, instruction, reminder, general), OR if genuinely ambiguous reply with CLARIFY: followed by a short clarifying question.`;

  try {
    const result = await anthropic.messages.create({
      model: CLAUDE_MODEL,
      max_tokens: 60,
      messages: [{ role: "user", content: prompt }],
    });
    const raw = result.content[0]?.text?.trim() || "";
    if (raw.toUpperCase().startsWith("CLARIFY:")) return raw; // pass through as-is
    const intent = raw.toLowerCase();
    const valid = ["make", "stannp", "gocardless_balance", "arudd", "bacs_files", "bacs", "email", "summary", "channel", "refunds", "agreement", "close_agreement", "tasks", "instruction", "reminder", "missing_instalment_drill", "general"];
    return valid.includes(intent) ? intent : "general";
  } catch {
    return "general";
  }
}

/**
 * Get or create the in-memory conversation history for a given user.
 *
 * @param {string} userId
 * @returns {Array<{role: string, content: string}>}
 */
function getHistory(userId) {
  if (!conversationHistories.has(userId)) {
    conversationHistories.set(userId, []);
  }
  return conversationHistories.get(userId);
}

// ---------------------------------------------------------------------------
// Slack helpers
// ---------------------------------------------------------------------------

/**
 * Open (or retrieve) the DM channel with Hargo and return the channel ID.
 *
 * @returns {Promise<string>} DM channel ID
 */
async function getHargoDMChannel() {
  const result = await app.client.conversations.open({
    token: SLACK_BOT_TOKEN,
    users: HARGO_USER_ID,
  });
  return result.channel.id;
}

/**
 * Send a DM message to Hargo.
 *
 * @param {string} text  Message text (Slack mrkdwn)
 */
async function dmHargo(text) {
  const channelId = await getHargoDMChannel();
  const res = await app.client.chat.postMessage({
    token: SLACK_BOT_TOKEN,
    channel: channelId,
    text,
    mrkdwn: true,
  });
  // Return the posted message ts so callers can use it as a state key
  // (e.g. iOutlet "reply send email in this thread" workflow).
  return res?.ts || null;
}

/**
 * Detect if a message is asking to notify / DM Hargo and, if so, send
 * the DM and return a confirmation string.  Returns null if no notify
 * request was detected.
 *
 * @param {string} text         The user's message text
 * @param {string} senderName   Display name of the person asking
 * @param {string} [context]    Optional thread/conversation context
 * @returns {Promise<string|null>}  Confirmation text or null
 */
// Broader detection of 'please get a message to Hargo' phrasings so the
// deterministic dmHargo() path fires rather than the LLM hallucinating a
// fake DM. Covers: tell/notify/ping/dm/message/let/send/shoot/ask/flag/
// pass on/loop in/raise with Hargo, and the reverse 'Hargo should know /
// be informed / be updated / get a heads up' forms.
const NOTIFY_HARGO_RE = /\b(tell|notify|ping|dm|message|let|send|shoot|ask|flag|raise|loop|pass\s+on|pass\s+to|forward)\b[^.]{0,80}\bhargo\b|\bhargo\b[^.]{0,80}\b(know|informed|updated|aware|heads?[\s-]?up|a message|a dm|a ping|a note|in the loop)\b/i;

async function maybeNotifyHargo(text, senderName, context) {
  if (!NOTIFY_HARGO_RE.test(text)) return null;

  // Build a concise DM to Hargo with who asked and what about
  let dmText = `📩 *${senderName}* asked me to notify you`;

  // Try to extract the substance — strip the "tell Hargo" preamble
  const substance = text
    .replace(/\b(please\s+)?(tell|notify|ping|dm|message|let)\s+hargo\b/gi, "")
    .replace(/\bhargo\b/gi, "")
    .replace(/\b(know|informed|updated|aware)\b/gi, "")
    .replace(/^[\s,.:—–-]+/, "")
    .trim();

  if (substance.length > 5) {
    dmText += `:\n> ${substance}`;
  } else if (context) {
    // If the ask itself is vague ("tell Hargo"), pull from thread context
    const snippet = context.split("\n").slice(0, 4).join("\n");
    dmText += ` about this conversation:\n>>> ${snippet}`;
  } else {
    dmText += ` — they didn't specify details, you may want to check in with them.`;
  }

  try {
    await dmHargo(dmText);
    console.log(`[bill-ling] Sent Hargo notification DM on behalf of ${senderName}`);
    return `Done — I've sent Hargo a DM to let him know. 👍`;
  } catch (err) {
    console.error("[bill-ling] Failed to DM Hargo:", err);
    return `I tried to DM Hargo but hit an error. You may want to message him directly.`;
  }
}

/**
 * Send a DM to an arbitrary Slack user on Hargo's behalf.
 *
 * Only Hargo can trigger this (gated by caller). Detects the target via
 * an @-mention in the text (e.g. 'send @Sam ...' / 'DM @Sam ...'),
 * extracts the message payload, opens an IM channel with that user, and
 * posts the message. Returns a confirmation string for Slack, or null
 * if no eligible target was found.
 *
 * Returns null when:
 *   - No @-mention in the message (so we don't know who to DM)
 *   - The @-mentioned user is Billington (loop)
 *   - The @-mentioned user is Hargo (use the dmHargo path for that)
 */
async function maybeDMUserOnHargosBehalf(text, requesterUserId) {
  if (!text || requesterUserId !== HARGO_USER_ID) return null;
  // Must look like a DM-someone instruction (any of the standard verbs)
  // AND contain at least one @-mention of someone other than Billington/Hargo.
  if (!/\b(send|dm|message|tell|notify|ping|shoot|forward|pass\s+(to|on))\b/i.test(text)) return null;

  const mentioned = [...text.matchAll(/<@([A-Z0-9]+)>/g)].map(m => m[1])
    .filter(uid => uid !== BOT_USER_ID && uid !== HARGO_USER_ID);
  if (mentioned.length === 0) return null;
  // Pick the first eligible target — if Hargo wants multiple, he'll
  // issue separate commands.
  const targetUserId = mentioned[0];

  // Extract the actual message payload by stripping the command verbs
  // and the @-mentions. Heuristic but good enough for the 'send Sam
  // 5 bread sauce facts' shape.
  let payload = text
    .replace(new RegExp(`<@${BOT_USER_ID}>`, "g"), "")
    .replace(/<@[A-Z0-9]+>/g, "")
    .replace(/\b(please\s+)?(send|dm|message|tell|notify|ping|shoot|forward|pass\s+(to|on))\b/gi, "")
    .replace(/^[\s,.:—–-]+/, "")
    .trim();

  // If the payload is too short (e.g. just 'DM @Sam'), refuse rather
  // than send something empty.
  if (payload.length < 5) {
    return `I'd need a message to send. Try \`@Billington send <@${targetUserId}> [the actual content]\`.`;
  }

  try {
    const im = await app.client.conversations.open({
      token: SLACK_BOT_TOKEN,
      users: targetUserId,
    });
    const dmChannel = im.channel?.id;
    if (!dmChannel) throw new Error("conversations.open returned no channel id");
    // Prefix so the recipient knows the message came via Hargo, not from
    // Billington spontaneously. Helps if the message reads ambiguously.
    const message = `📨 _From Hargo (via Billington):_\n\n${payload}`;
    await app.client.chat.postMessage({
      token: SLACK_BOT_TOKEN,
      channel: dmChannel,
      text: message,
      mrkdwn: true,
      unfurl_links: false,
      unfurl_media: false,
    });
    console.log(`[bill-ling] Sent DM to ${targetUserId} on Hargo's behalf (${payload.length} chars).`);
    return `Done — DM sent to <@${targetUserId}>.`;
  } catch (err) {
    console.error(`[bill-ling] Failed to DM ${targetUserId} on Hargo's behalf:`, err.message);
    return `I tried to DM <@${targetUserId}> but hit an error: ${err.message}. You may want to message them directly.`;
  }
}

/**
 * Fetch the last N messages from a Slack channel and return them as a
 * formatted string suitable for inclusion in a Claude prompt.
 *
 * @param {string} channelId
 * @param {number} limit
 * @returns {Promise<string>}
 */
async function fetchChannelHistory(channelId, limit = HISTORY_LIMIT) {
  try {
    const result = await app.client.conversations.history({
      token: SLACK_BOT_TOKEN,
      channel: channelId,
      limit,
    });

    if (!result.messages || result.messages.length === 0) {
      return "(no recent messages)";
    }

    // Messages come back newest-first; reverse to chronological order
    const messages = [...result.messages].reverse();

    return messages
      .map((msg) => {
        const ts = msg.ts
          ? new Date(parseFloat(msg.ts) * 1000).toISOString()
          : "unknown time";
        const user = msg.user || msg.username || "unknown";
        const text = msg.text || "(no text)";
        return `[${ts}] <@${user}>: ${text}`;
      })
      .join("\n");
  } catch (err) {
    console.error(
      `[bill-ling] Error fetching history for channel ${channelId}:`,
      err.message
    );
    return `(error fetching messages: ${err.message})`;
  }
}

// ---------------------------------------------------------------------------
// BigQuery
// ---------------------------------------------------------------------------

function formatBQValue(v) {
  if (v === null || v === undefined) return "null";
  // BigQuery DATE/DATETIME/TIMESTAMP fields come back as {value: '2026-04-07'}
  if (typeof v === "object" && v !== null && "value" in v) return String(v.value);
  // BigQuery BigInt-like objects
  if (typeof v === "object" && typeof v.toNumber === "function") return String(v.toNumber());
  return String(v);
}

const BACS_SCHEMA = `Table: \`raylo-production.landing_billington.bacs_monitoring\`
Each row = one due_date. All _amount columns are in £ (decimal, e.g. 169895.53 = £169,895.53). Do NOT divide by 100.

Columns (exact names — use these precisely in SQL):
- due_date (DATE): instalment due date the batch relates to
- collection_batch_created_at (DATE): date the collections payment batch was generated — use to answer "was a file generated today?"
- recollection_batch_created_at (DATE): date the re-collections payment batch was generated
- total_instalments_due (INTEGER): total instalments falling due on this date
- instalment_profiles_due_after_30d (INTEGER): instalment profiles due more than 30 days away

Instalment Direct Debits:
- instalment_direct_debits_called_for_count (INTEGER): count of instalment DDs submitted/raised in Anchor
- instalment_direct_debits_called_for_amount (DECIMAL pence): total value of instalment DD requests
- instalment_direct_debits_posted_count (INTEGER): count of instalment DDs that successfully posted
- instalment_direct_debits_posted_amount (DECIMAL pence): value of successfully posted instalment DDs
- instalment_direct_debits_bounced_count (INTEGER): count of instalment DDs that bounced/failed (ARUDD)
- instalment_direct_debits_bounced_amount (DECIMAL pence): value of bounced instalment DDs
- instalment_direct_debits_in_batch_count (INTEGER): count of instalment DDs in the BACS file sent to GoCardless
- instalment_direct_debits_in_batch_amount (DECIMAL pence): value of instalment DDs in the BACS file
- instalment_direct_debits_failed_gc_count (INTEGER): count rejected by GoCardless before BACS submission
- instalment_direct_debits_confirmed_gc_count (INTEGER): count confirmed by GoCardless as submitted to BACS
- instalment_direct_debits_in_flight_gc_count (INTEGER): count still pending final status from GoCardless

Recollection Direct Debits (retries after a bounce):
- recollection_direct_debits_called_for_count (INTEGER): count of recollection/retry DDs raised
- recollection_direct_debits_called_for_amount (DECIMAL pence): value of recollection DDs raised
- recollection_direct_debits_posted_count (INTEGER): recollection DDs that successfully posted
- recollection_direct_debits_posted_amount (DECIMAL pence): value recovered via recollection
- recollection_direct_debits_bounced_count (INTEGER): recollection DDs that bounced again
- recollection_direct_debits_bounced_amount (DECIMAL pence): value of failed recollection attempts
- recollection_direct_debits_in_batch_count (INTEGER): recollection DDs in a BACS file
- recollection_direct_debits_in_batch_amount (DECIMAL pence): value of recollection DDs in file
- recollection_direct_debits_failed_gc_count (INTEGER): recollection DDs rejected by GoCardless
- recollection_direct_debits_confirmed_gc_count (INTEGER): recollection DDs confirmed by GoCardless
- recollection_direct_debits_in_flight_gc_count (INTEGER): recollection DDs awaiting GC status

Repair / Damage Fee Direct Debits:
- repair_direct_debits_called_for_count (INTEGER): count of repair/damage fee DDs raised
- repair_direct_debits_called_for_amount (DECIMAL pence): value of repair/damage fee DDs raised
- repair_direct_debits_posted_count (INTEGER): repair DDs that successfully posted
- repair_direct_debits_posted_amount (DECIMAL pence): value of collected repair fees
- repair_direct_debits_bounced_count (INTEGER): repair DDs that bounced
- repair_direct_debits_bounced_amount (DECIMAL pence): value of bounced repair DDs
- repair_direct_debits_in_batch_count (INTEGER): repair DDs in the BACS file
- repair_direct_debits_in_batch_amount (DECIMAL pence): value of repair DDs in file
- repair_direct_debits_failed_gc_count (INTEGER): repair DDs rejected by GoCardless
- repair_direct_debits_confirmed_gc_count (INTEGER): repair DDs confirmed by GoCardless
- repair_direct_debits_in_flight_gc_count (INTEGER): repair DDs awaiting GC status
- damage_fee_profiles_due_after_30d (INTEGER): repair/damage fee profiles due more than 30 days away

GoCardless Aggregates:
- total_failed_go_cardless (INTEGER): total DDs across all types rejected by GoCardless
- total_in_flight_go_cardless (INTEGER): total DDs across all types still pending GC status
- total_confirmed_go_cardless (INTEGER): total DDs across all types confirmed by GC

Percentages, Forecasts & Pending:
- percent_of_instalment_due_called_for (DECIMAL %): % of due instalments with a DD raised
- percent_of_repair_due_called_for (DECIMAL %): % of repair/damage fees due with a DD raised
- pending_recollection_count (INTEGER): agreements in arrears with bacs_retransmit=TRUE, queued for retry
- pending_recollection_amount (DECIMAL pence): value of transactions queued for retry
- late_fees_applied (DECIMAL): late payment fees already applied
- estimated_late_fees_to_apply (DECIMAL): late fees expected based on current bounces
- estimated_direct_debits_called_for (INTEGER): forward estimate of DDs expected to be raised
- estimated_direct_debits_bounce (INTEGER): forward estimate of DDs expected to bounce

Operational Timing:
- time_to_create_payment_batch (DURATION): time from trigger to batch created in Anchor
- time_to_send_payment_file (DURATION): time from batch creation to BACS file sent to GoCardless
- time_to_apply_fees (DURATION): time for late fees to be applied after a bounce
- time_to_trigger (DURATION): time from scheduled trigger to process starting`;

async function buildBacsSQL(question, today) {
  // Known UK bank holidays (add more as needed)
  const bankHolidays = `UK bank holidays to know:
- Easter Good Friday 2026: 2026-04-03
- Easter Monday 2026: 2026-04-06
- Early May bank holiday 2026: 2026-05-04
- Spring bank holiday 2026: 2026-05-25
- Summer bank holiday 2026: 2026-08-31
- Christmas Day 2026: 2026-12-25
- Boxing Day 2026: 2026-12-28`;

  const prevWD = prevWorkingDay(today);
  const nextWD = nextWorkingDay(today);
  const prompt = `Today is ${today}. Previous working day: ${prevWD}. Next working day: ${nextWD}. Write a single BigQuery SQL query to answer this question: "${question}"

${BACS_SCHEMA}

${bankHolidays}

Rules:
- Only select the columns needed to answer the question
- Use WHERE, GROUP BY, ORDER BY, SUM() as appropriate
- "after Easter bank holiday" means due_date > '2026-04-06'
- "before Easter" means due_date < '2026-04-03'
- For aggregates (totals, counts) use SUM()
- If the question is about BigQuery table/view metadata (last modified, last updated, list tables, list views), use __TABLES__ like this:
  - All tables and views in landing_billington: SELECT table_id, table_type, TIMESTAMP_MILLIS(last_modified_time) as last_modified FROM \`raylo-production.landing_billington.__TABLES__\` ORDER BY last_modified DESC
  - Single table/view: SELECT TIMESTAMP_MILLIS(last_modified_time) as last_modified FROM \`raylo-production.landing_billington.__TABLES__\` WHERE table_id = 'table_name'
  - For other datasets: replace landing_billington with the correct dataset name (e.g. dbt_production)
  - table_type values: TABLE = base table, VIEW = view
  - IMPORTANT: if the question asks about SOURCE TABLES of a view, OR asks "when was bacs_monitoring last updated/modified/refreshed", OR asks about the freshness/staleness of bacs_monitoring or any other landing_billington view — return the special token VIEW_SOURCE_LOOKUP:landing_billington:<view_name> and nothing else. e.g. VIEW_SOURCE_LOOKUP:landing_billington:bacs_monitoring or VIEW_SOURCE_LOOKUP:landing_billington:bacs_monitoring_mandates. These are VIEWs whose data comes from source tables; their freshness = the freshness of those source tables. The response will also include key upstream tables like core_subscriptions and core_payment_profiles.
- ARUDD mismatch queries: anchor_bounces = instalment_direct_debits_bounced_count + recollection_direct_debits_bounced_count + repair_direct_debits_bounced_count. gc_failed = total_failed_go_cardless. A mismatch = WHERE (instalment_direct_debits_bounced_count + recollection_direct_debits_bounced_count + repair_direct_debits_bounced_count) != total_failed_go_cardless. Always filter to rows where (collection_batch_created_at IS NOT NULL OR recollection_batch_created_at IS NOT NULL) (i.e. a file was actually generated). IMPORTANT: future dates (due_date > CURRENT_DATE()) will always show zero anchor bounces because the ARUDD file hasn't been processed into Anchor yet — this is expected, not a mismatch. For mismatch queries, always add AND due_date <= CURRENT_DATE() to exclude future dates from the mismatch comparison. If the user asks to see future dates separately, include them but label them clearly as 'pending — not yet due' (batch/GC data exists but Anchor bounce data will be 0 until the due date passes).
- AGREEMENT-LEVEL BACS DATA: \`raylo-production.landing_billington.bacs_monitoring_agreement_level\` has one row per BACS transmission, joined across the full payment lifecycle. Use this table to:
  (a) Drill down when bacs_monitoring shows discrepancies — find WHICH specific agreements/payments have issues
  (b) Investigate a specific agreement's payment history
  (c) Answer questions about stuck/failed/missing payments at the individual level
  Key columns: agreement_id, customer_id, bacs_trans_unique_id, gc_payment_id, anchor_transaction_id, anchor_reversal_id, bacs_date (DATE), bacs_amount (DECIMAL GBP), bacs_is_recollect (BOOL), bacs_error_desc, payment_profile_subtype (NULL=instalment, 'Damage Fee'=repair), gc_latest_action (STRING), gc_event_cause, gc_event_at, txn_creator (AUTOPOSTMON=auto-posted), txn_posted_date, reversal_posted_date, days_since_bacs_date (INT), lifecycle_stage (STRING), issue_bacs_error (BOOL), issue_no_batch (BOOL), issue_missing_from_gc (BOOL), issue_gc_stuck_in_flight (BOOL), issue_gc_failed_no_reversal (BOOL), issue_gc_paid_not_posted (BOOL).
  LIFECYCLE STAGES: 1_BACS_ERROR, 2_NO_GC_PAYMENT, 3_NO_BATCH, 4_AWAITING_GC, 5_GC_IN_FLIGHT, 6_GC_CONFIRMED, 7_SETTLED, 8_GC_PAID_NOT_POSTED, 9_BOUNCED_REVERSED, 10_BOUNCED_NOT_REVERSED, 11_GC_FAILED_NOT_POSTED, UNKNOWN.
  ISSUE SEVERITY: Critical = issue_gc_failed_no_reversal + issue_gc_paid_not_posted. High = issue_gc_stuck_in_flight WHERE days_since_bacs_date > 3. Medium = issue_no_batch + issue_missing_from_gc. Low = issue_bacs_error + issue_gc_stuck_in_flight WHERE days_since_bacs_date <= 2.
  DOMAIN RULES: BACS takes 3 working days — do NOT flag 'submitted' as stuck unless days_since_bacs_date > 3. Recollections (bacs_is_recollect=TRUE) have higher bounce rates (expected). AUTOPOSTMON = auto-posted (normal). GC terminal success: confirmed, paid_out. GC terminal failure: failed, cancelled, charged_back, chargeback_settled, late_failure_settled.
  DATE TERMINOLOGY: "payment date", "collection date", "due date" = bacs_date in this table (or due_date in bacs_monitoring). When filtering by payment date, ALWAYS use bacs_date — do NOT join to GC events just to get a date filter.
  CRITICAL — DO NOT JOIN TO GC EVENTS TABLE: bacs_monitoring_agreement_level ALREADY contains gc_event_at, gc_latest_action, and gc_event_cause. Do NOT join to intermediate_gocardless__payment_events unless the user explicitly asks for webhook IDs or multiple events per payment.
  CRITICAL — USE LIFECYCLE_STAGE FOR FILTERING: Always use lifecycle_stage to identify payment states. Do NOT reconstruct filters using individual columns (e.g. do NOT use "anchor_transaction_id IS NULL AND gc_latest_action IN (...)"). The lifecycle_stage column already encodes the correct business logic. Examples:
    - Bounces not posted in Anchor → WHERE lifecycle_stage = '11_GC_FAILED_NOT_POSTED' AND bacs_date <= CURRENT_DATE()
    - GC paid but not posted → WHERE lifecycle_stage = '8_GC_PAID_NOT_POSTED'
    - Bounced and reversed → WHERE lifecycle_stage = '9_BOUNCED_REVERSED'
  CRITICAL — FUTURE DATES: When querying for missing bounces / unposted reversals (lifecycle_stage = '11_GC_FAILED_NOT_POSTED'), ALWAYS add AND bacs_date <= CURRENT_DATE(). Anchor cannot have reversal transactions until the bacs_date has passed — future-dated rows will always appear as "not posted" but that is expected, not an issue. This applies to any query about missing/unposted bounce transactions.
  CRITICAL — DATE COLUMNS: "payment date", "collection date", "BACS date", "due date", "date of the bounce" = bacs_date. "Date GC reported the failure" = gc_event_at. When grouping bounces by date, use bacs_date (the payment date) unless the user specifically asks for the GC event/reporting date.
  CRITICAL — TIMESTAMP QUERIES: "when did we receive bounces from GoCardless?" or "what time did bounces come in?" = query bacs_monitoring_agreement_level for MIN(gc_event_at) and MAX(gc_event_at) grouped by bacs_date. "When were bounces posted in Anchor?" = there is no exact Anchor posting timestamp, but reversal_posted_date gives the date. The aggregate table bacs_monitoring does NOT have timestamps — always use the agreement-level table for any time/timing questions. Default to today's prevWorkingDay if no date specified.
  CRITICAL — BOUNCE TIMING: When querying gc_event_at for a bacs_date, ALWAYS show BOTH the earliest and latest event timestamps AND the DATE of those events (not just the time). Bounces for a single bacs_date can arrive over multiple days. Show: earliest gc_event_at, latest gc_event_at, and COUNT of bounces. If bounces arrived on different dates, break down by DATE(gc_event_at) so the user can see which arrived same-day vs late. Example: SELECT DATE(gc_event_at) AS received_date, MIN(gc_event_at) AS earliest, MAX(gc_event_at) AS latest, COUNT(*) AS bounces FROM bacs_monitoring_agreement_level WHERE bacs_date = '2026-04-17' AND gc_event_at IS NOT NULL GROUP BY DATE(gc_event_at) ORDER BY received_date
  STRATEGY: Use bacs_monitoring for aggregate questions. If it shows a discrepancy (e.g. anchor bounces != GC failures), automatically drill into bacs_monitoring_agreement_level to identify the specific agreements. When the user asks "which lines have an issue" or "show me the problems", query bacs_monitoring_agreement_level WHERE the relevant issue_* flag = TRUE.
  DRILL-DOWN QUERIES: When the user asks to see specific agreements (e.g. "show me the agreements", "which agreements", "list them", "drill down"), ALWAYS include agreement_id, bacs_amount, and bacs_date in the SELECT — these are needed for Anchor API cross-referencing. Example: SELECT agreement_id, bacs_amount, bacs_date FROM \`raylo-production.landing_billington.bacs_monitoring_agreement_level\` WHERE lifecycle_stage = '11_GC_FAILED_NOT_POSTED' AND bacs_date = '2026-03-27'
- AGREEMENT INFO: \`raylo-production.landing_billington.agreement_info\` — one row per agreement. Full schema:
  agreement_id (STRING — ALWAYS use this column name, NEVER agreement_reference or agreement_number),
  total_arrears (NUMERIC — positive = owes money, zero or negative = cleared),
  next_payment_date (DATE),
  assessment_completed_at (TIMESTAMP — when the device return assessment was completed; NULL = not yet assessed/returned),
  monthly_payment_amount (FLOAT64 — the recurring DD amount for this agreement),
  grade_description (STRING — device condition grade after assessment: 'Grade A', 'Grade B', 'Grade C', 'Grade D', 'Grade E', 'Grade F'),
  asset_return_category (STRING — type of return: 'warranty', 'upgrade', 'cancellation', etc.; NULL = no return),
  cancellation (BOOLEAN — true if the agreement is being cancelled, false if the lease continues).
  TERMINOLOGY: "repair charge" and "damage fee" mean the same thing at Raylo — both refer to payment_profile_subtype = 'Damage Fee' in bacs_monitoring_agreement_level. When the user says "repair charge", treat it identically to "damage fee".
  Agreement IDs always look like 'A' followed by 5 or 8 digits. "Agreement number", "agreement reference", "agreement ref", and "agreement ID" all mean agreement_id.
  JOINING TABLES: You can JOIN agreement_info with bacs_monitoring_agreement_level ON agreement_id to answer cross-cutting questions like:
  - "What % of assessed/returned devices have damage fees?" → JOIN agreement_info (WHERE assessment_completed_at IS NOT NULL) with bacs_monitoring_agreement_level (WHERE payment_profile_subtype = 'Damage Fee')
  - "Average damage fee amount" → AVG(bacs_amount) from bacs_monitoring_agreement_level WHERE payment_profile_subtype = 'Damage Fee'
  - "Damage fee rate by grade" → JOIN and GROUP BY grade_description
  Example: What percentage of assessed agreements have a damage fee?
    SELECT
      COUNTIF(df.agreement_id IS NOT NULL) AS with_damage_fee,
      COUNT(DISTINCT ai.agreement_id) AS total_assessed,
      ROUND(100.0 * COUNTIF(df.agreement_id IS NOT NULL) / COUNT(DISTINCT ai.agreement_id), 1) AS damage_fee_pct
    FROM \`raylo-production.landing_billington.agreement_info\` ai
    LEFT JOIN (SELECT DISTINCT agreement_id FROM \`raylo-production.landing_billington.bacs_monitoring_agreement_level\` WHERE payment_profile_subtype = 'Damage Fee') df ON ai.agreement_id = df.agreement_id
    WHERE ai.assessment_completed_at IS NOT NULL
  Example: Average damage fee amount
    SELECT ROUND(AVG(bacs_amount), 2) AS avg_damage_fee FROM \`raylo-production.landing_billington.bacs_monitoring_agreement_level\` WHERE payment_profile_subtype = 'Damage Fee'
  Example: Damage fee rate by device grade
    SELECT ai.grade_description, COUNT(DISTINCT ai.agreement_id) AS assessed, COUNTIF(df.agreement_id IS NOT NULL) AS with_damage_fee, ROUND(100.0 * COUNTIF(df.agreement_id IS NOT NULL) / COUNT(DISTINCT ai.agreement_id), 1) AS damage_fee_pct
    FROM \`raylo-production.landing_billington.agreement_info\` ai
    LEFT JOIN (SELECT DISTINCT agreement_id FROM \`raylo-production.landing_billington.bacs_monitoring_agreement_level\` WHERE payment_profile_subtype = 'Damage Fee') df ON ai.agreement_id = df.agreement_id
    WHERE ai.assessment_completed_at IS NOT NULL GROUP BY 1 ORDER BY 1
- GOCARDLESS PAYMENT EVENTS: \`raylo-production.dbt_production.intermediate_gocardless__payment_events\` tracks GoCardless payment lifecycle events. EXACT schema (use ONLY these column names):
  event_id (STRING), webhook_id (STRING), resource_type (STRING), action (STRING — e.g. "failed", "confirmed", "paid_out", "cancelled"), payment_id (STRING), event_cause (STRING — e.g. "payment_failed", "mandate_cancelled", "bank_account_closed"), event_description (STRING), agreement_id (STRING), created_at (STRING — ISO timestamp as string, e.g. "2026-03-30T09:15:00Z"), original_charge_date (STRING), webhook_pk (STRING).
  IMPORTANT: The column is called "action" NOT "event_action". created_at is a STRING not TIMESTAMP — use SAFE_CAST(created_at AS TIMESTAMP) or PARSE_TIMESTAMP when filtering by date.
  For latest failure today: SELECT SAFE_CAST(created_at AS TIMESTAMP) AS failed_at, payment_id, event_cause, event_description, agreement_id FROM \`raylo-production.dbt_production.intermediate_gocardless__payment_events\` WHERE DATE(SAFE_CAST(created_at AS TIMESTAMP)) = CURRENT_DATE() AND (action = 'failed' OR event_cause = 'payment_failed') ORDER BY created_at DESC LIMIT 1
- TRANSACTIONS DATA: \`raylo-production.dbt_production.stg_landing_sentinel_s3db01__transactions\` contains Raylo's internal transaction records (from Aryza/Anchor/Sentinel). EXACT schema:
  transaction_id (INT64), transaction_type_id (INT64), batch_number (STRING), transaction_reference (STRING), agreement_id (STRING), created_at (TIMESTAMP), transaction_date (TIMESTAMP), bacs_payment_made (BOOL), code (STRING), principal_net (NUMERIC), interest_net (NUMERIC), fees_net (NUMERIC), fees_vat (NUMERIC), arrears_principal_net (NUMERIC), arrears_fees_net (NUMERIC), arrears_tax (NUMERIC).
  Use this table to reconcile payments received in GoCardless against what is recorded internally. When asked to compare GC payments vs transactions, query both tables and compare counts/amounts by date.
- PROCESSED REFUNDS: \`raylo-production.landing_billington.processed_refunds\` — daily summary of refunds paid out via the bulk BACS refund file. Schema:
  date (DATE — the BACS processing date), amount (FLOAT — total refund amount in GBP for that day), count (INTEGER — number of individual refunds processed that day).
  This view only contains working days (Mon-Fri) — BACS does not process on weekends or bank holidays.
  Use this to answer questions like "how many refunds were processed last week?", "what was the total refund value this month?", "when was the last bulk refund file?".
  Example: SELECT date, count, amount FROM \`raylo-production.landing_billington.processed_refunds\` WHERE date >= DATE_SUB(CURRENT_DATE(), INTERVAL 30 DAY) ORDER BY date DESC
- MANDATE MONITORING (AGGREGATE): \`raylo-production.landing_billington.bacs_monitoring_mandates\` — daily aggregate counts of mandate activity (orders, agreements, BACS 0N instructions, GoCardless mandate events). Schema:
  date (DATE), agreement_created_count (INT), first_bacs_created_count (INT), orders_placed_count (INT), subscription_created_count (INT), gc_mandate_created (INT), gc_mandate_submitted (INT), gc_mandate_active (INT), gc_mandate_reinstated (INT), gc_mandate_resubmission_requested (INT), gc_mandate_failed (INT), gc_mandate_blocked (INT), gc_mandate_cancelled (INT), gc_mandate_transferred (INT), gc_mandate_expired (INT).
  Use this for aggregate mandate questions: "how many mandates failed this week?", "mandate creation vs activation trend", "what's the mandate failure rate?", "how many new mandates today?".
  bank_detail_classification context: first_bacs_created_count = first-ever 0N instruction per agreement ("New Mandate"). The gc_mandate_* columns track GoCardless lifecycle events by date.
  Example: SELECT date, gc_mandate_created, gc_mandate_active, gc_mandate_failed FROM \`raylo-production.landing_billington.bacs_monitoring_mandates\` WHERE date >= DATE_SUB(CURRENT_DATE(), INTERVAL 7 DAY) ORDER BY date DESC
- MANDATE MONITORING (AGREEMENT LEVEL): \`raylo-production.landing_billington.bacs_monitoring_mandates_agreement_level\` — per-agreement mandate detail with full GoCardless lifecycle dates. Schema:
  agreement_id (STRING), date (DATE — date of 0N BACS instruction), account_rank (INT — rank of this bank account for the agreement), agreement_rank (INT — rank of this 0N instruction for the agreement), mandate_id (STRING), bank_detail_classification (STRING — 'New Mandate' | 'New Bank Details' | 'Reinstate Bank Details'), mandate_created_at (DATE), mandate_submitted_at (DATE), mandate_active_at (DATE), mandate_reinstated_at (DATE), mandate_resubmission_requested_at (DATE), mandate_failed_at (DATE), mandate_blocked_at (DATE), mandate_cancelled_at (DATE), mandate_transferred_at (DATE), mandate_expired_at (DATE).
  Use this for agreement-level mandate questions: "what's the mandate status for A00XXXXXX?", "which agreements had mandate failures today?", "show me mandates that failed before going active".
  bank_detail_classification: 'New Mandate' = first-ever 0N for the agreement, 'New Bank Details' = new bank account (account_rank=1), 'Reinstate Bank Details' = same bank account resubmitted (account_rank>1).
  Example: SELECT agreement_id, mandate_id, bank_detail_classification, mandate_created_at, mandate_active_at, mandate_failed_at FROM \`raylo-production.landing_billington.bacs_monitoring_mandates_agreement_level\` WHERE agreement_id = 'A00XXXXXX'
- PENDING LATE FEES: \`raylo-production.landing_billington.pending_late_fees\` — agreements with late payment fees queued but not yet applied. Schema:
  execution_reference (STRING), agreement_id (STRING), add_transaction_transaction_date (DATE), add_transaction_transaction_amount (INT64 — pounds), set_team_status_status_id (INT64).
  Only shows fees where charge_lpf = TRUE and count_lpf_charged = 0. Source: collections_controls_late_payment_fees_to_apply.
  Use for: "how many pending late fees?", "total pending LPF amount?", "which agreements have pending fees?"
  Example: SELECT COUNT(*) AS volume, SUM(add_transaction_transaction_amount) AS total_amount FROM \`raylo-production.landing_billington.pending_late_fees\`
- NODS MONITORING: \`raylo-production.landing_billington.nods_monitoring\` — daily LPF (late payment fee) and NODS (Notice of Direct Debit Shortfall) totals. Schema:
  late_payment_fee_transaction_date (DATE), lpf_transaction_count (INT64), total_lpf_amount (NUMERIC), nods_email_count (INT64), nods_letter_count (INT64), total_nods_count (INT64), nods_coverage_pct (FLOAT64).
  Use for: "how many late fees today?", "NODS coverage?", "how many NODS emails sent?", "LPF totals this week?"
  Example: SELECT * FROM \`raylo-production.landing_billington.nods_monitoring\` WHERE late_payment_fee_transaction_date = CURRENT_DATE()
- NOSIA/SNOSIA MONITORING: \`raylo-production.landing_billington.nosia_snosia_monitoring\` — daily NOSIA (Notice of Subsequent Instalment Amounts) and SNOSIA (Sub-Notice of Subsequent Instalment Amounts) email send status. Schema:
  notice_due_date (DATE), notice_type (STRING — 'NOSIA' or 'SNOSIA'), triggered (INT64), sent (INT64), pending (INT64), failed (INT64).
  Use for: "NOSIA failures today?", "how many SNOSIA emails sent?", "notices QA for yesterday?"
  Example: SELECT * FROM \`raylo-production.landing_billington.nosia_snosia_monitoring\` WHERE notice_due_date = CURRENT_DATE()
- LATE FEES TIMING: Late payment fees are applied on the NEXT working day after the due date. So "late fees today" or "late fees being applied today" means late fees for payments that were due on the PREVIOUS working day (${prevWD}). When the user asks "how many late fees today", query bacs_monitoring WHERE due_date = '${prevWD}'. The relevant columns are estimated_late_fees_to_apply (count) and estimated_time_to_apply_late_fees (time). Similarly, "late fees tomorrow" = fees for today's due_date (${today}). ALWAYS use the previous working day for "today's late fees" — never use today's date.
- BANK HOLIDAYS: If the question asks about a specific date that falls on a UK bank holiday, return BANK_HOLIDAY:<date> (e.g. BANK_HOLIDAY:2026-04-06) instead of SQL. No instalments fall due on bank holidays, so there will never be any data for those dates.
- IMPORTANT: You have access to ALL the tables listed above — bacs_monitoring, bacs_monitoring_agreement_level, agreement_info, intermediate_gocardless__payment_events, stg_landing_sentinel_s3db01__transactions, processed_refunds, bacs_monitoring_mandates, bacs_monitoring_mandates_agreement_level, nods_monitoring, and nosia_snosia_monitoring. If the question can be answered by joining or querying these tables, WRITE THE SQL. Do NOT say you don't have access or ask which table to use — the schemas are all documented above. "Asset returns", "assessments", "damage fees", "grades" → use agreement_info and bacs_monitoring_agreement_level. "Mandates", "mandate failures", "mandate status" → use bacs_monitoring_mandates (aggregate) or bacs_monitoring_mandates_agreement_level (per-agreement). "NODS", "late payment fees", "LPF" → use nods_monitoring. "NOSIA", "SNOSIA", "notices" → use nosia_snosia_monitoring. "Pending fees", "fees to apply", "queued LPF" → use pending_late_fees.
- If you are not confident you can write a correct SQL query for the question asked, return CLARIFY: followed by a short question to ask the user for the missing detail. Do not guess.
- Return ONLY the SQL (or CLARIFY: message or BANK_HOLIDAY: token) — no explanation, no markdown, no backtick fences`;

  const raw = await askClaude(prompt);
  let sql = raw.trim();
  // Strip markdown code fences (start/end)
  sql = sql.replace(/^```sql?\n?/i, "").replace(/\n?```$/, "").trim();
  // If Claude returned preamble text + SQL in fences, extract just the SQL block
  const fenceMatch = sql.match(/```sql?\s*\n([\s\S]+?)\n```/i);
  if (fenceMatch) sql = fenceMatch[1].trim();
  // If Claude returned preamble text + bare SQL, extract from first SELECT/WITH
  // Note: WITH must be followed by a valid CTE pattern (WITH <name> AS) to avoid matching natural language like "with bacs_monitoring..."
  if (!/^\s*(SELECT\b|WITH\s+\w+\s+AS\s*\(|SHOW\b|DESCRIBE\b|CLARIFY:|BANK_HOLIDAY:|VIEW_SOURCE_LOOKUP:|FORECAST:)/i.test(sql)) {
    const sqlStart = sql.match(/\b(SELECT\b|WITH\s+\w+\s+AS\s*\()[\s\S]+$/i);
    if (sqlStart) sql = sqlStart[0].trim();
  }
  // Final cleanup
  return sql.replace(/^```sql?\n?/i, "").replace(/\n?```$/, "").trim();
}

async function runBigQuery(sql) {
  try {
    const [rows] = await bigquery.query({ query: sql, location: "EU" });
    if (!rows.length) return "No results returned.";
    const headers = Object.keys(rows[0]).join(" | ");
    const divider = headers.replace(/[^|]/g, "-");
    const body = rows.slice(0, 50).map((r) => Object.values(r).map(formatBQValue).join(" | ")).join("\n");
    const footer = rows.length > 50 ? `\n... (${rows.length - 50} more rows not shown)` : "";
    return `${headers}\n${divider}\n${body}${footer}`;
  } catch (err) {
    console.error("[bill-ling] BigQuery error:", err.message);
    return `BigQuery error: ${err.message}`;
  }
}

async function runBigQueryRaw(sql) {
  const [rows] = await bigquery.query({ query: sql, location: "EU" });
  return rows;
}

// ---------------------------------------------------------------------------
// Anchor Transaction Types (from Notion: Transaction Types page)
// ---------------------------------------------------------------------------
const TRANSACTION_TYPES = {
  0: "Cash receipt", 12: "Direct debit", 14: "Upfront payment", 15: "Upfront payment refund",
  20: "Adjustment", 22: "Promotional Credit", 23: "Card payment (S)", 24: "Card payment (S) reversal",
  25: "Early Termination Fee (Card)", 26: "Write-off", 27: "Write-back", 28: "Non-return fee (Card)",
  29: "FPC payment", 30: "Asset returned", 31: "Asset returned reversal",
  32: "Rebate future charges reversal", 33: "Rebate future charges", 34: "Asset purchased",
  35: "Refund bank transfer reversal", 36: "Asset purchased reversal",
  42: "Damage fee (Card)", 43: "Damage fee reversal (Card)", 44: "Non-return fee reversal (Card)",
  45: "Raylo payment", 46: "Asset lost in transit", 47: "Asset lost in transit reversal",
  48: "Raylo payment reversal", 49: "Late payment fee", 50: "Late payment fee reversal",
  51: "Adjustment (No Arrears)", 52: "SNOSIA letter", 53: "Opos payment",
  55: "Perch payment", 56: "Perch payment reversal", 59: "Early termination fee due",
  60: "Early termination fee applied", 61: "Gesture of goodwill", 62: "Gesture of goodwill reversal",
  63: "Non-return fee due", 64: "Non-return fee applied", 65: "NOSIA letter",
  66: "Non-return fee due reversal", 67: "Non-return fee applied reversal",
  68: "Debt sale proceeds", 69: "Debt sale proceeds reversal", 70: "Debt sale write-off",
  71: "Debt sale write-off reversal", 72: "Repair charge adjustment", 73: "Repair charge adjustment reversal",
  74: "Write off reversal", 75: "Write back reversal", 76: "Asset rehired", 99: "Instalment Due",
  149: "Refund bank transfer", 150: "Returned DD (RTP)", 151: "Returned DD (IC)", 152: "Returned DD (NI)",
  153: "Returned DD (NA)", 154: "Returned DD (ANYD)", 155: "Returned DD (PD)", 156: "Returned DD (AC)",
  157: "Chargeback", 158: "Chargeback reversed"
};

// ---------------------------------------------------------------------------
// Anchor SOAP API — GetAgreement
// ---------------------------------------------------------------------------
const ANCHOR_SOAP_URL = "https://xylofiproposalservice.anchor.co.uk/AnchorCollections.svc";
const ANCHOR_SOAP_ACTION = "urn:anchor.co.uk/2017/05/AnchorCollections/IAnchorCollections/GetAgreement";
const ANCHOR_SOAP_ADD_TXN_ACTION = "urn:anchor.co.uk/2017/05/AnchorCollections/IAnchorCollections/AddTransaction";
const ANCHOR_SOAP_CHANGE_DUE_DATE_ACTION = "urn:anchor.co.uk/2017/05/AnchorCollections/IAnchorCollections/ChangePayProDueDate";
const ANCHOR_SOAP_SET_TEAM_STATUS_ACTION = "urn:anchor.co.uk/2017/05/AnchorCollections/IAnchorCollections/SetTeamStatus";
// Target team status for the "NODS missing → move to 532" remediation flow.
// 532 is the status that downstream automation reads to send the NODS email.
const NODS_TARGET_TEAM_STATUS_ID = 532;
// TypeId 49 = Late payment fee. Used by the NODS remediation flow to find
// the most recent LPF date per agreement.
const LATE_PAYMENT_FEE_TYPE_ID = 49;

// Anchor SOAP credentials. Use env vars in production, with the new
// 'Billington' user (UserID 130) as the default — Aryza issued this user
// specifically for the bot so transactions posted by Billington are
// distinguishable from human MAKE-user activity in their audit trail.
const ANCHOR_USER_ID   = process.env.ANCHOR_USER_ID   || "130";
const ANCHOR_USER_NAME = process.env.ANCHOR_USER_NAME || "Billington";
const ANCHOR_PASSWORD  = process.env.ANCHOR_PASSWORD  || "";
if (!ANCHOR_PASSWORD) console.warn("[bill-ling] ANCHOR_PASSWORD is not set — Anchor SOAP write operations will fail auth until it is provided as an env var.");
const ANCHOR_CREDENTIALS_XML = `            <anc:Credentials>
               <anc:Password>${ANCHOR_PASSWORD}</anc:Password>
               <anc:UserID>${ANCHOR_USER_ID}</anc:UserID>
               <anc:UserName>${ANCHOR_USER_NAME}</anc:UserName>
            </anc:Credentials>`;
// Transaction types Billington is permitted to post via the deterministic
// write paths. Anything else throws.
//   61  = Gesture of goodwill (GOGW)                — add_transaction / add_gogw_and_refund
//   149 = Refund bank transfer                       — add_refund / add_gogw_and_refund /
//                                                      close_account_and_refund (step 1)
//   26  = Write-off                                  — close_account_and_refund (step 2, fraud / write-off)
//   30  = Asset returned                             — close_account_and_refund (step 2, default)
//   46  = Asset lost in transit                      — close_account_and_refund (step 2, lost in transit)
//   33  = Rebate future charges                      — close_account_and_refund (step 3)
const ANCHOR_ALLOWED_TRANSACTION_TYPE = 61; // legacy alias used elsewhere
// Hargo, 27/05/2026: added TypeId 50 (Late payment fee reversal) to the
// allow-list so Billington can action late-fee waivers from the responses
// sheet workflow.
const ANCHOR_ALLOWED_TRANSACTION_TYPES = new Set([26, 30, 33, 46, 50, 61, 149]);

// Composite close-account-and-refund flow constants.
const CLOSURE_TYPE_MAP = {
  asset_return:     { typeId: 30, label: "Asset returned" },
  lost_in_transit:  { typeId: 46, label: "Asset lost in transit" },
  write_off:        { typeId: 26, label: "Write-off" },
};
const CLOSE_ACCOUNT_AUTHORISED_USERS = new Set([HARGO_USER_ID]);
// Active payment-in transaction types per Notion Anchor Transaction Types page.
// Reversal map: typeId → set of reversal typeIds.
const COLLECTION_TYPE_IDS = new Set([12, 23, 53, 55]);
const COLLECTION_REVERSAL_TYPE_IDS = new Set([24, 54, 56, 149, 150, 151, 152, 153, 154, 155, 156]);
// TypeId 35 (Refund bank transfer reversal) un-does a TypeId 149. When
// computing net paid-to-date, a 35 must ADD BACK against the 149 that
// `COLLECTION_REVERSAL_TYPE_IDS` already subtracted — otherwise a manually
// reversed bad refund still shows as "customer refunded" and step 1 skips.
const REVERSAL_OF_REVERSAL_TYPE_IDS = new Set([35]);
// TypeIds whose presence on an agreement BLOCKS a GOGW — must escalate to Charlotte/Hargo instead
const GOGW_BLOCKING_TYPE_IDS = new Set([
  30,  // Asset returned
  28,  // Non-return fee (Card)
  63,  // Non-return fee due
  64,  // Non-return fee applied
  34,  // Asset purchased
  26,  // Write-off
  70,  // Debt sale write-off
  46,  // Asset lost in transit
]);

async function getAgreementFromAnchor(agreementId) {
  const soapBody = `<?xml version="1.0" encoding="UTF-8"?>
<soapenv:Envelope xmlns:soapenv="http://schemas.xmlsoap.org/soap/envelope/" xmlns:anc="urn:anchor.co.uk/2017/05/AnchorCollections">
   <soapenv:Header/>
   <soapenv:Body>
      <anc:GetAgreement>
         <anc:request>
${ANCHOR_CREDENTIALS_XML}
            <anc:AgreementNumber>${agreementId}</anc:AgreementNumber>
         </anc:request>
      </anc:GetAgreement>
   </soapenv:Body>
</soapenv:Envelope>`;

  const res = await fetch(ANCHOR_SOAP_URL, {
    method: "POST",
    headers: {
      "Content-Type": "text/xml;charset=UTF-8",
      "SOAPAction": ANCHOR_SOAP_ACTION,
    },
    body: soapBody,
  });

  if (!res.ok) {
    const errText = await res.text().catch(() => "");
    throw new Error(`Anchor API ${res.status}: ${errText.slice(0, 200)}`);
  }

  return await res.text(); // raw SOAP XML
}

/**
 * Post a transaction to Anchor via AddTransaction SOAP API.
 * SECURITY:
 *   - caller must verify the operator is in the appropriate authorised set
 *     (GOGW_AUTHORISED_USERS for typeId 61, REFUND_AUTHORISED_USERS for typeId 149)
 *     before calling this.
 *   - typeId must be in ANCHOR_ALLOWED_TRANSACTION_TYPES (currently {61, 149}).
 * @param {string} agreementId  e.g. "A00293914"
 * @param {string} transactionDate  YYYY-MM-DD
 * @param {number} amount  numeric, e.g. 150.00
 * @param {string} [notes]  optional notes / execution reference
 * @param {number} [typeId]  Anchor TypeId. Default 61 (GOGW). 149 = refund bank transfer.
 * @returns {string} raw SOAP XML response
 */
async function addTransactionToAnchor(agreementId, transactionDate, amount, notes = "", typeId = ANCHOR_ALLOWED_TRANSACTION_TYPE, auditContext = null) {
  if (!ANCHOR_ALLOWED_TRANSACTION_TYPES.has(typeId)) {
    throw new Error(`addTransactionToAnchor refused: TypeId ${typeId} is not in the allow-list (${[...ANCHOR_ALLOWED_TRANSACTION_TYPES].join(", ")}).`);
  }
  const soapBody = `<?xml version="1.0" encoding="UTF-8"?>
<soapenv:Envelope xmlns:soapenv="http://schemas.xmlsoap.org/soap/envelope/" xmlns:anc="urn:anchor.co.uk/2017/05/AnchorCollections">
   <soapenv:Header/>
   <soapenv:Body>
      <anc:AddTransaction>
         <anc:request>
${ANCHOR_CREDENTIALS_XML}
            <anc:AgreementNumber>${agreementId}</anc:AgreementNumber>
            <anc:TransactionDate>${transactionDate}</anc:TransactionDate>
            <anc:TransactionType>${typeId}</anc:TransactionType>
            <anc:Amount>${amount.toFixed(2)}</anc:Amount>
            <anc:Notes>${notes}</anc:Notes>
         </anc:request>
      </anc:AddTransaction>
   </soapenv:Body>
</soapenv:Envelope>`;

  try {
    const res = await fetch(ANCHOR_SOAP_URL, {
      method: "POST",
      headers: {
        "Content-Type": "text/xml;charset=UTF-8",
        "SOAPAction": ANCHOR_SOAP_ADD_TXN_ACTION,
      },
      body: soapBody,
    });

    const status = res.status;
    const responseXml = await res.text().catch(() => "");
    // Confirm the status code + result of EVERY AddTransaction (Hargo, 07/07/2026).
    // Log the HTTP status + body snippet on every call so a flaky Anchor API is
    // diagnosable; the failure branches below throw a STATUS-TAGGED error which
    // the caller surfaces. A clean 200-success stays quiet (no Slack noise).
    console.log(`[anchor-txn] AddTransaction ${agreementId} TypeId ${typeId} £${amount.toFixed(2)} (${transactionDate}) -> HTTP ${status}${res.ok ? "" : " NOT-OK"} | ${(responseXml || "").slice(0, 400).replace(/\s+/g, " ")}`);

    // Helper: throw a failure carrying structured fields (HTTP status code,
    // Anchor Status, reason) so callers can ALWAYS show them (Hargo, 07/07/2026).
    const anchorFail = (httpStatus, anchorStatus, reason, message) => {
      const e = new Error(message);
      e.anchorHttpStatus = httpStatus;
      e.anchorStatus = anchorStatus;
      e.anchorReason = (reason || "").toString().slice(0, 300);
      throw e;
    };

    if (!res.ok) {
      anchorFail(status, `HTTP ${status}`, (responseXml || "").slice(0, 200) || "(empty body)",
        `Anchor AddTransaction HTTP ${status}: ${(responseXml || "").slice(0, 200) || "(empty body)"}`);
    }

    // 200 but a SOAP fault envelope.
    const faultMatch = responseXml.match(/<(?:faultstring|faultcode)[^>]*>([^<]+)<\//i);
    if (faultMatch || /<(?:soap|soapenv|s):fault>/i.test(responseXml)) {
      const f = faultMatch ? faultMatch[1].trim() : "unknown fault";
      anchorFail(status, "SOAP fault", f, `Anchor AddTransaction failed (HTTP ${status}, SOAP fault): ${f}`);
    }

    // 200 but the AddTransactionResult reports a failure. Anchor's real schema
    // (Hargo sample, 07/07/2026): <Status>Failure</Status>, <Result>false</Result>,
    // with the reason under <Messages><a:string>…</a:string>. A 200 whose Status
    // isn't "Success" (or Result=false) has NOT posted — never treat as success.
    const statusM = responseXml.match(/<Status>\s*([^<]+?)\s*<\/Status>/i);
    const resultM = responseXml.match(/<Result>\s*(true|false)\s*<\/Result>/i);
    const txnStatus = statusM ? statusM[1].trim() : null;
    const txnResult = resultM ? resultM[1].toLowerCase() : null;
    if ((txnStatus && !/^success$/i.test(txnStatus)) || txnResult === "false") {
      const anchorMsgs = [...responseXml.matchAll(/<a:string>\s*([^<]+?)\s*<\/a:string>/gi)]
        .map(m => m[1].replace(/\s+/g, " ").trim()).filter(Boolean);
      const detail = anchorMsgs.length ? anchorMsgs.join(" | ") : (txnStatus || "failure");
      anchorFail(status, txnStatus || "Failure", detail,
        `Anchor AddTransaction returned HTTP ${status} but Status=${txnStatus || "?"} / Result=${txnResult ?? "?"}: ${detail.slice(0, 220)}`);
    }
    if (!responseXml.trim()) {
      anchorFail(status, "Failure", "empty response body",
        `Anchor AddTransaction returned HTTP ${status} with an EMPTY body — cannot confirm the transaction posted.`);
    }

    // ── Audit log (success) ── only when caller passes auditContext
    if (auditContext) {
      const actionType = auditContext.actionType || `anchor_typeid_${typeId}_posted`;
      await logBillingtonAction({
        actionCategory: "anchor_transaction",
        actionType,
        agreementId,
        anchorTypeId: typeId,
        amountGbp: typeof amount === "number" ? amount : NaN,
        reference: notes || "",
        status: "success",
        description: auditContext.description || `Anchor TypeId ${typeId} posted: £${amount.toFixed(2)} on ${agreementId} (${transactionDate})`,
        requestedBy: auditContext.requestedBy,
        requestedByUserId: auditContext.requestedByUserId,
        triggeredBy: auditContext.triggeredBy,
        triggerSource: auditContext.triggerSource,
        sourceLink: auditContext.sourceLink,
        idempotencyKey: auditContext.idempotencyKey || `anchor_txn:${agreementId}:${typeId}:${notes}:${transactionDate}`,
      });
    }
    return responseXml;
  } catch (err) {
    // ── Audit log (error) ── still log failures so investigations are traceable
    if (auditContext) {
      const actionType = auditContext.actionType || `anchor_typeid_${typeId}_posted`;
      await logBillingtonAction({
        actionCategory: "anchor_transaction",
        actionType,
        agreementId,
        anchorTypeId: typeId,
        amountGbp: typeof amount === "number" ? amount : NaN,
        reference: notes || "",
        status: "error",
        description: auditContext.description || `FAILED Anchor TypeId ${typeId}: £${amount.toFixed(2)} on ${agreementId} (${transactionDate})`,
        requestedBy: auditContext.requestedBy,
        requestedByUserId: auditContext.requestedByUserId,
        triggeredBy: auditContext.triggeredBy,
        triggerSource: auditContext.triggerSource,
        sourceLink: auditContext.sourceLink,
        errorMessage: err.message,
        idempotencyKey: auditContext.idempotencyKey,
      });
    }
    throw err;
  }
}

/**
 * Change a single payment's due date on an agreement via the Anchor
 * ChangePayProDueDate SOAP endpoint.
 *
 * Use case: a future PaymentProfile entry falls on a UK bank holiday or
 * weekend. We move that one payment to the next working day while leaving
 * the agreement's recurring DueDay metadata untouched (IsSinglePaymentChange).
 *
 * Parameters mirror the SOAP fields exactly so we can audit:
 *   ChangeReason          = 1   (hardcoded — single-payment date correction)
 *   IsContractualChange   = false (hardcoded — operational fix, not contract change)
 *   IsSinglePaymentChange = true  (hardcoded — only this one payment)
 *
 * SECURITY: caller must verify user is in PAYPRO_FIX_AUTHORISED_USERS before
 * calling this. Dates must be YYYY-MM-DD. newDueDay is an integer 1..31
 * representing the agreement's existing dueday (we always send the agreement's
 * own dueday, which is the same as the day-of-month of the date we're moving
 * away from).
 */
async function changePayProDueDate(agreementId, dateToChange, dateToChangeTo, newDueDay) {
  // Sanity guards
  if (!/^A\d{5,9}$/i.test(agreementId)) throw new Error(`changePayProDueDate: bad agreement id: ${agreementId}`);
  if (!/^\d{4}-\d{2}-\d{2}$/.test(dateToChange)) throw new Error(`changePayProDueDate: bad dateToChange (need YYYY-MM-DD): ${dateToChange}`);
  if (!/^\d{4}-\d{2}-\d{2}$/.test(dateToChangeTo)) throw new Error(`changePayProDueDate: bad dateToChangeTo (need YYYY-MM-DD): ${dateToChangeTo}`);
  if (!Number.isInteger(newDueDay) || newDueDay < 1 || newDueDay > 31) {
    throw new Error(`changePayProDueDate: bad newDueDay (need 1..31 int): ${newDueDay}`);
  }
  const soapBody = `<?xml version="1.0" encoding="UTF-8"?>
<soapenv:Envelope xmlns:soapenv="http://schemas.xmlsoap.org/soap/envelope/" xmlns:anc="urn:anchor.co.uk/2017/05/AnchorCollections">
   <soapenv:Header/>
   <soapenv:Body>
      <anc:ChangePayProDueDate>
         <anc:request>
${ANCHOR_CREDENTIALS_XML}
            <anc:AgreementNumber>${agreementId}</anc:AgreementNumber>
            <anc:ChangeReason>1</anc:ChangeReason>
            <anc:DateToChange>${dateToChange}</anc:DateToChange>
            <anc:DateToChangeTo>${dateToChangeTo}</anc:DateToChangeTo>
            <anc:IsContractualChange>false</anc:IsContractualChange>
            <anc:IsSinglePaymentChange>true</anc:IsSinglePaymentChange>
            <anc:NewDueDay>${newDueDay}</anc:NewDueDay>
         </anc:request>
      </anc:ChangePayProDueDate>
   </soapenv:Body>
</soapenv:Envelope>`;

  const res = await fetch(ANCHOR_SOAP_URL, {
    method: "POST",
    headers: {
      "Content-Type": "text/xml;charset=UTF-8",
      "SOAPAction": ANCHOR_SOAP_CHANGE_DUE_DATE_ACTION,
    },
    body: soapBody,
  });
  const responseXml = await res.text().catch(() => "");
  if (!res.ok) throw new Error(`Anchor ChangePayProDueDate HTTP ${res.status}: ${responseXml.slice(0, 200)}`);
  const faultMatch = responseXml.match(/<(?:faultstring|faultcode)[^>]*>([^<]+)<\//i);
  if (faultMatch || responseXml.toLowerCase().includes("<soap:fault>") || responseXml.toLowerCase().includes("<soapenv:fault>")) {
    throw new Error(`Anchor SOAP fault: ${faultMatch ? faultMatch[1].trim() : "unknown error"}`);
  }
  return responseXml;
}

/**
 * POST SetTeamStatus to Anchor. Moves an agreement into the given TeamStatusId.
 * Used by the NODS missing-notice remediation flow (NODS_TARGET_TEAM_STATUS_ID = 532).
 *
 * SECURITY: caller must verify user is in LATE_FEE_APPLY_AUTHORISED_USERS before
 * calling. This is a destructive write — it changes the customer's status, which
 * triggers downstream email automation.
 *
 * Returns the raw response XML on success; throws on HTTP or SOAP fault.
 */
async function setAnchorTeamStatus(agreementId, statusId) {
  if (!/^A\d{5,9}$/i.test(agreementId)) throw new Error(`setAnchorTeamStatus: bad agreement id: ${agreementId}`);
  if (!Number.isInteger(statusId) || statusId < 1) throw new Error(`setAnchorTeamStatus: bad statusId: ${statusId}`);
  const soapBody = `<?xml version="1.0" encoding="UTF-8"?>
<soapenv:Envelope xmlns:soapenv="http://schemas.xmlsoap.org/soap/envelope/" xmlns:anc="urn:anchor.co.uk/2017/05/AnchorCollections">
   <soapenv:Header/>
   <soapenv:Body>
      <anc:SetTeamStatus>
         <anc:request>
${ANCHOR_CREDENTIALS_XML}
            <anc:AgreementNumber>${agreementId}</anc:AgreementNumber>
            <anc:StatusId>${statusId}</anc:StatusId>
         </anc:request>
      </anc:SetTeamStatus>
   </soapenv:Body>
</soapenv:Envelope>`;
  const res = await fetch(ANCHOR_SOAP_URL, {
    method: "POST",
    headers: {
      "Content-Type": "text/xml;charset=UTF-8",
      "SOAPAction": ANCHOR_SOAP_SET_TEAM_STATUS_ACTION,
    },
    body: soapBody,
  });
  const responseXml = await res.text().catch(() => "");
  if (!res.ok) throw new Error(`Anchor SetTeamStatus HTTP ${res.status}: ${responseXml.slice(0, 200)}`);
  const faultMatch = responseXml.match(/<(?:faultstring|faultcode)[^>]*>([^<]+)<\//i);
  if (faultMatch || responseXml.toLowerCase().includes("<soap:fault>") || responseXml.toLowerCase().includes("<soapenv:fault>")) {
    throw new Error(`Anchor SOAP fault: ${faultMatch ? faultMatch[1].trim() : "unknown error"}`);
  }
  return responseXml;
}

/**
 * Parse <CollectionsHistory> entries from the Anchor GetAgreement response.
 * Each <History> block has:
 *   <Type>...</Type>
 *   <Notes>...</Notes>           — for team status movements this reads
 *                                   "{fromStatusId}. {fromLabel} -&gt; {toStatusId}. {toLabel}"
 *   <DateCreated>YYYY-MM-DDTHH:MM:SS</DateCreated>
 *   <User>...</User>
 * Returns an array of { type, notes, dateCreated, user, fromStatusId, toStatusId }.
 * `dateCreated` is kept as a string for easy date-only comparison.
 */
function parseCollectionsHistory(xml) {
  const chMatch = xml.match(/<(?:a:)?CollectionsHistory>([\s\S]*?)<\/(?:a:)?CollectionsHistory>/);
  if (!chMatch) return [];
  const inner = chMatch[1];
  const blocks = inner.match(/<(?:a:)?History>[\s\S]*?<\/(?:a:)?History>/g) || [];
  const entries = [];
  for (const block of blocks) {
    const type = (block.match(/<(?:a:)?Type>([^<]*)<\/(?:a:)?Type>/) || [])[1] || "";
    // Notes is HTML-entity-encoded in the SOAP — &gt; for arrow.
    const notesRaw = (block.match(/<(?:a:)?Notes>([^<]*)<\/(?:a:)?Notes>/) || [])[1] || "";
    const notes = notesRaw.replace(/&gt;/g, ">").replace(/&lt;/g, "<").replace(/&amp;/g, "&");
    const dateCreated = (block.match(/<(?:a:)?DateCreated>([^<]*)<\/(?:a:)?DateCreated>/) || [])[1] || "";
    const user = (block.match(/<(?:a:)?User>([^<]*)<\/(?:a:)?User>/) || [])[1] || "";
    // Parse status movement pattern: "351. New agreements -> 103. Due in 30 - 6 days"
    const moveMatch = notes.match(/^\s*(\d+)\.\s*[^>]*?->\s*(\d+)\./);
    const fromStatusId = moveMatch ? parseInt(moveMatch[1], 10) : null;
    const toStatusId   = moveMatch ? parseInt(moveMatch[2], 10) : null;
    entries.push({ type, notes, dateCreated, user, fromStatusId, toStatusId });
  }
  return entries;
}

/**
 * Fetch + parse the agreement's CollectionsHistory.
 */
async function getAgreementCollectionsHistory(agreementId) {
  if (!/^A\d{5,9}$/i.test(agreementId)) {
    throw new Error(`getAgreementCollectionsHistory: bad agreement id: ${agreementId}`);
  }
  const xml = await getAgreementFromAnchor(agreementId);
  return parseCollectionsHistory(xml);
}

/**
 * For a given agreement, check whether a NODS-triggering movement has occurred
 * since the most recent LPF transaction.
 *
 * Definition (Hargo, 19/05/2026):
 *   A "NODS-triggering movement" is any History entry where toStatusId ===
 *   NODS_TARGET_TEAM_STATUS_ID (532), with DateCreated on or after the date
 *   of the most recent TypeId 49 (LPF) transaction. Current team status is
 *   irrelevant — what matters is whether a *movement INTO* 532 has happened
 *   in that window.
 *
 * Returns:
 *   {
 *     agreementId,
 *     lastLpfDate: 'YYYY-MM-DD' | null,
 *     currentTeamStatusId: number | null,
 *     movementsToTarget: [{ dateCreated, fromStatusId, toStatusId, user }, ...],
 *     hasMovementSinceLpf: boolean,
 *     needsRemediation: boolean
 *   }
 */
async function checkNodsMovementForAgreement(agreementId) {
  const xml = await getAgreementFromAnchor(agreementId);
  const txContainer = (xml.match(/<(?:a:)?Transactions>([\s\S]*?)<\/(?:a:)?Transactions>/) || [])[1] || "";
  // Walk transactions once — track most recent LPF (TypeId 49) AND collect
  // dates of LPF reversals (TypeId 50). If a 50 sits on the SAME day as the
  // most recent 49, the fee was applied-then-reversed; no NODS should fire
  // and no remediation is needed (Hargo, 19/05/2026).
  let lastLpfDate = null;
  const lpfReversalDates = new Set();
  for (const block of (txContainer.match(/<(?:a:)?Transaction>[\s\S]*?<\/(?:a:)?Transaction>/g) || [])) {
    const tid = parseInt(((block.match(/<(?:a:)?TypeId>(\d+)<\/(?:a:)?TypeId>/) || [])[1]) || "0", 10);
    const d = ((block.match(/<(?:a:)?TransactionDate>([^<]+)<\/(?:a:)?TransactionDate>/) || [])[1] || "").slice(0, 10);
    if (tid === LATE_PAYMENT_FEE_TYPE_ID && d && (!lastLpfDate || d > lastLpfDate)) lastLpfDate = d;
    if (tid === 50 && d) lpfReversalDates.add(d);
  }
  const lpfReversedSameDay = !!lastLpfDate && lpfReversalDates.has(lastLpfDate);
  const currentTeamStatusId = (() => {
    const m = xml.match(/<(?:a:)?TeamStatusId>(\d+)<\/(?:a:)?TeamStatusId>/);
    return m ? parseInt(m[1], 10) : null;
  })();
  const history = parseCollectionsHistory(xml);
  const movementsToTarget = history.filter(h => h.toStatusId === NODS_TARGET_TEAM_STATUS_ID);
  const hasMovementSinceLpf = lastLpfDate
    ? movementsToTarget.some(h => h.dateCreated.slice(0, 10) >= lastLpfDate)
    : movementsToTarget.length > 0;
  return {
    agreementId,
    lastLpfDate,
    lpfReversedSameDay,
    currentTeamStatusId,
    movementsToTarget,
    hasMovementSinceLpf,
    needsRemediation: !!lastLpfDate && !hasMovementSinceLpf && !lpfReversedSameDay,
  };
}

// Source of truth for "did the NODS actually send": the audit copy that lands
// in billingoperations@ (label Audits/NODS, from payment.notification@raylo.com,
// subject "Notice of default sums DD/MM/YYYY Ref: <agreementId>"). Hargo,
// 02/07/2026 — check the EMAIL, not the Anchor team-status movement. A movement
// into 532 can still yield a FAILED send (e.g. A00294834: moved into 532 by
// MAKE but the email failed with status 2), which the status proxy wrongly
// treated as "covered". The email is the only signal that proves delivery.
const NODS_AUDIT_LABEL = "Audits/NODS";
const NODS_AUDIT_FROM  = "payment.notification@raylo.com";

/**
 * Check whether the NODS "Notice of default sums" audit email exists for an
 * agreement in the billingoperations@ inbox. Returns:
 *   { found: boolean, date?: string, subject?: string, error?: string }
 * On a Gmail error `found` is false AND `error` is set — callers MUST treat an
 * error as inconclusive and NOT refire (avoids a duplicate NODS send).
 */
async function checkNodsAuditEmailSent(agreementId) {
  const client = gmailBillingOpsClient;
  if (!client) return { found: false, error: "gmail_not_connected" };
  const q = `label:${NODS_AUDIT_LABEL} from:${NODS_AUDIT_FROM} subject:"Notice of default sums" subject:${agreementId} newer_than:30d`;
  try {
    const res = await client.users.messages.list({ userId: "me", q, maxResults: 5 });
    const msgs = res.data.messages || [];
    if (!msgs.length) return { found: false };
    let subject = null, date = null;
    try {
      const det = await client.users.messages.get({
        userId: "me", id: msgs[0].id, format: "metadata", metadataHeaders: ["Subject", "Date"],
      });
      (det.data.payload.headers || []).forEach(h => {
        if (h.name === "Subject") subject = h.value;
        if (h.name === "Date") date = h.value;
      });
    } catch (_) { /* metadata fetch failed — still counts as found */ }
    return { found: true, subject, date, messageId: msgs[0].id };
  } catch (err) {
    return { found: false, error: err.message };
  }
}

/**
 * Remediate a missing-NODS agreement. Source of truth is the audit EMAIL
 * (checkNodsAuditEmailSent), NOT the Anchor team-status movement (Hargo,
 * 02/07/2026). If the NODS audit email is present → covered, no-op. If it is
 * absent → confirm a NODS is actually warranted (an LPF that was not reversed
 * the same day) via Anchor, then POST SetTeamStatus(532) to refire the email.
 *
 * Safety: if the inbox check itself errors, this is treated as inconclusive —
 * we do NOT refire (no `posted`), to avoid double-sending a NODS.
 *
 * Returns {
 *   agreementId, auditEmailFound, auditEmailDate, auditCheckError,
 *   lastLpfDate, lpfReversedSameDay, currentTeamStatusId,
 *   needsRemediation, posted, dryRun, error
 * }. Caller is responsible for authorisation gating.
 */
async function remediateMissingNodsForAgreement(agreementId, { dryRun = false } = {}) {
  const out = {
    agreementId,
    auditEmailFound: false,
    auditEmailDate: null,
    auditCheckError: null,
    lastLpfDate: null,
    lpfReversedSameDay: false,
    currentTeamStatusId: null,
    needsRemediation: false,
    posted: false,
    dryRun,
    error: null,
  };

  // 1) Email source of truth.
  const audit = await checkNodsAuditEmailSent(agreementId);
  if (audit.error) {
    // Inbox unreachable → inconclusive. Do NOT refire.
    out.auditCheckError = audit.error;
    return out;
  }
  if (audit.found) {
    out.auditEmailFound = true;
    out.auditEmailDate = audit.date || null;
    return out; // NODS genuinely sent — nothing to do.
  }

  // 2) No audit email — confirm a NODS is actually due (LPF present, not
  //    reversed the same day) before refiring.
  try {
    const check = await checkNodsMovementForAgreement(agreementId);
    out.lastLpfDate = check.lastLpfDate;
    out.lpfReversedSameDay = check.lpfReversedSameDay;
    out.currentTeamStatusId = check.currentTeamStatusId;
    if (!check.lastLpfDate) return out;       // no LPF → can't determine window
    if (check.lpfReversedSameDay) return out;  // fee reversed same day → no NODS needed
    out.needsRemediation = true;
    if (dryRun) return out;
    await setAnchorTeamStatus(agreementId, NODS_TARGET_TEAM_STATUS_ID);
    out.posted = true;
  } catch (err) {
    out.error = err.message;
  }
  return out;
}

/**
 * Parse an AddTransaction request from a Slack message.
 * Returns { agreementId, amount, transactionDate, notes } or null if required fields missing.
 * Strict: only extracts values explicitly present in the text — no defaults from context.
 */
function parseAddTransactionRequest(text) {
  // Agreement ID — must be explicit
  const agMatch = text.match(/\bA(\d{5,9})\b/i);
  if (!agMatch) return null;
  const agreementId = `A${agMatch[1].toUpperCase()}`;

  // Amount — £X, £X.XX, or plain number near keywords
  const amountMatch = text.match(/£\s*([\d,]+(?:\.\d{1,2})?)/i)
    || text.match(/\bamount\b[^0-9£]*£?\s*([\d,]+(?:\.\d{1,2})?)/i)
    || text.match(/([\d,]+\.\d{2})\b/); // bare decimal like 150.00
  if (!amountMatch) return null;
  const amount = parseFloat(amountMatch[1].replace(/,/g, ""));
  if (isNaN(amount) || amount <= 0) return null;

  // Date — DD/MM/YYYY, YYYY-MM-DD, or "today" / "tomorrow" — defaults to today
  const todayStr = new Date().toLocaleDateString("en-CA", { timeZone: "Europe/London" }); // YYYY-MM-DD
  let transactionDate = todayStr;
  const dmyMatch = text.match(/\b(\d{1,2})\/(\d{1,2})\/(\d{4})\b/);
  const isoMatch  = text.match(/\b(\d{4})-(\d{2})-(\d{2})\b/);
  if (dmyMatch) {
    transactionDate = `${dmyMatch[3]}-${dmyMatch[2].padStart(2,"0")}-${dmyMatch[1].padStart(2,"0")}`;
  } else if (isoMatch) {
    transactionDate = isoMatch[0];
  } else if (/\btomorrow\b/i.test(text)) {
    transactionDate = nextWorkingDay(todayStr);
  }
  // else keep today

  // Notes — anything after "notes:", "ref:", "reference:", "note:" (optional)
  const notesMatch = text.match(/(?:notes?|ref(?:erence)?)\s*[:=]\s*(.+)/i);
  const notes = notesMatch ? notesMatch[1].trim().slice(0, 200) : "";

  return { agreementId, amount, transactionDate, notes };
}

/**
 * Look up live total_arrears for a single agreement from
 * `raylo-production.landing_billington.agreement_info`.
 *
 * Sign convention (per the dbt source):
 *   positive total_arrears = customer owes Raylo money
 *   negative total_arrears = customer is in credit (refund candidate)
 *   zero                   = cleared
 *
 * Returns the numeric value, or null if the agreement isn't found.
 */
async function getAgreementArrears(agreementId) {
  // Strict format guard — agreement_id format is A + 5-9 digits. Refuse anything else.
  if (!/^A\d{5,9}$/i.test(agreementId)) {
    throw new Error(`getAgreementArrears: bad agreement id format: ${agreementId}`);
  }
  const sql = `SELECT total_arrears FROM \`raylo-production.landing_billington.agreement_info\` WHERE agreement_id = '${agreementId.toUpperCase()}' LIMIT 1`;
  const rows = await runBigQueryRaw(sql);
  if (!rows.length) return null;
  const v = formatBQValue(rows[0].total_arrears);
  return v === null || v === undefined ? null : Number(v);
}

/**
 * Read live total_arrears from Anchor's getAgreement SOAP response.
 *
 * Sign convention (Anchor):
 *   total_arrears > 0  → customer owes money (no refund due)
 *   total_arrears = 0  → cleared (no refund due)
 *   total_arrears < 0  → customer in CREDIT (refund candidate)
 *
 * For refund validation: a refund of £X is valid only when
 * total_arrears == -X (within ±£0.01). The refund amount is always
 * positive in the SOAP request; Anchor automatically stores the TypeId 149
 * transaction as negative on the ledger. After posting, total_arrears
 * shifts back toward zero by exactly £X.
 *
 * Replaces the stale BigQuery `agreement_info.total_arrears` check —
 * Anchor reflects a freshly-posted GOGW immediately.
 *
 * Returns the numeric value, or null if the field isn't present on the
 * response.
 */
async function getAgreementLiveTotalArrears(agreementId) {
  if (!/^A\d{5,9}$/i.test(agreementId)) {
    throw new Error(`getAgreementLiveTotalArrears: bad agreement id: ${agreementId}`);
  }
  const xml = await getAgreementFromAnchor(agreementId);
  const m = xml.match(/<(?:a:)?TotalArrears>([^<]+)<\/(?:a:)?TotalArrears>/);
  if (!m) return null;
  const n = parseFloat(m[1]);
  return Number.isFinite(n) ? Number(n.toFixed(2)) : null;
}

/**
 * Read all <Transaction> blocks from an Anchor getAgreement response and
 * return them as structured objects.
 *
 * Returns: [{ typeId, amount, transactionDate, raw }]
 * - typeId        integer
 * - amount        signed number as it appears on the ledger
 * - transactionDate  ISO date string (YYYY-MM-DD)
 * - raw           the original block (for debugging)
 *
 * Used by the close-account-and-refund orchestrator to scope payments by
 * date / last-N and to detect already-actioned steps for idempotency.
 */
async function getAgreementTransactionsFromAnchor(agreementId) {
  if (!/^A\d{5,9}$/i.test(agreementId)) {
    throw new Error(`getAgreementTransactionsFromAnchor: bad agreement id: ${agreementId}`);
  }
  const xml = await getAgreementFromAnchor(agreementId);
  // Restrict to the top-level <Transactions> container — LockedTransactions /
  // CollectionsHistory may also contain <Transaction> blocks that aren't part
  // of the active ledger.
  const txContainerMatch = xml.match(/<(?:a:)?Transactions>([\s\S]*?)<\/(?:a:)?Transactions>/);
  const txContainer = txContainerMatch ? txContainerMatch[1] : xml;
  const blocks = txContainer.match(/<(?:a:)?Transaction>[\s\S]*?<\/(?:a:)?Transaction>/g) || [];
  const txns = [];
  for (const block of blocks) {
    const typeMatch = block.match(/<(?:a:)?TypeId>(\d+)<\/(?:a:)?TypeId>/);
    // Anchor's <Transaction> blocks expose the total via <Gross>. There is
    // no <Amount> tag here — earlier versions of this parser used <Amount>
    // and silently found nothing, treating every agreement as zero
    // collections. Falls back to <Amount> just in case Anchor ever exposes
    // it as an alias.
    const grossMatch = block.match(/<(?:a:)?Gross>(-?[\d.]+)<\/(?:a:)?Gross>/)
                    || block.match(/<(?:a:)?Amount>(-?[\d.]+)<\/(?:a:)?Amount>/);
    const dateMatch = block.match(/<(?:a:)?TransactionDate>([^<]+)<\/(?:a:)?TransactionDate>/);
    // Principal portion of the transaction — used by step 2 of the
    // close-account flow to compute outstanding principal as
    // sum(PaymentProfile.Principal) − sum(Transaction.Principal where TypeId ≠ 99).
    const principalMatch = block.match(/<(?:a:)?Principal>(-?[\d.]+)<\/(?:a:)?Principal>/);
    if (!typeMatch || !grossMatch) continue;
    txns.push({
      typeId: parseInt(typeMatch[1], 10),
      amount: parseFloat(grossMatch[1]),
      principal: principalMatch ? parseFloat(principalMatch[1]) : 0,
      transactionDate: dateMatch ? dateMatch[1].slice(0, 10) : null,
      raw: block,
    });
  }
  return txns;
}

/**
 * Sum the <Principal> field across every <PaymentProfile> entry in the
 * agreement SOAP. The PaymentProfile is the schedule of expected payments
 * (Fee/Payment/VAT entries) over the agreement term — its principal portions
 * sum to the agreement's total scheduled principal.
 *
 * Used by step 2 of close-account-and-refund to compute outstanding principal
 * via: sum(PaymentProfile.Principal) − sum(Transaction.Principal excl TypeId 99).
 * The top-level <Principal> SOAP field is NOT reliable (Hargo, 19/05/2026 —
 * it doesn't always reflect post-refund state correctly), so we recompute
 * from the schedule.
 */
async function getAgreementLivePaymentProfilePrincipalSum(agreementId) {
  if (!/^A\d{5,9}$/i.test(agreementId)) {
    throw new Error(`getAgreementLivePaymentProfilePrincipalSum: bad agreement id: ${agreementId}`);
  }
  const xml = await getAgreementFromAnchor(agreementId);
  const profiles = xml.match(/<(?:a:)?PaymentProfile>[\s\S]*?<\/(?:a:)?PaymentProfile>/g) || [];
  let total = 0;
  for (const p of profiles) {
    const m = p.match(/<(?:a:)?Principal>(-?[\d.]+)<\/(?:a:)?Principal>/);
    if (m) total += parseFloat(m[1]);
  }
  return Number(total.toFixed(2));
}

/**
 * Compute live outstanding principal for an agreement using the canonical
 * formula (Hargo, 19/05/2026):
 *
 *   outstanding_principal = sum(PaymentProfile.Principal)
 *                         − sum(Transaction.Principal where TypeId ≠ 99)
 *
 * TypeId 99 (Instalment Due) is the accounting offset that pairs with each
 * scheduled payment — its principal already cancels the PaymentProfile entry,
 * so including it would double-count.
 *
 * Returns { ppSum, txSumExcl99, outstanding }.
 */
async function getAgreementLiveOutstandingPrincipal(agreementId) {
  const [ppSum, txns] = await Promise.all([
    getAgreementLivePaymentProfilePrincipalSum(agreementId),
    getAgreementTransactionsFromAnchor(agreementId),
  ]);
  const txSumExcl99 = txns
    .filter(t => t.typeId !== 99)
    .reduce((sum, t) => sum + (Number.isFinite(t.principal) ? t.principal : 0), 0);
  const outstanding = Number((ppSum - txSumExcl99).toFixed(2));
  return { ppSum: Number(ppSum.toFixed(2)), txSumExcl99: Number(txSumExcl99.toFixed(2)), outstanding };
}

/**
 * Read live <Balance> from Anchor (the outstanding amount owed by the
 * customer on the agreement). Distinct from total_arrears — Balance is the
 * remaining principal + charges that haven't been paid yet, regardless of
 * arrears state. Used by close-account-and-refund.
 *
 * Returns the numeric value or null if the field isn't present.
 */
async function getAgreementLiveBalance(agreementId) {
  if (!/^A\d{5,9}$/i.test(agreementId)) {
    throw new Error(`getAgreementLiveBalance: bad agreement id: ${agreementId}`);
  }
  const xml = await getAgreementFromAnchor(agreementId);
  const m = xml.match(/<(?:a:)?Balance>([^<]+)<\/(?:a:)?Balance>/);
  if (!m) return null;
  const n = parseFloat(m[1]);
  return Number.isFinite(n) ? Number(n.toFixed(2)) : null;
}

/**
 * Read live <ChargesOutstanding> from Anchor.
 * Returns the numeric value or null if not present.
 */
async function getAgreementLiveChargesOutstanding(agreementId) {
  if (!/^A\d{5,9}$/i.test(agreementId)) {
    throw new Error(`getAgreementLiveChargesOutstanding: bad agreement id: ${agreementId}`);
  }
  const xml = await getAgreementFromAnchor(agreementId);
  const m = xml.match(/<(?:a:)?ChargesOutstanding>([^<]+)<\/(?:a:)?ChargesOutstanding>/);
  if (!m) return null;
  const n = parseFloat(m[1]);
  return Number.isFinite(n) ? Number(n.toFixed(2)) : null;
}

/**
 * Compute scoped paid-to-date from a transactions list.
 * scope = { kind: 'all' } | { kind: 'last', n: 2 } | { kind: 'since', date: 'YYYY-MM-DD' }
 *
 * Implementation:
 *   1. Filter to COLLECTION_TYPE_IDS with positive Amount.
 *   2. Apply the scope filter to the in-set collections.
 *   3. Add absolute Amount of all in-scope collections.
 *   4. For each collection in scope, find any subsequent reversal/bounce
 *      (typeId in COLLECTION_REVERSAL_TYPE_IDS, on or after the collection
 *      date) and SUBTRACT its absolute amount. We treat reversals/bounces
 *      that occurred WITHIN the scope window as part of the net "actually
 *      paid in" figure. Reversals outside the scope window are ignored.
 *
 * Returns { totalPaid, perTxn: [{ collection, reversal? }], scopedCollections }.
 */
function computeScopedPaidToDate(txns, scope) {
  const collections = txns
    .filter(t => COLLECTION_TYPE_IDS.has(t.typeId) && t.amount > 0)
    .sort((a, b) => (a.transactionDate || "").localeCompare(b.transactionDate || ""));
  let scoped;
  if (scope.kind === "all") {
    scoped = collections.slice();
  } else if (scope.kind === "last") {
    const n = Math.max(0, Math.floor(scope.n));
    scoped = collections.slice(-n);
  } else if (scope.kind === "since") {
    scoped = collections.filter(c => c.transactionDate && c.transactionDate >= scope.date);
  } else {
    scoped = [];
  }
  let totalPaid = 0;
  for (const c of scoped) totalPaid += Math.abs(c.amount);
  // Subtract reversals that fall within the scope window, then add back
  // any reversal-of-reversal (TypeId 35) entries in the same window.
  const reversals = txns.filter(t => COLLECTION_REVERSAL_TYPE_IDS.has(t.typeId));
  const reversalOfReversals = txns.filter(t => REVERSAL_OF_REVERSAL_TYPE_IDS.has(t.typeId));
  const scopedReversals = [];
  const scopedReversalOfReversals = [];
  if (scoped.length) {
    const minScopeDate = scope.kind === "since" ? scope.date : scoped[0].transactionDate;
    for (const r of reversals) {
      if (r.transactionDate && (!minScopeDate || r.transactionDate >= minScopeDate)) {
        scopedReversals.push(r);
        totalPaid -= Math.abs(r.amount);
      }
    }
    for (const r of reversalOfReversals) {
      if (r.transactionDate && (!minScopeDate || r.transactionDate >= minScopeDate)) {
        scopedReversalOfReversals.push(r);
        totalPaid += Math.abs(r.amount);
      }
    }
  }
  return { totalPaid: Number(totalPaid.toFixed(2)), scopedCollections: scoped, scopedReversals, scopedReversalOfReversals };
}

/**
 * Parse a "close account and refund [scope] on A00... [A00... ...] [closure type]" command.
 * Returns null if not a valid close-account command, otherwise
 *   { agreementIds: [...], scope: {kind:'all'|'last'|'since', n?, date?}, closureType: 'asset_return'|'lost_in_transit'|'write_off' }
 */
function parseCloseAccountRequest(text) {
  if (!text) return null;
  if (!/\b(close|closing|closure)\b/i.test(text)) return null;
  if (!/\b(account|accounts|agreement|agreements)\b/i.test(text)) return null;
  if (!/\brefund\b/i.test(text)) return null;
  // Agreement IDs (one or more)
  const idMatches = [...text.matchAll(/\bA(\d{5,9})\b/gi)].map(m => `A${m[1].toUpperCase()}`);
  const agreementIds = [...new Set(idMatches)];
  if (agreementIds.length === 0) return null;
  // Scope
  let scope = { kind: "all" };
  const lastMatch = text.match(/\blast\s+(\d+)\s+payments?\b/i);
  const sinceMatch = text.match(/\b(?:payments?\s+)?since\s+(\d{4}-\d{2}-\d{2})\b/i);
  const allMatch = /\b(all\s+payments?|refund\s+all)\b/i.test(text);
  if (lastMatch) scope = { kind: "last", n: Number(lastMatch[1]) };
  else if (sinceMatch) scope = { kind: "since", date: sinceMatch[1] };
  else if (allMatch) scope = { kind: "all" };
  // Closure type — no default. Hargo's rule (20/05/2026): the operator
  // must specify which closure-transaction type to use. If unspecified,
  // the handler refuses and asks for clarification.
  let closureType = null;
  if (/\b(asset\s+return(?:ed)?)\b/i.test(text)) closureType = "asset_return";
  else if (/\b(lost\s+in\s+transit|asset\s+lost)\b/i.test(text)) closureType = "lost_in_transit";
  else if (/\b(write[\s-]?off|fraud)\b/i.test(text)) closureType = "write_off";
  // Note: explicitly excluding debt sale write-off (TypeId 70) per Hargo's
  // direction — not in CLOSURE_TYPE_MAP.
  // Optional per-step debug mode: "step 1" / "step 2" / "step 3" runs
  // only that step in isolation. Operator can verify Anchor state between
  // each step. Null = run full chain.
  let stepFilter = null;
  const stepMatch = text.match(/\bstep\s+([123])\b/i);
  if (stepMatch) stepFilter = Number(stepMatch[1]);
  return { agreementIds, scope, closureType, stepFilter };
}

/**
 * Orchestrate the three-step close-account-and-refund flow for a single
 * agreement. Each step is idempotent: if it's already been actioned on
 * the agreement, the step is skipped and we move to the next one.
 *
 * Step 1 — Refund.
 *   Sum the in-scope collections (typeId 12/23/53/55 minus reversals
 *   24/54/56/149/150-156). Check existing TypeId 149 transactions; if
 *   the cumulative |Amount| of TypeId 149 already matches the target
 *   sum within ±£0.01, skip. Otherwise post TypeId 149 for the gap.
 *
 * Step 2 — Closure transaction (asset return / lost in transit / write off).
 *   Read live Balance and ChargesOutstanding → outstanding principal.
 *   Skip if a transaction with the chosen TypeId already exists on the
 *   agreement. Otherwise post the chosen TypeId for the outstanding
 *   principal value. If outstanding principal is £0, skip silently.
 *
 * Step 3 — Rebate future charges (TypeId 33).
 *   Read live Balance. Skip if TypeId 33 already exists. Otherwise post
 *   TypeId 33 for the live Balance.
 *
 * Between steps, poll getAgreement with backoff until the previous write
 * is reflected on the ledger (similar to the combined gogw+refund flow).
 *
 * Returns a per-step result object describing what happened.
 */
/**
 * Net payments collected per Hargo's formula (22/05/2026):
 *   sum(Gross) across TypeId 12 / 23 / 24 / 149 / 150–156.
 * Gross is signed (inflows positive, outflows negative).
 */
const NET_PAYMENT_TYPE_IDS_FOR_REFUND = new Set([12, 23, 24, 149, 150, 151, 152, 153, 154, 155, 156]);

/**
 * Check if an agreement may have had its asset returned. Hargo, 22/05/2026:
 * before adding to the close sheet under Fraud & VC Write Off, query
 * landing_billington for `collection_completed_at` and
 * `assessment_completed_at`. If either is non-null, the device may have
 * already been collected/assessed — the agreement should probably be
 * closed under Asset Return, NOT Fraud & VC Write Off. Surfaced as a note
 * in the thread reply so the operator can review before the closure
 * transaction is posted.
 *
 * Uses `final_hire_payments_returns` because `agreement_info` view
 * currently has a duplicate-column bug (assessment_completed_at_1)
 * that errors any SELECT.
 *
 * Returns { collectionCompletedAt, assessmentCompletedAt, mayHaveReturnedAsset, error? }.
 */
async function checkAssetReturnStatus(agreementId) {
  if (!/^A\d{5,9}$/i.test(agreementId)) return { mayHaveReturnedAsset: false };
  const sql =
    `SELECT collection_completed_at, assessment_completed_at ` +
    `FROM \`raylo-production.landing_billington.final_hire_payments_returns\` ` +
    `WHERE agreement_id = '${agreementId.toUpperCase()}' LIMIT 1`;
  try {
    const [rows] = await bigquery.query({ query: sql, location: "EU" });
    if (rows.length === 0) return { mayHaveReturnedAsset: false };
    const r = rows[0];
    const collectionCompletedAt = r.collection_completed_at?.value || r.collection_completed_at || null;
    const assessmentCompletedAt = r.assessment_completed_at?.value || r.assessment_completed_at || null;
    return {
      collectionCompletedAt,
      assessmentCompletedAt,
      mayHaveReturnedAsset: !!(collectionCompletedAt || assessmentCompletedAt),
    };
  } catch (err) {
    console.error(`[bill-ling] checkAssetReturnStatus(${agreementId}):`, err.message);
    return { mayHaveReturnedAsset: false, error: err.message };
  }
}

function computeStrictNetPayments(txns) {
  return Number(
    txns
      .filter(t => NET_PAYMENT_TYPE_IDS_FOR_REFUND.has(t.typeId))
      .reduce((sum, t) => sum + (Number.isFinite(t.amount) ? t.amount : 0), 0)
      .toFixed(2)
  );
}

/**
 * Modal monthly instalment for the agreement — sum PaymentProfile entries per
 * PaymentDate (Fee + Payment + VAT etc.), then return the most-common total.
 * That's the canonical "regular monthly instalment" Hargo uses to size step
 * 1 refunds. Returns 0 if PaymentProfile is empty or unreadable.
 */
function getRegularMonthlyInstalmentAmount(xml) {
  const profiles = xml.match(/<(?:a:)?PaymentProfile>[\s\S]*?<\/(?:a:)?PaymentProfile>/g) || [];
  if (profiles.length === 0) return 0;
  const totalByDate = new Map();
  for (const p of profiles) {
    const dt = (p.match(/<(?:a:)?PaymentDate>([^<]+)/) || [])[1];
    const amt = parseFloat((p.match(/<(?:a:)?PaymentAmount>([^<]+)/) || [])[1] || "0");
    if (!dt || !Number.isFinite(amt)) continue;
    const key = dt.slice(0, 10);
    totalByDate.set(key, (totalByDate.get(key) || 0) + amt);
  }
  // Count modal total
  const counts = new Map();
  for (const total of totalByDate.values()) {
    const k = total.toFixed(2);
    counts.set(k, (counts.get(k) || 0) + 1);
  }
  let modeAmt = 0, modeCount = 0;
  for (const [k, c] of counts) {
    if (c > modeCount) { modeAmt = parseFloat(k); modeCount = c; }
  }
  return Number(modeAmt.toFixed(2));
}

async function runCloseAccountAndRefund({ agreementId, scope, closureType, today, stepFilter = null, auditCtx = null }) {
  // closureType only required when step 2 is in scope (full chain or step 2 only).
  const step2InScope = stepFilter === null || stepFilter === 2;
  if (step2InScope && !CLOSURE_TYPE_MAP[closureType]) {
    throw new Error(`Step 2 requires a valid closureType; got: ${closureType}`);
  }
  const closure = closureType && CLOSURE_TYPE_MAP[closureType]
    ? CLOSURE_TYPE_MAP[closureType]
    : { typeId: null, label: "(closure type not specified — step 2 not in scope)" };
  const result = {
    agreementId,
    stepFilter,
    deferred: false,
    deferReason: null,
    step1: { status: stepFilter !== null && stepFilter !== 1 ? "not_in_scope" : "pending", typeId: 149, amount: null, note: null, error: null },
    step2: { status: stepFilter !== null && stepFilter !== 2 ? "not_in_scope" : "pending", typeId: closure.typeId, label: closure.label, amount: null, note: null, error: null },
    step3: { status: stepFilter !== null && stepFilter !== 3 ? "not_in_scope" : "pending", typeId: 33, label: "Rebate future charges", amount: null, note: null, error: null },
  };

  // ── Step 0: Same-day DD pre-flight check ───────────────────────────
  // Only applies when step 1 (refund) is in scope. Steps 2 and 3 don't
  // refund money so the BACS bounce concern doesn't apply to them.
  let txns;
  try {
    txns = await getAgreementTransactionsFromAnchor(agreementId);
  } catch (err) {
    const target = stepFilter === 2 ? result.step2 : stepFilter === 3 ? result.step3 : result.step1;
    target.status = "failed";
    target.error = `Couldn't read agreement from Anchor: ${err.message}`;
    return result;
  }
  if (stepFilter === null || stepFilter === 1) {
    const todayDD = txns.find(t => t.typeId === 12 && t.amount > 0 && t.transactionDate === today);
    if (todayDD) {
      result.deferred = true;
      result.deferReason = `A Direct Debit of £${Math.abs(todayDD.amount).toFixed(2)} landed today (${today}). At least 1 working day must pass before refunding to ensure it isn't bounced by BACS.`;
      return result;
    }
  }
  // ── Step 1: Refund ─────────────────────────────────────────────────
  // Hargo's rule (22/05/2026, third pass): compute net cash collected via
  // the strict formula — sum(Gross) across TypeId 12/23/24/149/150-156 —
  // then refund ONE TypeId 149 per regular monthly instalment owed.
  //   - Net must be a whole-number multiple of the regular monthly
  //     instalment amount (from PaymentProfile modal total). If not,
  //     REFUSE — surfaces an unexpected payment shape for manual review.
  //   - All refunds posted on TODAY's date.
  //   - Replaces the prior per-positive-collection loop which over-refunded
  //     bounced DDs (e.g. A00216640 would have refunded £392.10 vs net £62.98).
  if (stepFilter === null || stepFilter === 1) {
    const netCollected = computeStrictNetPayments(txns); // signed sum
    const xmlForProfile = await getAgreementFromAnchor(agreementId);
    const monthlyInstalment = getRegularMonthlyInstalmentAmount(xmlForProfile);
    result.step1.amount = netCollected;
    result.step1.monthlyInstalment = monthlyInstalment;
    result.step1.perRefund = [];
    result.step1.note = `scope=${scope.kind}${scope.kind === "last" ? `(${scope.n})` : scope.kind === "since" ? `(${scope.date})` : ""}, net collected (strict formula) £${netCollected.toFixed(2)}, monthly instalment £${monthlyInstalment.toFixed(2)}`;

    if (netCollected <= 0.01) {
      result.step1.status = "skipped_no_payments";
      result.step1.note += "; net collected ≤ £0 — nothing to refund";
    } else if (monthlyInstalment <= 0.01) {
      result.step1.status = "failed";
      result.step1.error = `Could not determine regular monthly instalment (PaymentProfile returned £${monthlyInstalment.toFixed(2)}). Manual review required.`;
      result.step1.note += "; refusing — no usable instalment amount";
      return result;
    } else {
      const ratio = netCollected / monthlyInstalment;
      const nearestWhole = Math.round(ratio);
      const isWholeMultiple = Math.abs(ratio - nearestWhole) <= 0.005 && nearestWhole > 0;
      if (!isWholeMultiple) {
        result.step1.status = "failed";
        result.step1.error =
          `Net collected £${netCollected.toFixed(2)} is NOT a whole-number multiple of the monthly instalment £${monthlyInstalment.toFixed(2)} ` +
          `(ratio = ${ratio.toFixed(3)}). Hargo's rule: refuse and surface for manual review when amount doesn't divide cleanly.`;
        result.step1.note += `; refusing — non-divisible amount`;
        return result;
      }
      // Pre-flight: Anchor only actually disburses a TypeId 149 refund when
      // the customer is in credit by at least the refund amount (i.e. the
      // resulting TotalArrears would be ≤ 0). If we post when TotalArrears
      // is still positive, Anchor silently splits each refund (gross→Fee
      // offset) and auto-posts a matching TypeId 35 reversal — net cash to
      // customer = £0, but the ledger gains 2N bogus entries. Surfaced on
      // A00190153 22/05/2026: pre-refund TotalArrears was +£388 (customer
      // still owed principal), all 6 refunds got neutralised by TypeId 35s.
      // The fix is to run step 2 (closure) FIRST so the customer's debt is
      // cleared and they're in credit by their net payments — only then
      // does TypeId 149 actually disburse. We don't auto-reorder here
      // (that's a bigger architectural change pending Hargo's call); we
      // just refuse step 1 with a clear message.
      let preflightArrears = null;
      try {
        preflightArrears = await getAgreementLiveTotalArrears(agreementId);
      } catch (_) { /* fall through — if Anchor doesn't surface it, we'll proceed */ }
      if (Number.isFinite(preflightArrears)) {
        // Customer must be in credit by ≥ netCollected for refund to disburse.
        // Equivalent: preflightArrears + netCollected ≤ £0.01 tolerance.
        // (preflightArrears > 0 means owes Raylo; netCollected > 0 means we're
        // about to refund that much, which subtracts from arrears.)
        const arrearsAfterRefund = preflightArrears - netCollected;
        if (arrearsAfterRefund > 0.01) {
          result.step1.status = "failed";
          result.step1.error =
            `Pre-refund TotalArrears is £${preflightArrears.toFixed(2)} (customer still owes Raylo). ` +
            `Posting £${netCollected.toFixed(2)} of refunds would leave TotalArrears at £${arrearsAfterRefund.toFixed(2)} — ` +
            `Anchor will silently split each TypeId 149 and auto-post matching TypeId 35 reversals, leaving net cash to customer = £0 but polluting the ledger. ` +
            `Run step 2 (closure transaction) FIRST to clear the outstanding principal, then re-run step 1.`;
          result.step1.note += `; refusing — customer not in credit (pre-arrears £${preflightArrears.toFixed(2)}, would land at £${arrearsAfterRefund.toFixed(2)})`;
          return result;
        }
      }
      // Post `nearestWhole` refunds of `monthlyInstalment` each, all dated today.
      const perRefund = [];
      let postedTotal = 0;
      let firstError = null;
      for (let i = 0; i < nearestWhole; i++) {
        const amount = Number(monthlyInstalment.toFixed(2));
        const notes = `Account closure refund — instalment ${i + 1} of ${nearestWhole} (£${amount.toFixed(2)})`;
        try {
          await addTransactionToAnchor(agreementId, today, amount, notes, 149, auditCtx ? {
            ...auditCtx,
            actionType: "refund_posted",
            description: `Account closure refund instalment ${i + 1}/${nearestWhole}: £${amount.toFixed(2)} on ${agreementId}`,
            idempotencyKey: `close_account_refund:${agreementId}:${today}:${i + 1}`,
          } : null);
          perRefund.push({ index: i + 1, total: nearestWhole, amount, posted: true });
          postedTotal += amount;
        } catch (err) {
          perRefund.push({ index: i + 1, total: nearestWhole, amount, posted: false, error: err.message });
          firstError = firstError || err.message;
          break;
        }
      }
      result.step1.perRefund = perRefund;
      result.step1.amount = Number(postedTotal.toFixed(2));
      const postedCount = perRefund.filter(p => p.posted).length;
      if (firstError) {
        result.step1.status = "failed";
        result.step1.error = `posted ${postedCount}/${nearestWhole} refunds; first failure: ${firstError}`;
        result.step1.note += `; posted £${postedTotal.toFixed(2)} of £${netCollected.toFixed(2)} target before halting`;
        return result;
      }
      result.step1.status = "posted";
      result.step1.note += `; posted ${postedCount} × £${monthlyInstalment.toFixed(2)} refunds totalling £${postedTotal.toFixed(2)}, dated ${today}`;
    }

    // Wait for Anchor to reflect step 1 before proceeding.
    if (result.step1.status === "posted") {
      const attempts = [0, 1000, 2000, 3000, 5000];
      const targetNet = computeStrictNetPayments(txns) - (result.step1.amount || 0);
      for (let i = 0; i < attempts.length; i++) {
        if (attempts[i] > 0) await new Promise(r => setTimeout(r, attempts[i]));
        try {
          const t = await getAgreementTransactionsFromAnchor(agreementId);
          const fresh = computeStrictNetPayments(t);
          if (Math.abs(fresh - targetNet) <= 0.01) break;
        } catch (_) { /* ignore and retry */ }
      }
    }
  }

  // Step-filter early return: if we only wanted step 1, stop here.
  if (stepFilter === 1) return result;

  // ── Step 2: Closure transaction ─────────────────────────────────────
  if (stepFilter === null || stepFilter === 2) {
  // Outstanding principal = sum(PaymentProfile.Principal) − sum(Transaction.Principal where TypeId ≠ 99)
  // Top-level <Principal> SOAP field isn't reliable post-refund (Hargo, 19/05/2026),
  // so we recompute from the schedule.
  let op;
  try {
    op = await getAgreementLiveOutstandingPrincipal(agreementId);
  } catch (err) {
    result.step2.status = "failed";
    result.step2.error = `Couldn't compute live outstanding principal: ${err.message}`;
    return result;
  }
  const outstandingPrincipal = op.outstanding;
  result.step2.amount = outstandingPrincipal;
  // Check for an existing TypeId 30/46/26 transaction (the chosen closure type)
  // OR any of the OTHER closure types — if any closure-y transaction already
  // exists on the agreement we shouldn't post a second one in this run.
  const closureTypeIds = new Set([CLOSURE_TYPE_MAP.asset_return.typeId, CLOSURE_TYPE_MAP.lost_in_transit.typeId, CLOSURE_TYPE_MAP.write_off.typeId]);
  const existingClosure = txns.find(t => closureTypeIds.has(t.typeId));
  if (existingClosure) {
    result.step2.status = "skipped_already_actioned";
    result.step2.note = `existing TypeId ${existingClosure.typeId} on ${existingClosure.transactionDate} — not posting another`;
  } else if (outstandingPrincipal <= 0.01) {
    result.step2.status = "skipped_zero_principal";
    result.step2.note = `outstanding principal is £${outstandingPrincipal.toFixed(2)} — nothing to post`;
  } else {
    try {
      const notes = `Account closure — ${closure.label} (outstanding principal £${outstandingPrincipal.toFixed(2)})`;
      await addTransactionToAnchor(agreementId, today, outstandingPrincipal, notes, closure.typeId, auditCtx ? {
        ...auditCtx,
        actionType: `closure_typeid_${closure.typeId}_posted`,
        description: `Closure TypeId ${closure.typeId} (${closure.label}) posted £${outstandingPrincipal.toFixed(2)} on ${agreementId}`,
        idempotencyKey: `closure_step2:${agreementId}:${today}:${closure.typeId}`,
      } : null);
      result.step2.status = "posted";
      result.step2.note = `posted £${outstandingPrincipal.toFixed(2)} (PP.Principal sum £${op.ppSum.toFixed(2)} − Tx.Principal sum excl TypeId 99 £${op.txSumExcl99.toFixed(2)})`;
    } catch (err) {
      result.step2.status = "failed";
      result.step2.error = err.message;
      return result; // halt chain
    }
  }

    // Wait for step 2 to reflect — outstanding principal should drop to ~0.
    if (result.step2.status === "posted") {
      const attempts = [0, 1000, 2000, 3000, 5000];
      for (let i = 0; i < attempts.length; i++) {
        if (attempts[i] > 0) await new Promise(r => setTimeout(r, attempts[i]));
        try {
          const opAfter = await getAgreementLiveOutstandingPrincipal(agreementId);
          if (Math.abs(opAfter.outstanding) <= 0.01) break;
        } catch (_) { /* ignore */ }
      }
    }
  } // end step 2 gate

  // Step-filter early return: if we only wanted step 2, stop here.
  if (stepFilter === 2) return result;

  // ── Step 3: Rebate future charges ───────────────────────────────────
  if (stepFilter !== null && stepFilter !== 3) return result;

  let balanceAfterStep2;
  try {
    balanceAfterStep2 = await getAgreementLiveBalance(agreementId);
  } catch (err) {
    result.step3.status = "failed";
    result.step3.error = `Couldn't read post-step-2 Balance: ${err.message}`;
    return result;
  }
  if (balanceAfterStep2 === null) {
    result.step3.status = "failed";
    result.step3.error = "Anchor response missing Balance for step 3";
    return result;
  }
  result.step3.amount = balanceAfterStep2;
  // Re-read transactions to detect an already-posted TypeId 33.
  let txnsAfter;
  try {
    txnsAfter = await getAgreementTransactionsFromAnchor(agreementId);
  } catch (err) {
    result.step3.status = "failed";
    result.step3.error = `Couldn't re-read transactions for step 3 idempotency: ${err.message}`;
    return result;
  }
  const existingRebate = txnsAfter.find(t => t.typeId === 33);
  if (existingRebate) {
    result.step3.status = "skipped_already_actioned";
    result.step3.note = `existing TypeId 33 on ${existingRebate.transactionDate} (£${Math.abs(existingRebate.amount).toFixed(2)}) — not posting another`;
  } else if (balanceAfterStep2 <= 0.01) {
    result.step3.status = "skipped_zero_balance";
    result.step3.note = `balance is £${balanceAfterStep2.toFixed(2)} — nothing to rebate`;
  } else {
    try {
      const notes = `Account closure — Rebate future charges (Balance £${balanceAfterStep2.toFixed(2)})`;
      await addTransactionToAnchor(agreementId, today, balanceAfterStep2, notes, 33, auditCtx ? {
        ...auditCtx,
        actionType: "rebate_future_charges_posted",
        description: `Rebate future charges (TypeId 33) posted £${balanceAfterStep2.toFixed(2)} on ${agreementId}`,
        idempotencyKey: `closure_step3:${agreementId}:${today}`,
      } : null);
      result.step3.status = "posted";
      result.step3.note = `posted £${balanceAfterStep2.toFixed(2)}`;
    } catch (err) {
      result.step3.status = "failed";
      result.step3.error = err.message;
    }
  }

  return result;
}

/**
 * Parse a "post refund £X on A00XXXXX" / "refund £X on A00XXXXX" request.
 * Returns { agreementId, amount, transactionDate, notes } or null if any of
 * the required fields are missing or the amount is not a positive number.
 *
 * The amount is ALWAYS positive in the request text (Hargo's convention).
 * Validation against the agreement's arrears happens at the handler level.
 */
function parseAddRefundRequest(text) {
  // Agreement ID must be explicit
  const agMatch = text.match(/\bA(\d{5,9})\b/i);
  if (!agMatch) return null;
  const agreementId = `A${agMatch[1].toUpperCase()}`;

  // Amount: positive £X[.XX] or bare decimal
  const amountMatch = text.match(/£\s*([\d,]+(?:\.\d{1,2})?)/i)
    || text.match(/\bamount\b[^0-9£]*£?\s*([\d,]+(?:\.\d{1,2})?)/i)
    || text.match(/([\d,]+\.\d{2})\b/);
  if (!amountMatch) return null;
  const amount = parseFloat(amountMatch[1].replace(/,/g, ""));
  if (isNaN(amount) || amount <= 0) return null;

  const todayStr = new Date().toLocaleDateString("en-CA", { timeZone: "Europe/London" });
  let transactionDate = todayStr;
  const dmyMatch = text.match(/\b(\d{1,2})\/(\d{1,2})\/(\d{4})\b/);
  const isoMatch = text.match(/\b(\d{4})-(\d{2})-(\d{2})\b/);
  if (dmyMatch) {
    transactionDate = `${dmyMatch[3]}-${dmyMatch[2].padStart(2, "0")}-${dmyMatch[1].padStart(2, "0")}`;
  } else if (isoMatch) {
    transactionDate = isoMatch[0];
  } else if (/\btomorrow\b/i.test(text)) {
    transactionDate = nextWorkingDay(todayStr);
  }

  const notesMatch = text.match(/(?:notes?|ref(?:erence)?)\s*[:=]\s*(.+)/i);
  const notes = notesMatch ? notesMatch[1].trim().slice(0, 200) : "";

  return { agreementId, amount, transactionDate, notes };
}

/**
 * Extract the most likely TOTAL amount for a given agreement ID from a block of
 * thread context text (human messages only — not Denton).
 *
 * Supports:
 *   "£13.08 x 12 = £156.96"  → 156.96  (take the product after "=")
 *   "£5.50/mo x 24 = £132"   → 132.00
 *   "£132.00"                 → 132.00  (plain amount near the agreement ID)
 *
 * Only uses lines that DIRECTLY contain the agreement ID — avoids bleeding into
 * adjacent agreements when multiple are listed together (e.g. Laura's refund list).
 */
function extractAmountFromContext(agreementId, contextText) {
  if (!contextText) return null;
  const agUpper = agreementId.toUpperCase();
  const allIdsInContext = new Set([...contextText.matchAll(/\bA\d{5,9}\b/gi)].map(m => m[0].toUpperCase()));

  let text;
  if (allIdsInContext.size <= 1) {
    // Single-agreement thread — no cross-agreement contamination risk, so scan the
    // WHOLE text. The refund TOTAL often sits on a different line than the agreement
    // ID (A00353969, 20/07/2026: the ID line only had the monthly "£10.29 x 24",
    // while the total "£12.38 x 24 = £297.12" was on its own line, so the old
    // line-isolation picked the £10.29 monthly rate instead of the £297.12 total).
    text = contextText;
  } else {
    // Multi-agreement thread — isolate the segment(s) bound to OUR agreement ID so a
    // neighbouring agreement's amount can't bleed in (the 30/04/2026 wrong-£132 bug).
    const lines = contextText.split(/\n/);
    const directLines = lines.filter(line => line.toUpperCase().includes(agUpper));
    const segments = [];
    for (const line of directLines) {
      const idMatches = [...line.matchAll(/\bA\d{5,9}\b/gi)];
      if (idMatches.length <= 1) { segments.push(line); continue; }
      for (let i = 0; i < idMatches.length; i++) {
        if (idMatches[i][0].toUpperCase() !== agUpper) continue;
        const startIdx = idMatches[i].index;
        const endIdx   = (idMatches[i + 1]?.index) ?? line.length;
        segments.push(line.slice(startIdx, endIdx));
      }
    }
    if (segments.length === 0) return null; // can't isolate ours — don't guess
    text = segments.join("\n");
  }

  // 'X[/mo] x N = £TOTAL' — the total is what comes after the '='.
  const multiMatch = text.match(/£[\d,.]+[^\s]*\s*x\s*\d+\s*=\s*£\s*([\d,]+(?:\.\d{1,2})?)/i);
  if (multiMatch) return parseFloat(multiMatch[1].replace(/,/g, ""));

  // Plain '£TOTAL' — largest amount, but EXCLUDE per-period rates ("£X x N",
  // "£X/mo", "£X per month"): those are monthly figures, not refund totals (A00353969).
  const allAmounts = [...text.matchAll(/£\s*([\d,]+(?:\.\d{1,2})?)(\s*(?:[x×*]\s*\d|\/\s*mo|per\s+month))?/gi)]
    .filter(m => !m[2]) // drop per-period rates ("£X x N", "£X/mo", "£X per month")
    .map(m => parseFloat(m[1].replace(/,/g, "")))
    .filter(v => !isNaN(v) && v > 0);
  if (allAmounts.length > 0) return Math.max(...allAmounts);

  return null;
}

/**
 * Extract the total amount that Denton reported for a given agreement ID.
 * Denton's format: "£156.96 total (£13.08/mo)" or "£132.00 total (£5.50/mo)"
 *
 * Uses index-based block extraction to handle both raw Denton output and the
 * contextMessages format (where each message is prefixed "Name: ...").
 * The block boundary is the next "Trade-In: A..." occurrence, regardless of
 * any prefix before it.
 */
function extractDentonAmountFromContext(agreementId, contextText) {
  if (!contextText) return null;
  const agUpper = agreementId.toUpperCase();
  const upper = contextText.toUpperCase();

  // Find the position of "Trade-In:" followed by this agreement ID (with optional space)
  const needle = `TRADE-IN:`;
  let searchFrom = 0;
  let blockStart = -1;
  while (searchFrom < upper.length) {
    const idx = upper.indexOf(needle, searchFrom);
    if (idx === -1) break;
    // Skip "Trade-In:" and optional spaces/colon
    let after = idx + needle.length;
    while (after < upper.length && (upper[after] === " " || upper[after] === ":")) after++;
    // Check if this matches our agreement ID
    if (upper.startsWith(agUpper, after)) {
      blockStart = idx;
      break;
    }
    searchFrom = idx + 1;
  }
  if (blockStart === -1) return null;

  // Find the end: the next "Trade-In: A..." occurrence anywhere after blockStart
  const afterBlock = upper.indexOf(needle, blockStart + needle.length);
  const blockText = afterBlock !== -1
    ? contextText.slice(blockStart, afterBlock)
    : contextText.slice(blockStart);

  // "£156.96 total" — amount immediately before the word "total"
  const totalMatch = blockText.match(/£\s*([\d,]+(?:\.\d{1,2})?)\s+total/i);
  if (totalMatch) return parseFloat(totalMatch[1].replace(/,/g, ""));

  return null;
}

/**
 * Detect a 'revised trade-in difference' refund pattern in the thread for
 * a given agreement. See knowledge/revised-trade-in-refunds.txt for the
 * full description.
 *
 * Returns null if the pattern doesn't appear, or:
 *   {
 *     declared: number,            // £ from the 'declared' line
 *     revised:  number,            // £ from the 'accessed' / 'revised' line
 *     statedDifference: number|null, // £ from the 'difference' line, if any
 *     computedDifference: number,  // declared - revised
 *     arithmeticOK: boolean,       // statedDifference matches computed (±1p)
 *     evidenceOfDeclination: boolean,
 *     evidenceOfPushedToStock: boolean,
 *   }
 */
function parseRevisedTradeInRequest(contextText, agreementId) {
  if (!contextText || !agreementId) return null;
  const agUpper = agreementId.toUpperCase();
  const lines = contextText.split(/\n/);

  // Find lines mentioning this agreement, then take a 10-line window around
  // each so we capture the math lines that often follow the agreement
  // header on subsequent lines.
  const windowSet = new Set();
  lines.forEach((line, i) => {
    if (line.toUpperCase().includes(agUpper)) {
      for (let j = Math.max(0, i); j < Math.min(lines.length, i + 12); j++) {
        windowSet.add(j);
      }
    }
  });
  if (windowSet.size === 0) return null;
  const windowText = [...windowSet].sort((a, b) => a - b).map(i => lines[i]).join("\n");

  // 'Declared' total — accept many phrasings:
  //   '£25.17 Smart declared x 12 - £302.04'    (label between £ and 'x')
  //   'Declared: £23.08 x 12 = £276.96'         (label first)
  //   'Customer declared: £302.04 total'        (Denton-style total)
  // We extract the TOTAL on the right of '=' or '-' / '–' / '—'.
  const declaredTotal = (() => {
    const a = windowText.match(/£\s*[\d,.]+\s*(?:smart\s+|customer\s+)?declared\s*[xX×]\s*\d+\s*[=\-–—]\s*£\s*([\d,]+(?:\.\d{1,2})?)/i);
    if (a) return parseFloat(a[1].replace(/,/g, ""));
    const b = windowText.match(/(?:customer\s+|smart\s+)?declared\s*[:\-]?\s*£\s*[\d,.]+\s*(?:[\/p]?(?:mo|month|inst))?\s*[xX×]\s*\d+\s*[=\-–—]\s*£\s*([\d,]+(?:\.\d{1,2})?)/i);
    if (b) return parseFloat(b[1].replace(/,/g, ""));
    return null;
  })();

  // 'Revised' / 'Accessed' total — same patterns, alternative labels.
  const revisedTotal = (() => {
    const a = windowText.match(/£\s*[\d,.]+\s*(?:smart\s+)?(?:accessed|revised|post[\s-]?assess(?:ed|ment))\s*[xX×]\s*\d+\s*[=\-–—]\s*£\s*([\d,]+(?:\.\d{1,2})?)/i);
    if (a) return parseFloat(a[1].replace(/,/g, ""));
    const b = windowText.match(/(?:smart\s+)?(?:accessed|revised|post[\s-]?assess(?:ed|ment))\s*[:\-]?\s*£\s*[\d,.]+\s*(?:[\/p]?(?:mo|month|inst))?\s*[xX×]\s*\d+\s*[=\-–—]\s*£\s*([\d,]+(?:\.\d{1,2})?)/i);
    if (b) return parseFloat(b[1].replace(/,/g, ""));
    return null;
  })();

  // Need both to confirm this is a revised-difference scenario.
  if (declaredTotal == null || revisedTotal == null) return null;

  // 'Difference' line — optional but usually present.
  let statedDifference = null;
  const diffMatch = windowText.match(/difference\s*[:\-]?\s*£\s*([\d,]+(?:\.\d{1,2})?)/i);
  if (diffMatch) statedDifference = parseFloat(diffMatch[1].replace(/,/g, ""));

  const computedDifference = Math.round((declaredTotal - revisedTotal) * 100) / 100;
  const arithmeticOK = (statedDifference !== null) && Math.abs(computedDifference - statedDifference) <= 0.01;

  // Evidence checks — both should be present to justify the refund.
  const evidenceOfDeclination = /\b(declined|rejected|refused|did(?:n['']?t| not)\s+(?:accept|consent)|not\s+accepted|customer\s+disagreed)\b/i.test(windowText);
  const evidenceOfPushedToStock = /\b(pushed\s+to\s+stock|already\s+in\s+stock|in\s+stock\b|processed\s+anyway|ingram\s+(?:has\s+|already\s+)?(?:processed|pushed))\b/i.test(windowText);

  return {
    declared: Math.round(declaredTotal * 100) / 100,
    revised:  Math.round(revisedTotal  * 100) / 100,
    statedDifference,
    computedDifference,
    arithmeticOK,
    evidenceOfDeclination,
    evidenceOfPushedToStock,
  };
}

/**
 * Parse the figures from DENTON's trade-in card for a given agreement.
 * Denton's card layout puts device text between the label and the value:
 *   "Customer declared: Apple iPhone 7 32GB · Grade B+ · £32.04 total (£2.67/mo)"
 *   "Assessed as:        Apple iPhone 7 32GB · Grade C  · £25.56 total (£2.13/mo)"
 *   "⚠️ different condition than declared · cashback reduced by £6.48"
 * Returns { declared, assessed, difference } (any field null if absent), or
 * null if none could be read. NOTE: parseRevisedTradeInRequest() handles the
 * TEAM's "£X declared x12 = £Y" working format — this handles Denton's CARD
 * format, which differs (Hargo, 22/06/2026).
 */
function parseDentonTradeInFigures(contextText, agreementId) {
  if (!contextText) return null;
  // Scope to THIS agreement's Denton card when present — a thread may carry
  // several cards. Anchor on "Trade-In: <agId>" and read to the next
  // "Trade-In:" header (same approach as extractDentonAmountFromContext). If
  // cards exist but none for this agreement, return null rather than reading a
  // neighbouring agreement's figures.
  let scope = contextText;
  if (agreementId) {
    const upper = contextText.toUpperCase();
    const agUpper = agreementId.toUpperCase();
    const needle = "TRADE-IN:";
    let from = 0, start = -1;
    while (from < upper.length) {
      const idx = upper.indexOf(needle, from);
      if (idx === -1) break;
      let after = idx + needle.length;
      while (after < upper.length && (upper[after] === " " || upper[after] === ":")) after++;
      if (upper.startsWith(agUpper, after)) { start = idx; break; }
      from = idx + 1;
    }
    if (start !== -1) {
      const next = upper.indexOf(needle, start + needle.length);
      scope = next !== -1 ? contextText.slice(start, next) : contextText.slice(start);
    } else if (upper.includes(needle)) {
      return null; // cards present, but not for this agreement → don't guess
    }
    // else: no card header at all → parse whole text (figures may be pasted
    // without Denton's header).
  }
  const num = (s) => parseFloat(String(s).replace(/,/g, ""));
  // Non-greedy {0,220} window lets a LONG device/grade string sit between the
  // label and the "£X total" without over-reaching into the next field. 80 was
  // too short for long spec strings (Hargo, 07/07/2026 — A00366841's "Apple
  // MacBook Pro 13-inch M1 (2020) 8GB Memory 8-core CPU … 1TB SSD · Grade B+ ·"
  // is 117 chars, so the figure was missed and the flow stalled on "still
  // waiting on Denton"). Still lazy, so it stops at the first "£X total".
  const declaredM = scope.match(/customer\s+declared:?[\s\S]{0,220}?£\s*([\d,]+(?:\.\d{1,2})?)\s*total/i);
  const assessedM = scope.match(/assessed\s+as:?[\s\S]{0,220}?£\s*([\d,]+(?:\.\d{1,2})?)\s*total/i);
  const reducedM  = scope.match(/cashback\s+reduced\s+by\s*£\s*([\d,]+(?:\.\d{1,2})?)/i);
  const declared = declaredM ? num(declaredM[1]) : null;
  const assessed = assessedM ? num(assessedM[1]) : null;
  let difference = reducedM ? num(reducedM[1]) : null;
  if (difference == null && declared != null && assessed != null) {
    difference = Math.round((declared - assessed) * 100) / 100;
  }
  if (declared == null && assessed == null && difference == null) return null;
  return {
    declared:   declared   != null ? Math.round(declared   * 100) / 100 : null,
    assessed:   assessed   != null ? Math.round(assessed   * 100) / 100 : null,
    difference: difference != null ? Math.round(difference * 100) / 100 : null,
  };
}

/**
 * When parseAddTransactionRequest returns null (no amount in the command text),
 * try to extract the amount from thread context.
 *
 * Priority order:
 *   1. Revised trade-in difference (declared − accessed)  — distinct refund pattern
 *   2. Denton's confirmed amount                          — standard trade-in
 *   3. Human thread text                                  — last resort
 *
 * For (1), the amount is always the COMPUTED difference, never the team's
 * stated difference, even if both are present. If the team's stated
 * difference disagrees with the computed value (off by >1p), the function
 * returns { needsConfirmation: true, revised: ... } so the caller can
 * surface the discrepancy and refuse to post.
 *
 * Returns:
 *   { parsed: { agreementId, amount, transactionDate, notes, dentonVerified, revisedDifference? } }
 *   { needsConfirmation: 'revised_math_mismatch' | 'revised_evidence_missing', revised: {...}, agreementId }
 *   null  — not enough data in context (caller should ask Denton proactively)
 */
/**
 * Classify a GOGW posting as one of the three known categories.
 * Anchor's TypeId 61 transactions carry their type via the Notes field
 * (no separate Reference column on the AddTransaction SOAP). Hargo's rule
 * (20/05/2026): the Notes MUST match one of the known categories, OR be
 * null + flag-to-Hargo if Billington can't determine it.
 *
 * Returns one of:
 *   "Full trade in value"          — standard trade-in cashback case.
 *   "Partial trade in value"       — revised trade-in difference refund
 *                                    (Ingram revised the offer down,
 *                                    customer declined, but the trade-in
 *                                    was pushed to stock → Raylo refunds
 *                                    declared − accessed).
 *   "Refund and account closure"   — non-trade-in case where Raylo is
 *                                    refunding all collected payments via
 *                                    GOGW + refund, and the agreement is
 *                                    being / will be closed afterwards.
 *                                    Test orders and similar one-offs.
 *   "Escalation resolution"        — CS escalation goodwill payment
 *                                    (Hargo, 20/05/2026). CS team is
 *                                    resolving a complaint / issue with a
 *                                    GOGW to the customer's account — not
 *                                    a trade-in, not a closure. Identified
 *                                    by phrasing like "CS escalation
 *                                    resolution" / "escalation resolution"
 *                                    / "escalation refund" in the thread.
 *   null                           — couldn't determine; caller must
 *                                    refuse and ask the operator to
 *                                    clarify.
 *
 * Detection priority:
 *   1. Explicit operator override in the command itself
 *      ("type:escalation"/"escalation resolution",
 *       "type:closure"/"refund and account closure",
 *       "type:partial"/"partial trade in value",
 *       "type:full"/"full trade in value").
 *   2. CS escalation resolution signals in thread context. Specific phrase
 *      so runs early to avoid mis-classification as Full trade-in (which
 *      also has "trade-in escalation" as a signal).
 *   3. Revised-trade-in (Partial) signals in thread context.
 *   4. Refund-and-account-closure signals — closure intent AND
 *      refund/GOGW intent both present in the thread.
 *   5. Standard trade-in (Full) signals.
 *   6. Otherwise null.
 */
// A trade-in Denton reports as still PENDING ASSESSMENT / awaiting the device is
// NOT yet payable — the declared value isn't confirmed until the device is
// assessed. Detect that so we never propose/post a full or partial payout off the
// declared figure (A00379109, 15/07/2026: Billington proposed a full £167.04 payout
// while Denton showed "Declared — awaiting device", "Pending assessment", 0/36
// cashback paid). Conservative: only true on explicit pending markers, so a genuine
// assessed full trade-in is never blocked. Hargo, 15/07/2026.
function tradeInPendingAssessment(ctx) {
  const t = String(ctx || "");
  // Key on the ASSESSMENT status, not the "awaiting device" trade-in-status label —
  // that label is stale and can sit right next to a COMPLETED assessment on the same
  // Denton card (A00353969, 20/07/2026: "Declared — awaiting device" but "Assessment
  // complete" + "Assessed as £246.96"). If Denton shows an assessed value or the
  // assessment is complete, it is NOT pending, whatever the status line says. Only
  // hold when the card explicitly says pending / not-yet-assessed AND has no assessed value.
  const assessed = /\bassessed\s+as\b/i.test(t) || /\bassessment\b[\s:]*complete\b/i.test(t);
  if (assessed) return false;
  return /\bpending\s+assessment\b/i.test(t) || /\bnot\s+yet\s+assessed\b/i.test(t);
}

// How many days since the trade-in device was received (or last updated) per the
// Denton card. Used to quantify how OVERDUE an assessment is on a pending trade-in
// (Hargo, 21/07/2026): the assessment delay is itself the reason for these refunds,
// so we surface it rather than block. Returns { date: "DD/MM/YYYY", days } or null.
function daysSinceReceived(threadText) {
  const t = String(threadText || "");
  const m =
    t.match(/\b(?:device\s+received|received(?:\s+on)?|last\s+updat(?:e|ed))\b[^\d]{0,20}(\d{1,2})\/(\d{1,2})\/(\d{4})/i) ||
    t.match(/\b(?:device\s+received|received(?:\s+on)?|last\s+updat(?:e|ed))\b[^\d]{0,20}(\d{4})-(\d{2})-(\d{2})/i);
  if (!m) return null;
  let dd, mm, yyyy;
  if (m[1].length === 4) { yyyy = m[1]; mm = m[2]; dd = m[3]; }
  else { dd = m[1].padStart(2, "0"); mm = m[2].padStart(2, "0"); yyyy = m[3]; }
  const then = new Date(`${yyyy}-${mm}-${dd}T12:00:00Z`);
  if (isNaN(then.getTime())) return null;
  const todayStr = new Date().toLocaleDateString("en-CA", { timeZone: "Europe/London" });
  const now = new Date(`${todayStr}T12:00:00Z`);
  const days = Math.round((now - then) / 86400000);
  if (days < 0 || days > 3650) return null;
  return { date: `${dd}/${mm}/${yyyy}`, days };
}

// One-liner describing how overdue the assessment is, for the pending-trade-in warning.
function overdueAssessmentPhrase(threadText) {
  const r = daysSinceReceived(threadText);
  if (!r) return "";
  return ` The device was last updated/received *${r.date}* — that's *${r.days} day${r.days === 1 ? "" : "s"} ago* with still no assessment.`;
}

function inferGogwCategory(cleanText, contextMessages) {
  const cmd = String(cleanText || "");
  const ctx = String(contextMessages || "");

  // 1. Explicit operator override in the command
  if (/\btype\s*[:=]\s*(escalation|cs.?escalation)\b/i.test(cmd)
      || /\b(cs\s+)?escalation\s+resolution\b/i.test(cmd)
      || /\bescalation\s+gogw\b/i.test(cmd)) {
    return "Escalation resolution";
  }
  if (/\btype\s*[:=]\s*(closure|account.?closure)\b/i.test(cmd)
      || /\brefund\s+and\s+account\s+closure\b/i.test(cmd)
      || /\baccount\s+closure\b/i.test(cmd)
      || /\bclosure\s+gogw\b/i.test(cmd)) {
    return "Refund and account closure";
  }
  if (/\btype\s*[:=]\s*partial\b/i.test(cmd)) return "Partial trade in value";
  if (/\btype\s*[:=]\s*full\b/i.test(cmd)) return "Full trade in value";
  if (/\bpartial\s+trade.?in\b|\btrade.?in\s+partial\b|\bpartial\s+gogw\b/i.test(cmd)) return "Partial trade in value";
  if (/\bfull\s+trade.?in\b|\btrade.?in\s+full\b|\bfull\s+gogw\b/i.test(cmd)) return "Full trade in value";

  // 2. CS escalation resolution signals — match the specific phrase pattern
  //    CS uses ("CS escalation resolution", "escalation resolution",
  //    "escalation refund"). Runs BEFORE trade-in detection because
  //    "trade-in escalation" is also a Full-trade-in signal — we want
  //    the more specific "escalation resolution" match to win.
  const escalationSignals = [
    /\bcs\s+escalation\s+resolution\b/i,
    /\bescalation\s+resolution\b/i,
    /\bcs\s+escalation\s+refund\b/i,
    /\bescalation\s+refund\b/i,
    /\bgoodwill.{0,30}\bescalation\b/i,
  ];
  if (escalationSignals.some(r => r.test(ctx))) return "Escalation resolution";

  // 3. Revised trade-in (Partial) signals
  const partialSignals = [
    /\brevised\s+offer\b/i,
    /\bdeclined\s+the\s+revised\b/i,
    /\bcust\s+declined\s+trade.?in\s+revised\b/i,
    /\bsmart\s+accessed\b/i,
    /\baccessed\s+£\d/i,
    /\btrade.?in\s+difference\b/i,
    /\brevised.?\/.?accessed\b/i,
    /\bdeclared.{0,40}\baccessed\b/i,
  ];
  if (partialSignals.some(r => r.test(ctx))) return "Partial trade in value";

  // 4. Refund-and-account-closure signals — fires when both closure intent
  //    AND refund/GOGW intent are present in thread context. Test-order
  //    refunds and similar non-trade-in cases land here.
  const closureIntent = /\b(closure|close\s+(the\s+)?(agreement|account)|account\s+closure|request\s+closure|action\s+closure|closing\s+(the\s+)?agreement)\b/i;
  const closureRefundIntent = /\b(refund\s+all\s+payments?|refund\s+all\s+collections?|refund\s+the\s+payments?|test\s+order|gogw\s+payment|gogw\s+in\s+meantime)\b/i;
  if (closureIntent.test(ctx) && closureRefundIntent.test(ctx)) {
    return "Refund and account closure";
  }

  // 5. Standard trade-in (Full) signals
  const fullSignals = [
    /\btrade.?in\s+escalation\b/i,
    /\bsmart\s+declared\b/i,
    /\btrade.?in\s+cashback\b/i,
    /\btrade.?in\s+status\b/i,
    /\bdenton\b[\s\S]{0,500}\bdeclared\b[\s\S]{0,200}£\d/i,
  ];
  if (fullSignals.some(r => r.test(ctx))) return "Full trade in value";

  return null;
}

/**
 * Compute the locked GOGW+refund figure for an agreement from thread text.
 * Shared by the approval monitor and the chaser (to DISPLAY the figure) and by
 * executeBillingtonAutoApprovedRefund (to RE-DERIVE it at approval time when
 * Billington's displayed command can't be found). Pass thread text that
 * INCLUDES other bots' messages (e.g. Denton's trade-in confirmation) so the
 * amount/type can be read, but EXCLUDES Billington's own proposal.
 *
 * Returns { amount, category, tag, cmd }:
 *   - amount:   positive number, or null if no clear figure
 *   - category: "Full trade in value" | ... | null
 *   - tag:      "type:full" | ... | null
 *   - cmd:      "post gogw and refund £X on A00… type:<tag>" when BOTH amount
 *               and category are known, else null. Never defaults to a type —
 *               a null cmd means the caller should ASK rather than guess.
 */
function computeRefundLock(agreementId, threadText) {
  if (!agreementId || !threadText) return null;
  let amount = extractAmountFromContext(agreementId, threadText);
  if (amount == null) {
    try { amount = extractDentonAmountFromContext(agreementId, threadText); } catch (_) { /* ignore */ }
  }
  if (amount == null) {
    // Lenient fallbacks — callers only lock a SINGLE-agreement thread, so a
    // clearly-labelled total / declared product is unambiguous. Covers the
    // cases the strict line-isolated and Denton-block parsers miss (e.g. when
    // Denton's figure arrives via Block Kit and the "Trade-In: <id>" header
    // sits in a different block from the "£X total" line):
    //   "£87.12 total"          — Denton's confirmed cashback total
    //   "£3.63 x 24 = £87.12"   — declared monthly × term = total
    const totalM = threadText.match(/£\s*([\d,]+(?:\.\d{1,2})?)\s+total\b/i);
    const productM = threadText.match(/£\s*[\d,]+(?:\.\d{1,2})?\s*[x×*]\s*\d+\s*=\s*£\s*([\d,]+(?:\.\d{1,2})?)/i);
    const cand = totalM ? totalM[1] : (productM ? productM[1] : null);
    if (cand) {
      const n = parseFloat(cand.replace(/,/g, ""));
      if (Number.isFinite(n) && n > 0) amount = n;
    }
  }
  const category = inferGogwCategory("", threadText);
  const tag = category ? GOGW_CATEGORY_TO_TYPE_TAG[category] : null;
  const amt = (amount != null && amount > 0) ? amount : null;
  // Never lock a payable command for a trade-in still pending assessment (declared
  // value unconfirmed). Every proposal path keys off `cmd`, so this single guard
  // covers them all — the direct-approval monitor AND the button-approval path
  // (Hargo, 20/07/2026: A00377383 was proposed via the button path, uncaught).
  const isTradeIn = category === "Full trade in value" || category === "Partial trade in value";
  const pending = isTradeIn && tradeInPendingAssessment(threadText);
  const cmd = (amt != null && tag && !pending) ? `post gogw and refund £${amt.toFixed(2)} on ${agreementId.toUpperCase()} ${tag}` : null;
  return { amount: amt, category: category || null, tag: tag || null, cmd, pending };
}

/**
 * Work out FULL vs PARTIAL trade-in from Denton's figures by comparing the
 * refund amount to the values themselves (Hargo, 07/07/2026 — "confirm himself
 * if it's full or not" rather than trusting a phrase or bouncing to the operator):
 *   - refund ≈ declared total          → Full trade in value
 *   - refund ≈ difference (declared−assessed) → Partial trade in value
 * Returns the category string, or null if it can't be determined unambiguously.
 */
function categoryFromDentonFigures(amount, fig) {
  if (!fig || !Number.isFinite(amount)) return null;
  const near = (v) => v != null && Number.isFinite(v) && Math.abs(v - amount) <= 0.01;
  const matchesDeclared   = near(fig.declared);
  const matchesDifference = near(fig.difference);
  if (matchesDeclared && !matchesDifference) return "Full trade in value";
  if (matchesDifference && !matchesDeclared) return "Partial trade in value";
  return null; // ambiguous (both or neither)
}

/**
 * Resolve the trade-in category by asking Denton when the thread doesn't make it
 * clear. Checks the thread for Denton's figures first; if absent, @-asks Denton
 * and polls for the card (~40s), then determines full/partial from the figures.
 * Returns { category: string|null, reason: string }. (Hargo, 07/07/2026)
 */
async function resolveTradeInCategoryViaDenton({ agreementId, amount, channel, thread_ts }) {
  const readThread = async () => {
    try {
      const tr = await app.client.conversations.replies({ token: SLACK_BOT_TOKEN, channel, ts: thread_ts, limit: 100 });
      return (tr.messages || []).map(m => (typeof getMessageText === "function" ? getMessageText(m) : (m.text || ""))).join("\n");
    } catch (_) { return ""; }
  };

  // 1. Denton figures already in the thread?
  const threadText0 = await readThread();
  // Don't confirm a payout for a trade-in Denton still shows as pending assessment.
  if (tradeInPendingAssessment(threadText0)) {
    return { category: null, reason: `${agreementId}'s trade-in has not been assessed yet, so I can't auto-confirm the declared-vs-assessed figure. If that assessment delay is itself the reason for the refund, use the *⚠️ Process anyway* button on the approval message to push it through, or post it explicitly (e.g. \`type:full\`)` };
  }
  let fig = parseDentonTradeInFigures(threadText0, agreementId);
  let cat = categoryFromDentonFigures(amount, fig);
  if (cat) return { category: cat, reason: `Denton figures already on the thread (declared £${fig.declared ?? "?"}, difference £${fig.difference ?? "?"})` };

  // 2. Ask Denton and poll for the card.
  try {
    await app.client.chat.postMessage({
      token: SLACK_BOT_TOKEN, channel, thread_ts,
      text: `<@${DENTON_USER_ID}> what is the trade-in status of ${agreementId}? I need the declared vs assessed figures to confirm whether this £${Number(amount).toFixed(2)} refund is a full or partial trade-in before I post.`,
      mrkdwn: true, unfurl_links: false, unfurl_media: false,
    });
  } catch (e) {
    return { category: null, reason: `couldn't ask Denton (${e.message})` };
  }
  for (let i = 0; i < 8; i++) {
    await new Promise(r => setTimeout(r, 5000));
    const polled = await readThread();
    if (tradeInPendingAssessment(polled)) {
      return { category: null, reason: `${agreementId}'s trade-in has not been assessed yet, so I can't auto-confirm the declared-vs-assessed figure. If that assessment delay is itself the reason for the refund, use the *⚠️ Process anyway* button on the approval message to push it through, or post it explicitly (e.g. \`type:full\`)` };
    }
    fig = parseDentonTradeInFigures(polled, agreementId);
    cat = categoryFromDentonFigures(amount, fig);
    if (cat) return { category: cat, reason: `Denton confirmed (declared £${fig.declared ?? "?"}, assessed £${fig.assessed ?? "?"}, difference £${fig.difference ?? "?"})` };
    // Denton replied with figures but they don't cleanly match the refund — stop
    // early and report, rather than waiting the full window.
    if (fig && (fig.declared != null || fig.difference != null)) {
      return { category: null, reason: `Denton's figures don't line up with £${Number(amount).toFixed(2)} (declared £${fig.declared ?? "?"}, assessed £${fig.assessed ?? "?"}, difference £${fig.difference ?? "?"})` };
    }
  }
  return { category: null, reason: "Denton didn't return figures in time" };
}

/**
 * Build the exact-action "Post GOGW + refund" button for a trade-in refund. The
 * button label and the message spell out precisely what a click will do — no
 * typed command anywhere (Hargo, 07/07/2026: buttons only, never "type this").
 */
// Parse a stated fee/deduction from the thread — e.g. "minus the £40 accessory
// fee", "less £40", "take off £40", "£40 accessory flat fee". Hargo, 07/07/2026
// (A00366841: £317.48 = £357.48 trade-in − £40 accessory fee).
function extractStatedFee(text) {
  if (!text) return 0;
  const m = text.match(/\b(?:minus|less|take\s+off|deduct(?:ing)?|after)\b[^£\d]{0,25}£\s*([\d,]+(?:\.\d{1,2})?)/i)
        || text.match(/£\s*([\d,]+(?:\.\d{1,2})?)\s*(?:accessory|replacement|admin|damage|flat|restocking)\s*(?:replacement\s*)?(?:flat\s*)?fee\b/i);
  if (!m) return 0;
  const n = parseFloat(m[1].replace(/,/g, ""));
  return Number.isFinite(n) && n > 0 ? n : 0;
}

// Pick the operative REQUESTED refund amount from a thread — the most recent
// explicit "refund … £X" / "£X … refund/due", which can differ from the trade-in
// total when a fee is deducted (Hargo, 07/07/2026). Falls back to the
// agreement-scoped extractor.
function extractRequestedRefundAmount(text, agreementId) {
  const matches = [...(text || "").matchAll(/(?:refund|arrange(?:\s+a)?(?:\s+refund)?)\s+(?:for\s+|of\s+|amount\s+)?£\s*([\d,]+(?:\.\d{1,2})?)|£\s*([\d,]+(?:\.\d{1,2})?)\s+(?:refund|due(?:\s+for\s+refund)?|due\s+per\s+approval)/gi)];
  if (matches.length) {
    const last = matches[matches.length - 1];
    const n = parseFloat((last[1] || last[2]).replace(/,/g, ""));
    if (Number.isFinite(n) && n > 0) return n;
  }
  return extractAmountFromContext(agreementId, text);
}

// opts: { fee, tradeInValue } — when a fee was deducted, show the breakdown and
// require the presser to confirm the revised amount. The button carries the
// vetted amount/category/agreement so the executor posts exactly that (no
// re-derivation drift).
function buildTradeInPostButtonBlocks(agreementId, amount, category, channel, threadTs, opts = {}) {
  const amt = Number(amount).toFixed(2);
  const catShort = category === "Full trade in value" ? "Full trade-in"
                 : category === "Partial trade in value" ? "Partial trade-in"
                 : category;
  const fee = Number(opts.fee) > 0 ? Number(opts.fee) : 0;
  const tradeInValue = fee > 0 && Number(opts.tradeInValue) > 0 ? Number(opts.tradeInValue) : null;
  const breakdown = (fee > 0 && tradeInValue) ? ` (trade-in £${tradeInValue.toFixed(2)} − £${fee.toFixed(2)} fee = £${amt})` : "";
  const prefix = opts.supersede ? `♻️ *Corrected figure* — use this, ignore my earlier button.\n` : "";
  const line = prefix + (fee > 0
    ? `✅ *${agreementId}* — Denton reconciled: *${catShort}*${breakdown}. This button posts *GOGW £${amt} + refund £${amt}* — the *fee-reduced* amount — after the live pre-checks (blockers 26/28/30/34/46/63/64/70, existing TypeId 61, TotalArrears). Confirm the *£${amt}* figure when you press; only ${BILLINGTON_REFUND_AUTHORISER_NAMES} can action.`
    : `✅ *${agreementId}* — Denton reconciled: *${catShort}*, £${amt}. This button posts *GOGW £${amt} + refund £${amt}* (${category}) after the live pre-checks (blockers 26/28/30/34/46/63/64/70, existing TypeId 61, TotalArrears). Only ${BILLINGTON_REFUND_AUTHORISER_NAMES} can action.`);
  const confirmText = fee > 0
    ? `Posts GOGW £${amt} + refund £${amt} on ${agreementId} — the fee-reduced figure${breakdown}. Confirm this revised amount.`
    : `Posts GOGW £${amt} + refund £${amt} on ${agreementId} (${category}) after live pre-checks.`;
  return {
    text: line,
    blocks: [
      { type: "section", text: { type: "mrkdwn", text: line } },
      { type: "actions", elements: [
        { type: "button", text: { type: "plain_text", text: `💸 Post GOGW £${amt} + refund £${amt} — ${catShort}`, emoji: true }, style: "primary", action_id: "btn_post_gogw_refund",
          value: JSON.stringify({ t: threadTs, c: channel, amount: Number(amount), category, ag: agreementId }),
          confirm: { title: { type: "plain_text", text: fee > 0 ? "Confirm revised amount?" : "Post GOGW + refund?" }, text: { type: "mrkdwn", text: confirmText }, confirm: { type: "plain_text", text: `Post £${amt}` }, deny: { type: "plain_text", text: "Cancel" } } },
        billingtonIncorrectButton(),
      ]},
    ],
  };
}

/**
 * Prepare a trade-in refund in a thread the button-first way (Hargo, 07/07/2026):
 *   - Denton's figures already in the thread → reconcile £amount → post the
 *     exact-action button (or flag if it doesn't reconcile).
 *   - Denton not consulted yet → @-mention Denton for the trade-in status; the
 *     Denton watcher posts the button when he replies.
 * Idempotent: won't re-ask Denton or re-post a button if already done in-thread.
 * Never suggests a typed command. Returns a short status string.
 */
async function prepareTradeInRefundButton({ channel, threadTs, agreementId, amount, forceNew = false }) {
  let msgs = [];
  try {
    const tr = await app.client.conversations.replies({ token: SLACK_BOT_TOKEN, channel, ts: threadTs, limit: 100 });
    msgs = tr.messages || [];
  } catch (e) { return `couldn't read thread: ${e.message}`; }
  const isBillington = (m) => m.user === BOT_USER_ID || m.bot_id;
  const threadText = msgs.map(m => getMessageText(m)).join("\n");
  // Derive the requested amount from HUMAN messages only, chronologically
  // (conversations.replies is oldest→newest) so the NEWEST human "refund £X"
  // wins. CRITICAL: exclude Billington's OWN messages — its earlier button/recap
  // echoes ("refund of £357.48") would otherwise become the "latest" match and
  // it'd keep re-deriving the wrong figure (Hargo, 07/07/2026 — A00366841 kept
  // picking £357.48 from its own posts instead of Laura's £317.48). Denton's card
  // stays out of this too (his "£X total" isn't a "refund £X"). Falls back to the
  // caller-passed amount if there's no explicit human refund figure.
  const humanText = msgs.filter(m => !isBillington(m)).map(m => getMessageText(m)).join("\n");
  const derivedAmount = extractRequestedRefundAmount(humanText, agreementId);
  if (Number.isFinite(derivedAmount) && derivedAmount > 0) amount = derivedAmount;
  const amtStr = Number(amount).toFixed(2);
  // Already a button up for THIS exact amount → nothing to do (unless the caller
  // explicitly asked for a fresh one — "the button is wrong, make a new one").
  // A stale button for a DIFFERENT amount is superseded by the corrected one below.
  const priorButton = msgs.some(m => isBillington(m) && /GOGW\s*£[\d.,]+\s*\+\s*refund/i.test(getMessageText(m)));
  const buttonForThisAmount = msgs.some(m => isBillington(m) && new RegExp(`GOGW\\s*£\\s*${amtStr.replace(/\./g, "\\.")}\\s*\\+\\s*refund`, "i").test(getMessageText(m)));
  if (buttonForThisAmount && !forceNew) return "button already up";

  const fig = parseDentonTradeInFigures(threadText, agreementId);
  const dentonPresent = fig && (fig.declared != null || fig.difference != null);

  if (dentonPresent) {
    // "Corrected figure" note only when a prior button existed for a DIFFERENT
    // amount (a genuine correction), not on a same-amount forced repost.
    const supersede = priorButton && !buttonForThisAmount;
    let category = categoryFromDentonFigures(amount, fig);
    let feeInfo = { supersede };
    if (!category) {
      // Fee-reduced trade-in (Hargo, 07/07/2026): the refund is the trade-in
      // value minus a stated fee (e.g. £317.48 = £357.48 − £40 accessory fee).
      // Reconcile refund + fee against Denton; if it lines up, treat it as a
      // fee-reduced full/partial and show the breakdown on the button.
      const fee = extractStatedFee(threadText);
      if (fee > 0) {
        const catWithFee = categoryFromDentonFigures(amount + fee, fig);
        if (catWithFee) { category = catWithFee; feeInfo = { fee, tradeInValue: amount + fee, supersede }; }
      }
    }
    if (!category) {
      await app.client.chat.postMessage({ token: SLACK_BOT_TOKEN, channel, thread_ts: threadTs, mrkdwn: true, unfurl_links: false, unfurl_media: false,
        text: `⚠️ *${agreementId}* — Denton's figures (declared £${fig.declared ?? "?"}, assessed £${fig.assessed ?? "?"}, difference £${fig.difference ?? "?"}) don't reconcile with the £${Number(amount).toFixed(2)} requested here (even allowing for a stated fee), so I can't confirm full vs partial. Worth a review with Denton before this posts.` });
      return "denton mismatch";
    }
    const btn = buildTradeInPostButtonBlocks(agreementId, amount, category, channel, threadTs, feeInfo);
    await app.client.chat.postMessage({ token: SLACK_BOT_TOKEN, channel, thread_ts: threadTs, text: btn.text, blocks: btn.blocks, mrkdwn: true, unfurl_links: false, unfurl_media: false });
    return "button posted";
  }

  // Denton has ALREADY posted a trade-in card in this thread but the figures
  // didn't parse — do NOT ask him again (Hargo, 07/07/2026: "does not need to
  // mention Denton again"). Flag it for a human instead.
  const dentonHasPosted = msgs.some(m =>
    (m.user === DENTON_USER_ID || m.bot_id) &&
    /trade-?in:?\s*A\d|trade.?in\s+status|customer\s+declared/i.test(getMessageText(m))
  );
  if (dentonHasPosted) {
    await app.client.chat.postMessage({ token: SLACK_BOT_TOKEN, channel, thread_ts: threadTs, mrkdwn: true, unfurl_links: false, unfurl_media: false,
      text: `⚠️ *${agreementId}* — Denton has already replied in this thread but I couldn't read his declared/assessed figures, so I can't reconcile the £${Number(amount).toFixed(2)} refund. Worth a quick look at his card before this posts (I won't re-ask him).` });
    return "denton unparseable";
  }

  // Denton not consulted — ask him (once). The watcher will post the button on reply.
  const alreadyAsked = msgs.some(m => m.user === BOT_USER_ID && /what is the trade-in status of/i.test(getMessageText(m)));
  if (alreadyAsked) return "already asked denton, awaiting reply";
  pendingGOGWRequests.set(`${channel}:${agreementId}`, { requesterId: null, thread_ts: threadTs, requestedAt: Date.now() });
  await app.client.chat.postMessage({ token: SLACK_BOT_TOKEN, channel, thread_ts: threadTs, mrkdwn: true, unfurl_links: false, unfurl_media: false,
    text: `<@${DENTON_USER_ID}> what is the trade-in status of ${agreementId}? Once you confirm the declared/assessed figures I'll reconcile them against the £${Number(amount).toFixed(2)} approved here and put a *Post GOGW + refund* button up for ${BILLINGTON_REFUND_AUTHORISER_NAMES}.` });
  // Proactively follow up ~30s later to read Denton's reply and post the button
  // (the passive watcher can miss Denton's Block Kit messages). Hargo, 07/07/2026.
  scheduleDentonFollowUp({ channel, threadTs, agreementId, amount });
  return "asked denton";
}

/**
 * After Billington @-asks Denton for a trade-in status, poll the thread every
 * ~30s (up to maxAttempts) and post the Post GOGW + refund button as soon as
 * Denton's figures land. Reuses prepareTradeInRefundButton, which is idempotent
 * (won't re-ask Denton or double-post). Gives up with a hold note after the
 * window. (Hargo, 07/07/2026 — "follow up after 30 seconds to check Denton".)
 */
function scheduleDentonFollowUp({ channel, threadTs, agreementId, amount }, attempt = 1, maxAttempts = 4) {
  setTimeout(async () => {
    try {
      const status = await prepareTradeInRefundButton({ channel, threadTs, agreementId, amount });
      if (status === "button posted" || status === "button already up" || status === "denton mismatch") return;
      if (attempt < maxAttempts) {
        scheduleDentonFollowUp({ channel, threadTs, agreementId, amount }, attempt + 1, maxAttempts);
      } else {
        try {
          await app.client.chat.postMessage({
            token: SLACK_BOT_TOKEN, channel, thread_ts: threadTs, mrkdwn: true, unfurl_links: false, unfurl_media: false,
            text: `⏳ Still waiting on Denton's trade-in figures for ${agreementId}. I'll hold — re-tag me once he's replied and I'll put the *Post GOGW + refund* button up.`,
          });
        } catch (_) {}
      }
    } catch (e) {
      console.error(`[bill-ling] Denton follow-up (${agreementId}) error:`, e.message);
    }
  }, 30000);
}

function tryExtractGOGWFromContext(cleanText, contextMessages) {
  const agMatch = cleanText.match(/\b(A\d{5,9})\b/i);
  if (!agMatch || !contextMessages) return null;
  const agreementId = agMatch[1].toUpperCase();

  const todayStr = new Date().toLocaleDateString("en-CA", { timeZone: "Europe/London" });
  const notesMatch = cleanText.match(/(?:notes?|ref(?:erence)?)\s*[:=]\s*(.+)/i);
  const notes = notesMatch ? notesMatch[1].trim().slice(0, 200) : "Trade-in refund";

  // ── 1. Revised trade-in difference scenario takes priority ────────────
  // If the thread has both 'declared' and 'accessed/revised' totals for
  // this agreement, we're in a revised-difference refund flow, not a
  // standard trade-in. Use the COMPUTED difference, not the stated one.
  const revised = parseRevisedTradeInRequest(contextMessages, agreementId);
  if (revised) {
    if (!revised.arithmeticOK) {
      // Stated difference doesn't match computed. Don't guess — refuse and
      // surface the mismatch for the operator to clarify.
      return {
        needsConfirmation: "revised_math_mismatch",
        revised,
        agreementId,
      };
    }
    if (!revised.evidenceOfDeclination || !revised.evidenceOfPushedToStock) {
      return {
        needsConfirmation: "revised_evidence_missing",
        revised,
        agreementId,
      };
    }
    return {
      parsed: {
        agreementId,
        amount: revised.computedDifference,
        transactionDate: todayStr,
        notes: `Trade-in revised difference refund — declared £${revised.declared.toFixed(2)}, accessed £${revised.revised.toFixed(2)}, difference £${revised.computedDifference.toFixed(2)}`,
        fromContext: true,
        dentonVerified: false,
        revisedDifference: revised,
      },
    };
  }

  // ── 2. Denton's confirmed amount — standard trade-in ──────────────────
  const dentonAmt = extractDentonAmountFromContext(agreementId, contextMessages);
  if (dentonAmt !== null) {
    return {
      parsed: {
        agreementId,
        amount: dentonAmt,
        transactionDate: todayStr,
        notes,
        fromContext: true,
        dentonVerified: true,
      },
    };
  }

  // Denton hasn't confirmed yet — try human thread text as fallback.
  // extractAmountFromContext already returns null when the thread
  // contains multiple agreement IDs and the target's amount can't be
  // unambiguously isolated, so we propagate that null upward without
  // silently grabbing 'whatever amount is closest to the agreement
  // ID'. This is the safety net that prevents the wrong-£132-on-
  // A00343917 class of error.
  const requestedAmt = extractAmountFromContext(agreementId, contextMessages);
  if (!requestedAmt) return null;

  return {
    parsed: {
      agreementId,
      amount: requestedAmt,
      transactionDate: todayStr,
      notes,
      fromContext: true,
      dentonVerified: false,
    },
  };
}

/**
 * Extract bounce/reversal transactions (TypeId 150-156) from Anchor SOAP XML.
 * Returns a compact summary string instead of the full XML to stay within token limits.
 */
function extractReversalsFromXml(xml, agreementId) {
  // Extract all Transaction blocks
  const txnBlocks = xml.match(/<a:Transaction>([\s\S]*?)<\/a:Transaction>/g) || [];
  const reversals = [];
  for (const block of txnBlocks) {
    const typeMatch = block.match(/<a:TypeId>(\d+)<\/a:TypeId>/);
    if (!typeMatch) continue;
    const typeId = parseInt(typeMatch[1], 10);
    if (typeId < 150 || typeId > 156) continue;
    const amountMatch = block.match(/<a:Amount>([\d.-]+)<\/a:Amount>/);
    const dateMatch = block.match(/<a:TransactionDate>([\d-T:.]+)<\/a:TransactionDate>/);
    const createdMatch = block.match(/<a:CreatedAt>([\d-T:.]+)<\/a:CreatedAt>/);
    reversals.push({
      typeId,
      amount: amountMatch ? amountMatch[1] : "unknown",
      date: dateMatch ? dateMatch[1].slice(0, 10) : "unknown",
      created: createdMatch ? createdMatch[1].slice(0, 10) : "unknown",
    });
  }
  if (reversals.length === 0) return `${agreementId}: NO reversal transactions (TypeId 150-156) found`;
  return `${agreementId}: ${reversals.length} reversal(s) — ` +
    reversals.map(r => `TypeId ${r.typeId} | £${r.amount} | date ${r.date}`).join("; ");
}

/**
 * Strip PII fields from Anchor SOAP XML before passing to Claude.
 * Removes: customer name, DOB, bank account details (name, sort code, account number, IBAN, BIC).
 */
function stripPiiFromXml(xml) {
  // Remove entire Customers block (contains Name, DateOfBirth, addresses, etc.)
  xml = xml.replace(/<(?:a:)?Customers>[\s\S]*?<\/(?:a:)?Customers>/g, "<Customers>[REDACTED]</Customers>");
  // Remove bank details (handle both namespaced a: and non-namespaced tags)
  xml = xml.replace(/<(?:a:)?BankAccountName>[^<]*<\/(?:a:)?BankAccountName>/g, "<BankAccountName>[REDACTED]</BankAccountName>");
  xml = xml.replace(/<(?:a:)?BankSortCode>[^<]*<\/(?:a:)?BankSortCode>/g, "<BankSortCode>[REDACTED]</BankSortCode>");
  xml = xml.replace(/<(?:a:)?BankAccountNumber>[^<]*<\/(?:a:)?BankAccountNumber>/g, "<BankAccountNumber>[REDACTED]</BankAccountNumber>");
  xml = xml.replace(/<(?:a:)?BankIBAN>[^<]*<\/(?:a:)?BankIBAN>/g, "<BankIBAN>[REDACTED]</BankIBAN>");
  xml = xml.replace(/<(?:a:)?BankBIC>[^<]*<\/(?:a:)?BankBIC>/g, "<BankBIC>[REDACTED]</BankBIC>");
  return xml;
}

// ---------------------------------------------------------------------------
// Apportionment Analysis
//
// Pulls an agreement from Anchor, extracts every transaction + payment
// profile chronologically, and runs the apportionment rules (see
// /knowledge/apportionment-logic.txt) to detect:
//   - late fees (TypeId 49) settled while normal components were still
//     outstanding ("settled too early")
//   - card payments / DDs that previously settled a late fee and were
//     subsequently reversed without the late fee being reinstated
//   - any other downstream allocations that were based on a now-reversed
//     state
//
// The deterministic part of this function is the parsing + structuring
// of transactions; the apportionment reasoning itself is handed to
// Claude with the rules baked into the system prompt via the knowledge
// file. The LLM gets clean structured data, not raw XML.
// ---------------------------------------------------------------------------

/**
 * Parse all `<Transaction>` blocks from an agreement's Anchor XML and
 * return a chronologically-sorted array of structured rows. Tags are
 * matched both with and without the `a:` namespace prefix (Aryza's SOAP
 * payload uses both forms depending on which method was called).
 */
function parseAnchorTransactions(xml) {
  const blocks = xml.match(/<(?:a:)?Transaction>[\s\S]*?<\/(?:a:)?Transaction>/g) || [];
  const tag = (block, name) => {
    const m = block.match(new RegExp(`<(?:a:)?${name}>([^<]*)<\\/(?:a:)?${name}>`));
    return m ? m[1] : null;
  };
  const txns = blocks.map((block) => {
    const typeIdRaw = tag(block, "TypeId");
    const typeId    = typeIdRaw != null ? parseInt(typeIdRaw, 10) : null;
    const dateRaw   = tag(block, "TransactionDate");
    const postedRaw = tag(block, "PostedDate") || tag(block, "PostingDate");
    const date      = dateRaw   ? dateRaw.slice(0, 10)   : null;
    const posted    = postedRaw ? postedRaw.slice(0, 10) : null;
    const amount    = parseFloat(tag(block, "Amount") || "NaN");
    const gross     = parseFloat(tag(block, "Gross")  || "NaN");
    const net       = parseFloat(tag(block, "Net")    || "NaN");
    const vat       = parseFloat(tag(block, "VAT")    || "NaN");
    const interest  = parseFloat(tag(block, "Interest") || "NaN");
    const principal = parseFloat(tag(block, "Principal") || "NaN");
    const fees      = parseFloat(tag(block, "Fees") || "NaN");
    const vatOnFees = parseFloat(tag(block, "VATOnFees") || tag(block, "VatOnFees") || "NaN");
    const id        = tag(block, "TransactionId") || tag(block, "Id");
    const paymentDate = tag(block, "PaymentDate"); // links a payment-shaped txn to a profile
    const description = TRANSACTION_TYPES[typeId] || (typeId != null ? `Unknown (${typeId})` : "Unknown");
    return {
      id, typeId, description, date, posted,
      amount: isFinite(amount) ? Math.round(amount * 100) / 100 : null,
      gross:  isFinite(gross)  ? Math.round(gross  * 100) / 100 : null,
      net:    isFinite(net)    ? Math.round(net    * 100) / 100 : null,
      vat:    isFinite(vat)    ? Math.round(vat    * 100) / 100 : null,
      interest:  isFinite(interest)  ? Math.round(interest  * 100) / 100 : null,
      principal: isFinite(principal) ? Math.round(principal * 100) / 100 : null,
      fees:      isFinite(fees)      ? Math.round(fees      * 100) / 100 : null,
      vatOnFees: isFinite(vatOnFees) ? Math.round(vatOnFees * 100) / 100 : null,
      profileDate: paymentDate ? paymentDate.slice(0, 10) : null,
    };
  });
  // Chronological sort, falling back to TypeId so reversals immediately
  // follow the originals on the same day.
  txns.sort((a, b) => {
    const ad = a.date || a.posted || "";
    const bd = b.date || b.posted || "";
    if (ad !== bd) return ad < bd ? -1 : 1;
    return (a.typeId || 0) - (b.typeId || 0);
  });
  return txns;
}

/**
 * Parse `<PaymentProfile>` rows. Each row represents an instalment due
 * on a specific date with its component breakdown. Returns an array
 * sorted oldest-first so the apportionment walk can settle the oldest
 * profile first per the rules.
 */
function parseAnchorProfiles(xml) {
  const blocks = xml.split(/<(?:a:)?PaymentProfile>/).slice(1);
  const tag = (block, name) => {
    const m = block.match(new RegExp(`<(?:a:)?${name}>([^<]*)<\\/(?:a:)?${name}>`));
    return m ? m[1] : null;
  };
  const profiles = [];
  for (const raw of blocks) {
    const dateRaw = tag(raw, "PaymentDate");
    if (!dateRaw) continue;
    const date = dateRaw.slice(0, 10);
    const num = (k) => {
      const v = parseFloat(tag(raw, k) || "NaN");
      return isFinite(v) ? Math.round(v * 100) / 100 : null;
    };
    profiles.push({
      date,
      amount:    num("PaymentAmount"),
      principal: num("Principal"),
      interest:  num("Interest"),
      fees:      num("Fees"),
      vatOnFees: num("VATOnFees") ?? num("VatOnFees"),
      vat:       num("VAT"),
    });
  }
  profiles.sort((a, b) => (a.date < b.date ? -1 : a.date > b.date ? 1 : 0));
  return profiles;
}

/**
 * Format the parsed transaction list into a compact, LLM-friendly table.
 * Drops empty/null fields so the prompt isn't dominated by `null,null,null`.
 */
function formatTxnsForPrompt(txns) {
  return txns.map((t, idx) => {
    const parts = [`#${idx + 1}`, t.date || t.posted || "(no date)", `TypeId ${t.typeId} (${t.description})`];
    if (t.gross != null) parts.push(`gross £${t.gross.toFixed(2)}`);
    else if (t.amount != null) parts.push(`amount £${t.amount.toFixed(2)}`);
    if (t.principal != null) parts.push(`principal £${t.principal.toFixed(2)}`);
    if (t.interest  != null) parts.push(`interest £${t.interest.toFixed(2)}`);
    if (t.vatOnFees != null) parts.push(`vatOnFees £${t.vatOnFees.toFixed(2)}`);
    if (t.fees      != null) parts.push(`fees £${t.fees.toFixed(2)}`);
    if (t.vat       != null) parts.push(`vat £${t.vat.toFixed(2)}`);
    if (t.profileDate)       parts.push(`profileDate ${t.profileDate}`);
    if (t.id)                parts.push(`txnId ${t.id}`);
    return parts.join(" | ");
  }).join("\n");
}

function formatProfilesForPrompt(profiles) {
  return profiles.map((p) => {
    const parts = [`profile ${p.date}`];
    if (p.amount    != null) parts.push(`total £${p.amount.toFixed(2)}`);
    if (p.principal != null) parts.push(`P £${p.principal.toFixed(2)}`);
    if (p.interest  != null) parts.push(`I £${p.interest.toFixed(2)}`);
    if (p.vatOnFees != null) parts.push(`VATfees £${p.vatOnFees.toFixed(2)}`);
    if (p.fees      != null) parts.push(`F £${p.fees.toFixed(2)}`);
    if (p.vat       != null) parts.push(`V £${p.vat.toFixed(2)}`);
    return parts.join(" | ");
  }).join("\n");
}

/**
 * Run the apportionment analysis for a single agreement. Returns the
 * formatted markdown report ready to post to Slack.
 */
async function analyseApportionment(agreementId) {
  let xml;
  try {
    xml = await getAgreementFromAnchor(agreementId);
  } catch (err) {
    return `Could not fetch ${agreementId} from Anchor: ${err.message}`;
  }
  const safeXml  = stripPiiFromXml(xml);
  const txns     = parseAnchorTransactions(safeXml);
  const profiles = parseAnchorProfiles(safeXml);
  if (txns.length === 0) {
    return `${agreementId}: no transactions found in Anchor — nothing to analyse.`;
  }

  // Quick deterministic flag: every TypeId 49 (late fee) that was followed
  // by any reversal-class TypeId on the same payment leg. We surface this
  // to the LLM as 'attention rows' so it pays special attention.
  const reversalTypeIds = new Set([24, 31, 32, 35, 36, 43, 44, 47, 48, 50, 56, 66, 67, 69, 71, 73, 74, 75, 150, 151, 152, 153, 154, 155, 156, 157]);
  const lateFees      = txns.filter(t => t.typeId === 49);
  const lateFeeRevs   = txns.filter(t => t.typeId === 50);
  const reversals     = txns.filter(t => reversalTypeIds.has(t.typeId));

  const today = new Date().toLocaleDateString("en-CA", { timeZone: "Europe/London" });
  const prompt = `You are auditing an apportionment trail for Raylo agreement ${agreementId}. Today is ${today}.

Apply the rules in the 'apportionment-logic.txt' knowledge file. The core question: have all TypeId 49 (Late payment fee) entries been settled correctly per Raylo's rules — i.e. only after every other component (principal, interest, VAT on fees, fees, VAT) was clear at the moment of payment, and never settled by a payment that has since been reversed without the late fee being reinstated.

Output a Slack-formatted report with these sections (omit any that are empty):

*Summary*
1-2 lines: total instalments, total late fees applied, total late fee reversals, ballpark balance state (in arrears / in credit / clear).

*Late fee position*
For each TypeId 49 in the list, state whether it currently appears settled or outstanding, and whether the settlement was correct under the rules. Cite specific transactions by # (#3, #11, etc.).

*Issues found*
Each issue starts with one of:
  - :rotating_light: 'Late fee settled too early' — late fee 49 appears cleared while a normal component on an older or same-date profile was still outstanding.
  - :rotating_light: 'Reversal not reflected in late fee status' — a payment that contributed to settling a late fee was reversed (TypeId 24/50/150-156/etc.) and the late fee is not back as outstanding.
  - :warning: 'Downstream allocation suspect' — a payment after a reversal may have been applied to components already covered by the reversed payment.

*Recommended actions*
Concrete next steps — e.g. 'reverse the TypeId 49 settlement, re-apply the surplus to outstanding principal on the 2026-01-02 profile', 'manual reapportion needed on Anchor', etc.

If no issues are found, say so explicitly with a single line: ':white_check_mark: No apportionment issues detected.'

NEVER quote raw transaction IDs (TransactionId is fine for cross-ref); never invent numbers. Round to 2dp.

— Payment Profiles (oldest first) —
${formatProfilesForPrompt(profiles)}

— Transactions (chronological) —
${formatTxnsForPrompt(txns)}

— Reference counts —
Late fees applied (TypeId 49): ${lateFees.length}
Late fee reversals (TypeId 50): ${lateFeeRevs.length}
Total reversal-class transactions (any TypeId): ${reversals.length}`;

  let report;
  try {
    report = await askClaude(prompt);
  } catch (err) {
    return `${agreementId}: apportionment analysis failed during LLM call: ${err.message}`;
  }
  return `*Apportionment audit — ${agreementId}*\n\n${report}`;
}

// UK bank holidays — extend as needed
const UK_BANK_HOLIDAYS = new Set([
  "2026-01-01","2026-04-03","2026-04-06","2026-05-04",
  "2026-05-25","2026-08-31","2026-12-25","2026-12-28",
  "2027-01-01","2027-04-02","2027-04-05","2027-05-03",
  "2027-05-31","2027-08-30","2027-12-27","2027-12-28",
]);

const UK_BANK_HOLIDAY_NAMES = {
  "2026-01-01": "New Year's Day",
  "2026-04-03": "Good Friday",
  "2026-04-06": "Easter Monday",
  "2026-05-04": "Early May Bank Holiday",
  "2026-05-25": "Spring Bank Holiday",
  "2026-08-31": "Summer Bank Holiday",
  "2026-12-25": "Christmas Day",
  "2026-12-28": "Boxing Day (substitute)",
  "2027-01-01": "New Year's Day",
  "2027-04-02": "Good Friday",
  "2027-04-05": "Easter Monday",
  "2027-05-03": "Early May Bank Holiday",
  "2027-05-31": "Spring Bank Holiday",
  "2027-08-30": "Summer Bank Holiday",
  "2027-12-27": "Christmas Day (substitute)",
  "2027-12-28": "Boxing Day (substitute)",
};

function isWorkingDay(dateStr) {
  const d = new Date(dateStr + "T12:00:00Z");
  const dow = d.getUTCDay();
  return dow !== 0 && dow !== 6 && !UK_BANK_HOLIDAYS.has(dateStr);
}

function prevWorkingDay(dateStr) {
  const d = new Date(dateStr + "T12:00:00Z");
  do { d.setUTCDate(d.getUTCDate() - 1); }
  while (!isWorkingDay(d.toISOString().slice(0, 10)));
  return d.toISOString().slice(0, 10);
}

function nextWorkingDay(dateStr) {
  const d = new Date(dateStr + "T12:00:00Z");
  do { d.setUTCDate(d.getUTCDate() + 1); }
  while (!isWorkingDay(d.toISOString().slice(0, 10)));
  return d.toISOString().slice(0, 10);
}

function fmtDate(dateStr) {
  const [y, m, d] = dateStr.split("-");
  return `${d}/${m}/${y}`;
}

// Day-of-week name for a YYYY-MM-DD date (UTC midday-anchored to avoid TZ drift).
function dayOfWeekName(dateStr) {
  const d = new Date(dateStr + "T12:00:00Z");
  return ["Sunday", "Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday"][d.getUTCDay()];
}

// Previous calendar day (NOT previous working day — this is "yesterday" in the
// strict sense, weekends and bank holidays included).
function previousCalendarDay(dateStr) {
  const d = new Date(dateStr + "T12:00:00Z");
  d.setUTCDate(d.getUTCDate() - 1);
  return d.toISOString().slice(0, 10);
}

// Returns a flag object describing the previous calendar day's status, used
// by the BACS forecast to surface compressed-batch-window risk:
//   - bank holiday → 🚨 red alert + holiday name
//   - weekend     → ⚠️ warning
//   - normal day  → null
function previousDayFlag(dateStr) {
  const prev = previousCalendarDay(dateStr);
  if (UK_BANK_HOLIDAYS.has(prev)) {
    const name = (typeof UK_BANK_HOLIDAY_NAMES !== "undefined" && UK_BANK_HOLIDAY_NAMES[prev]) || "bank holiday";
    return { emoji: "🚨", kind: "bank_holiday", prev, label: `Previous day (${dayOfWeekName(prev)} ${fmtDate(prev)}) is a bank holiday — ${name}. Compressed batch window; expect rolled-over volume.` };
  }
  const dow = new Date(prev + "T12:00:00Z").getUTCDay();
  if (dow === 0 || dow === 6) {
    return { emoji: "⚠️", kind: "weekend", prev, label: `Previous day (${dayOfWeekName(prev)} ${fmtDate(prev)}) is a weekend — expect rolled-over volume from non-working days.` };
  }
  return null;
}

async function extractAruddDate(question) {
  const todayStr = new Date().toLocaleDateString("en-CA", { timeZone: "Europe/London" });
  const yesterdayWD = prevWorkingDay(todayStr);
  const twoDaysAgoWD = prevWorkingDay(yesterdayWD);
  const prompt = `Today is ${todayStr}. Extract the charge date (due_date) the user is asking about for an ARUDD report.

IMPORTANT TIMING: The ARUDD report posted on day X covers bounces for the PREVIOUS working day's due_date.
- "Today's ARUDD" or default → due_date = ${yesterdayWD} (previous working day)
- "Yesterday's ARUDD" → the report posted yesterday, which covered due_date = ${twoDaysAgoWD}
- "ARUDD for 30/03" → due_date = 2026-03-30 (the literal date they mention)

Return ONLY a date in YYYY-MM-DD format.
If no specific date is mentioned and nothing implies a different day, return the word "default".
UK bank holidays: Good Friday 2026: 2026-04-03, Easter Monday 2026: 2026-04-06.
Weekends are not working days. "Last Friday" means the most recent Friday.

Question: "${question}"`;
  const result = (await askClaude(prompt)).trim();
  if (result === "default" || !/^\d{4}-\d{2}-\d{2}$/.test(result)) return null;
  return result;
}

// ---------------------------------------------------------------------------
// Missing bounces report — deterministic query, no LLM SQL generation
// ---------------------------------------------------------------------------
const MISSING_BOUNCES_PATTERN = /\b(bounce|bounced|bounces).{0,40}(not posted|missing|not.{0,10}anchor|unposted|no.{0,10}reversal|not.{0,10}reversed)\b/i;

async function buildMissingBouncesReport() {
  const today = new Date().toLocaleDateString("en-CA", { timeZone: "Europe/London" });
  const sql = `
    SELECT
      bacs_date,
      COUNT(*) AS bounce_count_not_posted
    FROM \`raylo-production.landing_billington.bacs_monitoring_agreement_level\`
    WHERE lifecycle_stage = '11_GC_FAILED_NOT_POSTED'
      AND bacs_date <= '${today}'
    GROUP BY bacs_date
    ORDER BY bacs_date DESC`;

  console.log(`[bill-ling] Missing bounces SQL: ${sql}`);
  const rows = await runBigQueryRaw(sql);

  if (!rows || rows.length === 0) {
    return "No bounce transactions missing from Anchor were found (for payment dates up to and including today).\n\nAll GoCardless failures that have reached their payment date have corresponding reversal transactions in Anchor.";
  }

  const total = rows.reduce((sum, r) => sum + (Number(r.bounce_count_not_posted) || 0), 0);
  const lines = [
    `*Bounce transactions not posted in Anchor (payment date ≤ ${fmtDate(today)}):*\n`,
    "```",
    "BACS Date    | Count Not Posted",
    "-------------|------------------",
  ];
  for (const r of rows) {
    const d = formatBQValue(r.bacs_date);
    const c = Number(r.bounce_count_not_posted).toLocaleString("en-GB");
    lines.push(`${d}  | ${c.padStart(16)}`);
  }
  lines.push("```");
  lines.push(`\n*Total: ${total.toLocaleString("en-GB")} bounce transactions* in GoCardless with no corresponding reversal in Anchor.`);

  return lines.join("\n");
}

async function buildMissingBouncesForDate(targetDate) {
  const sql = `
    SELECT agreement_id, bacs_amount, bacs_date, gc_latest_action, gc_event_cause, gc_event_at
    FROM \`raylo-production.landing_billington.bacs_monitoring_agreement_level\`
    WHERE lifecycle_stage = '11_GC_FAILED_NOT_POSTED'
      AND bacs_date = '${targetDate}'
    ORDER BY bacs_amount DESC`;

  console.log(`[bill-ling] Missing bounces drill-down SQL: ${sql}`);
  const rows = await runBigQueryRaw(sql);

  if (!rows || rows.length === 0) {
    return { report: `No missing bounce transactions found for ${fmtDate(targetDate)}.`, agreements: [] };
  }

  const total = rows.reduce((sum, r) => sum + (Number(r.bacs_amount) || 0), 0);
  const lines = [
    `*Missing bounce transactions for ${fmtDate(targetDate)}: ${rows.length} agreement(s), £${total.toLocaleString("en-GB", { minimumFractionDigits: 2 })}*\n`,
    "```",
    "Agreement   | Amount    | GC Action   | GC Cause",
    "------------|-----------|-------------|----------",
  ];
  for (const r of rows.slice(0, 100)) {
    const id = r.agreement_id || "";
    const amt = `£${Number(r.bacs_amount || 0).toFixed(2).padStart(8)}`;
    const action = (r.gc_latest_action || "").padEnd(11);
    const cause = r.gc_event_cause || "";
    lines.push(`${id.padEnd(11)} | ${amt} | ${action} | ${cause}`);
  }
  lines.push("```");
  if (rows.length > 100) lines.push(`... and ${rows.length - 100} more.`);

  return {
    report: lines.join("\n"),
    agreements: rows.map(r => ({ id: (r.agreement_id || "").toUpperCase(), amount: r.bacs_amount, date: formatBQValue(r.bacs_date) })),
  };
}

async function buildAruddReport(targetDueDate = null) {
  const todayStr  = new Date().toLocaleDateString("en-CA", { timeZone: "Europe/London" });
  const dueDate   = targetDueDate || prevWorkingDay(todayStr);
  const aruddDate = nextWorkingDay(dueDate);

  // Run today's data and 30-day averages in parallel
  let rows, avgRows;
  try {
    [rows, avgRows] = await Promise.all([
      runBigQueryRaw(`
        SELECT
          instalment_direct_debits_bounced_count   AS instalment_bounced,
          recollection_direct_debits_bounced_count AS recollection_bounced,
          repair_direct_debits_bounced_count       AS repair_bounced,
          total_failed_go_cardless                 AS gc_failed
        FROM \`raylo-production.landing_billington.bacs_monitoring\`
        WHERE due_date = '${dueDate}'
        LIMIT 1
      `),
      runBigQueryRaw(`
        SELECT
          AVG(instalment_direct_debits_bounced_count + recollection_direct_debits_bounced_count + IFNULL(repair_direct_debits_bounced_count, 0)) AS avg_total_bounced,
          AVG(instalment_direct_debits_bounced_count)   AS avg_instalment_bounced,
          AVG(recollection_direct_debits_bounced_count) AS avg_recollection_bounced,
          AVG(IFNULL(repair_direct_debits_bounced_count, 0)) AS avg_repair_bounced
        FROM \`raylo-production.landing_billington.bacs_monitoring\`
        WHERE due_date >= DATE_SUB('${dueDate}', INTERVAL 30 DAY)
          AND due_date < '${dueDate}'
          AND (instalment_direct_debits_bounced_count + recollection_direct_debits_bounced_count + IFNULL(repair_direct_debits_bounced_count, 0)) > 0
      `),
    ]);
  } catch (err) {
    return { report: `BigQuery error building ARUDD report: ${err.message}`, discrepancyPct: 0, anchorBounces: 0, gcFailed: 0, dueDate, postedPct: 0 };
  }

  const row = rows[0] || {};
  const instalmentBounced   = Number(formatBQValue(row.instalment_bounced))   || 0;
  const recollectionBounced = Number(formatBQValue(row.recollection_bounced)) || 0;
  const repairBounced       = Number(formatBQValue(row.repair_bounced))       || 0;
  const gcFailed            = Number(formatBQValue(row.gc_failed))            || 0;
  const anchorBounces       = instalmentBounced + recollectionBounced + repairBounced;

  if (!rows.length || (anchorBounces === 0 && gcFailed === 0)) {
    return {
      report: `*ARUDD: ${fmtDate(aruddDate)}*\nCharge date: ${fmtDate(dueDate)}\n\nNo ARUDD data available yet.`,
      discrepancyPct: 0, anchorBounces: 0, gcFailed: 0, dueDate, postedPct: 0,
    };
  }

  const avg = avgRows[0] || {};
  const avgTotal       = Number(formatBQValue(avg.avg_total_bounced))       || 0;
  const avgInstalment  = Number(formatBQValue(avg.avg_instalment_bounced))  || 0;
  const avgRecollection= Number(formatBQValue(avg.avg_recollection_bounced))|| 0;
  const avgRepair      = Number(formatBQValue(avg.avg_repair_bounced))      || 0;

  const postedPct       = gcFailed > 0 ? Math.round((anchorBounces / gcFailed) * 100) : 0;
  const collectionPct   = anchorBounces > 0 ? Math.round((instalmentBounced / anchorBounces) * 100) : 0;
  const recollectionPct = anchorBounces > 0 ? Math.round((recollectionBounced / anchorBounces) * 100) : 0;
  const repairPct       = anchorBounces > 0 ? Math.round((repairBounced / anchorBounces) * 100) : 0;
  const discrepancyPct  = gcFailed > 0 ? Math.abs((anchorBounces - gcFailed) / gcFailed) * 100 : 0;

  let report =
    `*ARUDD: ${fmtDate(aruddDate)}*\n` +
    `Charge date: ${fmtDate(dueDate)}\n\n` +
    `Anchor #: ${anchorBounces.toLocaleString("en-GB")}\n` +
    `GoCardless #: ${gcFailed.toLocaleString("en-GB")}\n` +
    `Posted in Anchor: ${postedPct}%\n\n` +
    `Collection #: ${instalmentBounced.toLocaleString("en-GB")} (${collectionPct}%)\n` +
    `Recollection #: ${recollectionBounced.toLocaleString("en-GB")} (${recollectionPct}%)` +
    (repairBounced > 0 ? `\nRepair #: ${repairBounced.toLocaleString("en-GB")} (${repairPct}%)` : ``);

  const flags = [];

  // --- Posted in Anchor status ---
  if (postedPct === 100) {
    flags.push(`✅ No issues with receiving bounce transactions — all GoCardless failures posted in Anchor.`);
  } else if (postedPct >= 95) {
    const diff = Math.abs(anchorBounces - gcFailed);
    const direction = anchorBounces > gcFailed ? "more" : "fewer";
    flags.push(`⚠️ Minor discrepancy — Anchor has ${diff.toLocaleString("en-GB")} ${direction} bounces than GoCardless (${postedPct}% posted). May resolve as data catches up.`);
  } else {
    // < 95% — source table freshness will be checked by the caller
    const diff = Math.abs(anchorBounces - gcFailed);
    const direction = anchorBounces > gcFailed ? "more" : "fewer";
    flags.push(`🚨 Significant discrepancy — only ${postedPct}% of GoCardless failures posted in Anchor. Anchor has ${diff.toLocaleString("en-GB")} ${direction} bounces than GoCardless (${discrepancyPct.toFixed(1)}%). Checking source table freshness...`);
  }

  // --- Volume context vs 30-day average (always shown) ---
  // When the bounce volume comes in dramatically below average (< 30% of
  // the 30-day mean), this is almost always a data-freshness issue rather
  // than a genuinely low bounce day. The 11/05/2026 ARUDD showed 146
  // bounces vs an average of 2,645 (5.5% of average) and Billington
  // initially flagged it as 'low bounce day' rather than 'data may not
  // yet be in'. The threshold below catches the obvious data-incomplete
  // pattern and suggests the source-table freshness check.
  let dataLikelyIncomplete = false;
  if (avgTotal > 0) {
    const totalRatio = anchorBounces / avgTotal;
    const pct = Math.round(Math.abs(totalRatio - 1) * 100);
    let bounceContext;
    if (totalRatio >= 1.5)       bounceContext = `📈 High bounce day — ${pct}% above the 30-day average (avg: #${Math.round(avgTotal).toLocaleString("en-GB")}).`;
    else if (totalRatio >= 1.15) bounceContext = `↑ Bounce volume slightly above average (+${pct}% vs 30-day avg of #${Math.round(avgTotal).toLocaleString("en-GB")}).`;
    else if (totalRatio < 0.3) {
      // Extreme drop — almost always means data is still landing.
      dataLikelyIncomplete = true;
      bounceContext = `⚠️ *Bounce volume well below expected* — #${anchorBounces.toLocaleString("en-GB")} vs 30-day avg of #${Math.round(avgTotal).toLocaleString("en-GB")} (${pct}% below). The ARUDD/source-table data likely hasn't fully loaded yet — re-run in a few hours or check BACS source-table freshness.`;
    }
    else if (totalRatio <= 0.5)  bounceContext = `📉 Low bounce day — ${pct}% below the 30-day average (avg: #${Math.round(avgTotal).toLocaleString("en-GB")}).`;
    else if (totalRatio <= 0.85) bounceContext = `↓ Bounce volume slightly below average (-${pct}% vs 30-day avg of #${Math.round(avgTotal).toLocaleString("en-GB")}).`;
    else                         bounceContext = `Bounce volume is in line with the 30-day average (#${Math.round(avgTotal).toLocaleString("en-GB")}).`;
    flags.push(bounceContext);
  }
  if (avgRecollection > 0) {
    const recolRatio = recollectionBounced / avgRecollection;
    const pct = Math.round(Math.abs(recolRatio - 1) * 100);
    let recolContext;
    if (recolRatio >= 1.5)       recolContext = `📈 High recollection day — ${pct}% above the 30-day average (avg: #${Math.round(avgRecollection).toLocaleString("en-GB")}).`;
    else if (recolRatio >= 1.15) recolContext = `↑ Recollection volume slightly above average (+${pct}% vs 30-day avg of #${Math.round(avgRecollection).toLocaleString("en-GB")}).`;
    else if (recolRatio < 0.3) {
      dataLikelyIncomplete = true;
      recolContext = `⚠️ *Recollection volume well below expected* — #${recollectionBounced.toLocaleString("en-GB")} vs 30-day avg of #${Math.round(avgRecollection).toLocaleString("en-GB")} (${pct}% below). Likely indicates the recollection data hasn't fully loaded yet.`;
    }
    else if (recolRatio <= 0.5)  recolContext = `📉 Low recollection day — ${pct}% below the 30-day average (avg: #${Math.round(avgRecollection).toLocaleString("en-GB")}).`;
    else if (recolRatio <= 0.85) recolContext = `↓ Recollection volume slightly below average (-${pct}% vs 30-day avg of #${Math.round(avgRecollection).toLocaleString("en-GB")}).`;
    else                         recolContext = `Recollection volume is in line with the 30-day average (#${Math.round(avgRecollection).toLocaleString("en-GB")}).`;
    flags.push(recolContext);
  }

  // If volume looks suspiciously low, append a concrete next-step the
  // operator can take rather than leaving them to guess. The
  // 'tell me when bacs_monitoring was last updated' path already exists
  // via the agreement intent handler, so we just direct them there.
  if (dataLikelyIncomplete) {
    flags.push(`_Suggestion: ask me_ \`when was bacs_monitoring last updated?\` _to check the source-table freshness, or wait and re-run this ARUDD shortly._`);
  }

  if (flags.length) report += "\n\n" + flags.join("\n");

  return { report, discrepancyPct, anchorBounces, gcFailed, dueDate, postedPct };
}

// ---------------------------------------------------------------------------
// View source table metadata
// ---------------------------------------------------------------------------

/**
 * Given a view name and dataset, fetches the view definition, extracts all
 * source table references, then looks up each table's last_modified time.
 * Returns a formatted string.
 */
async function getViewSourceMetadata(dataset, viewName) {
  // Step 1: fetch the view SQL definition from INFORMATION_SCHEMA
  const defSQL = `SELECT view_definition FROM \`raylo-production.${dataset}.INFORMATION_SCHEMA.VIEWS\` WHERE table_name = '${viewName}'`;
  const [defRows] = await bigquery.query({ query: defSQL, location: "EU" });
  if (!defRows.length) return `No view named \`${viewName}\` found in \`${dataset}\`.`;
  const viewDef = defRows[0].view_definition;

  // Step 2: ask Claude to extract all table references from the view SQL
  const extractPrompt = `Extract every unique BigQuery table reference from this SQL view definition. Include backtick-quoted references in formats: \`project.dataset.table\`, \`dataset.table\`. Exclude CTEs (WITH clause aliases) — only real table/dataset paths. Return ONLY a JSON array of fully-qualified strings like ["project.dataset.table"], no markdown, no explanation:\n\n${viewDef}`;
  const rawList = await askClaude(extractPrompt);
  let tableRefs = [];
  try {
    tableRefs = JSON.parse(rawList.trim().replace(/^```json?\n?/i, "").replace(/\n?```$/, ""));
  } catch (_) {
    tableRefs = (rawList.match(/`[^`]+\.[^`]+\.[^`]+`/g) || []).map(s => s.replace(/`/g, ""));
  }

  if (!tableRefs || !tableRefs.length) return `Could not extract source tables from \`${viewName}\` definition.`;

  // Step 2b: include key upstream tables that feed into BACS monitoring views
  const EXTRA_UPSTREAM_TABLES = [
    "raylo-production.dbt_production.core_subscriptions",
    "raylo-production.dbt_production.core_payment_profiles",
  ];
  for (const extra of EXTRA_UPSTREAM_TABLES) {
    if (!tableRefs.some(r => r.replace(/`/g, "") === extra)) {
      tableRefs.push(extra);
    }
  }

  // Step 3: for each table ref, query __TABLES__ for last_modified (in parallel)
  const results = await Promise.all(tableRefs.map(async (ref) => {
    const clean = ref.replace(/`/g, "").trim();
    const parts = clean.split(".");
    let proj = "raylo-production", ds, tbl;
    if (parts.length === 3) { [proj, ds, tbl] = parts; }
    else if (parts.length === 2) { [ds, tbl] = parts; }
    else { ds = dataset; tbl = parts[0]; }

    try {
      const metaSQL = `SELECT TIMESTAMP_MILLIS(last_modified_time) as last_modified, row_count, type FROM \`${proj}.${ds}.__TABLES__\` WHERE table_id = '${tbl}'`;
      const [metaRows] = await bigquery.query({ query: metaSQL, location: "EU" });
      if (metaRows.length) {
        const lm = formatBQValue(metaRows[0].last_modified);
        const dt = new Date(lm).toLocaleString("en-GB", { timeZone: "Europe/London", day: "2-digit", month: "2-digit", year: "numeric", hour: "2-digit", minute: "2-digit" });
        return `• \`${proj}.${ds}.${tbl}\` — last modified: ${dt}`;
      } else {
        return `• \`${proj}.${ds}.${tbl}\` — not found in __TABLES__`;
      }
    } catch (e) {
      return `• \`${proj}.${ds}.${tbl}\` — error: ${e.message}`;
    }
  }));

  return `*Source tables for \`${dataset}.${viewName}\`:*\n\n${results.join("\n")}`;
}

// ---------------------------------------------------------------------------
// BACS File Summary — formatted batch report
// ---------------------------------------------------------------------------

/**
 * Query bacs_monitoring rows as raw objects (not formatted text).
 */
async function queryBacsRows(whereClause) {
  const sql = `
    SELECT
      due_date,
      total_instalments_due,
      instalment_direct_debits_called_for_count,
      instalment_direct_debits_called_for_amount,
      percent_of_instalment_due_called_for,
      recollection_direct_debits_called_for_count,
      recollection_direct_debits_called_for_amount,
      repair_direct_debits_called_for_count,
      repair_direct_debits_called_for_amount,
      percent_of_repair_due_called_for,
      collection_batch_created_at,
      recollection_batch_created_at,
      estimated_late_fees_to_apply,
      estimated_direct_debits_bounce,
      time_to_apply_fees
    FROM \`raylo-production.landing_billington.bacs_monitoring\`
    WHERE (collection_batch_created_at IS NOT NULL OR recollection_batch_created_at IS NOT NULL)
      AND ${whereClause}
    ORDER BY due_date ASC
  `;
  const [rows] = await bigquery.query({ query: sql, location: "EU" });
  return rows;
}

/**
 * Volume indicator banner for BACS updates. Takes the projected DD count
 * (forecast: estimated_direct_debits_called_for; batch summary: actual
 * called_for_count + recollections) and returns a colour-coded multi-line
 * block stating expected bounces, LPF count and apply-time band.
 *
 * Bands and ranges per Hargo's May 2026 spec:
 *   < 20k → blue   (current norm,        ~1,600–2,040 LPFs / ~2h 48m – 3h 34m)
 *  20–30k → green  (manageable,           ~2,040–3,060 / ~3h 34m – 5h 21m)
 *  30–45k → orange (concern,              ~3,060–4,590 / ~5h 21m – 8h 02m)
 *   > 45k → red    (exceeds capacity,     ~4,600+      / 8h+)
 *
 * Returns null if ddCount is missing / non-positive so the caller can
 * skip the line cleanly.
 */
/**
 * Traffic-light colour for an estimated fee-apply time, in seconds.
 * Thresholds follow Hargo's 06/05/2026 spec:
 *   - <= 3h 34m         → blue    (well within the current-norm band)
 *   - 3h 34m–5h 21m     → green   (operationally safe but still needs monitoring)
 *   - 5h 21m–8h 02m     → orange  (starting to become a concern)
 *   - > 8h 02m          → red     (exceeds current processing capacity)
 *
 * Returns the matching Slack emoji string or null when the time string
 * is missing/malformed.
 */
function applyTimeIndicator(timeStr) {
  if (!timeStr || typeof timeStr !== "string") return null;
  const m = timeStr.match(/^(\d+):(\d{2})(?::(\d{2}))?$/);
  if (!m) return null;
  const seconds = (parseInt(m[1], 10) || 0) * 3600
                + (parseInt(m[2], 10) || 0) * 60
                + (parseInt(m[3] || "0", 10) || 0);
  if (seconds <= 0) return null;
  if (seconds <= 3 * 3600 + 34 * 60) return ":large_blue_circle:";
  if (seconds <= 5 * 3600 + 21 * 60) return ":large_green_circle:";
  if (seconds <= 8 * 3600 +  2 * 60) return ":large_orange_circle:";
  return ":red_circle:";
}

function bacsVolumeIndicator(ddCount) {
  if (!Number.isFinite(ddCount) || ddCount <= 0) return null;
  const formatted = Math.round(ddCount).toLocaleString("en-GB");
  if (ddCount < 20000) {
    return `:large_blue_circle: *${formatted}* projected DDs (< 20k)\n` +
           `→ Est. bounces: ~1,600–2,040\n` +
           `→ LPFs to apply: ~1,600–2,040\n` +
           `→ Fee apply time: ~2h 48m – 3h 34m (current norm)`;
  } else if (ddCount < 30000) {
    return `:large_green_circle: *${formatted}* projected DDs (20–30k)\n` +
           `→ Est. bounces: ~2,040–3,060\n` +
           `→ LPFs to apply: ~2,040–3,060\n` +
           `→ Fee apply time: ~3h 34m – 5h 21m`;
  } else if (ddCount < 45000) {
    return `:large_orange_circle: *${formatted}* projected DDs (30–45k)\n` +
           `→ Est. bounces: ~3,060–4,590\n` +
           `→ LPFs to apply: ~3,060–4,590\n` +
           `→ Fee apply time: ~5h 21m – 8h 02m — starting to become a concern`;
  }
  return `:red_circle: *${formatted}* projected DDs (> 45k)\n` +
         `→ Est. bounces: ~4,600+\n` +
         `→ LPFs to apply: ~4,600+\n` +
         `→ Fee apply time: 8h+ — exceeds current processing capacity`;
}

/**
 * Format a single bacs_monitoring row into the standard BACS file block.
 */
function formatBacsFileBlock(row) {
  const rawDate = formatBQValue(row.due_date);
  // rawDate is 'YYYY-MM-DD' — convert to DD/MM/YYYY
  const [y, m, d] = rawDate.split("-");
  const displayDate = `${d}/${m}/${y}`;

  const num = (v) => {
    const n = typeof v === "object" && v !== null && "value" in v ? Number(v.value) : Number(v);
    return isNaN(n) ? 0 : n;
  };
  // Amounts are stored in £ (decimal), not pence — no division needed
  const gbp = (v) => `£${num(v).toLocaleString("en-GB", { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
  const pct = (v) => `%${num(v).toFixed(2)}`;
  const cnt = (v) => `#${num(v).toLocaleString("en-GB")}`;

  // Percentages are NULL in the view — calculate from counts
  const instDue = num(row.total_instalments_due);
  const instCalledFor = num(row.instalment_direct_debits_called_for_count);
  const instPct = instDue > 0 ? (instCalledFor / instDue) * 100 : 0;

  const repairCalledFor = num(row.repair_direct_debits_called_for_count);
  // Repair "due" total isn't directly in the data — omit the line if 0 to avoid misleading zeros
  const repairDue = repairCalledFor; // minimum we know is at least the called-for count

  // Format batch created dates (now split into collection and recollection)
  const collBatchDate = formatBQValue(row.collection_batch_created_at);
  const recolBatchDate = formatBQValue(row.recollection_batch_created_at);
  let batchCreated = "";
  if (collBatchDate && collBatchDate !== "null" && recolBatchDate && recolBatchDate !== "null" && collBatchDate !== recolBatchDate) {
    batchCreated = `${fmtDate(collBatchDate)} (collections), ${fmtDate(recolBatchDate)} (re-collections)`;
  } else {
    const d = (collBatchDate && collBatchDate !== "null") ? collBatchDate : recolBatchDate;
    if (d && d !== "null") batchCreated = fmtDate(d);
  }

  const estLateFees = num(row.estimated_late_fees_to_apply);
  const estBounces = num(row.estimated_direct_debits_bounce);

  // Late fees are applied on the next working day after the due date
  const feeApplyDate = fmtDate(nextWorkingDay(rawDate));
  const applyTimeRaw = formatBQValue(row.time_to_apply_fees);
  const applyTime = (applyTimeRaw && applyTimeRaw !== "null" && applyTimeRaw !== "0") ? applyTimeRaw : null;

  // Volume indicator total: instalment DDs + recollection DDs (the
  // operationally relevant volume for bounce / LPF estimation).
  const ddTotal =
    num(row.instalment_direct_debits_called_for_count) +
    num(row.recollection_direct_debits_called_for_count);
  const volumeIndicator = bacsVolumeIndicator(ddTotal);

  return [
    `*BACS file generated for: ${displayDate}*`,
    batchCreated ? `Batch created: ${batchCreated}` : null,
    ``,
    `Instalments due count: ${cnt(row.total_instalments_due)}`,
    `Instalment Direct Debits called for count: ${cnt(row.instalment_direct_debits_called_for_count)}`,
    `Instalment Direct Debits called for cash: ${gbp(row.instalment_direct_debits_called_for_amount)}`,
    `Percent of instalments called for by Direct Debit: ${pct(instPct)}`,
    `Re-collections Direct Debits called for count: ${cnt(row.recollection_direct_debits_called_for_count)}`,
    `Re-collections Direct Debits called for cash: ${gbp(row.recollection_direct_debits_called_for_amount)}`,
    repairCalledFor > 0 ? `` : null,
    repairCalledFor > 0 ? `Repair charge Direct Debits called for count: ${cnt(row.repair_direct_debits_called_for_count)}` : null,
    repairCalledFor > 0 ? `Repair charge Direct Debits called for cash: ${gbp(row.repair_direct_debits_called_for_amount)}` : null,
    ``,
    volumeIndicator,
    applyTime
      ? `${applyTimeIndicator(applyTime) ? applyTimeIndicator(applyTime) + " " : ""}Late fees will be applied: ${feeApplyDate} (est. ${applyTime})`
      : estLateFees > 0 ? `Late fees will be applied: ${feeApplyDate}` : null,
  ].filter(v => v !== null).join("\n");
}

/**
 * Consolidate multiple bacs_monitoring rows for the same due_date into one block.
 * This happens when collections and re-collections batches are created on different dates.
 */
function formatConsolidatedBacsBlock(rows) {
  const num = (v) => {
    const n = typeof v === "object" && v !== null && "value" in v ? Number(v.value) : Number(v);
    return isNaN(n) ? 0 : n;
  };
  const gbp = (v) => `£${num(v).toLocaleString("en-GB", { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
  const cnt = (v) => `#${num(v).toLocaleString("en-GB")}`;
  const pct = (v) => `%${num(v).toFixed(2)}`;

  const rawDate = formatBQValue(rows[0].due_date);
  const [y, m, d] = rawDate.split("-");
  const displayDate = `${d}/${m}/${y}`;

  // Aggregate across all rows
  const totalInstDue = Math.max(...rows.map(r => num(r.total_instalments_due)));
  const instCount = rows.reduce((s, r) => s + num(r.instalment_direct_debits_called_for_count), 0);
  const instAmount = rows.reduce((s, r) => s + num(r.instalment_direct_debits_called_for_amount), 0);
  const recolCount = rows.reduce((s, r) => s + num(r.recollection_direct_debits_called_for_count), 0);
  const recolAmount = rows.reduce((s, r) => s + num(r.recollection_direct_debits_called_for_amount), 0);
  const repairCount = rows.reduce((s, r) => s + num(r.repair_direct_debits_called_for_count), 0);
  const repairAmount = rows.reduce((s, r) => s + num(r.repair_direct_debits_called_for_amount), 0);
  const instPct = totalInstDue > 0 ? (instCount / totalInstDue) * 100 : 0;

  const estLateFees = Math.max(...rows.map(r => num(r.estimated_late_fees_to_apply)));
  const estBounces = Math.max(...rows.map(r => num(r.estimated_direct_debits_bounce)));

  const feeApplyDate = fmtDate(nextWorkingDay(rawDate));
  const applyTimeRaw = rows.map(r => formatBQValue(r.time_to_apply_fees)).find(t => t && t !== "null" && t !== "0") || null;

  // Identify which batch had collections vs re-collections for the batch-created label
  const collectionBatch = rows.find(r => num(r.instalment_direct_debits_called_for_count) > 0);
  const recollectionBatch = rows.find(r => num(r.recollection_direct_debits_called_for_count) > 0);

  const collBatchRaw = collectionBatch ? formatBQValue(collectionBatch.collection_batch_created_at) : null;
  const recolBatchRaw = recollectionBatch ? formatBQValue(recollectionBatch.recollection_batch_created_at) : null;
  const collectionDate = collBatchRaw && collBatchRaw !== "null" ? new Date(collBatchRaw).toLocaleDateString("en-GB", { timeZone: "Europe/London" }) : null;
  const recollectionDate = recolBatchRaw && recolBatchRaw !== "null" ? new Date(recolBatchRaw).toLocaleDateString("en-GB", { timeZone: "Europe/London" }) : null;

  let batchLine;
  if (collectionDate && recollectionDate && collectionDate !== recollectionDate) {
    batchLine = `Batch created: ${collectionDate} (collections), ${recollectionDate} (re-collections)`;
  } else {
    batchLine = `Batch created: ${batchDates.join(", ")}`;
  }

  const ddTotal = instCount + recolCount;
  const volumeIndicator = bacsVolumeIndicator(ddTotal);

  return [
    `*BACS file generated for: ${displayDate}*`,
    batchLine,
    ``,
    `Instalments due count: ${cnt(totalInstDue)}`,
    `Instalment Direct Debits called for count: ${cnt(instCount)}`,
    `Instalment Direct Debits called for cash: ${gbp(instAmount)}`,
    `Percent of instalments called for by Direct Debit: ${pct(instPct)}`,
    `Re-collections Direct Debits called for count: ${cnt(recolCount)}`,
    `Re-collections Direct Debits called for cash: ${gbp(recolAmount)}`,
    repairCount > 0 ? `` : null,
    repairCount > 0 ? `Repair charge Direct Debits called for count: ${cnt(repairCount)}` : null,
    repairCount > 0 ? `Repair charge Direct Debits called for cash: ${gbp(repairAmount)}` : null,
    ``,
    volumeIndicator,
    applyTimeRaw
      ? `${applyTimeIndicator(applyTimeRaw) ? applyTimeIndicator(applyTimeRaw) + " " : ""}Late fees will be applied: ${feeApplyDate} (est. ${applyTimeRaw})`
      : estLateFees > 0 ? `Late fees will be applied: ${feeApplyDate}` : null,
  ].filter(v => v !== null).join("\n");
}

/**
 * Pre-resolve any "working day before/after X" expressions in a question to a concrete date,
 * so Claude doesn't have to do working-day arithmetic across bank holidays.
 * Returns the question with the expression replaced by "YYYY-MM-DD".
 */
async function resolveWorkingDayExpressions(question, today) {
  // Ask Claude to extract any date anchor and working-day direction from the question.
  // Returns JSON: { resolved: "YYYY-MM-DD" | null, direction: "prev" | "next" | null }
  const extractPrompt = `Today is ${today}.
Extract the anchor date and working-day direction from this question, if any.
Question: "${question}"

Rules:
- "working day before X", "previous working day of X", "day before X" → direction: "prev", resolved: X as YYYY-MM-DD
- "working day after X", "next working day after X", "day after X" → direction: "next", resolved: X as YYYY-MM-DD
- If no working-day expression exists, return null for both.
- Always resolve month names to YYYY-MM-DD using year ${today.slice(0, 4)} unless stated otherwise.

Reply ONLY with valid JSON, no explanation. Example: {"direction":"prev","resolved":"2026-04-07"}`;

  try {
    const raw = await askClaude(extractPrompt);
    const json = JSON.parse(raw.replace(/```json|```/g, "").trim());
    if (json.resolved && json.direction === "prev") {
      const computed = prevWorkingDay(json.resolved);
      return question.replace(/working\s+day\s+before\s+[\d\/\w\s]+/i, computed)
                     .replace(/previous\s+working\s+day\s+of\s+[\d\/\w\s]+/i, computed)
                     .replace(/day\s+before\s+[\d\/\w\s]+/i, computed)
                     + ` (${computed})`;
    }
    if (json.resolved && json.direction === "next") {
      const computed = nextWorkingDay(json.resolved);
      return question + ` (${computed})`;
    }
  } catch (e) {
    // Extraction failed — pass question through unchanged
  }
  return question;
}

/**
 * Use Claude to turn a question into a BigQuery WHERE clause modifier for the BACS file report.
 */
async function buildBacsFileWhere(question, today) {
  // Pre-resolve any working day expressions so Claude gets a concrete YYYY-MM-DD date
  const resolvedQuestion = await resolveWorkingDayExpressions(question, today);

  const bhList = [...UK_BANK_HOLIDAYS].sort().map(d => `  ${d}`).join("\n");
  const prompt = `Today is ${today}. Question: "${resolvedQuestion}"

The bacs_monitoring table has two types of rows:
1. Rows WHERE (collection_batch_created_at IS NOT NULL OR recollection_batch_created_at IS NOT NULL) — the batch file has already been generated.
2. Rows WHERE collection_batch_created_at IS NULL AND recollection_batch_created_at IS NULL — no batch yet, just instalment forecast data.

Batch columns: collection_batch_created_at (DATE) and recollection_batch_created_at (DATE).

IMPORTANT: If the question asks about the NEXT batch TO BE generated (e.g. "next generation date", "next batch to generate", "when will the next file be created", "not yet generated"), reply with exactly:
  FORECAST:due_date > '${today}'
This routes to the forecast path which shows ungenerated future batches.

LATE FEES TIMING: Late payment fees are applied on the NEXT working day after the due date. So "late fees today" or "late fees being applied today" = late fees for the PREVIOUS working day's due_date (${prevWorkingDay(today)}). "Late fees tomorrow" = late fees for today's due_date (${today}).

Otherwise return ONLY a BigQuery SQL WHERE sub-clause (no WHERE keyword, no semicolon). Examples:
- "future dates" → due_date > CURRENT_DATE()
- "today" or "generated today" → collection_batch_created_at = CURRENT_DATE() OR recollection_batch_created_at = CURRENT_DATE()
- "this week" → collection_batch_created_at >= DATE_TRUNC(CURRENT_DATE(), WEEK) OR recollection_batch_created_at >= DATE_TRUNC(CURRENT_DATE(), WEEK)
- "27 March" or "2026-03-27" → due_date = '2026-03-27'
- "after Easter" → due_date > '2026-04-06'
- "all" or unspecific → due_date > DATE_SUB(CURRENT_DATE(), INTERVAL 30 DAY)
- "late fees today" or "late fees applied today" → due_date = '${prevWorkingDay(today)}'
- If the question contains a YYYY-MM-DD date in parentheses, use that exact date.

UK bank holidays (non-working days):
${bhList}

Reply with ONLY the WHERE sub-clause string or the FORECAST: prefix, nothing else.`;
  const clause = await askClaude(prompt);
  // Strip any ORDER BY / LIMIT that Claude may have appended — queryBacsRows handles ordering
  let result = clause.trim()
    .replace(/;$/, "")
    .replace(/\s+(ORDER\s+BY|LIMIT)\s+.*/i, "")
    .trim();
  // Safety net: LLM may still hallucinate the old column name
  if (/\bbatch_created_at\b/.test(result) && !/collection_batch_created_at|recollection_batch_created_at/.test(result)) {
    console.log(`[bill-ling] buildBacsFileWhere: fixing hallucinated batch_created_at in: ${result}`);
    result = result.replace(/\bDATE\(batch_created_at\)/g, "(collection_batch_created_at")
      .replace(/\bbatch_created_at\s+IS\s+NOT\s+NULL/gi, "(collection_batch_created_at IS NOT NULL OR recollection_batch_created_at IS NOT NULL)")
      .replace(/\bbatch_created_at\s+IS\s+NULL/gi, "(collection_batch_created_at IS NULL AND recollection_batch_created_at IS NULL)")
      .replace(/\bbatch_created_at\b/g, "collection_batch_created_at");
  }
  console.log(`[bill-ling] buildBacsFileWhere resolved: "${resolvedQuestion}" → ${result}`);
  return result;
}

/**
 * Pull rows and return formatted report blocks. Returns null if no data.
 */
async function getBacsFileReport(whereClause) {
  const rows = await queryBacsRows(whereClause);
  if (!rows.length) return null;

  // Group rows by due_date — same due_date can have separate collection & recollection batches
  const groups = new Map();
  for (const row of rows) {
    const key = formatBQValue(row.due_date);
    if (!groups.has(key)) groups.set(key, []);
    groups.get(key).push(row);
  }

  const blocks = [];
  for (const [dueDate, groupRows] of groups) {
    if (groupRows.length === 1) {
      blocks.push(formatBacsFileBlock(groupRows[0]));
    } else {
      blocks.push(formatConsolidatedBacsBlock(groupRows));
    }
  }
  return blocks.join("\n\n---\n\n");
}

/**
 * Read #customer-refunds-and-complaints for the last 30 days, fetch thread replies
 * for any message that has them, and use Claude to identify refund requests that
 * are still pending approval or have not been confirmed as processed.
 */

/**
 * Analyse the transcript to infer who most commonly performs each refund stage.
 * Returns { approval, processing, batch_file, barclays_confirmation } — each an array
 * of { name, id, count } sorted by count desc. Falls back to REFUND_CONTACTS if inference fails.
 */
async function inferRefundContacts(transcript) {
  const prompt = `Analyse this Slack transcript from #customer-refunds-and-complaints.
Count how many times each person performs each of these actions:

APPROVAL: giving explicit approval for a refund ("approved", "happy to approve", "yes go ahead", "please process", "go ahead", or directing someone to process)
PROCESSING: confirming an individual refund is done ("processed", "done", "sent", "refunded", "actioned", "completed", "paid") — in a thread reply to a refund request, NOT a batch file message
BATCH_FILE: posting a channel-level message announcing a refund file has been generated and uploaded to Google Drive for Barclays
BARCLAYS_CONFIRMATION: confirming a batch file has been paid/authorised on Barclays ("paid", "authorised", "confirmed", "uploaded")

User IDs appear in parentheses after names in the transcript, e.g. "Laura Sierociuk (<@U123ABC>)".

Return ONLY a JSON object in this exact format (no other text):
{
  "approval": [{"name": "...", "id": "U...", "count": N}],
  "processing": [{"name": "...", "id": "U...", "count": N}],
  "batch_file": [{"name": "...", "id": "U...", "count": N}],
  "barclays_confirmation": [{"name": "...", "id": "U...", "count": N}]
}
Sort each array by count descending. Only include people with count >= 1.

--- TRANSCRIPT ---
${transcript}
--- END ---`;

  try {
    const raw = await askClaude(prompt);
    const match = raw.match(/\{[\s\S]*\}/);
    if (!match) return null;
    return JSON.parse(match[0]);
  } catch (e) {
    console.error("[bill-ling] inferRefundContacts error:", e.message);
    return null;
  }
}

// Count working days between two ISO date strings (exclusive of start, inclusive of end)
function workingDaysBetween(fromIso, toIso) {
  if (!fromIso || fromIso >= toIso) return 0;
  let count = 0;
  let d = new Date(fromIso + "T12:00:00Z");
  const end = new Date(toIso + "T12:00:00Z");
  while (d < end) {
    d.setUTCDate(d.getUTCDate() + 1);
    const ds = d.toISOString().slice(0, 10);
    if (isWorkingDay(ds)) count++;
  }
  return count;
}

/**
 * Add ✅ reaction to the parent message of each resolved refund thread.
 * Silently ignores "already_reacted" errors (idempotent).
 */
async function markResolvedThreads(resolved) {
  for (const item of resolved) {
    if (!item.thread_ts) continue;
    try {
      await app.client.reactions.add({
        token: SLACK_BOT_TOKEN,
        channel: CHANNELS.CUSTOMER_REFUNDS,
        timestamp: item.thread_ts,
        name: "white_check_mark",
      });
      console.log(`[bill-ling] ✅ reaction added to thread ${item.thread_ts}`);
    } catch (err) {
      if (err.data?.error !== "already_reacted") {
        console.error(`[bill-ling] Failed to add reaction to ${item.thread_ts}:`, err.message);
      }
    }
  }
}

// Dedup: track which threads have been chased today to prevent duplicate messages
const chasedThreadsToday = new Set();
// Threads where Billington has already posted an "on hold pending arrears" note,
// so it surfaces the hold once rather than chasing daily. (Hargo, 29/06/2026.)
const arrearsHoldNotified = new Set();

// Action IDs for the interactive refund buttons. Used to dedup (one button-set
// per thread) so the daily chase keeps going as text without stacking buttons.
const REFUND_CHASE_BUTTON_IDS = ["btn_confirm_batch_paid", "btn_refund_approve", "btn_refund_decline", "btn_refund_manual", "btn_post_gogw_refund"];

/**
 * Build the action-button block for a refund chase, by bucket (Hargo,
 * 25/06/2026). The approval PROCESS is unchanged — when Billington asks a
 * question in the refund channel it now offers a button, and a click routes
 * through the SAME gated handler as typing the answer would.
 *   • awaiting_approval   → ✅ Approve for processing / ❌ Decline
 *   • awaiting_processing → 💸 Post GOGW + refund (if a figure is locked) +
 *                           ✋ Mark refunded manually
 *   • batch_files         → ✅ Confirm uploaded & processed
 */
function buildRefundChaseBlocks(item, chaseMsg, lock) {
  const v = (extra = {}) => JSON.stringify({ t: item.thread_ts, c: CHANNELS.CUSTOMER_REFUNDS, ref: item.ref || null, ...extra });
  const section = { type: "section", text: { type: "mrkdwn", text: (chaseMsg || "").slice(0, 3000) } };
  if (item._bucket === "batch_files") {
    return [section, { type: "actions", elements: [{
      type: "button", text: { type: "plain_text", text: "✅ Confirm uploaded & processed", emoji: true }, style: "primary",
      action_id: "btn_confirm_batch_paid", value: v(),
      confirm: { title: { type: "plain_text", text: "Confirm this refund file?" }, text: { type: "mrkdwn", text: "Marks this Barclays refund file as uploaded & processed and stops the daily chase." }, confirm: { type: "plain_text", text: "Confirm" }, deny: { type: "plain_text", text: "Cancel" } },
    }]}];
  }
  if (item._bucket === "awaiting_approval") {
    return [section, { type: "actions", elements: [
      { type: "button", text: { type: "plain_text", text: "✅ Approve for processing", emoji: true }, style: "primary", action_id: "btn_refund_approve", value: v(),
        confirm: { title: { type: "plain_text", text: "Approve this refund?" }, text: { type: "mrkdwn", text: "Records your approval and moves it to processing. The actual posting stays gated — Billington auto-post is Hargo/Charlotte/Ciaran; a manual refund is Charlotte/Ciaran." }, confirm: { type: "plain_text", text: "Approve" }, deny: { type: "plain_text", text: "Cancel" } } },
      { type: "button", text: { type: "plain_text", text: "❌ Decline", emoji: true }, style: "danger", action_id: "btn_refund_decline", value: v() },
    ]}];
  }
  if (item._bucket === "awaiting_processing") {
    const elements = [];
    if (lock && lock.cmd) {
      elements.push({ type: "button", text: { type: "plain_text", text: "💸 Post GOGW + refund", emoji: true }, style: "primary", action_id: "btn_post_gogw_refund", value: v(),
        confirm: { title: { type: "plain_text", text: "Post GOGW + refund?" }, text: { type: "mrkdwn", text: `I'll run my usual checks then post:\n\`${lock.cmd}\`` }, confirm: { type: "plain_text", text: "Post it" }, deny: { type: "plain_text", text: "Cancel" } } });
    }
    elements.push({ type: "button", text: { type: "plain_text", text: "✋ Mark refunded manually", emoji: true }, action_id: "btn_refund_manual", value: v(),
      confirm: { title: { type: "plain_text", text: "Mark refunded manually?" }, text: { type: "mrkdwn", text: "Records that this refund was actioned by hand and stops the chase. Charlotte/Ciaran/Hargo only." }, confirm: { type: "plain_text", text: "Mark done" }, deny: { type: "plain_text", text: "Cancel" } } });
    return [section, { type: "actions", elements }];
  }
  return undefined;
}

/**
 * Post chaser replies into individual refund threads for items older than 0 working days.
 * data = structured JSON returned by getRefundsSummary.
 */
async function postRefundChasers(data) {
  if (!data) return;
  const today = new Date().toLocaleDateString("en-CA", { timeZone: "Europe/London" });

  // Customer action items: only chase if > 7 working days (give customer time to respond)
  // Internal Raylo items: chase every time (approval, processing, batch files)
  const customerItems  = (data.awaiting_customer_action || []).map(i => ({ ...i, minDays: 7 }));
  const internalItems  = [
    ...(data.awaiting_approval   || []).map(i => ({ ...i, _bucket: "awaiting_approval" })),
    ...(data.awaiting_processing || []).map(i => ({ ...i, _bucket: "awaiting_processing" })),
    ...(data.batch_files         || []).map(i => ({ ...i, _bucket: "batch_files" })),
  ].map(i => ({ ...i, minDays: 1 }));

  for (const item of [...customerItems, ...internalItems]) {
    const days = workingDaysBetween(item.date_iso, today);
    if (days < item.minDays) {
      console.log(`[bill-ling] Skipping chaser for ${item.ref || item.date} — ${days} working day(s) (min ${item.minDays})`);
      continue;
    }
    if (!item.thread_ts || !item.chase_message) continue;

    // Skip chasing if Billington already posted an approval notification today
    const notifiedDate = approvalNotifiedThreads.get(item.thread_ts);
    if (notifiedDate === today) {
      console.log(`[bill-ling] Skipping chaser for ${item.ref || item.date} — approval notification already posted today`);
      continue;
    }

    // Defer to the button flow (Hargo, 07/07/2026): if a Post GOGW + refund
    // button is up in the thread, don't chase — the button (gated to the
    // authorisers) is the action path and the approval is already in place.
    try {
      const tr = await app.client.conversations.replies({ token: SLACK_BOT_TOKEN, channel: CHANNELS.CUSTOMER_REFUNDS, ts: item.thread_ts, limit: 50 });
      const btnUp = (tr.messages || []).some(r => (r.user === BOT_USER_ID || r.bot_id) && /GOGW\s*£[\d.,]+\s*\+\s*refund/i.test(getMessageText(r)));
      if (btnUp) {
        console.log(`[bill-ling] Skipping chaser for ${item.ref || item.date} — Post GOGW + refund button is up (button flow owns it).`);
        continue;
      }
    } catch (_) { /* best effort — fall through to normal chase */ }

    // For awaiting_processing items with an agreement ID, check Anchor first.
    // If the refund (TypeId 149) has already been posted, confirm instead of chasing.
    if (item.ref && /^A\d{5,8}$/i.test(item.ref) && item._bucket === "awaiting_processing") {
      const afterDate = item.date_iso || today;
      const result = await checkAnchorForRefund(item.ref, afterDate);
      if (result.posted) {
        try {
          await app.client.chat.postMessage({
            token: SLACK_BOT_TOKEN,
            channel: CHANNELS.CUSTOMER_REFUNDS,
            thread_ts: item.thread_ts,
            text: `I've checked Anchor and the refund for ${item.ref} has been posted (${result.detail}). ✅ Marking as complete.`,
            mrkdwn: true,
          });
          await app.client.reactions.add({
            token: SLACK_BOT_TOKEN,
            channel: CHANNELS.CUSTOMER_REFUNDS,
            timestamp: item.thread_ts,
            name: "white_check_mark",
          }).catch(e => { if (!e.message?.includes("already_reacted")) console.error(e.message); });
          console.log(`[bill-ling] Refund confirmed via Anchor for ${item.ref} (${result.detail}) — skipping chaser`);
        } catch (err) {
          console.error(`[bill-ling] Failed to post Anchor confirmation for ${item.ref}:`, err.message);
        }
        continue; // skip the normal chaser
      }
    }

    // Arrears hold: an approved refund whose agreement is in arrears can't be
    // posted until the arrears clear (or the team decides to post-to-offset), so
    // don't chase it as "approved, please action / hasn't been actioned" — that's
    // the false-chase Hargo flagged on A00351578 (29/06/2026, held for £65.19
    // arrears per Laura). Surface the hold once, then stay quiet until it clears.
    if (item.ref && /^A\d{5,9}$/i.test(item.ref) && item._bucket === "awaiting_processing") {
      try {
        const axml = await getAgreementFromAnchor(item.ref);
        const arrM = axml.match(/<(?:a:)?TotalArrears>([^<]+)<\/(?:a:)?TotalArrears>/);
        const arrears = arrM ? parseFloat(arrM[1]) : 0;
        if (arrears > 0.005) {
          if (!arrearsHoldNotified.has(item.thread_ts)) {
            arrearsHoldNotified.add(item.thread_ts);
            try {
              await app.client.chat.postMessage({
                token: SLACK_BOT_TOKEN,
                channel: CHANNELS.CUSTOMER_REFUNDS,
                thread_ts: item.thread_ts,
                text: `⏸️ *${item.ref}* — on hold pending arrears of *£${arrears.toFixed(2)}*. The approved GOGW + refund can't post until the arrears clear, or ${BILLINGTON_REFUND_AUTHORISER_NAMES} choose to post-to-offset. I'll stop chasing this as outstanding and resume once the arrears are cleared.`,
                mrkdwn: true, unfurl_links: false, unfurl_media: false,
              });
            } catch (e) { console.error(`[bill-ling] arrears-hold note failed for ${item.ref}:`, e.message); }
          }
          console.log(`[bill-ling] Refund ${item.ref} on hold pending arrears £${arrears.toFixed(2)} — suppressing "please action" chase.`);
          continue; // skip the normal chase while on arrears hold
        } else {
          // Arrears cleared — drop any prior hold note so future chases resume.
          arrearsHoldNotified.delete(item.thread_ts);
        }
      } catch (e) {
        console.error(`[bill-ling] arrears check failed for ${item.ref} in refund chase:`, e.message);
        // fall through to the normal chase on a lookup error
      }
    }

    // Dedup: only one chase per thread per day
    const chaseKey = `${item.thread_ts}:${today}`;
    if (chasedThreadsToday.has(chaseKey)) {
      console.log(`[bill-ling] Skipping duplicate chaser for ${item.ref || item.date} — already chased today`);
      continue;
    }

    try {
      let chaseMsg = item.chase_message;
      let processingLock = null; // set when an awaiting_processing chase locks a figure (drives the Post button)
      const chain = item._bucket === "batch_files" ? getBatchFileChaseChain()
        : item._bucket === "awaiting_processing" ? REFUND_CHASE_CHAINS.PROCESSING
        : item._bucket === "awaiting_approval" ? REFUND_CHASE_CHAINS.APPROVAL
        : null;
      if (chain) {
        let target;
        if (item._bucket === "batch_files") {
          // Day-based escalation for batch files: day 1 → Caitlyn, day 2 → Aoibheann, day 3 → Darragh, day 4+ → Peter
          const chainIdx = Math.min(days - 1, chain.length - 1);
          target = chain[chainIdx];
          console.log(`[bill-ling] Batch file chase day ${days}: ${target.name} for ${item.ref || item.date}`);
        } else if (item._bucket === "awaiting_processing") {
          // Day-based escalation for processing: Charlotte in billing actions
          // every approved refund. If 2 working days pass without action,
          // ping Hargo directly. Skip OOO-fallback — Charlotte not being
          // available doesn't mean Darragh in finance should be chased
          // (finance isn't in this loop at all).
          const chainIdx = Math.min(days - 1, chain.length - 1);
          target = chain[chainIdx];
          console.log(`[bill-ling] Processing chase day ${days}: ${target.name} for ${item.ref || item.date}`);
        } else if (item._bucket === "awaiting_approval") {
          // Approval routing (Hargo, 08/06/2026):
          //   1. Refund ≤ £LEAD_APPROVAL_LIMIT_GBP → chase the lead (Laura),
          //      OOO-fallback to Hargo.
          //   2. Above the limit (or amount unreadable) → senior approval chain
          //      (Stephen Riley, then Hargo).
          //   3. Adam Lusk is NEVER chased for refund approvals (Hargo, 08/06/2026):
          //      he is not in either chain and is not an OOO fallback. Do NOT re-add
          //      an Adam carve-out here, even when a thread @mentions him.
          const amt = parseApprovalAmountGBP(item);
          const withinLeadLimit = amt != null && amt <= LEAD_APPROVAL_LIMIT_GBP;
          const approvalChain = withinLeadLimit
            ? REFUND_CHASE_CHAINS.APPROVAL_LEAD
            : REFUND_CHASE_CHAINS.APPROVAL;
          target = await getAvailableChaseTarget(approvalChain);
          chaseMsg = setChaseMention(chaseMsg, target.id);
          console.log(`[bill-ling] Approval chase for ${item.ref || item.thread_ts}: amount=${amt == null ? "unknown" : "£" + amt}, target=${target.name}${withinLeadLimit ? " (within lead limit)" : ""}`);
        } else {
          // OOO-aware fallback for any other chain types
          target = await getAvailableChaseTarget(chain);
        }
        // Replace any @-mention of the primary contact with the escalation
        // target. Skipped for awaiting_approval, whose mention is set above.
        const primaryId = chain[0].id;
        if (item._bucket !== "awaiting_approval" && chaseMsg.includes(`<@${primaryId}>`) && target.id !== primaryId) {
          chaseMsg = chaseMsg.replace(`<@${primaryId}>`, `<@${target.id}>`);
        }
        // For awaiting_processing items past the 2-working-day mark, we're
        // now pinging Hargo himself — so strip the LLM's day-1 tail
        // ('If not actioned within 2 working days I'll escalate to Hargo')
        // and replace it with a 2-days-overdue framing.
        if (item._bucket === "awaiting_processing" &&
            target.id === REFUND_CONTACTS.PROCESSING_ESCALATION.id) {
          chaseMsg = chaseMsg.replace(
            /\.?\s*If not actioned within 2 working days I'?ll escalate to Hargo\.?/i,
            ""
          ).trimEnd();
          chaseMsg += ` _Escalating to you and <@${CIARAN_DOBBIN_USER_ID}> because this approved refund hasn't been actioned in 2 working days — please action or chase Charlotte directly._`;
        }
      }
      // Hargo, 09/06/2026: for an approved refund awaiting processing, STATE
      // the exact figure in the chase — agreement, GOGW amount, refund amount,
      // type — so the approver sees what they're authorising, and so "approved
      // @billington" has a displayed `post gogw and refund …` command to read
      // back. Derived from the thread incl. Denton's trade-in confirmation.
      if (item._bucket === "awaiting_processing" && item.thread_ts && !/I read this as:|Here's exactly what I'd post/i.test(chaseMsg)) {
        try {
          const tr = await app.client.conversations.replies({
            token: SLACK_BOT_TOKEN, channel: CHANNELS.CUSTOMER_REFUNDS, ts: item.thread_ts, limit: 50,
          });
          const tmsgs = tr.messages || [];
          const inferenceText = [
            tmsgs[0] ? getMessageText(tmsgs[0]) : "",
            ...tmsgs.slice(1)
              .filter(m => m.user !== BOT_USER_ID && !/good to go for processing|I read this as:/i.test(getMessageText(m)))
              .map(m => getMessageText(m)),
          ].join("\n");
          const agId = (item.ref && /^A\d{5,9}$/i.test(item.ref))
            ? item.ref.toUpperCase()
            : ((inferenceText.match(/\bA\d{5}(?:\d{3})?\b/i) || [])[0] || "").toUpperCase();
          if (agId) {
            const lock = computeRefundLock(agId, inferenceText);
            if (lock && lock.cmd) {
              processingLock = lock;
              chaseMsg += `\nHere's exactly what I'd post: GOGW *£${lock.amount.toFixed(2)}* + refund *£${lock.amount.toFixed(2)}* on *${agId}*, type *${lock.category}*.\n\`${lock.cmd}\``;
            }
          }
        } catch (e) {
          console.error(`[bill-ling] chase lock-display error for ${item.ref || item.thread_ts}:`, e.message);
        }
      }
      // Attach action buttons to the chase by bucket (Hargo, 25/06/2026): refund
      // questions get buttons; clicks route through the same gated handlers as the
      // typed replies. ONE button-set per thread — scan the thread and skip if any
      // refund button is already present, so the daily chase keeps going as text
      // without stacking buttons (and so a later stage's buttons aren't duplicated).
      let chaseBlocks;
      if (INTERACTIVE_BUTTONS_ENABLED && item.thread_ts &&
          ["batch_files", "awaiting_approval", "awaiting_processing"].includes(item._bucket)) {
        let buttonAlreadyInThread = false;
        try {
          const tr = await app.client.conversations.replies({
            token: SLACK_BOT_TOKEN, channel: CHANNELS.CUSTOMER_REFUNDS, ts: item.thread_ts, limit: 100,
          });
          buttonAlreadyInThread = (tr.messages || []).some(m =>
            (m.blocks || []).some(b => b.type === "actions" && (b.elements || []).some(e => REFUND_CHASE_BUTTON_IDS.includes(e.action_id)))
          );
        } catch (e) {
          console.error(`[bill-ling] refund button thread-scan failed for ${item.thread_ts}:`, e.message);
          buttonAlreadyInThread = true; // on error, don't risk a duplicate button
        }
        if (!buttonAlreadyInThread) {
          chaseBlocks = buildRefundChaseBlocks(item, chaseMsg, processingLock);
        }
      }
      await app.client.chat.postMessage({
        token: SLACK_BOT_TOKEN,
        channel: CHANNELS.CUSTOMER_REFUNDS,
        thread_ts: item.thread_ts,
        text: chaseMsg,
        ...(chaseBlocks ? { blocks: chaseBlocks } : {}),
        mrkdwn: true,
      });
      chasedThreadsToday.add(chaseKey);
      console.log(`[bill-ling] Chaser posted in thread ${item.thread_ts} for ${item.ref || item.date} (${days} working days)${chaseBlocks ? " [with confirm button]" : ""}`);
    } catch (err) {
      console.error(`[bill-ling] Failed to chase thread ${item.thread_ts}:`, err.message);
    }
  }
}

// ---------------------------------------------------------------------------
// Check Anchor API for a refund transaction (TypeId 149) on a given agreement
// Returns { posted: true, detail: "£X.XX posted on YYYY-MM-DD" } or { posted: false }
// ---------------------------------------------------------------------------
async function checkAnchorForRefund(agreementId, afterDate) {
  try {
    console.log(`[bill-ling] Checking Anchor for refund on ${agreementId} (after: ${afterDate})`);
    const xml = await getAgreementFromAnchor(agreementId);
    // Match Transaction blocks with or without namespace prefix (a: or none)
    const txnBlocks = xml.match(/<(?:a:)?Transaction>([\s\S]*?)<\/(?:a:)?Transaction>/g) || [];

    for (const block of txnBlocks) {
      const typeMatch = block.match(/<(?:a:)?TypeId>(\d+)<\/(?:a:)?TypeId>/);
      if (!typeMatch || parseInt(typeMatch[1], 10) !== 149) continue; // TypeId 149 = refund

      // Match Gross (non-namespaced) or Amount (namespaced)
      const amountMatch = block.match(/<(?:a:)?(?:Amount|Gross)>([\d.-]+)<\/(?:a:)?(?:Amount|Gross)>/);
      const dateMatch = block.match(/<(?:a:)?TransactionDate>([\d-T:.]+)<\/(?:a:)?TransactionDate>/);
      if (!amountMatch || !dateMatch) continue;

      const txnAmount = Math.abs(parseFloat(amountMatch[1]));
      const txnDate = dateMatch[1].slice(0, 10);

      // Transaction must be on or after the request date
      if (txnDate < afterDate) continue;

      return { posted: true, detail: `£${txnAmount.toFixed(2)} refunded on ${txnDate}` };
    }
    return { posted: false };
  } catch (err) {
    console.error(`[bill-ling] Anchor refund check failed for ${agreementId}:`, err.message);
    return { posted: false };
  }
}

// ---------------------------------------------------------------------------
// Hourly approval monitor — checks if Stephen Riley has approved a refund/GOGW
// ---------------------------------------------------------------------------
function textContainsAny(text, keywords) {
  const lower = (text || "").toLowerCase();
  return keywords.some(kw => lower.includes(kw));
}

// Approver name lookup for notification messages
const APPROVER_NAMES = {
  "U0972QQNKH7": "Stephen Riley",
  "U01DMHVF8KG": "Hargo",
  "UJH96RKNK":   "Adam Lusk",
  "U09D1UMM8GY": "Ronan",
  "U031G7PQVM0": "Michael Bland",
  "U02NRTVLPC5": "Daniel Murphy",
};

// Use LLM to classify whether a reply from an approver is giving the green light
// Returns: { type: "APPROVED" | "CONDITIONAL" | "NO", condition?: string }
async function classifyApproval(parentText, replyText, replyAuthor) {
  const prompt = `You are classifying a message in a refund/complaints Slack channel.

The original request:
"${(parentText || "").slice(0, 500)}"

A reply from ${replyAuthor}:
"${(replyText || "").slice(0, 500)}"

Classify this reply as one of:
APPROVED — unconditional approval to process the refund/payment/GOGW right now.
CONDITIONAL — approval is given BUT with a condition that must be met first.
NO — not an approval at all (a question, request for info, general comment, etc.).

APPROVED examples: "approved", "go ahead", "yes process it", "happy with that", "we should go ahead with the payments", "Approved @Julia", "A00343917 - Happy to approve for this one" (even if the same message raises questions about other agreements).
CONDITIONAL examples: "Approved if arrears are cleared", "Approved once the device is received", "Go ahead when the customer pays", "Yes but only after the account is up to date", "Happy to approve subject to the customer confirming".
NO examples: "Check the status first", "What is the trade in status?", any question without approval, any request for information, any message that is an instruction to a bot (e.g. "@Billington post GOGW on A00293914" — this is a bot command, NOT an approval).

IMPORTANT: A message can contain BOTH questions about some items AND an explicit approval for another. If any part of the message gives explicit unconditional approval (e.g. "Happy to approve for this one", "approved"), classify as APPROVED.

If APPROVED, also identify which specific agreement IDs are approved. If the message approves specific IDs (e.g. "A00343917 - Happy to approve for this one"), list only those. If it approves all items without specifying, do not list any.

Reply format:
- If APPROVED with specific IDs: reply with "APPROVED (A00343917)" — comma-separate multiple IDs
- If APPROVED without specific IDs: reply with just "APPROVED"
- If CONDITIONAL: reply with "CONDITIONAL: " followed by a brief description of the condition (max 20 words)
- If NO: reply with just "NO"`;

  try {
    const result = await anthropic.messages.create({
      model: "claude-sonnet-4-6",
      max_tokens: 50,
      messages: [{ role: "user", content: prompt }],
    });
    const raw = (result.content[0]?.text || "").trim();
    if (raw.toUpperCase().startsWith("APPROVED")) {
      // Extract specific agreement IDs if the classifier listed them: "APPROVED (A00343917, A00344922)"
      const idMatch = raw.match(/\(([A-Z0-9,\s]+)\)/i);
      const specificIds = idMatch
        ? idMatch[1].split(/[,\s]+/).map(s => s.trim().toUpperCase()).filter(s => /^A\d{5,9}$/.test(s))
        : [];
      return { type: "APPROVED", specificIds };
    }
    if (raw.toUpperCase().startsWith("CONDITIONAL")) {
      const condition = raw.replace(/^CONDITIONAL:\s*/i, "").trim();
      return { type: "CONDITIONAL", condition: condition || "condition not specified" };
    }
    return { type: "NO" };
  } catch (err) {
    console.error("[bill-ling] Approval classification error:", err.message);
    return { type: "NO" };
  }
}

// Use LLM to check if a thread's subsequent discussion indicates a conditional approval's
// condition has been met (or an alternative agreed condition has been met)
async function classifyConditionMet(parentText, conditionText, threadContext) {
  const prompt = `You are monitoring a refund/complaints thread in Slack.

Original request:
"${(parentText || "").slice(0, 300)}"

An approver gave CONDITIONAL approval with this condition:
"${(conditionText || "").slice(0, 200)}"

Here is what happened in the thread AFTER the conditional approval:
${(threadContext || "").slice(0, 2000)}

Has the condition been met, OR has an alternative condition been agreed and confirmed?

Important: conditions can evolve through discussion. If the team agreed to change the condition (e.g. from "arrears cleared" to "customer confirms they're happy") and someone has now confirmed the new condition is met, that counts as YES.

A simple "I'm happy with that" or "confirmed" or "good to go" from a team member discussing the condition counts as the condition being met.

Questions, updates without confirmation, or "we're checking" do NOT count — the condition is still pending.

Reply with ONLY "YES" or "NO".`;

  try {
    const result = await anthropic.messages.create({
      model: "claude-sonnet-4-6",
      max_tokens: 5,
      messages: [{ role: "user", content: prompt }],
    });
    return (result.content[0]?.text || "").trim().toUpperCase() === "YES";
  } catch (err) {
    console.error("[bill-ling] Condition-met classification error:", err.message);
    return false;
  }
}

// Use LLM to check if a human reply in the thread is confirming they have PROCESSED
// the refund (e.g. "done", "refund sent", "payment posted"). Must distinguish from
// unrelated uses of similar words (e.g. "it was sent to 3PP" = not about the refund).
async function classifyProcessingConfirmation(parentText, replyText, replyAuthor) {
  const prompt = `You are monitoring a refund/complaints thread in Slack.

Original request (the parent message):
"${(parentText || "").slice(0, 300)}"

A team member (${replyAuthor}) replied:
"${(replyText || "").slice(0, 300)}"

Is this reply confirming that the REFUND has been PROCESSED / SENT / COMPLETED / PAID?

Examples of YES:
- "Done" (in response to a request to process a refund)
- "Refund sent"
- "Payment posted"
- "Processed"
- "Refund has been actioned"
- "Transferred"

Examples of NO:
- "it was sent to 3PP" (talking about a package, not the refund)
- "the customer sent an email" (not about processing the refund)
- "I've done the investigation" (done refers to investigation, not refund processing)
- "Has this been processed?" (this is a question, not confirmation)
- "We need to check if it's been paid" (not confirming, asking)
- Any question (contains "?")
- General discussion about the case

Reply with ONLY "YES" or "NO".`;

  try {
    const result = await anthropic.messages.create({
      model: "claude-sonnet-4-6",
      max_tokens: 5,
      messages: [{ role: "user", content: prompt }],
    });
    return (result.content[0]?.text || "").trim().toUpperCase() === "YES";
  } catch (err) {
    console.error("[bill-ling] Processing confirmation classification error:", err.message);
    return false;
  }
}

async function checkRefundApprovals() {
  const today = new Date().toLocaleDateString("en-CA", { timeZone: "Europe/London" });
  const oldest = String(Math.floor(Date.now() / 1000) - 30 * 86400); // last 30 days

  const histResp = await app.client.conversations.history({
    token: SLACK_BOT_TOKEN,
    channel: CHANNELS.CUSTOMER_REFUNDS,
    oldest,
    limit: 100,
  });

  const messages = (histResp.messages || []).filter((msg) => {
    if (msg.bot_id || msg.subtype) return false;
    if (msg.reply_count === 0) return false; // no replies = no approval
    if (BOT_USER_ID) {
      const alreadyDone = (msg.reactions || []).some(
        (r) => r.name === "white_check_mark" && (r.users || []).includes(BOT_USER_ID)
      );
      if (alreadyDone) return false;
    }
    // If BOT_USER_ID isn't resolved yet we don't filter here — the in-thread
    // reply-text dedup (gated on r.bot_id || r.user === BOT_USER_ID) is the
    // backstop and catches duplicates without risking false-positive skips
    // from human ✅ reactions.
    return true;
  });

  let notified = 0;
  for (const msg of messages) {
    // Only skip if we've already confirmed the refund is posted (value = "confirmed")
    // Threads that were just notified (value = date string) should still be re-checked for Anchor posting
    if (approvalNotifiedThreads.get(msg.ts) === "confirmed") {
      console.log(`[bill-ling] Approval monitor: skipping thread ${msg.ts} — already confirmed via Anchor`);
      continue;
    }

    let replies;
    try {
      const threadResp = await app.client.conversations.replies({
        token: SLACK_BOT_TOKEN,
        channel: CHANNELS.CUSTOMER_REFUNDS,
        ts: msg.ts,
        limit: 50,
      });
      replies = (threadResp.messages || []).slice(1); // skip parent
    } catch (e) {
      continue;
    }

    // Defer to the button flow (Hargo, 07/07/2026 — "it was approved"): if
    // Billington has posted a Post GOGW + refund button in this thread, the
    // trade-in/button flow owns the action. The approval is already in place and
    // the button (gated to the authorisers) is the path to press — so do NOT
    // notify / chase / ask to re-approve here. We still CONFIRM below if Anchor
    // shows the refund posted.
    const hasPostButton = (replies || []).some(r =>
      (r.user === BOT_USER_ID || r.bot_id) && /GOGW\s*£[\d.,]+\s*\+\s*refund/i.test(getMessageText(r))
    );

    // 30-day timeout: if the latest reply in the thread is > 30 days old, stop checking
    const latestReplyTs = replies.length > 0 ? Math.max(...replies.map(r => Number(r.ts))) : Number(msg.ts);
    const daysSinceLastReply = (Date.now() / 1000 - latestReplyTs) / 86400;
    if (daysSinceLastReply > 30) {
      console.log(`[bill-ling] Approval monitor: skipping thread ${msg.ts} — no activity for ${Math.floor(daysSinceLastReply)} days (>30 day timeout)`);
      continue;
    }

    // Self-approved requests: CS escalation refunds don't need separate approval —
    // the requester IS the approver (within their allowance). Treat as pre-approved.
    const parentLower = (msg.text || "").toLowerCase();
    const isSelfApproved = /\b(cs\s+escalation|escalation\s+resolution|escalation\s+refund|within\s+(my\s+)?allowance|approved\s+by\s+cs|cs\s+approved)\b/i.test(parentLower);
    if (isSelfApproved) {
      console.log(`[bill-ling] Approval monitor: thread ${msg.ts} — self-approved CS escalation, skipping approval chase`);
      // Treat the parent message author as the approver
      const requesterName = APPROVER_NAMES[msg.user] || "the requester";
      const agIds = [...new Set((msg.text.match(/\bA\d{5}(?:\d{3})?\b/gi) || []).map(id => id.toUpperCase()))];
      const agRef = agIds.length ? ` (${agIds.join(", ")})` : "";
      const alreadyNotified = replies.some((r) => (r.user === BOT_USER_ID || r.bot_id) && (r.text || "").includes("good to go for processing"));
      // Dedupe: once any bot has posted a confirmation message containing
      // "has been posted in Anchor" / "Marking as complete", skip subsequent
      // cron cycles. Gate on (r.bot_id || r.user === BOT_USER_ID) — BOT_USER_ID
      // can be null momentarily after a redeploy (auth.test hasn't resolved
      // yet) and a startup approval check fired in that window would otherwise
      // re-post the confirmation. 20/05/2026 spam incident.
      const alreadyConfirmed = replies.some((r) => {
        if (!r.bot_id && r.user !== BOT_USER_ID) return false;
        const t = r.text || "";
        return t.includes("has been posted in Anchor") || t.includes("Marking as complete");
      });
      if (alreadyConfirmed) { approvalNotifiedThreads.set(msg.ts, "confirmed"); continue; }

      // Check Anchor for refund posting
      let refundPosted = false;
      let anchorDetail = "";
      if (agIds.length > 0) {
        const requestDate = new Date(Number(msg.ts) * 1000).toISOString().slice(0, 10);
        const result = await checkAnchorForRefund(agIds[0], requestDate);
        refundPosted = result.posted;
        anchorDetail = result.detail || "";
      }

      if (refundPosted) {
        const confirmText = `Refund for ${agIds[0]} has been posted in Anchor (${anchorDetail}). ✅ Marking as complete.`;
        try {
          await app.client.chat.postMessage({ token: SLACK_BOT_TOKEN, channel: CHANNELS.CUSTOMER_REFUNDS, thread_ts: msg.ts, text: confirmText, mrkdwn: true });
          await app.client.reactions.add({ token: SLACK_BOT_TOKEN, channel: CHANNELS.CUSTOMER_REFUNDS, timestamp: msg.ts, name: "white_check_mark" }).catch(() => {});
          notified++;
        } catch (err) { console.error(`[bill-ling] CS escalation confirm error:`, err.message); }
      } else if (!alreadyNotified) {
        const processingTarget = await getAvailableChaseTarget(REFUND_CHASE_CHAINS.PROCESSING);
        const notifyText = `CS escalation refund${agRef} — self-approved by ${requesterName || "CS"}. <@${processingTarget.id}>, this is good to go for processing.`;
        try {
          await app.client.chat.postMessage({ token: SLACK_BOT_TOKEN, channel: CHANNELS.CUSTOMER_REFUNDS, thread_ts: msg.ts, text: notifyText, mrkdwn: true });
          notified++;
          console.log(`[bill-ling] CS escalation notification posted in thread ${msg.ts}${agRef}`);
        } catch (err) { console.error(`[bill-ling] CS escalation notify error:`, err.message); }
      } else {
        console.log(`[bill-ling] Approval monitor: thread ${msg.ts}${agRef} — CS escalation already notified, checking Anchor next cycle`);
      }
      approvalNotifiedThreads.set(msg.ts, refundPosted ? "confirmed" : today);
      continue;
    }

    // Check if any approved user posted an approval (LLM-based classification)
    let approvalReply = null;
    let approvalResult = null;
    const approverReplies = replies.filter(r => {
      if (!REFUND_APPROVERS.has(r.user)) return false;
      // Exclude messages that are bot posting instructions (e.g. "@Billington post GOGW on X")
      // These are commands to Billington, not approvals from a human approver
      const txt = (r.text || "").trim();
      if (/^<@[A-Z0-9]+>\s*(post\s+(gogw|the\s+refund|this)|gesture\s+of\s+goodwill)/i.test(txt)) return false;
      return true;
    });
    console.log(`[bill-ling] Approval monitor: thread ${msg.ts} has ${replies.length} replies, ${approverReplies.length} from approvers`);
    for (const r of approverReplies) {
      const approverName = APPROVER_NAMES[r.user] || "Unknown";
      console.log(`[bill-ling] Approval monitor: classifying reply from ${approverName}: "${(r.text || "").slice(0, 60)}"`);
      const result = await classifyApproval(msg.text, r.text, approverName);
      console.log(`[bill-ling] Approval monitor: classification result = ${result.type}${result.condition ? ` (${result.condition})` : ""}`);
      if (result.type === "APPROVED") {
        approvalReply = r;
        approvalResult = result;
        break;
      }
      if (result.type === "CONDITIONAL" && !approvalResult) {
        approvalReply = r;
        approvalResult = result;
        // Don't break — keep checking for a later unconditional approval
      }
    }

    // Handle CONDITIONAL approvals — check if the condition has since been met
    if (approvalResult && approvalResult.type === "CONDITIONAL") {
      const approvalTs = Number(approvalReply.ts);
      const repliesAfterApproval = replies.filter(r => Number(r.ts) > approvalTs && !r.bot_id && r.user !== BOT_USER_ID);
      if (repliesAfterApproval.length === 0) {
        console.log(`[bill-ling] Approval monitor: conditional approval in thread ${msg.ts} — no subsequent replies yet, skipping`);
        continue;
      }
      // Build thread context from replies after the conditional approval
      const threadContext = repliesAfterApproval.map(r => {
        const name = APPROVER_NAMES[r.user] || r.user;
        return `${name}: ${(r.text || "").slice(0, 300)}`;
      }).join("\n");
      const conditionMet = await classifyConditionMet(msg.text, approvalResult.condition, threadContext);
      console.log(`[bill-ling] Approval monitor: condition "${approvalResult.condition}" met = ${conditionMet}`);
      if (!conditionMet) {
        console.log(`[bill-ling] Approval monitor: conditional approval in thread ${msg.ts} — condition not yet met, skipping`);
        continue;
      }
      // Condition met — treat as approved from here on
      console.log(`[bill-ling] Approval monitor: conditional approval in thread ${msg.ts} — condition met, proceeding as approved`);
    }

    if (!approvalReply) {
      console.log(`[bill-ling] Approval monitor: no approval found in thread ${msg.ts}`);
      continue;
    }

    // Skip if a human confirmed they've already PROCESSED the refund (LLM-based check)
    // Only check non-bot human replies that contain potential processing keywords
    let humanProcessingConfirm = false;
    const potentialProcessingReplies = replies.filter((r) => {
      if (r.user === BOT_USER_ID || r.bot_id) return false;
      const txt = (r.text || "").trim();
      if (txt.includes("?") || /^(has|have|did|was|were|is|can|could|will|when|check)\b/i.test(txt)) return false;
      return textContainsAny(txt, PROCESSING_KEYWORDS);
    });
    for (const r of potentialProcessingReplies) {
      const authorName = APPROVER_NAMES[r.user] || r.user;
      const isConfirm = await classifyProcessingConfirmation(msg.text, r.text, authorName);
      console.log(`[bill-ling] Approval monitor: processing check — "${(r.text || "").slice(0, 60)}" from ${authorName} → ${isConfirm ? "YES (processed)" : "NO (not about refund processing)"}`);
      if (isConfirm) {
        humanProcessingConfirm = true;
        break;
      }
    }
    if (humanProcessingConfirm) {
      console.log(`[bill-ling] Approval monitor: thread ${msg.ts} has confirmed human processing — skipping`);
      continue;
    }

    // Extract agreement IDs — prefer IDs the classifier identified as specifically approved,
    // then IDs mentioned in the approval reply itself, then fall back to all thread IDs.
    // This prevents A00344922/A00327357 appearing when only A00343917 was approved.
    const allThreadText = [msg.text || "", ...replies.filter(r => !r.bot_id && r.user !== BOT_USER_ID).map(r => r.text || "")].join(" ");
    let agIds;
    if (approvalResult.specificIds && approvalResult.specificIds.length > 0) {
      // Classifier told us which specific IDs were approved
      agIds = approvalResult.specificIds;
    } else {
      // Fall back: IDs mentioned in the approval reply itself (not the whole thread)
      const approvalOnlyText = approvalReply.text || "";
      const approvalOnlyIds = [...new Set(
        (approvalOnlyText.match(/\bA\d{5}(?:\d{3})?\b/gi) || []).map(id => id.toUpperCase())
      )];
      agIds = approvalOnlyIds.length > 0
        ? approvalOnlyIds
        : [...new Set((allThreadText.match(/\bA\d{5}(?:\d{3})?\b/gi) || []).map(id => id.toUpperCase()))];
    }
    const agRef = agIds.length ? ` (${agIds.join(", ")})` : "";

    // Request date = parent message timestamp
    const requestDate = new Date(Number(msg.ts) * 1000).toISOString().slice(0, 10);

    // Resolve approver name
    const approverName = APPROVER_NAMES[approvalReply.user] || "An approver";

    // Extract the approval-relevant line — find the line containing explicit approval keywords,
    // not necessarily the first line (which may be a question about a different agreement).
    const fullText = (approvalReply.text || "").trim();
    const textLines = fullText.split(/\n/).map(l => l.trim()).filter(Boolean);
    const approvalLine = textLines.find(l =>
      /\b(happy\s+to\s+approve|approved|go\s+ahead|yes.*process|proceed|approve\s+for\s+this)\b/i.test(l)
    ) || textLines[0] || fullText;
    const quote = approvalLine.slice(0, 80);

    // Check if Billington already posted an approval notification OR a pending-hold
    // in this thread. The hold used to re-post every cycle (A00382311 got ~9 copies,
    // 20/07/2026) because only "good to go for processing" counted as notified.
    const alreadyNotified = replies.some((r) => (r.user === BOT_USER_ID || r.bot_id) && ((r.text || "").includes("good to go for processing") || (r.text || "").includes("holding off rather than proposing") || (r.text || "").includes("not been assessed")));
    // Stand-down: if this thread was flagged "Billington is incorrect" (or otherwise
    // stood down), do nothing further here until Hargo re-engages via @-mention.
    const stoodDown = replies.some((r) => (r.user === BOT_USER_ID || r.bot_id) && /\b(standing down|stood down)\b/i.test(r.text || ""));
    // Check if Billington already confirmed this refund via Anchor.
    // Gate on (r.bot_id || r.user === BOT_USER_ID) — BOT_USER_ID can be null
    // momentarily after a redeploy (auth.test hasn't resolved yet) and the
    // startup approval check fired in that window would otherwise re-post
    // the confirmation. 20/05/2026 spam incident: A00346678 got the
    // "Marking as complete" message 4× across redeploys before this guard.
    const alreadyConfirmed = replies.some((r) => {
      if (!r.bot_id && r.user !== BOT_USER_ID) return false;
      const t = r.text || "";
      return t.includes("has been posted in Anchor") || t.includes("Marking as complete");
    });

    if (alreadyConfirmed) continue; // fully resolved — nothing more to do
    if (stoodDown) continue;        // flagged incorrect / stood down — stay silent until re-engaged

    // Check Anchor API for refund transaction (TypeId 149) if we have an agreement ID
    let refundPosted = false;
    let anchorDetail = "";
    if (agIds.length > 0) {
      const result = await checkAnchorForRefund(agIds[0], requestDate);
      refundPosted = result.posted;
      anchorDetail = result.detail || "";
      console.log(`[bill-ling] Approval monitor: Anchor check for ${agIds[0]} — posted: ${refundPosted}${anchorDetail ? `, ${anchorDetail}` : ""}`);
    }

    if (refundPosted) {
      // Refund posted in Anchor — confirm and mark complete
      const confirmText = `Refund for ${agIds[0]} has been posted in Anchor (${anchorDetail}). ✅ Marking as complete.`;
      try {
        await app.client.chat.postMessage({
          token: SLACK_BOT_TOKEN,
          channel: CHANNELS.CUSTOMER_REFUNDS,
          thread_ts: msg.ts,
          text: confirmText,
          mrkdwn: true,
        });
        await app.client.reactions.add({
          token: SLACK_BOT_TOKEN,
          channel: CHANNELS.CUSTOMER_REFUNDS,
          timestamp: msg.ts,
          name: "white_check_mark",
        }).catch(e => { if (!e.message?.includes("already_reacted")) console.error(e.message); });
        notified++;
        console.log(`[bill-ling] Refund confirmed via Anchor in thread ${msg.ts} for ${agIds[0]} (${anchorDetail})`);
      } catch (err) {
        console.error(`[bill-ling] Failed to post Anchor confirmation in thread ${msg.ts}:`, err.message);
      }
    } else if (hasPostButton) {
      // A Post GOGW + refund button is already up — the button flow owns this
      // thread. Don't notify / chase / re-approve (the approval stands).
      console.log(`[bill-ling] Approval monitor: thread ${msg.ts} — deferring to the Post GOGW + refund button (button flow owns it).`);
      continue;
    } else if (!alreadyNotified) {
      // First time seeing this approval — notify for processing (OOO-aware)
      const processingTarget = await getAvailableChaseTarget(REFUND_CHASE_CHAINS.PROCESSING);
      // Hargo, 08/06/2026: offer the processor a choice — post the GOGW +
      // refund themselves, OR delegate to Billington with `approved
      // @billington`. To keep the auto-action deterministic (no LLM inference
      // at approval time), Billington LOCKS the figure here: when there's a
      // single agreement and the amount + GOGW type can be read straight from
      // the thread, it displays the exact command it would run. "approved
      // @billington" then posts that displayed figure verbatim. If the type
      // can't be inferred, Billington ASKS the requester which category the
      // refund is (never defaulting to escalation). Hargo or Charlotte Platt
      // can authorise.
      // Lock-time inference text (Hargo, 09/06/2026). CRUCIAL: include OTHER
      // bots' replies — especially Denton's trade-in confirmation, which is the
      // real signal for whether this is a full/partial trade-in — but EXCLUDE
      // Billington's OWN messages so we never read back our own proposal (it is
      // circular, and the fallback example text "type:escalation / type:full /
      // …" would otherwise bias inference toward escalation). allThreadText
      // above stays human-only and is only used for agreement-ID extraction.
      const inferenceThreadText = [
        getMessageText(msg),
        ...replies
          .filter(r => r.user !== BOT_USER_ID && !/good to go for processing|I read this as:/i.test(getMessageText(r)))
          .map(r => getMessageText(r)),
      ].join("\n");
      // Compute the lock (amount + GOGW type) from the thread, incl. Denton's
      // trade-in confirmation. computeRefundLock returns cmd=null when it can't
      // determine BOTH — it never defaults to escalation — so that routes to
      // the ASK branches below.
      let lockedCmd = null, lockedAmount = null, lockedCategory = null;
      if (agIds.length === 1) {
        const lock = computeRefundLock(agIds[0], inferenceThreadText);
        if (lock) { lockedAmount = lock.amount; lockedCategory = lock.category; lockedCmd = lock.cmd; }
      }
      // The requester = whoever raised the thread. If we can't determine the
      // refund TYPE we ask THEM (Hargo: "ask the person who asked … what type
      // of refund this is categorised at") rather than defaulting to anything.
      const requesterMention = msg.user ? `<@${msg.user}>` : "the person who raised this";
      let notifyText, pendingHold = false;
      const isTradeInLock = lockedCategory === "Full trade in value" || lockedCategory === "Partial trade in value";
      if (isTradeInLock && tradeInPendingAssessment(inferenceThreadText)) {
        // Trade-in still pending assessment — declared value not confirmed. Don't
        // auto-propose, but still offer a "Process anyway" override so an authoriser
        // who knows better (e.g. device already stocked) can push it through. Hargo,
        // 20/07/2026 (A00353969). Drop the auto Post button; the override triple bypasses the guard.
        lockedCmd = null;
        pendingHold = true;
        const overdue = overdueAssessmentPhrase(inferenceThreadText);
        notifyText = (lockedAmount > 0)
          ? `⚠️ ${approverName} has approved this refund${agRef} — "${quote}" — but ${agIds[0]}'s trade-in has *not been assessed* yet.${overdue} You don't need to wait for the assessment — if that delay is the reason for the refund, use *⚠️ Process anyway* below to push it through at the declared *£${lockedAmount.toFixed(2)}*. ${requesterMention}`
          : `⚠️ ${approverName} has approved this refund${agRef} — "${quote}" — but ${agIds[0]}'s trade-in has *not been assessed* yet.${overdue} I couldn't read a clear figure to offer a one-click button, so ${BILLINGTON_REFUND_AUTHORISER_NAMES} can post it explicitly with the amount. ${requesterMention}`;
      } else if (lockedCmd) {
        // State the figure explicitly (Hargo, 09/06/2026): agreement, GOGW
        // amount, refund amount and type, so the authoriser sees exactly what
        // "approved @billington" will post.
        notifyText =
          `${approverName} has approved this refund${agRef} — "${quote}" — <@${processingTarget.id}>, this is good to go for processing.\n` +
          `Here's exactly what I'd post:\n` +
          `• Agreement: *${agIds[0]}*\n` +
          `• GOGW: *£${lockedAmount.toFixed(2)}* (TypeId 61)\n` +
          `• Refund: *£${lockedAmount.toFixed(2)}* (TypeId 149)\n` +
          `• Type: *${lockedCategory}*\n` +
          `Command: \`${lockedCmd}\`\n` +
          `Option A: post it yourself.\n` +
          `Option B: reply *approved @billington* and I'll re-check it hasn't already been processed, then post exactly that. (${BILLINGTON_REFUND_AUTHORISER_NAMES} can authorise.)`;
      } else if (lockedAmount != null && lockedAmount > 0 && agIds.length === 1) {
        // We can read the figure but not the category — ASK the requester which
        // type it is. Never assume escalation.
        notifyText =
          `${approverName} has approved this refund${agRef} — "${quote}" — this is good to go for processing.\n` +
          `I can see a £${lockedAmount.toFixed(2)} refund on ${agIds[0]}, but I'm not certain which category it falls under, so I won't guess.\n` +
          `${requesterMention}, what type of refund is this — *full trade-in*, *partial trade-in*, *account closure*, or *escalation resolution*?\n` +
          `Once that's confirmed, ${BILLINGTON_REFUND_AUTHORISER_NAMES} can post it — e.g. \`post gogw and refund £${lockedAmount.toFixed(2)} on ${agIds[0]} type:full\` (type:full / type:partial / type:closure / type:escalation).`;
      } else {
        // Couldn't pin down a single clear figure — ASK the requester for the
        // figure AND the type, rather than "post by hand".
        notifyText =
          `${approverName} has approved this refund${agRef} — "${quote}" — this is good to go for processing.\n` +
          `${requesterMention}, I couldn't pin down a single clear figure + category from this thread, so I won't guess. How much is the refund, and what type is it — *full trade-in*, *partial trade-in*, *account closure*, or *escalation resolution*?\n` +
          `Then it can be posted — e.g. \`post gogw and refund £AMOUNT on ${agIds[0] || "A00XXXXXX"} type:full\` (type:full / type:partial / type:closure / type:escalation). ${BILLINGTON_REFUND_AUTHORISER_NAMES} can authorise.`;
      }
      try {
        // One-click "Post GOGW + refund" button when we've locked a figure
        // (Hargo, 18/06/2026). Same executor as typing "approved @billington" —
        // gated to the refund authorisers in the handler, with a confirm step.
        const actionEls = [];
        if (lockedCmd) {
          actionEls.push({
            type: "button",
            text: { type: "plain_text", text: "✅ Post GOGW + refund", emoji: true },
            style: "primary",
            action_id: "btn_post_gogw_refund",
            value: JSON.stringify({ t: msg.ts, c: CHANNELS.CUSTOMER_REFUNDS }),
            confirm: {
              title: { type: "plain_text", text: "Post GOGW + refund?" },
              text: { type: "mrkdwn", text: `I'll run my usual checks then post:\n\`${lockedCmd}\`` },
              confirm: { type: "plain_text", text: "Post it" },
              deny: { type: "plain_text", text: "Cancel" },
            },
          });
          actionEls.push({
            type: "button",
            text: { type: "plain_text", text: "✋ Mark refunded manually", emoji: true },
            action_id: "btn_refund_manual",
            value: JSON.stringify({ t: msg.ts, c: CHANNELS.CUSTOMER_REFUNDS, ref: agIds[0] || null }),
            confirm: {
              title: { type: "plain_text", text: "Mark refunded manually?" },
              text: { type: "mrkdwn", text: "Records that this refund was actioned by hand and stops the chase. Charlotte/Ciaran/Hargo only." },
              confirm: { type: "plain_text", text: "Mark done" },
              deny: { type: "plain_text", text: "Cancel" },
            },
          });
        }
        if (pendingHold && lockedAmount > 0) actionEls.push(processAnywayButton(msg.ts, CHANNELS.CUSTOMER_REFUNDS, agIds[0], lockedAmount, lockedCategory));
        actionEls.push(billingtonIncorrectButton()); // always offer "Billington is incorrect"
        const notifyBlocks = INTERACTIVE_BUTTONS_ENABLED ? [
          { type: "section", text: { type: "mrkdwn", text: notifyText } },
          { type: "actions", elements: actionEls },
        ] : undefined;
        await app.client.chat.postMessage({
          token: SLACK_BOT_TOKEN,
          channel: CHANNELS.CUSTOMER_REFUNDS,
          thread_ts: msg.ts,
          text: notifyText,
          ...(notifyBlocks ? { blocks: notifyBlocks } : {}),
          mrkdwn: true,
        });
        notified++;
        console.log(`[bill-ling] Approval notification posted in thread ${msg.ts}${agRef} (approved by ${approverName}, chasing ${processingTarget.name})`);
      } catch (err) {
        console.error(`[bill-ling] Failed to post approval notification in thread ${msg.ts}:`, err.message);
      }
    } else if (alreadyNotified && !refundPosted) {
      // Already notified — just silently re-check Anchor each hour.
      // Only post again when the refund is actually confirmed as posted (handled above).
      console.log(`[bill-ling] Approval monitor: thread ${msg.ts}${agRef} — already notified, refund not yet in Anchor. Will re-check next hour.`);
    }

    approvalNotifiedThreads.set(msg.ts, refundPosted ? "confirmed" : today);
  }

  console.log(`[bill-ling] Approval monitor: scanned ${messages.length} threads, notified ${notified}.`);
}

// Cache: { data, summary, fetchedAt } — reused for drill-down queries within 2 hours
let lastRefundsCache = null;

// Count working days between two ISO date strings
function workingDaysBetween(fromIso, toIso) {
  if (!fromIso || fromIso >= toIso) return 0;
  let count = 0;
  let d = new Date(fromIso + "T12:00:00Z");
  const end = new Date(toIso + "T12:00:00Z");
  while (d < end) {
    d.setUTCDate(d.getUTCDate() + 1);
    const ds = d.toISOString().slice(0, 10);
    if (isWorkingDay(ds)) count++;
  }
  return count;
}

// Build a drill-down response from cached/fresh refunds data
function buildDrillDown(data, question) {
  if (!data) return null;
  const lower = question.toLowerCase();
  const today = new Date().toLocaleDateString("en-CA", { timeZone: "Europe/London" });
  const wd = (iso) => workingDaysBetween(iso || today, today);
  const gbp = (n) => n != null ? `£${Number(n).toLocaleString("en-GB", { minimumFractionDigits: 2, maximumFractionDigits: 2 })}` : "";

  const isBatch      = /batch|barclays|refund file|file.*confirm|confirm.*file/.test(lower);
  const isApproval   = /approv/.test(lower);
  const isProcessing = /process/.test(lower);
  const isCustomer   = /customer|bank detail|blocked/.test(lower);
  const isOutOfSla   = /out.?of.?sla|overdue|past.?sla|> ?2/.test(lower);

  let heading, items;

  if (isOutOfSla) {
    heading = "*Out of SLA items (> 2 working days)*";
    items = [
      ...(data.awaiting_approval        || []).filter(i => wd(i.date_iso) > 2).map(i => ({ ...i, _bucket: "Awaiting approval" })),
      ...(data.awaiting_processing       || []).filter(i => wd(i.date_iso) > 2).map(i => ({ ...i, _bucket: "Awaiting processing" })),
      ...(data.awaiting_customer_action  || []).filter(i => wd(i.date_iso) > 2).map(i => ({ ...i, _bucket: "Customer action" })),
      ...(data.batch_files               || []).filter(i => wd(i.date_iso) > 2).map(i => ({ ...i, _bucket: "Batch file" })),
    ];
  } else if (isBatch) {
    heading = "*Refund files awaiting Barclays confirmation*";
    items = (data.batch_files || []).map(i => ({ ...i, _bucket: "Batch file" }));
  } else if (isApproval) {
    heading = "*Awaiting approval*";
    items = (data.awaiting_approval || []).map(i => ({ ...i, _bucket: "Awaiting approval" }));
  } else if (isProcessing) {
    heading = "*Awaiting processing*";
    items = (data.awaiting_processing || []).map(i => ({ ...i, _bucket: "Awaiting processing" }));
  } else if (isCustomer) {
    heading = "*Awaiting customer action*";
    items = (data.awaiting_customer_action || []).map(i => ({ ...i, _bucket: "Customer action" }));
  } else {
    heading = "*All pending refund items*";
    items = [
      ...(data.awaiting_customer_action || []).map(i => ({ ...i, _bucket: "Awaiting customer action" })),
      ...(data.awaiting_approval        || []).map(i => ({ ...i, _bucket: "Awaiting approval" })),
      ...(data.awaiting_processing       || []).map(i => ({ ...i, _bucket: "Awaiting processing" })),
      ...(data.batch_files              || []).map(i => ({ ...i, _bucket: "Batch file" })),
    ];
  }

  if (!items.length) return "Nothing currently in that category.";

  const lines = [heading, ""];
  for (const item of items) {
    const days = item.date_iso ? wd(item.date_iso) : null;
    const daysStr = days !== null ? `${days} working day${days !== 1 ? "s" : ""}` : "";
    const slaFlag = days > 2 ? " ⚠️" : "";

    if (item._bucket === "Batch file") {
      const amt = item.amount ? gbp(item.amount) : "";
      const pmts = item.payments ? `${Number(item.payments).toLocaleString("en-GB")} payments` : "";
      lines.push(`• *${item.date}* — ${[pmts, amt].filter(Boolean).join(", ")} — ${daysStr} waiting${slaFlag}`);
    } else {
      lines.push(`• *${item.ref || "—"}* — ${item.description || ""} — ${daysStr}${slaFlag}`);
      if (isOutOfSla) lines.push(`  _${item._bucket}_`);
    }
    if (item.permalink) lines.push(`  <${item.permalink}|View thread>`);
  }
  return lines.filter(l => l !== null).join("\n");
}

async function getRefundsSummary() {
  try {
    const oldest = String(Math.floor((Date.now() - 30 * 24 * 60 * 60 * 1000) / 1000));

    // Fetch up to 100 messages from the last 30 days
    const histResp = await app.client.conversations.history({
      token: SLACK_BOT_TOKEN,
      channel: CHANNELS.CUSTOMER_REFUNDS,
      oldest,
      limit: 100,
    });

    const messages = histResp.messages || [];
    if (!messages.length) {
      return "No messages found in #customer-refunds-and-complaints in the last 30 days.";
    }

    // Skip bot messages (Billington's own reports etc.) before fetching threads —
    // they don't contain refund requests and are often very long.
    // Also skip messages already marked ✅ by the bot — no need to re-check those.
    const humanMessages = messages.filter((msg) => {
      if (msg.bot_id || msg.subtype) return false;
      if (BOT_USER_ID) {
        const alreadyDone = (msg.reactions || []).some(
          (r) => r.name === "white_check_mark" && (r.users || []).includes(BOT_USER_ID)
        );
        if (alreadyDone) return false;
      }
      return true;
    });

    // For each human message that has thread replies, fetch the full thread
    const threads = await Promise.all(
      humanMessages.map(async (msg) => {
        let replies = [];
        if (msg.reply_count > 0) {
          try {
            const threadResp = await app.client.conversations.replies({
              token: SLACK_BOT_TOKEN,
              channel: CHANNELS.CUSTOMER_REFUNDS,
              ts: msg.ts,
              limit: 50,
            });
            // replies[0] is the parent, skip it
            replies = (threadResp.messages || []).slice(1);
          } catch (e) {
            // ignore thread fetch errors
          }
        }
        const date = new Date(Number(msg.ts) * 1000).toLocaleDateString("en-GB");
        const tsClean = msg.ts.replace(".", "");
        const permalink = `https://joinraylo.slack.com/archives/${CHANNELS.CUSTOMER_REFUNDS}/p${tsClean}`;
        return { date, ts: msg.ts, permalink, userId: msg.user || "unknown", text: msg.text || "", replies };
      })
    );

    // Collect all unique user IDs across messages and replies, then resolve to real names
    const allUserIds = new Set();
    for (const t of threads) {
      if (t.userId) allUserIds.add(t.userId);
      for (const r of t.replies) { if (r.user) allUserIds.add(r.user); }
    }
    const userNames = {};
    await Promise.all([...allUserIds].map(async (uid) => {
      try {
        const info = await app.client.users.info({ token: SLACK_BOT_TOKEN, user: uid });
        userNames[uid] = info.user?.real_name || info.user?.name || uid;
      } catch {
        userNames[uid] = uid;
      }
    }));

    // Build compact transcript — include both name and Slack user ID so Claude can
    // emit <@USERID> mentions in the output for any person referenced.
    const fmtSender = (uid) => {
      const name = userNames[uid] || uid;
      return uid ? `${name} (<@${uid}>)` : name;
    };
    const transcript = threads
      .map((t) => {
        const sender = fmtSender(t.userId);
        const replyBlock = t.replies.length
          ? `\n  Replies:\n${t.replies.map((r) => {
              return `    - ${fmtSender(r.user)}: ${r.text || ""}`;
            }).join("\n")}`
          : "";
        return `[${t.date}] [ts:${t.ts}] [permalink:${t.permalink}] ${sender}: ${t.text}${replyBlock}`;
      })
      .join("\n\n");

    // --- Arrears check: find any refunds/GOGWs conditional on arrears clearance ---
    // Agreement IDs always look like A followed by 5 or 8 digits (e.g. A00307833 or A12345).
    // "agreement number", "agreement reference", "agreement ID", "agreement ref" all mean agreement_id.

    // Step 1: regex-scan transcript for all agreement IDs present
    const allRefsInTranscript = [...new Set(
      [...transcript.matchAll(/\bA\d{5}(?:\d{3})?\b/g)].map((m) => m[0])
    )];

    // Step 2: run arrears extraction and contact inference in parallel
    const arrearsExtractPrompt = allRefsInTranscript.length > 0
      ? `From this Slack transcript, which of these agreement IDs (${allRefsInTranscript.join(", ")}) have a refund or goodwill gesture that is explicitly conditional on the customer clearing their arrears first?
"Agreement number", "agreement reference", "agreement ref", and "agreement ID" all refer to the same thing.
Return ONLY a JSON array of the matching IDs, e.g. ["A00307833"]. If none, return [].

--- TRANSCRIPT ---
${transcript}
--- END ---`
      : null;

    const [arrearsRaw, contacts] = await Promise.all([
      arrearsExtractPrompt ? askClaude(arrearsExtractPrompt).catch(() => "[]") : Promise.resolve("[]"),
      inferRefundContacts(transcript),
    ]);

    let arrearsRefs = [];
    try {
      const m = arrearsRaw.match(/\[[\s\S]*?\]/);
      arrearsRefs = m ? JSON.parse(m[0]) : [];
    } catch (e) { /* ignore */ }

    let arrearsContext = "";
    if (arrearsRefs.length > 0) {
      console.log(`[bill-ling] Checking arrears for: ${arrearsRefs.join(", ")}`);
      try {
        const arrearsSql = `
          SELECT agreement_id, total_arrears
          FROM \`raylo-production.landing_billington.agreement_info\`
          WHERE agreement_id IN (${arrearsRefs.map((r) => `'${r}'`).join(",")})
        `;
        const rows = await runBigQueryRaw(arrearsSql);
        const arrearsMap = {};
        for (const row of rows) arrearsMap[row.agreement_id] = Number(row.total_arrears) || 0;

        arrearsContext = `\nLIVE ARREARS STATUS (from BigQuery — use this to determine approval for arrears-conditional items):\n`;
        for (const ref of arrearsRefs) {
          const amt = arrearsMap[ref];
          if (amt === undefined) {
            arrearsContext += `• ${ref}: not found in database — keep in bucket 1\n`;
          } else if (amt <= 0) {
            arrearsContext += `• ${ref}: total_arrears = £${Math.abs(amt).toFixed(2)} credit — ARREARS CLEARED → treat as APPROVED (move to bucket 2)\n`;
          } else {
            arrearsContext += `• ${ref}: total_arrears = £${amt.toFixed(2)} outstanding — still in arrears → keep in bucket 1\n`;
          }
        }
      } catch (e) {
        console.error("[bill-ling] arrears BigQuery error:", e.message);
        arrearsContext = `\nNote: Could not check live arrears data (BigQuery error: ${e.message})\n`;
      }
    }
    // --- End arrears check ---
    const fmtContact = (arr, fallbackId, fallbackName) => {
      if (!arr || !arr.length) return `<@${fallbackId}> (${fallbackName}) — fallback`;
      return arr.slice(0, 2).map((p, i) =>
        `<@${p.id}> (${p.name}, ${p.count}x in last 30d)${i === 1 ? " — escalate to" : ""}`
      ).join(" → ");
    };
    const responsibilityContext = contacts ? `
RESPONSIBILITY (inferred from last 30 days of channel activity — primary contact first, escalation second):
• Approvals: ${fmtContact(contacts.approval, REFUND_CONTACTS.PROCESSING_ESCALATION.id, "Hargo")}
• Processing refunds: ${fmtContact(contacts.processing, REFUND_CONTACTS.PROCESSING.id, "Charlotte Platt")}
• Batch file / Barclays upload: ${fmtContact(contacts.batch_file, REFUND_CONTACTS.BATCH_FILE_OWNER.id, "Caitlyn Watson")}
• Barclays confirmation: ${fmtContact(contacts.barclays_confirmation, REFUND_CONTACTS.BATCH_FILE_OWNER.id, "Caitlyn Watson")}
` : `
RESPONSIBILITY (fallback — could not infer from history):
• Barclays refund file (upload + confirmation) → <@${REFUND_CONTACTS.BATCH_FILE_OWNER.id}> (Caitlyn Watson)
• Finance escalation → <@${REFUND_CONTACTS.FINANCE_ESCALATION.id}> (Darragh Keogh)
• Processing individual refund requests → <@${REFUND_CONTACTS.PROCESSING.id}> (Charlotte Platt)
• Refund processing escalation → <@${REFUND_CONTACTS.PROCESSING_ESCALATION.id}> (Hargo)
`;
    // --- End responsibility inference ---

    const today = new Date().toLocaleDateString("en-CA", { timeZone: "Europe/London" });

    const prompt = `You are Billington, an AI assistant for Raylo's billing operations team.
Classify unresolved items from the #customer-refunds-and-complaints transcript below.${arrearsContext}

RULES:
APPROVAL: ${APPROVAL_KEYWORDS.map(k => `"${k}"`).join(", ")}, or a manager directing someone to process. Questions and comments are NOT approval.
PROCESSING: ${PROCESSING_KEYWORDS.map(k => `"${k}"`).join(", ")}.
ARREARS: if LIVE ARREARS STATUS says CLEARED → approved. If still in arrears → bucket 1.
BATCH FILE: a channel-level message (not a thread reply) announcing a refund file for Barclays — has payment count and £ total.
BARCLAYS CONFIRMED: a reply or follow-up with "paid", "paid [date]", "authorised", "confirmed", "uploaded to Barclays".
BLOCKED: a refund that can't proceed (bad bank details, customer not responding, open unresolved question/task).
AMOUNT (awaiting_approval only): set "amount" to the GBP figure being approved — the refund/cashback the customer will receive, or the declared/quoted value if that is what's stated (e.g. "£72 declared" → 72). Use null if no amount appears in the thread. This drives approval routing, so be accurate; do not guess.

User IDs appear as (<@USERID>) after names. thread_ts values appear as [ts:XXXXXXXXX.XXXXXX] in the transcript.

CHASE MESSAGE RULES:
- All chase_messages must @-mention the responsible person using their <@USERID>
- Keep chase messages concise and factual
- For awaiting_processing items: an APPROVED refund is actioned by Charlotte in the billing team — do NOT mention 'finance team' or 'escalate with finance'. The chase should ask Charlotte to action (post the GOGW / process the refund). The day-based escalation logic (day 1-2 → Charlotte, day 3+ → Hargo) is handled in code; the message just needs to ask the day-1 contact (Charlotte) to action.

Return ONLY valid JSON in this exact structure (no other text):
{
  "awaiting_customer_action": [
    {
      "ref": "AXXXXXXXX",
      "description": "brief description",
      "thread_ts": "XXXXXXXXX.XXXXXX",
      "date_iso": "YYYY-MM-DD",
      "issue": "what customer needs to do",
      "permalink": "https://...",
      "chase_message": "message to post in the thread using <@USERID> mentions"
    }
  ],
  "awaiting_approval": [
    {
      "ref": "AXXXXXXXX",
      "description": "brief description",
      "thread_ts": "XXXXXXXXX.XXXXXX",
      "date_iso": "YYYY-MM-DD",
      "requested_by": "<@USERID>",
      "amount": 0.00,
      "permalink": "https://...",
      "quote": "exact quote or no explicit signal found",
      "chase_message": "<@USERID> — this refund has been waiting for approval. Can you approve or decline?"
    }
  ],
  "awaiting_processing": [
    {
      "ref": "AXXXXXXXX",
      "description": "brief description",
      "thread_ts": "XXXXXXXXX.XXXXXX",
      "date_iso": "YYYY-MM-DD",
      "requested_by": "<@USERID>",
      "approved_by": "<@USERID>",
      "permalink": "https://...",
      "quote": "exact quote",
      "chase_message": "<@USERID> — this refund was approved. Option A: post the GOGW + refund yourself. Option B: reply *approved @billington* and I'll check it hasn't already been processed, then post the figure I locked. Hargo or Charlotte Platt can authorise."
    }
  ],
  "batch_files": [
    {
      "date": "DD/MM/YYYY",
      "date_iso": "YYYY-MM-DD",
      "thread_ts": "XXXXXXXXX.XXXXXX",
      "payments": 0,
      "amount": 0.00,
      "permalink": "https://...",
      "chase_message": "<@${REFUND_CONTACTS.BATCH_FILE_OWNER.id}> can you confirm if this refund file has been uploaded and processed on Barclays?"
    }
  ],
  "resolved": [
    {
      "thread_ts": "XXXXXXXXX.XXXXXX"
    }
  ]
}

"resolved" = ONLY include a thread here if it meets ONE of these two criteria exactly:
1. An adhoc refund or GOGW request where a PROCESSING signal ("processed", "done", "sent", "refunded", "actioned", "completed", "paid", "posted", "transferred") has been confirmed in the thread replies — i.e. someone has confirmed the money has actually been sent to the customer.
2. A batch file announcement where Barclays confirmation has been explicitly given in the thread replies ("paid", "authorised", "confirmed", "uploaded to Barclays").
Do NOT include: general messages, status updates, approvals without processing confirmation, questions, comments, or anything without a clear end-to-end completion signal. When in doubt, leave it out. Only include the thread_ts of the original parent message.

--- TRANSCRIPT ---
${transcript}
--- END ---`;

    const raw = await askClaude(prompt);
    const jsonMatch = raw.match(/\{[\s\S]*\}/);
    if (!jsonMatch) throw new Error("Claude did not return valid JSON");
    const data = JSON.parse(jsonMatch[0]);

    // Stamp ✅ reaction on resolved threads (fire-and-forget)
    markResolvedThreads(data.resolved || []).catch(() => {});

    // Build high-level count summary
    const wd = (iso) => workingDaysBetween(iso, today);
    const inSla  = (iso) => wd(iso) <= 2;
    const outSla = (iso) => wd(iso) > 2;

    const customer    = (data.awaiting_customer_action || []);
    const approval    = (data.awaiting_approval || []);
    const processing  = (data.awaiting_processing || []);
    const batches     = (data.batch_files || []);

    const approvalIn   = approval.filter(i => inSla(i.date_iso)).length;
    const approvalOut  = approval.filter(i => outSla(i.date_iso)).length;
    const processIn    = processing.filter(i => inSla(i.date_iso)).length;
    const processOut   = processing.filter(i => outSla(i.date_iso)).length;
    const batchIn      = batches.filter(i => inSla(i.date_iso)).length;
    const batchOut     = batches.filter(i => outSla(i.date_iso)).length;

    const lines = [
      `*Refunds update — ${fmtDate(today)}*`,
      ``,
    ];

    if (customer.length > 0) {
      lines.push(`*Awaiting customer action*`);
      lines.push(`• ${customer.length} item${customer.length > 1 ? "s" : ""}`);
      lines.push(``);
    }

    // Render one bullet per item for approval / processing, matching the
    // refund-files section format. Each line shows ref, working days, SLA
    // warning icon if out of SLA, and a View thread permalink. Capped at
    // 15 per section with an overflow line.
    const renderAdhocItem = (item) => {
      const days = wd(item.date_iso);
      const daysStr = `${days} working day${days !== 1 ? "s" : ""}`;
      const slaFlag = days > 2 ? " ⚠️" : "";
      const link = item.permalink ? ` — <${item.permalink}|View thread>` : "";
      const ref = item.ref || item.description || "unknown";
      return `• ${ref} — ${daysStr}${slaFlag}${link}`;
    };

    if (approval.length === 0) {
      lines.push(`✅ *Adhoc refunds/GOGW — awaiting approval*`);
      lines.push(`• None`);
    } else {
      const outCount = approval.filter(i => outSla(i.date_iso)).length;
      const slaTag = outCount > 0 ? `  *${approval.length} total, ${outCount} out of SLA*` : `  *${approval.length} total, all in SLA*`;
      lines.push(`*Adhoc refunds/GOGW — awaiting approval*${slaTag}`);
      for (const item of approval.slice(0, 15)) lines.push(renderAdhocItem(item));
      if (approval.length > 15) lines.push(`• …and ${approval.length - 15} more`);
    }
    lines.push(``);

    if (processing.length === 0) {
      lines.push(`✅ *Adhoc refunds/GOGW — awaiting processing*`);
      lines.push(`• None`);
    } else {
      const outCount = processing.filter(i => outSla(i.date_iso)).length;
      const slaTag = outCount > 0 ? `  *${processing.length} total, ${outCount} out of SLA*` : `  *${processing.length} total, all in SLA*`;
      lines.push(`*Adhoc refunds/GOGW — awaiting processing*${slaTag}`);
      for (const item of processing.slice(0, 15)) lines.push(renderAdhocItem(item));
      if (processing.length > 15) lines.push(`• …and ${processing.length - 15} more`);
    }
    lines.push(``);

    if (batches.length === 0) {
      lines.push(`✅ *Refund files — awaiting Barclays confirmation*`);
      lines.push(`• None`);
    } else {
      lines.push(`*Refund files — awaiting Barclays confirmation*`);
      const fmtGbp = (n) => n != null ? `£${Number(n).toLocaleString("en-GB", { minimumFractionDigits: 2, maximumFractionDigits: 2 })}` : "";
      for (const b of batches) {
        const days = wd(b.date_iso);
        const daysStr = `${days} working day${days !== 1 ? "s" : ""}`;
        const slaFlag = days > 2 ? " ⚠️" : "";
        const amt = b.amount ? fmtGbp(b.amount) : "";
        const pmts = b.payments ? `${Number(b.payments).toLocaleString("en-GB")} payments` : "";
        const detail = [pmts, amt].filter(Boolean).join(", ");
        const link = b.permalink ? ` — <${b.permalink}|View thread>` : "";
        lines.push(`• ${b.date} — ${detail} — ${daysStr}${slaFlag}${link}`);
      }
    }

    const summary = lines.join("\n");
    // Populate cache for drill-down queries
    lastRefundsCache = { summary, data, fetchedAt: Date.now() };
    return { summary, data };

  } catch (err) {
    console.error("[bill-ling] getRefundsSummary error:", err.message);
    return { summary: `Error reading the refunds channel: ${err.message}`, data: null };
  }
}

// Returns cached refunds data if fresh (< 2 hours), otherwise re-fetches
async function getRefundsData() {
  const TWO_HOURS = 2 * 60 * 60 * 1000;
  if (lastRefundsCache && (Date.now() - lastRefundsCache.fetchedAt) < TWO_HOURS) {
    return lastRefundsCache;
  }
  return await getRefundsSummary();
}

// True if the message is asking for specific items rather than a top-level count
function isRefundsDrillDown(text) {
  return /\b(which|what (are|were|is|was)|show me|list|give me|details?|tell me about|out.?of.?sla|overdue|past.?sla|specific|share the|link to|thread for|more explicit|more detail|more info|be more|can you be|date and amount|outstanding)\b/i.test(text);
}

/**
 * Attempt to answer a bacs_files question, with one automatic retry if the first
 * WHERE clause produces no results. On retry, Claude is told what was tried and
 * asked to suggest a corrected date/clause.
 * Returns { result: string, warned: boolean }
 */
async function resolveBacsFiles(question, today) {
  const attempt = async (where) => {
    const report = await getBacsFileReport(where);
    if (report) return report;
    const forecast = await getPreBatchForecast(where);
    return forecast || null;
  };

  // First attempt
  const where1 = await buildBacsFileWhere(question, today);
  console.log(`[bill-ling] bacs_files attempt 1 WHERE: ${where1}`);

  // FORECAST: prefix means go straight to pre-batch forecast (not-yet-generated batches)
  if (where1.toUpperCase().startsWith("FORECAST:")) {
    const forecastWhere = where1.replace(/^FORECAST:\s*/i, "").trim();
    console.log(`[bill-ling] FORECAST path: ${forecastWhere}`);
    const forecast = await getPreBatchForecast(forecastWhere, 1);
    return { result: forecast || "No upcoming ungenerated batches found.", warned: false };
  }

  const result1 = await attempt(where1);
  if (result1) return { result: result1, warned: false };

  // First attempt returned nothing — ask Claude to re-reason
  console.log(`[bill-ling] bacs_files attempt 1 returned no data — retrying with corrected clause`);
  const retryPrompt = `You are helping Billington, a Slack bot for Raylo.

The user asked: "${question}"
Today is ${today}.

Billington tried the BigQuery WHERE clause: ${where1}
But got zero rows from the table \`raylo-production.landing_billington.bacs_monitoring\`.

The table has a \`due_date\` column (DATE), \`collection_batch_created_at\` (DATE), and \`recollection_batch_created_at\` (DATE).
UK bank holidays (non-working days): ${[...UK_BANK_HOLIDAYS].sort().join(", ")}

Working days skip weekends AND the bank holidays above.
"Working day before 07/04/2026" = 02/04/2026 (skip Easter Mon 06/04, Sun 05/04, Sat 04/04, Good Fri 03/04).

Suggest a corrected BigQuery WHERE sub-clause (no WHERE keyword, no semicolon) that is more likely to find data.
Reply with ONLY the WHERE sub-clause, nothing else.`;

  const where2 = (await askClaude(retryPrompt)).trim().replace(/;$/, "").trim();
  console.log(`[bill-ling] bacs_files attempt 2 WHERE: ${where2}`);
  const result2 = await attempt(where2);
  if (result2) return { result: result2, warned: false };

  // Both attempts failed
  return {
    result: `I couldn't find any data matching that request. I tried:\n• \`${where1}\`\n• \`${where2}\`\n\nCould you clarify the date or what you're looking for?`,
    warned: true,
  };
}

/**
 * For future dates where no batch has been generated yet, return a forecast
 * based on total_instalments_due vs the 45-day rolling average.
 * Returns null if no instalment data exists for the date range.
 */
async function getPreBatchForecast(whereClause, limit = null, includeGenerated = false) {
  try {
    // Instalment data — by default only batches whose COLLECTION batch hasn't
    // been generated yet. Hargo, 26/05/2026 (post-bank-holiday A00368478
    // bug): the previous filter also required recollection_batch_created_at
    // IS NULL, but the recollection batch is an independent workflow (for
    // previously bounced DDs) — it can be generated days before the new
    // collection batch. Treating recollection-done as "this whole due-date
    // is finished" caused the forecast to skip 29/05 (recollection done
    // 25/05, collection still pending) and jump to 01/06. The forecast is
    // about the NEXT collection batch to generate, so only the collection
    // column gates the row. If includeGenerated=true we surface today's
    // deadline batch even if the data says it's been generated.
    const generatedFilter = includeGenerated
      ? ""
      : "AND collection_batch_created_at IS NULL";
    const forecastSql = `
      SELECT
        due_date,
        total_instalments_due,
        estimated_late_fees_to_apply,
        estimated_direct_debits_bounce,
        estimated_direct_debits_called_for,
        time_to_create_payment_batch,
        time_to_send_payment_file,
        time_to_apply_fees
      FROM \`raylo-production.landing_billington.bacs_monitoring\`
      WHERE total_instalments_due > 0
        ${generatedFilter}
        AND ${whereClause}
      ORDER BY due_date ASC
      ${limit ? `LIMIT ${limit}` : ""}
    `;

    // Average timing from recent completed batches — time columns are HH:MM:SS strings,
    // convert to seconds via TIME_DIFF then back to a display string in JS
    const statsSql = `
      SELECT
        AVG(total_instalments_due) AS avg_instalments,
        AVG(TIME_DIFF(SAFE_CAST(time_to_create_payment_batch AS TIME), TIME '00:00:00', SECOND)) AS avg_create_secs,
        AVG(TIME_DIFF(SAFE_CAST(time_to_send_payment_file AS TIME), TIME '00:00:00', SECOND)) AS avg_send_secs,
        AVG(TIME_DIFF(SAFE_CAST(time_to_apply_fees AS TIME), TIME '00:00:00', SECOND)) AS avg_apply_secs
      FROM \`raylo-production.landing_billington.bacs_monitoring\`
      WHERE (collection_batch_created_at IS NOT NULL OR recollection_batch_created_at IS NOT NULL)
        AND due_date >= DATE_SUB(CURRENT_DATE(), INTERVAL 45 DAY)
        AND total_instalments_due > 0
    `;

    // Data freshness check — detect stale source pipeline
    // If collection_batch_created_at hasn't been updated since the previous working day,
    // the underlying source table (e.g. payment_services anchor) may not be writing new rows,
    // meaning batch status shown here may not reflect reality.
    const freshnessSql = `
      SELECT DATE(MAX(collection_batch_created_at)) AS latest_batch_date
      FROM \`raylo-production.landing_billington.bacs_monitoring\`
      WHERE collection_batch_created_at IS NOT NULL
    `;

    const [[forecastRows], [statsRows], [freshnessRows]] = await Promise.all([
      bigquery.query({ query: forecastSql, location: "EU" }),
      bigquery.query({ query: statsSql, location: "EU" }),
      bigquery.query({ query: freshnessSql, location: "EU" }),
    ]);

    if (!forecastRows.length) return null;

    // Today in London time — used to detect overdue generation deadlines
    const forecastToday = new Date().toLocaleDateString("en-CA", { timeZone: "Europe/London" });

    // Staleness check: if the latest completed batch is before the previous working day,
    // the data pipeline hasn't updated — batch status (especially NULL collection_batch_created_at)
    // may not reflect what was actually generated. Overdue banners could be misleading.
    let stalenessBanner = null;
    const freshnessRow = freshnessRows && freshnessRows[0];
    if (freshnessRow && freshnessRow.latest_batch_date) {
      const latestBatchDate = formatBQValue(freshnessRow.latest_batch_date);
      const expectedLatest = prevWorkingDay(forecastToday);
      if (latestBatchDate < expectedLatest) {
        stalenessBanner = `⚠️ *Data pipeline alert: \`bacs_monitoring\` last batch update was ${fmtDate(latestBatchDate)} — source table may not be writing new data. Batch status and overdue warnings below may not reflect actual state.*`;
        console.warn(`[bill-ling] bacs_monitoring staleness detected: latest batch date is ${latestBatchDate}, expected >= ${expectedLatest}`);
      }
    }

    const num = (v) => {
      if (v === null || v === undefined) return 0;
      if (typeof v === "object" && "value" in v) return Number(v.value);
      return Number(v);
    };

    // Helper: convert seconds → "H:MM:SS" display string
    const secsToHMS = (secs) => {
      if (!secs || secs <= 0) return null;
      const h = Math.floor(secs / 3600);
      const m = Math.floor((secs % 3600) / 60);
      const s = Math.round(secs % 60);
      return h > 0
        ? `${h}:${String(m).padStart(2, "0")}:${String(s).padStart(2, "0")}`
        : `${m}:${String(s).padStart(2, "0")}`;
    };

    const stats = statsRows[0] || {};
    const avgInstalments = num(stats.avg_instalments);
    const avgCreateSecs = num(stats.avg_create_secs);
    const avgSendSecs   = num(stats.avg_send_secs);
    const avgApplySecs  = num(stats.avg_apply_secs);

    // Parse "HH:MM:SS" or "MM:SS" string → seconds
    const parseHMS = (s) => {
      if (!s || s === "null" || s === "0") return 0;
      const parts = s.split(":").map(Number);
      if (parts.length === 3) return parts[0] * 3600 + parts[1] * 60 + parts[2];
      if (parts.length === 2) return parts[0] * 60 + parts[1];
      return 0;
    };

    // For each forecast row, compute genByDate and its previous working day (the due date
    // whose late fees will be applying on the same day as batch generation).
    const genByDates = forecastRows.map((row) => {
      let d = formatBQValue(row.due_date);
      for (let i = 0; i < 3; i++) d = prevWorkingDay(d);
      return d;
    });
    const prevDueDates = [...new Set(genByDates.map((d) => prevWorkingDay(d)))];
    const prevFeesSql = `
      SELECT due_date, time_to_apply_fees, estimated_late_fees_to_apply
      FROM \`raylo-production.landing_billington.bacs_monitoring\`
      WHERE due_date IN (${prevDueDates.map((d) => `'${d}'`).join(",")})
    `;
    const [prevFeeRows] = await bigquery.query({ query: prevFeesSql, location: "EU" });
    const prevFeeMap = {};
    for (const r of prevFeeRows) {
      prevFeeMap[formatBQValue(r.due_date)] = {
        time:  formatBQValue(r.time_to_apply_fees),
        count: num(r.estimated_late_fees_to_apply),
      };
    }

    const blocks = forecastRows.map((row, idx) => {
      const rawDate = formatBQValue(row.due_date);
      const [y, m, d] = rawDate.split("-");
      const displayDate = `${d}/${m}/${y}`;
      const dueDow     = dayOfWeekName(rawDate);
      const prevFlag   = previousDayFlag(rawDate);
      const instCount = num(row.total_instalments_due);

      // Calculate generate-by date: 3 working days before due date
      const genByDate = genByDates[idx];
      const genByDisplay = fmtDate(genByDate);

      // Compare generate-by date against today — flag if the deadline has already passed
      const genByOverdue = genByDate < forecastToday;   // strict: deadline was before today
      const genByToday   = genByDate === forecastToday; // deadline is today

      // Previous due date whose late fees land on the generate-by day
      const prevDueDate   = prevWorkingDay(genByDate);
      const prevFeeEntry  = prevFeeMap[prevDueDate] || {};
      const prevApplyTime = prevFeeEntry.time;
      const prevApplyCount = prevFeeEntry.count || 0;
      const prevApplyDisplay = (prevApplyTime && prevApplyTime !== "null" && prevApplyTime !== "0")
        ? prevApplyTime : null;

      // Size vs average
      const ratio = avgInstalments > 0 ? instCount / avgInstalments : 1;
      const pctAbove = Math.round((ratio - 1) * 100);
      let sizeFlag = null;
      if (ratio >= 1.5)       sizeFlag = `⚠️ +${pctAbove}% above 45-day average — significantly larger than normal`;
      else if (ratio >= 1.15) sizeFlag = `↑ +${pctAbove}% above 45-day average`;
      else if (ratio <= 0.75) sizeFlag = `↓ ${Math.round((1 - ratio) * 100)}% below average`;

      // Identify preceding bank holidays / weekend rollover
      const rollovers = [];
      let checkDate = rawDate;
      for (let i = 0; i < 5; i++) {
        const prev = new Date(checkDate + "T12:00:00Z");
        prev.setUTCDate(prev.getUTCDate() - 1);
        const prevStr = prev.toISOString().slice(0, 10);
        const dow = prev.getUTCDay();
        if (UK_BANK_HOLIDAYS.has(prevStr)) {
          rollovers.push(`${UK_BANK_HOLIDAY_NAMES[prevStr] || prevStr} (${fmtDate(prevStr)})`);
          checkDate = prevStr;
        } else if (dow === 0 || dow === 6) {
          checkDate = prevStr; // step over weekends silently
        } else {
          break;
        }
      }

      // Timing — use row values if populated, otherwise fall back to average from recent batches
      const rawCreate = formatBQValue(row.time_to_create_payment_batch);
      const rawSend   = formatBQValue(row.time_to_send_payment_file);
      const rawApply  = formatBQValue(row.time_to_apply_fees);

      const createSecs = parseHMS(rawCreate !== "null" && rawCreate !== "0" ? rawCreate : null)
                       || avgCreateSecs;
      const sendSecs   = parseHMS(rawSend   !== "null" && rawSend   !== "0" ? rawSend   : null)
                       || avgSendSecs;
      const createAndSendSecs = createSecs + sendSecs;
      const displayCreateAndSend = createAndSendSecs > 0 ? secsToHMS(createAndSendSecs) : null;

      const displayApply = (rawApply && rawApply !== "null" && rawApply !== "0") ? rawApply
                         : secsToHMS(avgApplySecs);

      // Next working day after due date (when fees are applied)
      const applyDay = fmtDate(nextWorkingDay(rawDate));

      // Estimates for current due date
      const estLateFees      = num(row.estimated_late_fees_to_apply);
      const estDDsCalledFor  = num(row.estimated_direct_debits_called_for);

      // ⚠️ on generate-by day if create+send+prev_apply_fees > 4 hours total
      const prevApplySecs      = parseHMS(prevApplyDisplay);
      const totalGenByDaySecs  = createAndSendSecs + prevApplySecs;
      const genByTimeWarning   = prevApplyDisplay && totalGenByDaySecs > 4 * 3600;

      // File generation assessment: create+send vs 4h threshold
      const fileGenOk = createAndSendSecs > 0 && createAndSendSecs < 4 * 3600;
      const fileGenAssessment = createAndSendSecs > 0
        ? (fileGenOk
          ? `✅ No issues expected generating payment file`
          : `⚠️ File generation estimated to take over 4 hours — monitor closely`)
        : null;

      // Generic 'must be generated TODAY' / 'OVERDUE' banners removed —
      // the deadline date is already shown on its own line below ('Batch
      // must be generated by: ...') and the volume colour-band conveys
      // operational risk more usefully than a generic urgency tag.

      const volumeIndicator = bacsVolumeIndicator(estDDsCalledFor);

      const lines = [
        `*BACS batch forecast for instalments due on: ${dueDow} ${displayDate}*`,
        prevFlag ? `${prevFlag.emoji} ${prevFlag.label}` : null,
        `Instalments due: #${instCount.toLocaleString("en-GB")}`,
        estDDsCalledFor > 0
          ? `Estimated count of Direct Debits: #${Math.round(estDDsCalledFor).toLocaleString("en-GB")}`
          : null,
        displayCreateAndSend
          ? `Estimated time to create payment batch and send payment file: ${displayCreateAndSend}`
          : null,
        fileGenAssessment,
        rollovers.length > 0 ? `📅 Includes rollovers from: ${rollovers.join(", ")}` : null,
        ``,
        volumeIndicator,
        ``,
        `Batch must be generated by: ${genByDisplay}`,
        prevApplyDisplay
          ? `${applyTimeIndicator(prevApplyDisplay) ? applyTimeIndicator(prevApplyDisplay) + " " : ""}Late payment fees for ${fmtDate(prevDueDate)} also applying on ${genByDisplay} — est.${prevApplyCount > 0 ? ` #${Math.round(prevApplyCount).toLocaleString("en-GB")} fees |` : ""} ${prevApplyDisplay}`
          : null,
        displayApply
          ? `${applyTimeIndicator(displayApply) ? applyTimeIndicator(displayApply) + " " : ""}Estimated time to apply late fees (${applyDay}): ${displayApply}`
          : null,
      ];

      return lines.filter((v) => v !== null).join("\n");
    });

    const output = blocks.join("\n\n---\n\n");
    return stalenessBanner ? `${stalenessBanner}\n\n${output}` : output;
  } catch (err) {
    console.error("[bill-ling] getPreBatchForecast error:", err.message);
    return null;
  }
}

/**
 * 3pm cron: send today's batch summary to Hargo.
 */
async function runBacsFileSummary() {
  console.log("[bill-ling] Running 3pm BACS file summary...");
  try {
    const report = await getBacsFileReport("(collection_batch_created_at = CURRENT_DATE() OR recollection_batch_created_at = CURRENT_DATE())");
    const todayDisplay = new Date().toLocaleDateString("en-GB", { timeZone: "Europe/London" });
    const text = report
      ? `*BACS Batch Update — ${todayDisplay}*\n\n${report}`
      : `🚨 *No BACS batch files were created today (${todayDisplay})*\n\nThis could mean one of two things:\n• *Data pipeline issue* — \`bacs_monitoring\` source tables may not be writing new rows (timestamp may appear fresh but data is stale)\n• *Operational issue* — the BACS batch was genuinely not generated today\n\nPlease investigate immediately.`;
    await app.client.chat.postMessage({
      token: SLACK_BOT_TOKEN,
      channel: CHANNELS.DATA_BILLING_UPDATES,
      text,
      mrkdwn: true,
    });
    console.log("[bill-ling] 3pm BACS file summary posted to #data-billing-updates.");
  } catch (err) {
    console.error("[bill-ling] Error running BACS file summary:", err);
    try { await dmHargo(`Error generating BACS batch summary: ${err.message}`); } catch (_) {}
  }
}

// ---------------------------------------------------------------------------
// Generic refresh of a scheduled-alert parent message — shared between the
// immediate update_alert intent handler and the deferred (scheduled) action.
// Reads the parent at parentTs, identifies the report type from its text,
// re-runs the matching generator using the parent's POST DATE as the anchor,
// and edits the parent in place via chat.update.
// Returns { success: bool, alertType: string, reason?: string }.
// ---------------------------------------------------------------------------
async function runUpdateAlertForParent(channel, parentTs) {
  try {
    const parentResp = await app.client.conversations.replies({
      token: SLACK_BOT_TOKEN, channel, ts: parentTs, limit: 1, inclusive: true,
    });
    const parentMsg = parentResp.messages?.[0];
    if (!parentMsg) return { success: false, alertType: null, reason: "parent_not_found" };
    const parentText = parentMsg.text || "";
    const isBotPosted = parentMsg.user === BOT_USER_ID || !!parentMsg.bot_id;
    if (!isBotPosted) return { success: false, alertType: null, reason: "parent_not_bot_posted" };

    // Anchor regenerated data to the parent's post date (Europe/London).
    const parentTsSecs = parseFloat(parentMsg.ts);
    const parentDateObj = !isNaN(parentTsSecs) ? new Date(parentTsSecs * 1000) : new Date();
    const parentIso     = parentDateObj.toLocaleDateString("en-CA", { timeZone: "Europe/London" });
    const parentDisplay = parentDateObj.toLocaleDateString("en-GB", { timeZone: "Europe/London" });

    let newText = null;
    let alertType = "report";
    let bhStillFlagged = null; // bank-holiday: carry flagged agreements so refresh keeps the Fix buttons

    console.log(`[bill-ling] runUpdateAlertForParent: parentTs=${parentTs} parentText="${(parentText || "").slice(0, 240).replace(/\n/g, "\\n")}"`);

    if (/BACS batch forecast for instalments due on/i.test(parentText)) {
      alertType = "BACS batch forecast";
      const targetDueDate = nextWorkingDay(nextWorkingDay(nextWorkingDay(parentIso)));
      let forecast = await getPreBatchForecast(`due_date = '${targetDueDate}'`, 1, /* includeGenerated */ true);
      if (!forecast) forecast = await getPreBatchForecast(`due_date >= '${targetDueDate}'`, 1);
      newText = forecast || "No matching BACS batches found in `bacs_monitoring`.";
    } else if (/BACS Batch Update — |BACS file generated for|No BACS batch files were created today/i.test(parentText)) {
      // Hargo, 27/05/2026: also handle the "🚨 No BACS batch files were
      // created today" stale-pipeline alert. When the operator asks to
      // refresh that alert, re-run today's batch report — only files
      // CREATED today (not files DUE today, which are stale rows from
      // earlier batch generation). Matches the 3pm cron's filter exactly.
      alertType = "BACS batch summary";
      const report = await getBacsFileReport(
        `(collection_batch_created_at = '${parentIso}' OR recollection_batch_created_at = '${parentIso}')`
      );
      newText = report
        ? `*BACS Batch Update — ${parentDisplay}*\n\n${report}`
        : `🚨 *No BACS batch activity found for ${parentDisplay}*\n\nNo files with creation date = ${parentDisplay} and no files with due_date = ${parentDisplay} in \`bacs_monitoring\`. Either the data pipeline is stale or no batch was scheduled for that day.`;
    } else if (/ARUDD:/i.test(parentText)) {
      alertType = "ARUDD report";
      let targetDue = null;
      const chargeMatch = parentText.match(/Charge date:\s*(\d{2})\/(\d{2})\/(\d{4})/);
      if (chargeMatch) targetDue = `${chargeMatch[3]}-${chargeMatch[2]}-${chargeMatch[1]}`;
      else targetDue = prevWorkingDay(parentIso);
      const aruddResult = await buildAruddReport(targetDue);
      newText = aruddResult?.report || null;
    } else if (/Refunds update — /i.test(parentText)) {
      alertType = "refunds update";
      const result = await getRefundsSummary();
      newText = result?.summary || null;
    } else if (/LPF and NODS Email QA|NOSIA|SNOSIA/i.test(parentText)) {
      alertType = "Notices QA report";
      let targetDate = null;
      const headerMatch = parentText.match(/(\d{2})\/(\d{2})\/(\d{4})\s+LPF and NODS/);
      if (headerMatch) targetDate = `${headerMatch[3]}-${headerMatch[2]}-${headerMatch[1]}`;
      else targetDate = prevWorkingDay(parentIso);
      newText = await buildNoticesReport(targetDate);
    } else if (/Bank Holiday Profile Check/i.test(parentText)) {
      alertType = "bank holiday check";
      const result = await buildBankHolidayReportText();
      newText = result?.text || "✅ No instalments falling due on bank holidays.";
      bhStillFlagged = result?.stillFlagged || [];
    }

    if (!newText) return { success: false, alertType: null, reason: "unknown_report_type" };

    // Bank-holiday refresh: rebuild the Fix buttons so a refresh doesn't strip
    // them (and clears them once everything's corrected).
    let updateBlocks = null;
    if (alertType === "bank holiday check") {
      updateBlocks = buildBankHolidayFixBlocks(newText, bhStillFlagged || [])
        || [{ type: "section", text: { type: "mrkdwn", text: newText.slice(0, 3000) } }];
    }
    await app.client.chat.update({
      token: SLACK_BOT_TOKEN,
      channel,
      ts: parentTs,
      text: newText,
      ...(updateBlocks ? { blocks: updateBlocks } : {}),
      mrkdwn: true,
      link_names: true,
      unfurl_links: false,
      unfurl_media: false,
    });
    console.log(`[bill-ling] Updated parent ${alertType} at ts=${parentTs}.`);
    return { success: true, alertType };
  } catch (err) {
    console.error(`[bill-ling] runUpdateAlertForParent error (parentTs=${parentTs}):`, err.message);
    return { success: false, alertType: null, reason: err.message };
  }
}

// ---------------------------------------------------------------------------
// Notices QA — LPF/NODS + NOSIA/SNOSIA daily report
// ---------------------------------------------------------------------------

/**
 * Build the LPF + NODS section of the notices report.
 * Queries `nods_monitoring` for the given date.
 */
async function buildNodsReport(targetDate) {
  const rows = await runBigQueryRaw(`
    SELECT
      lpf_transaction_count,
      nods_email_count,
      nods_letter_count,
      total_nods_count,
      nods_coverage_pct
    FROM \`raylo-production.landing_billington.nods_monitoring\`
    WHERE late_payment_fee_transaction_date = '${targetDate}'
    LIMIT 1
  `);
  if (!rows.length) return null;
  const r = rows[0];
  const lpf       = Number(formatBQValue(r.lpf_transaction_count))  || 0;
  const emails    = Number(formatBQValue(r.nods_email_count))       || 0;
  const letters   = Number(formatBQValue(r.nods_letter_count))      || 0;
  const total     = Number(formatBQValue(r.total_nods_count))       || 0;
  const coverage  = Number(formatBQValue(r.nods_coverage_pct))      || 0;
  return { lpf, emails, letters, total, coverage };
}

/**
 * Build the NOSIA + SNOSIA section of the notices report.
 * Queries `nosia_snosia_monitoring` for the given date.
 */
async function buildNosiaSnosiaReport(targetDate) {
  const rows = await runBigQueryRaw(`
    SELECT notice_type, triggered, sent, pending, failed
    FROM \`raylo-production.landing_billington.nosia_snosia_monitoring\`
    WHERE notice_due_date = '${targetDate}'
    ORDER BY notice_type
  `);
  if (!rows.length) return null;
  const notices = rows.map(r => ({
    type:      formatBQValue(r.notice_type) || "UNKNOWN",
    triggered: Number(formatBQValue(r.triggered)) || 0,
    sent:      Number(formatBQValue(r.sent))      || 0,
    pending:   Number(formatBQValue(r.pending))    || 0,
    failed:    Number(formatBQValue(r.failed))     || 0,
  }));
  // Add cancelled = triggered - sent - pending - failed
  for (const n of notices) {
    n.cancelled = Math.max(0, n.triggered - n.sent - n.pending - n.failed);
  }
  return notices;
}

/**
 * Get NOSIA/SNOSIA agreements that were NOT successfully sent for a given date.
 * Returns array of { agreement_id, notice_type, status }.
 */
async function getNosiaSnosiaNotSent(targetDate) {
  const rows = await runBigQueryRaw(`
    SELECT
      client_application_reference AS agreement_id,
      CASE WHEN message_definition_id = 63 THEN 'NOSIA' WHEN message_definition_id = 64 THEN 'SNOSIA' END AS notice_type,
      CASE current_status
        WHEN 0 THEN 'Pending'
        WHEN 2 THEN 'Failed'
        WHEN 3 THEN 'Cancelled'
        WHEN 7 THEN 'Queued'
        ELSE CONCAT('Status ', CAST(current_status AS STRING))
      END AS status
    FROM \`raylo-production.dbt_production.stg_landing_sentinel_collections__messages\`
    WHERE message_definition_id IN (63, 64)
      AND DATE(created_at) = '${targetDate}'
      AND current_status NOT IN (1, 4)
    ORDER BY notice_type, status, agreement_id
  `);
  return rows.map(r => ({
    agreement_id: formatBQValue(r.agreement_id),
    notice_type:  formatBQValue(r.notice_type),
    status:       formatBQValue(r.status),
  }));
}

/**
 * Get agreements that had an LPF but no NODS email/letter was sent on the given date.
 * Returns array of { agreement_id }.
 */
async function getNodsNotCovered(targetDate) {
  // Email-only query — the letters table is excluded here because:
  // (a) NODS delivery is email-driven; letter counts from nods_monitoring cover
  //     the letter path in aggregate, and (b) the letters staging table has
  //     intermittent permission/existence issues that would crash the drill-down.
  const emailOnlySql = `
    SELECT l.agreement_id
    FROM (
      SELECT DISTINCT agreement_id
      FROM \`raylo-production.dbt_production.stg_landing_sentinel_s3db01__transactions\`
      WHERE transaction_type_id = 49
        AND DATE(transaction_date) = '${targetDate}'
    ) l
    LEFT JOIN (
      SELECT DISTINCT client_application_reference AS agreement_id
      FROM \`raylo-production.dbt_production.stg_landing_sentinel_collections__messages\`
      WHERE Message_Definition_ID IN (56, 65)
        AND current_status IN (1, 4)
        AND DATE(created_at) = '${targetDate}'
    ) e ON e.agreement_id = l.agreement_id
    WHERE e.agreement_id IS NULL
    ORDER BY l.agreement_id
  `;
  const rows = await runBigQueryRaw(emailOnlySql);
  return rows.map(r => ({ agreement_id: formatBQValue(r.agreement_id) }));
}

/** SQL template for NOSIA/SNOSIA not-sent drill-down (for user to run in BigQuery console). */
function nosiaSnosiaNotSentSQL(targetDate) {
  return `SELECT
  client_application_reference AS agreement_id,
  CASE WHEN message_definition_id = 63 THEN 'NOSIA' WHEN message_definition_id = 64 THEN 'SNOSIA' END AS notice_type,
  CASE current_status
    WHEN 0 THEN 'Pending' WHEN 2 THEN 'Failed' WHEN 3 THEN 'Cancelled' WHEN 7 THEN 'Queued'
    ELSE CONCAT('Status ', CAST(current_status AS STRING))
  END AS status
FROM \`raylo-production.dbt_production.stg_landing_sentinel_collections__messages\`
WHERE message_definition_id IN (63, 64)
  AND DATE(created_at) = '${targetDate}'
  AND current_status NOT IN (1, 4)
ORDER BY notice_type, status, agreement_id`;
}

/** SQL template for NODS not-covered drill-down (email-only, letters excluded). */
function nodsNotCoveredSQL(targetDate) {
  return `SELECT l.agreement_id
FROM (
  SELECT DISTINCT agreement_id
  FROM \`raylo-production.dbt_production.stg_landing_sentinel_s3db01__transactions\`
  WHERE transaction_type_id = 49 AND DATE(transaction_date) = '${targetDate}'
) l
LEFT JOIN (
  SELECT DISTINCT client_application_reference AS agreement_id
  FROM \`raylo-production.dbt_production.stg_landing_sentinel_collections__messages\`
  WHERE Message_Definition_ID IN (56, 65) AND current_status IN (1, 4) AND DATE(created_at) = '${targetDate}'
) e ON e.agreement_id = l.agreement_id
WHERE e.agreement_id IS NULL
ORDER BY l.agreement_id`;
}

/**
 * SQL for the notice-recipient customer-data completeness check (Hargo,
 * 25/06/2026). For every agreement that received a NODS / NOSIA / SNOSIA on
 * the date, join core_agreements -> the Sentinel customer table on customer_id
 * and flag any with a missing address line 1, postcode, name or email.
 * "missing" = NULL or blank; "name" = no first name, surname OR company at all.
 * Table: ...s3custdb__customer_table (Hargo's specified table — a materialised
 * BASE TABLE Billington can query). The sibling ...__customers is a VIEW over
 * airbyte_anchor_s3custdb.CustomerTable, which Billington's service account
 * can't access (Access Denied), so we do NOT use it.
 * Only agreements that ARE in the customer table are checked (inner join) — an
 * agreement not present isn't a "field null in the customer table".
 */
function noticeCustomerDataGapsSQL(targetDate) {
  return `WITH notice_ags AS (
  SELECT DISTINCT agreement_id AS agreement_id
  FROM \`raylo-production.dbt_production.stg_landing_sentinel_s3db01__transactions\`
  WHERE transaction_type_id = 49 AND DATE(transaction_date) = '${targetDate}'
  UNION DISTINCT
  SELECT DISTINCT client_application_reference
  FROM \`raylo-production.dbt_production.stg_landing_sentinel_collections__messages\`
  WHERE message_definition_id IN (56, 65, 63, 64) AND DATE(created_at) = '${targetDate}'
),
cust AS (
  SELECT customer_id, address1, postcode, email, first_name, surname, company,
    ROW_NUMBER() OVER (PARTITION BY customer_id ORDER BY amend_date DESC) AS rn
  FROM \`raylo-production.dbt_production.stg_landing_sentinel_s3custdb__customer_table\`
)
SELECT
  na.agreement_id,
  ARRAY_TO_STRING([
    IF(c.address1 IS NULL OR TRIM(c.address1) = '', 'address line 1', NULL),
    IF(c.postcode IS NULL OR TRIM(c.postcode) = '', 'postcode', NULL),
    IF(COALESCE(NULLIF(TRIM(c.first_name), ''), NULLIF(TRIM(c.surname), ''), NULLIF(TRIM(c.company), '')) IS NULL, 'name', NULL),
    IF(c.email IS NULL OR TRIM(c.email) = '', 'email', NULL)
  ], ', ') AS missing_fields
FROM notice_ags na
JOIN \`raylo-production.dbt_production.core_agreements\` ca ON ca.agreement_id = na.agreement_id
JOIN cust c ON c.customer_id = ca.customer_id AND c.rn = 1
WHERE c.address1 IS NULL OR TRIM(c.address1) = ''
   OR c.postcode IS NULL OR TRIM(c.postcode) = ''
   OR c.email IS NULL OR TRIM(c.email) = ''
   OR COALESCE(NULLIF(TRIM(c.first_name), ''), NULLIF(TRIM(c.surname), ''), NULLIF(TRIM(c.company), '')) IS NULL
ORDER BY na.agreement_id`;
}

/**
 * Run the notice-recipient customer-data completeness check.
 * Returns [{ agreement_id, missing }] where missing is a comma-separated string
 * of the fields that are null/blank (or "no customer record").
 */
async function getNoticeCustomerDataGaps(targetDate) {
  const rows = await runBigQueryRaw(noticeCustomerDataGapsSQL(targetDate));
  return rows.map(r => ({
    agreement_id: formatBQValue(r.agreement_id),
    missing: formatBQValue(r.missing_fields),
  }));
}

/**
 * Parse how many weeks back the user wants for a historical notices gap request.
 * "last 1 month" → 4, "last 3 months" → 13, "last 6 weeks" → 6, "last few months" → 12
 */
function parseNoticesWeeksBack(text) {
  const monthMatch = text.match(/\blast\s+(\d+)\s+months?\b/i);
  if (monthMatch) return Math.max(1, Math.round(parseInt(monthMatch[1], 10) * 4.33));
  const weekMatch = text.match(/\blast\s+(\d+)\s+weeks?\b/i);
  if (weekMatch) return Math.max(1, parseInt(weekMatch[1], 10));
  if (/\blast\s+few\s+months?\b/i.test(text)) return 12;
  return 12;
}

/**
 * Build a historical notices gap report: agreements that had LPFs applied but
 * no NODS sent, or had NOSIA/SNOSIA triggered but not successfully sent,
 * over the past N weeks (default 12).
 */
async function buildHistoricalNoticesGaps(weeksBack = 12) {
  const sinceDate = new Date();
  sinceDate.setDate(sinceDate.getDate() - weeksBack * 7);
  const since = sinceDate.toISOString().slice(0, 10);
  const today = new Date().toLocaleDateString("en-CA", { timeZone: "Europe/London" });

  const [nodsRows, nosiaRows] = await Promise.all([
    // NODS gaps: LPF applied (type_id 49) but no NODS email/letter sent
    runBigQueryRaw(`
      SELECT l.agreement_id, DATE(l.transaction_date) AS lpf_date
      FROM (
        SELECT DISTINCT agreement_id, MIN(transaction_date) AS transaction_date
        FROM \`raylo-production.dbt_production.stg_landing_sentinel_s3db01__transactions\`
        WHERE transaction_type_id = 49
          AND DATE(transaction_date) >= '${since}'
          AND DATE(transaction_date) <= '${today}'
        GROUP BY agreement_id
      ) l
      LEFT JOIN (
        SELECT DISTINCT client_application_reference AS agreement_id
        FROM \`raylo-production.dbt_production.stg_landing_sentinel_collections__messages\`
        WHERE Message_Definition_ID IN (56, 65)
          AND current_status IN (1, 4)
          AND DATE(created_at) >= '${since}'
      ) e ON e.agreement_id = l.agreement_id
      WHERE e.agreement_id IS NULL
      ORDER BY lpf_date DESC, l.agreement_id
    `),
    // NOSIA/SNOSIA gaps: triggered but failed/cancelled/pending
    runBigQueryRaw(`
      SELECT
        client_application_reference AS agreement_id,
        CASE WHEN message_definition_id = 63 THEN 'NOSIA' WHEN message_definition_id = 64 THEN 'SNOSIA' END AS notice_type,
        DATE(created_at) AS triggered_date,
        CASE current_status
          WHEN 0 THEN 'Pending'
          WHEN 2 THEN 'Failed'
          WHEN 3 THEN 'Cancelled'
          WHEN 7 THEN 'Queued'
          ELSE CONCAT('Status ', CAST(current_status AS STRING))
        END AS status
      FROM \`raylo-production.dbt_production.stg_landing_sentinel_collections__messages\`
      WHERE message_definition_id IN (63, 64)
        AND DATE(created_at) >= '${since}'
        AND current_status NOT IN (1, 4)
      ORDER BY triggered_date DESC, notice_type, agreement_id
    `),
  ]);

  const sinceFmt = fmtDate(since);
  const lines = [`*Historical Notices Coverage Gaps — ${sinceFmt} to today*\n`];

  // NODS section
  lines.push(`*NODS (LPF applied, no NODS email/letter sent)*`);
  if (nodsRows.length === 0) {
    lines.push(`✅ No gaps found — all LPF agreements received NODS.`);
  } else {
    lines.push(`❌ *${nodsRows.length} agreement${nodsRows.length > 1 ? "s" : ""} with LPF but no NODS:*`);
    const preview = nodsRows.slice(0, 20);
    for (const r of preview) {
      lines.push(`  › ${formatBQValue(r.agreement_id)} — LPF on ${fmtDate(formatBQValue(r.lpf_date))}`);
    }
    if (nodsRows.length > 20) lines.push(`  ...and ${nodsRows.length - 20} more`);
  }

  lines.push(``);

  // NOSIA/SNOSIA section
  lines.push(`*NOSIA / SNOSIA (triggered but not successfully sent)*`);
  if (nosiaRows.length === 0) {
    lines.push(`✅ No failures found.`);
  } else {
    lines.push(`❌ *${nosiaRows.length} record${nosiaRows.length > 1 ? "s" : ""} not successfully sent:*`);
    const preview = nosiaRows.slice(0, 20);
    for (const r of preview) {
      lines.push(`  › ${formatBQValue(r.agreement_id)} — ${formatBQValue(r.notice_type)} — ${formatBQValue(r.status)} — ${fmtDate(formatBQValue(r.triggered_date))}`);
    }
    if (nosiaRows.length > 20) lines.push(`  ...and ${nosiaRows.length - 20} more`);
  }

  return lines.join("\n");
}

/**
 * Build the full Notices QA report (LPF/NODS + NOSIA/SNOSIA) for a given date.
 */
async function buildNoticesReport(targetDate) {
  const dateFmt = fmtDate(targetDate);
  // Fetch NODS and NOSIA/SNOSIA sections independently so one failure doesn't kill the other
  const [nodsResult, nosiaResult] = await Promise.allSettled([
    buildNodsReport(targetDate),
    buildNosiaSnosiaReport(targetDate),
  ]);
  const nods  = nodsResult.status  === "fulfilled" ? nodsResult.value  : null;
  const nosia = nosiaResult.status === "fulfilled" ? nosiaResult.value : null;
  if (nodsResult.status  === "rejected") console.error("[bill-ling] buildNodsReport error:", nodsResult.reason?.message);
  if (nosiaResult.status === "rejected") console.error("[bill-ling] buildNosiaSnosiaReport error:", nosiaResult.reason?.message);

  const sections = [];

  // --- LPF and NODS ---
  if (nods) {
    let nodsSection =
      `*${dateFmt} LPF and NODS Email QA*\n\n` +
      `Late payment fees applied total: ${nods.lpf.toLocaleString("en-GB")}\n` +
      `NODS emails triggered total: ${nods.emails.toLocaleString("en-GB")}`;
    if (nods.letters > 0) {
      nodsSection += `\nNODS letters triggered total: ${nods.letters.toLocaleString("en-GB")}`;
    }
    nodsSection += `\n\nCoverage: ${Math.round(nods.coverage)}%`;
    if (nods.coverage >= 100) {
      nodsSection += `\n\n✅ NODS: all sent successfully.`;
    } else {
      const missing = nods.lpf - nods.total;
      const icon = nods.coverage >= 95 ? "⚠️" : "🚨";
      nodsSection += `\n\n${icon} NODS: ${missing.toLocaleString("en-GB")} notice${missing === 1 ? "" : "s"} missing (${Math.round(nods.coverage)}% coverage).`;
      // Drill-down: list agreements if < 10, provide query if >= 10
      try {
        const notCovered = await getNodsNotCovered(targetDate);
        if (notCovered.length > 0 && notCovered.length < 10) {
          nodsSection += `\n` + notCovered.map(r => `  › ${r.agreement_id}`).join("\n");
        } else if (notCovered.length >= 10) {
          nodsSection += `\n${notCovered.length} agreements without NODS. Run in BigQuery:\n\`\`\`${nodsNotCoveredSQL(targetDate)}\`\`\``;
        }
      } catch (err) {
        console.error("[bill-ling] NODS drill-down error:", err.message);
      }
    }
    sections.push(nodsSection);
  } else {
    sections.push(`*${dateFmt} LPF and NODS Email QA*\n\nNo NODS data available for today.`);
  }

  // --- NOSIA and SNOSIA ---
  if (nosia && nosia.length > 0) {
    const totalTriggered = nosia.reduce((s, n) => s + n.triggered, 0);
    let nosiaSection = `*${dateFmt} NOSIA and SNOSIA Email QA*\n\nNotice dates applied total: ${totalTriggered.toLocaleString("en-GB")}`;

    for (const n of nosia) {
      nosiaSection +=
        `\n\n${n.type} emails triggered total: ${n.triggered.toLocaleString("en-GB")}\n` +
        `Sent: ${n.sent.toLocaleString("en-GB")}\n` +
        `Failed: ${n.failed.toLocaleString("en-GB")}\n` +
        `Pending: ${n.pending.toLocaleString("en-GB")}\n` +
        `Cancelled: ${n.cancelled.toLocaleString("en-GB")}`;
    }

    // Per-type status flags
    const statusLines = [];
    const totalNotSent = nosia.reduce((s, n) => s + (n.triggered - n.sent), 0);
    for (const n of nosia) {
      const notSent = n.triggered - n.sent;
      if (n.failed > 0) {
        statusLines.push(`🚨 ${n.type}: ${n.failed.toLocaleString("en-GB")} failed.`);
      } else if (n.pending > 0) {
        statusLines.push(`⚠️ ${n.type}: ${n.pending.toLocaleString("en-GB")} still pending.`);
      } else if (notSent > 0) {
        statusLines.push(`⚠️ ${n.type}: ${notSent.toLocaleString("en-GB")} not sent.`);
      } else if (n.sent === n.triggered && n.triggered > 0) {
        statusLines.push(`✅ ${n.type}: all sent successfully.`);
      } else if (n.triggered === 0) {
        statusLines.push(`${n.type}: no notices triggered.`);
      }
    }
    if (statusLines.length) {
      nosiaSection += "\n\n" + statusLines.join("\n");
    }

    // Drill-down if any not sent
    if (totalNotSent > 0) {
      try {
        const notSentRows = await getNosiaSnosiaNotSent(targetDate);
        if (notSentRows.length > 0 && notSentRows.length < 10) {
          nosiaSection += "\n";
          for (const r of notSentRows) {
            nosiaSection += `\n  › ${r.agreement_id} (${r.notice_type}, ${r.status})`;
          }
        } else if (notSentRows.length >= 10) {
          nosiaSection += `\n${notSentRows.length} agreements not sent. Run in BigQuery:\n\`\`\`${nosiaSnosiaNotSentSQL(targetDate)}\`\`\``;
        }
      } catch (err) {
        console.error("[bill-ling] NOSIA/SNOSIA drill-down error:", err.message);
      }
    }
    sections.push(nosiaSection);
  } else {
    sections.push(`*${dateFmt} NOSIA and SNOSIA Email QA*\n\nNo NOSIA/SNOSIA data available for today.`);
  }

  // --- Notice recipients: customer data completeness (Hargo, 25/06/2026) ---
  // For every agreement that got a NODS/NOSIA/SNOSIA today, check the Sentinel
  // customer record has address line 1, postcode, name and email. ≤10 missing →
  // list them for remediation; >10 → give the BigQuery query (same rule as
  // emails-not-sent). A failure here never blocks the rest of the report.
  try {
    const gaps = await getNoticeCustomerDataGaps(targetDate);
    let custSection = `*${dateFmt} Notice recipients — customer data completeness*`;
    if (gaps.length === 0) {
      custSection += `\n\n✅ All notice recipients have a name, address line 1, postcode and email on file.`;
    } else if (gaps.length <= 10) {
      custSection += `\n\n⚠️ ${gaps.length} notice recipient${gaps.length === 1 ? "" : "s"} with missing customer data — flag for remediation:`;
      custSection += `\n` + gaps.map(g => `  › ${g.agreement_id} — missing: ${g.missing}`).join("\n");
    } else {
      custSection += `\n\n🚨 ${gaps.length} notice recipients with missing customer data (address line 1 / postcode / name / email). Run in BigQuery:\n\`\`\`${noticeCustomerDataGapsSQL(targetDate)}\`\`\``;
    }
    sections.push(custSection);
  } catch (err) {
    console.error("[bill-ling] notice customer-data completeness error:", err.message);
    sections.push(`*${dateFmt} Notice recipients — customer data completeness*\n\n⚠️ Check skipped: ${err.message}`);
  }

  return sections.join("\n\n---\n\n");
}

/**
 * Decide which action buttons a Notices QA report should carry (Hargo,
 * 23/06/2026):
 *   • Refresh report — whenever the figures don't match (any ⚠️/🚨 in the
 *     report), so an operator can re-pull after the downstream models catch up.
 *   • Remediate notices — when there are missing NODS notices listed
 *     individually (1–9 agreements, i.e. the remediable volume). 10+ is left to
 *     the BigQuery query the report already prints (manual / bulk).
 */
async function computeNoticesButtonState(reportText, reportDate) {
  const anyMismatch = /⚠️|🚨/.test(reportText || "");
  let nodsMissing = [];
  if (anyMismatch) {
    try { nodsMissing = await getNodsNotCovered(reportDate); } catch (_) { nodsMissing = []; }
  }
  return {
    showRefresh: anyMismatch,
    showRemediate: nodsMissing.length >= 1 && nodsMissing.length <= 10,
    nodsMissingCount: nodsMissing.length,
  };
}

/**
 * Build Slack blocks for a Notices QA report: the report text chunked into
 * section blocks (≤3000 chars each) plus a conditional actions block.
 */
function buildNoticesBlocks(reportText, { date, showRefresh, showRemediate }) {
  const blocks = [];
  const lines = (reportText || "").split("\n");
  let buf = "";
  const flush = () => { if (buf) { blocks.push({ type: "section", text: { type: "mrkdwn", text: buf.slice(0, 3000) } }); buf = ""; } };
  for (const line of lines) {
    if (buf && (buf.length + 1 + line.length) > 2900) flush();
    buf = buf ? buf + "\n" + line : line;
  }
  flush();
  const elements = [];
  if (showRefresh) {
    elements.push({
      type: "button",
      text: { type: "plain_text", text: "🔄 Refresh report", emoji: true },
      action_id: "btn_notices_refresh",
      value: JSON.stringify({ date }),
    });
  }
  if (showRemediate) {
    elements.push({
      type: "button",
      text: { type: "plain_text", text: "🩹 Remediate notices", emoji: true },
      style: "primary",
      action_id: "btn_notices_remediate",
      value: JSON.stringify({ date }),
      confirm: {
        title: { type: "plain_text", text: "Remediate missing NODS?" },
        text: { type: "mrkdwn", text: "For each missing-NODS agreement, checks the Audits/NODS inbox for a sent 'Notice of default sums' email. Where it's missing, posts SetTeamStatus(532) to refire the NODS. Skips any already sent, or whose LPF was reversed the same day." },
        confirm: { type: "plain_text", text: "Remediate" },
        deny: { type: "plain_text", text: "Cancel" },
      },
    });
  }
  if (elements.length) blocks.push({ type: "actions", elements });
  return blocks;
}

// Track the latest Notices QA message so we can update it later
let lastNoticesMessage = { ts: null, channel: null, reportDate: null };

/**
 * 3pm cron: post today's Notices QA (LPF/NODS + NOSIA/SNOSIA) to #data-billing-updates.
 */
async function runNoticesCron() {
  console.log("[bill-ling] Running 3pm Notices QA report...");
  try {
    const todayStr = new Date().toLocaleDateString("en-CA", { timeZone: "Europe/London" });
    const report = await buildNoticesReport(todayStr);
    const postArgs = {
      token: SLACK_BOT_TOKEN,
      channel: CHANNELS.DATA_BILLING_UPDATES,
      text: report,
      mrkdwn: true,
      unfurl_links: false,
      unfurl_media: false,
    };
    // Add Refresh / Remediate buttons only when the figures don't match. The
    // all-clear happy path stays plain text (unchanged). Defensive: any block
    // failure falls back to the plain-text post above.
    try {
      if (INTERACTIVE_BUTTONS_ENABLED) {
        const st = await computeNoticesButtonState(report, todayStr);
        if (st.showRefresh || st.showRemediate) {
          postArgs.blocks = buildNoticesBlocks(report, { date: todayStr, ...st });
        }
      }
    } catch (e) { console.error("[bill-ling] notices button build failed:", e.message); }
    const result = await app.client.chat.postMessage(postArgs);
    lastNoticesMessage = { ts: result.ts, channel: CHANNELS.DATA_BILLING_UPDATES, reportDate: todayStr };
    console.log("[bill-ling] Notices QA report posted to #data-billing-updates (ts: " + result.ts + ").");
  } catch (err) {
    console.error("[bill-ling] Notices QA cron error:", err.message);
    try { await dmHargo(`Error generating Notices QA report: ${err.message}`); } catch (_) {}
  }
}

/**
 * Find today's Notices QA message in #data-billing-updates.
 */
async function findTodaysNoticesMessage() {
  if (lastNoticesMessage.ts && lastNoticesMessage.channel) return lastNoticesMessage;
  try {
    const todayStr = new Date().toLocaleDateString("en-CA", { timeZone: "Europe/London" });
    const isBST = new Date().toLocaleString("en-GB", { timeZone: "Europe/London", timeZoneName: "short" }).includes("BST");
    const offset = isBST ? "+01:00" : "+00:00";
    const londonMidnight = new Date(todayStr + "T00:00:00" + offset);
    const oldest = String(Math.floor(londonMidnight.getTime() / 1000));
    const history = await app.client.conversations.history({
      token: SLACK_BOT_TOKEN,
      channel: CHANNELS.DATA_BILLING_UPDATES,
      oldest,
      limit: 50,
    });
    const noticesMsg = (history.messages || []).find(
      m => /LPF and NODS Email QA/i.test(m.text || "") && (m.user === BOT_USER_ID || m.bot_id)
    );
    if (noticesMsg) {
      lastNoticesMessage = { ts: noticesMsg.ts, channel: CHANNELS.DATA_BILLING_UPDATES, reportDate: todayStr };
      console.log(`[bill-ling] Found today's Notices QA message (ts: ${noticesMsg.ts})`);
      return lastNoticesMessage;
    }
  } catch (err) {
    console.error("[bill-ling] Error searching for today's Notices QA message:", err.message);
  }
  return null;
}

/**
 * Search #data-billing-updates for a Notices QA message posted on a specific date.
 * @param {string} targetDate — YYYY-MM-DD of the date the message was POSTED
 */
async function findNoticesMessageByDate(targetDate) {
  try {
    const isBST = new Date(`${targetDate}T12:00:00Z`).toLocaleString("en-GB", { timeZone: "Europe/London", timeZoneName: "short" }).includes("BST");
    const offset = isBST ? "+01:00" : "+00:00";
    const dayStart = new Date(`${targetDate}T00:00:00${offset}`);
    const dayEnd = new Date(`${targetDate}T23:59:59${offset}`);
    const oldest = String(Math.floor(dayStart.getTime() / 1000));
    const latest = String(Math.floor(dayEnd.getTime() / 1000));
    console.log(`[bill-ling] Searching for Notices QA message on ${targetDate} (oldest: ${oldest}, latest: ${latest})`);
    const history = await app.client.conversations.history({
      token: SLACK_BOT_TOKEN,
      channel: CHANNELS.DATA_BILLING_UPDATES,
      oldest,
      latest,
      limit: 50,
    });
    const noticesMsg = (history.messages || []).find(
      m => /LPF and NODS Email QA/i.test(m.text || "") && (m.user === BOT_USER_ID || m.bot_id)
    );
    if (noticesMsg) {
      // Extract the report date from the message text (e.g. "14/04/2026 LPF and NODS Email QA")
      const dateMatch = (noticesMsg.text || "").match(/(\d{2})\/(\d{2})\/(\d{4})\s+LPF/);
      let reportDate = targetDate;
      if (dateMatch) {
        reportDate = `${dateMatch[3]}-${dateMatch[2]}-${dateMatch[1]}`;
      }
      console.log(`[bill-ling] Found Notices QA message from ${targetDate} (ts: ${noticesMsg.ts}, reportDate: ${reportDate})`);
      return { ts: noticesMsg.ts, channel: CHANNELS.DATA_BILLING_UPDATES, reportDate };
    }
    console.log(`[bill-ling] No Notices QA message found for ${targetDate}`);
  } catch (err) {
    console.error(`[bill-ling] Error searching for Notices QA on ${targetDate}:`, err.message);
  }
  return null;
}

/**
 * Refresh a Notices QA message. If targetPostDate is provided, finds that date's message.
 * Updates in-place via chat.update and posts a thread reply confirming the edit.
 */
async function refreshNoticesMessage(targetPostDate, explicitTs = null, explicitChannel = null, explicitReportDate = null) {
  let noticesMsg;
  if (explicitTs) {
    noticesMsg = { ts: explicitTs, channel: explicitChannel, reportDate: explicitReportDate };
  } else {
    noticesMsg = targetPostDate
      ? await findNoticesMessageByDate(targetPostDate)
      : await findTodaysNoticesMessage();
  }
  if (!noticesMsg) {
    console.log(`[bill-ling] No Notices QA message found to refresh${targetPostDate ? ` for ${targetPostDate}` : ""}.`);
    return false;
  }
  console.log(`[bill-ling] Refreshing Notices QA report (reportDate: ${noticesMsg.reportDate})...`);
  try {
    const report = await buildNoticesReport(noticesMsg.reportDate);
    const now = new Date().toLocaleTimeString("en-GB", { hour: "2-digit", minute: "2-digit", timeZone: "Europe/London" });
    const editDate = new Date().toLocaleDateString("en-GB", { day: "2-digit", month: "2-digit", year: "numeric", timeZone: "Europe/London" });
    const updatedReport = report + `\n\n_Updated ${editDate} at ${now} with latest data._`;
    const updateArgs = {
      token: SLACK_BOT_TOKEN,
      channel: noticesMsg.channel,
      ts: noticesMsg.ts,
      text: updatedReport,
      mrkdwn: true,
    };
    // Rebuild blocks so the buttons reflect the refreshed figures: keep/show
    // them while there's still a mismatch, drop them once everything's clean.
    try {
      if (INTERACTIVE_BUTTONS_ENABLED) {
        const st = await computeNoticesButtonState(report, noticesMsg.reportDate);
        updateArgs.blocks = buildNoticesBlocks(updatedReport, { date: noticesMsg.reportDate, ...st });
      }
    } catch (e) { console.error("[bill-ling] notices refresh block build failed:", e.message); }
    await app.client.chat.update(updateArgs);
    console.log(`[bill-ling] Notices QA message updated.`);

    // Post a thread reply confirming the edit
    await app.client.chat.postMessage({
      token: SLACK_BOT_TOKEN,
      channel: noticesMsg.channel,
      thread_ts: noticesMsg.ts,
      text: `📝 *Notices QA updated — ${editDate} at ${now}*\nReport refreshed with latest data from BigQuery.`,
      mrkdwn: true,
      unfurl_links: false,
      unfurl_media: false,
    });

    return true;
  } catch (err) {
    console.error("[bill-ling] Notices QA refresh error:", err.message);
    return false;
  }
}

