/**
 * Dry-run preview of the daily hire agreement audit post. Runs the same
 * query + dedup as the real cron, then renders the messages back to the
 * caller (DM or thread) WITHOUT posting to #collab-hire-agreement-audit-updates.
 *
 * Tagging is muted (`<!@CHARLOTTE>` rendered as plain @charlotte.platt) so
 * the dry-run doesn't ping her.
 *
 * @param {object} args
 * @param {string} args.channel  — channel/DM to post the preview into
 * @param {string} args.thread_ts — optional thread to post into
 */
async function runHireAgreementAuditDryRun({ channel, thread_ts }) {
  const allCandidates = await queryHireAgreementAuditCandidates();
  const fresh = selectHireAgreementAuditCandidatesForToday(allCandidates);
  const regulatedCount   = fresh.filter(c => c.isRegulated === true).length;
  const unregulatedCount = fresh.filter(c => c.isRegulated === false).length;
  const header = `*Hire agreement audit — DRY RUN preview*\n` +
    `Unique templates from BQ: ${new Set(allCandidates.map(c => c.template)).size}. Today's pick: ${fresh.length} (${regulatedCount} regulated, ${unregulatedCount} unregulated).\n` +
    `Real post fires at 13:00 London Mon–Fri to <#${CHANNELS.HIRE_AGREEMENT_AUDIT}>.` +
    (fresh.length === 0 ? `\n_No templates would post today._` : ` Charlotte's ping is muted in this preview.`);
  await app.client.chat.postMessage({
    token: SLACK_BOT_TOKEN,
    channel,
    thread_ts,
    text: header,
    mrkdwn: true,
    unfurl_links: false,
    unfurl_media: false,
  });
  // Per-candidate post mirrors the production format (postDailyHireAgreementAudits)
  // including the Anchor validation block.
  for (const c of fresh) {
    const fmtMoney = (v) => (v === null || v === undefined) ? "(unknown)" : `£${Number(v).toFixed(2)}`;
    const regulatedLabel = c.isRegulated ? "regulated (consumer)" : "unregulated (business)";
    const termLabel = c.termLength != null ? `${c.termLength}mo (${c.termLengthGroup})` : (c.termLengthGroup || "(unknown)");

    // Anchor validation — same logic as production. No PII in output.
    let validationLines = [];
    try {
      // Fetch missing hire-agreement fields (registered_address etc.) via
      // a separate query so the user's verbatim SELECT stays untouched.
      const extras = await fetchHireAgreementExtrasForAgreement(c.agreementId);
      if (extras) Object.assign(c, extras);
      const xml = await getAgreementFromAnchor(c.agreementId);
      const anchorFields = extractAnchorAuditFields(xml);
      const results = validateAgreementVsAnchor(c, anchorFields);
      const scored = results.filter(r => !r.deferred);
      const passes = scored.filter(r => r.ok).length;
      validationLines = [
        ``,
        `*Anchor validation:* ${passes}/${scored.length} pass`,
        ...results.map(r => r.deferred
          ? `  ⏳ ${r.label}`
          : `  ${r.ok ? "✅" : "❌"} ${r.label}${r.ok ? " — matches Anchor" : " — *mismatch*"}`),
      ];
    } catch (err) {
      validationLines = [``, `⚠️ Anchor validation skipped: ${err.message}`];
    }

    const text =
      `*Template* \`${c.template}\`  —  *${regulatedLabel}*\n` +
      `• Newest agreement ID: \`${c.agreementId}\`\n` +
      `• Selected as: \`${c.selectionBasis || "template rotation"}\`\n` +
      `• Product: \`${c.productDisplayName ?? "(unknown)"}\`\n` +
      `• Term length: \`${termLabel}\`\n` +
      `• Business type: \`${c.structureType ?? "(none)"}\`\n` +
      `• Insurance: \`${c.orderHasInsurance ? "yes" : "no"}\`\n` +
      `• PricePlan recurring (incl. tax): ${fmtMoney(c.pricePlanRecurringAmountIncludingTax)}\n` +
      `• Agreement started: \`${c.hireAgreementStartedAt || "(not yet)"}\`` +
      validationLines.join("\n");
    await app.client.chat.postMessage({
      token: SLACK_BOT_TOKEN,
      channel,
      thread_ts,
      text,
      mrkdwn: true,
      unfurl_links: false,
      unfurl_media: false,
    });
  }
  // Mirror the real run's final consolidated ping (muted in preview).
  if (fresh.length > 0) {
    const isOne = fresh.length === 1;
    await app.client.chat.postMessage({
      token: SLACK_BOT_TOKEN,
      channel,
      thread_ts,
      text: `@charlotte.platt — please audit ${isOne ? "the agreement" : `the ${fresh.length} agreements`} above and react ✅ on each message when complete (or ❌ + note in thread if any fails).`,
      mrkdwn: true,
      unfurl_links: false,
      unfurl_media: false,
    });
  }
}

