/**
 * Returns true if Billington has DM'd Hargo about this ticket reference
 * within the last `windowHours` hours, regardless of message type. Used as
 * the global per-ticket cap so a Railway-restart-induced re-poll can't
 * spam the same ref multiple times in a day.
 */
async function hasRecentDmAboutTicket(ticketRef, windowHours = 24) {
  if (!ticketRef) return false;
  return hasRecentBillingtonDm(new RegExp(`\\b${ticketRef.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")}\\b`, "i"), windowHours);
}

/**
 * Returns true if Billington has posted a DM to Hargo within the last
 * `windowHours` hours that matches `pattern`. Used to cap chasing at
 * once per day per ticket+notification-type when the ticket-store JSON
 * has been wiped by a Railway restart and would otherwise re-fire.
 * Fails open (returns false on error) so we'd rather over-DM than
 * silently swallow a real new alert.
 */
async function hasRecentBillingtonDm(pattern, windowHours = 24) {
  try {
    const dmChannelId = await getHargoDMChannel();
    if (!dmChannelId) return false;
    const oldest = String(Math.floor((Date.now() - windowHours * 3600 * 1000) / 1000));
    const recent = await app.client.conversations.history({
      token: SLACK_BOT_TOKEN,
      channel: dmChannelId,
      limit: 200,
      oldest,
    });
    return (recent.messages || []).some(m => {
      const isOurs = (BOT_USER_ID && m.user === BOT_USER_ID) || !!m.bot_id;
      if (!isOurs) return false;
      return pattern.test(m.text || "");
    });
  } catch (err) {
    console.warn("[bill-ling] hasRecentBillingtonDm check failed:", err.message);
    return false;
  }
}

