/**
 * Convert an "in N (minutes|hours)" priority cadence to a fireAt ISO string
 * relative to `from` (a Date). Used for scheduling follow-ups.
 */
function priorityCadenceMs(priority) {
  switch (priority) {
    case "P1": return 15 * 60 * 1000;          // 15 min
    case "P2": return 2 * 60 * 60 * 1000;      // 2 h
    case "P3":
    case "P4":
    case "P5":
    default:   return 24 * 60 * 60 * 1000;     // daily
  }
}

/**
 * Extract a usable plain-text body from a Gmail messages.get full payload.
 */
function extractBody(payload) {
  if (!payload) return "";
  const walk = (part) => {
    if (!part) return "";
    if (part.mimeType === "text/plain" && part.body?.data) {
      return Buffer.from(part.body.data, "base64").toString("utf-8");
    }
    if (Array.isArray(part.parts)) {
      for (const sub of part.parts) {
        const got = walk(sub);
        if (got) return got;
      }
    }
    return "";
  };
  const direct = walk(payload);
  if (direct) return direct;
  // Fall back to HTML, stripped of tags
  const walkHtml = (part) => {
    if (!part) return "";
    if (part.mimeType === "text/html" && part.body?.data) {
      return Buffer.from(part.body.data, "base64").toString("utf-8")
        .replace(/<style[\s\S]*?<\/style>/gi, " ")
        .replace(/<script[\s\S]*?<\/script>/gi, " ")
        .replace(/<[^>]+>/g, " ")
        .replace(/&nbsp;/g, " ")
        .replace(/&amp;/g, "&")
        .replace(/&lt;/g, "<")
        .replace(/&gt;/g, ">")
        .replace(/\s+/g, " ")
        .trim();
    }
    if (Array.isArray(part.parts)) {
      for (const sub of part.parts) {
        const got = walkHtml(sub);
        if (got) return got;
      }
    }
    return "";
  };
  return walkHtml(payload);
}

function getEmailHeader(headers, name) {
  const h = (headers || []).find(x => x.name.toLowerCase() === name.toLowerCase());
  return h ? h.value : "";
}

/**
 * Find or create a ticket entry by LCSDL ref. Returns the ticket.
 */
function getOrCreateAryzaTicket(ref, seedFromMessage) {
  const upperRef = ref.toUpperCase();
  let t = aryzaTickets.find(x => x.ref === upperRef);
  if (t) return t;
  t = {
    ref: upperRef,
    kind: "unknown",                  // 'issue' | 'workaround' | 'unknown'
    priority: null,                   // 'P1'|'P2'|'P3'|'P4'|'P5'|null
    priorityConfirmed: false,         // true if Hargo has confirmed
    subject: seedFromMessage?.subject || "",
    gmailThreadId: seedFromMessage?.threadId || null,
    seenMessageIds: [],               // Gmail message IDs we've processed
    status: "open",                   // 'open' | 'pending_validation' | 'closed'
    createdAt: new Date().toISOString(),
    lastInboundAt: null,
    lastOutboundAt: null,
    nextFollowupAt: null,
    followupReminderId: null,
    history: [],                      // log of events: {at, kind, summary}
  };
  aryzaTickets.push(t);
  return t;
}

function logTicketEvent(ticket, kind, summary) {
  ticket.history = ticket.history || [];
  ticket.history.push({ at: new Date().toISOString(), kind, summary });
  if (ticket.history.length > 200) ticket.history = ticket.history.slice(-200);
}

/**
 * Use Claude to classify a ticket from its subject + body snippet.
 * Returns:
 *   { kind: 'workaround'|'issue'|'unknown',
 *     priority: 'P1'|'P2'|'P3'|'P4'|'P5'|null,
 *     confidence: 0..1,
 *     resolvedWithoutValidation: bool,
 *     gaps: [strings],            // missing items: 'root cause' / 'fix detail' / 'permanence'
 *     summary: '...' }
 */
async function classifyAryzaEmail({ subject, body, isPriorMatch }) {
  const prompt = `You are classifying an inbound email about an Aryza Lend support ticket. The ticket reference is in the subject (format LCSDL-XXXXX).

Definitions:
- WORKAROUND: a known, recurring manual fix Raylo or Aryza performs to compensate for a system limitation until Aryza ship a permanent fix. Workarounds are scheduled (e.g. monthly), have defined completion criteria, and tend to be raised by Raylo. Phrases like "monthly recalculation", "manual transaction split", "data correction", "scheduled fix" are signals.
- ISSUE: an unexpected defect, regression, or incident raised with Aryza that needs investigation, root cause and a permanent fix. Phrases like "outage", "regression", "broken", "unable to", "error", "intermittent", "P1/P2/P3" are signals.

Priority detection. If the subject explicitly contains [P1], P2 -, (P3) etc, use it. Otherwise infer:
- P1: urgent, critical, down, all customers affected, payments broken, mass impact
- P2: significant impact, multiple customers, payment failure for some
- P3: intermittent, edge case, single customer, default for general issues
- P4 / P5: cosmetic, reporting only, low impact

Resolved-without-validation detection. Set resolvedWithoutValidation=true ONLY if the email is from Aryza saying the ticket has been resolved/closed WITHOUT clearly stating BOTH (a) the root cause and (b) a specific fix that was applied. "We have resolved this" with no detail counts. "We resolved this by patching X due to Y" does NOT count.

Gaps. If resolvedWithoutValidation is true, list which of the following are missing: 'root cause', 'fix detail', 'permanence' (not stated whether fix is permanent or temp).

Reply with ONLY a JSON object, no markdown, no extra text:
{"kind": "workaround"|"issue"|"unknown", "priority": "P1"|"P2"|"P3"|"P4"|"P5"|null, "confidence": 0.0-1.0, "resolvedWithoutValidation": false, "gaps": [], "summary": "1-2 sentence summary of what the email says"}

Subject: ${JSON.stringify(subject || "")}
Body:
${(body || "").slice(0, 6000)}
`;

  try {
    const raw = await askClaude(prompt);
    const json = JSON.parse(raw.replace(/```json|```/g, "").trim());
    if (!["workaround", "issue", "unknown"].includes(json.kind)) json.kind = "unknown";
    if (json.priority && !["P1", "P2", "P3", "P4", "P5"].includes(json.priority)) json.priority = null;
    if (typeof json.confidence !== "number") json.confidence = 0.5;
    json.resolvedWithoutValidation = !!json.resolvedWithoutValidation;
    json.gaps = Array.isArray(json.gaps) ? json.gaps : [];
    json.summary = json.summary || "";
    return json;
  } catch (err) {
    console.error("[bill-ling] Aryza classifier failed:", err.message);
    return { kind: "unknown", priority: null, confidence: 0, resolvedWithoutValidation: false, gaps: [], summary: "" };
  }
}

