/**
 * Build a draft chase email body for an Aryza-resolved-without-validation case,
 * matching the spec's template.
 */
function buildResolvedWithoutValidationDraft(ticket, latestEmailFrom) {
  const subject = `Re: ${ticket.subject || ticket.ref}`;
  const body =
`Hi ${latestEmailFrom || "Aryza team"},

Thank you for the update on ${ticket.ref}. Before we can confirm resolution on our side, we need to complete internal validation. Could you please keep this ticket open until we revert?

We also want to ensure we have the following on record before closure:
• Root cause of the issue
• Details of the fix applied
• Confirmation this is a permanent resolution

We'll be back in touch as soon as we've validated. Thanks for your patience.

Billington | Raylo Billing Operations`;
  return { subject, body };
}

/**
 * Queue a draft for Hargo's approval and DM him with the contents.
 * draft = { ticketRef, gmailThreadId, to, cc, subject, body, reason }
 * On Hargo's "send" reply in DM, the queued draft is sent via Gmail.
 *
 * Dedupes both in-memory and Slack-side: if there's already a pending
 * draft for the same ticket+reason in the in-memory queue, OR a recent
 * draft DM in Hargo's IM channel for the same ticket+reason, we skip.
 */
async function queueDraftForApproval(draft) {
  // 1. In-memory dedupe (catches duplicates within a single process lifetime)
  const existingInMemory = aryzaPendingDrafts.find(d =>
    d.status === "awaiting_approval" &&
    d.ticketRef === draft.ticketRef &&
    d.reason === draft.reason
  );
  if (existingInMemory) {
    console.log(`[bill-ling] Draft for ${draft.ticketRef} (${draft.reason}) already awaiting approval as #${existingInMemory.id}. Skipping queue.`);
    return existingInMemory;
  }

  // 2. Slack-side dedupe — scan Hargo's DM channel for a recent draft with
  // the same ticket+reason. Survives Railway restarts where the in-memory
  // queue is empty after the JSON file is wiped.
  try {
    const dmChannelId = await getHargoDMChannel();
    if (dmChannelId) {
      const sevenDaysAgoTs = String(Math.floor((Date.now() - 7 * 24 * 3600 * 1000) / 1000));
      const recent = await app.client.conversations.history({
        token: SLACK_BOT_TOKEN,
        channel: dmChannelId,
        limit: 100,
        oldest: sevenDaysAgoTs,
      });
      const ours = (recent.messages || []).find(m => {
        const isOurs = (BOT_USER_ID && m.user === BOT_USER_ID) || !!m.bot_id;
        if (!isOurs) return false;
        const body = m.text || "";
        return /Draft email for your approval/i.test(body)
          && body.includes(draft.ticketRef)
          && (!draft.reason || body.includes(draft.reason));
      });
      if (ours) {
        console.log(`[bill-ling] Draft DM for ${draft.ticketRef} (${draft.reason}) already in Hargo's DM (ts=${ours.ts}). Skipping repeat.`);
        return null;
      }
    }
  } catch (err) {
    console.warn(`[bill-ling] Could not check Hargo's DM history for existing ${draft.ticketRef} draft (will queue anyway):`, err.message);
  }

  draft.id = (aryzaPendingDrafts.length > 0 ? Math.max(...aryzaPendingDrafts.map(d => d.id || 0)) : 0) + 1;
  draft.createdAt = new Date().toISOString();
  draft.status = "awaiting_approval";
  aryzaPendingDrafts.push(draft);
  saveAryzaTickets();

  const dmText =
    `📧 *Draft email for your approval — ${draft.ticketRef}* (Draft #${draft.id})\n` +
    `Reason: ${draft.reason || "Aryza follow-up"}\n` +
    `\n*To:* ${draft.to}` +
    (draft.cc ? `\n*Cc:* ${draft.cc}` : "") +
    `\n*Subject:* ${draft.subject}\n` +
    `\n\`\`\`\n${draft.body}\n\`\`\`\n` +
    `Reply *send* to approve, *cancel* to drop, or paste an edited version of the body to replace.`;
  try {
    await dmHargo(dmText);
    console.log(`[bill-ling] Queued Aryza draft #${draft.id} for ${draft.ticketRef} and DM'd Hargo.`);
  } catch (err) {
    console.error(`[bill-ling] Failed to DM Hargo for draft #${draft.id}:`, err.message);
  }
  return draft;
}

/**
 * Compose and send an email reply via Gmail (DWD client).
 */
async function sendAryzaEmail(draft) {
  const client = gmailBillingOpsClient;
  if (!client) throw new Error("Gmail (billingoperations@) is not connected.");

  const headers = [
    `From: ${GMAIL_DWD_SUBJECT}`,
    `To: ${draft.to}`,
  ];
  if (draft.cc) headers.push(`Cc: ${draft.cc}`);
  if (draft.inReplyTo) headers.push(`In-Reply-To: ${draft.inReplyTo}`);
  if (draft.references) headers.push(`References: ${draft.references}`);
  headers.push(`Subject: ${draft.subject}`);
  headers.push("Content-Type: text/plain; charset=utf-8");
  const raw = headers.join("\r\n") + "\r\n\r\n" + (draft.body || "");
  const encoded = Buffer.from(raw, "utf-8")
    .toString("base64")
    .replace(/\+/g, "-")
    .replace(/\//g, "_")
    .replace(/=+$/, "");

  const sendOpts = { userId: "me", requestBody: { raw: encoded } };
  if (draft.gmailThreadId) sendOpts.requestBody.threadId = draft.gmailThreadId;
  const sendRes = await client.users.messages.send(sendOpts);
  return sendRes.data;
}

// ── iOutlet email workflow (Hargo, 22/05/2026) ─────────────────────────
// Hourly poll Mon-Fri 09:00-17:00. For each iOutlet-labelled email:
//   1. Extract supplier_reference (7-digit number) from subject + body
//   2. BQ lookup `landing_billington.order_item_fulfillment_trade_in_view`
//      → agreement_id + subscription state
//   3. Anchor SOAP → live state + collected DDs (confirmed > 1 working day,
//      excluding reversals)
//   4. Build a drafted reply, route by label:
//        - Status Enquiry  → "is agreement active?" reply
//        - Cancellation    → suggest refund/close + draft confirmation
//   5. Send the draft FROM billingops@ TO hargobind@raylo.com for Hargo's
//      review before he forwards to iOutlet.
//   6. Track processed message_ids in ioutlet-processed.json (local + GCS).

const IOUTLET_PROCESSED_FILE = require("path").join(__dirname, "ioutlet-processed.json");
const IOUTLET_PROCESSED_GCS_KEY = "ioutlet-processed.json";
let ioutletProcessedMessageIds = new Set();

const IOUTLET_LABEL_NAMES = {
  status:        "Merchants/iOutlet/Agreement Status Enquiry",
  cancellation:  "Merchants/iOutlet/Agreement Cancellation",
  general:       "Merchants/iOutlet/Agreement General Enquiry",
  parent:        "Merchants/iOutlet",
  // Hargo, 25/05/2026: applied to a thread AFTER Billington has sent the
  // confirmation reply. Subsequent polls skip Completed threads UNLESS a
  // new message lands, in which case the actionability classifier decides
  // whether to re-open.
  completed:     "Merchants/iOutlet/Completed",
};

/**
 * Ensure the Completed label exists on the billingops mailbox. Returns the
 * label id. Called lazily once per process.
 */
let _iOutletCompletedLabelId = null;
async function ensureIOutletCompletedLabel() {
  if (_iOutletCompletedLabelId) return _iOutletCompletedLabelId;
  const list = (await gmailBillingOpsClient.users.labels.list({ userId: "me" })).data.labels || [];
  const existing = list.find(l => l.name === IOUTLET_LABEL_NAMES.completed);
  if (existing) {
    _iOutletCompletedLabelId = existing.id;
    return existing.id;
  }
  const res = await gmailBillingOpsClient.users.labels.create({
    userId: "me",
    requestBody: {
      name: IOUTLET_LABEL_NAMES.completed,
      labelListVisibility: "labelShow",
      messageListVisibility: "show",
    },
  });
  _iOutletCompletedLabelId = res.data.id;
  console.log(`[bill-ling] iOutlet: created ${IOUTLET_LABEL_NAMES.completed} label (${res.data.id}).`);
  return res.data.id;
}

/**
 * LLM-classify whether a thread that's already been Completed needs to be
 * re-opened. A new inbound message could be:
 *   - a simple acknowledgement / thanks (no action)
 *   - a brand-new request or follow-up question (action needed)
 * Returns true if action is needed, false otherwise.
 */
async function isIOutletThreadActionable(threadMessages) {
  if (!Array.isArray(threadMessages) || threadMessages.length === 0) return false;
  // Build a chronological summary, marking who sent each (Raylo billing ops
  // = us; everyone else = counterparty / iOutlet).
  const summary = threadMessages.map((m, idx) => {
    const headers = Object.fromEntries((m.payload?.headers || []).map(h => [h.name, h.value]));
    const from = headers.From || "(unknown sender)";
    const isUs = /billingoperations@raylo\.com/i.test(from) || /<.*@raylo\.com>/i.test(from);
    const date = headers.Date || "";
    const subject = headers.Subject || "";
    const body = extractEmailBodyPlaintext(m.payload).slice(0, 2000);
    return `--- Message ${idx + 1} (${isUs ? "RAYLO BILLING OPS" : "COUNTERPARTY"}) ---\nFrom: ${from}\nDate: ${date}\nSubject: ${subject}\n\n${body}`;
  }).join("\n\n");

  const prompt = `You are reviewing an email thread between Raylo Billing Operations and iOutlet (a returns partner) that was previously marked as Completed by Raylo. A new message has arrived. Decide whether the new message requires any further action from Raylo or is simply an acknowledgement / closing courtesy.

Treat the LATEST message in the thread as the new arrival. Output ONLY JSON:
  {"actionNeeded": true|false, "reason": "<=200 char short rationale"}

actionNeeded=TRUE examples:
  - Counterparty asks a new question
  - Counterparty raises a new agreement ID or supplier reference
  - Counterparty disputes our reply / asks us to do something
  - Counterparty escalates or chases for a previous unanswered point

actionNeeded=FALSE examples:
  - Counterparty says "thanks" / "noted" / "received, no further action required"
  - Counterparty confirms what we said
  - Counterparty says "perfect" / "great, thank you"
  - Pure auto-reply / out-of-office (no substantive request)

Thread:
${summary}`;

  try {
    const raw = await askClaude(prompt);
    const parsed = JSON.parse(raw.replace(/\`\`\`json|\`\`\`/g, "").trim());
    if (parsed && typeof parsed.actionNeeded === "boolean") {
      console.log(`[bill-ling] iOutlet actionability: actionNeeded=${parsed.actionNeeded} — "${(parsed.reason || "").slice(0,120)}"`);
      return parsed.actionNeeded;
    }
  } catch (err) {
    console.error(`[bill-ling] isIOutletThreadActionable LLM error:`, err.message);
  }
  // Fail safe: assume action needed so a human still sees it.
  return true;
}

/**
 * Before drafting a templated cancellation/status reply, decide whether the
 * LATEST inbound message is actually something Billington can action with that
 * templated reply — or whether the request was already answered earlier in the
 * thread and/or the latest message is a new question Billington can't answer
 * (e.g. a general "how does the leasing process work" / address-behaviour
 * question). In the latter case we SURFACE the latest email for a human rather
 * than sending a misleading confirmation. (Hargo, 23/06/2026 — the A00381933 /
 * supplier 1506227 thread, where the cancellation was already actioned by
 * Ciaran and the latest email was a general process question.)
 * Returns { action: "draft" | "surface", reason }.
 */
async function assessIOutletDraftability(threadMessages, kind, anchorState) {
  if (!Array.isArray(threadMessages) || threadMessages.length < 2) {
    return { action: "draft", reason: "single-message thread — normal draft" };
  }
  const summary = threadMessages.map((m, idx) => {
    const headers = Object.fromEntries((m.payload?.headers || []).map(h => [h.name, h.value]));
    const from = headers.From || "(unknown sender)";
    const isUs = /billingoperations@raylo\.com/i.test(from) || /<.*@raylo\.com>/i.test(from);
    const date = headers.Date || "";
    const subject = headers.Subject || "";
    const bodyTxt = extractEmailBodyPlaintext(m.payload).slice(0, 2000);
    return `--- Message ${idx + 1} (${isUs ? "RAYLO BILLING OPS" : "iOUTLET"}) ---\nFrom: ${from}\nDate: ${date}\nSubject: ${subject}\n\n${bodyTxt}`;
  }).join("\n\n");
  const closedNote = anchorState?.closureTxn
    ? `Anchor shows this agreement is ALREADY closed (${TRANSACTION_TYPES?.[anchorState.closureTxn.typeId] || "closure"} on ${anchorState.closureTxn.transactionDate}).`
    : `Anchor does NOT show a closure transaction yet.`;

  const prompt = `You are deciding whether Billington (an automated Raylo billing-ops assistant) should send a TEMPLATED "${kind}" reply to iOutlet, or whether a human must handle the LATEST message instead.

${closedNote}

Billington can ONLY help with a templated reply for:
  - "cancellation": confirming an agreement cancellation/closure that iOutlet requested.
  - "status": confirming the current status of an agreement iOutlet asked about.
Billington CANNOT answer general/process/technical questions (e.g. "why does the shipping address change to match the billing address", "how does the leasing process work", policy or system-behaviour questions). Those need a human.

Look at the LATEST message in the thread (the most recent one) and the conversation so far. Output ONLY JSON:
  {"action": "draft" | "surface", "reason": "<=200 chars"}

action = "draft"  → the LATEST message is genuinely asking for the "${kind}" confirmation Billington can give, AND that confirmation has NOT already been given/actioned earlier in the thread.
action = "surface" → ANY of these is true:
  - the "${kind}" request was ALREADY answered/actioned earlier in the thread (e.g. Raylo already replied confirming closure), and the latest message is a new or follow-up point; OR
  - the latest message is a general / process / technical question Billington cannot answer; OR
  - the latest message is asking for something other than a "${kind}" confirmation.

Thread (oldest first):
${summary}`;

  try {
    const raw = await askClaude(prompt);
    const parsed = JSON.parse(raw.replace(/```json|```/g, "").trim());
    if (parsed && (parsed.action === "draft" || parsed.action === "surface")) {
      console.log(`[bill-ling] iOutlet draftability: ${parsed.action} — "${(parsed.reason || "").slice(0, 140)}"`);
      return parsed;
    }
  } catch (err) {
    console.error("[bill-ling] assessIOutletDraftability LLM error:", err.message);
  }
  // Fail safe: default to drafting (the draft still needs a human to send), so
  // an LLM hiccup never silently suppresses a legitimate reply.
  return { action: "draft", reason: "assessment unavailable — defaulted to draft" };
}

// Classify an iOutlet email by subject (and body, as fallback) when Gmail's
// auto-filter hasn't applied a child sub-label. Hargo, 25/05/2026 — after
// UK405052 / UK405381 sat unactioned in the parent label without being
// classified by the filter.
function classifyIOutletKindBySubject(subject = "", body = "") {
  const blob = `${subject}\n${body}`.toLowerCase();
  if (/\bcancellation\b|\bcancel\b|\bcancelling\b|\bcancelled\b/.test(blob)) return "cancellation";
  if (/\bstatus\b|\benquiry\b|\bcheck\b|\bconfirmation\b/.test(blob)) return "status";
  return null; // unknown — caller decides what to do (skip / flag)
}

/**
 * Classify an iOutlet email thread by scanning the entire conversation.
 * Returns "status" | "cancellation" | "general" | null. Hargo, 25/05/2026 —
 * the parent-label fallback should consider the FULL thread context, not
 * just the latest message's subject. Cancellation requests often have a
 * status-enquiry subject like "Agreement confirmation" but the body
 * actually requests cancellation, and vice versa.
 *
 * Uses the LLM for robust classification; subject heuristic as fallback
 * if the LLM call fails.
 */
async function classifyIOutletThreadKind(threadMessages) {
  if (!Array.isArray(threadMessages) || threadMessages.length === 0) return null;
  // Build a compact summary of every message in the thread.
  const summary = threadMessages.map((m, idx) => {
    const headers = Object.fromEntries((m.payload?.headers || []).map(h => [h.name, h.value]));
    const from = headers.From || "(unknown sender)";
    const date = headers.Date || "";
    const subject = headers.Subject || "";
    const body = extractEmailBodyPlaintext(m.payload).slice(0, 2000); // cap each msg
    return `--- Message ${idx + 1} ---\nFrom: ${from}\nDate: ${date}\nSubject: ${subject}\n\n${body}`;
  }).join("\n\n");

  const prompt = `You are classifying an email thread between Raylo's billing ops team and iOutlet (Raylo's returns partner). Output ONLY JSON.

Decide which of these three categories best fits the thread, based on what iOutlet is asking for and what's been agreed:

1. "cancellation" — iOutlet is requesting (or confirming) that an agreement should be cancelled. Phrases: "please cancel", "agreement cancellation", "cancel this account", "we'd like to cancel the subscription", "the customer is returning the device for cancellation". Usually triggered by a customer returning the device for refund/cancellation rather than upgrade.
2. "status" — iOutlet is asking about the current state of an agreement WITHOUT requesting cancellation. Phrases: "is this agreement still active", "what is the agreement status", "please confirm the agreement", "agreement confirmation".
3. "general" — anything else (device block queries, email change requests, miscellaneous questions). Use this only when neither status nor cancellation fits cleanly.

If the thread contains BOTH a status enquiry AND a subsequent cancellation request, classify as "cancellation" — the cancellation directive supersedes the earlier enquiry.

Reply ONLY this JSON shape:
{"kind": "status"|"cancellation"|"general", "confidence": "high"|"medium"|"low", "reasoning": "<=200 char short rationale"}

Thread:
${summary}`;

  try {
    const raw = await askClaude(prompt);
    const parsed = JSON.parse(raw.replace(/\`\`\`json|\`\`\`/g, "").trim());
    if (parsed && typeof parsed.kind === "string" && ["status","cancellation","general"].includes(parsed.kind)) {
      console.log(`[bill-ling] iOutlet thread classifier: kind=${parsed.kind} confidence=${parsed.confidence} — "${(parsed.reasoning || "").slice(0,120)}"`);
      return parsed.kind;
    }
  } catch (err) {
    console.error(`[bill-ling] classifyIOutletThreadKind LLM error:`, err.message);
  }
  // Fallback: subject/body of the most recent message via heuristic.
  const last = threadMessages[threadMessages.length - 1];
  const headers = Object.fromEntries((last.payload?.headers || []).map(h => [h.name, h.value]));
  return classifyIOutletKindBySubject(headers.Subject || "", extractEmailBodyPlaintext(last.payload));
}

/**
 * Apply the child iOutlet label (status / cancellation / general) to a
 * Gmail thread when it currently only sits under the parent label. Idempotent:
 * if the thread already has the target child label, returns false without
 * modifying. Returns true on a fresh label application.
 */
async function applyIOutletChildLabel(threadId, kind, childLabelIdsByKind, currentLabelIds = []) {
  const targetLabelId = childLabelIdsByKind[kind];
  if (!targetLabelId) {
    console.warn(`[bill-ling] applyIOutletChildLabel: no label id for kind=${kind}`);
    return false;
  }
  if (currentLabelIds.includes(targetLabelId)) return false; // already labelled
  try {
    await gmailBillingOpsClient.users.threads.modify({
      userId: "me",
      id: threadId,
      requestBody: { addLabelIds: [targetLabelId] },
    });
    console.log(`[bill-ling] iOutlet: applied child label "${kind}" to thread ${threadId}.`);
    return true;
  } catch (err) {
    console.error(`[bill-ling] applyIOutletChildLabel failed for thread ${threadId}:`, err.message);
    return false;
  }
}

function loadIOutletProcessedFromLocal() {
  try {
    if (fs.existsSync(IOUTLET_PROCESSED_FILE)) {
      const data = JSON.parse(fs.readFileSync(IOUTLET_PROCESSED_FILE, "utf8"));
      ioutletProcessedMessageIds = new Set(data.messageIds || []);
      console.log(`[bill-ling] Loaded ${ioutletProcessedMessageIds.size} iOutlet processed id(s) from local.`);
    }
  } catch (err) {
    console.error("[bill-ling] iOutlet local load failed:", err.message);
  }
}

async function loadIOutletProcessedFromGcs() {
  try {
    const data = await loadJsonFromGcs(IOUTLET_PROCESSED_GCS_KEY);
    if (data?.messageIds) {
      // Union — GCS may have ids the local file missed across deploys.
      for (const id of data.messageIds) ioutletProcessedMessageIds.add(id);
      console.log(`[bill-ling] Loaded iOutlet processed ids from GCS; total now ${ioutletProcessedMessageIds.size}.`);
    }
  } catch (err) {
    console.warn("[bill-ling] iOutlet GCS load failed:", err.message);
  }
}

function saveIOutletProcessed() {
  const payload = { messageIds: [...ioutletProcessedMessageIds] };
  try {
    fs.writeFileSync(IOUTLET_PROCESSED_FILE, JSON.stringify(payload, null, 2));
  } catch (err) {
    console.error("[bill-ling] iOutlet local save failed:", err.message);
  }
  saveJsonToGcs(IOUTLET_PROCESSED_GCS_KEY, payload).catch(() => {});
}

function extractEmailBodyPlaintext(payload) {
  if (!payload) return "";
  if (payload.mimeType === "text/plain" && payload.body?.data) {
    return Buffer.from(payload.body.data, "base64url").toString("utf8");
  }
  if (payload.parts) {
    for (const p of payload.parts) {
      const t = extractEmailBodyPlaintext(p);
      if (t) return t;
    }
  }
  return "";
}

function extractIOutletSupplierReference(body, subject) {
  // iOutlet supplier_references are 7-digit numbers (verified against
  // raylo-production.landing_billington.order_item_fulfillment_trade_in_view).
  // Look in body first (more reliable — they put it as a standalone line),
  // then subject as a fallback.
  const corpus = `${body || ""}\n${subject || ""}`;
  const m = corpus.match(/\b(\d{7})\b/);
  return m ? m[1] : null;
}

async function lookupAgreementBySupplierReference(supplierRef) {
  const sql = `
    SELECT agreement_id, order_state, subscription_state, merchant_display_name,
           variant_display_name, fulfillment_dispatched_at, delivered_at,
           order_created_at
    FROM \`raylo-production.landing_billington.order_item_fulfillment_trade_in_view\`
    WHERE supplier_reference = @ref
    LIMIT 1
  `;
  const [rows] = await bigquery.query({ query: sql, location: "EU", params: { ref: supplierRef } });
  if (!rows || rows.length === 0) return null;
  const r = rows[0];
  return {
    agreementId: formatBQValue(r.agreement_id),
    orderState: formatBQValue(r.order_state),
    subscriptionState: formatBQValue(r.subscription_state),
    merchant: formatBQValue(r.merchant_display_name),
    variant: formatBQValue(r.variant_display_name),
    deliveredAt: formatBQValue(r.delivered_at),
    orderCreatedAt: formatBQValue(r.order_created_at),
  };
}

async function getIOutletAnchorState(agreementId) {
  const xml = await getAgreementFromAnchor(agreementId);
  const teamStatusIdMatch = xml.match(/<(?:a:)?TeamStatusId>(\d+)<\/(?:a:)?TeamStatusId>/);
  const teamStatusId = teamStatusIdMatch ? parseInt(teamStatusIdMatch[1], 10) : null;
  // Team status name (Anchor exposes it as <TeamStatus> next to the id).
  const teamStatusNameMatch = xml.match(/<(?:a:)?TeamStatus>([^<]+)<\/(?:a:)?TeamStatus>/);
  const teamStatusName = teamStatusNameMatch ? teamStatusNameMatch[1].trim() : null;
  const balanceMatch = xml.match(/<(?:a:)?Balance>([^<]+)<\/(?:a:)?Balance>/);
  const balance = balanceMatch ? parseFloat(balanceMatch[1]) : null;

  // Pull transactions, identify confirmed collections
  const txns = await getAgreementTransactionsFromAnchor(agreementId);
  const REVERSAL_TYPES = new Set([24, 54, 56, 150, 151, 152, 153, 154, 155, 156]);
  const todayLondon = new Date().toLocaleDateString("en-CA", { timeZone: "Europe/London" });

  const collections = txns.filter(t => COLLECTION_TYPE_IDS.has(t.typeId) && t.amount > 0);
  const reversals   = txns.filter(t => REVERSAL_TYPES.has(t.typeId));
  const isReversed  = (coll) => reversals.some(r =>
    Math.abs(Math.abs(r.amount) - coll.amount) <= 0.01 &&
    (r.transactionDate || "") >= (coll.transactionDate || "")
  );
  const unreversed = collections.filter(c => !isReversed(c));

  const confirmedDDs = unreversed.filter(c =>
    c.typeId === 12 && c.transactionDate && todayLondon > nextWorkingDay(c.transactionDate)
  );
  const confirmedCards = unreversed.filter(c => c.typeId === 23);
  const confirmedOther = unreversed.filter(c =>
    (c.typeId === 53 || c.typeId === 55) && c.transactionDate && todayLondon > nextWorkingDay(c.transactionDate)
  );
  const totalCollected = [...confirmedDDs, ...confirmedCards, ...confirmedOther]
    .reduce((sum, t) => sum + Math.abs(t.amount), 0);

  // "Active" = there's a positive Balance still owed (rough heuristic — caller
  // can drill into TeamStatusId for the precise lifecycle stage).
  const isActive = balance !== null && balance > 0.01;

  // Has a closure transaction been posted? (TypeId 26 = Write-off, 30 = Asset
  // returned, 46 = Asset lost in transit). Surface the most recent one so the
  // cancellation draft can say "closure already posted on …" rather than
  // unconditionally asserting closure (Hargo, 22/05/2026 — A00365652 case).
  const CLOSURE_TXN_TYPE_IDS = new Set([26, 30, 46]);
  const closureTxns = txns
    .filter(t => CLOSURE_TXN_TYPE_IDS.has(t.typeId))
    .sort((a, b) => (b.transactionDate || "").localeCompare(a.transactionDate || ""));
  const closureTxn = closureTxns[0] || null;
  const rebateTxn  = txns.find(t => t.typeId === 33) || null;

  return {
    teamStatusId,
    teamStatusName,
    balance,
    isActive,
    confirmedDDs,
    confirmedCards,
    confirmedOther,
    totalCollected: Number(totalCollected.toFixed(2)),
    closureTxn,
    rebateTxn,
  };
}

function buildIOutletStatusEnquiryDraft({ subject, supplierRef, agreement, anchorState }) {
  const draftSubject = subject?.startsWith("Re:") ? subject : `Re: ${subject || "iOutlet Agreement Status Enquiry"}`;
  // Customer-facing reply (sent verbatim to iOutlet when Hargo says "send email").
  const emailBody = [
    `Hi,`,
    ``,
    `Agreement: ${agreement.agreementId}`,
    `Subscription state: ${agreement.subscriptionState || "unknown"}`,
    `Order state: ${agreement.orderState || "unknown"}`,
    `Variant: ${agreement.variant || "unknown"}`,
    `Supplier reference: ${supplierRef}`,
    ``,
    `Kind regards,`,
    `Raylo Billing Operations`,
  ].join("\n");
  // DM preview (what Hargo sees in Slack — same as the email here since
  // there's no extra debug to show for status enquiries).
  const body = emailBody + "\n\n[Billington — draft reply for your review. Reply *send email* in this thread to send to iOutlet on the original Gmail thread and mark the source as read.]";
  return { subject: draftSubject, body, emailBody };
}

function buildIOutletCancellationDraft({ subject, supplierRef, agreement, anchorState }) {
  const draftSubject = subject?.startsWith("Re:") ? subject : `Re: ${subject || "iOutlet Agreement Cancellation"}`;
  const ddCount = anchorState.confirmedDDs.length;
  const ddTotal = anchorState.confirmedDDs.reduce((s, t) => s + Math.abs(t.amount), 0);
  const cardTotal = anchorState.confirmedCards.reduce((s, t) => s + Math.abs(t.amount), 0);

  // Has Anchor already processed the closure?
  const alreadyClosed = !!anchorState.closureTxn;
  const closureTypeName = anchorState.closureTxn
    ? (TRANSACTION_TYPES?.[anchorState.closureTxn.typeId] || `TypeId ${anchorState.closureTxn.typeId}`)
    : null;

  // Merchant Cancellation workflow (Hargo, 25/05/2026):
  //   - iOutlet has the device. Close should be Asset Return (TypeId 30),
  //     NOT a write-off (TypeId 26).
  //   - If no refund is due, Billington adds to the close sheet under
  //     "Asset Return — Device Received" (column E) when Hargo replies
  //     "send email", then sends the confirmation and posts a summary in
  //     #data-billing-updates.
  //   - If a refund IS due, hold off the sheet add — refund flow runs
  //     first, then the operator manually re-triggers.
  let recommendation;
  let mcAction = null; // metadata for the send-email handler to act on
  if (alreadyClosed) {
    recommendation =
`*Suggested action:* No close-command needed — Anchor already shows the closure transaction (${closureTypeName} on ${anchorState.closureTxn.transactionDate}). Verify in Anchor, then reply *send email* to send the confirmation to iOutlet.`;
  } else if (anchorState.totalCollected > 0.01) {
    recommendation =
`*Suggested action:* Refund all collected payments (£${anchorState.totalCollected.toFixed(2)}) and close the account as *Asset Return* (TypeId 30 — iOutlet has the device).

Command you'd run:
  • close account and refund all payments on ${agreement.agreementId} asset return
    (from #customer-refunds-and-complaints)

*Note:* Billington will NOT auto-add this to the close sheet yet — process the refund first, then re-trigger the iOutlet poll or add manually. Replying *send email* now will send the acknowledgement to iOutlet only.`;
  } else {
    recommendation =
`*Suggested action:* Add to the close sheet under *Asset Return — Device Received* (TypeId 30) — no payments to refund.

Reply *send email* to:
  • Add ${agreement.agreementId} to the close sheet under *Asset Return — Device Received*
  • Send the confirmation email below to iOutlet
  • Post a summary to #data-billing-updates
  • Mark the source Gmail thread as read`;
    mcAction = {
      type: "add_asset_return",
      agreementId: agreement.agreementId,
      supplierRef,
      closeReasonKey: "asset_return_cancelled_device_received",
    };
  }

  const confirmationToIOutlet = alreadyClosed
    ? `Hi,

Confirming cancellation of the agreement linked to supplier reference ${supplierRef}. The account is closed${
        anchorState.totalCollected > 0.01 ? ` and any refunds due have been processed` : ""
      }.

Kind regards,
Raylo Billing Operations`
    : `Hi,

Acknowledging your cancellation request for supplier reference ${supplierRef}. We will action the close on our side shortly — confirming once complete.

Kind regards,
Raylo Billing Operations`;

  // The DM preview Hargo sees (full Anchor state + recommendation + the
  // exact customer-facing reply, clearly fenced).
  const previewLines = [
    `iOutlet has requested cancellation of supplier reference ${supplierRef} → agreement ${agreement.agreementId}.`,
    ``,
    `*Anchor state:*`,
    `  • Subscription state: ${agreement.subscriptionState || "unknown"}`,
    `  • TeamStatus: ${anchorState.teamStatusName || "(unknown)"}  (TeamStatusId ${anchorState.teamStatusId ?? "?"})`,
    `  • Balance: £${anchorState.balance?.toFixed(2) ?? "unknown"}`,
    `  • Confirmed DD collections: ${ddCount} (£${ddTotal.toFixed(2)})`,
    `  • Confirmed card payments: ${anchorState.confirmedCards.length} (£${cardTotal.toFixed(2)})`,
    `  • Total collected: £${anchorState.totalCollected.toFixed(2)}`,
    `  • Closure transaction posted: ${alreadyClosed ? `${closureTypeName} on ${anchorState.closureTxn.transactionDate}` : "❌ not yet posted"}`,
    `  • Rebate (TypeId 33) posted: ${anchorState.rebateTxn ? `on ${anchorState.rebateTxn.transactionDate}` : "❌ not yet posted"}`,
    ``,
    recommendation,
    ``,
    `--- Reply that will be sent to iOutlet on the original Gmail thread ---`,
    confirmationToIOutlet,
    `--- end ---`,
    ``,
    `[Billington — draft for your review. Reply *send email* in this thread to action this.]`,
  ];
  return {
    subject: draftSubject,
    body: previewLines.join("\n"),
    emailBody: confirmationToIOutlet, // customer-facing reply ONLY
    mcAction,
  };
}

// ── iOutlet draft → "reply send email" state ─────────────────────────
// We store (DM ts → source email metadata + drafted reply) so a follow-up
// "send email" reply in the DM thread can be turned into an actual Gmail
// reply against the original iOutlet thread.
const IOUTLET_DRAFTS_FILE = require("path").join(__dirname, "ioutlet-drafts.json");
const IOUTLET_DRAFTS_GCS_KEY = "ioutlet-drafts.json";
let ioutletDraftsByTs = new Map();

function loadIOutletDraftsLocal() {
  try {
    if (fs.existsSync(IOUTLET_DRAFTS_FILE)) {
      const data = JSON.parse(fs.readFileSync(IOUTLET_DRAFTS_FILE, "utf8"));
      ioutletDraftsByTs = new Map(Object.entries(data.drafts || {}));
      console.log(`[bill-ling] Loaded ${ioutletDraftsByTs.size} iOutlet draft(s) from local.`);
    }
  } catch (err) {
    console.error("[bill-ling] iOutlet drafts local load failed:", err.message);
  }
}
async function loadIOutletDraftsGcs() {
  try {
    const data = await loadJsonFromGcs(IOUTLET_DRAFTS_GCS_KEY);
    if (data?.drafts) {
      for (const [k, v] of Object.entries(data.drafts)) ioutletDraftsByTs.set(k, v);
      console.log(`[bill-ling] Loaded iOutlet drafts from GCS; total now ${ioutletDraftsByTs.size}.`);
    }
  } catch (err) {
    console.warn("[bill-ling] iOutlet drafts GCS load failed:", err.message);
  }
}
function saveIOutletDrafts() {
  const payload = { drafts: Object.fromEntries(ioutletDraftsByTs) };
  try { fs.writeFileSync(IOUTLET_DRAFTS_FILE, JSON.stringify(payload, null, 2)); } catch (_) {}
  saveJsonToGcs(IOUTLET_DRAFTS_GCS_KEY, payload).catch(() => {});
}
loadIOutletDraftsLocal();
loadIOutletDraftsGcs();

/**
 * Summarise iOutlet drafts that are still waiting on Hargo's "send email"
 * approval — drafts with `sentAt === null`. Used by the on-demand
 * "are there any iOutlet emails to be actioned?" handler so Hargo can
 * see at a glance what's outstanding rather than the previous useless
 * "drafts DM'd separately" line. Hargo, 25/05/2026.
 */
function summarisePendingIOutletDrafts() {
  const pending = [];
  for (const [dmTs, draft] of ioutletDraftsByTs.entries()) {
    if (draft.sentAt) continue;
    pending.push({
      dmTs,
      draftSubject: draft.draftSubject || "(no subject)",
      agreementId: draft.mcAction?.agreementId || null,
      supplierRef: draft.mcAction?.supplierRef || null,
      draftedAt: draft.draftedAt || null,
    });
  }
  pending.sort((a, b) => (a.draftedAt || "").localeCompare(b.draftedAt || ""));
  return pending;
}

async function postIOutletDraftForReview({ subject, body, emailBody, source, mcAction }) {
  // Hargo, 18/06/2026: post to #data-billing-updates (was a DM to Hargo).
  // source = { gmailMessageId, gmailThreadId, fromAddress, originalSubject, originalMessageIdHeader }
  // mcAction = { type: "add_asset_return", agreementId, supplierRef, closeReasonKey } or null
  // Anyone in #team-billing-operations-emails can reply "send email" in the draft thread
  // to send the reply to the original iOutlet email AND fire any associated
  // merchant cancellation action (e.g. add to close sheet under Asset Return).
  const postText =
    `📧 *iOutlet draft for review*\n` +
    `*Subject:* ${subject}\n` +
    "```\n" + body + "\n```";
  let draftTs = null;
  try {
    const ioutletBlocks = INTERACTIVE_BUTTONS_ENABLED ? [
      { type: "section", text: { type: "mrkdwn", text: postText.slice(0, 2900) } },
      { type: "actions", elements: [
        {
          type: "button",
          text: { type: "plain_text", text: "📧 Send email", emoji: true },
          style: "primary",
          action_id: "btn_ioutlet_send",
          value: "send",
          confirm: {
            title: { type: "plain_text", text: "Send to iOutlet?" },
            text: { type: "mrkdwn", text: "Sends this reply to iOutlet on the original Gmail thread, marks the source read, and runs any close-sheet follow-up." },
            confirm: { type: "plain_text", text: "Send it" },
            deny: { type: "plain_text", text: "Cancel" },
          },
        },
        {
          type: "button",
          text: { type: "plain_text", text: "🗑️ Reject draft", emoji: true },
          style: "danger",
          action_id: "btn_ioutlet_reject",
          value: "reject",
          confirm: {
            title: { type: "plain_text", text: "Reject this draft?" },
            text: { type: "mrkdwn", text: "Discards this draft without sending. The iOutlet email is left for a human to handle." },
            confirm: { type: "plain_text", text: "Reject it" },
            deny: { type: "plain_text", text: "Keep it" },
          },
        },
      ]},
    ] : undefined;
    const res = await app.client.chat.postMessage({
      token: SLACK_BOT_TOKEN,
      channel: CHANNELS.TEAM_BILLING_OPERATIONS_EMAILS,
      text: postText,
      ...(ioutletBlocks ? { blocks: ioutletBlocks } : {}),
      mrkdwn: true,
      unfurl_links: false,
      unfurl_media: false,
    });
    draftTs = res?.ts || null;
  } catch (err) {
    console.error("[bill-ling] iOutlet draft post to #team-billing-operations-emails failed:", err.message);
  }
  if (draftTs && source) {
    ioutletDraftsByTs.set(draftTs, {
      channel: CHANNELS.TEAM_BILLING_OPERATIONS_EMAILS,
      gmailMessageId: source.gmailMessageId,
      gmailThreadId: source.gmailThreadId,
      fromAddress: source.fromAddress,
      replyToAddress: source.replyToAddress || source.fromAddress,
      ccHeader: source.ccHeader || "",
      originalSubject: source.originalSubject || subject,
      originalMessageIdHeader: source.originalMessageIdHeader || null,
      draftSubject: subject,
      draftBody: body,          // DM preview (with debug)
      emailBody: emailBody || null, // customer-facing reply ONLY
      draftedAt: new Date().toISOString(),
      sentAt: null,
      mcAction: mcAction || null,
    });
    saveIOutletDrafts();
  }
}

/**
 * Surface an iOutlet email for a human instead of drafting a templated reply,
 * when assessIOutletDraftability() decided Billington can't action the latest
 * message (already answered / general question). Shows the original unanswered
 * latest email so someone in #data-billing-updates can reply on Gmail. No
 * draft, no send button — there is nothing for Billington to send.
 * (Hargo, 23/06/2026.)
 */
async function postIOutletNeedsHumanReview({ subject, supplierRef, agreement, anchorState, latestFrom, latestDate, latestBody, reason }) {
  const closedLine = anchorState?.closureTxn
    ? `Anchor shows this agreement is already closed (${TRANSACTION_TYPES?.[anchorState.closureTxn.typeId] || "closure"} on ${anchorState.closureTxn.transactionDate}).`
    : "";
  const refLine = supplierRef
    ? `Supplier ref ${supplierRef}${agreement?.agreementId ? ` → ${agreement.agreementId}` : ""}`
    : "";
  const quoted = (latestBody || "").trim().split(/\n/).map(l => `> ${l}`).join("\n").slice(0, 2500);
  const text =
    `📨 *iOutlet — needs a human (I can't action this one)*\n` +
    `*Subject:* ${subject}\n` +
    (refLine ? `${refLine}\n` : "") +
    (closedLine ? `${closedLine}\n` : "") +
    `\n*Why I'm not drafting:* ${reason || "the latest email isn't a cancellation/status confirmation I can send."}\n` +
    `\n*Latest email${latestFrom ? ` from ${latestFrom}` : ""}${latestDate ? ` (${latestDate})` : ""} — needs a reply:*\n` +
    (quoted || "_(no readable body)_") +
    `\n\n_No draft created — please reply to iOutlet on the original Gmail thread._`;
  try {
    await app.client.chat.postMessage({
      token: SLACK_BOT_TOKEN,
      channel: CHANNELS.TEAM_BILLING_OPERATIONS_EMAILS,
      text,
      mrkdwn: true,
      unfurl_links: false,
      unfurl_media: false,
    });
  } catch (err) {
    console.error("[bill-ling] postIOutletNeedsHumanReview failed:", err.message);
  }
}

/**
 * Shared: action an iOutlet draft send — used by the DM responder (legacy DM
 * drafts) and the #data-billing-updates channel mention responder. Sends the
 * drafted reply to iOutlet, marks the source read, fires any merchant-
 * cancellation follow-up, persists, and posts the result via postResult(text).
 * Hargo, 18/06/2026.
 */
async function actionIOutletDraftSend({ draftTs, user, triggerSource, sourceLink, postResult }) {
  const draft = ioutletDraftsByTs.get(draftTs);
  if (!draft) return;
  if (draft.sentAt) { await postResult(`⚠️ This draft was already sent at ${draft.sentAt}.`); return; }
  if (draft.rejectedAt) { await postResult(`⚠️ This draft was rejected${draft.rejectedBy ? ` by <@${draft.rejectedBy}>` : ""} and won't be sent.`); return; }
  try {
    await sendIOutletDraftAsEmail(draft, { triggeredBy: user, triggerSource, sourceLink: sourceLink || "" });
    draft.sentAt = new Date().toISOString();
    let mcResult = null;
    if (draft.mcAction) {
      try {
        mcResult = await processMerchantCancellation(draft.mcAction, { triggeredBy: user, triggerSource, requestedBy: draft.fromAddress || "" });
        draft.mcResult = mcResult;
      } catch (err) {
        console.error("[bill-ling] iOutlet send: processMerchantCancellation failed:", err.message);
        mcResult = { added: false, error: err.message };
        draft.mcResult = mcResult;
      }
    }
    ioutletDraftsByTs.set(draftTs, draft);
    saveIOutletDrafts();
    const lines = [
      `✅ Sent. Replied to *${draft.fromAddress}* on the original Gmail thread and marked the source message as read.`,
      `*Subject:* ${draft.draftSubject}`,
    ];
    if (mcResult) {
      if (mcResult.error) lines.push(`⚠️ Merchant cancellation follow-up: ${mcResult.error}`);
      else if (mcResult.alreadyInSheet) lines.push(`📦 Merchant cancellation: *${draft.mcAction.agreementId}* was already on the close sheet — no new row added.`);
      else lines.push(`📦 Merchant cancellation: added *${draft.mcAction.agreementId}* to the close sheet under *Asset Return — Device Received*${mcResult.row ? ` (row ${mcResult.row})` : ""} and posted to #data-billing-updates.`);
    }
    await postResult(lines.join("\n"));
  } catch (err) {
    console.error("[bill-ling] iOutlet send failed:", err.message);
    await postResult(`❌ Send failed: ${err.message}`);
  }
}

/**
 * Process a Merchant Cancellation (Hargo, 25/05/2026): an iOutlet
 * cancellation request where no refund is due. Adds the agreement to the
 * close sheet under "Asset Return — Device Received" (column E, TypeId 30)
 * and posts a summary in #data-billing-updates. Called by the "send email"
 * DM responder when the draft carries an mcAction.
 *
 * Returns { added, row, alreadyInSheet, error }.
 */
async function processMerchantCancellation(mcAction, auditCtx = null) {
  if (!mcAction || mcAction.type !== "add_asset_return") {
    return { added: false, error: "unsupported mcAction" };
  }
  const { agreementId, supplierRef, closeReasonKey = "asset_return_cancelled_device_received" } = mcAction;
  if (!/^A\d{5,9}$/i.test(agreementId)) {
    return { added: false, error: `invalid agreementId: ${agreementId}` };
  }
  // Add to the close sheet under Asset Return — Device Received.
  let row = null, alreadyInSheet = false;
  try {
    const result = await writeCloseAgreements([agreementId], closeReasonKey, auditCtx ? {
      ...auditCtx,
      actionTypeSuffix: "merchant_cancellation",
    } : null);
    const wrote = (result.written || []).find(w => w.id === agreementId);
    row = wrote ? wrote.row : null;
    alreadyInSheet = (result.duplicates || []).map(s => s.toUpperCase()).includes(agreementId.toUpperCase());
  } catch (err) {
    console.error(`[bill-ling] processMerchantCancellation: writeCloseAgreements failed for ${agreementId}:`, err.message);
    return { added: false, error: err.message };
  }

  // Post summary in #data-billing-updates.
  const labelForKey = CLOSE_REASON_COLUMNS[closeReasonKey]?.label || closeReasonKey;
  const summary =
    `📦 *Merchant cancellation processed* — iOutlet supplier reference *${supplierRef}* → *${agreementId}*\n` +
    (alreadyInSheet
      ? `• Already on the close sheet — no new row added (under *${labelForKey}*).`
      : row
        ? `• Added to close sheet under *${labelForKey}* (row ${row}).`
        : `• Added to close sheet under *${labelForKey}*.`) + `\n` +
    `• Confirmation email sent to iOutlet.\n` +
    `• Closure type: *Asset Return* (TypeId 30) — iOutlet has the device.`;
  try {
    await app.client.chat.postMessage({
      token: SLACK_BOT_TOKEN,
      channel: CHANNELS.TEAM_BILLING_OPERATIONS_EMAILS,
      text: summary,
      mrkdwn: true,
      unfurl_links: false,
      unfurl_media: false,
    });
  } catch (err) {
    console.error(`[bill-ling] processMerchantCancellation: #team-billing-operations-emails post failed for ${agreementId}:`, err.message);
    // Sheet write succeeded — surface partial-success to caller.
    return { added: !alreadyInSheet, row, alreadyInSheet, error: `Sheet OK but channel post failed: ${err.message}` };
  }
  return { added: !alreadyInSheet, row, alreadyInSheet };
}

/**
 * Send a Gmail reply against the original iOutlet message linked to a Slack
 * DM. Used by the "send email" DM responder.
 */
async function sendIOutletDraftAsEmail(draft, auditCtx = null) {
  if (!gmailBillingOpsClient) throw new Error("Gmail (billingoperations@) not connected");

  // Customer-facing reply body. Prefer the explicit `emailBody` (set by the
  // new draft builders, Hargo 25/05/2026 — the DM preview must NOT leak into
  // the customer-facing email). Legacy fallback: strip the bracket note from
  // the DM body.
  let bodyToSend;
  if (typeof draft.emailBody === "string" && draft.emailBody.trim()) {
    bodyToSend = draft.emailBody;
  } else {
    // Legacy drafts saved before the emailBody split. Strip the trailing
    // "[Billington — …]" note that's meant for Hargo only, and also strip
    // any preceding debug block fenced by the "--- Suggested ... ---"
    // markers (defensive — don't send Anchor state debug to iOutlet).
    let legacy = draft.draftBody || "";
    legacy = legacy.replace(/\n\n\[Billington[^\]]*\]\s*$/, "");
    // Extract just the bit between "--- Suggested confirmation email to iOutlet ---" and "--- end ---"
    const fencedMatch = legacy.match(/---\s*(?:Suggested confirmation email to iOutlet|Reply that will be sent to iOutlet[^-]*)\s*---\s*([\s\S]*?)\s*---\s*end\s*---/i);
    if (fencedMatch) {
      bodyToSend = fencedMatch[1].trim();
    } else {
      bodyToSend = legacy;
    }
  }

  const headers = [
    `From: ${GMAIL_DWD_SUBJECT}`,
    `To: ${draft.replyToAddress || draft.fromAddress}`,
    `Subject: ${draft.draftSubject}`,
    "Content-Type: text/plain; charset=utf-8",
  ];
  // Retain Cc from the original email (Hargo, 25/05/2026). The poll
  // captures the original Cc header; we strip ourselves and our reply-to
  // address out so we don't accidentally double-CC ourselves.
  if (draft.ccHeader && draft.ccHeader.trim()) {
    const ccCleaned = draft.ccHeader
      .split(",")
      .map(s => s.trim())
      .filter(s => s)
      .filter(s => !s.toLowerCase().includes("billingoperations@raylo.com"))
      .filter(s => {
        const lower = s.toLowerCase();
        const replyTo = (draft.replyToAddress || draft.fromAddress || "").toLowerCase();
        return !lower.includes(replyTo);
      })
      .join(", ");
    if (ccCleaned) headers.push(`Cc: ${ccCleaned}`);
  }
  // In-Reply-To + References + threadId together cause Gmail to thread the
  // reply against the original iOutlet message (Hargo 25/05/2026 — reply
  // must land on the original email chain, not as a new conversation).
  if (draft.originalMessageIdHeader) {
    headers.push(`In-Reply-To: ${draft.originalMessageIdHeader}`);
    headers.push(`References: ${draft.originalMessageIdHeader}`);
  }
  const raw = headers.join("\r\n") + "\r\n\r\n" + bodyToSend;
  const encoded = Buffer.from(raw, "utf-8")
    .toString("base64").replace(/\+/g, "-").replace(/\//g, "_").replace(/=+$/, "");
  const sendOpts = { userId: "me", requestBody: { raw: encoded } };
  if (draft.gmailThreadId) sendOpts.requestBody.threadId = draft.gmailThreadId;
  await gmailBillingOpsClient.users.messages.send(sendOpts);
  // Mark the original message as read AND apply the Completed label to the
  // whole thread (Hargo, 25/05/2026 — once Billington has replied, the
  // thread is done unless a new inbound message arrives).
  if (draft.gmailMessageId) {
    try {
      await gmailBillingOpsClient.users.messages.modify({
        userId: "me",
        id: draft.gmailMessageId,
        requestBody: { removeLabelIds: ["UNREAD"] },
      });
    } catch (err) {
      console.warn(`[bill-ling] failed to mark ${draft.gmailMessageId} as read:`, err.message);
    }
  }
  if (draft.gmailThreadId) {
    try {
      const completedLabelId = await ensureIOutletCompletedLabel();
      await gmailBillingOpsClient.users.threads.modify({
        userId: "me",
        id: draft.gmailThreadId,
        requestBody: { addLabelIds: [completedLabelId], removeLabelIds: ["UNREAD"] },
      });
    } catch (err) {
      console.warn(`[bill-ling] failed to apply Completed label to ${draft.gmailThreadId}:`, err.message);
    }
  }

  // ── Audit log ── this is a real outbound action (not a draft).
  await logBillingtonAction({
    actionCategory: "email_sent",
    actionType: "ioutlet_reply_sent",
    agreementId: draft.mcAction?.agreementId || "",
    reference: draft.draftSubject || "",
    status: "success",
    description: `iOutlet reply sent to ${draft.replyToAddress || draft.fromAddress} — subject: "${draft.draftSubject}"`,
    requestedBy: draft.fromAddress || "",
    triggeredBy: auditCtx?.triggeredBy || "",
    triggerSource: auditCtx?.triggerSource || "dm",
    sourceLink: auditCtx?.sourceLink || "",
    idempotencyKey: `ioutlet_email:${draft.gmailMessageId || draft.gmailThreadId || draft.draftSubject}`,
  });
}

async function processIOutletEmails() {
  if (!gmailBillingOpsClient) {
    console.warn("[bill-ling] iOutlet poll: billingops Gmail client not connected.");
    return;
  }
  try {
    const labels = (await gmailBillingOpsClient.users.labels.list({ userId: "me" })).data.labels || [];
    const byName = new Map(labels.map(l => [l.name, l.id]));
    const statusLabelId = byName.get(IOUTLET_LABEL_NAMES.status);
    const cancellationLabelId = byName.get(IOUTLET_LABEL_NAMES.cancellation);
    const generalLabelId = byName.get(IOUTLET_LABEL_NAMES.general);
    const parentLabelId = byName.get(IOUTLET_LABEL_NAMES.parent);
    if (!statusLabelId && !cancellationLabelId && !parentLabelId) {
      console.warn("[bill-ling] iOutlet poll: no iOutlet labels found in billingops.");
      return;
    }
    const childLabelIdsByKind = {
      status: statusLabelId,
      cancellation: cancellationLabelId,
      general: generalLabelId,
    };

    // We query three labels:
    //   - statusLabelId / cancellationLabelId: kind is known from label.
    //   - parentLabelId: a fall-through bucket — Gmail's filter often drops
    //     mail here without auto-applying the child sub-label. We classify
    //     these by full-thread LLM scan (Hargo, 25/05/2026) and then APPLY
    //     the correct child label so future polls see them under the right
    //     bucket too.
    const labelEntries = [
      { id: statusLabelId, kind: "status" },
      { id: cancellationLabelId, kind: "cancellation" },
      { id: generalLabelId, kind: "general" },
      { id: parentLabelId, kind: null }, // null = LLM-classify the thread
    ].filter(e => e.id);
    const allMsgIds = new Set();
    const labelKindByMsgId = new Map();
    const seenThreadIds = new Set();

    for (const { id: lid, kind: presetKind } of labelEntries) {
      const list = await gmailBillingOpsClient.users.threads.list({
        userId: "me",
        labelIds: [lid],
        q: "newer_than:14d",
        maxResults: 50,
      });
      for (const t of (list.data.threads || [])) {
        if (seenThreadIds.has(t.id)) continue; // already covered by a more-specific child label
        seenThreadIds.add(t.id);
        const thr = await gmailBillingOpsClient.users.threads.get({
          userId: "me", id: t.id, format: "full",
        });
        // Only the latest message of each thread — earlier ones already
        // actioned (or won't have new value).
        const m = thr.data.messages[thr.data.messages.length - 1];
        if (allMsgIds.has(m.id)) continue;

        // If the LATEST message in the thread is from Raylo (outbound), we've
        // already replied — there is nothing for Billington to draft OR surface.
        // Skip the thread entirely. (Hargo, 24/06/2026 — the A00381933 thread,
        // where Ciaran had already answered the policy question but Billington
        // still surfaced it for a human.)
        {
          const _lastFrom = ((m.payload.headers || []).find(h => h.name === "From")?.value || "").toLowerCase();
          if (/billingoperations@raylo\.com|<[^>]*@raylo\.com>/i.test(_lastFrom)) {
            ioutletProcessedMessageIds.add(m.id);
            console.log(`[bill-ling] iOutlet: thread ${t.id} latest message is from Raylo (already replied) — skipping.`);
            continue;
          }
        }

        const threadLabelIds = Array.from(new Set((thr.data.messages || []).flatMap(msg => msg.labelIds || [])));

        // If the thread already has the Completed label AND the latest
        // message is a new inbound (not from us), classify whether action
        // is needed. If not — silently mark read and skip. If yes — strip
        // the Completed label and continue with the normal flow.
        // Hargo, 25/05/2026.
        const completedLabelId = await ensureIOutletCompletedLabel().catch(() => null);
        if (completedLabelId && threadLabelIds.includes(completedLabelId)) {
          const lastHeaders = Object.fromEntries((m.payload.headers || []).map(h => [h.name, h.value]));
          const lastFrom = (lastHeaders.From || "").toLowerCase();
          const isInbound = !/billingoperations@raylo\.com|<.*@raylo\.com>/i.test(lastFrom);
          if (!isInbound) {
            // Our own most recent message — already completed, nothing to do.
            console.log(`[bill-ling] iOutlet: thread ${t.id} already Completed (last msg is from us), skipping.`);
            ioutletProcessedMessageIds.add(m.id);
            continue;
          }
          // Inbound reply on a Completed thread — classify.
          const actionNeeded = await isIOutletThreadActionable(thr.data.messages || []);
          if (!actionNeeded) {
            // Acknowledgement / thanks — re-mark read and keep Completed.
            try {
              await gmailBillingOpsClient.users.threads.modify({
                userId: "me", id: t.id, requestBody: { removeLabelIds: ["UNREAD"] },
              });
            } catch (err) {
              console.warn(`[bill-ling] iOutlet: failed to mark Completed thread ${t.id} read:`, err.message);
            }
            ioutletProcessedMessageIds.add(m.id);
            console.log(`[bill-ling] iOutlet: thread ${t.id} new reply was an acknowledgement — kept Completed, marked read.`);
            continue;
          }
          // Action needed — strip Completed and let the normal flow run.
          try {
            await gmailBillingOpsClient.users.threads.modify({
              userId: "me", id: t.id, requestBody: { removeLabelIds: [completedLabelId] },
            });
            console.log(`[bill-ling] iOutlet: thread ${t.id} new actionable reply — Completed label removed, will re-draft.`);
          } catch (err) {
            console.warn(`[bill-ling] iOutlet: failed to remove Completed label from ${t.id}:`, err.message);
          }
        }

        // For the parent-only catch-all bucket, scan the entire thread with
        // the LLM to determine the correct kind. Subject/body heuristic
        // falls back if the LLM fails.
        let kind = presetKind;
        if (!kind) {
          kind = await classifyIOutletThreadKind(thr.data.messages || []);
          if (!kind) {
            const headers = Object.fromEntries((m.payload.headers || []).map(h => [h.name, h.value]));
            console.log(`[bill-ling] iOutlet: parent-label thread ${t.id} subject "${headers.Subject}" — could not classify, skipping.`);
            continue;
          }
          console.log(`[bill-ling] iOutlet: parent-label thread ${t.id} classified as "${kind}" via LLM thread scan.`);
          // APPLY the child label so future polls see the thread under the
          // right bucket and the inbox stays tidy.
          try {
            await applyIOutletChildLabel(t.id, kind, childLabelIdsByKind, threadLabelIds);
          } catch (err) {
            console.error(`[bill-ling] iOutlet: applyIOutletChildLabel failed for ${t.id}:`, err.message);
          }
        }
        // General-bucket: don't action automatically (Hargo reviews these
        // manually). Just classify, label, and move on without drafting.
        if (kind === "general") {
          console.log(`[bill-ling] iOutlet: thread ${t.id} is general enquiry — labelled, no automated draft.`);
          continue;
        }

        allMsgIds.add(m.id);
        labelKindByMsgId.set(m.id, kind);
        // Cache the whole message on the map so we don't re-fetch.
        labelKindByMsgId.set(m.id + "::msg", m);
        labelKindByMsgId.set(m.id + "::threadId", t.id);
        labelKindByMsgId.set(m.id + "::thread", thr.data.messages || []);
      }
    }

    let actioned = 0;
    let skipped = 0;
    let surfaced = 0;
    for (const mid of allMsgIds) {
      if (ioutletProcessedMessageIds.has(mid)) { skipped++; continue; }

      const kind = labelKindByMsgId.get(mid);
      const m = labelKindByMsgId.get(mid + "::msg");
      const threadId = labelKindByMsgId.get(mid + "::threadId");
      const headers = Object.fromEntries((m.payload.headers || []).map(h => [h.name, h.value]));
      const subject = headers.Subject || "";
      const body = extractEmailBodyPlaintext(m.payload);

      const supplierRef = extractIOutletSupplierReference(body, subject);
      if (!supplierRef) {
        console.log(`[bill-ling] iOutlet: ${mid} — no supplier_reference found, marking processed.`);
        ioutletProcessedMessageIds.add(mid);
        continue;
      }

      let agreement;
      try {
        agreement = await lookupAgreementBySupplierReference(supplierRef);
      } catch (err) {
        console.error(`[bill-ling] iOutlet BQ lookup failed for ${supplierRef}:`, err.message);
        continue;
      }
      if (!agreement) {
        // Flag to Hargo as "unmatched"
        try {
          await postIOutletDraftForReview({
            subject: `iOutlet (${kind}) — supplier_reference ${supplierRef} not found in BQ`,
            body: `Hi,\n\nReceived an iOutlet ${kind} email referencing supplier_reference ${supplierRef} but the BigQuery view returned no matching agreement.\n\nSubject: ${subject}\n\n[Billington — manual review needed]`,
          });
        } catch (e) { console.error(`[bill-ling] iOutlet unmatched-send failed:`, e.message); }
        ioutletProcessedMessageIds.add(mid);
        continue;
      }

      let anchorState;
      try {
        anchorState = await getIOutletAnchorState(agreement.agreementId);
      } catch (err) {
        console.error(`[bill-ling] iOutlet Anchor lookup failed for ${agreement.agreementId}:`, err.message);
        continue; // will retry next hour
      }

      // Before drafting, check the LATEST message is actually something a
      // templated cancellation/status reply can action. If it was already
      // answered earlier in the thread, or the latest message is a new question
      // Billington can't answer (e.g. a general process question), surface the
      // email for a human instead of sending a misleading confirmation.
      const threadMsgs = labelKindByMsgId.get(mid + "::thread") || [];
      const draftability = await assessIOutletDraftability(threadMsgs, kind, anchorState);
      if (draftability.action === "surface") {
        try {
          await postIOutletNeedsHumanReview({
            subject, supplierRef, agreement, anchorState,
            latestFrom: headers.From || "",
            latestDate: headers.Date || "",
            latestBody: body,
            reason: draftability.reason,
          });
        } catch (e) { console.error("[bill-ling] iOutlet surface failed:", e.message); }
        ioutletProcessedMessageIds.add(mid);
        surfaced++;
        console.log(`[bill-ling] iOutlet: ${supplierRef} → surfaced for human (${draftability.reason})`);
        continue;
      }

      const draft = kind === "status"
        ? buildIOutletStatusEnquiryDraft({ subject, supplierRef, agreement, anchorState })
        : buildIOutletCancellationDraft({ subject, supplierRef, agreement, anchorState });

      // Capture the source-email metadata so the DM "send email" responder
      // can reply to the original iOutlet thread directly.
      const fromHeader = headers.From || "";
      const replyToHeader = headers["Reply-To"] || "";
      const messageIdHeader = headers["Message-ID"] || headers["Message-Id"] || "";
      const ccHeader = headers.Cc || headers.CC || "";
      const fromAddress = (fromHeader.match(/<([^>]+)>/) || [, fromHeader])[1];
      const replyToAddress = replyToHeader
        ? (replyToHeader.match(/<([^>]+)>/) || [, replyToHeader])[1]
        : null;

      try {
        await postIOutletDraftForReview({
          ...draft,
          source: {
            gmailMessageId: m.id,
            gmailThreadId: threadId,
            fromAddress,
            replyToAddress,
            originalSubject: subject,
            originalMessageIdHeader: messageIdHeader,
            ccHeader,
          },
        });
        ioutletProcessedMessageIds.add(mid);
        actioned++;
        console.log(`[bill-ling] iOutlet: drafted ${kind} reply for ${supplierRef} → ${agreement.agreementId}`);
      } catch (err) {
        console.error(`[bill-ling] iOutlet send failed for ${supplierRef}:`, err.message);
      }
    }

    if (actioned > 0 || skipped > 0 || surfaced > 0) saveIOutletProcessed();
    console.log(`[bill-ling] iOutlet poll done: ${actioned} drafted, ${surfaced} surfaced for human, ${skipped} already-processed, ${allMsgIds.size - actioned - skipped - surfaced} skipped (no ref / errors).`);
  } catch (err) {
    console.error("[bill-ling] processIOutletEmails error:", err.message);
  }
}

// Boot-time load (deferred to after the module's let-bindings are initialised).
loadIOutletProcessedFromLocal();
loadIOutletProcessedFromGcs();

/**
 * Post the spec's templated alert to #team-ops-strategy-only when Aryza marks
 * a ticket resolved without supplying root cause / fix detail.
 *
 * Dedupes Slack-side rather than relying on aryza-tickets.json (which is
 * ephemeral on Railway restarts). We search the channel for a recent post
 * by Billington that already references this ticket with the same alert
 * text — if one exists, we don't post again.
 */
async function postPendingValidationSlack(ticket, gaps, latestSubject) {
  // Slack-side dedupe — scan recent messages in the channel for an existing
  // alert about this ticket. Bounded to the last 7 days so a future
  // re-resolution of the same ticket eventually re-alerts (after Hargo's
  // had reasonable time to validate the original).
  try {
    const sevenDaysAgoTs = String(Math.floor((Date.now() - 7 * 24 * 3600 * 1000) / 1000));
    const recent = await app.client.conversations.history({
      token: SLACK_BOT_TOKEN,
      channel: CHANNELS.TEAM_BILLING_OPERATIONS_EMAILS,
      limit: 200,
      oldest: sevenDaysAgoTs,
    });
    const ours = (recent.messages || []).find(m => {
      const isOurs = (BOT_USER_ID && m.user === BOT_USER_ID) || !!m.bot_id;
      if (!isOurs) return false;
      const body = m.text || "";
      return /Pending Raylo Validation/i.test(body) && body.includes(ticket.ref);
    });
    if (ours) {
      console.log(`[bill-ling] Pending-validation alert for ${ticket.ref} already exists in #team-ops-strategy-only (ts=${ours.ts}). Skipping repeat.`);
      return;
    }
  } catch (err) {
    console.warn(`[bill-ling] Could not check #team-ops-strategy-only history for existing ${ticket.ref} alert (will post anyway):`, err.message);
  }

  const gapStr = (gaps && gaps.length) ? gaps.join(" / ") : "root cause / fix detail";
  // Slack mrkdwn link format: <URL|label>. Prefer the portal URL captured
  // from the email body; fall back to the standard /browse/ URL.
  const ticketUrl = ticket.portalUrl || `https://aryza-lending.atlassian.net/browse/${ticket.ref}`;
  const ticketLink = `<${ticketUrl}|${ticket.ref}>`;
  const text =
`*Aryza Ticket — Pending Raylo Validation*
Ticket: ${ticketLink}
Subject: ${latestSubject || ticket.subject}
Status: Aryza marked resolved — not yet validated by Raylo
Gaps outstanding: ${gapStr}
Action needed: <@${HARGO_USER_ID}> or <@${REFUND_CONTACTS.PROCESSING.id}> to validate and confirm back to Billington (cc <@${CIARAN_DOBBIN_USER_ID}>)`;
  try {
    // Validation pass / fail buttons (Hargo, 26/06/2026). A click does the same
    // as a typed confirmation, but deterministically: Pass closes the ticket,
    // Fail re-opens it and resumes chasing Aryza. Gated to the validators
    // (Hargo / Charlotte / Ciaran) in the handlers.
    const validationBlocks = INTERACTIVE_BUTTONS_ENABLED ? [
      { type: "section", text: { type: "mrkdwn", text } },
      { type: "actions", elements: [
        {
          type: "button",
          text: { type: "plain_text", text: "✅ Validation pass", emoji: true },
          style: "primary",
          action_id: "btn_aryza_validate_pass",
          value: JSON.stringify({ ref: ticket.ref }),
          confirm: {
            title: { type: "plain_text", text: "Mark validated (pass)?" },
            text: { type: "mrkdwn", text: `Confirms Aryza's fix for ${ticket.ref} is valid and closes the ticket.` },
            confirm: { type: "plain_text", text: "Pass" },
            deny: { type: "plain_text", text: "Cancel" },
          },
        },
        {
          type: "button",
          text: { type: "plain_text", text: "❌ Validation fail", emoji: true },
          style: "danger",
          action_id: "btn_aryza_validate_fail",
          value: JSON.stringify({ ref: ticket.ref }),
          confirm: {
            title: { type: "plain_text", text: "Mark validation failed?" },
            text: { type: "mrkdwn", text: `Rejects Aryza's resolution for ${ticket.ref} — re-opens it and resumes chasing Aryza.` },
            confirm: { type: "plain_text", text: "Fail it" },
            deny: { type: "plain_text", text: "Cancel" },
          },
        },
      ]},
    ] : undefined;
    await app.client.chat.postMessage({
      token: SLACK_BOT_TOKEN,
      channel: CHANNELS.TEAM_BILLING_OPERATIONS_EMAILS,
      text,
      ...(validationBlocks ? { blocks: validationBlocks } : {}),
      mrkdwn: true,
      unfurl_links: false,
      unfurl_media: false,
    });
    console.log(`[bill-ling] Posted pending-validation alert to #team-billing-operations-emails for ${ticket.ref}.`);
  } catch (err) {
    console.error("[bill-ling] Failed to post pending-validation Slack alert:", err.message);
  }
}

/**
 * Schedule (or reschedule) the next follow-up for an issue ticket using the
 * existing reminder system. The followup_aryza action handler chases per the
 * priority cadence.
 */
function scheduleAryzaFollowup(ticket) {
  if (ticket.kind !== "issue" || ticket.status !== "open") return;
  const cadenceMs = priorityCadenceMs(ticket.priority);
  const fireAt = new Date(Date.now() + cadenceMs).toISOString();

  // Cancel any existing follow-up reminder for this ticket
  if (ticket.followupReminderId) {
    cancelReminder(ticket.followupReminderId);
  }

  const reminder = createReminder({
    createdBy: HARGO_USER_ID,
    targetUserId: HARGO_USER_ID,
    targetUserName: "Hargo",
    channel: CHANNELS.TEAM_BILLING_OPERATIONS_EMAILS,
    what: `Aryza follow-up: ${ticket.ref} (${ticket.priority || "P3"})`,
    fireAt,
    actionType: "aryza_followup",
    parentTs: null,
  });
  reminder.aryzaTicketRef = ticket.ref;
  ticket.followupReminderId = reminder.id;
  ticket.nextFollowupAt = fireAt;
  saveReminders();
}

/**
 * Process a single Gmail message we've identified as Aryza-related.
 * Updates ticket store and triggers the appropriate downstream actions.
 */
async function processAryzaMessage(msg) {
  const headers = msg.payload?.headers || [];
  const subject = getEmailHeader(headers, "Subject");
  const from    = getEmailHeader(headers, "From");
  const messageIdHdr = getEmailHeader(headers, "Message-ID");
  const refsHdr = getEmailHeader(headers, "References");
  const body = extractBody(msg.payload);

  // Extract the ticket ref (subject preferred, body fallback)
  const refMatch = (subject + " " + body).match(ARYZA_TICKET_PATTERN);
  if (!refMatch) {
    console.log(`[bill-ling] Aryza poll: skipping ${msg.id} — no LCSDL-XXXXX in subject/body.`);
    return;
  }
  const ref = refMatch[0].toUpperCase();

  const ticket = getOrCreateAryzaTicket(ref, { subject, threadId: msg.threadId });
  if (ticket.seenMessageIds.includes(msg.id)) return; // already processed
  ticket.seenMessageIds.push(msg.id);
  ticket.subject = ticket.subject || subject;
  ticket.gmailThreadId = ticket.gmailThreadId || msg.threadId;
  ticket.lastInboundAt = new Date().toISOString();

  // Extract Aryza service-desk link from the email body so we can deep-link
  // to it in Slack alerts. Two URL shapes show up in Aryza's notifications:
  //   - https://aryza-lending.atlassian.net/servicedesk/customer/portal/2/LCSDL-XXXXX
  //   - https://aryza-lending.atlassian.net/browse/LCSDL-XXXXX
  // Prefer the servicedesk portal link (matches the email's 'View request'
  // CTA). Persist on the ticket so subsequent alerts/drafts can re-use it.
  if (!ticket.portalUrl) {
    const portalMatch = (body || "").match(new RegExp(`https?://aryza-lending\\.atlassian\\.net/servicedesk/customer/portal/\\d+/${ref}\\b[^"\\s>]*`, "i"));
    const browseMatch = (body || "").match(new RegExp(`https?://aryza-lending\\.atlassian\\.net/browse/${ref}\\b`, "i"));
    if (portalMatch) ticket.portalUrl = portalMatch[0];
    else if (browseMatch) ticket.portalUrl = browseMatch[0];
    else ticket.portalUrl = `https://aryza-lending.atlassian.net/browse/${ref}`; // best-effort fallback
  }

  logTicketEvent(ticket, "inbound", `Email from ${from}: ${(subject || "").slice(0, 100)}`);

  // ── Aggressive global cap ─────────────────────────────────────────────
  // If Hargo has been DM'd ANYTHING about this ticket ref in the last 24h,
  // skip every per-ticket DM in this run. The pending-validation channel
  // post and the email-approval draft DM keep their own 7-day dedupes
  // because those are once-per-incident events; this cap targets the
  // chatty 'new ticket' / 'workaround needs Notion' DMs that were spamming
  // on Railway redeploys.
  const cappedForToday = await hasRecentDmAboutTicket(ref, 24);
  if (cappedForToday) {
    console.log(`[bill-ling] Aryza ${ref}: ticket was DM'd within last 24h — suppressing per-ticket DMs.`);
  }

  // Classify
  const cls = await classifyAryzaEmail({ subject, body });
  console.log(`[bill-ling] Aryza ${ref} classified: kind=${cls.kind}, priority=${cls.priority}, conf=${cls.confidence}, resolved=${cls.resolvedWithoutValidation}.`);

  // Apply classification (don't overwrite a confirmed value with a low-conf guess)
  const isFirstClassification = ticket.kind === "unknown";
  if (isFirstClassification || cls.confidence >= 0.7) {
    if (cls.kind !== "unknown") ticket.kind = cls.kind;
    if (cls.priority && !ticket.priorityConfirmed) ticket.priority = cls.priority;
  }
  if (!ticket.priority && ticket.kind === "issue") {
    ticket.priority = "P3"; // spec default
  }

  // Resolved-without-validation handling — post Slack alert + draft chase email
  // (own 7-day dedupes; not affected by the 24h ticket cap above).
  if (cls.resolvedWithoutValidation && ticket.status !== "pending_validation") {
    ticket.status = "pending_validation";
    await postPendingValidationSlack(ticket, cls.gaps, subject);
    const draft = buildResolvedWithoutValidationDraft(ticket, from);
    await queueDraftForApproval({
      ticketRef: ticket.ref,
      gmailThreadId: ticket.gmailThreadId,
      to: from,
      subject: draft.subject,
      body: draft.body,
      reason: "Aryza marked resolved without root cause/fix detail",
      inReplyTo: messageIdHdr || undefined,
      references: refsHdr ? `${refsHdr} ${messageIdHdr || ""}`.trim() : (messageIdHdr || undefined),
    });
    logTicketEvent(ticket, "pending_validation", "Aryza resolved without validation; chase drafted.");
  }

  // Low-confidence classification → DM Hargo to confirm kind. Suppressed by
  // the ticket-level 24h cap above; otherwise also Slack-side deduped on
  // its own message signature.
  if (isFirstClassification && !cappedForToday) {
    const newTicketPattern = new RegExp(`New Aryza\\s+(?:ticket|workaround|issue)[\\s\\S]{0,120}\\b${ticket.ref}\\b`, "i");
    const recentlyDmd = await hasRecentBillingtonDm(newTicketPattern, 24);
    if (recentlyDmd) {
      console.log(`[bill-ling] Skipping 'new ticket' DM for ${ticket.ref} — already DM'd in the last 24h.`);
    } else if (cls.confidence < 0.7) {
      try {
        await dmHargo(
          `🆕 *New Aryza ticket detected: ${ticket.ref}*\n` +
          `Subject: ${subject}\n` +
          `My best guess: *${cls.kind}* (${Math.round(cls.confidence * 100)}% confidence)` +
          (ticket.priority ? `, priority *${ticket.priority}*` : "") +
          `\n\n${cls.summary || "(no summary)"}\n\n` +
          `Reply *workaround ${ticket.ref}* or *issue ${ticket.ref}* to confirm.`
        );
      } catch (_) {}
    } else {
      try {
        await dmHargo(
          `🆕 *New Aryza ${ticket.kind}: ${ticket.ref}*` +
          (ticket.priority ? ` (${ticket.priority})` : "") +
          `\nSubject: ${subject}\n\n${cls.summary || "(no summary)"}`
        );
      } catch (_) {}
    }
  }

  // Workaround Notion lookup (placeholder until parent page ID is set).
  // Suppressed by the ticket-level 24h cap; otherwise Slack-side deduped
  // on its own message signature.
  if (ticket.kind === "workaround" && !ticket._workaroundChecked && !cappedForToday) {
    ticket._workaroundChecked = true;
    const lookup = await lookupWorkaroundInNotion(ref);
    if (!lookup.found) {
      const workaroundDmPattern = new RegExp(`Workaround\\s+\\b${ticket.ref}\\b[\\s\\S]{0,80}no matching Notion page`, "i");
      const recentlyDmd = await hasRecentBillingtonDm(workaroundDmPattern, 24);
      if (recentlyDmd) {
        console.log(`[bill-ling] Skipping workaround Notion DM for ${ticket.ref} — already DM'd in the last 24h.`);
      } else {
        try {
          await dmHargo(
            `📋 *Workaround ${ticket.ref}* — no matching Notion page yet.\n` +
            `To set this up, please confirm:\n` +
            `1. Description and context\n` +
            `2. Completion criteria / verification BigQuery query\n` +
            `3. Expected recurrence cadence (e.g. monthly, end of month)\n` +
            `4. Any specific actions I need to take\n` +
            `\nReply with the details and I'll create the Notion child page.`
          );
        } catch (_) {}
      }
    }
  }

  // Schedule follow-ups for issues
  if (ticket.kind === "issue" && ticket.status === "open") {
    scheduleAryzaFollowup(ticket);
  }

  saveAryzaTickets();
}

/**
 * Hourly poll: list new emails matching the Aryza filter and process each.
 */
let aryzaLastPollAt = null;

async function pollAryzaInbox() {
  if (!gmailBillingOpsClient) {
    console.log("[bill-ling] Aryza poll skipped — billingoperations@ Gmail client not initialised.");
    return;
  }
  console.log("[bill-ling] Aryza inbox poll starting...");
  try {
    // Labelling disabled (Hargo, 22/05/2026) — Billington must not touch
    // the billingoperations inbox with modify actions. Dedup relies solely
    // on seenMessageIds in aryza-tickets.json.
    const lookbackHours = 26;
    const sinceEpochSec = Math.floor((Date.now() - lookbackHours * 3600 * 1000) / 1000);
    const q = `(from:${ARYZA_FROM_ADDRESS} OR subject:LCSDL-) after:${sinceEpochSec}`;
    const list = await gmailBillingOpsClient.users.messages.list({
      userId: "me", q, maxResults: 50,
    });
    const messages = list.data.messages || [];
    console.log(`[bill-ling] Aryza poll: ${messages.length} unprocessed candidate message(s) in last ${lookbackHours}h.`);

    let processed = 0;
    for (const m of messages) {
      // Belt-and-braces in-process dedupe (in case the same poll lists the
      // same id twice, or a previous poll in this process saw it).
      const seen = aryzaTickets.some(t => t.seenMessageIds.includes(m.id));
      if (seen) {
        // Still mark in Gmail so future polls skip it via the label filter.
        await markAryzaMessageProcessed(m.id);
        continue;
      }
      try {
        const full = await gmailBillingOpsClient.users.messages.get({
          userId: "me", id: m.id, format: "full",
        });
        await processAryzaMessage(full.data);
        // Tag in Gmail AFTER successful processing — if we crashed mid-way
        // the next poll will retry, but the message stays unlabelled.
        await markAryzaMessageProcessed(m.id);
        processed++;
      } catch (err) {
        console.error(`[bill-ling] Aryza poll: failed to process ${m.id}:`, err.message);
      }
    }
    aryzaLastPollAt = new Date().toISOString();
    saveAryzaTickets();
    console.log(`[bill-ling] Aryza poll complete: ${processed} new message(s) processed.`);
  } catch (err) {
    console.error("[bill-ling] Aryza poll failed:", err.message);
  }
}

/**
 * Handle a Hargo DM that may be approving / editing / cancelling a queued draft.
 * Returns true if the DM was consumed (caller should not fall through to LLM).
 */
async function handleAryzaDraftDM(text, userId) {
  if (userId !== HARGO_USER_ID) return false;
  if (aryzaPendingDrafts.length === 0) return false;
  const trimmed = (text || "").trim();
  if (!trimmed) return false;

  // Auto-expire awaiting-approval drafts older than 6 hours so a stale one
  // doesn't block every subsequent DM Hargo sends.
  const STALE_HOURS = 6;
  const nowMs = Date.now();
  let expired = false;
  for (const d of aryzaPendingDrafts) {
    if (d.status !== "awaiting_approval" || !d.createdAt) continue;
    const ageHours = (nowMs - new Date(d.createdAt).getTime()) / 3600000;
    if (Number.isFinite(ageHours) && ageHours > STALE_HOURS) {
      d.status = "expired";
      d.expiredAt = new Date().toISOString();
      expired = true;
      console.log(`[bill-ling] Aryza draft #${d.id} (${d.ticketRef}) auto-expired after ${ageHours.toFixed(1)}h.`);
    }
  }
  if (expired) saveAryzaTickets();

  // Most recent draft awaiting approval is the implicit target
  const draft = [...aryzaPendingDrafts].reverse().find(d => d.status === "awaiting_approval");
  if (!draft) return false;

  // Optional explicit reference: "send #3" or "cancel #2"
  const explicitId = (trimmed.match(/^#?(?:send|cancel|approve|drop)\s+#?(\d+)/i) || [])[1];
  const targetDraft = explicitId
    ? aryzaPendingDrafts.find(d => d.id === Number(explicitId))
    : draft;
  if (!targetDraft) return false;

  if (/^(send|approve|ok|go)(\s+#?\d+)?\s*$/i.test(trimmed)) {
    try {
      const sent = await sendAryzaEmail(targetDraft);
      targetDraft.status = "sent";
      targetDraft.sentAt = new Date().toISOString();
      targetDraft.sentMessageId = sent.id;
      const ticket = aryzaTickets.find(t => t.ref === targetDraft.ticketRef);
      if (ticket) {
        ticket.lastOutboundAt = targetDraft.sentAt;
        logTicketEvent(ticket, "outbound", `Sent draft #${targetDraft.id} to ${targetDraft.to}: ${targetDraft.subject}`);
      }
      saveAryzaTickets();
      await dmHargo(`✅ Sent draft #${targetDraft.id} to ${targetDraft.to} (${targetDraft.ticketRef}).`);
    } catch (err) {
      console.error("[bill-ling] Failed to send Aryza draft:", err.message);
      await dmHargo(`❌ Failed to send draft #${targetDraft.id}: ${err.message}`);
    }
    return true;
  }

  if (/^(cancel|drop|discard|no)(\s+#?\d+)?\s*$/i.test(trimmed)) {
    targetDraft.status = "cancelled";
    targetDraft.cancelledAt = new Date().toISOString();
    saveAryzaTickets();
    await dmHargo(`🗑️ Dropped draft #${targetDraft.id} (${targetDraft.ticketRef}).`);
    return true;
  }

  // Edit-the-draft path. Previously this swallowed ANY >30-char message that
  // wasn't a workaround/issue confirmation — which meant a question like
  // "what's the outstanding principal on A00348108?" got eaten as a draft
  // edit. Now we only treat the message as an edit when it actually looks
  // like a draft body:
  //   - explicitly prefixed with `edit:` / `body:` / `content:`, OR
  //   - multi-line (a real email body almost always is), AND
  //   - doesn't look like a query/command to Billington.
  const explicitEdit = /^(edit|body|content):\s*/i.test(trimmed);
  const isMultiline = /\n/.test(trimmed);
  // Patterns that strongly suggest the operator is asking a question rather
  // than amending the draft. Mention of the bot, common interrogatives,
  // explicit command verbs, or any agreement ID all defer to the LLM/intent
  // router instead.
  const looksLikeQuery = (
    /<@[A-Z0-9]+>/.test(trimmed)
    || /(?:^|\s)@\s*billington\b/i.test(trimmed)
    || /\?/.test(trimmed)
    || /^(what|how|why|when|who|where|which)\b/i.test(trimmed)
    || /\b(check|show|list|find|get|run|post|trigger|update|refresh|status|tell\s+me|look\s+up)\b/i.test(trimmed)
    || /\bA\d{5,9}\b/i.test(trimmed)
  );

  if ((explicitEdit || isMultiline) && !looksLikeQuery && trimmed.length > 30 && !/^(workaround|issue)\s+LCSDL/i.test(trimmed)) {
    const body = explicitEdit ? trimmed.replace(/^(edit|body|content):\s*/i, "") : trimmed;
    targetDraft.body = body;
    targetDraft.status = "awaiting_approval"; // still needs send
    saveAryzaTickets();
    await dmHargo(`✏️ Updated draft #${targetDraft.id} body. Reply *send* to approve, or paste another edit.`);
    return true;
  }

  // Not a draft edit — let the normal DM flow handle it.
  return false;
}

/**
 * Hargo confirms ticket kind via DM: "workaround LCSDL-12345" or "issue LCSDL-12345 P2".
 */
async function handleAryzaKindDM(text, userId) {
  if (userId !== HARGO_USER_ID) return false;
  const m = (text || "").match(/^(workaround|issue)\s+(LCSDL-\d{4,6})(?:\s+(P[1-5]))?\s*$/i);
  if (!m) return false;
  const [, kind, ref, priority] = m;
  const ticket = aryzaTickets.find(t => t.ref === ref.toUpperCase());
  if (!ticket) {
    await dmHargo(`I don't have a ticket for ${ref.toUpperCase()} on file. Has it come in yet?`);
    return true;
  }
  ticket.kind = kind.toLowerCase();
  if (priority) {
    ticket.priority = priority.toUpperCase();
    ticket.priorityConfirmed = true;
  }
  logTicketEvent(ticket, "manual_classify", `Hargo set kind=${ticket.kind}${priority ? `, priority=${ticket.priority}` : ""}`);
  if (ticket.kind === "issue" && ticket.status === "open") {
    scheduleAryzaFollowup(ticket);
  }
  saveAryzaTickets();
  await dmHargo(`✅ ${ticket.ref} set to *${ticket.kind}*${ticket.priority ? ` (${ticket.priority})` : ""}.`);
  return true;
}

