// ---------------------------------------------------------------------------
// Daily summary
// ---------------------------------------------------------------------------

/**
 * Fetch messages from all monitored channels, build a prompt, send to Claude,
 * and DM the result to Hargo.
 */
async function runDailySummary() {
  console.log("[bill-ling] Running daily summary...");

  try {
    // Fetch all channels in parallel
    const channelEntries = Object.entries(CHANNELS);
    const histories = await Promise.all(
      channelEntries.map(([, id]) => fetchChannelHistory(id))
    );

    // Build the formatted channel block for the prompt
    let channelBlock = "";
    channelEntries.forEach(([key, id], index) => {
      const name = CHANNEL_NAMES[id] || key;
      channelBlock += `\n\n--- ${name} (${id}) ---\n${histories[index]}`;
    });

    const userMessage =
      "Please produce the daily channel summary for all 5 channels based on the messages below. Format it clearly for Slack.\n\n" +
      channelBlock;

    const summary = await askClaude(userMessage);

    await dmHargo(summary);

    console.log("[bill-ling] Daily summary sent to Hargo.");
  } catch (err) {
    console.error("[bill-ling] Error running daily summary:", err);
    // Attempt to notify Hargo of the failure rather than silently dropping it
    try {
      await dmHargo(
        `Bill Ling here. I ran into an error generating today's summary: ${err.message}. I'll try again at the next scheduled run.`
      );
    } catch (notifyErr) {
      console.error(
        "[bill-ling] Could not notify Hargo of summary error:",
        notifyErr.message
      );
    }
  }
}

// ---------------------------------------------------------------------------
// Cron: 8am Mon-Fri — BACS batch forecast (next ungenerated batch)
// ---------------------------------------------------------------------------
async function runBacsBatchForecastCron() {
  const today = new Date().toLocaleDateString("en-CA", { timeZone: "Europe/London" });
  if (!isWorkingDay(today)) {
    console.log(`[bill-ling] BACS forecast cron: skipping — ${today} is not a working day.`);
    return;
  }
  console.log("[bill-ling] Running 9am BACS batch forecast cron...");
  try {
    // Only show batches whose generate-by deadline is today or in the future.
    // generate-by = due_date - 3 working days, so min due_date = today + 3 working days.
    const minDueDate = nextWorkingDay(nextWorkingDay(nextWorkingDay(today)));
    const forecast = await getPreBatchForecast(`due_date >= '${minDueDate}'`, 1);
    const text = forecast || "No upcoming ungenerated BACS batches found.";
    await app.client.chat.postMessage({
      token: SLACK_BOT_TOKEN,
      channel: CHANNELS.DATA_BILLING_UPDATES,
      text,
      mrkdwn: true,
    });
    console.log("[bill-ling] 8am BACS batch forecast posted to #data-billing-updates.");
  } catch (err) {
    console.error("[bill-ling] Error running BACS batch forecast cron:", err);
    try { await dmHargo(`Error generating BACS batch forecast: ${err.message}`); } catch (_) {}
  }
}

// ---------------------------------------------------------------------------
// Missing Instalment Due check — compares Anchor PaymentProfile vs Transactions
// For each profile date on or before today, there should be a TypeId 99 transaction
// with a Gross matching the sum of PaymentAmounts for that date.
// ---------------------------------------------------------------------------

/**
 * Check a single agreement for missing instalment due transactions.
 * Returns { agId, confirmed: [{ date, expected, actual }], missing: [{ date, expected }] }
 */
async function checkMissingInstalments(agreementId) {
  const xml = await getAgreementFromAnchor(agreementId);
  const today = new Date().toLocaleDateString("en-CA", { timeZone: "Europe/London" });

  // Parse PaymentProfile — sum PaymentAmounts per date (non-namespaced tags)
  const profileEntries = xml.split(/<(?:a:)?PaymentProfile>/).filter(e => e.includes("PaymentDate"));
  const profileByDate = {};
  for (const entry of profileEntries) {
    const dateMatch = entry.match(/<(?:a:)?PaymentDate>([^<]+)<\/(?:a:)?PaymentDate>/);
    const amountMatch = entry.match(/<(?:a:)?PaymentAmount>([^<]+)<\/(?:a:)?PaymentAmount>/);
    if (!dateMatch || !amountMatch) continue;
    const date = dateMatch[1].slice(0, 10);
    if (date > today) continue; // only check dates up to today
    const amount = parseFloat(amountMatch[1]) || 0;
    profileByDate[date] = (profileByDate[date] || 0) + amount;
  }

  // Parse Transactions — collect TypeId 99 Gross amounts per date
  const txnBlocks = xml.split(/<(?:a:)?Transaction>/).filter(t => t.includes("</"));
  const type99ByDate = {};
  for (const block of txnBlocks) {
    const typeMatch = block.match(/<(?:a:)?TypeId>(\d+)<\/(?:a:)?TypeId>/);
    if (!typeMatch || parseInt(typeMatch[1], 10) !== 99) continue;
    const dateMatch = block.match(/<(?:a:)?TransactionDate>([^<]+)<\/(?:a:)?TransactionDate>/);
    const grossMatch = block.match(/<(?:a:)?Gross>([^<]+)<\/(?:a:)?Gross>/);
    if (!dateMatch) continue;
    const date = dateMatch[1].slice(0, 10);
    // Keep sign — PaymentAmount in the profile is negative (debit), Gross on TypeId 99 is also
    // negative. Stripping the sign with Math.abs causes a false mismatch: actual=+29 vs expected=-29.
    const gross = grossMatch ? parseFloat(grossMatch[1]) : 0;
    type99ByDate[date] = (type99ByDate[date] || 0) + gross;
  }

  // Compare: for each profile date, check if there's a matching TypeId 99 transaction.
  // Match rule: TypeId 99 Gross is the negation of PaymentProfile.PaymentAmount, i.e.
  // gross + profile_amount ≈ 0 (opposite signs). A regular instalment of +£18.48 in the
  // profile is expected as a -£18.48 debit in TypeId 99; an LPF reversal of -£29.00 in
  // the profile is expected as a +£29.00 credit. Mismatch = no transaction (actual=0)
  // or wrong amount/sign so the pair doesn't sum to zero.
  const confirmed = [];
  const missing = [];
  for (const [date, expectedTotal] of Object.entries(profileByDate)) {
    const roundedExpected = Math.round(expectedTotal * 100) / 100;
    const actualTotal = type99ByDate[date] || 0;
    const roundedActual = Math.round(actualTotal * 100) / 100;
    if (Math.abs(roundedActual + roundedExpected) < 0.02) {
      confirmed.push({ date, expected: roundedExpected, actual: roundedActual });
    } else {
      missing.push({ date, expected: roundedExpected, actual: roundedActual });
    }
  }

  return { agId: agreementId, confirmed, missing };
}

/**
 * Cron job: query BigQuery for flagged agreements, then verify each via Anchor.
 */
// Store the last missing instalment check result for on-demand drill-down
let lastMissingInstalmentResult = { flaggedRows: [], allConfirmed: [], allMissing: [], ts: null };

// Recheck timer: ONLY scheduled when the cron finds >10 flagged
// agreements (too many to individually verify via Anchor). At that
// volume we re-run 5h later in case more data has landed and reduced
// the count to something we can verify. For 0-flagged or ≤10-with-
// clean Anchor verification, no recheck — those are already a clean
// pass and a daily re-run is just noise (per 11/05 user feedback).
let missingInstalmentRecheckTimer = null;

async function runMissingInstalmentCheck(opts = {}) {
  const isRecheck = !!opts.isRecheck;
  // Schedule ONE follow-up recheck. Used by the >10 path only.
  // Cleared on every run so we never overlap timers.
  const scheduleRecheckIn5h = () => {
    if (isRecheck) return; // already a recheck — don't chain another
    if (missingInstalmentRecheckTimer) clearTimeout(missingInstalmentRecheckTimer);
    missingInstalmentRecheckTimer = setTimeout(() => {
      missingInstalmentRecheckTimer = null;
      runMissingInstalmentCheck({ isRecheck: true })
        .catch(err => console.error("[bill-ling] Missing instalment recheck failed:", err.message));
    }, 5 * 60 * 60 * 1000); // 5 hours
    console.log("[bill-ling] Missing instalment check has >10 flagged agreements — scheduled recheck in 5 hours.");
  };

  console.log(`[bill-ling] Running missing instalment due control check${isRecheck ? " (recheck)" : ""}...`);
  try {
    const [rows] = await bigquery.query({
      query: "SELECT * FROM `raylo-production.landing_billington.controls_missing_instalment_check`",
      location: "EU",
    });

    const todayFmt = new Date().toLocaleDateString("en-GB", { day: "2-digit", month: "2-digit", year: "numeric", timeZone: "Europe/London" });
    const recheckSuffix = isRecheck ? " (recheck)" : "";

    if (!rows || rows.length === 0) {
      console.log("[bill-ling] Missing instalment check: 0 rows — all clear.");
      lastMissingInstalmentResult = { flaggedRows: [], allConfirmed: [], allMissing: [], ts: null };
      const result = await app.client.chat.postMessage({
        token: SLACK_BOT_TOKEN,
        channel: CHANNELS.DATA_BILLING_UPDATES,
        text: `✅ *Missing Instalment Due Check — ${todayFmt}${recheckSuffix}*\nAll instalment due transactions have been posted. No agreements flagged.`,
        mrkdwn: true,
        unfurl_links: false,
        unfurl_media: false,
      });
      lastMissingInstalmentResult.ts = result.ts;
      // 0 flagged → no recheck. Next 12pm cron tomorrow picks up.
      return;
    }

    console.log(`[bill-ling] Missing instalment check: ${rows.length} row(s) found.`);

    // Store raw flagged rows for on-demand drill-down
    const flaggedRows = rows.map(r => ({
      agreementId: r.collections_agreements_missing_instalment_due_arrears_estimates_agreement_id,
      estimatedPia: Number(r.collections_agreements_missing_instalment_due_arrears_estimates_estimated_pia) || 0,
      earliestMissing: formatBQValue(r.collections_agreements_missing_instalment_due_arrears_estimates_earliest_instalment_missing_date),
      latestMissing: formatBQValue(r.collections_agreements_missing_instalment_due_arrears_estimates_latest_instalment_missing_date),
      recurringAmount: Number(formatBQValue(r.collections_agreements_missing_instalment_due_arrears_estimates_recurring_total_amount_after_tax)) || 0,
      estimatedArrears: Number(formatBQValue(r.collections_agreements_missing_instalment_due_arrears_estimates_sum_estimated_arrears)) || 0,
      missingInstalments: Number(formatBQValue(r.collections_agreements_missing_instalment_due_arrears_estimates_sum_missing_instalments)) || 0,
    }));

    if (rows.length > 10) {
      // Too many to verify via API — report summary with totals AND the
      // BigQuery query inline so the operator can pull the full list
      // without needing to ask for it. Per Hargo's 06/05 feedback:
      // include the SQL in the initial post when count > 10.
      // Per Hargo's 11/05 feedback: schedule a 5h recheck here — this
      // is the volume band where data is most likely still landing.
      const totalMissingInstalments = flaggedRows.reduce((s, r) => s + r.missingInstalments, 0);
      const totalEstimatedArrears = flaggedRows.reduce((s, r) => s + r.estimatedArrears, 0);
      const text =
        `🚨 *Missing Instalment Due Check — ${todayFmt}${recheckSuffix}*\n` +
        `*${rows.length}* agreements flagged with missing instalment due transactions.\n` +
        `Total missing instalments: ${totalMissingInstalments.toLocaleString("en-GB")}\n` +
        `Total estimated arrears: £${totalEstimatedArrears.toLocaleString("en-GB", { minimumFractionDigits: 2, maximumFractionDigits: 2 })}\n\n` +
        `Too many to verify individually via Anchor API. <@${HARGO_USER_ID}> / <@${REFUND_CONTACTS.PROCESSING.id}> / <@${CIARAN_DOBBIN_USER_ID}> please investigate.\n\n` +
        `*Full population query:*\n` +
        "```\n" +
        "SELECT *\n" +
        "FROM `raylo-production.landing_billington.controls_missing_instalment_check`\n" +
        "ORDER BY collections_agreements_missing_instalment_due_arrears_estimates_sum_estimated_arrears DESC\n" +
        "```" +
        (isRecheck ? "" : "\n_I'll re-check in 5 hours in case more data has landed and the count drops to a verifiable level._");
      const result = await app.client.chat.postMessage({
        token: SLACK_BOT_TOKEN,
        channel: CHANNELS.DATA_BILLING_UPDATES,
        text,
        mrkdwn: true,
        unfurl_links: false,
        unfurl_media: false,
      });
      lastMissingInstalmentResult = { flaggedRows, allConfirmed: [], allMissing: [], ts: result.ts };
      // >10 → recheck in 5h.
      scheduleRecheckIn5h();
      return;
    }

    // <= 10: verify each via Anchor API
    const allConfirmed = [];
    const allMissing = [];

    for (const row of rows) {
      const agId = row.collections_agreements_missing_instalment_due_arrears_estimates_agreement_id;
      try {
        const apiResult = await checkMissingInstalments(agId);
        if (apiResult.missing.length > 0) {
          allMissing.push(apiResult);
        } else {
          allConfirmed.push(apiResult);
        }
      } catch (err) {
        console.error(`[bill-ling] Missing instalment API check failed for ${agId}:`, err.message);
        allMissing.push({ agId, confirmed: [], missing: [{ date: "unknown", expected: 0, actual: 0, error: err.message }] });
      }
    }

    const lines = [`*Missing Instalment Due Check — ${todayFmt}${recheckSuffix}*\n`];

    if (allMissing.length === 0) {
      // All flagged agreements verified OK via API. No recheck — the
      // BigQuery flags were false alarms, Anchor's clean, nothing to
      // chase. Next 12pm cron picks up tomorrow.
      lines.push(`✅ All instalment due transactions have been posted.`);
      lines.push(`${allConfirmed.length} agreement(s) flagged by BigQuery but all verified correct via Anchor API.`);
      for (const r of allConfirmed) {
        lines.push(`  › ${r.agId} — ${r.confirmed.length} instalment(s) confirmed`);
      }
    } else {
      if (allConfirmed.length > 0) {
        lines.push(`✅ *${allConfirmed.length} agreement(s) — all instalments posted correctly* (verified via Anchor API)`);
        for (const r of allConfirmed) {
          lines.push(`  › ${r.agId} — ${r.confirmed.length} instalment(s) confirmed`);
        }
        lines.push(``);
      }

      const totalMissingValue = allMissing.reduce((s, r) => s + r.missing.reduce((s2, m) => s2 + (m.expected || 0), 0), 0);
      const processingTarget = await getAvailableChaseTarget(REFUND_CHASE_CHAINS.PROCESSING);
      lines.push(`❌ *${allMissing.length} agreement(s) — missing instalment due transactions* (£${totalMissingValue.toFixed(2)} total):`);
      for (const r of allMissing) {
        for (const m of r.missing) {
          const errNote = m.error ? ` (API error: ${m.error})` : "";
          const actualNote = m.actual !== 0 ? ` (found £${m.actual.toFixed(2)} — mismatch)` : "";
          lines.push(`  › ${r.agId} — ${m.date} — expected £${m.expected.toFixed(2)}${actualNote}${errNote}`);
        }
      }
      lines.push(``);
      lines.push(`<@${HARGO_USER_ID}> / <@${processingTarget.id}> / <@${CIARAN_DOBBIN_USER_ID}> — these need to be posted.`);
    }

    const result = await app.client.chat.postMessage({
      token: SLACK_BOT_TOKEN,
      channel: CHANNELS.DATA_BILLING_UPDATES,
      text: lines.join("\n"),
      mrkdwn: true,
      unfurl_links: false,
      unfurl_media: false,
    });
    lastMissingInstalmentResult = { flaggedRows, allConfirmed, allMissing, ts: result.ts };
    console.log(`[bill-ling] Missing instalment check complete: ${allConfirmed.length} confirmed, ${allMissing.length} with missing.`);
    // No recheck scheduled in the <=10 branch. The 5h recheck only fires
    // for the >10 case (where data is most likely still landing). For
    // <=10 with anything genuinely missing, the team has work to do
    // and a follow-up post would just be noise.
  } catch (err) {
    console.error("[bill-ling] Missing instalment check error:", err.message);
  }
}

/**
 * Get a summary of the last missing instalment check results for on-demand drill-down.
 */
function getMissingInstalmentDrillDown() {
  const { flaggedRows, allMissing } = lastMissingInstalmentResult;
  if (!flaggedRows.length && !allMissing.length) {
    return "No agreements flagged in the last missing instalment check. All clear.";
  }

  const lines = [`*Missing Instalment Due — Flagged Agreements*\n`];

  if (allMissing.length > 0) {
    // We have API-verified results
    lines.push(`*API-verified missing (${allMissing.length}):*`);
    for (const r of allMissing) {
      for (const m of r.missing) {
        const errNote = m.error ? ` (API error: ${m.error})` : "";
        const actualNote = m.actual !== 0 ? ` (found £${m.actual.toFixed(2)} — mismatch)` : "";
        lines.push(`  › ${r.agId} — ${m.date} — expected £${m.expected.toFixed(2)}${actualNote}${errNote}`);
      }
    }
  }

  if (flaggedRows.length > allMissing.length) {
    // Show sample of BigQuery-flagged agreements (first 15)
    const sample = flaggedRows.slice(0, 15);
    lines.push(``);
    lines.push(`*BigQuery-flagged agreements (showing ${sample.length} of ${flaggedRows.length}):*`);
    for (const r of sample) {
      const missingDates = r.earliestMissing === r.latestMissing
        ? r.earliestMissing
        : `${r.earliestMissing} to ${r.latestMissing}`;
      lines.push(`  › ${r.agreementId} — ${r.missingInstalments} missing — £${r.estimatedArrears.toFixed(2)} est. arrears — ${missingDates}`);
    }
    if (flaggedRows.length > 15) {
      lines.push(`  ...and ${flaggedRows.length - 15} more. Query BigQuery for full list:`);
      lines.push("```SELECT * FROM `raylo-production.landing_billington.controls_missing_instalment_check` ORDER BY collections_agreements_missing_instalment_due_arrears_estimates_sum_estimated_arrears DESC```");
    }
  }

  return lines.join("\n");
}

// ---------------------------------------------------------------------------
// Bank holiday profile check — daily 12pm, posts to #data-billing-updates
// ---------------------------------------------------------------------------

/**
 * Check a single agreement's Anchor PaymentProfile for future payment dates
 * that fall on UK bank holidays OR weekends. BACS doesn't process on either,
 * and the BigQuery view `bank_holiday_profile_check` mirrors that — flagging
 * any future payment with `DAYOFWEEK NOT BETWEEN 2 AND 6` (Sat/Sun) OR a
 * matching bank-holiday-table row. The per-agreement Anchor cross-check
 * must use the same definition or it'll falsely classify a Sat/Sun-due
 * agreement as "corrected".
 *
 * Returns { agreementId, bankHolidayDates: string[] } where each entry is
 * a YYYY-MM-DD date falling on a bank holiday or weekend.
 */
async function checkAgreementForBankHolidayDates(agreementId) {
  const xml = await getAgreementFromAnchor(agreementId);
  const today = new Date().toLocaleDateString("en-CA", { timeZone: "Europe/London" });
  const profileEntries = xml.split(/<(?:a:)?PaymentProfile>/).filter(e => e.includes("PaymentDate"));
  const seen = new Set();
  const bankHolidayDates = [];
  for (const entry of profileEntries) {
    const dateMatch = entry.match(/<(?:a:)?PaymentDate>([^<]+)<\/(?:a:)?PaymentDate>/);
    if (!dateMatch) continue;
    const date = dateMatch[1].slice(0, 10);
    if (date <= today) continue; // only check future payments
    if (seen.has(date)) continue;
    const isBankHoliday = UK_BANK_HOLIDAYS.has(date);
    // Parse YYYY-MM-DD into a UTC midnight Date and read its UTC weekday so
    // we get a stable answer regardless of the host TZ. UTC dow: 0=Sun, 6=Sat.
    const [y, m, d] = date.split("-").map(Number);
    const dow = new Date(Date.UTC(y, m - 1, d)).getUTCDay();
    const isWeekend = dow === 0 || dow === 6;
    if (isBankHoliday || isWeekend) {
      seen.add(date);
      bankHolidayDates.push(date);
    }
  }
  return { agreementId, bankHolidayDates };
}

/**
 * Apply the bank-holiday/weekend fix for one agreement. Hargo, 29/06/2026:
 * re-submit each bad PaymentProfile date to Anchor AS THE SAME DATE
 * (ChangePayProDueDate, IsSinglePaymentChange) — Anchor itself auto-rolls a
 * bank-holiday/weekend date to the next valid working day, so we don't compute
 * the target date (its working-day logic is authoritative). After submitting,
 * re-fetch to confirm the dates are no longer on bank holidays/weekends.
 * Shared by the typed `fix bank holiday` command and the Fix button.
 * Returns { agreementId, submitted:[date], failures:[{badDate,error}], remaining:[date], nothingToFix }.
 */
async function fixBankHolidayDatesForAgreement(agId) {
  const { bankHolidayDates } = await checkAgreementForBankHolidayDates(agId);
  if (!bankHolidayDates || bankHolidayDates.length === 0) {
    return { agreementId: agId, submitted: [], failures: [], remaining: [], nothingToFix: true };
  }
  const submitted = [];
  const failures = [];
  for (const badDate of [...bankHolidayDates].sort()) {
    const newDueDay = Number(badDate.slice(-2)); // day-of-month = agreement's existing dueday
    try {
      // Same date in and out — Anchor auto-adjusts it to the next working day.
      await changePayProDueDate(agId, badDate, badDate, newDueDay);
      submitted.push(badDate);
    } catch (err) {
      failures.push({ badDate, error: err.message });
    }
  }
  // Confirm Anchor moved them off bank holidays / weekends.
  let remaining = [];
  try {
    const after = await checkAgreementForBankHolidayDates(agId);
    remaining = after.bankHolidayDates || [];
  } catch (_) { /* best-effort confirmation only */ }
  return { agreementId: agId, submitted, failures, remaining, nothingToFix: false };
}

/**
 * Core logic: query BigQuery + verify via Anchor API.
 * Returns:
 *   { text, count, stillFlagged, rowCount } on success (text is the formatted report)
 *   { text: null, count: 0, stillFlagged: [], rowCount: 0 } if all clear
 *
 * stillFlagged: [{ agId, bankHolidayDates }] — populated for ≤10 results only
 * rowCount: raw BQ row count (before dedup) — used to detect >10 path
 * Shared by the 12pm cron and the on-demand mention/DM handler.
 */
async function buildBankHolidayReportText() {
  const todayStr = new Date().toLocaleDateString("en-CA", { timeZone: "Europe/London" });
  const now = new Date().toLocaleTimeString("en-GB", { hour: "2-digit", minute: "2-digit", timeZone: "Europe/London" });

  const rows = await runBigQueryRaw(`
    SELECT *
    FROM \`raylo-production.landing_billington.bank_holiday_profile_check\`
  `);

  if (rows.length === 0) return { text: null, count: 0, stillFlagged: [], rowCount: 0 };

  const header = `*Bank Holiday Profile Check — ${fmtDate(todayStr)} ${now}*\n`;

  if (rows.length > 10) {
    const lines = [
      header,
      `⚠️ *${rows.length.toLocaleString("en-GB")} agreements* have instalments falling due on a bank holiday.`,
      ``,
      `Full population query:`,
      "```",
      "SELECT * FROM `raylo-production.landing_billington.bank_holiday_profile_check`",
      "```",
    ];
    return { text: lines.join("\n"), count: rows.length, stillFlagged: [], rowCount: rows.length };
  }

  // ≤10 rows — verify each via Anchor API
  const agIds = [...new Set(
    rows.map(r => formatBQValue(r.agreement_id)).filter(Boolean).map(id => id.toUpperCase())
  )];

  const stillFlagged = [];
  const nowCorrected = [];
  const errors = [];

  for (const agId of agIds) {
    try {
      const { bankHolidayDates } = await checkAgreementForBankHolidayDates(agId);
      if (bankHolidayDates.length > 0) {
        stillFlagged.push({ agId, bankHolidayDates });
      } else {
        nowCorrected.push(agId);
      }
    } catch (err) {
      console.error(`[bill-ling] Bank holiday Anchor check failed for ${agId}:`, err.message);
      errors.push({ agId, error: err.message });
    }
  }

  const lines = [header];

  if (stillFlagged.length > 0) {
    lines.push(`⚠️ *${stillFlagged.length} agreement${stillFlagged.length === 1 ? "" : "s"} still have instalments due on bank holidays or weekends:*`);
    for (const { agId, bankHolidayDates } of stillFlagged) {
      const dateList = bankHolidayDates
        .sort()
        .map(d => {
          if (UK_BANK_HOLIDAY_NAMES[d]) return `${fmtDate(d)} — ${UK_BANK_HOLIDAY_NAMES[d]}`;
          if (UK_BANK_HOLIDAYS.has(d)) return `${fmtDate(d)} — bank holiday`;
          // Weekend fallback — name the day for clarity
          const [y, m, day] = d.split("-").map(Number);
          const dow = new Date(Date.UTC(y, m - 1, day)).getUTCDay();
          return `${fmtDate(d)} — ${dow === 0 ? "Sunday" : "Saturday"}`;
        })
        .join(", ");
      lines.push(`  › *${agId}* — ${dateList}`);
    }
  }

  if (nowCorrected.length > 0) {
    lines.push(``);
    lines.push(`✅ *${nowCorrected.length} agreement${nowCorrected.length === 1 ? "" : "s"} now corrected* — no future payments on bank holidays or weekends:`);
    lines.push(`  › ${nowCorrected.join(", ")}`);
  }

  if (errors.length > 0) {
    lines.push(``);
    lines.push(`❌ Anchor API errors: ${errors.map(e => `${e.agId} (${e.error})`).join(", ")}`);
  }

  return { text: lines.join("\n"), count: agIds.length, stillFlagged, rowCount: rows.length };
}

/**
 * Blocks for a bank-holiday report: the message text (chunked into section
 * blocks) + a "🔧 Fix <agId>" button per still-flagged agreement. A click runs
 * the same Anchor ChangePayProDueDate fix as the typed `fix bank holiday`
 * command, gated to the pay-profile fix operators in the handler. (Hargo,
 * 29/06/2026 — buttons so "remediate A00…" doesn't mis-route to the NODS flow.)
 */
function buildBankHolidayFixBlocks(messageText, stillFlagged) {
  if (!INTERACTIVE_BUTTONS_ENABLED || !Array.isArray(stillFlagged) || stillFlagged.length === 0) return null;
  const blocks = [];
  let buf = "";
  const flush = () => { if (buf) { blocks.push({ type: "section", text: { type: "mrkdwn", text: buf.slice(0, 3000) } }); buf = ""; } };
  for (const ln of (messageText || "").split("\n")) {
    if (buf && (buf.length + 1 + ln.length) > 2900) flush();
    buf = buf ? buf + "\n" + ln : ln;
  }
  flush();
  blocks.push({ type: "actions", elements: stillFlagged.slice(0, 20).map(({ agId }) => ({
    type: "button",
    text: { type: "plain_text", text: `🔧 Fix ${agId}`.slice(0, 75), emoji: true },
    action_id: "btn_fix_bank_holiday",
    value: JSON.stringify({ ag: agId }),
    confirm: {
      title: { type: "plain_text", text: "Fix bank-holiday dates?" },
      text: { type: "mrkdwn", text: `Moves every future bank-holiday/weekend payment date on ${agId} to the next working day via Anchor (ChangePayProDueDate). Authorised operators only.` },
      confirm: { type: "plain_text", text: "Fix it" },
      deny: { type: "plain_text", text: "Cancel" },
    },
  })) });
  return blocks;
}

/**
 * Daily 12pm cron: run the bank holiday check and post to #data-billing-updates.
 * - If a previous check message already exists in the channel and there are still
 *   outstanding agreements: chase Hargo + Charlotte (+ Ciaran) in that thread (reply_broadcast: true)
 *   so it stays linked to the original thread but also surfaces in the main channel.
 * - If no previous check message exists: post a new top-level message.
 * - Silent if no agreements are flagged.
 */
async function runBankHolidayProfileCheck() {
  console.log("[bill-ling] Running bank holiday profile check...");
  try {
    const { text, count, stillFlagged, rowCount } = await buildBankHolidayReportText();
    if (!text) {
      console.log("[bill-ling] Bank holiday profile check: 0 flagged rows. No post.");
      return;
    }

    // Look for an existing bank holiday check message in the channel AND
    // verify the population matches. We only chase in an existing thread
    // when today's still-flagged set is a subset of that thread's original
    // population — i.e. agreements are being progressively cleared within
    // the same wave. If new agreements appear (or the populations are
    // disjoint), start a fresh top-level message so the new wave isn't
    // buried in an old thread.
    let existingMsgTs = null;
    const todayFlaggedIds = new Set(stillFlagged.map(({ agId }) => agId.toUpperCase()));
    try {
      const history = await app.client.conversations.history({
        token: SLACK_BOT_TOKEN,
        channel: CHANNELS.DATA_BILLING_UPDATES,
        limit: 200,
      });
      const candidates = (history.messages || []).filter(m =>
        m.bot_id && m.text && m.text.includes("Bank Holiday Profile Check")
      );

      // Walk candidates newest-first. For each candidate, gather the full
      // set of agreement IDs ever associated with that thread (the parent
      // top-level text + every Billington reply in the thread). Compare
      // against today's flagged set.
      for (const cand of candidates) {
        // Pull the original top-level message + all replies for its thread
        let threadAgIds = new Set();
        try {
          const replies = await app.client.conversations.replies({
            token: SLACK_BOT_TOKEN,
            channel: CHANNELS.DATA_BILLING_UPDATES,
            ts: cand.ts,
            limit: 200,
          });
          for (const m of (replies.messages || [])) {
            if (!m.bot_id || !m.text) continue;
            const ids = (m.text.match(/\bA\d{5,9}\b/g) || []).map(s => s.toUpperCase());
            for (const id of ids) threadAgIds.add(id);
          }
        } catch (_) {
          const ids = (cand.text.match(/\bA\d{5,9}\b/g) || []).map(s => s.toUpperCase());
          for (const id of ids) threadAgIds.add(id);
        }

        if (threadAgIds.size === 0) continue; // unparseable, skip
        // Today's set must be a subset of (or equal to) this thread's set
        const todaySubset = [...todayFlaggedIds].every(id => threadAgIds.has(id));
        if (todaySubset && todayFlaggedIds.size > 0) {
          existingMsgTs = cand.ts;
          console.log(`[bill-ling] Bank holiday: reusing thread ${cand.ts} — today's flagged set ${[...todayFlaggedIds].join(",") || "(empty)"} ⊆ thread's set ${[...threadAgIds].join(",")}.`);
          break;
        }
        // If today is empty (no still-flagged) but a thread exists with this
        // wave's history, reuse that thread for the silent-skip / corrected
        // confirmation flow — but only if at least one ID matches (we're
        // continuing the same wave).
        if (todayFlaggedIds.size === 0 && stillFlagged.length === 0) {
          // No still-flagged today — the silent-skip branch later will
          // suppress posting anyway, but pick the most recent thread for
          // logging coherence.
          existingMsgTs = cand.ts;
          break;
        }
      }
      if (!existingMsgTs && candidates.length > 0) {
        console.log(`[bill-ling] Bank holiday: ${candidates.length} candidate thread(s) found but none match today's population (${[...todayFlaggedIds].join(",") || "(empty)"}). Posting a fresh top-level.`);
      }
    } catch (histErr) {
      console.error("[bill-ling] Bank holiday: failed to search channel history:", histErr.message);
    }

    if (existingMsgTs) {
      // Previous check exists. ONLY chase if there's something genuinely
      // outstanding — i.e. stillFlagged has IDs (≤10 path) OR rowCount > 10
      // (we couldn't individually verify so assume some still bad). If
      // every BigQuery flag came back corrected in Anchor, there's
      // nothing to chase about — silent. Previously the cron always
      // fired a 'still agreements need fixing' reminder regardless of
      // whether anything was actually outstanding (08/05 case: 1
      // corrected, 0 still flagged → bare reminder with no IDs).
      const hasOutstanding = stillFlagged.length > 0 || rowCount > 10;

      if (hasOutstanding) {
        const chaseLines = [
          `<@${HARGO_USER_ID}> / <@${REFUND_CONTACTS.PROCESSING.id}> / <@${CIARAN_DOBBIN_USER_ID}> — reminder: there are still agreements with instalments falling due on bank holidays that need fixing in Anchor.`,
        ];

        if (stillFlagged.length > 0) {
          // ≤10 — list each outstanding agreement
          chaseLines.push(``);
          chaseLines.push(`*Still outstanding (${stillFlagged.length}):*`);
          for (const { agId, bankHolidayDates } of stillFlagged) {
            const dateList = bankHolidayDates
              .sort()
              .map(d => `${fmtDate(d)} — ${UK_BANK_HOLIDAY_NAMES[d] || "bank holiday"}`)
              .join(", ");
            chaseLines.push(`  › *${agId}* — ${dateList}`);
          }
        } else {
          // rowCount > 10 with no individual breakdown — embed the query
          chaseLines.push(``);
          chaseLines.push(`*${rowCount.toLocaleString("en-GB")} agreements* still flagged in BigQuery (too many to individually verify in Anchor). Full population query:`);
          chaseLines.push("```");
          chaseLines.push("SELECT * FROM `raylo-production.landing_billington.bank_holiday_profile_check`");
          chaseLines.push("```");
        }

        const chaseBhBlocks = buildBankHolidayFixBlocks(chaseLines.join("\n"), stillFlagged);
        await app.client.chat.postMessage({
          token: SLACK_BOT_TOKEN,
          channel: CHANNELS.DATA_BILLING_UPDATES,
          thread_ts: existingMsgTs,
          reply_broadcast: true, // also surfaces in main channel
          text: chaseLines.join("\n"),
          ...(chaseBhBlocks ? { blocks: chaseBhBlocks } : {}),
          mrkdwn: true,
          unfurl_links: false,
          unfurl_media: false,
        });
        console.log(`[bill-ling] Bank holiday chase posted in thread ${existingMsgTs} (reply_broadcast).`);
      } else {
        // Nothing actionable: BigQuery flagged some agreements but
        // Anchor verified all of them as corrected. Don't post — the
        // original thread already shows the agreement was corrected,
        // and re-posting daily 'still corrected, all good' is noise.
        // Silent skip; the next cron will check again tomorrow.
        console.log(`[bill-ling] Bank holiday: all flagged agreements verified corrected in Anchor. Silent — no thread post (existingMsgTs=${existingMsgTs}).`);
      }
    } else {
      // No previous message — post fresh top-level
      const freshBhBlocks = buildBankHolidayFixBlocks(text, stillFlagged);
      await app.client.chat.postMessage({
        token: SLACK_BOT_TOKEN,
        channel: CHANNELS.DATA_BILLING_UPDATES,
        text,
        ...(freshBhBlocks ? { blocks: freshBhBlocks } : {}),
        mrkdwn: true,
        unfurl_links: false,
        unfurl_media: false,
      });
      console.log(`[bill-ling] Bank holiday profile check posted fresh (${count} flagged).`);
    }
  } catch (err) {
    console.error("[bill-ling] Bank holiday profile check error:", err.message);
  }
}

// ---------------------------------------------------------------------------
// Payment Profile Issues — daily 12:00 detection + Notion tracker management
// SOP: knowledge/payment-profile-issues-sop.txt
// Notion parent page: 35e5bb4b4a65819592bec68918c0cc0e
// ---------------------------------------------------------------------------

const PAYMENT_PROFILES_PARENT_PAGE_ID = "35e5bb4b4a65819592bec68918c0cc0e";
const PAYMENT_PROFILES_VOLUME_THRESHOLD = 200;

const PAYMENT_PROFILE_ISSUES_QUERY = `
WITH
hire_agreements AS (
  SELECT identities.agreement_id, CAST(h.recurring_amount_including_tax AS DECIMAL) AS hire_recurring
  FROM \`raylo-production.dbt_production.stg_raylo_production__hire_agreements\` h
  LEFT JOIN \`raylo-production.dbt_production.intermediate_core_aggregated_identities\` identities
    ON identities.checkout_item_id = h.checkout_item_id
  WHERE identities.agreement_id IS NOT NULL
  QUALIFY RANK() OVER (PARTITION BY h.checkout_item_id ORDER BY h.created_at DESC) = 1
),
agreements AS (
  SELECT DISTINCT core_agreements.agreement_id,
    ROUND(core_subscriptions.recurring_total_amount_after_tax, 2) AS regular_installment_amount,
    ROUND((core_subscriptions.recurring_total_amount_after_tax * 0.35), 2) AS discounted_installment_amount,
    ROUND(hire_recurring, 2) AS regular_installment_amount_hire,
    DATE(core_agreements.next_payment_date) AS next_payment_date,
    core_agreements.instalment_net
  FROM \`raylo-production.dbt_production.core_agreements\` core_agreements
  LEFT JOIN \`raylo-production.dbt_production.core_subscriptions\` core_subscriptions
    ON core_subscriptions.agreement_id = core_agreements.agreement_id
  LEFT JOIN hire_agreements ON hire_agreements.agreement_id = core_agreements.agreement_id
),
payment_profiles AS (
  SELECT pp.agreement_id, pp.payment_profile_id, DATE(pp.due_date) AS due_date, pp.net_amount,
    LOWER(pp.type) AS type, COALESCE(pp.fee_or_insid, 0) AS fee_or_insid,
    NULLIF(pp.subtype_description, '') AS subtype_description,
    LOWER(COALESCE(pp.subtype_description, '')) = 'damage fee' AS damage_fee_profile_entry,
    COALESCE(pp.is_residual, FALSE) AS is_residual
  FROM \`raylo-production.dbt_production.stg_landing_sentinel_s3db01__payment_profiles\` pp
  LEFT JOIN agreements ON agreements.agreement_id = pp.agreement_id
  WHERE pp.type <> '' AND pp.type IS NOT NULL AND pp.payment_profile_id IS NOT NULL AND pp.agreement_id IS NOT NULL
    AND (pp.net_amount > 0 OR pp.fee_or_insid = 5)
    AND NOT (pp.reloan_id IS NULL AND pp.fee_or_insid = 6 AND pp.type = 'Fee')
),
installment_profiles AS (
  SELECT DISTINCT pp.*,
    CASE WHEN LOWER(pp.type) IN ('pay','fee','vfe','vat') THEN 'primary'
         WHEN LOWER(pp.type) IN ('sec','sfn','sfv','vsc') THEN 'secondary' END AS term_type
  FROM payment_profiles pp
  WHERE pp.is_residual IS FALSE AND pp.damage_fee_profile_entry IS FALSE AND pp.fee_or_insid <> 5
),
sum_by_due AS (
  SELECT agreement_id, due_date, term_type, SUM(net_amount) AS net_amount,
    RANK() OVER (PARTITION BY agreement_id, term_type ORDER BY due_date ASC) AS term_rank,
    RANK() OVER (PARTITION BY agreement_id ORDER BY due_date ASC) AS instalment_rank
  FROM installment_profiles GROUP BY agreement_id, due_date, term_type
),
issue AS (
  SELECT s.*, a.regular_installment_amount, a.discounted_installment_amount, a.regular_installment_amount_hire, a.next_payment_date,
    CASE
      WHEN (s.net_amount - a.regular_installment_amount BETWEEN -0.01 AND 0.01 OR s.net_amount - a.regular_installment_amount_hire BETWEEN -0.01 AND 0.01)
           AND s.instalment_rank > 1 AND s.term_type <> 'secondary' THEN FALSE
      WHEN (s.net_amount - a.regular_installment_amount BETWEEN -0.01 AND 0.01 OR s.net_amount - a.regular_installment_amount_hire BETWEEN -0.01 AND 0.01)
           AND s.term_rank <= 24 AND s.instalment_rank > 1 THEN FALSE
      WHEN s.term_rank > 24 AND s.term_type = 'secondary' AND s.net_amount - a.discounted_installment_amount BETWEEN -0.02 AND 0.02 THEN FALSE
      WHEN s.instalment_rank = 1 THEN FALSE
      ELSE TRUE END AS issue_to_review
  FROM sum_by_due s LEFT JOIN agreements a ON a.agreement_id = s.agreement_id
  WHERE a.regular_installment_amount IS NOT NULL
)
SELECT i.*, CASE WHEN i.term_type = 'secondary' AND i.term_rank > 24 THEN TRUE ELSE FALSE END AS discounted_secondary
FROM issue i
LEFT JOIN \`raylo-production.landing_billington.agreement_settlement_dates\` s ON s.agreement_id = i.agreement_id
WHERE i.issue_to_review IS TRUE
  AND s.settlement_date IS NULL
  AND i.next_payment_date < CURRENT_DATE() + 360
ORDER BY i.agreement_id, i.due_date
`;

// Issue Tracker column order — keep stable so we can read/write deterministically.
const ISSUE_TRACKER_HEADERS = [
  "Date of First Check", "Date Last Checked", "Raylo Reference", "Priority",
  "Unique Agreements Impacted", "Profile Entries Impacted", "Impact Type",
  "Aryza Reference", "Population & Details", "Status",
];

const PD_ENTRY_HEADERS = [
  "Agreement ID", "Due Date", "Priority", "Term Type", "Term Rank",
  "Instalment Rank", "Current Net Amount", "Expected Amount", "Variance",
  "Impact Type", "Status",
];

/**
 * Run the detection BigQuery. Returns array of raw rows.
 */
async function runPaymentProfileQuery() {
  const rows = await runBigQueryRaw(PAYMENT_PROFILE_ISSUES_QUERY);
  return rows.map(r => ({
    agreement_id: String(formatBQValue(r.agreement_id) || "").toUpperCase(),
    due_date: String(formatBQValue(r.due_date) || ""),
    net_amount: Number(formatBQValue(r.net_amount)) || 0,
    term_type: String(formatBQValue(r.term_type) || ""),
    term_rank: Number(formatBQValue(r.term_rank)) || 0,
    instalment_rank: Number(formatBQValue(r.instalment_rank)) || 0,
    regular_installment_amount: Number(formatBQValue(r.regular_installment_amount)) || 0,
    discounted_installment_amount: Number(formatBQValue(r.discounted_installment_amount)) || 0,
    regular_installment_amount_hire: Number(formatBQValue(r.regular_installment_amount_hire)) || 0,
    discounted_secondary: formatBQValue(r.discounted_secondary) === true || formatBQValue(r.discounted_secondary) === "true",
    next_payment_date: String(formatBQValue(r.next_payment_date) || ""),
  }));
}

/**
 * Pick the expected amount for a single profile entry based on which target it
 * is closest to. The view flags only entries that don't match ANY expected,
 * so the "closest" expected is the one to compare against for variance.
 */
function pickExpectedAmount(row) {
  const candidates = [
    { name: "primary", value: row.regular_installment_amount },
    { name: "hire", value: row.regular_installment_amount_hire },
    { name: "discounted", value: row.discounted_installment_amount },
  ].filter(c => c.value > 0);
  if (candidates.length === 0) return { value: row.regular_installment_amount, name: "primary" };
  // If this is a discounted-secondary row, the expected is the discounted amount.
  if (row.discounted_secondary && row.discounted_installment_amount > 0) {
    return { value: row.discounted_installment_amount, name: "discounted" };
  }
  // Otherwise pick the candidate with smallest |net - expected|.
  let best = candidates[0];
  let bestDiff = Math.abs(row.net_amount - best.value);
  for (const c of candidates.slice(1)) {
    const d = Math.abs(row.net_amount - c.value);
    if (d < bestDiff) { best = c; bestDiff = d; }
  }
  return { value: best.value, name: best.name };
}

/**
 * Group BQ rows into per-agreement payloads with priority + variance summaries.
 */
function buildPaymentProfileGroups(rawRows) {
  const today = new Date().toLocaleDateString("en-CA", { timeZone: "Europe/London" });
  const groups = new Map();
  for (const row of rawRows) {
    const expected = pickExpectedAmount(row);
    const variance = Number((row.net_amount - expected.value).toFixed(2));
    const impact = variance > 0.01 ? "Overcharged" : variance < -0.01 ? "Undercharged" : "On expected";
    const entryPriority = row.due_date <= today ? "P1" : "P2";
    const entry = {
      agreement_id: row.agreement_id,
      due_date: row.due_date,
      term_type: row.term_type,
      term_rank: row.term_rank,
      instalment_rank: row.instalment_rank,
      current_net_amount: row.net_amount,
      expected_amount: expected.value,
      expected_basis: expected.name,
      variance,
      impact,
      priority: entryPriority,
      next_payment_date: row.next_payment_date,
    };
    if (!groups.has(row.agreement_id)) {
      groups.set(row.agreement_id, { agreement_id: row.agreement_id, entries: [] });
    }
    groups.get(row.agreement_id).entries.push(entry);
  }
  const result = [];
  for (const g of groups.values()) {
    const hasP1 = g.entries.some(e => e.priority === "P1");
    const hasOver = g.entries.some(e => e.impact === "Overcharged");
    const hasUnder = g.entries.some(e => e.impact === "Undercharged");
    g.priority = hasP1 ? "P1" : "P2";
    g.impact_type = hasOver && hasUnder ? "Mixed" : hasOver ? "Overcharged" : hasUnder ? "Undercharged" : "On expected";
    g.entries_count = g.entries.length;
    g.past_due_count = g.entries.filter(e => e.priority === "P1").length;
    g.future_due_count = g.entries_count - g.past_due_count;
    g.net_variance = Number(g.entries.reduce((s, e) => s + e.variance, 0).toFixed(2));
    g.earliest_due = g.entries.reduce((m, e) => (e.due_date < m ? e.due_date : m), g.entries[0].due_date);
    g.latest_due = g.entries.reduce((m, e) => (e.due_date > m ? e.due_date : m), g.entries[0].due_date);
    result.push(g);
  }
  // Sort: P1 first, then P2; within priority, earliest_due asc
  result.sort((a, b) => {
    if (a.priority !== b.priority) return a.priority === "P1" ? -1 : 1;
    return a.earliest_due.localeCompare(b.earliest_due);
  });
  return result;
}

/**
 * Read the existing Issue Tracker table from the parent Notion page.
 * Returns { tableBlockId, rows: [{ raylo_ref, date_first, date_last, priority,
 *           agreements, entries, impact_type, aryza_ref, pd_page_url, status }] }
 * Returns null if the table isn't found.
 */
async function readIssueTracker() {
  const found = await notionFindTableBlock(PAYMENT_PROFILES_PARENT_PAGE_ID, "Date of First Check");
  if (!found) return null;
  const { headerCells, rows } = await notionReadTableBlock(found.blockId);
  const idx = (label) => headerCells.findIndex(h => h.toLowerCase().trim() === label.toLowerCase());
  const i = {
    date_first: idx("Date of First Check"),
    date_last: idx("Date Last Checked"),
    raylo_ref: idx("Raylo Reference"),
    priority: idx("Priority"),
    agreements: idx("Unique Agreements Impacted"),
    entries: idx("Profile Entries Impacted"),
    impact_type: idx("Impact Type"),
    aryza_ref: idx("Aryza Reference"),
    pd_link: idx("Population & Details"),
    status: idx("Status"),
  };
  const parsed = rows.map(cells => ({
    date_first: cells[i.date_first] || "",
    date_last: cells[i.date_last] || "",
    raylo_ref: cells[i.raylo_ref] || "",
    priority: cells[i.priority] || "",
    agreements: cells[i.agreements] || "",
    entries: cells[i.entries] || "",
    impact_type: cells[i.impact_type] || "",
    aryza_ref: cells[i.aryza_ref] || "",
    pd_link: cells[i.pd_link] || "",
    status: cells[i.status] || "",
    raw_cells: cells,
  })).filter(r => r.raylo_ref); // ignore empty rows
  return { tableBlockId: found.blockId, headerCells, rows: parsed };
}

/**
 * Generate the next Raylo Reference for today's detection run.
 * Format: RPP-YYYYMMDD-NNN where NNN is the per-day sequence.
 */
function nextRayloRef(existingRefs, sequence) {
  const today = new Date().toLocaleDateString("en-CA", { timeZone: "Europe/London" }).replace(/-/g, "");
  // Find largest existing NNN for today
  const todayRefs = existingRefs.filter(r => r.startsWith(`RPP-${today}-`));
  let n = sequence;
  for (const r of todayRefs) {
    const m = r.match(/^RPP-\d{8}-(\d{3,})$/);
    if (m) n = Math.max(n, Number(m[1]) + 1);
  }
  return `RPP-${today}-${String(n).padStart(3, "0")}`;
}

// Convert an entry object into a PD-table row's cell array.
function pdEntryToCells(e) {
  return [
    e.agreement_id,
    e.due_date,
    e.priority,
    e.term_type,
    String(e.term_rank),
    String(e.instalment_rank),
    `£${Number(e.current_net_amount).toFixed(2)}`,
    e.expected_basis
      ? `£${Number(e.expected_amount).toFixed(2)} (${e.expected_basis})`
      : `£${Number(e.expected_amount).toFixed(2)}`,
    `£${Number(e.variance).toFixed(2)}`,
    e.impact,
    e.status || "Not Corrected",
  ];
}

// Parse a PD-table row's cell array back into a structured entry.
function pdCellsToEntry(cells) {
  const parseGBP = (s) => Number(String(s).replace(/[£,\s]/g, "").replace(/\(.+?\)/g, "")) || 0;
  return {
    agreement_id: cells[0] || "",
    due_date: cells[1] || "",
    priority: cells[2] || "",
    term_type: cells[3] || "",
    term_rank: Number(cells[4]) || 0,
    instalment_rank: Number(cells[5]) || 0,
    current_net_amount: parseGBP(cells[6]),
    expected_amount: parseGBP(cells[7]),
    expected_basis: (String(cells[7]).match(/\((.+?)\)/) || [, ""])[1],
    variance: parseGBP(cells[8]),
    impact: cells[9] || "",
    status: cells[10] || "Not Corrected",
  };
}

// Read the PD-page's entries table back into structured entry objects.
async function readPdPageEntries(pdPageId) {
  const blocks = await notionGetBlockChildren(pdPageId);
  const tableBlock = blocks.find(b => b.type === "table");
  if (!tableBlock) return { tableBlockId: null, entries: [] };
  const { rows } = await notionReadTableBlock(tableBlock.id);
  const entries = rows.map(pdCellsToEntry).filter(e => e.agreement_id);
  return { tableBlockId: tableBlock.id, entries };
}

// Helper: derive priority/impact summary from a list of entries.
function summariseEntries(entries) {
  const hasP1 = entries.some(e => e.priority === "P1");
  const hasOver = entries.some(e => e.impact === "Overcharged");
  const hasUnder = entries.some(e => e.impact === "Undercharged");
  return {
    priority: hasP1 ? "P1" : "P2",
    impact_type: hasOver && hasUnder ? "Mixed" : hasOver ? "Overcharged" : hasUnder ? "Undercharged" : "On expected",
    unique_agreements: new Set(entries.map(e => e.agreement_id)).size,
    past_due: entries.filter(e => e.priority === "P1").length,
    future_due: entries.filter(e => e.priority === "P2").length,
  };
}

/**
 * Create ONE Population & Details child page covering an entire detection
 * wave (all agreements + all entries in one table). Returns the created
 * page object.
 *
 * Notion caps any block-creation call at 100 children, so we:
 *   1) Create the page with intro + table holding header + first 99 rows.
 *   2) Append remaining rows to the new table block in batches of 100.
 */
async function createPdPageForWave(entries, rayloRef) {
  const NOTION_BATCH_LIMIT = 100;
  const today = new Date().toLocaleDateString("en-CA", { timeZone: "Europe/London" });
  const summary = summariseEntries(entries);
  const title = `Payment Profile Issue — ${today} — ${summary.impact_type} — ${rayloRef}`;

  const dataCells = entries.map(pdEntryToCells);
  const headerRowBlock = notionTableRow(PD_ENTRY_HEADERS);
  const dataRowBlocks = dataCells.map(c => notionTableRow(c));
  const firstBatchData = dataRowBlocks.slice(0, NOTION_BATCH_LIMIT - 1);
  const remainingData = dataRowBlocks.slice(NOTION_BATCH_LIMIT - 1);

  const tableBlock = {
    type: "table",
    table: {
      table_width: PD_ENTRY_HEADERS.length,
      has_column_header: true,
      has_row_header: false,
      children: [headerRowBlock, ...firstBatchData],
    },
  };
  const intro = {
    type: "paragraph",
    paragraph: {
      rich_text: notionRichText(
        `Raylo Reference: ${rayloRef}. Detected ${today}. ` +
        `${summary.unique_agreements} agreement${summary.unique_agreements === 1 ? "" : "s"}, ` +
        `${entries.length} profile entr${entries.length === 1 ? "y" : "ies"} flagged, ` +
        `${summary.past_due} past-due, ${summary.future_due} future-due, priority ${summary.priority}, ${summary.impact_type}.`
      ),
    },
  };

  const createdPage = await notionCreatePage(PAYMENT_PROFILES_PARENT_PAGE_ID, title, [intro, tableBlock]);

  if (remainingData.length > 0) {
    try {
      const pageChildren = await notionGetBlockChildren(createdPage.id);
      const tableChild = pageChildren.find(b => b.type === "table");
      if (tableChild) {
        for (let i = 0; i < remainingData.length; i += NOTION_BATCH_LIMIT) {
          await notionAppendBlocks(tableChild.id, remainingData.slice(i, i + NOTION_BATCH_LIMIT));
        }
      } else {
        console.error(`[bill-ling] PPI: couldn't find table child on new PD page ${createdPage.id} to append rows`);
      }
    } catch (e) {
      console.error(`[bill-ling] PPI: failed appending PD rows:`, e.message);
    }
  }
  return createdPage;
}

/**
 * Refresh an existing PD page's entries table in-place with the supplied
 * entry list. Existing entries should be preserved (with updated status /
 * current_net_amount); new entries within the same wave are NOT added here
 * (per Hargo's rule: open rows only refresh agreements already logged).
 *
 * Implementation: delete the existing table block, append a fresh one with
 * the new contents, batched to respect the 100-children cap.
 */
async function refreshPdPageTable(pdPageId, entries) {
  const NOTION_BATCH_LIMIT = 100;
  // Locate existing table block on this page
  const blocks = await notionGetBlockChildren(pdPageId);
  const existingTable = blocks.find(b => b.type === "table");
  if (existingTable) {
    try { await notionDeleteBlock(existingTable.id); } catch (e) { console.error("[bill-ling] PPI refresh: deleteBlock failed:", e.message); }
  }
  const dataCells = entries.map(pdEntryToCells);
  const headerRowBlock = notionTableRow(PD_ENTRY_HEADERS);
  const dataRowBlocks = dataCells.map(c => notionTableRow(c));
  const firstBatch = dataRowBlocks.slice(0, NOTION_BATCH_LIMIT - 1);
  const remaining = dataRowBlocks.slice(NOTION_BATCH_LIMIT - 1);

  const newTableBlock = {
    type: "table",
    table: {
      table_width: PD_ENTRY_HEADERS.length,
      has_column_header: true,
      has_row_header: false,
      children: [headerRowBlock, ...firstBatch],
    },
  };
  const created = await notionAppendBlocks(pdPageId, [newTableBlock]);
  const newTableId = created?.results?.[0]?.id;
  if (!newTableId) throw new Error("Couldn't determine new PD table block ID after refresh");
  for (let i = 0; i < remaining.length; i += NOTION_BATCH_LIMIT) {
    await notionAppendBlocks(newTableId, remaining.slice(i, i + NOTION_BATCH_LIMIT));
  }
}

// Extract the Notion page ID from a tracker row's Population & Details cell.
// We store entries like "RPP-... — A00... — https://www.notion.so/Title-<32hex>"
// or sometimes just the page UUID. Try both.
function parsePdPageIdFromCell(cell) {
  if (!cell) return null;
  // Match a 32-char hex id (with or without dashes) from a notion.so URL
  const urlMatch = String(cell).match(/notion\.so\/[^\s]*?([a-f0-9]{32})\b/i);
  if (urlMatch) return urlMatch[1];
  // Direct UUID with dashes
  const uuidMatch = String(cell).match(/[a-f0-9]{8}-[a-f0-9]{4}-[a-f0-9]{4}-[a-f0-9]{4}-[a-f0-9]{12}/i);
  if (uuidMatch) return uuidMatch[0].replace(/-/g, "");
  // Bare 32-hex
  const bareMatch = String(cell).match(/\b[a-f0-9]{32}\b/i);
  return bareMatch ? bareMatch[0] : null;
}

/**
 * Append a Historical Values (Amendment Log) child page under a Population &
 * Details page. Immutable record of one field change.
 */
async function createHistoricalValuesPage(pdPageId, agreementId, beforeAfterRows) {
  const ts = new Date().toLocaleString("en-GB", { timeZone: "Europe/London" });
  const title = `Amendment Log — ${agreementId} — ${ts}`;
  const dataRows = beforeAfterRows.map(r => [r.field, r.before, r.after]);
  const tableBlock = notionTableBlock(["Field", "Before", "After"], dataRows);
  return notionCreatePage(pdPageId, title, [tableBlock]);
}

/**
 * Rewrite the Issue Tracker table block: delete it, append a fresh one with
 * the latest set of rows. Notion API doesn't expose row-level mutation on a
 * standard table, so wholesale rewrite is the simplest atomic approach.
 *
 * Notion's API caps any single block-creation call at 100 children. For a
 * table with N rows where N > 99 (header + 99 data rows = 100), we:
 *   1) Create the table block on the page with header + first 99 data rows.
 *   2) Append the remaining data rows to the new table block in batches of
 *      100 via PATCH /blocks/{table_block_id}/children.
 */
async function rewriteIssueTrackerTable(latestRows) {
  const NOTION_BATCH_LIMIT = 100;
  // Read the current state to find the table block ID
  const found = await notionFindTableBlock(PAYMENT_PROFILES_PARENT_PAGE_ID, "Date of First Check");
  // Build all row blocks
  const dataCells = latestRows.map(r => [
    r.date_first || "",
    r.date_last || "",
    r.raylo_ref || "",
    r.priority || "",
    String(r.agreements ?? ""),
    String(r.entries ?? ""),
    r.impact_type || "",
    r.aryza_ref || "",
    r.pd_link || "",
    r.status || "Not Corrected",
  ]);
  const headerRowBlock = notionTableRow(ISSUE_TRACKER_HEADERS);
  const dataRowBlocks = dataCells.map(c => notionTableRow(c));

  if (found) {
    try { await notionDeleteBlock(found.blockId); } catch (e) { console.error("[bill-ling] PPI: deleteBlock failed:", e.message); }
  }

  // First batch: header + first (100 - 1) data rows = 100 children
  const firstBatchData = dataRowBlocks.slice(0, NOTION_BATCH_LIMIT - 1);
  const remainingData = dataRowBlocks.slice(NOTION_BATCH_LIMIT - 1);

  const tableBlock = {
    type: "table",
    table: {
      table_width: ISSUE_TRACKER_HEADERS.length,
      has_column_header: true,
      has_row_header: false,
      children: [headerRowBlock, ...firstBatchData],
    },
  };
  const createRes = await notionAppendBlocks(PAYMENT_PROFILES_PARENT_PAGE_ID, [tableBlock]);
  const newTableBlockId = createRes?.results?.[0]?.id;
  if (!newTableBlockId) throw new Error("Couldn't determine the newly-created Issue Tracker table block ID");

  // Append remaining data rows as direct children of the new table block,
  // batched at NOTION_BATCH_LIMIT each.
  for (let i = 0; i < remainingData.length; i += NOTION_BATCH_LIMIT) {
    const batch = remainingData.slice(i, i + NOTION_BATCH_LIMIT);
    await notionAppendBlocks(newTableBlockId, batch);
  }
  console.log(`[bill-ling] PPI: Issue Tracker rewritten — ${dataRowBlocks.length} rows (${1 + Math.ceil(remainingData.length / NOTION_BATCH_LIMIT)} API call${1 + Math.ceil(remainingData.length / NOTION_BATCH_LIMIT) === 1 ? "" : "s"}).`);
}

/**
 * Daily Payment Profile Issues check (wave model).
 *
 *  1. Run the BQ detection query.
 *  2. Read the existing Issue Tracker rows.
 *  3. For each OPEN row (Status = Not Corrected):
 *       a. Read the entries currently on its PD page.
 *       b. For each entry, set Status = "Corrected" if the (agreement_id,
 *          due_date) tuple is NOT in today's query, else "Not Corrected".
 *          Refresh current_net_amount from today's query when still flagged.
 *       c. Rewrite the PD page table in place.
 *       d. Bump Date Last Checked on the tracker row. If every entry on
 *          the page is now Corrected, flip the row Status to "Corrected".
 *  4. Track every agreement_id covered by ANY existing OPEN row's PD page.
 *  5. For agreements in today's query that are NOT covered by any open row
 *     → bundle into ONE new PD page + ONE new Issue Tracker row.
 *  6. Rewrite the Issue Tracker table with the updated set of rows.
 *  7. DM Hargo a summary.
 */
async function runPaymentProfileCheck({ dmTargetUserId = HARGO_USER_ID } = {}) {
  console.log("[bill-ling] Running Payment Profile Issues check...");
  const today = new Date().toLocaleDateString("en-CA", { timeZone: "Europe/London" });

  // 1. Query
  let rawRows;
  try { rawRows = await runPaymentProfileQuery(); }
  catch (err) {
    console.error("[bill-ling] PPI: query failed:", err.message);
    await sendDM(dmTargetUserId, `❌ *Payment Profile Issues check* — query failed: ${err.message}`);
    return;
  }
  const groups = buildPaymentProfileGroups(rawRows);
  const todayEntries = groups.flatMap(g => g.entries);
  console.log(`[bill-ling] PPI: ${todayEntries.length} entries across ${groups.length} agreements.`);

  // Volume guard at agreement level
  if (groups.length > PAYMENT_PROFILES_VOLUME_THRESHOLD) {
    await sendDM(
      dmTargetUserId,
      `🚨 *Payment Profile Issues — ${today}*\n\n*${groups.length} distinct agreements flagged* (threshold: ${PAYMENT_PROFILES_VOLUME_THRESHOLD}). Taking no further action — no Notion writes, no rows created. Likely a systemic issue requiring bulk remediation.`
    );
    return;
  }

  // Build today fingerprint lookup: (agreement_id|due_date) → entry
  const todayByFingerprint = new Map();
  for (const e of todayEntries) {
    todayByFingerprint.set(`${e.agreement_id}|${e.due_date}`, e);
  }

  // 2. Read existing tracker
  let tracker;
  try { tracker = await readIssueTracker(); }
  catch (err) {
    console.error("[bill-ling] PPI: readIssueTracker failed:", err.message);
    await sendDM(dmTargetUserId, `❌ *Payment Profile Issues check* — couldn't read the Notion tracker: ${err.message}. Has the integration been granted access to the Payment Profiles Issues page?`);
    return;
  }
  const existingRows = (tracker?.rows || []);

  // 3. Refresh each open row's PD page
  //
  // Coverage rule (Hargo, 13/05/2026):
  //   - Once an entry is marked Corrected, it's FROZEN. Skip it in subsequent
  //     daily checks — never re-evaluate, never flip back to Not Corrected.
  //   - A Corrected entry does NOT count as "covered". If the same fingerprint
  //     (or any other entry for that agreement) reappears in today's query,
  //     it's a regression and goes to a NEW wave row.
  // So: coveredFingerprints = Not Corrected entries on open rows ONLY.
  // Everything else in today's query falls through to the new wave.
  const updatedRows = [];
  const refreshedRowStats = []; // for the summary DM
  const coveredFingerprints = new Set();
  const frozenCorrectedFingerprints = new Set(); // for regression detection
  for (const r of existingRows) {
    if (r.status !== "Not Corrected") {
      // Closed rows pass through unchanged. Their fingerprints are NOT
      // covered; reappearances go to a fresh wave.
      updatedRows.push(r);
      continue;
    }
    const pdPageId = parsePdPageIdFromCell(r.pd_link);
    if (!pdPageId) {
      console.warn(`[bill-ling] PPI: open row ${r.raylo_ref} has no parseable PD page id, leaving as-is`);
      updatedRows.push(r);
      continue;
    }

    let existingEntries;
    try {
      ({ entries: existingEntries } = await readPdPageEntries(pdPageId));
    } catch (err) {
      console.error(`[bill-ling] PPI: failed to read PD page ${pdPageId} for ${r.raylo_ref}:`, err.message);
      updatedRows.push(r);
      continue;
    }

    let flippedToday = 0;
    const refreshedEntries = existingEntries.map(e => {
      const fp = `${e.agreement_id}|${e.due_date}`;
      if ((e.status || "Not Corrected") === "Corrected") {
        // Frozen. Skip evaluation entirely. NOT added to coveredFingerprints
        // so a regression goes to a new wave.
        frozenCorrectedFingerprints.add(fp);
        return e;
      }
      // Not Corrected → re-evaluate against today's query.
      const stillFlagged = todayByFingerprint.has(fp);
      if (stillFlagged) {
        coveredFingerprints.add(fp);
        const live = todayByFingerprint.get(fp);
        return {
          ...e,
          status: "Not Corrected",
          current_net_amount: live.current_net_amount,
          expected_amount: live.expected_amount,
          expected_basis: live.expected_basis,
          variance: live.variance,
          impact: live.impact,
          priority: live.priority,
        };
      } else {
        flippedToday++;
        return { ...e, status: "Corrected" };
      }
    });

    try {
      await refreshPdPageTable(pdPageId, refreshedEntries);
    } catch (err) {
      console.error(`[bill-ling] PPI: refreshPdPageTable failed for ${r.raylo_ref}:`, err.message);
    }

    const allCorrected = refreshedEntries.length > 0 && refreshedEntries.every(e => e.status === "Corrected");
    const updatedRow = {
      ...r,
      date_last: today,
      status: allCorrected ? "Corrected" : "Not Corrected",
      entries: String(refreshedEntries.length),
      agreements: String(new Set(refreshedEntries.map(e => e.agreement_id)).size),
      priority: refreshedEntries.some(e => e.priority === "P1" && e.status === "Not Corrected") ? "P1" : "P2",
    };
    updatedRows.push(updatedRow);
    refreshedRowStats.push({ raylo_ref: r.raylo_ref, flippedToday, totalEntries: refreshedEntries.length, allCorrected });
  }

  // 4. Identify "new" entries (per Hargo's rule, fingerprint-level):
  //    - Genuinely new fingerprints (not on any open row)
  //    - Regressions: fingerprints that were Corrected on an open row and
  //      have reappeared in today's query (their old Corrected entry stays
  //      frozen on the old page; a fresh Not Corrected entry lands on the
  //      new wave page).
  const newEntries = todayEntries.filter(e => {
    const fp = `${e.agreement_id}|${e.due_date}`;
    return !coveredFingerprints.has(fp);
  });

  // 5. If we have new agreements, create ONE new row + ONE new PD page
  let newRow = null;
  if (newEntries.length > 0) {
    const existingRefs = updatedRows.map(r => r.raylo_ref).filter(Boolean);
    const rayloRef = nextRayloRef(existingRefs, 1);
    let pdPage = null;
    try { pdPage = await createPdPageForWave(newEntries, rayloRef); }
    catch (err) {
      console.error("[bill-ling] PPI: createPdPageForWave failed:", err.message);
      await sendDM(dmTargetUserId, `❌ *Payment Profile Issues check* — couldn't create new PD page: ${err.message}`);
      return;
    }
    const summary = summariseEntries(newEntries);
    const pdLinkCell = `${rayloRef} — ${pdPage.url || pdPage.id}`;
    newRow = {
      date_first: today,
      date_last: today,
      raylo_ref: rayloRef,
      priority: summary.priority,
      agreements: String(summary.unique_agreements),
      entries: String(newEntries.length),
      impact_type: summary.impact_type,
      aryza_ref: "",
      pd_link: pdLinkCell,
      status: "Not Corrected",
    };
    updatedRows.push(newRow);
  }

  // 6. Rewrite tracker
  try { await rewriteIssueTrackerTable(updatedRows); }
  catch (err) {
    console.error("[bill-ling] PPI: rewriteIssueTrackerTable failed:", err.message);
    await sendDM(dmTargetUserId, `❌ *Payment Profile Issues check* — couldn't rewrite the Notion tracker: ${err.message}`);
    return;
  }

  // 7. DM summary
  const lines = [
    `*Payment Profile Issues — ${today} 12:00*`,
    ``,
    `Today's query: *${groups.length}* agreement${groups.length === 1 ? "" : "s"}, *${todayEntries.length}* profile entr${todayEntries.length === 1 ? "y" : "ies"}.`,
  ];
  const openRowsCount = updatedRows.filter(r => r.status === "Not Corrected").length;
  const correctedRowsCount = updatedRows.filter(r => r.status === "Corrected").length;
  lines.push(`Tracker after this run: *${openRowsCount}* open row${openRowsCount === 1 ? "" : "s"}, *${correctedRowsCount}* corrected row${correctedRowsCount === 1 ? "" : "s"}.`);
  lines.push(``);

  if (newRow) {
    const regressions = newEntries.filter(e => frozenCorrectedFingerprints.has(`${e.agreement_id}|${e.due_date}`));
    lines.push(`*New wave created* — *${newRow.raylo_ref}* (${newRow.priority})`);
    lines.push(`  › ${newRow.agreements} agreements, ${newRow.entries} entries, ${newRow.impact_type}.`);
    if (regressions.length > 0) {
      const regressedAgreements = new Set(regressions.map(e => e.agreement_id));
      lines.push(`  › ⚠️ *${regressions.length}* of these are REGRESSIONS (previously Corrected fingerprints reappearing in the query) across ${regressedAgreements.size} agreement${regressedAgreements.size === 1 ? "" : "s"}.`);
    }
  } else {
    lines.push(`No new wave today — every flagged fingerprint is already on an open row.`);
  }

  const flippedRows = refreshedRowStats.filter(s => s.flippedToday > 0);
  if (flippedRows.length > 0) {
    lines.push(``);
    lines.push(`*Entries flipped to Corrected today (${flippedRows.reduce((a, b) => a + b.flippedToday, 0)} across ${flippedRows.length} row${flippedRows.length === 1 ? "" : "s"}):*`);
    for (const s of flippedRows.slice(0, 15)) {
      lines.push(`  ✅ ${s.raylo_ref} — ${s.flippedToday}/${s.totalEntries} entries now Corrected${s.allCorrected ? " (row Status → Corrected)" : ""}.`);
    }
  }

  const aryzaChase = updatedRows.filter(r =>
    r.status === "Not Corrected" && !r.aryza_ref &&
    r.date_first && daysBetweenLondon(r.date_first, today) >= 2
  );
  if (aryzaChase.length > 0) {
    lines.push(``);
    lines.push(`*Aryza Reference chase (${aryzaChase.length} row${aryzaChase.length === 1 ? "" : "s"} > 48h with no reference):*`);
    for (const r of aryzaChase.slice(0, 15)) lines.push(`  ⚠️ ${r.raylo_ref} — first detected ${r.date_first}. What's the Aryza ticket reference?`);
  }

  lines.push(``);
  lines.push(`Tracker: https://www.notion.so/${PAYMENT_PROFILES_PARENT_PAGE_ID}`);

  await sendDM(dmTargetUserId, lines.join("\n"));
  console.log(`[bill-ling] PPI: done. Open rows ${openRowsCount}, new wave ${newRow ? newRow.raylo_ref : "none"}, flipped ${flippedRows.reduce((a, b) => a + b.flippedToday, 0)}.`);
}

// Compute working-day-ish diff (just calendar days for now; tighten later if needed)
function daysBetweenLondon(iso1, iso2) {
  const d1 = new Date(iso1 + "T00:00:00Z").getTime();
  const d2 = new Date(iso2 + "T00:00:00Z").getTime();
  return Math.round(Math.abs(d2 - d1) / 86400000);
}

// Send a Slack DM to a user. Opens the IM channel first.
async function sendDM(userId, text) {
  try {
    const im = await app.client.conversations.open({ token: SLACK_BOT_TOKEN, users: userId });
    const ch = im?.channel?.id;
    if (!ch) throw new Error("conversations.open returned no channel id");
    await app.client.chat.postMessage({ token: SLACK_BOT_TOKEN, channel: ch, text, mrkdwn: true, unfurl_links: false, unfurl_media: false });
  } catch (err) {
    console.error("[bill-ling] sendDM error:", err.message);
  }
}

