// Startup recovery: if the app restarts between 08:40 and 12:30 on a weekday
// (the auto-trigger window — Hargo, 20/05/2026), check whether today's
// readiness check already passed. If it did, treat the scenario as already
// triggered. If it didn't (or hasn't run yet), resume the recheck loop.
{
  const londonHourNow = Number(new Date().toLocaleString("en-GB", { timeZone: "Europe/London", hour: "2-digit", hour12: false }));
  const londonMinNow = Number(new Date().toLocaleString("en-GB", { timeZone: "Europe/London", minute: "2-digit" }));
  const totalMinsNow = londonHourNow * 60 + londonMinNow;
  const dayOfWeek = new Date(new Date().toLocaleString("en-US", { timeZone: "Europe/London" })).getDay(); // 0=Sun, 6=Sat
  const isWeekday = dayOfWeek >= 1 && dayOfWeek <= 5;
  if (isWeekday && totalMinsNow >= 8 * 60 + 40 && totalMinsNow < 12 * 60 + 30) {
    console.log("[bill-ling] Startup recovery: within late fee check window (08:40-12:30 weekday). Checking channel for existing message...");
    setTimeout(async () => {
      if (lateFeeCheckTimer) return; // cron already scheduled one
      try {
        // Search for today's late fee readiness message in channel
        const todayFmt = new Date().toLocaleDateString("en-GB", { timeZone: "Europe/London", day: "2-digit", month: "2-digit", year: "numeric" });
        const history = await app.client.conversations.history({
          token: SLACK_BOT_TOKEN,
          channel: CHANNELS.DATA_BILLING_UPDATES,
          limit: 30,
        });
        const existing = (history.messages || []).find(m =>
          m.bot_id && m.text && m.text.includes("Late Fee Readiness Check") && m.text.includes(todayFmt)
        );
        if (existing && /All criteria met/i.test(existing.text)) {
          console.log("[bill-ling] Startup recovery: today's late fee check already passed. Treating scenario as already triggered.");
          lateFeeCriteriaMetNotified = true; // don't double-ping on next run
          lateFeeAutoTriggeredToday = true; // don't double-trigger after restart
          return;
        }
        if (existing && /Criteria not met/i.test(existing.text)) {
          // Resume recheck loop using the existing message
          console.log("[bill-ling] Startup recovery: today's late fee check still pending. Resuming recheck loop.");
          lateFeeCheckMessageTs = existing.ts;
          lateFeeCheckCount = 1; // treat as continuation, not first post
          lateFeeCriteriaMetNotified = false;
          lateFeeAutoTriggeredToday = false;
        } else {
          console.log("[bill-ling] Startup recovery: no late fee check found for today. Running fresh check.");
          lateFeeCheckCount = 0;
          lateFeeCheckMessageTs = null;
          lateFeeCriteriaMetNotified = false;
          lateFeeAutoTriggeredToday = false;
        }
        runLateFeeReadinessCheck();
      } catch (err) {
        console.error("[bill-ling] Startup recovery error:", err.message);
        // Fall back to running the check anyway
        lateFeeCheckCount = 0;
        lateFeeCheckMessageTs = null;
        lateFeeCriteriaMetNotified = false;
        lateFeeAutoTriggeredToday = false;
        runLateFeeReadinessCheck();
      }
    }, 60 * 1000);
  }
}

