// Track the latest ARUDD message so we can update it later (includes figures for change tracking)
let lastAruddMessage = { ts: null, channel: null, dueDate: null, postedPct: null, anchorBounces: null, gcFailed: null };
let aruddRefreshTimer = null; // Track the recurring refresh timer so we can clear it

async function runAruddCron() {
  console.log("[bill-ling] Running daily ARUDD report...");
  try {
    const { report, discrepancyPct, anchorBounces, gcFailed, dueDate, postedPct } = await buildAruddReport();
    const result = await app.client.chat.postMessage({
      token: SLACK_BOT_TOKEN,
      channel: CHANNELS.DATA_BILLING_UPDATES,
      text: report,
      mrkdwn: true,
      unfurl_links: false,
      unfurl_media: false,
    });
    // Store the message ts + figures so we can track changes on refresh
    lastAruddMessage = { ts: result.ts, channel: CHANNELS.DATA_BILLING_UPDATES, dueDate, postedPct, anchorBounces, gcFailed };
    console.log("[bill-ling] ARUDD report posted (ts: " + result.ts + ", posted: " + postedPct + "%).");

    // If < 95% posted in Anchor, check source table freshness and alert
    if (postedPct < 95 && gcFailed > 0) {
      console.log(`[bill-ling] ARUDD posted in Anchor ${postedPct}% < 95% — checking source tables...`);
      await checkAruddSourceTables(dueDate, discrepancyPct, anchorBounces, gcFailed);
    }

    // Schedule recurring hourly refresh if not yet at 99%
    scheduleAruddAutoRefresh(postedPct);
  } catch (err) {
    console.error("[bill-ling] ARUDD cron error:", err.message);
  }
}

/**
 * Schedule recurring hourly ARUDD auto-refresh when posted % < 100%.
 * Keeps checking every hour until posted >= 100% or past 17:00 London time.
 * Each refresh updates the original message in-place and posts a thread reply
 * showing what changed (with the date/time of the edit).
 */
function scheduleAruddAutoRefresh(currentPostedPct) {
  // Clear any existing timer
  if (aruddRefreshTimer) {
    clearTimeout(aruddRefreshTimer);
    aruddRefreshTimer = null;
  }

  if (currentPostedPct >= 100) {
    console.log(`[bill-ling] ARUDD posted ${currentPostedPct}% >= 100% — no further auto-refresh needed.`);
    return;
  }

  console.log(`[bill-ling] ARUDD posted ${currentPostedPct}% < 100% — scheduling hourly auto-refresh.`);
  aruddRefreshTimer = setTimeout(async () => {
    // Check if we're still within working hours (before 17:00 London)
    const londonHour = Number(new Date().toLocaleString("en-GB", { timeZone: "Europe/London", hour: "2-digit", hour12: false }));
    if (londonHour >= 17) {
      console.log("[bill-ling] ARUDD auto-refresh: past 17:00 London — stopping checks.");
      return;
    }

    console.log("[bill-ling] ARUDD auto-refresh: running hourly check...");
    const newPostedPct = await refreshAruddMessage();

    // If refreshAruddMessage returned a valid postedPct, schedule next check if still < 100%
    if (typeof newPostedPct === "number") {
      scheduleAruddAutoRefresh(newPostedPct);
    } else {
      // Refresh failed or no message found — retry in an hour anyway
      console.log("[bill-ling] ARUDD auto-refresh: refresh returned no pct, retrying in 1 hour.");
      scheduleAruddAutoRefresh(0);
    }
  }, 60 * 60 * 1000); // 1 hour
}

async function findTodaysAruddMessage() {
  // If we have it in memory, use it
  if (lastAruddMessage.ts && lastAruddMessage.channel) return lastAruddMessage;

  // Otherwise search #data-billing-updates for today's ARUDD posted by Billington
  try {
    // Use London midnight as the oldest timestamp (handles BST/GMT automatically)
    const todayStr = new Date().toLocaleDateString("en-CA", { timeZone: "Europe/London" });
    // Build a proper London midnight by using the date formatter to get the UTC offset
    const londonNow = new Date().toLocaleString("en-GB", { timeZone: "Europe/London", hour12: false });
    const isBST = new Date().toLocaleString("en-GB", { timeZone: "Europe/London", timeZoneName: "short" }).includes("BST");
    const offset = isBST ? "+01:00" : "+00:00";
    const londonMidnight = new Date(todayStr + "T00:00:00" + offset);
    const oldest = String(Math.floor(londonMidnight.getTime() / 1000));
    console.log(`[bill-ling] Searching for ARUDD message since ${todayStr} (oldest: ${oldest}, BOT_USER_ID: ${BOT_USER_ID})`);
    const history = await app.client.conversations.history({
      token: SLACK_BOT_TOKEN,
      channel: CHANNELS.DATA_BILLING_UPDATES,
      oldest,
      limit: 50,
    });
    console.log(`[bill-ling] Found ${(history.messages || []).length} messages in channel since midnight`);
    // Log first 80 chars of each message for debugging
    for (const m of (history.messages || [])) {
      const preview = (m.text || "").slice(0, 80).replace(/\n/g, "\\n");
      console.log(`[bill-ling]   msg ts=${m.ts} user=${m.user || "none"} bot_id=${m.bot_id || "none"} text="${preview}"`);
    }
    // Match by ARUDD content — check both user ID and bot_id since Slack can use either
    const aruddMsg = (history.messages || []).find(
      m => /ARUDD:/i.test(m.text || "") && (m.user === BOT_USER_ID || m.bot_id)
    );
    if (aruddMsg) {
      // Extract due date from the message text
      const dueDateMatch = (aruddMsg.text || "").match(/Charge date:\s*(\d{2}\/\d{2}\/\d{4})/);
      let dueDate = null;
      if (dueDateMatch) {
        const [d, mo, y] = dueDateMatch[1].split("/");
        dueDate = `${y}-${mo}-${d}`;
      }
      // Extract figures from message text so change tracking works even after a restart
      const postedMatch = (aruddMsg.text || "").match(/Posted in Anchor:\s*(\d+)%/);
      const anchorMatch = (aruddMsg.text || "").match(/Anchor #:\s*([\d,]+)/);
      const gcMatch = (aruddMsg.text || "").match(/GoCardless #:\s*([\d,]+)/);
      const postedPct = postedMatch ? Number(postedMatch[1]) : null;
      const anchorBounces = anchorMatch ? Number(anchorMatch[1].replace(/,/g, "")) : null;
      const gcFailed = gcMatch ? Number(gcMatch[1].replace(/,/g, "")) : null;
      lastAruddMessage = { ts: aruddMsg.ts, channel: CHANNELS.DATA_BILLING_UPDATES, dueDate, postedPct, anchorBounces, gcFailed };
      console.log(`[bill-ling] Found today's ARUDD message (ts: ${aruddMsg.ts}, dueDate: ${dueDate}, posted: ${postedPct}%)`);
      return lastAruddMessage;
    }
  } catch (err) {
    console.error("[bill-ling] Error searching for today's ARUDD message:", err.message);
  }
  return null;
}

/**
 * Search #data-billing-updates for an ARUDD message posted on a specific date.
 * @param {string} targetDate — YYYY-MM-DD of the date the ARUDD was POSTED (not the charge date)
 */
async function findAruddMessageByDate(targetDate) {
  try {
    // Build London midnight boundaries for the target date
    const isBST = new Date(`${targetDate}T12:00:00Z`).toLocaleString("en-GB", { timeZone: "Europe/London", timeZoneName: "short" }).includes("BST");
    const offset = isBST ? "+01:00" : "+00:00";
    const dayStart = new Date(`${targetDate}T00:00:00${offset}`);
    const dayEnd = new Date(`${targetDate}T23:59:59${offset}`);
    const oldest = String(Math.floor(dayStart.getTime() / 1000));
    const latest = String(Math.floor(dayEnd.getTime() / 1000));
    console.log(`[bill-ling] Searching for ARUDD message on ${targetDate} (oldest: ${oldest}, latest: ${latest})`);
    const history = await app.client.conversations.history({
      token: SLACK_BOT_TOKEN,
      channel: CHANNELS.DATA_BILLING_UPDATES,
      oldest,
      latest,
      limit: 50,
    });
    const aruddMsg = (history.messages || []).find(
      m => /ARUDD:/i.test(m.text || "") && (m.user === BOT_USER_ID || m.bot_id)
    );
    if (aruddMsg) {
      const dueDateMatch = (aruddMsg.text || "").match(/Charge date:\s*(\d{2}\/\d{2}\/\d{4})/);
      let dueDate = null;
      if (dueDateMatch) {
        const [d, mo, y] = dueDateMatch[1].split("/");
        dueDate = `${y}-${mo}-${d}`;
      }
      console.log(`[bill-ling] Found ARUDD message from ${targetDate} (ts: ${aruddMsg.ts}, dueDate: ${dueDate})`);
      return { ts: aruddMsg.ts, channel: CHANNELS.DATA_BILLING_UPDATES, dueDate };
    }
    console.log(`[bill-ling] No ARUDD message found for ${targetDate}`);
  } catch (err) {
    console.error(`[bill-ling] Error searching for ARUDD on ${targetDate}:`, err.message);
  }
  return null;
}

/**
 * Refresh an ARUDD message. If targetPostDate is provided, finds that date's message.
 * Otherwise falls back to today's message.
 * Returns the new postedPct (number) on success, or false on failure.
 * Posts a thread reply on the original message showing what changed + date/time of edit.
 */
async function refreshAruddMessage(targetPostDate) {
  const aruddMsg = targetPostDate
    ? await findAruddMessageByDate(targetPostDate)
    : await findTodaysAruddMessage();
  if (!aruddMsg) {
    console.log(`[bill-ling] No ARUDD message found to refresh${targetPostDate ? ` for ${targetPostDate}` : ""}.`);
    return false;
  }
  console.log(`[bill-ling] Refreshing ARUDD report (dueDate: ${aruddMsg.dueDate})...`);
  try {
    const { report, postedPct, anchorBounces, gcFailed } = await buildAruddReport(aruddMsg.dueDate);
    const now = new Date().toLocaleTimeString("en-GB", { hour: "2-digit", minute: "2-digit", timeZone: "Europe/London" });
    const editDate = new Date().toLocaleDateString("en-GB", { day: "2-digit", month: "2-digit", year: "numeric", timeZone: "Europe/London" });
    const updatedReport = report + `\n\n_Updated ${editDate} at ${now} with latest data._`;
    await app.client.chat.update({
      token: SLACK_BOT_TOKEN,
      channel: aruddMsg.channel,
      ts: aruddMsg.ts,
      text: updatedReport,
      mrkdwn: true,
    });
    console.log(`[bill-ling] ARUDD message updated (posted in Anchor now ${postedPct}%).`);

    // Grab the previous figures from memory (if this is today's message)
    const prevPostedPct = lastAruddMessage.ts === aruddMsg.ts ? lastAruddMessage.postedPct : null;
    const prevAnchorBounces = lastAruddMessage.ts === aruddMsg.ts ? lastAruddMessage.anchorBounces : null;
    const prevGcFailed = lastAruddMessage.ts === aruddMsg.ts ? lastAruddMessage.gcFailed : null;

    // Post a thread reply if figures actually changed
    const figuresChanged =
      prevPostedPct !== null && (prevPostedPct !== postedPct || prevAnchorBounces !== anchorBounces || prevGcFailed !== gcFailed);

    if (figuresChanged) {
      const changes = [];
      if (prevPostedPct !== postedPct) {
        changes.push(`Posted in Anchor: ${prevPostedPct}% → ${postedPct}%`);
      }
      if (prevAnchorBounces !== anchorBounces) {
        changes.push(`Anchor bounces: ${prevAnchorBounces.toLocaleString("en-GB")} → ${anchorBounces.toLocaleString("en-GB")}`);
      }
      if (prevGcFailed !== gcFailed) {
        changes.push(`GoCardless failures: ${prevGcFailed.toLocaleString("en-GB")} → ${gcFailed.toLocaleString("en-GB")}`);
      }
      const threadReply =
        `📝 *ARUDD updated — ${editDate} at ${now}*\n` +
        changes.map(c => `• ${c}`).join("\n");

      await app.client.chat.postMessage({
        token: SLACK_BOT_TOKEN,
        channel: aruddMsg.channel,
        thread_ts: aruddMsg.ts,
        text: threadReply,
        mrkdwn: true,
        unfurl_links: false,
        unfurl_media: false,
      });
      console.log(`[bill-ling] ARUDD thread reply posted (changes: ${changes.join(", ")}).`);
    } else if (prevPostedPct !== null) {
      console.log("[bill-ling] ARUDD refresh: no figure changes detected, skipping thread reply.");
    }

    // Update stored figures for next comparison
    if (lastAruddMessage.ts === aruddMsg.ts) {
      lastAruddMessage.postedPct = postedPct;
      lastAruddMessage.anchorBounces = anchorBounces;
      lastAruddMessage.gcFailed = gcFailed;
    }

    return postedPct;
  } catch (err) {
    console.error("[bill-ling] ARUDD refresh error:", err.message);
    return false;
  }
}

/**
 * Called 15 seconds after Denton posts a trade-in status response in the refunds channel.
 * Compares amounts in the original refund request with amounts Denton confirmed.
 * Posts a mismatch warning or a "verified — ready to post" confirmation.
 */
async function checkDentonTradeInAmounts(channel, threadTs) {
  try {
    const thread = await app.client.conversations.replies({
      token: SLACK_BOT_TOKEN,
      channel,
      ts: threadTs,
      limit: 50,
    });
    const msgs = thread.messages || [];

    // Avoid double-posting if Billington already commented on amounts in this thread
    const alreadyChecked = msgs.some(
      m => m.user === BOT_USER_ID &&
           /(Amount mismatch|Denton confirmed|GOGW posted to Anchor \(auto-confirmed\))/i.test(m.text || "")
    );
    if (alreadyChecked) return;

    // Separate human messages from bot (Denton) messages
    // Use getMessageText() so Denton's block-based messages are fully readable
    const humanText  = msgs.filter(m => !m.bot_id).map(m => getMessageText(m)).join("\n");
    const dentonText = msgs
      .filter(m => m.bot_id && /(trade-in:?\s*A\d|trade.in.status|customer declared)/i.test(getMessageText(m)))
      .map(m => getMessageText(m)).join("\n");

    if (!dentonText) return; // Denton hasn't posted trade-in info yet

    // Find all agreement IDs mentioned in the thread
    const allText = msgs.map(m => getMessageText(m)).join("\n");
    const agIds = [...new Set(
      (allText.match(/\bA\d{5,9}\b/gi) || []).map(id => id.toUpperCase())
    )];

    // Denton has replied. For each agreement with a stated refund amount in the
    // thread, reconcile it against Denton's figures and post the exact-action
    // *button* (full vs partial derived from declared vs difference), or flag if
    // it doesn't reconcile. No typed commands (Hargo, 07/07/2026).
    // prepareTradeInRefundButton is idempotent, so a re-run won't double-post.
    let anyHandled = false;
    for (const agId of agIds) {
      const requestedAmt = extractRequestedRefundAmount(humanText, agId);
      if (!requestedAmt) continue;
      const fig = parseDentonTradeInFigures(dentonText, agId) || parseDentonTradeInFigures(allText, agId);
      if (!fig || (fig.declared == null && fig.difference == null)) continue; // no Denton figures for this agId
      anyHandled = true;
      pendingGOGWRequests.delete(`${channel}:${agId}`); // Denton has now replied
      try {
        const status = await prepareTradeInRefundButton({ channel, threadTs, agreementId: agId, amount: requestedAmt });
        console.log(`[bill-ling] Denton watcher → ${agId} £${requestedAmt.toFixed(2)}: ${status}`);
      } catch (e) {
        console.error(`[bill-ling] Denton watcher button post failed for ${agId}:`, e.message);
      }
    }
    if (!anyHandled) return;
  } catch (err) {
    console.error("[bill-ling] checkDentonTradeInAmounts error:", err.message);
  }
}

async function checkAruddSourceTables(dueDate, discrepancyPct, anchorBounces, gcFailed) {
  try {
    const todayStr = new Date().toLocaleDateString("en-CA", { timeZone: "Europe/London" });
    // Fetch the view definition to extract source tables dynamically
    const viewRows = await runBigQueryRaw(`
      SELECT view_definition
      FROM \`raylo-production.landing_billington.INFORMATION_SCHEMA.VIEWS\`
      WHERE table_name = 'bacs_monitoring'
    `);
    if (!viewRows.length) return;
    const viewSql = formatBQValue(viewRows[0].view_definition) || "";
    // Extract all project.dataset.table references
    const tableRefs = [...new Set(
      [...viewSql.matchAll(/`(raylo-production\.[a-z_]+\.[a-z_]+)`/gi)].map(m => m[1])
    )];
    if (!tableRefs.length) return;

    // Check last_modified_time for each source table
    const staleTables = [];
    for (const ref of tableRefs) {
      const [, dataset, table] = ref.split(".");
      if (!dataset || !table) continue;
      try {
        const meta = await runBigQueryRaw(`
          SELECT TIMESTAMP_MILLIS(last_modified_time) AS last_modified
          FROM \`raylo-production.${dataset}.__TABLES__\`
          WHERE table_id = '${table}'
          LIMIT 1
        `);
        if (!meta.length) continue;
        const lastMod = formatBQValue(meta[0].last_modified).slice(0, 10);
        if (lastMod < todayStr) {
          staleTables.push(`• \`${ref}\` — last updated ${lastMod}`);
        }
      } catch (_) { /* skip tables we can't access */ }
    }

    if (staleTables.length) {
      const alertMsg =
        `⚠️ *ARUDD Data Freshness Alert*\n` +
        `Discrepancy between Anchor (#${anchorBounces.toLocaleString("en-GB")}) and GoCardless (#${gcFailed.toLocaleString("en-GB")}) is *${discrepancyPct.toFixed(1)}%* — above the 5% threshold.\n\n` +
        `The following source tables for \`bacs_monitoring\` do not appear to have been updated today (${todayStr}):\n` +
        staleTables.join("\n") + "\n\n" +
        `This may explain the discrepancy. Please check the data pipeline.`;
      await app.client.chat.postMessage({
        token: SLACK_BOT_TOKEN,
        channel: CHANNELS.DATA_BILLING_ALERTS,
        text: alertMsg,
        mrkdwn: true,
      });
      console.log("[bill-ling] ARUDD source table staleness alert posted to data-billing-alerts.");
    } else {
      console.log("[bill-ling] All source tables updated today — discrepancy is not a data freshness issue.");
    }
  } catch (err) {
    console.error("[bill-ling] Source table check error:", err.message);
  }
}

