// Stannp + GoCardless balance checks — finance channel only (Hargo, 15/07/2026)
// ---------------------------------------------------------------------------
// The standalone 08:10 Stannp and 08:15 GoCardless posts to #data-billing-updates
// were removed at Hargo's request. Both balances now post ONLY to
// #collab-finance-customer-ops, once, via the combined runFinanceBalanceUpdate()
// at 08:10 daily (see below). On-demand "what's the Stannp/GoCardless balance?"
// queries still work in whatever channel they're asked in.

// ---------------------------------------------------------------------------
// Cron: 8:10am daily — combined balance update to #collab-finance-customer-ops
// ---------------------------------------------------------------------------
// Hargo, 15/07/2026: post GoCardless and Stannp TOGETHER (same time) in
// #collab-finance-customer-ops every day, to avoid staggered pings. GoCardless
// first, then Stannp (matches the approved preview). This replaces the old
// Stannp-only cross-post from the 08:10 Stannp cron.
async function runFinanceBalanceUpdate() {
  // Only post an account that needs a top up; healthy accounts stay silent, so on a
  // fully-healthy day nothing is posted at all (Hargo, 15/07/2026). The balances are
  // still fetched (and the burn history still saved to GCS) so tracking never gaps.
  let posted = 0;
  try {
    const gc = await getGoCardlessBalance();
    const alert = getGoCardlessAlert(gc);
    if (alert.isWarning) {
      const report = formatGoCardlessReport(gc);
      await app.client.chat.postMessage({
        token: SLACK_BOT_TOKEN, channel: CHANNELS.FINANCE_CUSTOMER_OPS,
        text: report, blocks: buildBalanceBlocks(report, "gocardless", gc.balance, alert.withButton),
        mrkdwn: true, unfurl_links: false, unfurl_media: false,
      });
      posted++;
    }
  } catch (err) {
    console.error("[bill-ling] Finance update: GoCardless post failed:", err.message);
  }
  try {
    const st = await getStannpBalance();
    const alert = getStannpAlert(st);
    if (alert.isWarning) {
      const report = formatStannpReport(st);
      await app.client.chat.postMessage({
        token: SLACK_BOT_TOKEN, channel: CHANNELS.FINANCE_CUSTOMER_OPS,
        text: report, blocks: buildBalanceBlocks(report, "stannp", st.balance, alert.withButton),
        mrkdwn: true, unfurl_links: false, unfurl_media: false,
      });
      posted++;
    }
  } catch (err) {
    console.error("[bill-ling] Finance update: Stannp post failed:", err.message);
  }
  console.log(`[bill-ling] Finance balance update: ${posted} account(s) needed a top up; healthy accounts stayed silent.`);
}
cron.schedule("10 8 * * *", () => { runFinanceBalanceUpdate(); }, { timezone: "Europe/London" });
