// ---------------------------------------------------------------------------
// Cron: hourly — Waive Log → close sheet sync + report to data-billing-updates
// ---------------------------------------------------------------------------
// Runs every hour on the hour. Posts to #data-billing-updates ONLY if there's
// something to report (skipped_paid, no_damage_fee, written, errors).
// (Hargo, 21/05/2026.)
async function runWaiveLogCron() {
  try {
    const r = await processWaiveLog();
    const newWaives        = r.written            || [];
    const paidIgnore       = r.skippedPaid        || []; // first-time reports
    const noDamageFee      = r.skippedNoDamageFee || [];
    const unconfirmed      = r.skippedUnconfirmed || []; // first-time reports
    const chasesPaid       = r.chasesPaid         || []; // thread chases
    const chasesUnconfirmed = r.chasesUnconfirmed || []; // thread chases
    const partialPaid      = r.partialPaid        || []; // partial — fee collected
    const partialUncollected = r.partialUncollected || []; // partial — past due, uncollected
    const partialUnconfirmed = r.partialUnconfirmed || []; // partial — DD pending / not due
    const chasesPartial    = r.chasesPartial      || []; // partial thread chases
    const errors           = r.errors             || [];

    const todayWdIso = new Date().toLocaleDateString("en-CA", { timeZone: "Europe/London" });

    // ── 1. Top-level channel post — only first-time reports + new waives ──
    const hasTopLevelContent =
      newWaives.length > 0 ||
      paidIgnore.length > 0 ||
      noDamageFee.length > 0 ||
      unconfirmed.length > 0 ||
      partialPaid.length > 0 ||
      partialUncollected.length > 0 ||
      partialUnconfirmed.length > 0 ||
      errors.length > 0;

    let topLevelTs = null;
    if (hasTopLevelContent) {
      const todayDisplay = new Date().toLocaleString("en-GB", {
        timeZone: "Europe/London",
        day: "2-digit", month: "2-digit", year: "numeric",
        hour: "2-digit", minute: "2-digit",
      });
      const lines = [`*Waive Log update — ${todayDisplay} London*`];

      if (newWaives.length > 0) {
        lines.push("");
        lines.push(`*✅ ${newWaives.length} agreement${newWaives.length === 1 ? "" : "s"} added to closure sheet (damage fee uncollected / bounced):*`);
        for (const w of newWaives) {
          const amt = Number.isFinite(w.damageFeeAmount) && w.damageFeeAmount > 0 ? ` — £${w.damageFeeAmount.toFixed(2)}` : "";
          const reason = w.reason ? ` — _${w.reason}_` : "";
          lines.push(`• \`${w.agreementId}\`${amt}${reason}`);
        }
      }

      if (paidIgnore.length > 0) {
        lines.push("");
        lines.push(`*💷 ${paidIgnore.length} pending action — damage fee already collected, needs GOGW + refund + close-sheet (<@${CHARLOTTE_PLATT_USER_ID}> please action, J column flagged):*`);
        for (const p of paidIgnore) {
          const method = p.method === "paid_card" ? "card payment" : "DD";
          const amt = Number.isFinite(p.damageFeeAmount) && p.damageFeeAmount > 0 ? ` — £${p.damageFeeAmount.toFixed(2)}` : "";
          const gogwStr = p.gogwPosted ? `GOGW ✅${p.gogwDate ? ` ${p.gogwDate}` : ""}` : "GOGW ❌ not yet";
          const refundStr = p.refundPosted ? `refund ✅${p.refundDate ? ` ${p.refundDate}` : ""}` : "refund ❌ not yet";
          lines.push(`• \`${p.agreementId}\`${amt} — ${method} — ${gogwStr}, ${refundStr}`);
        }
      }

      if (noDamageFee.length > 0) {
        lines.push("");
        lines.push(`*🚫 ${noDamageFee.length} skipped — no damage fee on Anchor (note added in K):*`);
        for (const n of noDamageFee.slice(0, 25)) {
          lines.push(`• \`${n.agreementId}\``);
        }
        if (noDamageFee.length > 25) lines.push(`  …and ${noDamageFee.length - 25} more`);
      }

      if (unconfirmed.length > 0) {
        lines.push("");
        lines.push(`*⏳ ${unconfirmed.length} pending — DD attempted <1 working day ago, recheck on the next working day:*`);
        for (const u of unconfirmed.slice(0, 25)) {
          lines.push(`• \`${u.agreementId}\``);
        }
        if (unconfirmed.length > 25) lines.push(`  …and ${unconfirmed.length - 25} more`);
      }

      if (partialPaid.length > 0 || partialUncollected.length > 0 || partialUnconfirmed.length > 0) {
        const totalPartial = partialPaid.length + partialUncollected.length + partialUnconfirmed.length;
        lines.push("");
        lines.push(`*🟠 ${totalPartial} PARTIAL waiver${totalPartial === 1 ? "" : "s"} (column H < damage fee — will NOT auto-close):*`);
        for (const p of partialPaid) {
          const method = p.method === "paid_card" ? "card" : "DD";
          lines.push(`• \`${p.agreementId}\` — fee £${p.feeDue.toFixed(2)} collected (${method}); waive £${p.waiveAmt.toFixed(2)} → <@${CHARLOTTE_PLATT_USER_ID}> post GOGW £${p.waiveAmt.toFixed(2)} + refund £${p.waiveAmt.toFixed(2)}`);
        }
        for (const p of partialUncollected) {
          lines.push(`• \`${p.agreementId}\` — fee £${p.feeDue.toFixed(2)} uncollected, past due${p.dueDate ? ` (${p.dueDate})` : ""}; waive £${p.waiveAmt.toFixed(2)} → <@${CHARLOTTE_PLATT_USER_ID}> post GOGW £${p.waiveAmt.toFixed(2)} only (no refund). Do NOT close.`);
        }
        for (const p of partialUnconfirmed) {
          const detail = p.notDue ? `not yet due${p.dueDate ? ` (${p.dueDate})` : ""}` : `DD attempted ${p.collDate || "(date unknown)"}, awaiting confirmation`;
          lines.push(`• \`${p.agreementId}\` — fee £${p.feeDue.toFixed(2)}, waive £${p.waiveAmt.toFixed(2)} — ${detail}; waiting (will flag once the DD ${p.notDue ? "is attempted/confirms" : "confirms"})`);
        }
      }

      if (errors.length > 0) {
        lines.push("");
        lines.push(`*❌ ${errors.length} error${errors.length === 1 ? "" : "s"}:*`);
        for (const e of errors.slice(0, 10)) {
          lines.push(`• row ${e.rowNum} (\`${e.agreementId}\`): ${e.error}`);
        }
      }

      try {
        const fullText = lines.join("\n");
        // Per-agreement "Mark processed" buttons on the first-time report (Hargo,
        // 26/06/2026) — so Charlotte can close a row without waiting for a chase.
        // Actionable = needs a GOGW/refund posted (paid + partial-paid + partial-
        // uncollected); waiting rows (unconfirmed DD / not-yet-due) get no button.
        // The handler is idempotent + gated, and uses the report's own ts as the
        // thread when the value carries no `t`.
        const seenAg = new Set();
        const waiveBtnItems = [...paidIgnore, ...partialPaid, ...partialUncollected]
          .filter(p => p && p.rowNum && p.agreementId)
          .filter(p => { if (seenAg.has(p.agreementId)) return false; seenAg.add(p.agreementId); return true; })
          .slice(0, 20)
          .map(p => ({ r: p.rowNum, a: p.agreementId }));
        let topLevelBlocks;
        if (INTERACTIVE_BUTTONS_ENABLED && waiveBtnItems.length) {
          topLevelBlocks = [];
          let buf = "";
          const flush = () => { if (buf) { topLevelBlocks.push({ type: "section", text: { type: "mrkdwn", text: buf.slice(0, 3000) } }); buf = ""; } };
          for (const ln of fullText.split("\n")) {
            if (buf && (buf.length + 1 + ln.length) > 2900) flush();
            buf = buf ? buf + "\n" + ln : ln;
          }
          flush();
          topLevelBlocks.push({ type: "actions", elements: waiveBtnItems.map(it => ({
            type: "button",
            text: { type: "plain_text", text: `✋ Mark ${it.a} processed`.slice(0, 75), emoji: true },
            action_id: "btn_waive_mark_processed",
            value: JSON.stringify({ items: [{ r: it.r, a: it.a }] }),
            confirm: {
              title: { type: "plain_text", text: "Mark waive processed?" },
              text: { type: "mrkdwn", text: `Closes the Waive Log row for ${it.a} (I=TRUE, success note) and stops the chase. Charlotte / Ciaran / Hargo only.` },
              confirm: { type: "plain_text", text: "Mark done" },
              deny: { type: "plain_text", text: "Cancel" },
            },
          })) });
        }
        let postRes;
        try {
          postRes = await app.client.chat.postMessage({
            token: SLACK_BOT_TOKEN,
            channel: CHANNELS.DATA_BILLING_UPDATES,
            text: fullText,
            ...(topLevelBlocks ? { blocks: topLevelBlocks } : {}),
            mrkdwn: true,
            unfurl_links: false,
            unfurl_media: false,
          });
        } catch (blockErr) {
          console.error("[bill-ling] Waive Log top-level blocks post failed, falling back to text:", blockErr.message);
          postRes = await app.client.chat.postMessage({
            token: SLACK_BOT_TOKEN,
            channel: CHANNELS.DATA_BILLING_UPDATES,
            text: fullText,
            mrkdwn: true,
            unfurl_links: false,
            unfurl_media: false,
          });
        }
        topLevelTs = postRes?.ts || null;
      } catch (err) {
        console.error("[bill-ling] Waive Log top-level post failed:", err.message);
      }

      // ── 2. Record thread mapping for each first-time agreement ──
      if (topLevelTs) {
        const firstReportedAgreementIds = [
          ...paidIgnore.map(p => p.agreementId),
          ...unconfirmed.map(u => u.agreementId),
          ...partialPaid.map(p => p.agreementId),
          ...partialUncollected.map(p => p.agreementId),
          ...partialUnconfirmed.map(p => p.agreementId),
        ];
        for (const agreementId of firstReportedAgreementIds) {
          waiveLogReportThreads.set(agreementId, {
            channel: CHANNELS.DATA_BILLING_UPDATES,
            ts: topLevelTs,
            firstReportedAt: todayWdIso,
          });
        }
        if (firstReportedAgreementIds.length > 0) {
          await saveWaiveLogThreadsAsync();
          console.log(`[bill-ling] Waive Log: recorded thread mapping for ${firstReportedAgreementIds.length} agreements at ts=${topLevelTs}`);
        }
      }
    } else {
      console.log("[bill-ling] Waive Log hourly: no new top-level content — skipping channel post.");
    }

    // ── 3. Chases — post as thread replies on the ORIGINAL first-report ts ──
    // Group chases by their thread ts so we post one reply per thread that
    // covers all the agreements still pending in that thread.
    const chasesAll = [
      ...chasesPaid.map(c => ({ ...c, kind: "paid" })),
      ...chasesUnconfirmed.map(c => ({ ...c, kind: "unconfirmed" })),
      ...chasesPartial.map(c => ({ ...c, kind: "partial" })),
    ];
    const byThread = new Map(); // ts → { channel, items: [] }
    for (const ch of chasesAll) {
      if (!ch.ts || !ch.channel) continue;
      const key = `${ch.channel}:${ch.ts}`;
      if (!byThread.has(key)) byThread.set(key, { channel: ch.channel, ts: ch.ts, items: [] });
      byThread.get(key).items.push(ch);
    }
    for (const { channel, ts, items } of byThread.values()) {
      const todayDisplay = new Date().toLocaleString("en-GB", {
        timeZone: "Europe/London",
        day: "2-digit", month: "2-digit", year: "numeric",
        hour: "2-digit", minute: "2-digit",
      });
      const lines = [`*⏳ Still pending — ${todayDisplay} London* (<@${CHARLOTTE_PLATT_USER_ID}> please action)`];
      for (const it of items) {
        const sinceNote = it.firstReportedAt ? ` (first reported ${it.firstReportedAt})` : "";
        if (it.kind === "partial") {
          if (it.subkind === "paid") {
            const method = it.method === "paid_card" ? "card" : "DD";
            lines.push(`• \`${it.agreementId}\` — PARTIAL: fee £${it.feeDue.toFixed(2)} collected (${method}); still needs GOGW £${it.waiveAmt.toFixed(2)} + refund £${it.waiveAmt.toFixed(2)}${sinceNote}`);
          } else if (it.subkind === "uncollected") {
            lines.push(`• \`${it.agreementId}\` — PARTIAL: fee £${it.feeDue.toFixed(2)} uncollected past due; still needs GOGW £${it.waiveAmt.toFixed(2)} only (no refund), do NOT close${sinceNote}`);
          } else {
            lines.push(`• \`${it.agreementId}\` — PARTIAL: DD attempted ${it.collDate || "(date unknown)"}, still not confirmed; waiting${sinceNote}`);
          }
        } else if (it.kind === "paid") {
          const method = it.method === "paid_card" ? "card payment" : "DD";
          const amt = Number.isFinite(it.damageFeeAmount) && it.damageFeeAmount > 0 ? ` — £${it.damageFeeAmount.toFixed(2)}` : "";
          const gogwStr = it.gogwPosted ? `GOGW ✅ posted${it.gogwDate ? ` ${it.gogwDate}` : ""}` : "GOGW ❌ not yet";
          const refundStr = it.refundPosted ? `refund ✅ posted${it.refundDate ? ` ${it.refundDate}` : ""}` : "refund ❌ not yet";
          let tail;
          if (it.gogwPosted && !it.refundPosted) tail = `${gogwStr}, ${refundStr} — the £${(it.damageFeeAmount || 0).toFixed(2)} collected hasn't been refunded to the customer yet, please post the refund`;
          else if (!it.gogwPosted && it.refundPosted) tail = `${gogwStr}, ${refundStr} — please post the GOGW`;
          else tail = `${gogwStr}, ${refundStr} — still needs GOGW + refund + close-sheet`;
          lines.push(`• \`${it.agreementId}\`${amt} — ${method} — ${tail}${sinceNote}`);
        } else {
          lines.push(`• \`${it.agreementId}\` — DD attempted on ${it.collDate || "(date unknown)"}, still not confirmed${sinceNote}`);
        }
      }
      try {
        // "Mark as processed manually" button per agreement (Hargo, 26/06/2026):
        // after Billington chases, Charlotte/Ciaran/Hargo can click to close the
        // Waive Log row (I=TRUE, J=success, K=audit note) so the cron stops
        // chasing — the fix for rows that were actioned but never flipped to
        // I=TRUE (e.g. A00133052). One button per agreement; the handler is
        // idempotent, and once a row is flipped the cron won't re-chase it.
        const btnItems = items.filter(it => it.rowNum && it.agreementId).slice(0, 10);
        const waiveBlocks = (INTERACTIVE_BUTTONS_ENABLED && btnItems.length) ? [
          { type: "section", text: { type: "mrkdwn", text: lines.join("\n").slice(0, 3000) } },
          { type: "actions", elements: btnItems.map(it => ({
            type: "button",
            text: { type: "plain_text", text: `✋ Mark ${it.agreementId} processed`.slice(0, 75), emoji: true },
            action_id: "btn_waive_mark_processed",
            value: JSON.stringify({ t: ts, items: [{ r: it.rowNum, a: it.agreementId }] }),
            confirm: {
              title: { type: "plain_text", text: "Mark waive processed?" },
              text: { type: "mrkdwn", text: `Closes the Waive Log row for ${it.agreementId} (I=TRUE, success note) and stops the chase. Charlotte / Ciaran / Hargo only.` },
              confirm: { type: "plain_text", text: "Mark done" },
              deny: { type: "plain_text", text: "Cancel" },
            },
          })) },
        ] : null;
        await app.client.chat.postMessage({
          token: SLACK_BOT_TOKEN,
          channel,
          thread_ts: ts,
          text: lines.join("\n"),
          ...(waiveBlocks ? { blocks: waiveBlocks } : {}),
          mrkdwn: true,
          unfurl_links: false,
          unfurl_media: false,
        });
        console.log(`[bill-ling] Waive Log: posted ${items.length}-item chase in thread ts=${ts}`);
      } catch (err) {
        console.error(`[bill-ling] Waive Log chase post failed for ts=${ts}:`, err.message);
      }
    }
  } catch (err) {
    console.error("[bill-ling] Waive Log hourly cron error:", err.message);
  }
}

