// ---------------------------------------------------------------------------
// Cron: every minute — fire pending reminders
// ---------------------------------------------------------------------------
cron.schedule("* * * * *", async () => {
  const now = new Date();
  const pending = reminders.filter(r => !r.fired && !r.cancelled && new Date(r.fireAt) <= now);
  for (const r of pending) {
    try {
      if (r.actionType && SCHEDULED_ACTIONS[r.actionType]) {
        // This is a scheduled task — actually run the action. Pass the full
        // reminder object as the second argument so handlers like
        // update_alert_parent can read parentTs (and any future per-task data).
        console.log(`[bill-ling] Executing scheduled ${r.actionType} report (#${r.id})...`);
        await SCHEDULED_ACTIONS[r.actionType](r.channel, r);
        r.fired = true;
        console.log(`[bill-ling] Scheduled ${r.actionType} report #${r.id} executed.`);
      } else {
        // Normal reminder — post a descriptive message
        const mention = r.targetUserId ? `<@${r.targetUserId}>` : r.targetUserName;
        const text = `${mention} 🔔 *Reminder:* ${r.what}`;
        await app.client.chat.postMessage({
          token: SLACK_BOT_TOKEN,
          channel: r.channel,
          text,
          mrkdwn: true,
        });
        r.fired = true;
        console.log(`[bill-ling] Fired reminder #${r.id}: "${r.what}" for ${mention}`);
      }
    } catch (err) {
      console.error(`[bill-ling] Failed to fire reminder/task #${r.id}:`, err.message);
    }
  }
  if (pending.length > 0) saveReminders();
}, { timezone: "Europe/London" });

// ---------------------------------------------------------------------------
// Pending GOGW arrears decisions — keyed by `${channel}:${thread_ts || ts}`
// Set when arrears detected on an agreement; cleared once Hargo decides.
// ---------------------------------------------------------------------------
const pendingGOGWDecisions = new Map();

// ---------------------------------------------------------------------------
// Next-steps per-agreement evaluator (shared)
// ---------------------------------------------------------------------------
// Used by BOTH the add_transaction-nested "post GOGW on A and confirm next
// steps on B, C" path AND the standalone `next_steps` intent ("confirm next
// steps on A00…" / "what are the next steps in this thread?"). Returns ONE
// Slack bullet string describing the live status + next action for a single
// agreement. It live-reads Anchor every time (TotalArrears, GOGW TypeId 61/62,
// refund TypeId 149/35) so an arrears hold is only ever declared "ready to
// post" once the ledger actually shows the arrears cleared — Billington does
// not take the thread's word for it. Side effects: may @-ask Denton for the
// figure and register pending GOGW state. ctx = { channel, thread_ts, ts, say, user }.
async function buildNextStepsBullet(id, contextMessages, ctx) {
  const { channel, thread_ts, ts, say, user } = ctx;
  const ctxText = contextMessages || "";
  const nsTodayStr = new Date().toLocaleDateString("en-CA", { timeZone: "Europe/London" });
  try {
    // ── Step 0: Approval gate ─────────────────────────────────────────────
    // Only walk the post-readiness checks if there is explicit approval in
    // the thread for THIS agreement. Otherwise summarise current status.
    const ctxLines = ctxText.split(/\n/);
    let hasApprovalForId = false;
    for (let i = 0; i < ctxLines.length; i++) {
      const window = ctxLines.slice(Math.max(0, i - 2), Math.min(ctxLines.length, i + 3)).join(" ");
      if (
        window.toUpperCase().includes(id.toUpperCase()) &&
        /\b(happy\s+to\s+approve|approved|go\s+ahead|okay[,.]?\s+let['']?s?\s+do\s+that|let['']?s?\s+do\s+that|yes[,.]?\s+process|proceed|approve\s+this|approve\s+for\s+this)\b/i.test(window)
      ) {
        hasApprovalForId = true;
        break;
      }
    }

    if (!hasApprovalForId) {
      const statusPrompt =
        `You are Billington, a billing ops Slack bot for Raylo. ` +
        `Based on the thread context below, write ONE concise bullet (no bullet symbol) ` +
        `describing the current status and outstanding next action for agreement ${id}. ` +
        `State who owns the next action and what it is. Do not invent information not in the thread.\n\n` +
        `Thread context:\n${ctxText}`;
      const statusSummary = await askClaude(statusPrompt);
      return `• *${id}*: ${statusSummary.trim()}`;
    }

    // ── Step 1: Amount validation ──────────────────────────────────────────
    let dentonAmt    = extractDentonAmountFromContext(id, ctxText);
    const requestedAmt = extractAmountFromContext(id, ctxText);
    let amountNote = "";

    if (dentonAmt === null) {
      // Denton hasn't posted yet — ask, wait 30s, then re-read the thread.
      const dentonMention = `<@${DENTON_USER_ID}>`;
      await say({
        text: `${dentonMention} can you please provide the trade-in status and figures for agreement ${id}?`,
        thread_ts: thread_ts || ts,
        mrkdwn: true,
        unfurl_links: false,
        unfurl_media: false,
      });
      await new Promise(resolve => setTimeout(resolve, 30000));
      try {
        const updatedThread = await app.client.conversations.replies({
          token: SLACK_BOT_TOKEN,
          channel,
          ts: thread_ts || ts,
          limit: 50,
        });
        const updatedCtx = (updatedThread.messages || [])
          .map(m => `${m.username || m.user || "Unknown"}: ${getMessageText(m)}`)
          .join("\n");
        dentonAmt = extractDentonAmountFromContext(id, updatedCtx);
      } catch (_) { /* thread fetch failed — continue without */ }

      if (dentonAmt === null) {
        pendingGOGWRequests.set(`${channel}:${id}`, {
          requesterId: user,
          thread_ts: thread_ts || ts,
          requestedAt: Date.now(),
        });
        return `• *${id}*: Asked Denton for the trade-in amount — no response yet. Once he confirms, re-issue \`post GOGW on ${id} £<amount>\` and I'll validate it against Denton's figure before posting. I won't post automatically.`;
      }
    }

    if (requestedAmt !== null && Math.abs(dentonAmt - requestedAmt) > 0.01) {
      amountNote = ` _(thread requested £${requestedAmt.toFixed(2)}, using Denton's confirmed £${dentonAmt.toFixed(2)})_`;
    }

    // ── Step 2: Anchor checks (LIVE) ───────────────────────────────────────
    const nsXml       = await getAgreementFromAnchor(id);
    const nsTxnBlocks = nsXml.match(/<(?:a:)?Transaction>[\s\S]*?<\/(?:a:)?Transaction>/g) || [];

    // Check 1: Blocking TypeIds
    let nsBlockingTxn = null;
    for (const blk of nsTxnBlocks) {
      const tm = blk.match(/<(?:a:)?TypeId>(\d+)<\/(?:a:)?TypeId>/);
      if (!tm) continue;
      const tid = parseInt(tm[1], 10);
      if (GOGW_BLOCKING_TYPE_IDS.has(tid)) {
        const dm = blk.match(/<(?:a:)?TransactionDate>([^<]+)<\/(?:a:)?TransactionDate>/);
        nsBlockingTxn = {
          label: TRANSACTION_TYPES[tid] || `TypeId ${tid}`,
          typeId: tid,
          date: dm ? dm[1].slice(0, 10) : "unknown",
        };
        break;
      }
    }
    if (nsBlockingTxn) {
      return `• *${id}*: ⛔ Cannot post GOGW — *${nsBlockingTxn.label}* transaction present (TypeId ${nsBlockingTxn.typeId}, ${nsBlockingTxn.date}). Review before processing.`;
    }

    // Check 2: Net GOGW (61 vs 62) + refund bank transfer (149 vs 35)
    let nsPosted = 0, nsReversed = 0, nsHasAny = false, nsLastPostedDate = null;
    let refundPosted = 0, refundReversed = 0, lastRefundDate = null;
    for (const blk of nsTxnBlocks) {
      const tm = blk.match(/<(?:a:)?TypeId>(\d+)<\/(?:a:)?TypeId>/);
      if (!tm) continue;
      const tid = parseInt(tm[1], 10);
      const am = blk.match(/<(?:a:)?Amount>([^<]+)<\/(?:a:)?Amount>/);
      const dm = blk.match(/<(?:a:)?TransactionDate>([^<]+)<\/(?:a:)?TransactionDate>/);
      const rawAmt = am ? parseFloat(am[1]) : 0;
      const txnDate = dm ? dm[1].slice(0, 10) : null;
      if (tid === 61 || tid === 62) {
        nsHasAny = true;
        if (tid === 62 || rawAmt < 0) {
          nsReversed += Math.abs(rawAmt);
        } else {
          nsPosted += Math.abs(rawAmt);
          if (txnDate && (!nsLastPostedDate || txnDate > nsLastPostedDate)) nsLastPostedDate = txnDate;
        }
      } else if (tid === 149 || tid === 35) {
        if (tid === 35 || rawAmt < 0) {
          refundReversed += Math.abs(rawAmt);
        } else {
          refundPosted += Math.abs(rawAmt);
          if (txnDate && (!lastRefundDate || txnDate > lastRefundDate)) lastRefundDate = txnDate;
        }
      }
    }
    const nsNet        = nsPosted - nsReversed;
    const nsUnreversed = nsHasAny && nsNet > 0.01;
    const refundNet    = refundPosted - refundReversed;
    const hasRefund    = refundNet > 0.01;

    // Closed: both GOGW and refund posted
    if (nsUnreversed && hasRefund) {
      const gogwDateStr = nsLastPostedDate
        ? new Date(nsLastPostedDate).toLocaleDateString("en-GB", { day: "2-digit", month: "short", year: "numeric" })
        : "unknown date";
      const refundDateStr = lastRefundDate
        ? new Date(lastRefundDate).toLocaleDateString("en-GB", { day: "2-digit", month: "short", year: "numeric" })
        : "unknown date";
      const matchNote = (typeof dentonAmt === "number" && Math.abs(nsNet - dentonAmt) > 0.01)
        ? ` _(GOGW £${nsNet.toFixed(2)} differs from Denton's £${dentonAmt.toFixed(2)} — verify)_`
        : "";
      return `• *${id}*: ✅ Closed — GOGW *£${nsNet.toFixed(2)}* posted (${gogwDateStr}) and refund bank transfer *£${refundNet.toFixed(2)}* posted (${refundDateStr}). No further action.${matchNote}`;
    }

    if (nsUnreversed) {
      const postedDateStr = nsLastPostedDate
        ? new Date(nsLastPostedDate).toLocaleDateString("en-GB", { day: "2-digit", month: "short", year: "numeric" })
        : "unknown date";
      const amountMatchesRequested = (typeof dentonAmt === "number" && Math.abs(nsNet - dentonAmt) <= 0.01);
      if (amountMatchesRequested) {
        return `• *${id}*: GOGW of *£${nsNet.toFixed(2)}* posted on *${postedDateStr}*; refund bank transfer (TypeId 149) not yet posted. <@${REFUND_CONTACTS.PROCESSING.id}> to action the bank transfer.`;
      }
      return `• *${id}*: ⚠️ A GOGW of *£${nsNet.toFixed(2)}* was posted on *${postedDateStr}* and has not been fully reversed ` +
        `(posted: £${nsPosted.toFixed(2)}, reversed: £${nsReversed.toFixed(2)}). ` +
        `Should another GOGW of £${dentonAmt.toFixed(2)} be posted on top of this?`;
    }

    // Check 3: Arrears (LIVE TotalArrears read)
    const arM      = nsXml.match(/<(?:a:)?TotalArrears>([^<]+)<\/(?:a:)?TotalArrears>/);
    const nsArrears = arM ? parseFloat(arM[1]) : 0;

    if (nsArrears > 0.01) {
      pendingGOGWDecisions.set(`${channel}:${thread_ts || ts}:${id}`, {
        agreementId: id,
        amount: dentonAmt,
        transactionDate: nsTodayStr,
        notes: "Trade-in refund",
        arrearsAmount: nsArrears,
      });
      return `• *${id}*: ⚠️ Still in arrears of *£${nsArrears.toFixed(2)}* on Anchor (live check just now). ` +
        `Not cleared on the ledger yet — hold off. Once it shows £0, post the GOGW of £${dentonAmt.toFixed(2)} to offset, ` +
        `or reply *post now* to post it against the arrears now / *wait* to keep holding.`;
    }

    // ── All clear — recommend, do NOT auto-post ──────────────────────────
    const nsReversalNote = nsHasAny
      ? ` _(previous GOGW was posted and fully reversed)_`
      : "";
    const arrearsConfirm = nsArrears < -0.01
      ? `in credit £${Math.abs(nsArrears).toFixed(2)}`
      : `arrears £0.00`;
    return `• *${id}*: ✅ Pre-checks passed — live Anchor check shows *${arrearsConfirm}*, ready to post GOGW of *£${dentonAmt.toFixed(2)}*.${amountNote}${nsReversalNote} ` +
      `Reply \`post GOGW on ${id} £${dentonAmt.toFixed(2)}\` to action.`;

  } catch (e) {
    console.error(`[bill-ling] Next steps GOGW error for ${id}:`, e.message);
    return `• *${id}*: ❌ Anchor unavailable — ${e.message}`;
  }
}

