// "🩹 Remediate notices" on a Notices QA report → runs the missing-NODS
// remediation (SetTeamStatus 532) for the agreements currently missing a NODS.
// LPF-team-gated, same as the typed "remediate missing NODS" command. Writes to
// Anchor, so this only fires from this deterministic handler. (Hargo, 23/06/2026.)
app.action("btn_notices_remediate", async ({ body, ack, client }) => {
  await ack();
  try {
    const user = body.user?.id;
    const ch = body.channel?.id;
    const ts = body.message?.ts;
    let date = null;
    try { date = JSON.parse(body.actions?.[0]?.value || "{}").date || null; } catch (_) {}
    if (!LATE_FEE_APPLY_AUTHORISED_USERS.has(user)) {
      try { await client.chat.postEphemeral({ token: SLACK_BOT_TOKEN, channel: ch, user, text: `Only ${authorisedUsersList(LATE_FEE_APPLY_AUTHORISED_USERS)} can remediate missing NODS (it changes team status in Anchor).` }); } catch (_) {}
      return;
    }
    let missing = [];
    try { missing = await getNodsNotCovered(date); } catch (e) { console.error("[bill-ling] btn_notices_remediate getNodsNotCovered:", e.message); }
    const targets = [...new Set(missing.map(r => (r.agreement_id || "").toUpperCase()).filter(Boolean))];
    if (targets.length === 0) {
      try { await client.chat.postMessage({ token: SLACK_BOT_TOKEN, channel: ch, thread_ts: ts, text: `No missing-NODS agreements to remediate for ${date || "today"} — looks resolved. Hit *🔄 Refresh report* to confirm.` }); } catch (_) {}
      return;
    }
    if (targets.length > 10) {
      // Per-agreement email checks only run for ≤10 (Hargo, 02/07/2026). A miss
      // this large is systemic — surface it rather than bulk-refiring.
      try { await client.chat.postMessage({ token: SLACK_BOT_TOKEN, channel: ch, thread_ts: ts, text: `🛑 ${targets.length} agreements missing a NODS for ${date || "today"} — that's too many to email-check individually (≤10 only). This looks systemic; investigate before bulk-refiring. Drill-down:\n\`\`\`${nodsNotCoveredSQL(date || new Date().toLocaleDateString("en-CA", { timeZone: "Europe/London" }))}\`\`\`` , mrkdwn: true }); } catch (_) {}
      return;
    }
    await client.chat.postMessage({ token: SLACK_BOT_TOKEN, channel: ch, thread_ts: ts, text: `🩹 <@${user}> triggered NODS remediation for ${targets.length} agreement${targets.length === 1 ? "" : "s"} — checking the Audits/NODS email, refiring SetTeamStatus(${NODS_TARGET_TEAM_STATUS_ID}) where the NODS didn't send…`, mrkdwn: true });
    const resultLines = [];
    let posted = 0, skipped = 0, failed = 0;
    for (const agId of targets) {
      try {
        const r = await remediateMissingNodsForAgreement(agId, { dryRun: false });
        if (r.auditCheckError) { resultLines.push(`⚠️ *${agId}* — couldn't check the Audits/NODS inbox (${r.auditCheckError}); not refiring (avoids a duplicate send).`); skipped++; }
        else if (r.auditEmailFound) { resultLines.push(`⏭️ *${agId}* — NODS already sent (audit email on file${r.auditEmailDate ? `, ${r.auditEmailDate}` : ""}).`); skipped++; }
        else if (!r.lastLpfDate) { resultLines.push(`⏭️ *${agId}* — no NODS audit email, and no LPF (TypeId 49) on the agreement; can't confirm a NODS is due.`); skipped++; }
        else if (r.lpfReversedSameDay) { resultLines.push(`⏭️ *${agId}* — LPF was reversed (TypeId 50) the same day; NODS not required.`); skipped++; }
        else if (r.posted) { resultLines.push(`✅ *${agId}* — no NODS audit email found → posted SetTeamStatus(${NODS_TARGET_TEAM_STATUS_ID}) to refire.`); posted++; }
        else { resultLines.push(`❌ *${agId}* — SetTeamStatus failed: ${r.error || "unknown error"}`); failed++; }
      } catch (err) {
        resultLines.push(`❌ *${agId}* — remediation error: ${err.message}`); failed++;
      }
    }
    await client.chat.postMessage({ token: SLACK_BOT_TOKEN, channel: ch, thread_ts: ts, text: `*NODS remediation — ${posted} refired, ${skipped} skipped, ${failed} failed*\n\n${resultLines.join("\n")}\n\n_Hit *🔄 Refresh report* in a minute to confirm the NODS emails landed._`, mrkdwn: true });
  } catch (err) {
    console.error("[bill-ling] btn_notices_remediate error:", err.message);
  }
});

// ── Interactive buttons (Hargo, 18/06/2026) ──────────────────────────────
// Each mirrors the typed-command path exactly. They only fire if Slack
// Interactivity is enabled in the app config; in Socket Mode no Request URL
// is needed.

// "Post GOGW + refund" on a refund-approval message → identical to replying
// "approved @billington": gated to the refund authorisers, runs the locked
// figure through executeBillingtonAutoApprovedRefund (already-processed guards).
app.action("btn_post_gogw_refund", async ({ body, ack, client }) => {
  await ack();
  try {
    const user = body.user?.id;
    const clickChannel = body.channel?.id;
    let payload = {};
    try { payload = JSON.parse(body.actions?.[0]?.value || "{}"); } catch (_) {}
    const threadTs = payload.t;
    const ch = payload.c || clickChannel;
    if (!BILLINGTON_REFUND_AUTHORISERS.has(user)) {
      try { await client.chat.postEphemeral({ token: SLACK_BOT_TOKEN, channel: clickChannel, user, text: `Only ${BILLINGTON_REFUND_AUTHORISER_NAMES} can authorise me to post a GOGW + refund.` }); } catch (_) {}
      return;
    }
    if (!threadTs || !ch) {
      try { await client.chat.postEphemeral({ token: SLACK_BOT_TOKEN, channel: clickChannel, user, text: `I couldn't tell which thread this button belongs to — reply *approved @billington* in the thread instead.` }); } catch (_) {}
      return;
    }
    // Disable the button to prevent a double-click (the executor is idempotent
    // too, so a double-click is safe regardless).
    try {
      const kept = (body.message?.blocks || []).filter(b => b.type !== "actions");
      kept.push({ type: "context", elements: [{ type: "mrkdwn", text: `⏳ <@${user}> clicked *Post GOGW + refund* — processing…` }] });
      await client.chat.update({ token: SLACK_BOT_TOKEN, channel: ch, ts: body.message.ts, text: body.message.text || "Processing…", blocks: kept });
    } catch (_) {}
    await client.chat.postMessage({ token: SLACK_BOT_TOKEN, channel: ch, thread_ts: threadTs, text: `Checking this hasn't already been processed, then posting the GOGW + refund I locked… (authorised by <@${user}>)` });
    let sourceLink = "";
    try { sourceLink = await buildSlackPermalink(ch, threadTs); } catch (_) {}
    // The button may carry the vetted figure (amount/category/agreement) — e.g. a
    // fee-reduced trade-in the presser confirmed. Post that exact amount rather
    // than re-deriving. Older buttons without it fall back to re-derivation.
    const overrideAmount = (typeof payload.amount === "number" && payload.amount > 0) ? payload.amount : null;
    const r = await executeBillingtonAutoApprovedRefund({ channel: ch, thread_ts: threadTs, user, auditCtx: { requestedByUserId: user, triggeredBy: user, triggerSource: "slack_button", sourceLink }, overrideAmount, overrideCategory: payload.category || null, overrideAgreementId: payload.ag || null });
    if (r.fatal) {
      // Bring the button back so the operator can retry with a click (Hargo,
      // 07/07/2026 — e.g. after the arrears-poll timeout). The executor is
      // idempotent: on retry it skips an already-posted GOGW and just completes
      // the refund, so a re-click finishes the job rather than doubling up.
      // Always show the status code + Anchor status + reason on a failure
      // (Hargo, 07/07/2026 — so an Anchor issue is caught immediately), and keep
      // the button so it can be retried with a click.
      const retryText = (r.anchorHttpStatus != null || r.anchorStatus || r.anchorReason)
        ? `❌ *${r.agreementId || ""} — ${r.failedStep || "post"} not actioned.*\n` +
          `• *HTTP status:* ${r.anchorHttpStatus ?? "?"}\n` +
          `• *Anchor status:* ${r.anchorStatus || "Failure"}\n` +
          `• *Reason:* ${r.anchorReason || r.fatal}`
        : `❌ Not actioned. Reason: ${r.fatal}`;
      await client.chat.postMessage({
        token: SLACK_BOT_TOKEN, channel: ch, thread_ts: threadTs, text: retryText, mrkdwn: true,
        unfurl_links: false, unfurl_media: false,
        blocks: [
          { type: "section", text: { type: "mrkdwn", text: retryText } },
          { type: "actions", elements: [
            { type: "button", text: { type: "plain_text", text: "🔁 Retry post", emoji: true }, style: "primary", action_id: "btn_post_gogw_refund",
              value: JSON.stringify({ t: threadTs, c: ch }),
              confirm: { title: { type: "plain_text", text: "Retry GOGW + refund?" }, text: { type: "mrkdwn", text: "Re-runs the post. If the GOGW already landed, I'll skip it and just complete the refund once the arrears reflect." }, confirm: { type: "plain_text", text: "Retry" }, deny: { type: "plain_text", text: "Cancel" } } },
          ]},
        ],
      });
    } else {
      await client.chat.postMessage({ token: SLACK_BOT_TOKEN, channel: ch, thread_ts: threadTs, text: `✅ Done. Posted on *${r.agreementId}* (${r.category}):\n• GOGW: ${r.gogw && r.gogw.status === "already_posted" ? "already on Anchor (skipped re-post)" : `+£${r.amount.toFixed(2)} (TypeId 61)`}\n• Refund: £${r.amount.toFixed(2)} (TypeId 149, stored as negative)` });
    }
  } catch (err) {
    console.error("[bill-ling] btn_post_gogw_refund error:", err.message);
  }
});

