// "Reject draft" on an iOutlet draft → discards the draft without sending and
// disables the buttons. The Gmail email is left for a human to handle. Anyone
// in #data-billing-updates can reject. (Hargo, 23/06/2026.)
app.action("btn_ioutlet_reject", async ({ body, ack, client }) => {
  await ack();
  try {
    const user = body.user?.id;
    const ch = body.channel?.id;
    const draftTs = body.message?.ts;
    const draft = draftTs ? ioutletDraftsByTs.get(draftTs) : null;
    if (draft) {
      if (draft.sentAt) {
        try { await client.chat.postEphemeral({ token: SLACK_BOT_TOKEN, channel: ch, user, text: `This draft was already sent at ${draft.sentAt} — too late to reject.` }); } catch (_) {}
        return;
      }
      draft.rejectedAt = new Date().toISOString();
      draft.rejectedBy = user;
      ioutletDraftsByTs.set(draftTs, draft);
      saveIOutletDrafts();
    }
    try {
      const kept = (body.message?.blocks || []).filter(b => b.type !== "actions");
      kept.push({ type: "context", elements: [{ type: "mrkdwn", text: `🗑️ <@${user}> rejected this draft — not sent. The iOutlet email is left for a human to handle.` }] });
      await client.chat.update({ token: SLACK_BOT_TOKEN, channel: ch, ts: draftTs, text: body.message?.text || "Draft rejected.", blocks: kept });
    } catch (e) { console.error("[bill-ling] btn_ioutlet_reject update:", e.message); }
  } catch (err) {
    console.error("[bill-ling] btn_ioutlet_reject error:", err.message);
  }
});

// "Confirm uploaded & processed" on a batch-file chase → marks the Barclays
// refund file confirmed: ✅ on the parent + a confirmation reply so the refund
// scanner resolves the thread and stops the daily chase. Mirrors typing
// "this has been paid". Anyone in the channel can click (finance confirms).
app.action("btn_confirm_batch_paid", async ({ body, ack, client }) => {
  await ack();
  try {
    const user = body.user?.id;
    const clickChannel = body.channel?.id;
    let payload = {};
    try { payload = JSON.parse(body.actions?.[0]?.value || "{}"); } catch (_) {}
    const threadTs = payload.t;
    const ch = payload.c || clickChannel;
    if (!threadTs || !ch) {
      try { await client.chat.postEphemeral({ token: SLACK_BOT_TOKEN, channel: clickChannel, user, text: `I couldn't tell which refund file this button belongs to.` }); } catch (_) {}
      return;
    }
    const todayUk = new Date().toLocaleDateString("en-GB", { timeZone: "Europe/London", day: "2-digit", month: "2-digit", year: "numeric" });
    // Disable the button (one-click), keep the rest of the message.
    try {
      const kept = (body.message?.blocks || []).filter(b => b.type !== "actions");
      kept.push({ type: "context", elements: [{ type: "mrkdwn", text: `✅ Confirmed uploaded & processed by <@${user}> (${todayUk}).` }] });
      await client.chat.update({ token: SLACK_BOT_TOKEN, channel: ch, ts: body.message.ts, text: body.message.text || "Confirmed", blocks: kept });
    } catch (_) {}
    try { await client.reactions.add({ token: SLACK_BOT_TOKEN, channel: ch, timestamp: threadTs, name: "white_check_mark" }); } catch (e) { if (e.data?.error !== "already_reacted") console.error("[bill-ling] btn_confirm_batch_paid reaction:", e.message); }
    await client.chat.postMessage({
      token: SLACK_BOT_TOKEN,
      channel: ch,
      thread_ts: threadTs,
      text: `✅ Refund file confirmed uploaded & processed on Barclays — confirmed by <@${user}> (${todayUk}). Marking as complete.`,
      mrkdwn: true,
    });
  } catch (err) {
    console.error("[bill-ling] btn_confirm_batch_paid error:", err.message);
  }
});

// "Confirm account topped up" (Hargo, 15/07/2026) — any finance-team member can
// press when a Stannp/GoCardless top-up was flagged. Rechecks the live balance and
// records the before/after amendment. If the top-up has landed (balance went up) it
// disables the button and annotates the post; if it hasn't shown yet, it leaves the
// button so they can press again once it lands. No financial action — recheck only.
app.action("btn_confirm_topup", async ({ body, ack, client }) => {
  await ack();
  try {
    const user = body.user?.id;
    const ch = body.channel?.id;
    const ts = body.message?.ts;
    const gbp = (n) => Number(n).toLocaleString("en-GB", { style: "currency", currency: "GBP" });
    const todayUk = new Date().toLocaleDateString("en-GB", { timeZone: "Europe/London", day: "2-digit", month: "2-digit", year: "numeric" });
    let payload = {};
    try { payload = JSON.parse(body.actions?.[0]?.value || "{}"); } catch (_) {}
    const account = payload.account === "gocardless" ? "gocardless" : "stannp";
    const label = account === "gocardless" ? "GoCardless" : "Stannp";
    const before = Number(payload.before);
    const beforeStr = isFinite(before) ? gbp(before) : "unknown";

    // Recheck the live balance now the top-up is confirmed. getStannp/GoCardless
    // also refresh today's history + GCS, so the burn/runout picks up the new figure.
    let after = null, recheckErr = null;
    try {
      const data = account === "gocardless" ? await getGoCardlessBalance() : await getStannpBalance();
      after = Number(data.balance);
    } catch (e) { recheckErr = e.message; }

    if (after == null) {
      const note = `⚠️ ${label} top-up confirmed by <@${user}> (${todayUk}), but I couldn't recheck the live balance right now (${recheckErr || "unknown error"}). Balance before was ${beforeStr}. I'll pick up the new figure on the next daily check.`;
      await client.chat.postMessage({ token: SLACK_BOT_TOKEN, channel: ch, thread_ts: ts, text: note, mrkdwn: true, unfurl_links: false, unfurl_media: false });
      return;
    }

    const increased = isFinite(before) && after > before + 0.005;
    if (increased) {
      const delta = after - before;
      const note = `✅ ${label} top-up confirmed by <@${user}> (${todayUk}). Balance before ${beforeStr}, after ${gbp(after)} (+${gbp(delta)}).`;
      // Disable the button (keep the report), annotate with the amendment.
      try {
        const kept = (body.message?.blocks || []).filter(b => b.type !== "actions");
        kept.push({ type: "context", elements: [{ type: "mrkdwn", text: note }] });
        await client.chat.update({ token: SLACK_BOT_TOKEN, channel: ch, ts, text: note, blocks: kept });
      } catch (e) { console.error("[bill-ling] btn_confirm_topup update failed:", e.message); }
      // Leave a thread note too as the audit record.
      await client.chat.postMessage({ token: SLACK_BOT_TOKEN, channel: ch, thread_ts: ts, text: note, mrkdwn: true, unfurl_links: false, unfurl_media: false });
    } else {
      // No increase detected yet — top-ups can take a moment to show. Keep the
      // button so they can press again once it lands.
      const note = `ℹ️ ${label}: I rechecked but the balance is still ${gbp(after)} (was ${beforeStr}); the top-up may not have landed yet. Press the button again once it shows, or I'll pick it up on the next daily check. Checked by <@${user}> (${todayUk}).`;
      await client.chat.postMessage({ token: SLACK_BOT_TOKEN, channel: ch, thread_ts: ts, text: note, mrkdwn: true, unfurl_links: false, unfurl_media: false });
    }
  } catch (err) {
    console.error("[bill-ling] btn_confirm_topup error:", err.message);
  }
});

// ── Refund-channel question buttons (Hargo, 25/06/2026) ───────────────────
// Same approval PROCESS as before — these just give Billington's refund-channel
// questions a button. A click does what typing the answer would, with the same
// gating (approval is a logged business signal; the money step stays gated).

// "✅ Approve for processing" → records the approval (like an approver typing
// "approved") and posts the next-step options: the gated Post GOGW + refund
// button (if a figure is locked) and Mark refunded manually. Does NOT post money.
// ---------------------------------------------------------------------------
// "🚩 Billington is incorrect" — feedback + stand-down (Hargo, 20/07/2026)
// ---------------------------------------------------------------------------
// Appended to Billington's interactive question/proposal messages. On click it
// flags Hargo, stands down on the thread (no further action or questions until
// Hargo asks Billington to review), and logs the flag for a weekly learnings
// review. In a DM/private chat it just stores the request details (no shareable
// link, no public mention). The stand-down works via the message wording
// ("standing down") which the passive-trigger + approval-monitor checks detect.
const BILLINGTON_INCORRECT_GCS_KEY = "billington-incorrect-feedback.json";

function billingtonIncorrectButton() {
  return {
    type: "button",
    text: { type: "plain_text", text: "🚩 Billington is incorrect", emoji: true },
    action_id: "btn_billington_incorrect",
    confirm: {
      title: { type: "plain_text", text: "Flag as incorrect?" },
      text: { type: "mrkdwn", text: `I'll stop acting on this thread, flag it to <@${HARGO_USER_ID}>, and log it for review. I won't do anything further here unless he asks me to review.` },
      confirm: { type: "plain_text", text: "Flag it" }, deny: { type: "plain_text", text: "Cancel" },
    },
  };
}

// "⚠️ Process anyway" — an authoriser override for a trade-in Billington is holding
// as pending assessment. Carries the full {amount, category, ag} triple, which the
// executor treats as already-reconciled (dentonResolved) and so SKIPS the pending
// guard, while every other live pre-check (arrears, existing TypeId 61, blockers)
// still runs. Gated by btn_post_gogw_refund to the refund authorisers. Hargo,
// 20/07/2026 (A00353969: device stocked, so the "pending" status was moot).
function processAnywayButton(threadTs, channel, agreementId, amount, category) {
  const amt = Number(amount).toFixed(2);
  const cat = category || "Full trade in value";
  return {
    type: "button",
    text: { type: "plain_text", text: `⚠️ Process anyway — £${amt}`, emoji: true },
    style: "primary",
    action_id: "btn_post_gogw_refund",
    value: JSON.stringify({ t: threadTs, c: channel, amount: Number(amount), category: cat, ag: agreementId }),
    confirm: {
      title: { type: "plain_text", text: "Process despite pending assessment?" },
      text: { type: "mrkdwn", text: `Denton hasn't confirmed an assessed value for ${agreementId}, so I'm normally holding off. This overrides that and posts *GOGW £${amt} + refund £${amt}* (${cat}) after the usual live pre-checks (arrears, existing TypeId 61, blockers). Only do this if you're sure, e.g. the device is stocked.` },
      confirm: { type: "plain_text", text: `Post £${amt}` }, deny: { type: "plain_text", text: "Cancel" },
    },
  };
}

app.action("btn_billington_incorrect", async ({ body, ack, client }) => {
  await ack();
  const user = body.user?.id;
  const ch = body.channel?.id;
  const ts = body.message?.ts;
  const threadTs = body.message?.thread_ts || ts;
  const flaggedText = body.message?.text || "";
  const isPrivate = (ch || "").startsWith("D"); // DM
  try {
    let permalink = null;
    if (!isPrivate) { try { permalink = await getSlackMessagePermalink(ch, ts); } catch (_) {} }
    // Log for the weekly review (thread link for public; request details for private).
    try {
      const logArr = (await loadJsonFromGcs(BILLINGTON_INCORRECT_GCS_KEY)) || [];
      logArr.push({
        flaggedAt: new Date().toISOString(),
        flaggedBy: user, channel: ch, threadTs, messageTs: ts,
        permalink: isPrivate ? null : permalink,
        isPrivate,
        requestDetails: flaggedText.slice(0, 1500),
      });
      await saveJsonToGcs(BILLINGTON_INCORRECT_GCS_KEY, logArr);
    } catch (e) { console.error("[bill-ling] incorrect-log save:", e.message); }
    // A flag is feedback, NOT an action, so keep the card's action buttons (e.g.
    // Pass/Fail) intact — only a real action Billington takes should strip buttons
    // (Hargo, 20/07/2026). Just append a "flagged" note, leave every button in place.
    try {
      const kept = [...(body.message?.blocks || []), { type: "context", elements: [{ type: "mrkdwn", text: `🚩 Flagged as incorrect by <@${user}>.` }] }];
      await client.chat.update({ token: SLACK_BOT_TOKEN, channel: ch, ts, text: flaggedText || "Flagged as incorrect.", blocks: kept });
    } catch (_) {}
    // Stand down (the "standing down" wording is what the stand-down checks look for).
    const standDown = isPrivate
      ? `🚩 Noted, I've logged this as incorrect and stored the request details for review. Standing down. No further action or questions from me on this thread unless you ask me to review.`
      : `🚩 <@${HARGO_USER_ID}>, <@${user}> flagged this as incorrect. Standing down. I'll take no further action or questions on this thread unless <@${HARGO_USER_ID}> asks me to review.`;
    await client.chat.postMessage({ token: SLACK_BOT_TOKEN, channel: ch, thread_ts: threadTs, text: standDown, mrkdwn: true, unfurl_links: false, unfurl_media: false });
    console.log(`[bill-ling] btn_billington_incorrect by ${user} on ${ch}/${ts} (private=${isPrivate}).`);
  } catch (err) {
    console.error("[bill-ling] btn_billington_incorrect error:", err.message);
  }
});

// Weekly learnings review — Monday 09:00 London, DM Hargo the week's flags.
cron.schedule("0 9 * * 1", async () => {
  try {
    const logArr = (await loadJsonFromGcs(BILLINGTON_INCORRECT_GCS_KEY)) || [];
    const weekAgo = Date.now() - 7 * 86400 * 1000;
    const recent = logArr.filter(r => r && r.flaggedAt && new Date(r.flaggedAt).getTime() >= weekAgo);
    if (!recent.length) return;
    const lines = recent.map((r, i) => {
      const when = new Date(r.flaggedAt).toLocaleDateString("en-GB", { timeZone: "Europe/London" });
      const where = r.isPrivate ? `(private) "${(r.requestDetails || "").slice(0, 200)}"` : (r.permalink || `${r.channel}/${r.messageTs}`);
      return `${i + 1}. ${when}, by <@${r.flaggedBy}>: ${where}`;
    });
    await app.client.chat.postMessage({ token: SLACK_BOT_TOKEN, channel: HARGO_USER_ID, text: `🚩 *Billington-incorrect flags this week (${recent.length})* — worth a review:\n${lines.join("\n")}`, mrkdwn: true, unfurl_links: false, unfurl_media: false });
    console.log(`[bill-ling] Weekly incorrect-flag review DM sent (${recent.length}).`);
  } catch (e) { console.error("[bill-ling] weekly incorrect review error:", e.message); }
}, { timezone: "Europe/London" });
console.log("[bill-ling] Billington-incorrect feedback button + weekly review (Mon 09:00) wired.");

app.action("btn_refund_approve", async ({ body, ack, client }) => {
  await ack();
  try {
    const user = body.user?.id;
    const clickChannel = body.channel?.id;
    let payload = {}; try { payload = JSON.parse(body.actions?.[0]?.value || "{}"); } catch (_) {}
    const threadTs = payload.t;
    const channel = payload.c || clickChannel;
    const ref = payload.ref || null;
    if (!threadTs) {
      try { await client.chat.postEphemeral({ token: SLACK_BOT_TOKEN, channel: clickChannel, user, text: `I couldn't tell which refund this button belongs to.` }); } catch (_) {}
      return;
    }
    // Disable the approve/decline buttons and record who approved.
    try {
      const kept = (body.message?.blocks || []).filter(b => b.type !== "actions");
      kept.push({ type: "context", elements: [{ type: "mrkdwn", text: `✅ <@${user}> approved this refund for processing.` }] });
      await client.chat.update({ token: SLACK_BOT_TOKEN, channel: clickChannel, ts: body.message.ts, text: body.message?.text || "Approved", blocks: kept });
    } catch (_) {}
    const today = new Date().toLocaleDateString("en-CA", { timeZone: "Europe/London" });
    try { approvalNotifiedThreads.set(threadTs, today); } catch (_) {} // stop the approval chase today
    // Lock the figure from the thread so we can offer the Post button.
    let lock = null, agId = null, overduePhrase = "";
    try {
      const tr = await client.conversations.replies({ token: SLACK_BOT_TOKEN, channel, ts: threadTs, limit: 50 });
      const inferenceText = (tr.messages || []).map(m => getMessageText(m)).join("\n");
      agId = (ref && /^A\d{5,9}$/i.test(ref)) ? ref.toUpperCase() : ((inferenceText.match(/\bA\d{5}(?:\d{3})?\b/i) || [])[0] || "").toUpperCase();
      if (agId) lock = computeRefundLock(agId, inferenceText);
      overduePhrase = overdueAssessmentPhrase(inferenceText);
    } catch (e) { console.error("[bill-ling] btn_refund_approve lock:", e.message); }
    const elements = [];
    if (lock && lock.pending && lock.amount > 0 && agId) elements.push(processAnywayButton(threadTs, channel, agId, lock.amount, lock.category));
    if (lock && lock.cmd) {
      elements.push({ type: "button", text: { type: "plain_text", text: "💸 Post GOGW + refund", emoji: true }, style: "primary", action_id: "btn_post_gogw_refund", value: JSON.stringify({ t: threadTs, c: channel }),
        confirm: { title: { type: "plain_text", text: "Post GOGW + refund?" }, text: { type: "mrkdwn", text: `I'll run my usual checks then post:\n\`${lock.cmd}\`` }, confirm: { type: "plain_text", text: "Post it" }, deny: { type: "plain_text", text: "Cancel" } } });
    }
    elements.push({ type: "button", text: { type: "plain_text", text: "✋ Mark refunded manually", emoji: true }, action_id: "btn_refund_manual", value: JSON.stringify({ t: threadTs, c: channel, ref }),
      confirm: { title: { type: "plain_text", text: "Mark refunded manually?" }, text: { type: "mrkdwn", text: "Records that this refund was actioned by hand and stops the chase. Charlotte/Ciaran/Hargo only." }, confirm: { type: "plain_text", text: "Mark done" }, deny: { type: "plain_text", text: "Cancel" } } });
    elements.push(billingtonIncorrectButton());
    const headline = (lock && lock.pending)
      ? ((lock.amount > 0)
          ? `⚠️ Approved by <@${user}>, but ${ref ? `*${ref}*` : "this"} trade-in has *not been assessed* yet.${overduePhrase} You don't need to wait for the assessment — if that delay is the reason for the refund, use *⚠️ Process anyway* above to push it through at the declared *£${lock.amount.toFixed(2)}*.`
          : `⚠️ Approved by <@${user}>, but ${ref ? `*${ref}*` : "this"} trade-in has *not been assessed* yet.${overduePhrase} I couldn't read a clear figure to offer a one-click button, so ${BILLINGTON_REFUND_AUTHORISER_NAMES} can post it explicitly with the amount.`)
      : (lock && lock.cmd)
      ? `✅ Approved by <@${user}>. Good to go for processing:\n• GOGW: *£${lock.amount.toFixed(2)}* (TypeId 61)\n• Refund: *£${lock.amount.toFixed(2)}* (TypeId 149)\n• Type: *${lock.category}*\nCommand: \`${lock.cmd}\`\n${BILLINGTON_REFUND_AUTHORISER_NAMES} can post it, or Charlotte/Ciaran can mark it refunded manually.`
      : `✅ Approved by <@${user}>. Good to go for processing — Charlotte/Ciaran to action the refund, then mark it done.`;
    await client.chat.postMessage({ token: SLACK_BOT_TOKEN, channel, thread_ts: threadTs, text: headline, blocks: [{ type: "section", text: { type: "mrkdwn", text: headline } }, { type: "actions", elements }], mrkdwn: true });
  } catch (err) {
    console.error("[bill-ling] btn_refund_approve error:", err.message);
  }
});

